function normalizePromptStrategyMode(raw) {
  const value = String(raw || "").trim().toLowerCase();
  if (value === "auto") return "auto";
  if (value === "baseline") return "baseline";
  return "tail";
}

function loadPromptBenchmarkTrials() {
  try {
    const raw = localStorage.getItem(PROMPT_BENCHMARK_LS_KEY);
    if (!raw) return [];
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return [];
    return parsed
      .map((row) => (row && typeof row === "object" ? row : null))
      .filter(Boolean)
      .map((row) => ({
        id: Number(row.id) || 0,
        strategy: (() => {
          const s = String(row.strategy || "").trim().toLowerCase();
          if (s === "baseline" || s === "tail" || s === "repeat") return s;
          return "tail";
        })(),
        model: String(row.model || "").trim() || "unknown",
        startedAt: Number(row.startedAt) || Date.now(),
        status: String(row.status || "").trim().toLowerCase() === "failed" ? "failed" : "success",
        versionId: row.versionId ? String(row.versionId) : null,
        promptChars: Math.max(0, Number(row.promptChars) || 0),
        constraintCount: Math.max(0, Number(row.constraintCount) || 0),
        costUsd: Number.isFinite(Number(row.costUsd)) ? Number(row.costUsd) : null,
        latencyS: Number.isFinite(Number(row.latencyS)) ? Number(row.latencyS) : null,
        error: row.error ? String(row.error) : null,
      }))
      .filter((row) => row.id > 0)
      .slice(-PROMPT_BENCHMARK_MAX_TRIALS);
  } catch {
    return [];
  }
}

function normalizePromptBenchmarkStrategy(raw) {
  const value = String(raw || "").trim().toLowerCase();
  if (value === "baseline" || value === "tail" || value === "repeat") return value;
  return "tail";
}

function normalizePromptBenchmarkModel(raw) {
  const value = String(raw || "").trim();
  return value || "unknown";
}

function promptBenchmarkHydrateState() {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return;
  const history = Array.isArray(bench.trials) ? bench.trials.slice(-PROMPT_BENCHMARK_MAX_TRIALS) : [];
  bench.trials = history;
  bench.pendingIds = [];
  bench.versionToTrialId = new Map();
  bench.awaitingCostTrialIds = [];
  bench.trialById = new Map();
  let maxId = 0;
  for (const row of history) {
    if (!row || typeof row !== "object") continue;
    const id = Number(row.id) || 0;
    if (id <= 0) continue;
    row.id = id;
    row.strategy = normalizePromptBenchmarkStrategy(row.strategy);
    row.model = normalizePromptBenchmarkModel(row.model);
    row.status = String(row.status || "").trim().toLowerCase() === "failed" ? "failed" : "success";
    row.versionId = row.versionId ? String(row.versionId) : null;
    row.promptChars = Math.max(0, Number(row.promptChars) || 0);
    row.constraintCount = Math.max(0, Number(row.constraintCount) || 0);
    row.costUsd = Number.isFinite(Number(row.costUsd)) ? Number(row.costUsd) : null;
    row.latencyS = Number.isFinite(Number(row.latencyS)) ? Number(row.latencyS) : null;
    row.error = row.error ? String(row.error) : null;
    bench.trialById.set(id, row);
    if (id > maxId) maxId = id;
  }
  bench.nextId = Math.max(1, maxId + 1);
}

function promptBenchmarkPersistHistory() {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return;
  const serializable = (Array.isArray(bench.trials) ? bench.trials : [])
    .slice(-PROMPT_BENCHMARK_MAX_TRIALS)
    .map((row) => ({
      id: Number(row?.id) || 0,
      strategy: normalizePromptBenchmarkStrategy(row?.strategy),
      model: normalizePromptBenchmarkModel(row?.model),
      startedAt: Number(row?.startedAt) || Date.now(),
      status: String(row?.status || "").trim().toLowerCase() === "failed" ? "failed" : "success",
      versionId: row?.versionId ? String(row.versionId) : null,
      promptChars: Math.max(0, Number(row?.promptChars) || 0),
      constraintCount: Math.max(0, Number(row?.constraintCount) || 0),
      costUsd: Number.isFinite(Number(row?.costUsd)) ? Number(row.costUsd) : null,
      latencyS: Number.isFinite(Number(row?.latencyS)) ? Number(row.latencyS) : null,
      error: row?.error ? String(row.error) : null,
    }))
    .filter((row) => row.id > 0);
  try {
    localStorage.setItem(PROMPT_BENCHMARK_LS_KEY, JSON.stringify(serializable));
  } catch {
    // ignore localStorage failures
  }
}

function promptBenchmarkSyncHistoryRow(trialId) {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return;
  const id = Number(trialId) || 0;
  if (id <= 0) return;
  const trial = bench.trialById.get(id);
  if (!trial) return;
  const index = bench.trials.findIndex((row) => Number(row?.id) === id);
  if (index >= 0) {
    bench.trials[index] = trial;
  } else {
    bench.trials.push(trial);
  }
  if (bench.trials.length > PROMPT_BENCHMARK_MAX_TRIALS) {
    const dropCount = bench.trials.length - PROMPT_BENCHMARK_MAX_TRIALS;
    const removed = bench.trials.splice(0, dropCount);
    for (const row of removed) {
      const removedId = Number(row?.id) || 0;
      if (!removedId) continue;
      bench.trialById.delete(removedId);
      bench.pendingIds = bench.pendingIds.filter((value) => Number(value) !== removedId);
      bench.awaitingCostTrialIds = bench.awaitingCostTrialIds.filter((value) => Number(value) !== removedId);
    }
  }
}

function promptBenchmarkRenderReadout() {
  if (!els.promptBenchmarkReadout) return;
  const bench = state.promptBenchmark;
  const trials = Array.isArray(bench?.trials) ? bench.trials : [];
  const currentModel = normalizePromptBenchmarkModel(settings?.imageModel);
  const configuredMode = normalizePromptStrategyMode(settings?.promptStrategyMode || "tail");
  if (configuredMode === "auto") {
    const auto = promptBenchmarkAutoStrategyForModel(currentModel, { fallback: "tail" });
    const reason =
      auto.reason === "insufficient_data"
        ? `insufficient data (${auto.totalAttempts})`
        : auto.reason === "no_model_data"
          ? "no model data"
          : `benchmark (${auto.totalAttempts})`;
    const summaryLine = `Auto active: ${auto.strategy} for ${currentModel} (${reason})`;
    if (!trials.length) {
      els.promptBenchmarkReadout.textContent = `${summaryLine}\nNo benchmark data yet`;
      return;
    }
  }
  if (!trials.length) {
    els.promptBenchmarkReadout.textContent = "No benchmark data yet";
    return;
  }

  const strategyOrder = ["baseline", "tail", "repeat"];
  const modelRows = new Map();
  for (const row of trials) {
    if (!row || typeof row !== "object") continue;
    const model = normalizePromptBenchmarkModel(row.model);
    const strategy = normalizePromptBenchmarkStrategy(row.strategy);
    if (!modelRows.has(model)) {
      modelRows.set(model, {
        total: 0,
        byStrategy: new Map(strategyOrder.map((key) => [key, []])),
      });
    }
    const bucket = modelRows.get(model);
    bucket.total += 1;
    if (!bucket.byStrategy.has(strategy)) bucket.byStrategy.set(strategy, []);
    bucket.byStrategy.get(strategy).push(row);
  }

  const lines = [];
  if (configuredMode === "auto") {
    const auto = promptBenchmarkAutoStrategyForModel(currentModel, { fallback: "tail" });
    const reason =
      auto.reason === "insufficient_data"
        ? `insufficient data (${auto.totalAttempts})`
        : auto.reason === "no_model_data"
          ? "no model data"
          : `benchmark (${auto.totalAttempts})`;
    lines.push(`Auto active: ${auto.strategy} for ${currentModel} (${reason})`);
  }
  lines.push(`Total trials: ${trials.length}`);
  const orderedModels = Array.from(modelRows.entries()).sort((a, b) => {
    const totalA = Number(a?.[1]?.total) || 0;
    const totalB = Number(b?.[1]?.total) || 0;
    if (totalB !== totalA) return totalB - totalA;
    return String(a?.[0] || "").localeCompare(String(b?.[0] || ""));
  });
  for (const [model, bucket] of orderedModels) {
    lines.push(`${model} (${bucket.total})`);
    for (const strategy of strategyOrder) {
      const rows = Array.isArray(bucket.byStrategy.get(strategy)) ? bucket.byStrategy.get(strategy) : [];
      if (!rows.length) {
        lines.push(`  ${strategy}: no runs`);
        continue;
      }
      const success = rows.filter((row) => row.status === "success").length;
      const attempts = rows.length;
      const successPct = Math.round((success / Math.max(1, attempts)) * 100);
      const costRows = rows.map((row) => Number(row.costUsd)).filter((value) => Number.isFinite(value));
      const latencyRows = rows.map((row) => Number(row.latencyS)).filter((value) => Number.isFinite(value));
      const charsRows = rows.map((row) => Number(row.promptChars)).filter((value) => Number.isFinite(value));
      const avgCost = costRows.length ? costRows.reduce((sum, value) => sum + value, 0) / costRows.length : null;
      const avgLatency = latencyRows.length
        ? latencyRows.reduce((sum, value) => sum + value, 0) / latencyRows.length
        : null;
      const avgChars = charsRows.length ? Math.round(charsRows.reduce((sum, value) => sum + value, 0) / charsRows.length) : 0;
      lines.push(
        `  ${strategy}: ${successPct}% (${success}/${attempts}) | cost ${formatUsd(avgCost) || "n/a"} | latency ${
          avgLatency !== null ? `${avgLatency.toFixed(1)}s` : "n/a"
        } | prompt ${avgChars} chars`
      );
    }
  }
  els.promptBenchmarkReadout.textContent = lines.join("\n");
}

function promptBenchmarkAutoStrategyForModel(model = "", { fallback = "tail", minTrials = 4 } = {}) {
  const fallbackMode = normalizePromptStrategyMode(fallback) === "baseline" ? "baseline" : "tail";
  const modelKey = normalizePromptBenchmarkModel(model);
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") {
    return {
      strategy: fallbackMode,
      reason: "no_benchmark_state",
      totalAttempts: 0,
    };
  }
  const sourceRows = Array.isArray(bench.trials) ? bench.trials : [];
  const rows = sourceRows.filter((row) => {
    const rowModel = normalizePromptBenchmarkModel(row?.model);
    if (rowModel !== modelKey) return false;
    const strategy = normalizePromptBenchmarkStrategy(row?.strategy);
    return strategy === "tail" || strategy === "baseline";
  });
  if (!rows.length) {
    return {
      strategy: fallbackMode,
      reason: "no_model_data",
      totalAttempts: 0,
    };
  }
  const byStrategy = new Map([
    ["tail", []],
    ["baseline", []],
  ]);
  for (const row of rows) {
    const strategy = normalizePromptBenchmarkStrategy(row?.strategy);
    if (!byStrategy.has(strategy)) continue;
    byStrategy.get(strategy).push(row);
  }
  const totalAttempts = rows.length;
  if (totalAttempts < Math.max(2, Number(minTrials) || 4)) {
    return {
      strategy: fallbackMode,
      reason: "insufficient_data",
      totalAttempts,
    };
  }

  const summarize = (list = []) => {
    const attempts = list.length;
    const success = list.filter((row) => String(row?.status || "").trim().toLowerCase() === "success").length;
    const smoothedSuccess = (success + 1) / (attempts + 2); // Beta(1,1) prior
    const latencyRows = list
      .map((row) => Number(row?.latencyS))
      .filter((value) => Number.isFinite(value) && value > 0);
    const costRows = list
      .map((row) => Number(row?.costUsd))
      .filter((value) => Number.isFinite(value) && value >= 0);
    const avgLatency = latencyRows.length
      ? latencyRows.reduce((sum, value) => sum + value, 0) / latencyRows.length
      : null;
    const avgCost = costRows.length
      ? costRows.reduce((sum, value) => sum + value, 0) / costRows.length
      : null;
    return { attempts, success, smoothedSuccess, avgLatency, avgCost };
  };

  const ranked = ["tail", "baseline"]
    .map((strategy) => ({
      strategy,
      metrics: summarize(byStrategy.get(strategy)),
    }))
    .filter((row) => row.metrics.attempts > 0)
    .sort((a, b) => {
      const aMetrics = a.metrics;
      const bMetrics = b.metrics;
      if (bMetrics.smoothedSuccess !== aMetrics.smoothedSuccess) {
        return bMetrics.smoothedSuccess - aMetrics.smoothedSuccess;
      }
      const aLatency = Number.isFinite(aMetrics.avgLatency) ? aMetrics.avgLatency : Number.POSITIVE_INFINITY;
      const bLatency = Number.isFinite(bMetrics.avgLatency) ? bMetrics.avgLatency : Number.POSITIVE_INFINITY;
      if (aLatency !== bLatency) return aLatency - bLatency;
      const aCost = Number.isFinite(aMetrics.avgCost) ? aMetrics.avgCost : Number.POSITIVE_INFINITY;
      const bCost = Number.isFinite(bMetrics.avgCost) ? bMetrics.avgCost : Number.POSITIVE_INFINITY;
      if (aCost !== bCost) return aCost - bCost;
      if (bMetrics.attempts !== aMetrics.attempts) return bMetrics.attempts - aMetrics.attempts;
      return a.strategy.localeCompare(b.strategy);
    });

  if (!ranked.length) {
    return {
      strategy: fallbackMode,
      reason: "no_ranked_data",
      totalAttempts,
    };
  }
  return {
    strategy: ranked[0].strategy,
    reason: "benchmark",
    totalAttempts,
  };
}

function promptBenchmarkRegisterDispatch({ strategy = "tail", model = "unknown", promptChars = 0, constraintCount = 0 } = {}) {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return 0;
  const trialId = Math.max(1, Number(bench.nextId) || 1);
  bench.nextId = trialId + 1;
  const trial = {
    id: trialId,
    strategy: normalizePromptBenchmarkStrategy(strategy),
    model: normalizePromptBenchmarkModel(model),
    startedAt: Date.now(),
    status: "pending",
    versionId: null,
    promptChars: Math.max(0, Number(promptChars) || 0),
    constraintCount: Math.max(0, Number(constraintCount) || 0),
    costUsd: null,
    latencyS: null,
    error: null,
  };
  bench.trialById.set(trialId, trial);
  bench.pendingIds.push(trialId);
  while (bench.pendingIds.length > 24) {
    const dropped = Number(bench.pendingIds.shift()) || 0;
    if (!dropped) break;
    if (!bench.trials.some((row) => Number(row?.id) === dropped)) {
      bench.trialById.delete(dropped);
    }
  }
  promptBenchmarkRenderReadout();
  return trialId;
}

function promptBenchmarkBindVersion(versionId) {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return 0;
  const normalizedVersionId = String(versionId || "").trim();
  if (!normalizedVersionId) return 0;
  if (bench.versionToTrialId.has(normalizedVersionId)) return Number(bench.versionToTrialId.get(normalizedVersionId)) || 0;
  while (bench.pendingIds.length) {
    const candidate = Number(bench.pendingIds.shift()) || 0;
    if (!candidate) continue;
    const trial = bench.trialById.get(candidate);
    if (!trial) continue;
    if (trial.status !== "pending") continue;
    trial.versionId = normalizedVersionId;
    bench.versionToTrialId.set(normalizedVersionId, candidate);
    return candidate;
  }
  return 0;
}

function promptBenchmarkResolveTrialIdForFailure(versionId = null) {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return 0;
  const normalizedVersionId = String(versionId || "").trim();
  if (normalizedVersionId && bench.versionToTrialId.has(normalizedVersionId)) {
    return Number(bench.versionToTrialId.get(normalizedVersionId)) || 0;
  }
  for (const rawId of bench.pendingIds) {
    const id = Number(rawId) || 0;
    if (!id) continue;
    const trial = bench.trialById.get(id);
    if (trial && trial.status === "pending") return id;
  }
  return 0;
}

function promptBenchmarkFinalizeTrial(trialId, { status = "success", error = null, costUsd = null, latencyS = null } = {}) {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return false;
  const id = Number(trialId) || 0;
  if (!id) return false;
  const trial = bench.trialById.get(id);
  if (!trial) return false;
  if (trial.status !== "pending" && trial.status !== "success" && trial.status !== "failed") return false;
  const nextStatus = String(status || "").trim().toLowerCase() === "failed" ? "failed" : "success";
  if (trial.status !== "pending" && trial.status === nextStatus && nextStatus === "success") {
    // Allow metrics hydration for already completed successful rows.
  } else if (trial.status !== "pending") {
    return false;
  }
  trial.status = nextStatus;
  trial.error = nextStatus === "failed" ? (error ? String(error) : null) : null;
  if (Number.isFinite(Number(costUsd))) trial.costUsd = Number(costUsd);
  if (Number.isFinite(Number(latencyS))) trial.latencyS = Number(latencyS);

  bench.pendingIds = bench.pendingIds.filter((value) => Number(value) !== id);
  if (trial.versionId) {
    bench.versionToTrialId.delete(String(trial.versionId));
  }
  if (nextStatus === "success" && (trial.costUsd === null || trial.latencyS === null)) {
    if (!bench.awaitingCostTrialIds.includes(id)) bench.awaitingCostTrialIds.push(id);
  } else {
    bench.awaitingCostTrialIds = bench.awaitingCostTrialIds.filter((value) => Number(value) !== id);
  }

  promptBenchmarkSyncHistoryRow(id);
  promptBenchmarkPersistHistory();
  promptBenchmarkRenderReadout();
  return true;
}

function promptBenchmarkMarkSuccessFromArtifactEvent(event = {}) {
  const versionId = desktopEventVersionId(event);
  if (!versionId) return false;
  const trialId = Number(state.promptBenchmark?.versionToTrialId?.get(versionId)) || 0;
  if (!trialId) return false;
  const metrics = event.metrics && typeof event.metrics === "object" ? event.metrics : null;
  const costUsd = Number.isFinite(Number(metrics?.cost_total_usd)) ? Number(metrics.cost_total_usd) : null;
  const latencyS = Number.isFinite(Number(metrics?.latency_per_image_s)) ? Number(metrics.latency_per_image_s) : null;
  return promptBenchmarkFinalizeTrial(trialId, {
    status: "success",
    costUsd,
    latencyS,
  });
}

function promptBenchmarkMarkFailureFromGenerationFailedEvent(event = {}) {
  const versionId = desktopEventVersionId(event);
  const trialId = promptBenchmarkResolveTrialIdForFailure(versionId);
  if (!trialId) return false;
  return promptBenchmarkFinalizeTrial(trialId, {
    status: "failed",
    error: event?.error ? String(event.error) : "generation_failed",
  });
}

function promptBenchmarkAttachCostLatencyEvent(event = {}) {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return false;
  if (!bench.awaitingCostTrialIds.length) return false;
  const incomingModel = normalizePromptBenchmarkModel(event?.model);
  let trialId = 0;
  if (incomingModel && incomingModel !== "unknown") {
    for (const candidateRaw of bench.awaitingCostTrialIds) {
      const candidate = Number(candidateRaw) || 0;
      if (!candidate) continue;
      const row = bench.trialById.get(candidate);
      if (!row) continue;
      if (normalizePromptBenchmarkModel(row.model) === incomingModel) {
        trialId = candidate;
        break;
      }
    }
  }
  if (!trialId) {
    trialId = Number(bench.awaitingCostTrialIds[0]) || 0;
  }
  if (!trialId) return false;
  const trial = bench.trialById.get(trialId);
  if (!trial) return false;
  if (Number.isFinite(Number(event?.cost_total_usd))) trial.costUsd = Number(event.cost_total_usd);
  if (Number.isFinite(Number(event?.latency_per_image_s))) trial.latencyS = Number(event.latency_per_image_s);
  bench.awaitingCostTrialIds = bench.awaitingCostTrialIds.filter((value) => Number(value) !== trialId);
  promptBenchmarkSyncHistoryRow(trialId);
  promptBenchmarkPersistHistory();
  promptBenchmarkRenderReadout();
  return true;
}

function promptBenchmarkReset() {
  const bench = state.promptBenchmark;
  if (!bench || typeof bench !== "object") return;
  bench.trials = [];
  bench.pendingIds = [];
  bench.trialById = new Map();
  bench.versionToTrialId = new Map();
  bench.awaitingCostTrialIds = [];
  bench.nextId = 1;
  try {
    localStorage.removeItem(PROMPT_BENCHMARK_LS_KEY);
  } catch {
    // ignore localStorage failures
  }
  promptBenchmarkRenderReadout();
}

function migrateLegacyBroodLocalStorage() {
  try {
    const pending = [];
    for (let idx = 0; idx < localStorage.length; idx += 1) {
      const legacyKey = localStorage.key(idx);
      if (!legacyKey || !legacyKey.startsWith("brood.")) continue;
      const canonicalKey = `cue.${legacyKey.slice("brood.".length)}`;
      if (localStorage.getItem(canonicalKey) !== null) continue;
      pending.push([canonicalKey, localStorage.getItem(legacyKey)]);
    }
    for (const [canonicalKey, value] of pending) {
      if (value !== null) {
        localStorage.setItem(canonicalKey, value);
      }
    }
  } catch {
    // localStorage can fail in some embedded/test contexts
  }
}

migrateLegacyBroodLocalStorage();

const settings = {
  memory: localStorage.getItem("cue.memory") === "1",
  alwaysOnVision: false,
  railIconPack: normalizeJuggernautRailIconPackId(
    localStorage.getItem(RAIL_ICON_PACK_LS_KEY) || DEFAULT_JUGGERNAUT_RAIL_ICON_PACK_ID
  ),
  textModel: localStorage.getItem("cue.textModel") || "gpt-5.2",
  imageModel: (() => {
    const storedRaw = String(localStorage.getItem("cue.imageModel") || "").trim();
    const migrated = localStorage.getItem(IMAGE_MODEL_DEFAULT_MIGRATION_KEY) === "1";
    if (!storedRaw) {
      if (!migrated) localStorage.setItem(IMAGE_MODEL_DEFAULT_MIGRATION_KEY, "1");
      return DEFAULT_IMAGE_MODEL;
    }
    if (!migrated && storedRaw === LEGACY_DEFAULT_IMAGE_MODEL) {
      localStorage.setItem("cue.imageModel", DEFAULT_IMAGE_MODEL);
      localStorage.setItem(IMAGE_MODEL_DEFAULT_MIGRATION_KEY, "1");
      return DEFAULT_IMAGE_MODEL;
    }
    if (!migrated) localStorage.setItem(IMAGE_MODEL_DEFAULT_MIGRATION_KEY, "1");
    return storedRaw;
  })(),
  promptStrategyMode: normalizePromptStrategyMode(localStorage.getItem(PROMPT_STRATEGY_MODE_KEY) || "auto"),
  promptRepeatFull: localStorage.getItem(PROMPT_REPEAT_FULL_KEY) === "1",
  installTelemetryOptIn: localStorage.getItem(INSTALL_TELEMETRY_OPT_IN_KEY) === "1",
};

setJuggernautRailIconPack(settings.railIconPack);

function applyDocumentRailIconPack(packId = "") {
  const resolved = normalizeJuggernautRailIconPackId(packId);
  const root = typeof document !== "undefined" ? document.documentElement : null;
  const body = typeof document !== "undefined" ? document.body : null;
  if (root?.dataset) root.dataset.railIconPack = resolved;
  if (body?.dataset) body.dataset.railIconPack = resolved;
  return resolved;
}

applyDocumentRailIconPack(settings.railIconPack);

function renderJuggernautShellIconSlot(slot, iconId = "", packId = settings.railIconPack) {
  if (!slot) return;
  const resolvedIconId =
    String(iconId || slot.dataset?.juggernautIconSlot || slot.getAttribute?.("data-juggernaut-icon-slot") || "").trim();
  if (!resolvedIconId) return;
  const resolvedPackId = normalizeJuggernautRailIconPackId(packId);
  if (slot.dataset?.renderedIconId === resolvedIconId && slot.dataset?.renderedIconPack === resolvedPackId) {
    return;
  }
  slot.innerHTML = getJuggernautRailIconMarkup(resolvedIconId, resolvedPackId);
  if (slot.dataset) {
    slot.dataset.renderedIconId = resolvedIconId;
    slot.dataset.renderedIconPack = resolvedPackId;
  }
}

function syncJuggernautShellIconography(packId = settings.railIconPack) {
  const resolvedPackId = normalizeJuggernautRailIconPackId(packId);
  if (typeof document === "undefined") return resolvedPackId;
  const slots = document.querySelectorAll("[data-juggernaut-icon-slot]");
  for (const slot of slots) {
    renderJuggernautShellIconSlot(slot, "", resolvedPackId);
  }
  return resolvedPackId;
}

function forceRenderQuickActions() {
  state.lastRenderedQuickActionsKey = "";
  state.lastRenderedCustomToolDockKey = "";
  renderQuickActions();
}

function iconPackLabel(packId = "") {
  return getJuggernautRailIconPack(packId).label;
}

async function syncNativeIconographyMenu(activePackId = settings.railIconPack) {
  await invoke("sync_native_iconography_menu", {
    activePackId: normalizeJuggernautRailIconPackId(activePackId),
  }).catch((error) => {
    console.warn("native iconography menu sync failed", error);
  });
}

function applyRailIconPackSetting(packId, { announce = true, source = "settings" } = {}) {
  const resolved = normalizeJuggernautRailIconPackId(packId);
  const changed = settings.railIconPack !== resolved;
  settings.railIconPack = resolved;
  localStorage.setItem(RAIL_ICON_PACK_LS_KEY, resolved);
  setJuggernautRailIconPack(resolved);
  applyDocumentRailIconPack(resolved);
  if (els.railIconPack && els.railIconPack.value !== resolved) {
    els.railIconPack.value = resolved;
  }
  syncJuggernautShellIconography(resolved);
  state.lastRenderedTimelineStructureKey = "";
  renderTimeline();
  renderJuggernautShellChrome();
  renderActionGrid();
  syncNativeIconographyMenu(resolved).catch(() => {});
  if (changed) {
    queueNativeSystemMenuSync();
    recordUserEvent("rail_icon_pack_changed", {
      pack_id: resolved,
      source: String(source || "settings").trim() || "settings",
    });
    if (announce) {
      showToast(`Iconography set to ${iconPackLabel(resolved)}.`, "tip", 2200);
    }
  }
  return resolved;
}

function telemetryRandomHex(bytes = 10) {
  const size = Math.max(4, Math.floor(Number(bytes) || 10));
  try {
    const arr = new Uint8Array(size);
    crypto.getRandomValues(arr);
    return Array.from(arr, (value) => value.toString(16).padStart(2, "0")).join("");
  } catch {
    return `${Date.now().toString(16)}${Math.random().toString(16).slice(2, 10)}`;
  }
}

function telemetryMakeId(prefix = "id") {
  return `${String(prefix || "id").trim() || "id"}-${Date.now().toString(36)}-${telemetryRandomHex(6)}`;
}

function telemetryNormalizeBool(raw, fallback = false) {
  if (typeof raw === "boolean") return raw;
  const lower = String(raw || "").trim().toLowerCase();
  if (lower === "1" || lower === "true" || lower === "yes" || lower === "on") return true;
  if (lower === "0" || lower === "false" || lower === "no" || lower === "off") return false;
  return Boolean(fallback);
}

function telemetryClassifyErrorCode(err) {
  const text = String(err?.message || err || "").toLowerCase();
  if (!text) return "unknown_error";
  if (text.includes("timeout")) return "timeout";
  if (text.includes("network")) return "network_error";
  if (text.includes("lock")) return "backend_lock_error";
  if (text.includes("missing")) return "missing_prerequisite";
  if (text.includes("denied") || text.includes("permission")) return "permission_denied";
  return "unknown_error";
}

function telemetrySanitizeFields(fields = {}) {
  const out = {};
  for (const [key, value] of Object.entries(fields || {})) {
    if (!key) continue;
    if (value === null) {
      out[key] = null;
      continue;
    }
    if (typeof value === "boolean") {
      out[key] = value;
      continue;
    }
    if (typeof value === "number" && Number.isFinite(value)) {
      out[key] = value;
      continue;
    }
    if (typeof value === "string") {
      out[key] = value.slice(0, 200);
    }
  }
  return out;
}

async function resolveInstallTelemetryPaths() {
  const telemetry = state.installTelemetry;
  if (telemetry.configPath && telemetry.logPath) return true;
  try {
    const home = await homeDir();
    if (!home) return false;
    const broodDir = await join(home, ".cue");
    await createDir(broodDir, { recursive: true }).catch(() => {});
    telemetry.configPath = await join(broodDir, INSTALL_TELEMETRY_CONFIG_FILE);
    telemetry.logPath = await join(broodDir, INSTALL_TELEMETRY_LOG_FILE);
    return true;
  } catch {
    return false;
  }
}

async function loadInstallTelemetryDiskConfig() {
  const telemetry = state.installTelemetry;
  if (!telemetry.configPath) return null;
  try {
    const present = await exists(telemetry.configPath).catch(() => false);
    if (!present) return null;
    const raw = await readTextFile(telemetry.configPath);
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") return null;
    return parsed;
  } catch {
    return null;
  }
}

async function persistInstallTelemetryDiskConfig() {
  const telemetry = state.installTelemetry;
  if (!telemetry.configPath) return;
  try {
    const payload = {
      version: 1,
      opt_in: Boolean(telemetry.optIn),
      force_opt_in: Boolean(telemetry.forceOptIn),
      install_id: telemetry.installId ? String(telemetry.installId) : null,
      endpoint: telemetry.endpoint ? String(telemetry.endpoint) : null,
      updated_at: new Date().toISOString(),
    };
    await writeTextFile(telemetry.configPath, JSON.stringify(payload, null, 2));
  } catch {
    // ignore config write failures
  }
}

function renderInstallTelemetryStatus() {
  if (els.installTelemetryToggle) {
    els.installTelemetryToggle.checked = Boolean(state.installTelemetry?.optIn);
  }
  if (!els.installTelemetryStatus) return;
  const telemetry = state.installTelemetry;
  if (!telemetry.ready) {
    els.installTelemetryStatus.textContent = "Initializing…";
    return;
  }
  if (!telemetry.optIn) {
    els.installTelemetryStatus.textContent = "Off (opt-in required).";
    return;
  }
  const id = String(telemetry.installId || "").trim();
  const shortId = id ? id.slice(0, 14) : "unset";
  const channel = String(telemetry.runtimeChannel || "unknown");
  const endpoint = telemetry.endpoint ? "on" : "off";
  els.installTelemetryStatus.textContent = `On\nInstall: ${shortId}\nChannel: ${channel}\nUpload endpoint: ${endpoint}`;
}

async function maybeUploadInstallTelemetry(payload) {
  const telemetry = state.installTelemetry;
  const endpoint = String(telemetry.endpoint || "").trim();
  if (!endpoint) return;
  let timer = null;
  let controller = null;
  try {
    if (typeof AbortController === "function") {
      controller = new AbortController();
      timer = setTimeout(() => controller.abort(), INSTALL_TELEMETRY_UPLOAD_TIMEOUT_MS);
    }
    await fetch(endpoint, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(payload),
      signal: controller?.signal,
      keepalive: true,
    });
  } catch {
    // ignore upload errors; local log remains source of truth
  } finally {
    if (timer) clearTimeout(timer);
  }
}

function emitInstallTelemetryReady(eventName, fields = {}) {
  const telemetry = state.installTelemetry;
  if (!telemetry.ready || !telemetry.optIn) return Promise.resolve(false);
  const event = String(eventName || "").trim();
  if (!event) return Promise.resolve(false);
  const payload = {
    schema: INSTALL_TELEMETRY_SCHEMA_VERSION,
    event,
    at: new Date().toISOString(),
    at_ms: Date.now(),
    install_id: String(telemetry.installId || ""),
    session_id: String(telemetry.sessionId || ""),
    runtime_channel: String(telemetry.runtimeChannel || ""),
    app_version: String(telemetry.appVersion || ""),
    ...telemetrySanitizeFields(fields),
  };
  telemetry.writeQueue = telemetry.writeQueue
    .then(async () => {
      let wrote = false;
      try {
        await invoke("append_install_telemetry_event", {
          payload,
          maxBytes: INSTALL_TELEMETRY_LOG_MAX_BYTES,
        });
        wrote = true;
      } catch {
        wrote = false;
      }
      if (!wrote && telemetry.logPath) {
        await appendJsonlWithFallback(telemetry.logPath, payload, {
          maxBytes: INSTALL_TELEMETRY_LOG_MAX_BYTES,
        });
      }
      await maybeUploadInstallTelemetry(payload);
    })
    .catch(() => {});
  return telemetry.writeQueue.then(() => true);
}

async function ensureInstallTelemetryReady() {
  const telemetry = state.installTelemetry;
  if (telemetry.ready) return true;
  if (telemetry.initPromise) return telemetry.initPromise;
  telemetry.initPromise = (async () => {
    let defaults = null;
    try {
      defaults = await invoke("get_install_telemetry_defaults");
    } catch {
      defaults = null;
    }
    await resolveInstallTelemetryPaths();
    const disk = await loadInstallTelemetryDiskConfig();
    const lsOptRaw = localStorage.getItem(INSTALL_TELEMETRY_OPT_IN_KEY);
    const lsInstallId = String(localStorage.getItem(INSTALL_TELEMETRY_INSTALL_ID_KEY) || "").trim();
    const lsEndpoint = String(localStorage.getItem(INSTALL_TELEMETRY_ENDPOINT_KEY) || "").trim();
    const forceOptIn = telemetryNormalizeBool(disk?.force_opt_in, telemetryNormalizeBool(defaults?.force_opt_in, false));
    telemetry.forceOptIn = Boolean(forceOptIn);

    const optIn = telemetry.forceOptIn
      ? true
      : lsOptRaw !== null
        ? telemetryNormalizeBool(lsOptRaw, false)
        : telemetryNormalizeBool(
            disk?.opt_in,
            telemetryNormalizeBool(defaults?.opt_in_default, settings.installTelemetryOptIn)
          );
    telemetry.optIn = Boolean(optIn);
    settings.installTelemetryOptIn = telemetry.optIn;
    localStorage.setItem(INSTALL_TELEMETRY_OPT_IN_KEY, telemetry.optIn ? "1" : "0");

    let installId = lsInstallId || String(telemetry.installId || "").trim();
    if (!installId) installId = String(disk?.install_id || "").trim();
    if (!installId) installId = String(defaults?.install_id || "").trim();
    if (!installId) installId = telemetryMakeId("install");
    telemetry.installId = installId;
    localStorage.setItem(INSTALL_TELEMETRY_INSTALL_ID_KEY, installId);

    let endpoint = lsEndpoint;
    if (!endpoint) endpoint = String(disk?.endpoint || "").trim();
    if (!endpoint) endpoint = String(defaults?.endpoint || "").trim();
    telemetry.endpoint = endpoint;
    if (endpoint) localStorage.setItem(INSTALL_TELEMETRY_ENDPOINT_KEY, endpoint);

    const runtimeChannel = String(defaults?.runtime_channel || "").trim();
    if (runtimeChannel) telemetry.runtimeChannel = runtimeChannel;
    telemetry.appVersion = String(defaults?.app_version || "").trim();
    telemetry.sessionId = telemetryMakeId("session");
    telemetry.ready = true;
    await persistInstallTelemetryDiskConfig();
    renderInstallTelemetryStatus();
    if (!telemetry.appFirstLaunchLogged && telemetry.optIn) {
      telemetry.appFirstLaunchLogged = true;
      await emitInstallTelemetryReady("app_first_launch", {
        source: "boot",
      });
    }
    return true;
  })()
    .catch((err) => {
      console.warn("install telemetry init failed", err);
      telemetry.ready = false;
      renderInstallTelemetryStatus();
      return false;
    })
    .finally(() => {
      telemetry.initPromise = null;
    });
  return telemetry.initPromise;
}

async function emitInstallTelemetry(eventName, fields = {}) {
  const ready = await ensureInstallTelemetryReady();
  if (!ready) return false;
  return emitInstallTelemetryReady(eventName, fields);
}

async function setInstallTelemetryOptIn(enabled, { source = "settings" } = {}) {
  const ready = await ensureInstallTelemetryReady();
  if (!ready) return false;
  const telemetry = state.installTelemetry;
  const next = Boolean(enabled);
  if (telemetry.forceOptIn && !next) {
    renderInstallTelemetryStatus();
    return false;
  }
  const changed = telemetry.optIn !== next;
  telemetry.optIn = next;
  settings.installTelemetryOptIn = next;
  localStorage.setItem(INSTALL_TELEMETRY_OPT_IN_KEY, next ? "1" : "0");
  await persistInstallTelemetryDiskConfig();
  renderInstallTelemetryStatus();
  if (next && !telemetry.appFirstLaunchLogged) {
    telemetry.appFirstLaunchLogged = true;
    await emitInstallTelemetryReady("app_first_launch", {
      source: "opt_in_toggle",
    });
  }
  if (next && changed) {
    await emitInstallTelemetryReady("telemetry_opt_in", {
      source: String(source || "settings"),
    });
  }
  return changed;
}

function emitInstallTelemetryAsync(eventName, fields = {}) {
  emitInstallTelemetry(eventName, fields).catch(() => {});
}

function maybeEmitFirstImportOk(fields = {}) {
  const telemetry = state.installTelemetry;
  if (telemetry.firstImportLogged) return;
  telemetry.firstImportLogged = true;
  emitInstallTelemetryAsync("first_import_ok", fields);
}

function maybeEmitFirstAbilitySuccess(fields = {}) {
  const telemetry = state.installTelemetry;
  if (telemetry.firstAbilitySuccessLogged) return;
  telemetry.firstAbilitySuccessLogged = true;
  emitInstallTelemetryAsync("first_ability_success", fields);
}

function maybeEmitFirstAbilityFail(fields = {}) {
  const telemetry = state.installTelemetry;
  if (telemetry.firstAbilitySuccessLogged || telemetry.firstAbilityFailureLogged) return;
  telemetry.firstAbilityFailureLogged = true;
  emitInstallTelemetryAsync("first_ability_fail", fields);
}

function maybeEmitFirstProposalProposed(fields = {}) {
  const telemetry = state.installTelemetry;
  if (telemetry.firstProposalProposedLogged) return;
  telemetry.firstProposalProposedLogged = true;
  emitInstallTelemetryAsync("first_proposal_proposed", fields);
}

function maybeEmitFirstProposalAccepted(fields = {}) {
  const telemetry = state.installTelemetry;
  if (telemetry.firstProposalAcceptedLogged) return;
  telemetry.firstProposalAcceptedLogged = true;
  emitInstallTelemetryAsync("first_proposal_accepted", fields);
}

