const VISION_LABEL_ARTICLE_TOKENS = new Set(["a", "an", "the"]);
const VISION_LABEL_AUX_TOKENS = new Set(["is", "are", "was", "were"]);
const REALTIME_VISION_LABEL_MAX_CHARS = 40;

function _visionTokenCore(raw) {
  return String(raw || "")
    .replace(/^[^A-Za-z0-9]+/g, "")
    .replace(/[^A-Za-z0-9]+$/g, "");
}

function _visionTokenStartsUpper(raw) {
  const core = _visionTokenCore(raw);
  if (!core) return false;
  const first = core.charAt(0);
  return first >= "A" && first <= "Z";
}

function _compactVisionCaptionFragment(raw) {
  let text = String(raw || "")
    .replace(/[\r\n\t]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!text) return "";

  text = text
    .replace(/^["']+|["']+$/g, "")
    .replace(/[.,;:!?]+$/g, "")
    .replace(/[,:;]+/g, " ")
    .trim();
  if (!text) return "";

  text = text.replace(/^(?:an?\s+)?(?:photo|image|picture)\s+of\s+/i, "").trim();
  if (!text) return "";

  let tokens = text
    .split(/\s+/g)
    .map((token) => token.trim())
    .filter(Boolean);
  if (!tokens.length) return "";

  while (
    tokens.length > 1 &&
    VISION_LABEL_ARTICLE_TOKENS.has(_visionTokenCore(tokens[0]).toLowerCase())
  ) {
    tokens.shift();
  }

  if (tokens.length >= 3) {
    const second = _visionTokenCore(tokens[1]).toLowerCase();
    if (VISION_LABEL_AUX_TOKENS.has(second)) {
      tokens.splice(1, 1);
    } else if (tokens.length >= 4) {
      const third = _visionTokenCore(tokens[2]).toLowerCase();
      if (
        VISION_LABEL_AUX_TOKENS.has(third) &&
        _visionTokenStartsUpper(tokens[0]) &&
        _visionTokenStartsUpper(tokens[1])
      ) {
        tokens.splice(2, 1);
      }
    }
  }

  if (tokens.length >= 3) {
    for (let i = 1; i < tokens.length - 1; i += 1) {
      const current = _visionTokenCore(tokens[i]).toLowerCase();
      if (!VISION_LABEL_AUX_TOKENS.has(current)) continue;
      const next = _visionTokenCore(tokens[i + 1]).toLowerCase();
      if (next.endsWith("ing")) {
        tokens.splice(i, 1);
        break;
      }
    }
  }

  if (tokens.length > 2) {
    const lastIdx = tokens.length - 1;
    tokens = tokens.filter((token, idx) => {
      if (idx <= 0 || idx >= lastIdx) return true;
      return !VISION_LABEL_AUX_TOKENS.has(_visionTokenCore(token).toLowerCase());
    });
  }

  if (tokens.length > 2) {
    tokens = tokens.filter((token, idx) => {
      if (idx === 0) return true;
      return !VISION_LABEL_ARTICLE_TOKENS.has(_visionTokenCore(token).toLowerCase());
    });
  }

  return tokens
    .map((token) => _visionTokenCore(token))
    .filter(Boolean)
    .join(" ")
    .replace(/\s+/g, " ")
    .trim();
}

function _normalizeVisionLabel(raw, { maxChars = 32 } = {}) {
  const s = _compactVisionCaptionFragment(raw);
  if (!s) return "";
  // Keep it short and HUD-friendly. (Even though it may not be shown in intent mode,
  // we reuse the same field for later HUD rendering.)
  const clipped = maxChars > 0 ? clampText(s, maxChars) : s;
  // Avoid our intent-signature delimiter.
  return clipped.replace(/[|]/g, "/").trim();
}

function normalizeVisionHintForIntent(raw, { maxChars = REALTIME_VISION_LABEL_MAX_CHARS } = {}) {
  const label = _normalizeVisionLabel(raw, { maxChars });
  if (!label) return null;
  if (shouldBackfillVisionLabel(label)) return null;
  return label;
}

function _visionLabelTokens(raw) {
  const s = String(raw || "").toLowerCase();
  return s.match(/[a-z0-9]+/g) || [];
}

function _visionLabelNameTokenCount(raw) {
  const text = String(raw || "").trim();
  if (!text) return 0;
  const tokens = text.split(/\s+/g);
  let count = 0;
  for (const tokenRaw of tokens) {
    const token = String(tokenRaw || "").replace(/[^A-Za-z0-9'-]/g, "");
    if (!token || token.length < 3) continue;
    if (!/^[A-Z]/.test(token)) continue;
    const lower = token.toLowerCase();
    if (VISION_LABEL_GENERIC_TOKENS.has(lower)) continue;
    if (VISION_LABEL_DETAIL_TOKENS.has(lower)) continue;
    count += 1;
  }
  if (/\b[A-Z][a-z]+[A-Z][a-z]+\b/.test(text)) count += 1;
  return count;
}

function _isGenericVisionLabel(raw) {
  const tokens = _visionLabelTokens(raw);
  if (!tokens.length) return true;
  const genericCount = tokens.filter((token) => VISION_LABEL_GENERIC_TOKENS.has(token)).length;
  const detailCount = tokens.filter((token) => VISION_LABEL_DETAIL_TOKENS.has(token)).length;
  const headCount = tokens.filter((token) => VISION_LABEL_HEAD_TOKENS.has(token)).length;
  if (detailCount === 0 && tokens.length <= 4 && headCount >= 1) return true;
  return detailCount === 0 && genericCount >= Math.max(1, tokens.length - 1);
}

function _visionLabelSpecificityScore(raw) {
  const tokens = _visionLabelTokens(raw);
  if (!tokens.length) return 0;
  const uniqueCount = new Set(tokens).size;
  const detailCount = tokens.filter((token) => VISION_LABEL_DETAIL_TOKENS.has(token)).length;
  let score = 0;
  for (const token of tokens) {
    if (!VISION_LABEL_GENERIC_TOKENS.has(token)) score += 1;
    if (VISION_LABEL_DETAIL_TOKENS.has(token)) score += 1;
  }
  if (tokens.length >= 3 && tokens.length <= 6) score += 1;
  if (uniqueCount >= 3) score += 1;
  if (detailCount >= 2) score += 1;
  if (_isGenericVisionLabel(raw)) score -= 2;
  return Math.max(0, score);
}

function shouldPreferIncomingVisionLabel(existingRaw, incomingRaw) {
  const existing = _normalizeVisionLabel(existingRaw, { maxChars: 32 });
  const incoming = _normalizeVisionLabel(incomingRaw, { maxChars: 32 });
  if (!incoming) return false;
  if (!existing) return true;
  if (incoming === existing) return false;

  const existingGeneric = _isGenericVisionLabel(existing);
  const incomingGeneric = _isGenericVisionLabel(incoming);
  if (existingGeneric && !incomingGeneric) return true;
  if (!existingGeneric && incomingGeneric) return false;

  const existingNameTokens = _visionLabelNameTokenCount(existingRaw);
  const incomingNameTokens = _visionLabelNameTokenCount(incomingRaw);
  if (incomingNameTokens >= 2 && existingNameTokens < 2) return true;
  if (existingNameTokens >= 2 && incomingNameTokens < 2) return false;

  const existingScore = _visionLabelSpecificityScore(existing);
  const incomingScore = _visionLabelSpecificityScore(incoming);
  if (incomingNameTokens > existingNameTokens && incomingScore >= existingScore) return true;
  if (incomingScore > existingScore) return true;
  if (incomingScore < existingScore) return false;
  // Same score: prefer a slightly longer label only if it adds more lexical signal.
  return incoming.length >= existing.length + 6 && _visionLabelTokens(incoming).length >= _visionLabelTokens(existing).length + 1;
}

function shouldBackfillVisionLabel(raw) {
  const label = _normalizeVisionLabel(raw, { maxChars: 32 });
  // Keep fallback non-heuristic: only backfill when realtime provided no label.
  return !label;
}

function extractIntentImageDescriptions(parsed) {
  if (!parsed || typeof parsed !== "object") return [];
  const raw = Array.isArray(parsed.image_descriptions) ? parsed.image_descriptions : [];
  const out = [];
  for (const item of raw) {
    if (!item || typeof item !== "object") continue;
    const imageId = item.image_id ? String(item.image_id) : item.id ? String(item.id) : "";
    const labelRaw = item.label ?? item.description ?? item.text ?? "";
    const label = _normalizeVisionLabel(labelRaw, { maxChars: REALTIME_VISION_LABEL_MAX_CHARS });
    const confidence = typeof item.confidence === "number" ? item.confidence : null;
    if (!imageId || !label) continue;
    out.push({ image_id: imageId, label, confidence });
  }
  return out;
}

function primaryBranchIdFromIconState(iconState) {
  const branches = Array.isArray(iconState?.branches) ? iconState.branches : [];
  if (!branches.length) return null;
  const primaryIcons = new Set(
    (Array.isArray(iconState?.intent_icons) ? iconState.intent_icons : [])
      .filter((it) => String(it?.position_hint || "").toLowerCase() === "primary")
      .map((it) => String(it?.icon_id || "").trim())
      .filter(Boolean)
  );
  if (!primaryIcons.size) return String(branches[0]?.branch_id || "") || null;

  let best = null;
  let bestScore = -1;
  for (const b of branches) {
    const icons = Array.isArray(b?.icons) ? b.icons : [];
    let score = 0;
    for (const icon of icons) {
      if (primaryIcons.has(String(icon || "").trim())) score += 1;
    }
    if (score > bestScore) {
      bestScore = score;
      best = b;
    }
  }
  return best && best.branch_id ? String(best.branch_id) : String(branches[0]?.branch_id || "") || null;
}

function pickDefaultIntentFocusBranchId(iconState = null) {
  const intent = state.intent;
  const icon = iconState || intent?.iconState || null;
  const branches = Array.isArray(icon?.branches) ? icon.branches : [];
  const hasPrimaryCluster = Array.isArray(icon?.intent_icons) && icon.intent_icons.length > 0;

  const existing = intent?.focusBranchId ? String(intent.focusBranchId) : "";
  if (existing) {
    if (existing === "__primary__") {
      if (hasPrimaryCluster) return existing;
    }
    if (branches.some((b) => String(b?.branch_id || "") === existing)) return existing;
  }

  const primary = primaryBranchIdFromIconState(icon);
  if (primary) return primary;
  return "__primary__";
}

function latestIntentSelectionForBranch(branchId) {
  const bid = String(branchId || "");
  if (!bid) return null;
  const sels = Array.isArray(state.intent?.selections) ? state.intent.selections : [];
  let best = null;
  for (const sel of sels) {
    if (String(sel?.branch_id || "") !== bid) continue;
    const r = Number(sel?.round) || 0;
    if (!best || r > (Number(best.round) || 0)) best = sel;
  }
  return best;
}

function upsertIntentSelection({ round, branchId, tokenId }) {
  const intent = state.intent;
  if (!intent) return;
  const r = Math.max(1, Number(round) || 1);
  const bid = String(branchId || "");
  const tok = String(tokenId || "");
  if (!bid || !tok) return;
  const next = (Array.isArray(intent.selections) ? intent.selections : []).filter((sel) => Number(sel?.round) !== r);
  next.push({ round: r, branch_id: bid, token: tok });
  intent.selections = next;
}

const INTENT_BRANCH_TOKEN_STOPWORDS = new Set([
  "the",
  "and",
  "for",
  "with",
  "from",
  "that",
  "this",
  "mode",
  "branch",
  "image",
  "images",
  "icon",
  "icons",
  "intent",
  "token",
  "primary",
  "secondary",
  "left",
  "right",
  "lane",
  "position",
]);

function _intentBranchTokenScore(haystack, branch = null) {
  if (!haystack || !branch || typeof branch !== "object") return 0;
  const tokenSet = new Set();
  const branchKey = _normalizeIntentKey(branch.branch_id);
  if (branchKey) {
    for (const token of branchKey.split("_")) {
      const t = String(token || "").trim();
      if (!t || t.length < 3 || INTENT_BRANCH_TOKEN_STOPWORDS.has(t)) continue;
      tokenSet.add(t);
    }
  }
  const icons = Array.isArray(branch.icons) ? branch.icons : [];
  for (const iconId of icons) {
    const normalized = _normalizeIntentKey(iconId);
    if (!normalized) continue;
    for (const token of normalized.split("_")) {
      const t = String(token || "").trim();
      if (!t || t.length < 3 || INTENT_BRANCH_TOKEN_STOPWORDS.has(t)) continue;
      tokenSet.add(t);
    }
  }
  if (!tokenSet.size) return 0;
  let score = 0;
  for (const token of tokenSet) {
    if (!haystack.includes(token)) continue;
    score += token.length >= 6 ? 2 : 1;
  }
  return score;
}

function inferIntentBranchFromVisionDescriptions() {
  const items = Array.isArray(state.images) ? state.images : [];
  const texts = [];
  for (const item of items) {
    if (item?.visionDesc) texts.push(String(item.visionDesc));
  }
  const haystack = texts.join(" ").toLowerCase().trim();
  if (!haystack) return null;
  const branches = Array.isArray(state.intent?.iconState?.branches) ? state.intent.iconState.branches : [];
  if (!branches.length) return null;
  let bestBranchId = null;
  let bestScore = 0;
  for (const branch of branches) {
    const branchId = String(branch?.branch_id || "").trim();
    if (!branchId) continue;
    let s = _intentBranchTokenScore(haystack, branch);
    if (typeof branch?.confidence === "number" && Number.isFinite(branch.confidence)) {
      s += clamp(Number(branch.confidence), 0, 1) * 0.75;
    }
    if (s > bestScore) {
      bestScore = s;
      bestBranchId = branchId;
    }
  }
  // Require a little evidence before overriding icon-state suggestion.
  if (!bestBranchId || bestScore < 1.5) return null;
  return bestBranchId;
}

function _primaryBranchSuggestion(iconState) {
  const branches = Array.isArray(iconState?.branches) ? iconState.branches : [];
  if (!branches.length) return { branch_id: null, score: 0, ties: 0 };

  const primaryIcons = new Set(
    (Array.isArray(iconState?.intent_icons) ? iconState.intent_icons : [])
      .filter((it) => String(it?.position_hint || "").toLowerCase() === "primary")
      .map((it) => String(it?.icon_id || "").trim())
      .filter(Boolean)
  );
  if (!primaryIcons.size) return { branch_id: null, score: 0, ties: 0 };

  let bestId = null;
  let bestScore = 0;
  let ties = 0;
  for (const b of branches) {
    const bid = b?.branch_id ? String(b.branch_id) : "";
    if (!bid) continue;
    const icons = Array.isArray(b?.icons) ? b.icons : [];
    let score = 0;
    for (const icon of icons) {
      if (primaryIcons.has(String(icon || "").trim())) score += 1;
    }
    if (score > bestScore) {
      bestScore = score;
      bestId = bid;
      ties = score > 0 ? 1 : 0;
    } else if (score > 0 && score === bestScore) {
      ties += 1;
    }
  }
  if (!bestId || bestScore <= 0) return { branch_id: null, score: 0, ties: 0 };
  return { branch_id: bestId, score: bestScore, ties };
}

function _rankIntentBranches(iconState) {
  const branches = Array.isArray(iconState?.branches) ? iconState.branches : [];
  if (!branches.length) return [];
  const anyConf = branches.some((b) => typeof b?.confidence === "number" && Number.isFinite(b.confidence));
  if (!anyConf) return branches.slice();
  // Defensive: even though parseIntentIconsJson sorts, keep this stable if callers mutate iconState.
  const list = branches.map((b, idx) => ({ b, idx }));
  list.sort((a, b) => {
    const ac = typeof a?.b?.confidence === "number" && Number.isFinite(a.b.confidence) ? a.b.confidence : -1;
    const bc = typeof b?.b?.confidence === "number" && Number.isFinite(b.b.confidence) ? b.b.confidence : -1;
    if (bc !== ac) return bc - ac;
    return (Number(a.idx) || 0) - (Number(b.idx) || 0);
  });
  return list.map((it) => it.b);
}

function pickSuggestedIntentBranch(iconState = null) {
  const intent = state.intent;
  const icon = iconState || intent?.iconState || null;
  const branches = Array.isArray(icon?.branches) ? icon.branches : [];
  if (!branches.length) return { branch_id: null, reason: "none", ranked_branch_ids: [] };

  const isRejected = (bid) => {
    const sel = latestIntentSelectionForBranch(bid);
    const tok = sel?.token ? String(sel.token).trim().toUpperCase() : "";
    return tok === "NO_TOKEN";
  };

  const hasBranch = (bid) => branches.some((b) => String(b?.branch_id || "") === bid);
  const findBranchInsensitive = (raw) => {
    const wanted = String(raw || "").trim();
    if (!wanted) return "";
    const exact = branches.find((b) => String(b?.branch_id || "") === wanted);
    if (exact?.branch_id) return String(exact.branch_id);
    const lower = wanted.toLowerCase();
    const match = branches.find((b) => String(b?.branch_id || "").toLowerCase() === lower);
    return match?.branch_id ? String(match.branch_id) : "";
  };

  const rankedBranches = _rankIntentBranches(icon);
  const rankedIds = rankedBranches
    .map((b) => (b?.branch_id ? String(b.branch_id) : ""))
    .filter(Boolean);

  // If the model provided an explicit checkpoint target, treat it as the active suggestion.
  const checkpoint = icon?.checkpoint?.applies_to;
  const checkpointBid = findBranchInsensitive(checkpoint);
  if (checkpointBid && !isRejected(checkpointBid)) {
    return {
      branch_id: checkpointBid,
      reason: "checkpoint",
      ranked_branch_ids: rankedIds,
      checkpoint_branch_id: checkpointBid,
    };
  }

  const anyConf = rankedBranches.some((b) => typeof b?.confidence === "number" && Number.isFinite(b.confidence));
  if (anyConf) {
    for (const b of rankedBranches) {
      const bid = b?.branch_id ? String(b.branch_id) : "";
      if (!bid) continue;
      if (isRejected(bid)) continue;
      return { branch_id: bid, reason: "confidence", ranked_branch_ids: rankedIds, checkpoint_branch_id: checkpointBid || null };
    }
  }

  const primaryInfo = _primaryBranchSuggestion(icon);
  const p = primaryInfo?.branch_id ? String(primaryInfo.branch_id) : "";

  // Use per-image vision descriptions (derived from images) as a tie-breaker or fallback hint.
  const hint = inferIntentBranchFromVisionDescriptions();
  if (hint && hasBranch(hint) && !isRejected(hint)) {
    const primaryRejected = p ? isRejected(p) : true;
    const primaryWeak = (Number(primaryInfo?.score) || 0) <= 1;
    const primaryTied = (Number(primaryInfo?.ties) || 0) > 1;
    if (primaryRejected || primaryWeak || primaryTied) {
      return { branch_id: hint, reason: "vision_hint", ranked_branch_ids: rankedIds, checkpoint_branch_id: checkpointBid || null };
    }
  }

  if (p && hasBranch(p) && !isRejected(p)) {
    return { branch_id: p, reason: "primary_cluster", ranked_branch_ids: rankedIds, checkpoint_branch_id: checkpointBid || null };
  }

  for (const b of rankedBranches) {
    const bid = b?.branch_id ? String(b.branch_id) : "";
    if (!bid) continue;
    if (isRejected(bid)) continue;
    return { branch_id: bid, reason: "first_unrejected", ranked_branch_ids: rankedIds, checkpoint_branch_id: checkpointBid || null };
  }

  // If every branch has been rejected, fall back to the primary (if present) so START remains usable.
  if (p && hasBranch(p)) return { branch_id: p, reason: "all_rejected_primary", ranked_branch_ids: rankedIds, checkpoint_branch_id: checkpointBid || null };
  const first = rankedBranches[0]?.branch_id ? String(rankedBranches[0].branch_id) : "";
  return { branch_id: first || null, reason: "all_rejected_first", ranked_branch_ids: rankedIds, checkpoint_branch_id: checkpointBid || null };
}

function pickSuggestedIntentBranchId(iconState = null) {
  const picked = pickSuggestedIntentBranch(iconState);
  const bid = picked?.branch_id ? String(picked.branch_id) : "";
  return bid || null;
}

function lockIntentFromUi({ source = "ui" } = {}) {
  const intent = state.intent;
  if (!intent || intent.locked) return;

  const iconState = ensureIntentFallbackIconState("lock");
  if (!iconState) return;

  let bid = String(pickSuggestedIntentBranchId(iconState) || "").trim();
  if (bid === "__primary__") bid = "";
  if (!bid) bid = String(primaryBranchIdFromIconState(iconState) || "").trim();
  if (!bid) bid = String(pickDefaultIntentFocusBranchId(iconState) || "").trim();
  if (!bid) return;

  appendIntentTrace({
    kind: "ui_accept",
    source: source ? String(source) : "ui",
    round: Math.max(1, Number(intent.round) || 1),
    branch_id: bid,
    icon_frame_id: iconState?.frame_id ? String(iconState.frame_id) : null,
  }).catch(() => {});

  // Persist the user's final choice as a YES on the current round for debugging/replay.
  const round = Math.max(1, Number(intent.round) || 1);
  upsertIntentSelection({ round, branchId: bid, tokenId: "YES_TOKEN" });
  intent.focusBranchId = bid;
  intent.uiHideSuggestion = false;
  scheduleIntentStateWrite({ immediate: true });
  lockIntentToBranch(bid).catch((err) => console.error(err));
}

function applyIntentSelection(branchId, tokenId) {
  const intent = state.intent;
  if (!intent || intent.locked) return;
  const bid = String(branchId || intent.focusBranchId || pickSuggestedIntentBranchId(intent.iconState) || "").trim();
  if (!bid) return;
  const tok = String(tokenId || "")
    .trim()
    .toUpperCase();
  if (!tok) return;

  // Prevent users from spamming feedback while a new model frame is in flight.
  if (intent.pending || intentInferenceTimer) {
    showToast("Intent updating…", "tip", 1600);
    return;
  }

  const round = Math.max(1, Number(intent.round) || 1);
  if (tok === "YES_TOKEN") {
    lockIntentFromUi({ source: "yes_token" });
    return;
  }

  if (tok !== "NO_TOKEN") return;

  // NO: hide the current suggestion and load another candidate.
  upsertIntentSelection({ round, branchId: bid, tokenId: "NO_TOKEN" });
  intent.focusBranchId = null;
  intent.uiHideSuggestion = true;
  intent.pending = true;
  intent.pendingAt = Date.now();
  intent.round = round + 1;
  appendIntentTrace({
    kind: "ui_reject",
    source: "no_token",
    round,
    branch_id: bid,
    icon_frame_id: intent.iconState?.frame_id ? String(intent.iconState.frame_id) : null,
  }).catch(() => {});
  scheduleIntentStateWrite({ immediate: true });
  scheduleIntentInference({ immediate: true, reason: "reject" });
  requestRender();
}

async function lockIntentToBranch(branchId) {
  const intent = state.intent;
  if (!intent || intent.locked) return false;
  await ensureRun();

  intent.locked = true;
  intent.lockedAt = Date.now();
  intent.lockedBranchId = String(branchId || intent.focusBranchId || "") || null;
  intent.forceChoice = false;
  intent.pending = false;
  intent.pendingPath = null;
  intent.pendingAt = 0;
  intent.pendingFrameId = null;

  appendIntentTrace({
    kind: "intent_locked",
    branch_id: intent.lockedBranchId ? String(intent.lockedBranchId) : null,
    round: Math.max(1, Number(intent.round) || 1),
    selection_count: Array.isArray(intent.selections) ? intent.selections.length : 0,
    icon_frame_id: intent.iconState?.frame_id ? String(intent.iconState.frame_id) : null,
  }).catch(() => {});

  // Stop realtime session (best-effort).
  clearTimeout(intentInferenceTimer);
  intentInferenceTimer = null;
  clearTimeout(intentInferenceTimeout);
  intentInferenceTimeout = null;
  stopIntentTicker();
  intent.rtState = "off";
  intent.disabledReason = null;
  if (state.ptySpawned) {
    invoke("write_pty", { data: `${PTY_COMMANDS.INTENT_RT_STOP}\n` }).catch(() => {});
  }

  // Persist locked intent as a run artifact for downstream prompting/recommendations.
  const lockedPayload = {
    schema: "cue.intent_locked",
    schema_version: 1,
    locked_at_ms: Number(intent.lockedAt) || 0,
    locked_branch_id: intent.lockedBranchId,
    started_at_ms: Number(intent.startedAt) || 0,
    deadline_at_ms: INTENT_TIMER_ENABLED ? Number(intent.deadlineAt) || 0 : 0,
    round: Math.max(1, Number(intent.round) || 1),
    total_rounds: INTENT_ROUNDS_ENABLED ? Math.max(1, Number(intent.totalRounds) || 3) : 0,
    focus_branch_id: intent.focusBranchId ? String(intent.focusBranchId) : null,
    selections: Array.isArray(intent.selections) ? intent.selections : [],
    icon_state: intent.iconState || null,
    icon_state_at_ms: Number(intent.iconStateAt) || 0,
  };
  const outPath = `${state.runDir}/${INTENT_LOCKED_FILENAME}`;
  await writeTextFile(outPath, JSON.stringify(lockedPayload, null, 2)).catch(() => {});
  scheduleIntentStateWrite({ immediate: true });

  // Reveal the normal UI.
  syncIntentModeClass();
  updateEmptyCanvasHint();
  renderQuickActions();
  renderHudReadout();
  requestRender();
  showToast("Intent locked.", "tip", 1800);
  return true;
}

let thumbObserver = null;
function ensureThumbObserver() {
  if (thumbObserver) return;
  if (!("IntersectionObserver" in window)) return;
  thumbObserver = new IntersectionObserver(
    (entries) => {
      for (const entry of entries) {
        if (!entry.isIntersecting) continue;
        const imgEl = entry.target;
        const path = imgEl?.dataset?.path;
        if (!path) continue;
        thumbObserver.unobserve(imgEl);
        ensureImageUrl(path)
          .then((url) => {
            if (url) imgEl.src = url;
          })
          .catch(() => {});
      }
    },
    { root: els.filmstrip || null, rootMargin: "220px" }
  );
}

function getOrCreateImageCacheRecord(path, cache = state.imageCache) {
  const existing = cache.get(path);
  if (existing) return existing;
  const rec = { url: null, urlPromise: null, imgPromise: null };
  cache.set(path, rec);
  return rec;
}

async function ensureImageUrl(path, cache = state.imageCache) {
  if (!path) return null;
  const rec = getOrCreateImageCacheRecord(path, cache);
  if (rec.url) return rec.url;
  if (rec.urlPromise) return await rec.urlPromise;
  rec.urlPromise = (async () => {
    const data = await readBinaryFile(path);
    const blob = new Blob([data], { type: mimeFromPath(path) });
    const url = URL.createObjectURL(blob);
    rec.url = url;
    return url;
  })();
  try {
    return await rec.urlPromise;
  } catch (err) {
    rec.urlPromise = null;
    throw err;
  }
}

function isBrowserImagePath(path) {
  const ext = extname(path).toLowerCase();
  return FILE_BROWSER_IMAGE_EXTS.has(ext);
}

function fileBrowserIsSuppressedArtifactName(name) {
  const lowered = String(name || "").trim().toLowerCase();
  if (!lowered) return false;
  if (lowered === "_raw_provider_outputs") return true;
  if (lowered === "manifest.json") return true;
  if (/^contact_sheet(?:_.*)?\.(png|jpg|jpeg|webp)$/i.test(lowered)) return true;
  return false;
}

function parentDirPath(path) {
  const raw = String(path || "").trim();
  if (!raw) return null;
  const trimmed = raw.replace(/[\\/]+$/, "");
  if (!trimmed) return null;
  if (trimmed === "/" || trimmed === "\\") return null;
  const slashIdx = Math.max(trimmed.lastIndexOf("/"), trimmed.lastIndexOf("\\"));
  if (slashIdx < 0) return null;
  if (slashIdx === 0) return trimmed.slice(0, 1);
  if (slashIdx === 2 && /^[A-Za-z]:/.test(trimmed)) return `${trimmed.slice(0, 2)}\\`;
  return trimmed.slice(0, slashIdx);
}

function fileBrowserDisplayPathLabel({ cwd = "", rootDir = "" } = {}) {
  const current = String(cwd || "").trim();
  const root = String(rootDir || "").trim();
  const fallback = current || root;
  if (!fallback) return "No folder selected";
  const normalizedCurrent = current.replace(/[\\/]+$/, "");
  const normalizedRoot = root.replace(/[\\/]+$/, "");
  const leaf = basename(normalizedCurrent || normalizedRoot) || fallback;
  if (!normalizedCurrent || !normalizedRoot || normalizedCurrent === normalizedRoot) {
    return leaf;
  }
  const rootLeaf = basename(normalizedRoot) || normalizedRoot;
  if (normalizedCurrent.startsWith(normalizedRoot)) {
    const relative = normalizedCurrent.slice(normalizedRoot.length).replace(/^[\\/]+/, "");
    const parts = relative.split(/[\\/]+/).filter(Boolean);
    if (parts.length === 1) return `${rootLeaf}/${parts[0]}`;
    if (parts.length > 1) return `${rootLeaf}/.../${parts[parts.length - 1]}`;
  }
  return `${rootLeaf}/.../${leaf}`;
}

function normalizeLocalFsPath(rawPath) {
  let path = String(rawPath || "").trim();
  if (!path) return "";
  if (path.startsWith("file://")) {
    try {
      const u = new URL(path);
      path = decodeURIComponent(u.pathname || "");
      if (/^\/[A-Za-z]:\//.test(path)) {
        path = path.slice(1);
      }
    } catch {
      path = path.replace(/^file:\/\//i, "");
      try {
        path = decodeURIComponent(path);
      } catch {
        // ignore
      }
    }
  }
  return path;
}

function isAbsoluteLocalFsPath(path) {
  const target = String(path || "").trim();
  if (!target) return false;
  if (target.startsWith("/") || target.startsWith("\\")) return true;
  return /^[A-Za-z]:[\\/]/.test(target);
}

async function resolveLocalFsPathMaybeRelative(baseDir, rawPath) {
  const target = normalizeLocalFsPath(rawPath);
  if (!target) return "";
  if (isAbsoluteLocalFsPath(target)) return target;
  const base = String(baseDir || "").trim();
  if (!base) return "";
  try {
    return normalizeLocalFsPath(await join(base, target));
  } catch {
    return "";
  }
}

async function fileBrowserLoadImportPathMap(dir) {
  const targetDir = String(dir || "").trim();
  const out = new Map();
  if (!targetDir) return out;
  const manifestCandidates = [];
  try {
    manifestCandidates.push(await join(targetDir, "manifest.json"));
  } catch {
    manifestCandidates.push(`${targetDir}/manifest.json`);
  }
  const parent = parentDirPath(targetDir);
  if (parent) {
    try {
      manifestCandidates.push(await join(parent, "manifest.json"));
    } catch {
      manifestCandidates.push(`${parent}/manifest.json`);
    }
  }
  let payload = null;
  for (const candidate of manifestCandidates) {
    if (!candidate) continue;
    try {
      payload = JSON.parse(await readTextFile(candidate));
      if (payload && typeof payload === "object") break;
    } catch {
      payload = null;
    }
  }
  if (!payload || typeof payload !== "object") {
    return out;
  }
  const items = Array.isArray(payload?.items) ? payload.items : [];
  for (const item of items) {
    if (!item || typeof item !== "object") continue;
    const rawOutput =
      item.output ??
      item.preview ??
      item.rendered ??
      item.styled ??
      item.preview_path ??
      item.path ??
      "";
    const rawInput =
      item.input ??
      item.source ??
      item.original ??
      item.source_path ??
      item.input_path ??
      item.original_path ??
      "";
    const outputPath = await resolveLocalFsPathMaybeRelative(targetDir, rawOutput);
    const inputPath = await resolveLocalFsPathMaybeRelative(targetDir, rawInput);
    if (!outputPath || !inputPath) continue;
    if (!isBrowserImagePath(outputPath) || !isBrowserImagePath(inputPath)) continue;
    out.set(outputPath, inputPath);
    const outputKey = fileBrowserPathMapKey(outputPath);
    if (outputKey) out.set(outputKey, inputPath);
    const outBase = basename(outputPath);
    if (outBase) out.set(`name:${outBase}`, inputPath);
    if (outBase) out.set(`name:${outBase.toLowerCase()}`, inputPath);
    const outStem = outBase.replace(/\.[^.]+$/, "");
    if (outStem) out.set(`stem:${outStem}`, inputPath);
    if (outStem) out.set(`stem:${outStem.toLowerCase()}`, inputPath);
    const relaxedStem = outStem.replace(/_wire_subject(?:-\d+)?$/i, "");
    if (relaxedStem && relaxedStem !== outStem) out.set(`stem:${relaxedStem}`, inputPath);
    if (relaxedStem && relaxedStem !== outStem) out.set(`stem:${relaxedStem.toLowerCase()}`, inputPath);
  }
  return out;
}

function canvasWorldPointFromClient(clientX, clientY) {
  const cx = Number(clientX);
  const cy = Number(clientY);
  if (!Number.isFinite(cx) || !Number.isFinite(cy)) return null;
  const wrapRect = els.canvasWrap?.getBoundingClientRect?.();
  if (!wrapRect) return null;
  if (cx < wrapRect.left || cx > wrapRect.right || cy < wrapRect.top || cy > wrapRect.bottom) return null;
  const overlayRect = els.overlayCanvas?.getBoundingClientRect?.() || wrapRect;
  return canvasScreenCssToWorldCss({ x: cx - overlayRect.left, y: cy - overlayRect.top });
}

function fileBrowserCreateDragGhost(path) {
  const targetPath = String(path || "").trim();
  if (!targetPath) return null;
  const ghost = document.createElement("div");
  ghost.className = "file-browser-drag-ghost";
  ghost.setAttribute("aria-hidden", "true");
  ghost.dataset.path = targetPath;
  const thumb = document.createElement("img");
  thumb.className = "file-browser-drag-ghost-thumb";
  thumb.alt = "";
  thumb.src = THUMB_PLACEHOLDER_SRC;
  ghost.appendChild(thumb);
  const label = document.createElement("div");
  label.className = "file-browser-drag-ghost-label";
  const base = basename(targetPath) || "image";
  label.textContent = base.length > 20 ? `${base.slice(0, 19)}…` : base;
  ghost.appendChild(label);
  document.body.appendChild(ghost);
  const cache = state.fileBrowser?.thumbCache || state.imageCache;
  ensureImageUrl(targetPath, cache)
    .then((url) => {
      if (!url || !ghost.isConnected) return;
      thumb.src = url;
    })
    .catch(() => {});
  return ghost;
}

function fileBrowserUpdateDragGhost(el, clientX, clientY) {
  if (!el) return;
  const cx = Number(clientX);
  const cy = Number(clientY);
  if (!Number.isFinite(cx) || !Number.isFinite(cy)) return;
  el.classList.remove("is-drop");
  el.style.transition = "none";
  el.style.opacity = "0.98";
  el.style.filter = "";
  el.style.left = `${Math.round(cx)}px`;
  el.style.top = `${Math.round(cy)}px`;
  el.style.transform = "translate3d(-34%, -76%, 0) scale(0.84)";
}

function fileBrowserDestroyDragGhost(el) {
  if (!el) return;
  try {
    el.remove();
  } catch {
    // ignore
  }
}

function fileBrowserAnimateDropPulse(clientX, clientY) {
  if (!els.canvasWrap) return;
  const cx = Number(clientX);
  const cy = Number(clientY);
  if (!Number.isFinite(cx) || !Number.isFinite(cy)) return;
  const wrapRect = els.canvasWrap.getBoundingClientRect();
  if (!wrapRect) return;
  if (cx < wrapRect.left || cx > wrapRect.right || cy < wrapRect.top || cy > wrapRect.bottom) return;
  const pulse = document.createElement("div");
  pulse.className = "file-browser-drop-pulse";
  pulse.style.left = `${Math.round(cx - wrapRect.left)}px`;
  pulse.style.top = `${Math.round(cy - wrapRect.top)}px`;
  els.canvasWrap.appendChild(pulse);
  requestAnimationFrame(() => {
    pulse.classList.add("is-live");
  });
  setTimeout(() => {
    try {
      pulse.remove();
    } catch {
      // ignore
    }
  }, 420);
}

function fileBrowserAnimateDropGhost(ghostEl, { clientX, clientY, path = "" } = {}) {
  const cx = Number(clientX);
  const cy = Number(clientY);
  if (!Number.isFinite(cx) || !Number.isFinite(cy)) {
    if (ghostEl) fileBrowserDestroyDragGhost(ghostEl);
    return;
  }
  const ghost = ghostEl || fileBrowserCreateDragGhost(path);
  fileBrowserAnimateDropPulse(cx, cy);
  if (!ghost) return;
  ghost.classList.add("is-drop");
  ghost.style.left = `${Math.round(cx)}px`;
  ghost.style.top = `${Math.round(cy)}px`;
  ghost.style.opacity = "1";
  ghost.style.filter = "";
  ghost.style.transition =
    "transform 220ms cubic-bezier(0.22, 1, 0.36, 1), opacity 220ms ease-out, filter 220ms ease-out";
  requestAnimationFrame(() => {
    if (!ghost.isConnected) return;
    ghost.style.transform = "translate3d(-50%, -50%, 0) scale(2.08)";
    ghost.style.opacity = "0";
    ghost.style.filter = "saturate(1.2) brightness(1.12)";
  });
  const cleanup = () => fileBrowserDestroyDragGhost(ghost);
  ghost.addEventListener("transitionend", cleanup, { once: true });
  setTimeout(cleanup, 320);
}

function clearFileBrowserThumbCache({ keepPaths = null } = {}) {
  const fb = state.fileBrowser;
  if (!fb?.thumbCache) return;
  const keep = keepPaths instanceof Set ? keepPaths : null;
  for (const [path, rec] of fb.thumbCache.entries()) {
    if (keep && keep.has(path)) continue;
    const url = rec?.url;
    if (url) {
      try {
        URL.revokeObjectURL(url);
      } catch {
        // ignore
      }
    }
    fb.thumbCache.delete(path);
  }
}

function fileBrowserRenderMessage(message, { isError = false } = {}) {
  if (!els.fileBrowserList) return;
  const div = document.createElement("div");
  div.className = `file-browser-message${isError ? " is-error" : ""}`;
  div.textContent = String(message || "");
  els.fileBrowserList.innerHTML = "";
  els.fileBrowserList.appendChild(div);
}

function ensureFileBrowserObserver() {
  const fb = state.fileBrowser;
  if (!fb?.enabled) return null;
  if (!els.fileBrowserList) return null;
  if (fb.observer) return fb.observer;
  if (!("IntersectionObserver" in window)) return null;
  fb.observer = new IntersectionObserver(
    (entries) => {
      for (const entry of entries) {
        if (!entry.isIntersecting) continue;
        const imgEl = entry.target;
        const path = imgEl?.dataset?.path ? String(imgEl.dataset.path) : "";
        if (!path) continue;
        fb.observer.unobserve(imgEl);
        ensureImageUrl(path, fb.thumbCache)
          .then((url) => {
            if (url && imgEl && imgEl.dataset.path === path) imgEl.src = url;
          })
          .catch(() => {});
      }
    },
    { root: els.fileBrowserList, rootMargin: "140px" }
  );
  return fb.observer;
}

function fileBrowserSetSelectedPath(path) {
  const fb = state.fileBrowser;
  if (!fb) return;
  fb.selectedPath = path ? String(path) : null;
  if (!els.fileBrowserList) return;
  const rows = els.fileBrowserList.querySelectorAll(".file-browser-item");
  rows.forEach((row) => {
    const rowPath = String(row?.dataset?.path || "");
    const selected = Boolean(fb.selectedPath && rowPath && rowPath === fb.selectedPath);
    row.classList.toggle("is-selected", selected);
    row.setAttribute("aria-selected", selected ? "true" : "false");
  });
}

function fileBrowserEntriesForUi() {
  const fb = state.fileBrowser;
  if (!fb) return [];
  const list = Array.isArray(fb.entries) ? fb.entries : [];
  return list.slice(0, 550);
}

function renderFileBrowserDock() {
  const fb = state.fileBrowser;
  if (!fb?.enabled) return;
  if (!els.fileBrowserDock || !els.fileBrowserList) return;

  if (els.fileBrowserPath) {
    const fullPath = String(fb.cwd || fb.rootDir || "").trim();
    els.fileBrowserPath.textContent = fileBrowserDisplayPathLabel({ cwd: fb.cwd, rootDir: fb.rootDir });
    els.fileBrowserPath.title = fullPath || "No folder selected";
  }
  if (els.fileBrowserUp) {
    els.fileBrowserUp.disabled = Boolean(!fb.cwd || !parentDirPath(fb.cwd));
  }
  if (els.fileBrowserRefresh) {
    els.fileBrowserRefresh.disabled = Boolean(!fb.cwd || fb.loading);
  }
  if (els.fileBrowserChoose) {
    els.fileBrowserChoose.disabled = Boolean(fb.loading);
  }

  if (!fb.cwd) {
    fileBrowserRenderMessage("Choose Folder to browse local images.");
    return;
  }
  if (fb.loading) {
    fileBrowserRenderMessage("Loading folder…");
    return;
  }
  if (fb.error) {
    fileBrowserRenderMessage(String(fb.error || "Unable to read folder."), { isError: true });
    return;
  }

  const entries = fileBrowserEntriesForUi();
  if (!entries.length) {
    fileBrowserRenderMessage("No image files found in this folder.");
    return;
  }

  const observer = ensureFileBrowserObserver();
  const frag = document.createDocumentFragment();
  for (const entry of entries) {
    const row = document.createElement("div");
    row.className = "file-browser-item";
    row.dataset.path = entry.path;
    row.dataset.kind = entry.kind;
    if (entry.kind === "file") {
      row.dataset.importPath = String(entry.importPath || entry.path || "");
    }
    row.setAttribute("role", "option");
    row.setAttribute("aria-selected", "false");

    const thumb = document.createElement(entry.kind === "file" ? "img" : "div");
    thumb.className = "file-browser-thumb";
    if (entry.kind === "file") {
      thumb.alt = "";
      thumb.src = THUMB_PLACEHOLDER_SRC;
      thumb.dataset.path = entry.path;
      if (observer) observer.observe(thumb);
      else {
        ensureImageUrl(entry.path, fb.thumbCache)
          .then((url) => {
            if (url) thumb.src = url;
          })
          .catch(() => {});
      }
    }

    const name = document.createElement("div");
    name.className = "file-browser-name";
    name.textContent = entry.name;
    if (entry.kind === "file" && entry.importPath && entry.importPath !== entry.path) {
      name.title = `${entry.path}\nimports: ${entry.importPath}`;
    } else {
      name.title = entry.path;
    }

    row.appendChild(thumb);
    row.appendChild(name);
    frag.appendChild(row);
  }
  els.fileBrowserList.innerHTML = "";
  els.fileBrowserList.appendChild(frag);
  fileBrowserSetSelectedPath(fb.selectedPath);
}

async function fileBrowserResolveEntryKind(entry, path) {
  const target = String(path || "").trim();
  if (!target) return "other";
  if (/[\\/]$/.test(target)) return "dir";
  if (entry && typeof entry === "object" && Object.prototype.hasOwnProperty.call(entry, "children")) {
    if (Array.isArray(entry.children)) return "dir";
    if (entry.children === null) return "file";
  }
  try {
    await readDir(target, { recursive: false });
    return "dir";
  } catch {
    return "file";
  }
}

async function normalizeFileBrowserEntries(rawEntries, { importPathMap = null } = {}) {
  const dirs = [];
  const files = [];
  const entries = await Promise.all(
    (Array.isArray(rawEntries) ? rawEntries : []).map(async (entry) => {
      const path = entry?.path ? String(entry.path).trim() : "";
      if (!path) return null;
      const name = String(entry?.name || basename(path) || path).trim();
      if (!name || name.startsWith(".")) return null;
      if (fileBrowserIsSuppressedArtifactName(name)) return null;
      const resolvedKind = await fileBrowserResolveEntryKind(entry, path);
      if (resolvedKind === "dir") return { name, path, kind: "dir" };
      const ext = extname(path).toLowerCase();
      if (!FILE_BROWSER_IMAGE_EXTS.has(ext)) return null;
      let mappedImportPath = "";
      if (importPathMap instanceof Map) {
        mappedImportPath = normalizeLocalFsPath(importPathMap.get(path) || "");
        if (!mappedImportPath) {
          mappedImportPath = normalizeLocalFsPath(importPathMap.get(`name:${basename(path)}`) || "");
        }
        if (!mappedImportPath) {
          const stem = basename(path).replace(/\.[^.]+$/, "");
          mappedImportPath = normalizeLocalFsPath(importPathMap.get(`stem:${stem}`) || "");
        }
        if (!mappedImportPath) {
          const relaxed = basename(path).replace(/\.[^.]+$/, "").replace(/_wire_subject(?:-\d+)?$/i, "");
          if (relaxed) mappedImportPath = normalizeLocalFsPath(importPathMap.get(`stem:${relaxed}`) || "");
        }
      }
      const importPath = mappedImportPath && isBrowserImagePath(mappedImportPath) ? mappedImportPath : path;
      return { name, path, importPath, kind: "file", ext };
    })
  );
  for (const entry of entries) {
    if (!entry) continue;
    if (entry.kind === "dir") dirs.push(entry);
    else if (entry.kind === "file") files.push(entry);
  }
  dirs.sort((a, b) => a.name.localeCompare(b.name));
  files.sort((a, b) => a.name.localeCompare(b.name));
  return [...dirs, ...files];
}

async function fileBrowserLoadDir(dir, { pushHistory = true } = {}) {
  const fb = state.fileBrowser;
  if (!fb?.enabled) return;
  const target = String(dir || "").trim();
  if (!target) return;
  const seq = (Number(fb.loadSeq) || 0) + 1;
  fb.loadSeq = seq;
  fb.loading = true;
  fb.error = null;
  if (pushHistory && fb.cwd && fb.cwd !== target) {
    fb.history.push(fb.cwd);
    if (fb.history.length > 80) fb.history.shift();
  }
  fb.cwd = target;
  renderFileBrowserDock();
  let entries = [];
  try {
    entries = await readDir(target, { recursive: false });
  } catch (err) {
    if (fb.loadSeq !== seq) return;
    fb.loading = false;
    fb.error = err?.message ? `File browser: ${err.message}` : "File browser: cannot read folder";
    fb.entries = [];
    fb.importPathMap = new Map();
    renderFileBrowserDock();
    return;
  }
  if (fb.loadSeq !== seq) return;
  let importPathMap = null;
  try {
    importPathMap = await fileBrowserLoadImportPathMap(target);
  } catch {
    importPathMap = null;
  }
  const normalized = await normalizeFileBrowserEntries(entries, { importPathMap });
  if (fb.loadSeq !== seq) return;
  fb.importPathMap = importPathMap instanceof Map ? importPathMap : new Map();
  const keepThumbs = new Set(normalized.filter((it) => it.kind === "file").map((it) => it.path));
  clearFileBrowserThumbCache({ keepPaths: keepThumbs });
  fb.entries = normalized;
  fb.loading = false;
  fb.error = null;
  if (fb.selectedPath && !fb.entries.some((it) => it.path === fb.selectedPath)) {
    fb.selectedPath = null;
  }
  renderFileBrowserDock();
}

async function fileBrowserPickFolder() {
  const fb = state.fileBrowser;
  if (!fb?.enabled) return;
  bumpInteraction();
  const picked = await open({ directory: true, multiple: false });
  const dir = Array.isArray(picked) ? picked[0] : picked;
  if (!dir) return;
  const root = String(dir).trim();
  fb.rootDir = root || null;
  localStorage.setItem(FILE_BROWSER_ROOT_DIR_LS_KEY, root);
  await fileBrowserLoadDir(root, { pushHistory: false });
}

async function fileBrowserRefresh() {
  const fb = state.fileBrowser;
  if (!fb?.enabled || !fb.cwd) return;
  await fileBrowserLoadDir(fb.cwd, { pushHistory: false });
}

async function fileBrowserNavigateTo(path) {
  const fb = state.fileBrowser;
  if (!fb?.enabled) return;
  const target = String(path || "").trim();
  if (!target) return;
  await fileBrowserLoadDir(target);
}

async function fileBrowserNavigateUp() {
  const fb = state.fileBrowser;
  if (!fb?.enabled || !fb.cwd) return;
  const parent = parentDirPath(fb.cwd);
  if (!parent) return;
  await fileBrowserNavigateTo(parent);
}

async function fileBrowserImportPath(path, { focus = false } = {}) {
  const src = String(path || "").trim();
  if (!src || !isBrowserImagePath(src)) return;
  const center = canvasScreenCssToWorldCss(_defaultImportPointCss());
  await importLocalPathsAtCanvasPoint([src], center, {
    source: "browser",
    focusImported: focus,
    idPrefix: "dock",
  });
}

function fileBrowserCancelPendingClickImport() {
  const fb = state.fileBrowser;
  if (!fb) return;
  clearTimeout(fb.clickImportTimer);
  fb.clickImportTimer = null;
}

function fileBrowserScheduleClickImport(path) {
  const fb = state.fileBrowser;
  if (!fb?.enabled) return;
  fileBrowserCancelPendingClickImport();
  const target = String(path || "").trim();
  if (!target) return;
  fb.clickImportTimer = setTimeout(() => {
    fb.clickImportTimer = null;
    fileBrowserImportPath(target, { focus: false }).catch((err) => console.error(err));
  }, 210);
}

function fileBrowserSetDragPath(path) {
  const fb = state.fileBrowser;
  if (!fb) return;
  clearTimeout(fb.dragClearTimer);
  fb.dragClearTimer = null;
  fb.draggingPath = path ? String(path) : null;
}

function fileBrowserImportPathForEntry(entry) {
  const mapped = normalizeLocalFsPath(String(entry?.importPath || ""));
  if (mapped && isBrowserImagePath(mapped)) return mapped;
  const plain = normalizeLocalFsPath(String(entry?.path || ""));
  if (plain && isBrowserImagePath(plain)) return plain;
  return "";
}

function fileBrowserImportPathForRow(row) {
  if (!row) return "";
  return fileBrowserImportPathForEntry({
    path: String(row.dataset?.path || ""),
    importPath: String(row.dataset?.importPath || ""),
  });
}

function fileBrowserPathMapKey(path) {
  const target = normalizeLocalFsPath(path);
  if (!target) return "";
  return target.replace(/\\/g, "/").normalize("NFC");
}

function fileBrowserResolveMappedPath(path, map = null) {
  const target = normalizeLocalFsPath(path);
  if (!target || !isBrowserImagePath(target)) return "";
  const candidateMap =
    map instanceof Map
      ? map
      : state.fileBrowser?.importPathMap instanceof Map
        ? state.fileBrowser.importPathMap
        : null;
  if (!(candidateMap instanceof Map) || candidateMap.size <= 0) return target;
  const targetKey = fileBrowserPathMapKey(target);
  const name = basename(target);
  const stem = name.replace(/\.[^.]+$/, "");
  const relaxed = stem.replace(/_wire_subject(?:-\d+)?$/i, "");
  const candidates = [target, targetKey, `name:${name}`, `name:${name.toLowerCase()}`, `stem:${stem}`, `stem:${stem.toLowerCase()}`];
  if (relaxed && relaxed !== stem) candidates.push(`stem:${relaxed}`);
  if (relaxed && relaxed !== stem) candidates.push(`stem:${relaxed.toLowerCase()}`);
  for (const key of candidates) {
    const mapped = normalizeLocalFsPath(candidateMap.get(key) || "");
    if (mapped && isBrowserImagePath(mapped)) return mapped;
  }
  return target;
}

async function fileBrowserDeriveOriginalForWirePath(path) {
  const target = normalizeLocalFsPath(path);
  if (!target || !/_wire_subject(?:-\d+)?\.[^.]+$/i.test(target)) return "";
  const outDir = parentDirPath(target);
  const rootDir = outDir ? parentDirPath(outDir) : null;
  if (!rootDir) return "";
  const stem = basename(target).replace(/\.[^.]+$/, "").replace(/_wire_subject(?:-\d+)?$/i, "");
  if (!stem) return "";
  const imageExts = [".png", ".jpg", ".jpeg", ".webp", ".heic", ".bmp", ".tif", ".tiff"];
  const imagesDir = await join(rootDir, "images").catch(() => "");
  if (!imagesDir) return "";
  for (const ext of imageExts) {
    const candidate = await join(imagesDir, `${stem}${ext}`).catch(() => "");
    if (!candidate) continue;
    const ok = await exists(candidate).catch(() => false);
    if (ok) return normalizeLocalFsPath(candidate);
  }
  return "";
}

async function fileBrowserResolveImportPaths(paths) {
  const list = (Array.isArray(paths) ? paths : [paths]).map((p) => normalizeLocalFsPath(p)).filter(Boolean);
  if (!list.length) return [];
  const fb = state.fileBrowser;
  let activeMap = fb?.importPathMap instanceof Map ? fb.importPathMap : null;
  const out = [];
  let triedLazyLoad = false;
  for (const raw of list) {
    let resolved = fileBrowserResolveMappedPath(raw, activeMap);
    if (resolved === raw && /_wire_subject(?:-\d+)?\.[^.]+$/i.test(raw) && !triedLazyLoad) {
      triedLazyLoad = true;
      try {
        const cwd = String(fb?.cwd || "").trim();
        if (cwd) {
          activeMap = await fileBrowserLoadImportPathMap(cwd);
          if (fb) fb.importPathMap = activeMap instanceof Map ? activeMap : new Map();
        }
      } catch {
        // ignore
      }
      resolved = fileBrowserResolveMappedPath(raw, activeMap);
    }
    if (resolved === raw && /_wire_subject(?:-\d+)?\.[^.]+$/i.test(raw)) {
      try {
        const derived = await fileBrowserDeriveOriginalForWirePath(raw);
        if (derived && isBrowserImagePath(derived)) resolved = derived;
      } catch {
        // ignore
      }
    }
    out.push(resolved || raw);
  }
  return out;
}

function fileBrowserClearDragPathDeferred(delayMs = 320) {
  const fb = state.fileBrowser;
  if (!fb) return;
  clearTimeout(fb.dragClearTimer);
  const delay = Math.max(0, Number(delayMs) || 0);
  fb.dragClearTimer = setTimeout(() => {
    fb.dragClearTimer = null;
    fb.draggingPath = null;
  }, delay);
}

function fileBrowserReadInternalDragPath(dataTransfer) {
  const fallback = normalizeLocalFsPath(state.fileBrowser?.draggingPath || "");
  if (!dataTransfer) return fallback;
  if (typeof dataTransfer.getData === "function") {
    const custom = normalizeLocalFsPath(dataTransfer.getData(FILE_BROWSER_DRAG_MIME) || "");
    if (custom) return custom;
    const legacyCustom = normalizeLocalFsPath(dataTransfer.getData(LEGACY_FILE_BROWSER_DRAG_MIME) || "");
    if (legacyCustom) return legacyCustom;
    const plain = normalizeLocalFsPath(dataTransfer.getData("text/plain") || "");
    if (plain && isBrowserImagePath(plain)) return plain;
  }
  if (fallback) return fallback;
  return "";
}

async function initializeFileBrowserDock() {
  const fb = state.fileBrowser;
  if (!fb?.enabled) return;
  if (!els.fileBrowserDock) return;
  if (els.fileBrowserChoose) {
    els.fileBrowserChoose.addEventListener("click", () => {
      fileBrowserPickFolder().catch((err) => console.error(err));
    });
  }
  if (els.fileBrowserUp) {
    els.fileBrowserUp.addEventListener("click", () => {
      fileBrowserNavigateUp().catch((err) => console.error(err));
    });
  }
  if (els.fileBrowserRefresh) {
    els.fileBrowserRefresh.addEventListener("click", () => {
      fileBrowserRefresh().catch((err) => console.error(err));
    });
  }
  if (els.fileBrowserList) {
    els.fileBrowserList.tabIndex = 0;

    const endManualPointerDrag = ({ clearPath = true, keepGhost = false } = {}) => {
      const drag = fb.manualDrag;
      if (!drag) return null;
      const ghostEl = drag.ghostEl || null;
      if (ghostEl && !keepGhost) {
        fileBrowserDestroyDragGhost(drag.ghostEl);
      }
      drag.ghostEl = null;
      drag.active = false;
      drag.pointerId = null;
      drag.path = null;
      drag.previewPath = null;
      drag.moved = false;
      els.canvasWrap?.classList?.remove("is-browser-drag-over");
      if (clearPath) fileBrowserClearDragPathDeferred(80);
      return keepGhost ? ghostEl : null;
    };

    const onManualPointerMove = (event) => {
      const drag = fb.manualDrag;
      if (!drag?.active) return;
      if (drag.pointerId !== null && Number(event?.pointerId) !== Number(drag.pointerId)) return;
      const cx = Number(event?.clientX) || 0;
      const cy = Number(event?.clientY) || 0;
      const dx = cx - (Number(drag.startX) || 0);
      const dy = cy - (Number(drag.startY) || 0);
      const ghostPath = String(drag.previewPath || drag.path || "").trim();
      if (!drag.moved && Math.hypot(dx, dy) > 2) {
        drag.moved = true;
        if (!drag.ghostEl && ghostPath) {
          drag.ghostEl = fileBrowserCreateDragGhost(ghostPath);
        }
      }
      if (!drag.moved) return;
      if (!drag.ghostEl && ghostPath) {
        drag.ghostEl = fileBrowserCreateDragGhost(ghostPath);
      }
      fileBrowserUpdateDragGhost(drag.ghostEl, cx, cy);
      const overCanvas = Boolean(canvasWorldPointFromClient(cx, cy));
      els.canvasWrap?.classList?.toggle("is-browser-drag-over", overCanvas);
      event?.preventDefault?.();
    };

    const onManualPointerUp = (event) => {
      const drag = fb.manualDrag;
      if (!drag?.active) return;
      if (drag.pointerId !== null && Number(event?.pointerId) !== Number(drag.pointerId)) return;
      const cx = Number(event?.clientX) || 0;
      const cy = Number(event?.clientY) || 0;
      const path = normalizeLocalFsPath(drag.path || "");
      const previewPath = normalizeLocalFsPath(drag.previewPath || path);
      const didMove = Boolean(drag.moved);
      const keepGhost = Boolean(didMove && path && isBrowserImagePath(path));
      const ghostEl = endManualPointerDrag({ clearPath: false, keepGhost });
      if (!didMove || !path || !isBrowserImagePath(path)) {
        if (ghostEl) fileBrowserDestroyDragGhost(ghostEl);
        fileBrowserClearDragPathDeferred(80);
        return;
      }
      fb.suppressClickUntil = Date.now() + 380;
      const world = canvasWorldPointFromClient(cx, cy);
      if (!world) {
        if (ghostEl) fileBrowserDestroyDragGhost(ghostEl);
        fileBrowserClearDragPathDeferred(80);
        return;
      }
      fileBrowserAnimateDropGhost(ghostEl, { clientX: cx, clientY: cy, path: previewPath || path });
      importLocalPathsAtCanvasPoint([path], world, {
        source: "browser_pointer_drag",
        idPrefix: "dockdrag",
        enforceIntentLimit: true,
        focusImported: true,
      })
        .then((result) => {
          if (!result?.ok) showToast("Could not import dropped image.", "error", 2600);
        })
        .catch((err) => {
          console.error(err);
          showToast("Could not import dropped image.", "error", 2600);
        })
        .finally(() => {
          fileBrowserClearDragPathDeferred(80);
        });
    };

    const onManualPointerCancel = (event) => {
      const drag = fb.manualDrag;
      if (!drag?.active) return;
      if (drag.pointerId !== null && Number(event?.pointerId) !== Number(drag.pointerId)) return;
      endManualPointerDrag({ clearPath: true });
    };

    window.addEventListener("pointermove", onManualPointerMove, { passive: false });
    window.addEventListener("pointerup", onManualPointerUp, { passive: false });
    window.addEventListener("pointercancel", onManualPointerCancel, { passive: true });

    els.fileBrowserList.addEventListener("pointerdown", (event) => {
      const row = event?.target?.closest ? event.target.closest(".file-browser-item") : null;
      if (!row || !els.fileBrowserList.contains(row)) return;
      const displayPath = normalizeLocalFsPath(String(row.dataset?.path || ""));
      const importPath = fileBrowserImportPathForRow(row);
      const kind = String(row.dataset?.kind || "").trim();
      if (kind !== "file" || !displayPath || !importPath) return;
      event.preventDefault();
      fileBrowserSetDragPath(importPath);
      fileBrowserSetSelectedPath(displayPath);
      fb.manualDrag.active = true;
      fb.manualDrag.pointerId = Number(event?.pointerId);
      fb.manualDrag.path = importPath;
      fb.manualDrag.previewPath = displayPath;
      fb.manualDrag.startX = Number(event?.clientX) || 0;
      fb.manualDrag.startY = Number(event?.clientY) || 0;
      fb.manualDrag.moved = false;
      if (fb.manualDrag.ghostEl) {
        fileBrowserDestroyDragGhost(fb.manualDrag.ghostEl);
        fb.manualDrag.ghostEl = null;
      }
    });
    els.fileBrowserList.addEventListener("click", (event) => {
      if (Date.now() < (Number(fb.suppressClickUntil) || 0)) return;
      const row = event?.target?.closest ? event.target.closest(".file-browser-item") : null;
      if (!row || !els.fileBrowserList.contains(row)) return;
      const path = normalizeLocalFsPath(String(row.dataset?.path || ""));
      const importPath = fileBrowserImportPathForRow(row);
      const kind = String(row.dataset?.kind || "").trim();
      if (!path) return;
      fileBrowserSetSelectedPath(path);
      if (kind === "dir") {
        fileBrowserCancelPendingClickImport();
        fileBrowserNavigateTo(path).catch((err) => console.error(err));
        return;
      }
      if (!importPath) return;
      fileBrowserScheduleClickImport(importPath);
    });
    els.fileBrowserList.addEventListener("dblclick", (event) => {
      if (Date.now() < (Number(fb.suppressClickUntil) || 0)) return;
      const row = event?.target?.closest ? event.target.closest(".file-browser-item") : null;
      if (!row || !els.fileBrowserList.contains(row)) return;
      const path = normalizeLocalFsPath(String(row.dataset?.path || ""));
      const importPath = fileBrowserImportPathForRow(row);
      const kind = String(row.dataset?.kind || "").trim();
      if (!path) return;
      fileBrowserCancelPendingClickImport();
      fileBrowserSetSelectedPath(path);
      if (kind === "dir") {
        fileBrowserNavigateTo(path).catch((err) => console.error(err));
        return;
      }
      if (!importPath) return;
      fileBrowserImportPath(importPath, { focus: true }).catch((err) => console.error(err));
    });
    els.fileBrowserList.addEventListener("keydown", (event) => {
      const key = String(event?.key || "");
      const entries = fileBrowserEntriesForUi();
      if (!entries.length) return;
      const current = state.fileBrowser?.selectedPath || "";
      let idx = entries.findIndex((item) => item.path === current);
      if (key === "ArrowDown") {
        event.preventDefault();
        idx = clamp(idx + 1, 0, entries.length - 1);
        fileBrowserSetSelectedPath(entries[idx]?.path || null);
      } else if (key === "ArrowUp") {
        event.preventDefault();
        idx = clamp(idx < 0 ? 0 : idx - 1, 0, entries.length - 1);
        fileBrowserSetSelectedPath(entries[idx]?.path || null);
      } else if (key === "Enter") {
        event.preventDefault();
        if (idx < 0) idx = 0;
        const entry = entries[idx] || null;
        if (!entry?.path) return;
        fileBrowserCancelPendingClickImport();
        if (entry.kind === "dir") fileBrowserNavigateTo(entry.path).catch((err) => console.error(err));
        else {
          const importPath = fileBrowserImportPathForEntry(entry);
          if (!importPath) return;
          fileBrowserImportPath(importPath, { focus: true }).catch((err) => console.error(err));
        }
      }
    });
  }

  if (fb.rootDir) {
    await fileBrowserLoadDir(fb.rootDir, { pushHistory: false });
  } else {
    renderFileBrowserDock();
  }
}

function parseJsonSafe(raw) {
  try {
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

function loadOpenRouterOnboardingProfile() {
  const raw = localStorage.getItem(OPENROUTER_ONBOARDING_PROFILE_KEY);
  const parsed = parseJsonSafe(raw);
  if (!parsed || typeof parsed !== "object") return null;
  return parsed;
}

function saveOpenRouterOnboardingProfile(profile) {
  try {
    localStorage.setItem(OPENROUTER_ONBOARDING_PROFILE_KEY, JSON.stringify(profile));
  } catch {
    // ignore
  }
}

function markOpenRouterOnboardingCompleted(done = true) {
  localStorage.setItem(OPENROUTER_ONBOARDING_COMPLETED_KEY, done ? "1" : "0");
}

function clearOpenRouterOnboardingProfile() {
  localStorage.removeItem(OPENROUTER_ONBOARDING_PROFILE_KEY);
  localStorage.removeItem(OPENROUTER_ONBOARDING_COMPLETED_KEY);
}

async function clearStoredOpenRouterApiKey() {
  const result = await invoke("clear_openrouter_api_key");
  clearOpenRouterOnboardingProfile();
  await refreshKeyStatus({ reason: "openrouter_settings_clear" }).catch(() => {});
  renderOpenRouterOnboardingStatus();
  const stillDetected = Boolean(state?.keyStatus?.openrouter);
  if (stillDetected) {
    showToast("Stored OpenRouter key cleared. Another OpenRouter key is still detected from environment.", "tip", 3200);
    return result;
  }
  const removed = Boolean(result?.removed);
  showToast(
    removed ? "Stored OpenRouter key cleared." : "No stored OpenRouter key was found.",
    "tip",
    2200
  );
  return result;
}

function formatOpenRouterOnboardingTimestamp(value) {
  const at = new Date(value || 0);
  if (!Number.isFinite(at.getTime())) return "unknown time";
  return at.toLocaleString();
}

function renderOpenRouterOnboardingStatus() {
  if (!els.openrouterOnboardingStatus) return;
  const profile = loadOpenRouterOnboardingProfile();
  const detected = Boolean(state?.keyStatus?.openrouter);
  if (!profile) {
    els.openrouterOnboardingStatus.textContent = detected
      ? "OpenRouter key detected from environment."
      : "Not started";
    return;
  }
  const when = formatOpenRouterOnboardingTimestamp(profile.successAt || profile.completedAt || Date.now());
  if (profile.success || detected) {
    const masked = profile.keyMasked ? String(profile.keyMasked) : "saved";
    const detection = detected ? "detected" : "not detected yet";
    els.openrouterOnboardingStatus.textContent = `Connected (${masked})\nConfirmed ${when}\nKey status: ${detection}`;
    return;
  }
  if (profile.skipped) {
    els.openrouterOnboardingStatus.textContent = `Skipped ${when}\nRun setup anytime.`;
    return;
  }
  els.openrouterOnboardingStatus.textContent = `Viewed ${when}\nRun setup to finish.`;
}

function renderOpenRouterOnboardingProgress(stepIndex) {
  if (!els.openrouterOnboardingProgress) return;
  const dotCount = 2;
  els.openrouterOnboardingProgress.innerHTML = Array.from({ length: dotCount }, (_, idx) => {
      const active = idx === stepIndex ? " is-active" : "";
      const complete = idx < stepIndex ? " is-complete" : "";
      return `
        <div class="openrouter-onboarding-progress-dot${active}${complete}">
          <span class="openrouter-onboarding-progress-dot-point" aria-hidden="true"></span>
        </div>
      `;
    }).join("");
}

function openRouterOnboardingRawErrorDetail(err, fallback = "Could not complete OpenRouter sign-in.") {
  const value = err?.message || err?.cause?.message || err?.reason?.message || err || fallback;
  const detail = String(value || fallback).replace(/\s+/g, " ").trim();
  return detail || String(fallback);
}

function classifyOpenRouterOauthError(detail) {
  const raw = String(detail || "").trim();
  const lower = raw.toLowerCase();
  if (
    lower.includes("409") &&
    (lower.includes("granting auth") ||
      lower.includes("auth code") ||
      lower.includes("openrouter oauth") ||
      lower.includes("create or update app"))
  ) {
    return {
      message: "OpenRouter sign-in returned a 409. Try again, or switch to manual key paste.",
      canRetryOauth: true,
      canRevealManual: true,
      canCopyDetail: true,
    };
  }
  if (
    (lower.includes("port 3000") && (lower.includes("in use") || lower.includes("busy"))) ||
    lower.includes("address already in use")
  ) {
    return {
      message: "Port 3000 is in use, so Cue could not receive the OAuth callback. Retry after freeing that port, or use manual key paste.",
      canRetryOauth: true,
      canRevealManual: true,
      canCopyDetail: true,
    };
  }
  return {
    message: normalizeErrorMessage(raw, "Could not complete OpenRouter sign-in."),
    canRetryOauth: true,
    canRevealManual: true,
    canCopyDetail: true,
  };
}

function openRouterOnboardingSetStatus({
  message = "",
  isError = false,
  detail = "",
  canRetryOauth = false,
  canRevealManual = false,
  canCopyDetail = false,
} = {}) {
  openrouterOnboardingState.statusMessage = String(message || "").trim();
  openrouterOnboardingState.statusError = Boolean(isError);
  openrouterOnboardingState.statusDetail = String(detail || "").trim();
  openrouterOnboardingState.statusCanRetryOauth = Boolean(canRetryOauth);
  openrouterOnboardingState.statusCanRevealManual = Boolean(canRevealManual);
  openrouterOnboardingState.statusCanCopyDetail = Boolean(canCopyDetail);
}

function clearOpenRouterOnboardingOauthProgressTimer() {
  if (openrouterOnboardingState.oauthProgressTimer) {
    clearTimeout(openrouterOnboardingState.oauthProgressTimer);
    openrouterOnboardingState.oauthProgressTimer = null;
  }
}

function clearOpenRouterOnboardingAutoCloseTimer() {
  if (openrouterOnboardingState.autoCloseTimer) {
    clearTimeout(openrouterOnboardingState.autoCloseTimer);
    openrouterOnboardingState.autoCloseTimer = null;
  }
}

function scheduleOpenRouterOnboardingAutoClose() {
  clearOpenRouterOnboardingAutoCloseTimer();
  if (openrouterOnboardingState.source !== "first_run") return;
  openrouterOnboardingState.autoCloseTimer = setTimeout(() => {
    openrouterOnboardingState.autoCloseTimer = null;
    if (!openrouterOnboardingState.open) return;
    if (openrouterOnboardingState.stepIndex < 1) return;
    closeOpenRouterOnboardingModal();
  }, OPENROUTER_ONBOARDING_SUCCESS_AUTO_CLOSE_MS);
}

function revealOpenRouterOnboardingManualEntry({ focusInput = true } = {}) {
  if (openrouterOnboardingState.manualEntryVisible) {
    if (!focusInput) return;
  } else {
    openrouterOnboardingState.manualEntryVisible = true;
    openrouterOnboardingState.statusCanRevealManual = false;
  }
  renderOpenRouterOnboardingStep({ animate: false });
  if (!focusInput) return;
  requestAnimationFrame(() => {
    const inputEl = document.getElementById("openrouter-onboarding-key-input");
    if (inputEl && typeof inputEl.focus === "function") {
      inputEl.focus();
      if (typeof inputEl.select === "function" && inputEl.value) {
        inputEl.select();
      }
    }
  });
}

function buildOpenRouterOnboardingKeyHtml() {
  const current = escapeHtml(openrouterOnboardingState.draft.apiKey || "");
  const statusText = String(openrouterOnboardingState.statusMessage || "").trim();
  const statusClass = openrouterOnboardingState.statusError
    ? "openrouter-onboarding-form-status is-error"
    : "openrouter-onboarding-form-status";
  const submitDisabledAttr = openrouterOnboardingState.submitting ? " disabled" : "";
  const manualEntryVisible = Boolean(openrouterOnboardingState.manualEntryVisible);
  const statusActions = [];
  if (openrouterOnboardingState.statusCanRetryOauth) {
    statusActions.push(`
      <button
        type="button"
        class="ghost openrouter-onboarding-status-action"
        data-openrouter-action="oauth_retry"
        ${submitDisabledAttr}
      >
        Try again
      </button>
    `);
  }
  if (openrouterOnboardingState.statusCanRevealManual && !manualEntryVisible) {
    statusActions.push(`
      <button
        type="button"
        class="ghost openrouter-onboarding-status-action"
        data-openrouter-action="show_manual"
        ${submitDisabledAttr}
      >
        Use manual key
      </button>
    `);
  }
  if (openrouterOnboardingState.statusCanCopyDetail) {
    statusActions.push(`
      <button
        type="button"
        class="ghost openrouter-onboarding-status-action"
        data-openrouter-action="copy_error"
        ${submitDisabledAttr}
      >
        Copy error details
      </button>
    `);
  }
  const statusActionsHtml = statusActions.length
    ? `<div class="openrouter-onboarding-status-actions">${statusActions.join("")}</div>`
    : "";
  return `
    <section class="openrouter-onboarding-step openrouter-onboarding-step-key">
      <h3 class="openrouter-onboarding-intro-title">Cue works best with OpenRouter</h3>
      <p class="openrouter-onboarding-intro-copy openrouter-onboarding-key-lede">
        Sign in with OpenRouter to connect your key automatically.
      </p>
      <div class="openrouter-onboarding-oauth-row">
        <button
          type="button"
          class="openrouter-onboarding-oauth-button"
          data-openrouter-action="oauth_sign_in"
          ${submitDisabledAttr}
        >
          <span class="openrouter-onboarding-oauth-logo-wrap" aria-hidden="true">
            <img class="openrouter-onboarding-oauth-logo" src="${OPENROUTER_ONBOARDING_LOGO_WHITE_SRC}" alt="" />
          </span>
          <span class="openrouter-onboarding-oauth-button-label">Sign in with OpenRouter</span>
        </button>
        <div class="openrouter-onboarding-oauth-subsection">
          ${
            manualEntryVisible
              ? `<p class="openrouter-onboarding-manual-label">Manual key entry</p>`
              : `
                  <button
                    type="button"
                    class="openrouter-onboarding-inline-link"
                    data-openrouter-action="show_manual"
                    ${submitDisabledAttr}
                  >
                    Use API key manually instead
                  </button>
                `
          }
        </div>
      </div>
      ${
        manualEntryVisible
          ? `
              <div class="openrouter-onboarding-divider" aria-hidden="true"><span>OR PASTE KEY MANUALLY</span></div>
              <label class="openrouter-onboarding-inline-label" for="openrouter-onboarding-key-input">OPENROUTER_API_KEY</label>
              <input
                id="openrouter-onboarding-key-input"
                class="openrouter-onboarding-key-input"
                type="password"
                autocomplete="off"
                spellcheck="false"
                placeholder="sk-or-v1-..."
                value="${current}"
                ${submitDisabledAttr}
              />
            `
          : ""
      }
      <p class="openrouter-onboarding-intro-copy openrouter-onboarding-key-note openrouter-onboarding-skip-note">
        Skip for now keeps image generation disabled until you connect a key.
      </p>
      ${
        statusText
          ? `<div class="${statusClass}"><span>${escapeHtml(statusText)}</span>${statusActionsHtml}</div>`
          : ""
      }
    </section>
  `;
}

function buildOpenRouterOnboardingSuccessHtml() {
  const profile = loadOpenRouterOnboardingProfile();
  const when = formatOpenRouterOnboardingTimestamp(profile?.successAt || Date.now());
  const masked = profile?.keyMasked ? String(profile.keyMasked) : "saved";
  return `
    <section class="openrouter-onboarding-step openrouter-onboarding-step-confirm">
      <h3 class="openrouter-onboarding-intro-title">OpenRouter connected</h3>
      <p class="openrouter-onboarding-intro-copy">
        Setup complete. You can start generating on the canvas.
      </p>
      <p class="openrouter-onboarding-intro-copy openrouter-onboarding-key-note">Connected as <code>${escapeHtml(masked)}</code></p>
      <p class="openrouter-onboarding-intro-copy openrouter-onboarding-key-note">Confirmed: ${escapeHtml(when)}</p>
      <p class="openrouter-onboarding-intro-copy openrouter-onboarding-key-note">
        You can reopen this flow anytime from <strong>Settings → OpenRouter Onboarding</strong>.
      </p>
    </section>
  `;
}

function renderOpenRouterOnboardingStep({ animate = false } = {}) {
  if (!els.openrouterOnboardingModal || !els.openrouterOnboardingBody) return;
  const stepIndex = Math.max(0, Math.min(1, Number(openrouterOnboardingState.stepIndex) || 0));
  const centeredBodyLayout = stepIndex <= 1;
  const bodyEl = els.openrouterOnboardingBody;

  const renderBody = () => {
    if (stepIndex === 0) {
      bodyEl.innerHTML = buildOpenRouterOnboardingKeyHtml();
    } else {
      bodyEl.innerHTML = buildOpenRouterOnboardingSuccessHtml();
    }
  };

  if (animate) {
    if (openrouterOnboardingState.transitionTimer) {
      clearTimeout(openrouterOnboardingState.transitionTimer);
      openrouterOnboardingState.transitionTimer = null;
    }
    bodyEl.classList.remove("is-fading-out");
    renderBody();
    bodyEl.classList.remove("is-fading-in");
    void bodyEl.offsetWidth;
    bodyEl.classList.add("is-fading-in");
    openrouterOnboardingState.transitionTimer = setTimeout(() => {
      bodyEl.classList.remove("is-fading-in");
      openrouterOnboardingState.transitionTimer = null;
    }, 1260);
  } else {
    bodyEl.classList.remove("is-fading-out");
    bodyEl.classList.remove("is-fading-in");
    renderBody();
  }
  bodyEl.classList.toggle("is-intro-layout", centeredBodyLayout);

  renderOpenRouterOnboardingProgress(stepIndex);

  if (els.openrouterOnboardingBack) {
    const hidden = true;
    const disabled = openrouterOnboardingState.submitting || hidden;
    els.openrouterOnboardingBack.classList.toggle("openrouter-onboarding-footer-item-hidden", hidden);
    els.openrouterOnboardingBack.disabled = disabled;
    if (hidden) {
      els.openrouterOnboardingBack.setAttribute("aria-hidden", "true");
      els.openrouterOnboardingBack.setAttribute("tabindex", "-1");
    } else {
      els.openrouterOnboardingBack.removeAttribute("aria-hidden");
      els.openrouterOnboardingBack.removeAttribute("tabindex");
    }
  }
  if (els.openrouterOnboardingSkip) {
    const hidden = stepIndex >= 1;
    const disabled = openrouterOnboardingState.submitting;
    const unavailable = hidden || disabled;
    els.openrouterOnboardingSkip.classList.toggle("openrouter-onboarding-footer-item-hidden", hidden);
    els.openrouterOnboardingSkip.classList.toggle("is-disabled", unavailable);
    if (unavailable) {
      els.openrouterOnboardingSkip.setAttribute("aria-hidden", hidden ? "true" : "false");
      els.openrouterOnboardingSkip.setAttribute("aria-disabled", "true");
      els.openrouterOnboardingSkip.setAttribute("tabindex", "-1");
    } else {
      els.openrouterOnboardingSkip.removeAttribute("aria-hidden");
      els.openrouterOnboardingSkip.removeAttribute("aria-disabled");
      els.openrouterOnboardingSkip.removeAttribute("tabindex");
    }
  }
  if (els.openrouterOnboardingClose) {
    els.openrouterOnboardingClose.textContent = stepIndex >= 1 ? "Close" : "Later";
    els.openrouterOnboardingClose.disabled = openrouterOnboardingState.submitting;
  }
  const manualSaveVisible = stepIndex !== 0 || openrouterOnboardingState.manualEntryVisible;
  const nextText = stepIndex === 0 ? "Save key" : "Done";
  const nextDisabled = openrouterOnboardingState.submitting || !manualSaveVisible;
  if (els.openrouterOnboardingNext) {
    els.openrouterOnboardingNext.classList.toggle("openrouter-onboarding-footer-item-hidden", !manualSaveVisible);
    if (manualSaveVisible) {
      els.openrouterOnboardingNext.removeAttribute("aria-hidden");
      els.openrouterOnboardingNext.removeAttribute("tabindex");
    } else {
      els.openrouterOnboardingNext.setAttribute("aria-hidden", "true");
      els.openrouterOnboardingNext.setAttribute("tabindex", "-1");
    }
    els.openrouterOnboardingNext.textContent = nextText;
    els.openrouterOnboardingNext.disabled = nextDisabled;
  }
}

function closeOpenRouterOnboardingModal() {
  if (openrouterOnboardingState.transitionTimer) {
    clearTimeout(openrouterOnboardingState.transitionTimer);
    openrouterOnboardingState.transitionTimer = null;
  }
  clearOpenRouterOnboardingOauthProgressTimer();
  clearOpenRouterOnboardingAutoCloseTimer();
  if (els.openrouterOnboardingMediaVideo) {
    els.openrouterOnboardingMediaVideo.pause();
  }
  openrouterOnboardingState.open = false;
  openrouterOnboardingState.submitting = false;
  if (els.openrouterOnboardingModal) {
    els.openrouterOnboardingModal.classList.add("hidden");
  }
}

function playOpenRouterOnboardingMediaVideo({ restart = false } = {}) {
  const videoEl = els.openrouterOnboardingMediaVideo;
  if (!videoEl) return;
  if (!videoEl.src) {
    videoEl.src = OPENROUTER_ONBOARDING_SORA_VIDEO_SRC;
  }
  if (restart) {
    try {
      videoEl.currentTime = 0;
    } catch {
      // Ignore until metadata is available.
    }
  }
  const playResult = videoEl.play();
  if (playResult && typeof playResult.catch === "function") {
    playResult.catch(() => {});
  }
}

function saveOpenRouterOnboardingCompletion({
  success = false,
  skipped = false,
  keyMasked = null,
  envPath = null,
} = {}) {
  const prev = loadOpenRouterOnboardingProfile() || {};
  const nowIso = new Date().toISOString();
  const successFinal = Boolean(success || prev.success);
  const profile = {
    version: 1,
    source: openrouterOnboardingState.source,
    completedAt: nowIso,
    success: successFinal,
    skipped: Boolean(skipped) && !successFinal,
    successAt: success ? nowIso : prev.successAt || null,
    keyMasked: success ? keyMasked || prev.keyMasked || null : prev.keyMasked || null,
    envPath: success ? envPath || prev.envPath || null : prev.envPath || null,
  };
  saveOpenRouterOnboardingProfile(profile);
  markOpenRouterOnboardingCompleted(true);
  renderOpenRouterOnboardingStatus();
  if (profile.skipped) {
    emitInstallTelemetryAsync("onboarding_skipped", {
      onboarding: "openrouter",
      source: String(profile.source || "unknown"),
    });
  } else if (successFinal) {
    emitInstallTelemetryAsync("onboarding_completed", {
      onboarding: "openrouter",
      source: String(profile.source || "unknown"),
    });
  }
}

function openOpenRouterOnboardingModal({ force = false, source = "first_run" } = {}) {
  if (!els.openrouterOnboardingModal) return false;
  const completed = localStorage.getItem(OPENROUTER_ONBOARDING_COMPLETED_KEY) === "1";
  if (!force && completed) return false;
  clearOpenRouterOnboardingOauthProgressTimer();
  clearOpenRouterOnboardingAutoCloseTimer();
  openrouterOnboardingState.open = true;
  openrouterOnboardingState.stepIndex = 0;
  openrouterOnboardingState.source = source;
  openrouterOnboardingState.draft = defaultOpenRouterOnboardingDraft();
  openrouterOnboardingState.manualEntryVisible = false;
  openrouterOnboardingState.submitting = false;
  openRouterOnboardingSetStatus();
  openrouterOnboardingState.keyMasked = null;
  openrouterOnboardingState.envPath = null;
  els.openrouterOnboardingModal.classList.remove("hidden");
  playOpenRouterOnboardingMediaVideo({ restart: true });
  renderOpenRouterOnboardingStep({ animate: false });
  emitInstallTelemetryAsync("onboarding_started", {
    onboarding: "openrouter",
    source: String(source || "unknown"),
  });
  return true;
}

function skipOpenRouterOnboarding() {
  saveOpenRouterOnboardingCompletion({ skipped: true });
  closeOpenRouterOnboardingModal();
}

function handleOpenRouterOnboardingNextAction() {
  if (!openrouterOnboardingState.open || openrouterOnboardingState.submitting) return;
  if (openrouterOnboardingState.stepIndex === 0) {
    if (!openrouterOnboardingState.manualEntryVisible) {
      revealOpenRouterOnboardingManualEntry();
      return;
    }
    submitOpenRouterOnboardingKey().catch((err) => {
      console.error(err);
    });
    return;
  }
  closeOpenRouterOnboardingModal();
}

async function restartEngineAfterOpenRouterKeySave() {
  if (!state.runDir || !state.eventsPath) return true;
  const waitDeadline = Date.now() + 12_000;
  while (state.ptySpawning && Date.now() < waitDeadline) {
    await new Promise((resolve) => setTimeout(resolve, 60));
  }
  if (state.ptySpawning) {
    throw new Error("Engine restart still in progress. Please wait and retry.");
  }
  await spawnEngine();
  if (!state.ptySpawned) {
    throw new Error("OPENROUTER_API_KEY saved, but engine restart failed. Start a new run or relaunch.");
  }
  const readyDeadline = Date.now() + 12_000;
  while (Date.now() < readyDeadline) {
    let status = null;
    try {
      status = await invoke("get_pty_status");
    } catch (_) {
      status = null;
    }
    const running = Boolean(status && typeof status === "object" && status.running);
    if (running) {
      const statusRunDir = status?.run_dir ? String(status.run_dir) : "";
      const statusEventsPath = status?.events_path ? String(status.events_path) : "";
      const runMatch = !statusRunDir || statusRunDir === state.runDir;
      const eventsMatch = !statusEventsPath || statusEventsPath === state.eventsPath;
      if (runMatch && eventsMatch) {
        return true;
      }
    }
    await new Promise((resolve) => setTimeout(resolve, 120));
  }
  throw new Error("OPENROUTER_API_KEY saved, but engine did not report ready after restart. Start a new run or relaunch.");
}

async function finalizeOpenRouterOnboardingSuccess({ keyMasked = null, envPath = null } = {}) {
  clearOpenRouterOnboardingOauthProgressTimer();
  openRouterOnboardingSetStatus({ message: "Finishing setup…" });
  renderOpenRouterOnboardingStep({ animate: false });
  await refreshKeyStatus({ reason: "openrouter_onboarding" }).catch(() => {});
  if (!state?.keyStatus?.openrouter) {
    emitInstallTelemetryAsync("provider_check_fail", {
      provider: "openrouter",
      reason: "post_save_detection_missing",
    });
    throw new Error("OPENROUTER_API_KEY was saved but key detection did not confirm yet.");
  }
  await restartEngineAfterOpenRouterKeySave();
  await refreshKeyStatus({ reason: "openrouter_onboarding" }).catch(() => {});
  if (!state?.keyStatus?.openrouter) {
    emitInstallTelemetryAsync("provider_check_fail", {
      provider: "openrouter",
      reason: "post_restart_detection_missing",
    });
    throw new Error("OPENROUTER_API_KEY saved, but post-restart key detection is still unavailable.");
  }
  openrouterOnboardingState.keyMasked = keyMasked ? String(keyMasked) : null;
  openrouterOnboardingState.envPath = envPath ? String(envPath) : null;
  saveOpenRouterOnboardingCompletion({
    success: true,
    keyMasked: openrouterOnboardingState.keyMasked,
    envPath: openrouterOnboardingState.envPath,
  });
  // Ensure the confirm step renders with interactive controls enabled.
  openrouterOnboardingState.submitting = false;
  openrouterOnboardingState.stepIndex = 1;
  openRouterOnboardingSetStatus();
  showToast("OpenRouter key connected.", "tip", 2200);
  renderOpenRouterOnboardingStep({ animate: true });
  scheduleOpenRouterOnboardingAutoClose();
  emitInstallTelemetryAsync("provider_check_ok", {
    provider: "openrouter",
    reason: "onboarding_success",
  });
}

async function submitOpenRouterOnboardingKey() {
  if (openrouterOnboardingState.submitting) return false;
  const inputEl = document.getElementById("openrouter-onboarding-key-input");
  const raw = inputEl ? String(inputEl.value || "") : String(openrouterOnboardingState.draft.apiKey || "");
  const apiKey = raw.trim();
  openrouterOnboardingState.draft.apiKey = apiKey;
  if (!apiKey) {
    openRouterOnboardingSetStatus({
      message: "Please paste your OPENROUTER_API_KEY.",
      isError: true,
      canRevealManual: true,
    });
    renderOpenRouterOnboardingStep({ animate: false });
    return false;
  }

  clearOpenRouterOnboardingOauthProgressTimer();
  clearOpenRouterOnboardingAutoCloseTimer();
  openrouterOnboardingState.submitting = true;
  openRouterOnboardingSetStatus({ message: "Saving key and verifying detection…" });
  renderOpenRouterOnboardingStep({ animate: false });

  try {
    const result = await invoke("save_openrouter_api_key", { apiKey });
    await finalizeOpenRouterOnboardingSuccess({
      keyMasked: result?.key_masked || null,
      envPath: result?.env_path || null,
    });
    return true;
  } catch (err) {
    const detail = openRouterOnboardingRawErrorDetail(err, "Could not save OPENROUTER_API_KEY.");
    openRouterOnboardingSetStatus({
      message: normalizeErrorMessage(detail, "Could not save OPENROUTER_API_KEY."),
      isError: true,
      detail,
      canCopyDetail: true,
    });
    renderOpenRouterOnboardingStep({ animate: false });
    return false;
  } finally {
    openrouterOnboardingState.submitting = false;
    if (openrouterOnboardingState.stepIndex === 0 && openrouterOnboardingState.open) {
      renderOpenRouterOnboardingStep({ animate: false });
    }
  }
}

async function signInWithOpenRouterOauthPkce() {
  if (openrouterOnboardingState.submitting) return false;
  clearOpenRouterOnboardingOauthProgressTimer();
  clearOpenRouterOnboardingAutoCloseTimer();
  openrouterOnboardingState.submitting = true;
  openRouterOnboardingSetStatus({ message: "Opening browser…" });
  renderOpenRouterOnboardingStep({ animate: false });
  openrouterOnboardingState.oauthProgressTimer = setTimeout(() => {
    openrouterOnboardingState.oauthProgressTimer = null;
    if (!openrouterOnboardingState.open || !openrouterOnboardingState.submitting) return;
    openRouterOnboardingSetStatus({ message: "Waiting for OpenRouter approval…" });
    renderOpenRouterOnboardingStep({ animate: false });
  }, OPENROUTER_OAUTH_WAITING_STATE_DELAY_MS);

  try {
    const result = await invoke("openrouter_oauth_pkce_sign_in", { timeoutSeconds: 240 });
    clearOpenRouterOnboardingOauthProgressTimer();
    openRouterOnboardingSetStatus({ message: "Finishing setup…" });
    renderOpenRouterOnboardingStep({ animate: false });
    await finalizeOpenRouterOnboardingSuccess({
      keyMasked: result?.key_masked || null,
      envPath: result?.env_path || null,
    });
    return true;
  } catch (err) {
    clearOpenRouterOnboardingOauthProgressTimer();
    const detail = openRouterOnboardingRawErrorDetail(err, "Could not complete OpenRouter sign-in.");
    const classified = classifyOpenRouterOauthError(detail);
    openRouterOnboardingSetStatus({
      message: classified.message,
      isError: true,
      detail,
      canRetryOauth: classified.canRetryOauth,
      canRevealManual: classified.canRevealManual,
      canCopyDetail: classified.canCopyDetail,
    });
    renderOpenRouterOnboardingStep({ animate: false });
    return false;
  } finally {
    clearOpenRouterOnboardingOauthProgressTimer();
    openrouterOnboardingState.submitting = false;
    if (openrouterOnboardingState.stepIndex === 0 && openrouterOnboardingState.open) {
      renderOpenRouterOnboardingStep({ animate: false });
    }
  }
}

async function copyOpenRouterOnboardingErrorDetails() {
  const detail = String(
    openrouterOnboardingState.statusDetail || openrouterOnboardingState.statusMessage || ""
  ).trim();
  if (!detail) return false;
  try {
    await navigator.clipboard.writeText(detail);
    showToast("OpenRouter error details copied.", "tip", 1800);
    return true;
  } catch {
    showToast("Could not copy OpenRouter error details.", "error", 2200);
    return false;
  }
}

function maybeAutoOpenOpenRouterOnboarding() {
  const completed = localStorage.getItem(OPENROUTER_ONBOARDING_COMPLETED_KEY) === "1";
  if (completed) return false;
  return openOpenRouterOnboardingModal({ force: false, source: "first_run" });
}

function loadAestheticOnboardingProfile() {
  const raw = localStorage.getItem(AESTHETIC_ONBOARDING_PROFILE_KEY);
  const parsed = parseJsonSafe(raw);
  if (!parsed || typeof parsed !== "object") return null;
  return parsed;
}

function saveAestheticOnboardingProfile(profile) {
  try {
    localStorage.setItem(AESTHETIC_ONBOARDING_PROFILE_KEY, JSON.stringify(profile));
  } catch {
    // ignore
  }
}

function markAestheticOnboardingCompleted(done = true) {
  localStorage.setItem(AESTHETIC_ONBOARDING_COMPLETED_KEY, done ? "1" : "0");
}

function clearAestheticOnboardingProfile() {
  localStorage.removeItem(AESTHETIC_ONBOARDING_PROFILE_KEY);
  localStorage.removeItem(AESTHETIC_ONBOARDING_COMPLETED_KEY);
}

function getAestheticModelChoice(choiceId) {
  const id = String(choiceId || "").trim();
  if (!id) return null;
  return AESTHETIC_ONBOARDING_MODEL_CHOICES.find((choice) => choice.id === id) || null;
}

function formatAestheticTimestamp(value) {
  const at = new Date(value || 0);
  if (!Number.isFinite(at.getTime())) return "unknown time";
  return at.toLocaleString();
}

function describeAestheticChoice(choiceId) {
  const choice = getAestheticModelChoice(choiceId);
  if (!choice) return "Unknown";
  if (choice.modelValue && choice.modelValue !== choice.id) return `${choice.label} -> ${choice.modelValue}`;
  return choice.label;
}

function scoreAestheticOnboardingAnswers(answers) {
  const scoreByModel = Object.fromEntries(AESTHETIC_ONBOARDING_MODEL_CHOICES.map((choice) => [choice.id, 0]));
  const pickedModelId = String(answers?.imageChoiceId || "").trim();
  if (pickedModelId && scoreByModel[pickedModelId] != null) scoreByModel[pickedModelId] += 3;

  switch (String(answers?.featurePriority || "").trim()) {
    case "reproducible_receipts":
      scoreByModel["gpt-image-1.5"] += 2;
      scoreByModel["gemini-3-pro-image-preview"] += 1;
      break;
    case "image_mutations":
      scoreByModel["flux-2-flex"] += 2;
      scoreByModel["flux-2-max"] += 1;
      break;
    case "multi_model_workflows":
      scoreByModel["gemini-3-pro-image-preview"] += 2;
      scoreByModel["gpt-image-1.5"] += 1;
      break;
    default:
      for (const choice of AESTHETIC_ONBOARDING_MODEL_CHOICES) scoreByModel[choice.id] += 1;
      break;
  }

  switch (String(answers?.directionality || "").trim()) {
    case "fidelity":
      scoreByModel["gemini-3-pro-image-preview"] += 2;
      scoreByModel["gpt-image-1.5"] += 1;
      scoreByModel["flux-2-max"] += 1;
      break;
    case "speed":
      scoreByModel["flux-2-flex"] += 2;
      scoreByModel["flux-2-max"] += 1;
      break;
    default:
      for (const choice of AESTHETIC_ONBOARDING_MODEL_CHOICES) scoreByModel[choice.id] += 1;
      break;
  }

  let winnerId = AESTHETIC_ONBOARDING_MODEL_CHOICES[0]?.id || "gemini-3-pro-image-preview";
  let winnerScore = Number.NEGATIVE_INFINITY;
  for (const choice of AESTHETIC_ONBOARDING_MODEL_CHOICES) {
    const current = Number(scoreByModel[choice.id] || 0);
    if (current > winnerScore) {
      winnerId = choice.id;
      winnerScore = current;
      continue;
    }
    if (current === winnerScore && pickedModelId && choice.id === pickedModelId) {
      winnerId = choice.id;
      winnerScore = current;
    }
  }
  return { winnerId, scoreByModel };
}

function renderAestheticOnboardingStatus() {
  if (!els.aestheticOnboardingStatus) return;
  const profile = loadAestheticOnboardingProfile();
  if (!profile) {
    els.aestheticOnboardingStatus.textContent = "Not set yet";
    return;
  }
  const picked = describeAestheticChoice(profile.preferredModelId);
  const when = formatAestheticTimestamp(profile.completedAt || profile.updatedAt || Date.now());
  if (profile.skipped) {
    els.aestheticOnboardingStatus.textContent = `Skipped on ${when}. Current default: ${settings.imageModel}`;
    return;
  }
  els.aestheticOnboardingStatus.textContent = `Preferred: ${picked}\nSaved ${when}\nDefault model: ${settings.imageModel}`;
}

function renderAestheticOnboardingProgress(stepIndex) {
  if (!els.aestheticOnboardingProgress) return;
  const labels = ["Q1", "Q2", "Q3", "Result"];
  els.aestheticOnboardingProgress.innerHTML = labels
    .map((label, idx) => {
      const active = idx === stepIndex ? " is-active" : "";
      const complete = idx < stepIndex ? " is-complete" : "";
      return `<div class="aesthetic-onboarding-progress-dot${active}${complete}">${label}</div>`;
    })
    .join("");
}

function buildAestheticQuestionStepHtml() {
  const selected = String(aestheticOnboardingState.answers.imageChoiceId || "").trim();
  const cards = AESTHETIC_ONBOARDING_MODEL_CHOICES.map((choice) => {
    const chosen = selected === choice.id ? " is-selected" : "";
    return `
      <button
        class="aesthetic-choice-card${chosen}"
        type="button"
        data-aesthetic-select="imageChoiceId"
        data-aesthetic-value="${choice.id}"
      >
        <img class="aesthetic-choice-image" src="${choice.imageUrl}" alt="${choice.label}" />
        <div class="aesthetic-choice-meta">
          <div class="aesthetic-choice-title">${choice.label}</div>
          <div class="aesthetic-choice-note">${choice.note}</div>
        </div>
      </button>
    `;
  }).join("");
  return `
    <section class="aesthetic-question">
      <div class="aesthetic-question-head">
        <h3>Which image do you like best?</h3>
        <p>All options use the same prompt and differ only by model.</p>
      </div>
      <div class="aesthetic-choice-grid">${cards}</div>
      <div class="aesthetic-prompt-card">
        <div class="aesthetic-prompt-label">Prompt</div>
        <div class="aesthetic-prompt-text">${AESTHETIC_ONBOARDING_PROMPT}</div>
      </div>
    </section>
  `;
}

function buildAestheticOptionStepHtml(question) {
  const selected = String(aestheticOnboardingState.answers[question.answerKey] || "").trim();
  const cards = question.options
    .map((option) => {
      const chosen = selected === option.id ? " is-selected" : "";
      return `
        <button
          class="aesthetic-option-card${chosen}"
          type="button"
          data-aesthetic-select="${question.answerKey}"
          data-aesthetic-value="${option.id}"
        >
          <div class="aesthetic-option-title">${option.title}</div>
          <div class="aesthetic-option-description">${option.description}</div>
        </button>
      `;
    })
    .join("");
  return `
    <section class="aesthetic-question">
      <div class="aesthetic-question-head">
        <h3>${question.title}</h3>
        <p>${question.subtitle}</p>
      </div>
      <div class="aesthetic-option-grid">${cards}</div>
    </section>
  `;
}

function buildAestheticSummaryStepHtml() {
  const scored = scoreAestheticOnboardingAnswers(aestheticOnboardingState.answers);
  const winner = getAestheticModelChoice(scored.winnerId) || AESTHETIC_ONBOARDING_MODEL_CHOICES[0];
  const topReasons = [];
  if (aestheticOnboardingState.answers.imageChoiceId) {
    const picked = getAestheticModelChoice(aestheticOnboardingState.answers.imageChoiceId);
    if (picked) topReasons.push(`You initially preferred ${picked.label}.`);
  }
  if (aestheticOnboardingState.answers.featurePriority === "multi_model_workflows") {
    topReasons.push("You expect multi-model editing workflows.");
  } else if (aestheticOnboardingState.answers.featurePriority === "image_mutations") {
    topReasons.push("You prioritized mutation-heavy exploration.");
  } else if (aestheticOnboardingState.answers.featurePriority === "reproducible_receipts") {
    topReasons.push("You prioritized reproducibility and receipts.");
  }
  if (aestheticOnboardingState.answers.directionality === "fidelity") {
    topReasons.push("You favored polished fidelity.");
  } else if (aestheticOnboardingState.answers.directionality === "speed") {
    topReasons.push("You favored speed and iteration loops.");
  } else {
    topReasons.push("You preferred a balanced speed/quality default.");
  }
  const mappedNote =
    winner.modelValue && winner.modelValue !== winner.id
      ? `This preference maps to ${winner.modelValue} inside Cue right now.`
      : `This will become your default Image Model in Settings and Effects.`;
  return `
    <section class="aesthetic-question">
      <div class="aesthetic-question-head">
        <h3>Your default model recommendation</h3>
        <p>Confirm to apply it as your Cue image default.</p>
      </div>
      <div class="aesthetic-summary-card">
        <div class="aesthetic-summary-label">Recommended model</div>
        <div class="aesthetic-summary-model">${winner.label}</div>
        <div class="aesthetic-summary-note">${mappedNote}</div>
        <ul class="aesthetic-summary-reasons">
          ${topReasons.map((reason) => `<li>${reason}</li>`).join("")}
        </ul>
      </div>
    </section>
  `;
}

function canAdvanceAestheticStep(stepIndex = aestheticOnboardingState.stepIndex) {
  if (stepIndex === 0) return Boolean(aestheticOnboardingState.answers.imageChoiceId);
  if (stepIndex === 1) return Boolean(aestheticOnboardingState.answers.featurePriority);
  if (stepIndex === 2) return Boolean(aestheticOnboardingState.answers.directionality);
  return true;
}

function renderAestheticOnboardingStep({ animate = false } = {}) {
  if (!els.aestheticOnboardingModal || !els.aestheticOnboardingBody) return;
  const stepIndex = Math.max(0, Math.min(3, Number(aestheticOnboardingState.stepIndex) || 0));
  const renderBody = () => {
    if (stepIndex === 0) {
      els.aestheticOnboardingBody.innerHTML = buildAestheticQuestionStepHtml();
    } else if (stepIndex === 1) {
      els.aestheticOnboardingBody.innerHTML = buildAestheticOptionStepHtml({
        answerKey: "featurePriority",
        title: "What Cue feature do you expect to use the most?",
        subtitle: "This helps us bias toward a better default model for your workflow.",
        options: AESTHETIC_FEATURE_OPTIONS,
      });
    } else if (stepIndex === 2) {
      els.aestheticOnboardingBody.innerHTML = buildAestheticOptionStepHtml({
        answerKey: "directionality",
        title: "How should Cue bias your default?",
        subtitle: "Choose whether speed or final polish matters more by default.",
        options: AESTHETIC_DIRECTION_OPTIONS,
      });
    } else {
      els.aestheticOnboardingBody.innerHTML = buildAestheticSummaryStepHtml();
    }
  };

  if (animate) {
    if (aestheticOnboardingState.transitionTimer) {
      clearTimeout(aestheticOnboardingState.transitionTimer);
      aestheticOnboardingState.transitionTimer = null;
    }
    els.aestheticOnboardingBody.classList.add("is-fading-out");
    aestheticOnboardingState.transitionTimer = setTimeout(() => {
      renderBody();
      els.aestheticOnboardingBody.classList.remove("is-fading-out");
      els.aestheticOnboardingBody.classList.add("is-fading-in");
      requestAnimationFrame(() => els.aestheticOnboardingBody?.classList.remove("is-fading-in"));
    }, 130);
  } else {
    els.aestheticOnboardingBody.classList.remove("is-fading-out");
    renderBody();
  }

  const currentStep = stepIndex + 1;
  if (els.aestheticOnboardingTitle) {
    els.aestheticOnboardingTitle.textContent = currentStep <= 3 ? "Find your visual baseline" : "Aesthetic profile ready";
  }
  if (els.aestheticOnboardingSubtitle) {
    els.aestheticOnboardingSubtitle.textContent =
      currentStep <= 3
        ? `Question ${currentStep} of 3`
        : "Apply this recommendation as your default image model.";
  }
  renderAestheticOnboardingProgress(stepIndex);
  if (els.aestheticOnboardingBack) {
    els.aestheticOnboardingBack.classList.toggle("hidden", stepIndex <= 0);
    els.aestheticOnboardingBack.disabled = aestheticOnboardingState.applying;
  }
  if (els.aestheticOnboardingSkip) {
    els.aestheticOnboardingSkip.classList.toggle("hidden", stepIndex >= 3);
    els.aestheticOnboardingSkip.disabled = aestheticOnboardingState.applying;
  }
  if (els.aestheticOnboardingClose) {
    els.aestheticOnboardingClose.textContent = stepIndex >= 3 ? "Keep current" : "Skip";
    els.aestheticOnboardingClose.disabled = aestheticOnboardingState.applying;
  }
  if (els.aestheticOnboardingNext) {
    if (stepIndex < 2) els.aestheticOnboardingNext.textContent = "Next";
    else if (stepIndex === 2) els.aestheticOnboardingNext.textContent = "See result";
    else {
      const scored = scoreAestheticOnboardingAnswers(aestheticOnboardingState.answers);
      const winner = getAestheticModelChoice(scored.winnerId);
      els.aestheticOnboardingNext.textContent = winner ? `Set ${winner.modelValue}` : "Set default model";
    }
    const cannotAdvance = stepIndex < 3 && !canAdvanceAestheticStep(stepIndex);
    els.aestheticOnboardingNext.disabled = cannotAdvance || aestheticOnboardingState.applying;
  }
}

function closeAestheticOnboardingModal() {
  if (aestheticOnboardingState.transitionTimer) {
    clearTimeout(aestheticOnboardingState.transitionTimer);
    aestheticOnboardingState.transitionTimer = null;
  }
  aestheticOnboardingState.open = false;
  aestheticOnboardingState.applying = false;
  if (els.aestheticOnboardingModal) {
    els.aestheticOnboardingModal.classList.add("hidden");
  }
}

function openAestheticOnboardingModal({ force = false, source = "first_run" } = {}) {
  if (!els.aestheticOnboardingModal) return false;
  const completed = localStorage.getItem(AESTHETIC_ONBOARDING_COMPLETED_KEY) === "1";
  if (!force && completed) return false;
  aestheticOnboardingState.open = true;
  aestheticOnboardingState.stepIndex = 0;
  aestheticOnboardingState.answers = defaultAestheticAnswers();
  aestheticOnboardingState.source = source;
  aestheticOnboardingState.applying = false;
  els.aestheticOnboardingModal.classList.remove("hidden");
  renderAestheticOnboardingStep({ animate: false });
  emitInstallTelemetryAsync("onboarding_started", {
    onboarding: "aesthetic",
    source: String(source || "unknown"),
  });
  return true;
}

function saveAestheticOnboardingCompletion({
  skipped = false,
  preferredModelId = null,
  scoreByModel = null,
  appliedModel = null,
} = {}) {
  const profile = {
    version: 1,
    source: aestheticOnboardingState.source,
    skipped: Boolean(skipped),
    completedAt: new Date().toISOString(),
    preferredModelId: preferredModelId || null,
    preferredModelValue: preferredModelId ? getAestheticModelChoice(preferredModelId)?.modelValue || null : null,
    appliedModel: appliedModel || null,
    answers: { ...aestheticOnboardingState.answers },
    scoreByModel: scoreByModel && typeof scoreByModel === "object" ? scoreByModel : null,
  };
  saveAestheticOnboardingProfile(profile);
  markAestheticOnboardingCompleted(true);
  renderAestheticOnboardingStatus();
  if (profile.skipped) {
    emitInstallTelemetryAsync("onboarding_skipped", {
      onboarding: "aesthetic",
      source: String(profile.source || "unknown"),
    });
  } else {
    emitInstallTelemetryAsync("onboarding_completed", {
      onboarding: "aesthetic",
      source: String(profile.source || "unknown"),
    });
  }
}

async function applyImageModelSetting(nextValue, { announce = false } = {}) {
  const requested = String(nextValue || "").trim();
  if (!requested) return false;
  let resolved = requested;
  if (els.imageModel) {
    const optionValues = Array.from(els.imageModel.options || [])
      .map((opt) => String(opt?.value || "").trim())
      .filter(Boolean);
    if (optionValues.length && !optionValues.includes(resolved)) {
      resolved = optionValues.includes(DEFAULT_IMAGE_MODEL) ? DEFAULT_IMAGE_MODEL : optionValues[0];
    }
  }
  const changed = resolved !== settings.imageModel;
  settings.imageModel = resolved;
  localStorage.setItem("cue.imageModel", settings.imageModel);
  if (els.imageModel) {
    els.imageModel.value = settings.imageModel;
  }
  updatePortraitIdle({ fromSettings: true });
  if (state.ptySpawned) {
    await invoke("write_pty", { data: `${PTY_COMMANDS.IMAGE_MODEL} ${settings.imageModel}\n` }).catch(() => {});
  }
  if (announce && changed) {
    showToast(`Default image model set to ${settings.imageModel}.`, "tip", 2600);
  }
  renderAestheticOnboardingStatus();
  return changed;
}

async function finalizeAestheticOnboarding({ applyRecommendation = true } = {}) {
  const scored = scoreAestheticOnboardingAnswers(aestheticOnboardingState.answers);
  const winner = getAestheticModelChoice(scored.winnerId) || AESTHETIC_ONBOARDING_MODEL_CHOICES[0] || null;
  let appliedModel = null;
  if (applyRecommendation && winner?.modelValue) {
    aestheticOnboardingState.applying = true;
    renderAestheticOnboardingStep({ animate: false });
    await applyImageModelSetting(winner.modelValue, { announce: true }).catch(() => {});
    appliedModel = winner.modelValue;
  }
  saveAestheticOnboardingCompletion({
    skipped: !applyRecommendation,
    preferredModelId: winner?.id || null,
    scoreByModel: scored.scoreByModel,
    appliedModel,
  });
  closeAestheticOnboardingModal();
}

function skipAestheticOnboarding() {
  saveAestheticOnboardingCompletion({
    skipped: true,
    preferredModelId: null,
    scoreByModel: null,
    appliedModel: null,
  });
  closeAestheticOnboardingModal();
}

function providerFromModel(model) {
  const name = String(model || "").toLowerCase();
  if (!name) return null;
  if (name.startsWith("gemini")) return "gemini";
  if (name.startsWith("imagen") || name.includes("imagen")) return "imagen";
  if (name.startsWith("gpt-image") || name.startsWith("gptimage") || name.startsWith("openai")) return "openai";
  if (name.startsWith("flux")) return "flux";
  if (name.startsWith("sdxl")) return "sdxl";
  if (name.startsWith("dryrun")) return "dryrun";
  if (name.includes("claude")) return "anthropic";
  if (name.includes("gpt-") || name.includes("o1")) return "openai";
  return "unknown";
}

function googleBrandRectColorForKey(key = "", alpha = 0.44) {
  const palette = GOOGLE_BRAND_RECT_PALETTE_RGB;
  if (!Array.isArray(palette) || !palette.length) return `rgba(66, 133, 244, ${alpha})`;
  const idx = Math.abs(Number(hash32(String(key || ""))) || 0) % palette.length;
  return googleBrandRectColorForIndex(idx, alpha);
}

function googleBrandRectColorForIndex(index = 0, alpha = 0.44) {
  const palette = GOOGLE_BRAND_RECT_PALETTE_RGB;
  if (!Array.isArray(palette) || !palette.length) return `rgba(66, 133, 244, ${alpha})`;
  const len = Math.max(1, palette.length);
  const rawIndex = Math.floor(Number(index) || 0);
  const idx = ((rawIndex % len) + len) % len;
  const rgb = Array.isArray(palette[idx]) ? palette[idx] : palette[0];
  const a = Math.max(0, Math.min(1, Number(alpha) || 0));
  return `rgba(${Number(rgb[0]) || 66}, ${Number(rgb[1]) || 133}, ${Number(rgb[2]) || 244}, ${a})`;
}

function pickGeminiImageModel() {
  // Prefer the stronger multi-image model, but fall back to any Gemini option in the UI.
  const preferred = ["gemini-3-pro-image-preview", "gemini-2.5-flash-image"];
  for (const candidate of preferred) {
    if (providerFromModel(candidate) !== "gemini") continue;
    if (!els.imageModel) return candidate;
    if (Array.from(els.imageModel.options || []).some((opt) => opt?.value === candidate)) return candidate;
  }
  if (els.imageModel) {
    const opt = Array.from(els.imageModel.options || []).find(
      (o) => providerFromModel(o?.value) === "gemini"
    );
    if (opt?.value) return opt.value;
  }
  return "gemini-3-pro-image-preview";
}

function pickGeminiFastImageModel() {
  const desired = "gemini-2.5-flash-image";
  if (!els.imageModel) return desired;
  const hasDesired = Array.from(els.imageModel.options || []).some((opt) => opt?.value === desired);
  return hasDesired ? desired : pickGeminiImageModel();
}

// Action-specific model routing (quick actions / tools that drive the engine).
const ACTION_IMAGE_MODEL = {
  bg_replace: "gemini-2.5-flash-image",
  // Niche action: route to FLUX by default for testing; the global Image Model setting remains unchanged.
  surprise: "flux-2-pro",
  combine: "gemini-3-pro-image-preview",
  swap_dna: "gemini-3-pro-image-preview",
  bridge: "gemini-3-pro-image-preview",
  create_layers: "gemini-3-pro-image-preview",
  extract_dna_apply: "gemini-2.5-flash-image",
  soul_leech_apply: "gemini-2.5-flash-image",
  recast: "gemini-3-pro-image-preview",
  remove_people: "gemini-3-pro-image-preview",
};

async function ensureGeminiProImagePreviewForAction(actionLabel = "This action") {
  const desired = "gemini-3-pro-image-preview";
  const provider = providerFromModel(settings.imageModel);
  if (provider === "gemini" && settings.imageModel === desired) return true;

  let nextModel = desired;
  if (els.imageModel) {
    const hasDesired = Array.from(els.imageModel.options || []).some((opt) => opt?.value === desired);
    if (!hasDesired) nextModel = pickGeminiImageModel();
  }

  const changed = settings.imageModel !== nextModel;
  settings.imageModel = nextModel;
  localStorage.setItem("cue.imageModel", settings.imageModel);
  if (els.imageModel) els.imageModel.value = settings.imageModel;
  updatePortraitIdle({ fromSettings: true });
  if (state.ptySpawned) {
    await invoke("write_pty", { data: `${PTY_COMMANDS.IMAGE_MODEL} ${settings.imageModel}\n` }).catch(() => {});
  }

  if (changed) {
    if (nextModel === desired) {
      showToast(`${actionLabel} uses Gemini Pro. Switched image model to ${settings.imageModel}.`, "tip", 3200);
    } else {
      showToast(`${actionLabel} prefers ${desired}. Using ${settings.imageModel}.`, "tip", 3400);
    }
  }

  return providerFromModel(settings.imageModel) === "gemini";
}

function providerDisplay(provider) {
  if (!provider) return "Unknown";
  if (provider === "openai") return "OpenAI";
  if (provider === "gemini") return "Gemini";
  if (provider === "imagen") return "Imagen";
  if (provider === "flux") return "Flux";
  if (provider === "anthropic") return "Anthropic";
  if (provider === "sdxl") return "SDXL";
  if (provider === "dryrun") return "Dryrun";
  return String(provider);
}

function formatPortraitModelLabel(model) {
  const raw = String(model || "").trim();
  if (!raw) return "";
  const lower = raw.toLowerCase();
  const byExact = {
    "gemini-3-pro-image-preview": "Gem3Pro",
    "gemini-2.5-flash-image": "Gem2.5F",
    "imagen-4.0-ultra": "Img4Ult",
    "imagen-4": "Imagen4",
    "flux-2-max": "Flux2Mx",
    "flux-2-flex": "Flux2Fx",
    "flux-2-pro": "Flux2Pr",
    "flux-2": "Flux2",
    "gpt-image-1.5": "GImg1.5",
    "gpt-image-1-mini": "GImg1Mn",
    "gpt-image-1": "GImg1",
    "gpt-5.2": "GPT5.2",
    "gpt-5.1-codex-max": "GPT5.1C",
    "claude-opus-4-5-20251101": "ClOp4.5",
    "dryrun-text-1": "DryText",
    "dryrun-image-1": "DryImg",
  };
  const MAX = 8;
  function clampLabel(label) {
    return String(label || "").slice(0, MAX);
  }
  if (byExact[lower]) return clampLabel(byExact[lower]);
  if (lower.startsWith("gemini")) return "Gemini".slice(0, MAX);
  if (lower.startsWith("gpt")) return "GPT".slice(0, MAX);
  if (lower.startsWith("imagen")) return "Imagen".slice(0, MAX);
  if (lower.startsWith("flux")) return "Flux".slice(0, MAX);
  if (lower.startsWith("claude")) return "Claude".slice(0, MAX);
  if (lower.startsWith("dryrun")) return "Dryrun".slice(0, MAX);
  return clampLabel(raw);
}

function portraitTitleForSlot(slot, provider) {
  const imageModel = String(settings.imageModel || "").trim();
  const textModel = String(settings.textModel || "").trim();
  const providerKey = String(provider || "").toLowerCase();
  if (slot === "primary") {
    if (imageModel) return formatPortraitModelLabel(imageModel);
  } else {
    if (textModel) return formatPortraitModelLabel(textModel);
  }
  if (imageModel && providerFromModel(imageModel) === providerKey) return formatPortraitModelLabel(imageModel);
  if (textModel && providerFromModel(textModel) === providerKey) return formatPortraitModelLabel(textModel);
  return providerDisplay(provider);
}

const PORTRAITS_DIR_LS_KEY = "cue.portraitsDir";
const PORTRAITS_DIR_DISK_FILE = "portraits_dir.json";

async function getPortraitsDirDiskPath() {
  try {
    const home = await homeDir();
    if (!home) return null;
    const cuePath = await join(home, ".cue", PORTRAITS_DIR_DISK_FILE);
    if (await exists(cuePath).catch(() => false)) return cuePath;
    const legacyPath = await join(home, ".brood", PORTRAITS_DIR_DISK_FILE);
    if (await exists(legacyPath).catch(() => false)) return legacyPath;
    return cuePath;
  } catch (_) {
    return null;
  }
}

async function loadPortraitsDirFromDisk() {
  if (state.portraitMedia.diskDirChecked) return state.portraitMedia.diskDir;
  if (state.portraitMedia.diskDirPromise) return await state.portraitMedia.diskDirPromise;
  state.portraitMedia.diskDirPromise = (async () => {
    const path = await getPortraitsDirDiskPath();
    if (!path) return null;
    if (!(await exists(path).catch(() => false))) return null;
    try {
      const payload = JSON.parse(await readTextFile(path));
      const dir = typeof payload?.dir === "string" ? payload.dir.trim() : "";
      return dir ? dir : null;
    } catch (_) {
      return null;
    }
  })();
  try {
    state.portraitMedia.diskDir = await state.portraitMedia.diskDirPromise;
    state.portraitMedia.diskDirChecked = true;
    return state.portraitMedia.diskDir;
  } finally {
    state.portraitMedia.diskDirPromise = null;
  }
}

async function persistPortraitsDirToDisk(dir) {
  try {
    const home = await homeDir();
    if (!home) return;
    const cueDir = await join(home, ".cue");
    await createDir(cueDir, { recursive: true }).catch(() => {});
    const path = await join(cueDir, PORTRAITS_DIR_DISK_FILE);
    const payload = { dir: String(dir || "").trim() || null, updated_at: new Date().toISOString() };
    await writeTextFile(path, JSON.stringify(payload, null, 2));
    state.portraitMedia.diskDir = payload.dir;
    state.portraitMedia.diskDirChecked = true;
  } catch (_) {
    // ignore
  }
}

async function clearPortraitsDirOnDisk() {
  try {
    const path = await getPortraitsDirDiskPath();
    if (path) await removeFile(path).catch(() => {});
  } catch (_) {}
  state.portraitMedia.diskDir = null;
  state.portraitMedia.diskDirChecked = true;
}

function renderPortraitsDirReadout() {
  if (!els.portraitsDir) return;
  const custom = localStorage.getItem(PORTRAITS_DIR_LS_KEY);
  const disk = state.portraitMedia.diskDirChecked ? state.portraitMedia.diskDir : null;
  const resolved = state.portraitMedia.dir;
  const lines = [];
  if (custom) lines.push(`Custom (this build): ${custom}`);
  else if (disk) lines.push(`Custom (all builds): ${disk}`);
  if (resolved) {
    lines.push(`Using: ${resolved}`);
  } else if (state.portraitMedia.dirChecked) {
    lines.push("Using: (not found)");
    if (state.portraitMedia.lastResolveError) {
      lines.push(`Why: ${clampText(state.portraitMedia.lastResolveError, 180)}`);
    }
  } else {
    lines.push("Using: (searching...)");
  }
  els.portraitsDir.textContent = lines.join("\n");
}

async function refreshPortraitsDirReadout() {
  renderPortraitsDirReadout();
  try {
    await resolvePortraitsDir();
  } catch (_) {}
  renderPortraitsDirReadout();
}

function invalidatePortraitMediaCache() {
  state.portraitMedia.dir = null;
  state.portraitMedia.dirChecked = false;
  state.portraitMedia.dirPromise = null;
  state.portraitMedia.lastResolveError = null;
  state.portraitMedia.index = null;
  state.portraitMedia.indexChecked = false;
  state.portraitMedia.indexPromise = null;
  state.portraitMedia.activeKey1 = null;
  state.portraitMedia.activeKey2 = null;
  state.portraitMedia.missingToastShown = false;
  state.portraitMedia.loadErrorToastShown = false;
  if (state.portraitMedia.urlCache) {
    for (const rec of state.portraitMedia.urlCache.values()) {
      const url = rec?.url;
      if (!url) continue;
      try {
        URL.revokeObjectURL(url);
      } catch {
        // ignore
      }
    }
    state.portraitMedia.urlCache.clear();
  } else {
    state.portraitMedia.urlCache = new Map();
  }
}

async function pickPortraitsDir() {
  bumpInteraction();
  const picked = await open({ directory: true, multiple: false });
  const dir = Array.isArray(picked) ? picked[0] : picked;
  if (!dir) return;
  localStorage.setItem(PORTRAITS_DIR_LS_KEY, String(dir));
  persistPortraitsDirToDisk(String(dir)).catch(() => {});
  invalidatePortraitMediaCache();
  renderPortraitsDirReadout();
  ensurePortraitIndex().catch(() => {});
  updatePortraitIdle({ fromSettings: true });
}

function portraitAgentFromProvider(provider) {
  const p = String(provider || "").toLowerCase();
  // Primary mapping is provider-native so labels and visuals stay intuitive.
  if (p === "openai") return "openai";
  if (p === "sdxl" || p === "stability") return "stability";
  if (p === "gemini") return "gemini";
  if (p === "imagen") return "imagen";
  if (p === "flux") return "flux";
  return null;
}

function portraitFallbackAgentFromProvider(provider) {
  const p = String(provider || "").toLowerCase();
  // Secondary fallback keeps compatibility with the older swapped portrait packs.
  if (p === "openai") return "stability";
  if (p === "sdxl" || p === "stability") return "openai";
  if (p === "gemini") return "flux";
  if (p === "flux") return "gemini";
  return null;
}

function portraitClipPathForAgent(index, agent, clipState) {
  if (!index || !agent) return null;
  let clipPath = index?.[agent]?.[clipState] || null;
  if (!clipPath && clipState === "working") clipPath = index?.[agent]?.idle || null;
  return clipPath || null;
}

function portraitProviderForActiveKey(activeKeyField) {
  if (activeKeyField === "activeKey1") return state?.portrait?.provider || null;
  if (activeKeyField === "activeKey2") return state?.portrait2?.provider || null;
  return null;
}

function looksLikePortraitClipName(name) {
  const lower = String(name || "").toLowerCase();
  // Stable: `gemini_idle.mp4`
  if (lower.match(/^(dryrun|openai|gemini|imagen|flux|stability)_(idle|working)\.(mp4|mov|webm)$/)) {
    return true;
  }
  // Variant/timestamped: `gemini_idle_20240201_010203....mp4`
  return Boolean(lower.match(/^(dryrun|openai|gemini|imagen|flux|stability)_(idle|working)_.+\.(mp4|mov|webm)$/));
}

async function scanPortraitDir(dir) {
  const result = { entries: 0, videos: 0, matches: 0, sampleVideos: [] };
  if (!dir) return result;
  const candidateDirs = [dir];
  try {
    candidateDirs.push(await join(dir, "etc"));
  } catch (_) {}
  for (const candidateDir of candidateDirs) {
    let entries = [];
    try {
      entries = await readDir(candidateDir, { recursive: false });
    } catch (_) {
      continue;
    }
    for (const entry of entries || []) {
      const path = entry?.path;
      if (!path) continue;
      result.entries += 1;
      const ext = extname(path);
      if (ext !== ".mp4" && ext !== ".mov" && ext !== ".webm") continue;
      result.videos += 1;
      const name = basename(path);
      if (result.sampleVideos.length < 4 && name) result.sampleVideos.push(name);
      if (looksLikePortraitClipName(name)) result.matches += 1;
    }
  }
  return result;
}

async function deriveMainRepoRootFromWorktree(repoRoot) {
  if (!repoRoot) return null;
  try {
    const gitPath = await join(repoRoot, ".git");
    const content = await readTextFile(gitPath);
    const firstLine = String(content || "").split(/\r?\n/)[0] || "";
    const match = firstLine.match(/^gitdir:\s*(.+)\s*$/i);
    if (!match) return null;
    const gitdir = String(match[1] || "").trim();
    if (!gitdir) return null;

    const needlePosix = "/.git/worktrees/";
    const needleWin = "\\\\.git\\\\worktrees\\\\";
    let idx = gitdir.indexOf(needlePosix);
    if (idx !== -1) return gitdir.slice(0, idx) || null;
    idx = gitdir.indexOf(needleWin);
    if (idx !== -1) return gitdir.slice(0, idx) || null;
  } catch (_) {
    // ignore
  }
  return null;
}

async function resolvePortraitsDir() {
  if (state.portraitMedia.dirChecked) return state.portraitMedia.dir;
  if (state.portraitMedia.dirPromise) return await state.portraitMedia.dirPromise;
  state.portraitMedia.dirPromise = (async () => {
    state.portraitMedia.lastResolveError = null;
    const candidates = [];
    const fromLsRaw = localStorage.getItem(PORTRAITS_DIR_LS_KEY);
    const fromLs = fromLsRaw ? String(fromLsRaw).trim() : "";
    if (fromLs) candidates.push(fromLs);
    const fromDisk = await loadPortraitsDirFromDisk();
    if (fromDisk && (!fromLs || String(fromDisk) !== String(fromLs).trim())) candidates.push(String(fromDisk).trim());

    // Dev convenience: use repo-local tracked portrait videos first, then generated outputs.
    try {
      const repoRoot = await invoke("get_repo_root");
      if (repoRoot) {
        // Tracked baseline portrait pack for fresh clones.
        candidates.push(await join(repoRoot, "desktop", "src", "assets", "portraits", "videos"));
        // Back-compat with older checkouts that stored videos directly under portraits/.
        candidates.push(await join(repoRoot, "desktop", "src", "assets", "portraits"));
        candidates.push(await join(repoRoot, "outputs", "sora_portraits"));

        // If we're running inside a git worktree checkout, `.git` is a file that points
        // at the main repo's `.git/worktrees/...`. The portrait MP4s are often generated
        // in the main repo's `outputs/` (and are usually untracked), so prefer that if present.
        const mainRoot = await deriveMainRepoRootFromWorktree(repoRoot);
        if (mainRoot && mainRoot !== repoRoot) {
          candidates.push(await join(mainRoot, "desktop", "src", "assets", "portraits", "videos"));
          candidates.push(await join(mainRoot, "desktop", "src", "assets", "portraits"));
          candidates.push(await join(mainRoot, "outputs", "sora_portraits"));
        }
      }
    } catch (_) {}

    // Default persisted location (recommended for packaged builds).
    try {
      const home = await homeDir();
      if (home) {
        candidates.push(await join(home, ".cue", "portraits"));
        candidates.push(await join(home, "cue_runs", "portraits"));
        candidates.push(await join(home, ".brood", "portraits"));
        candidates.push(await join(home, "brood_runs", "portraits"));
      }
    } catch (_) {}

    const primaryCandidate = candidates.length > 0 ? String(candidates[0]) : "";
    let primaryError = null;
    let lastError = null;

    for (const dir of candidates) {
      let dirError = null;
      let ok = false;
      try {
        ok = await exists(dir);
      } catch (err) {
        dirError = `Cannot access folder: ${err?.message || err}`;
        if (dir === primaryCandidate) primaryError = primaryError || dirError;
        lastError = dirError;
        continue;
      }
      if (!ok) {
        dirError = `Folder not found: ${dir}`;
        if (dir === primaryCandidate) primaryError = primaryError || dirError;
        lastError = dirError;
        continue;
      }
      try {
        const scan = await scanPortraitDir(dir);
        if (scan.matches > 0) return dir;
        if (scan.videos === 0) {
          dirError = `No portrait clips found in: ${dir} (${scan.entries} entries, 0 videos)`;
        } else {
          const sample = scan.sampleVideos.length ? ` Sample: ${scan.sampleVideos.join(", ")}` : "";
          dirError = `No portrait clips matched naming in: ${dir} (${scan.videos} videos, 0 matches).${sample}`;
        }
      } catch (err) {
        dirError = `Cannot read folder: ${err?.message || err}`;
      }
      if (dirError) {
        if (dir === primaryCandidate) primaryError = primaryError || dirError;
        lastError = dirError;
      }
    }

    state.portraitMedia.lastResolveError = primaryError || lastError || null;
    return null;
  })();
  try {
    state.portraitMedia.dir = await state.portraitMedia.dirPromise;
    state.portraitMedia.dirChecked = true;
    renderPortraitsDirReadout();
    return state.portraitMedia.dir;
  } finally {
    state.portraitMedia.dirPromise = null;
  }
}

function extractPortraitStamp(name) {
  const matches = String(name || "").match(/\d{8}_\d{6}/g);
  if (!matches || matches.length === 0) return "";
  return matches[matches.length - 1] || "";
}

function isStablePortraitName(name, agent, clipState) {
  const lower = String(name || "").toLowerCase();
  const targets = [
    `${agent}_${clipState}.mp4`,
    `${agent}_${clipState}.mov`,
    `${agent}_${clipState}.webm`,
  ];
  return targets.includes(lower);
}

async function buildPortraitIndex(dir) {
  // Prefer a known-good Stability "working" clip as the default OpenAI waiting video.
  // OpenAI provider currently maps to the "stability" portrait agent (see portraitAgentFromProvider()).
  const DEFAULT_STABILITY_WORKING_CLIP =
    "stability_working_sora-2_720x1280_12s_20260205_231943.sq.mute.mp4";
  const DEFAULT_STABILITY_IDLE_CLIP =
    "stability_idle_sora-2_720x1280_12s_20260205_231943.sq.mute.mp4";
  const DEFAULT_FLUX_WORKING_CLIP = "flux_working_sora-2_720x1280_12s_20260209_183745.sq.mute.mp4";
  const DEFAULT_FLUX_IDLE_CLIP = "flux_idle_sora-2_720x1280_12s_20260209_183745.sq.mute.mp4";

  const index = {
    dryrun: { idle: null, working: null },
    openai: { idle: null, working: null },
    gemini: { idle: null, working: null },
    imagen: { idle: null, working: null },
    flux: { idle: null, working: null },
    stability: { idle: null, working: null },
  };

  let entries = [];
  try {
    entries = await readDir(dir, { recursive: false });
  } catch (_) {
    return index;
  }
  try {
    const etcDir = await join(dir, "etc");
    const etcEntries = await readDir(etcDir, { recursive: false });
    if (Array.isArray(etcEntries) && etcEntries.length) {
      entries.push(...etcEntries);
    }
  } catch (_) {}

  const candidates = entries
    .map((e) => ({ path: e?.path, name: basename(e?.path) || e?.name }))
    .filter((e) => {
      if (!e.path) return false;
      const ext = extname(e.path);
      return ext === ".mp4" || ext === ".mov" || ext === ".webm";
    });

  for (const item of candidates) {
    const name = String(item.name || "").toLowerCase();
    // Accept both "agent_idle_*" (timestamped / variant clips) and the stable
    // "agent_idle.mp4" naming used for hand-curated overrides.
    const match = name.match(/^(dryrun|openai|gemini|imagen|flux|stability)_(idle|working)(?:_|\.)/);
    if (!match) continue;
    const agent = match[1];
    const clipState = match[2];
    const stamp = extractPortraitStamp(name);
    let priority = isStablePortraitName(name, agent, clipState) ? 2 : 1;
    if (
      agent === "stability" &&
      clipState === "working" &&
      name === String(DEFAULT_STABILITY_WORKING_CLIP).toLowerCase()
    ) {
      priority = 3;
    }
    if (
      agent === "stability" &&
      clipState === "idle" &&
      name === String(DEFAULT_STABILITY_IDLE_CLIP).toLowerCase()
    ) {
      priority = 3;
    }
    if (agent === "flux" && clipState === "working" && name === String(DEFAULT_FLUX_WORKING_CLIP).toLowerCase()) {
      priority = 3;
    }
    if (agent === "flux" && clipState === "idle" && name === String(DEFAULT_FLUX_IDLE_CLIP).toLowerCase()) {
      priority = 3;
    }
    const slot = index[agent]?.[clipState];
    if (!slot) {
      // First one wins until a higher-priority / newer candidate arrives.
      index[agent][clipState] = { path: item.path, priority, stamp };
      continue;
    }
    const slotPrio = slot.priority || 0;
    const slotStamp = slot.stamp || "";
    const isBetter =
      priority > slotPrio || (priority === slotPrio && stamp && (!slotStamp || stamp > slotStamp));
    if (isBetter) {
      index[agent][clipState] = { path: item.path, priority, stamp };
    }
  }

  // Strip metadata: callers only care about a path or null.
  for (const agent of Object.keys(index)) {
    for (const clipState of ["idle", "working"]) {
      const v = index[agent][clipState];
      index[agent][clipState] = v && v.path ? v.path : null;
    }
  }
  return index;
}

async function ensurePortraitIndex() {
  if (state.portraitMedia.indexChecked) return state.portraitMedia.index;
  if (state.portraitMedia.indexPromise) return await state.portraitMedia.indexPromise;
  state.portraitMedia.indexPromise = (async () => {
    const dir = await resolvePortraitsDir();
    if (!dir) return null;
    return await buildPortraitIndex(dir);
  })();
  try {
    state.portraitMedia.index = await state.portraitMedia.indexPromise;
    state.portraitMedia.indexChecked = true;
    renderPortraitsDirReadout();
    return state.portraitMedia.index;
  } finally {
    state.portraitMedia.indexPromise = null;
  }
}

async function refreshPortraitVideo() {
  // Back-compat shim: older callers still invoke refreshPortraitVideo(). Keep it
  // delegating to the new multi-slot portrait implementation.
  await refreshAgentPortraitVideos();
}

function secondaryProviderFor(primaryProvider, index = null) {
  // Secondary portrait is UI-only. Prefer showing the *other* provider the user is
  // actually configured to use (text vs image), rather than an arbitrary always-on
  // mascot (Flux).
  const primary = String(primaryProvider || "").toLowerCase();
  const textProvider = providerFromModel(settings.textModel);
  const preferred = [];
  if (textProvider) preferred.push(textProvider);
  // Sensible fallbacks if the text provider doesn't have clips.
  preferred.push("gemini", "openai", "imagen", "flux", "sdxl");
  const ordered = Array.from(new Set(preferred.map((p) => String(p || "").toLowerCase()).filter(Boolean)));
  const candidates = ordered.filter((p) => p !== primary);

  function hasIdle(provider) {
    if (!index) return true; // optimistic until the index loads
    const agent = portraitAgentFromProvider(provider);
    return Boolean(index?.[agent]?.idle || index?.[agent]?.working);
  }

  for (const provider of candidates) {
    if (hasIdle(provider)) return provider;
  }

  // Even if we have no clips for any other provider, keep the secondary portrait
  // label different (the video loader will fall back to dryrun clips if needed).
  if (candidates.length) return candidates[0];
  return "gemini";
}

async function refreshPortraitVideoSlot({ videoEl, provider, busy, activeKeyField }) {
  if (!videoEl) return;
  const requestedProvider = String(provider || "").trim().toLowerCase();
  const currentProvider = String(portraitProviderForActiveKey(activeKeyField) || "")
    .trim()
    .toLowerCase();
  // Drop stale refreshes so older async calls cannot overwrite newer provider selections.
  if (requestedProvider !== currentProvider) return;
  // Portraits are decorative UI; they should load even before a run/photo is active.
  const visible = Boolean(els.portraitDock) && !els.portraitDock.classList.contains("hidden");
  if (!visible) {
    try {
      videoEl.pause();
    } catch (_) {}
    videoEl.classList.add("hidden");
    state.portraitMedia[activeKeyField] = null;
    return;
  }

  const agent = portraitAgentFromProvider(provider);
  const fallbackAgent = portraitFallbackAgentFromProvider(provider);
  const openAiBoost = openaiRealtimePortraitBoostActive && isOpenAiProvider(provider);
  const clipState = busy || openAiBoost ? "working" : "idle";
  const index = (await ensurePortraitIndex()) || {};
  const currentProviderAfterIndex = String(portraitProviderForActiveKey(activeKeyField) || "")
    .trim()
    .toLowerCase();
  if (requestedProvider !== currentProviderAfterIndex) return;

  // Prefer provider-native clips, then legacy swapped clips. Never use dryrun clips.
  let clipPath = portraitClipPathForAgent(index, agent, clipState);
  if (!clipPath && fallbackAgent && fallbackAgent !== agent) {
    clipPath = portraitClipPathForAgent(index, fallbackAgent, clipState);
  }

  if (!clipPath) {
    try {
      videoEl.pause();
    } catch (_) {}
    try {
      videoEl.removeAttribute("src");
      videoEl.load();
    } catch (_) {}
    videoEl.classList.add("hidden");
    state.portraitMedia[activeKeyField] = null;
    if (
      !state.portraitMedia.missingToastShown &&
      state.portraitMedia.dirChecked &&
      !state.portraitMedia.dir
    ) {
      state.portraitMedia.missingToastShown = true;
      showToast("Portrait clips not found. Settings -> Portraits Folder -> Choose…", "tip", 5200);
    }
    return;
  }

  let url = null;
  try {
    url = await ensureImageUrl(clipPath, state.portraitMedia.urlCache);
  } catch (err) {
    url = null;
    if (!state.portraitMedia.loadErrorToastShown) {
      state.portraitMedia.loadErrorToastShown = true;
      console.warn("Portrait clip load failed:", clipPath, err);
      showToast("Portrait clip failed to load. Check Portraits Folder in Settings.", "tip", 5200);
    }
  }
  if (!url) {
    videoEl.classList.add("hidden");
    state.portraitMedia[activeKeyField] = null;
    return;
  }

  const key = `${clipPath}:${clipState}`;
  const currentSrc = String(videoEl.currentSrc || videoEl.src || "");
  const needsSrcUpdate = Boolean(url && currentSrc !== String(url));
  if (state.portraitMedia[activeKeyField] !== key || needsSrcUpdate) {
    state.portraitMedia[activeKeyField] = key;
    videoEl.classList.remove("hidden");
    videoEl.src = url;
    try {
      videoEl.currentTime = 0;
    } catch (_) {}
    try {
      videoEl.load();
    } catch (_) {}
  }

  try {
    const p = videoEl.play();
    if (p && typeof p.catch === "function") p.catch(() => {});
  } catch (_) {}
}

async function refreshAgentPortraitVideos() {
  await Promise.all([
    refreshPortraitVideoSlot({
      videoEl: els.portraitVideo,
      provider: state.portrait.provider,
      busy: state.portrait.busy,
      activeKeyField: "activeKey1",
    }),
    refreshPortraitVideoSlot({
      videoEl: els.portraitVideo2,
      provider: state.portrait2.provider,
      busy: state.portrait2.busy,
      activeKeyField: "activeKey2",
    }),
  ]);
}

function setPortrait({ title, provider, busy } = {}) {
  syncPortraitDockVisibility();
  if (typeof busy === "boolean") {
    state.portrait.busy = busy;
  }
  if (provider !== undefined) {
    state.portrait.provider = provider;
    if (els.portraitAvatar) {
      els.portraitAvatar.dataset.provider = provider || "";
    }
  }
  if (title !== undefined) {
    state.portrait.title = title;
    if (els.portraitTitle) els.portraitTitle.textContent = title || "";
  }
  syncOpenAiRealtimePortraitBusyClasses();
  renderHudReadout();
  refreshAgentPortraitVideos().catch(() => {});
}

function setPortrait2({ title, provider, busy } = {}) {
  syncPortraitDockVisibility();
  if (typeof busy === "boolean") {
    state.portrait2.busy = busy;
  }
  if (provider !== undefined) {
    state.portrait2.provider = provider;
    if (els.portraitAvatar2) {
      els.portraitAvatar2.dataset.provider = provider || "";
    }
  }
  if (title !== undefined) {
    state.portrait2.title = title;
    if (els.portraitTitle2) els.portraitTitle2.textContent = title || "";
  }
  syncOpenAiRealtimePortraitBusyClasses();
  renderHudReadout();
  refreshAgentPortraitVideos().catch(() => {});
}

function updatePortraitIdle({ fromSettings = false } = {}) {
  // Persist the last provider we showed during an action until another action
  // replaces it (visual only; does not affect provider routing).
  //
  // When invoked from a settings change, prefer the selected model's provider.
  const providerDefault = providerFromModel(settings.imageModel);
  const provider = fromSettings ? providerDefault : state.portrait.provider || providerDefault;
  const hasImage = Boolean(state.activeId);
  const index = state.portraitMedia.index;
  const provider2Default = secondaryProviderFor(provider, index);
  let provider2 = fromSettings ? provider2Default : state.portrait2.provider || provider2Default;
  if (provider2 && provider && String(provider2).toLowerCase() === String(provider).toLowerCase()) {
    provider2 = secondaryProviderFor(provider, index);
  }
  setPortrait({
    visible: hasImage,
    busy: false,
    provider,
    title: portraitTitleForSlot("primary", provider),
  });
  setPortrait2({
    visible: hasImage,
    busy: false,
    provider: provider2,
    title: portraitTitleForSlot("secondary", provider2),
  });
  renderHudReadout();
}

function portraitWorking(_actionLabel, { providerOverride = null, forceProvider = false, clearDirector = true } = {}) {
  if (clearDirector && (state.lastDirectorText || state.lastDirectorMeta)) {
    state.lastDirectorText = null;
    state.lastDirectorMeta = null;
  }
  // Keep portrait identities stable during normal actions. Realtime paths can force
  // a provider switch (for example intent realtime OpenAI vs image-model Gemini).
  const overrideProvider = String(providerOverride || "")
    .trim()
    .toLowerCase();
  const providerDefault = providerFromModel(settings.imageModel) || overrideProvider || "gemini";
  const provider = forceProvider && overrideProvider ? overrideProvider : state.portrait.provider || providerDefault;
  setPortrait({
    visible: Boolean(state.activeId),
    busy: true,
    provider,
    title: portraitTitleForSlot("primary", provider),
  });
  // Secondary portrait is display-only for now (idle loop).
  const provider2Existing = state.portrait2.provider;
  const provider2 = forceProvider
    ? secondaryProviderFor(provider, state.portraitMedia.index)
    : provider2Existing || secondaryProviderFor(provider, state.portraitMedia.index);
  setPortrait2({
    visible: Boolean(state.activeId),
    busy: false,
    provider: provider2,
    title: portraitTitleForSlot("secondary", provider2),
  });
  renderHudReadout();
}

function renderKeyStatus(status) {
  if (!els.keyStatus) return;
  if (!status || typeof status !== "object") {
    els.keyStatus.textContent = "Key detection unavailable.";
    return;
  }
  const lines = [];
  lines.push(`OpenAI: ${status.openai ? "ok" : "missing"}`);
  lines.push(`OpenRouter: ${status.openrouter ? "ok" : "missing"}`);
  lines.push(`Gemini: ${status.gemini ? "ok" : "missing"}`);
  lines.push(`Imagen: ${status.imagen ? "ok" : "missing"}`);
  lines.push(`Flux: ${status.flux ? "ok" : "missing"}`);
  lines.push(`Anthropic: ${status.anthropic ? "ok" : "missing"}`);
  if (status.realtime_provider_default) {
    lines.push(
      `Realtime(default): ${status.realtime_provider_default} ${status.realtime_ready ? "ready" : "missing keys"}`
    );
  }
  if (status.realtime_provider_canvas_context) {
    lines.push(
      `Realtime(canvas): ${status.realtime_provider_canvas_context} ${
        status.realtime_ready_canvas_context ? "ready" : "missing keys"
      }`
    );
  }
  if (status.realtime_provider_intent) {
    lines.push(
      `Realtime(intent): ${status.realtime_provider_intent} ${status.realtime_ready_intent ? "ready" : "missing keys"}`
    );
  }
  els.keyStatus.textContent = lines.join("\n");
}

async function refreshKeyStatus({ reason = "general" } = {}) {
  try {
    const status = await invoke("get_key_status");
    state.keyStatus = status;
    renderKeyStatus(status);
    const telemetry = state.installTelemetry;
    const shouldEmit = reason !== "general" || !telemetry.providerCheckLogged;
    if (shouldEmit) {
      if (reason === "general") telemetry.providerCheckLogged = true;
      emitInstallTelemetryAsync("provider_check_ok", {
        provider: "key_status",
        reason: String(reason || "general"),
        openrouter: Boolean(status?.openrouter),
        openai: Boolean(status?.openai),
        gemini: Boolean(status?.gemini),
        realtime_ready: Boolean(status?.realtime_ready),
      });
    }
  } catch (err) {
    console.warn("Key detection failed:", err);
    state.keyStatus = null;
    renderKeyStatus(null);
    const telemetry = state.installTelemetry;
    const shouldEmit = reason !== "general" || !telemetry.providerCheckLogged;
    if (shouldEmit) {
      if (reason === "general") telemetry.providerCheckLogged = true;
      emitInstallTelemetryAsync("provider_check_fail", {
        provider: "key_status",
        reason: String(reason || "general"),
        error_code: telemetryClassifyErrorCode(err),
      });
    }
  } finally {
    renderOpenRouterOnboardingStatus();
    renderInstallTelemetryStatus();
    updateAlwaysOnVisionReadout();
  }
}

function setStatus(message, isError = false) {
  state.lastStatusText = String(message || "");
  state.lastStatusError = Boolean(isError);
  renderSessionApiCallsReadout();
}

function normalizeErrorMessage(err, fallback = "unknown error") {
  const msg = err?.message || err?.cause?.message || err?.reason?.message || err;
  const text = String(msg || fallback).replace(/\s+/g, " ").trim();
  if (!text) return String(fallback);
  return text.length > 180 ? `${text.slice(0, 179)}…` : text;
}

function reportUserError(context, err, { statusScope = "Engine", retryHint = "Try again." } = {}) {
  const label = String(context || "Action").trim() || "Action";
  const detail = normalizeErrorMessage(err);
  const statusLabel = label.toLowerCase();
  setStatus(`${statusScope}: ${statusLabel} failed (${detail})`, true);
  const hint = String(retryHint || "").trim();
  const suffix = hint ? ` ${hint}` : "";
  showToast(`${label} failed: ${detail}.${suffix}`, "error", 4200);
}

function runWithUserError(context, run, opts = {}) {
  const fn = typeof run === "function" ? run : null;
  if (!fn) return Promise.resolve(false);
  return Promise.resolve()
    .then(() => fn())
    .catch((err) => {
      console.error(`${context} failed:`, err);
      reportUserError(context, err, opts);
      return false;
    });
}

function captureRunResetSnapshot() {
  const queue = topMetricQueueCounts();
  return {
    runName: state.runDir ? basename(state.runDir) : "none",
    imageCount: Math.max(0, Number(state.images?.length) || 0),
    selectedCount: Math.max(0, Number(state.selectedIds?.length) || 0),
    queueDepth: Math.max(0, Number(queue.pending) || 0) + Math.max(0, Number(queue.running) || 0),
  };
}

function announceRunTransition(kind, snapshot) {
  const mode = String(kind || "").trim().toLowerCase();
  const summary = snapshot && typeof snapshot === "object" ? snapshot : captureRunResetSnapshot();
  const pieces = [];
  if (summary.imageCount > 0) pieces.push(`${summary.imageCount} photo${summary.imageCount === 1 ? "" : "s"}`);
  if (summary.selectedCount > 0) pieces.push(`${summary.selectedCount} selection${summary.selectedCount === 1 ? "" : "s"}`);
  if (summary.queueDepth > 0) pieces.push(`${summary.queueDepth} queued action${summary.queueDepth === 1 ? "" : "s"}`);
  const resetting = pieces.length ? pieces.join(", ") : "workspace state";
  if (mode === "open") {
    setStatus("Engine: opening run (resetting workspace)…");
    showToast(`Open Run: resetting ${resetting}.`, "tip", 3200);
    return;
  }
  setStatus("Engine: creating run (resetting workspace)…");
  showToast(`New Run: resetting ${resetting}.`, "tip", 3200);
}

function finalizeRunTransition(kind, { restoredArtifacts = 0, engineReady = true } = {}) {
  const mode = String(kind || "").trim().toLowerCase();
  const runName = basename(state.runDir) || "run";
  const ready = Boolean(engineReady);
  if (!ready) {
    if (mode === "open") {
      showToast(`Opened ${runName}, but engine failed to start. Retry Open Run.`, "error", 4200);
      return;
    }
    showToast(`Run ${runName} created, but engine failed to start. Retry New Run.`, "error", 4200);
    return;
  }
  if (mode === "open") {
    const restored = Math.max(0, Number(restoredArtifacts) || 0);
    showToast(
      `Opened ${runName}. Workspace reset complete; restored ${restored} artifact${restored === 1 ? "" : "s"}.`,
      "tip",
      3600
    );
    return;
  }
  showToast(`New run ready: ${runName}. Workspace reset complete.`, "tip", 3200);
}

function renderSessionApiCallsReadout() {
  renderTopMetricsGrid();
}

function bumpSessionApiCalls({ n = 1 } = {}) {
  const delta = Number(n) || 0;
  if (!Number.isFinite(delta) || delta <= 0) return;
  state.sessionApiCalls = (Number(state.sessionApiCalls) || 0) + delta;
  renderSessionApiCallsReadout();
}

let toastTimer = null;
let toastSwapTimer = null;
let juggernautExportMenuHideTimer = null;
let topMetricsTickTimer = null;
const TOAST_TRANSITION_MS = 180;

function finishToastHide() {
  if (!els.toast) return;
  els.toast.dataset.state = "hidden";
  els.toast.setAttribute("aria-hidden", "true");
  els.toast.removeAttribute("aria-label");
  els.toast.removeAttribute("title");
}

function hideToast({ immediate = false } = {}) {
  if (!els.toast) return;
  clearTimeout(toastTimer);
  toastTimer = null;
  clearTimeout(toastSwapTimer);
  toastSwapTimer = null;
  if (immediate) {
    finishToastHide();
    return;
  }
  els.toast.dataset.state = "exiting";
  toastSwapTimer = setTimeout(() => {
    toastSwapTimer = null;
    finishToastHide();
  }, TOAST_TRANSITION_MS);
}

function showToast(message, kind = "info", timeoutMs = 2400) {
  if (shouldSuppressToastInReelMode(message, kind)) return;
  if (!els.toast) return;
  const nextMessage = String(message || "").trim();
  if (!nextMessage) {
    hideToast({ immediate: true });
    return;
  }
  clearTimeout(toastTimer);
  toastTimer = null;
  clearTimeout(toastSwapTimer);
  toastSwapTimer = null;
  const commitToast = () => {
    if (!els.toast) return;
    const icon = document.createElement("span");
    icon.className = "toast-icon";
    icon.setAttribute("aria-hidden", "true");
    const label = document.createElement("span");
    label.className = "sr-only";
    label.textContent = nextMessage;
    els.toast.replaceChildren(icon, label);
    els.toast.dataset.kind = kind;
    els.toast.dataset.state = "visible";
    els.toast.setAttribute("aria-hidden", "false");
    els.toast.setAttribute("aria-label", nextMessage);
    els.toast.title = nextMessage;
  };
  if (els.toast.dataset.state === "visible" && String(els.toast.textContent || "").trim() && String(els.toast.textContent || "").trim() !== nextMessage) {
    els.toast.dataset.state = "refreshing";
    toastSwapTimer = setTimeout(() => {
      toastSwapTimer = null;
      commitToast();
      if (timeoutMs > 0) {
        toastTimer = setTimeout(() => {
          hideToast();
        }, timeoutMs);
      }
    }, TOAST_TRANSITION_MS);
    return;
  }
  commitToast();
  if (timeoutMs > 0) {
    toastTimer = setTimeout(() => {
      hideToast();
    }, timeoutMs);
  }
}

function juggernautShellToolLabel(toolKey) {
  const key = String(toolKey || "").trim();
  if (key === "export_psd") return "Export PSD";
  if (key === "export_png") return "Export PNG";
  if (key === "export_jpg") return "Export JPG";
  if (key === "export_webp") return "Export WEBP";
  if (key === "export_tiff") return "Export TIFF";
  return getSingleImageRailLabel(key) || key || "Tool";
}

function juggernautToolButtons() {
  return Array.from(els.actionGrid?.querySelectorAll?.("button[data-tool-id], button[data-tool-key]") || []);
}

function actionElementProvenance(button, fallback = ACTION_PROVENANCE.LOCAL_ONLY) {
  return normalizeActionProvenance(button?.dataset?.provenance || "", fallback);
}

function syncActionProvenanceBadge(button, provenance) {
  if (!button) return "";
  const normalized = normalizeActionProvenance(provenance);
  const costBearing = actionProvenanceHasModelCost(normalized);
  button.dataset.provenance = normalized;
  button.classList.toggle("has-action-provenance", costBearing);
  button.classList.toggle("is-local-utility", normalized === ACTION_PROVENANCE.LOCAL_ONLY);
  button.classList.toggle("is-local-first", normalized === ACTION_PROVENANCE.LOCAL_FIRST);
  button.classList.toggle("is-external-model", normalized === ACTION_PROVENANCE.EXTERNAL_MODEL);

  const existing = typeof button.querySelector === "function" ? button.querySelector(".action-provenance-affordance") : null;
  const markup = renderActionProvenanceBadge(normalized);
  if (!markup) {
    if (existing?.remove) existing.remove();
    return "";
  }
  if (existing && existing.dataset?.provenance === normalized) return normalized;
  if (existing) {
    existing.outerHTML = markup;
    return normalized;
  }
  if (typeof button.insertAdjacentHTML === "function") {
    button.insertAdjacentHTML("beforeend", markup);
  }
  return normalized;
}

function timelineShelfSummaryText(
  nodes = timelineSortedNodes(),
  headNode = currentTimelineHeadNode(),
  { timelineOpen = state.timelineOpen !== false } = {}
) {
  if (!Array.isArray(nodes) || !nodes.length) return "Upload an image to start your session history.";
  const count = nodes.length;
  const countLabel = `${count} state${count === 1 ? "" : "s"}`;
  if (timelineOpen) return `${countLabel} · Select a state to rewind`;
  const summary = headNode ? timelineNodeSummary(headNode) : "Committed session history";
  return `${countLabel} · ${summary}`;
}

function syncTimelineShelfToggle(nodes = timelineSortedNodes(), headNode = currentTimelineHeadNode()) {
  const timelineOpen = state.timelineOpen !== false;
  const actionLabel = timelineOpen ? "Collapse history timeline" : "Expand history timeline";
  const summary = timelineShelfSummaryText(nodes, headNode, { timelineOpen });
  if (els.timelineToggle) {
    els.timelineToggle.title = actionLabel;
    els.timelineToggle.setAttribute("aria-label", `${actionLabel}. ${summary}`);
    els.timelineToggle.setAttribute("aria-expanded", timelineOpen ? "true" : "false");
  }
  if (els.timelineToggleLabel) {
    els.timelineToggleLabel.textContent = "History";
  }
  if (els.timelineToggleSummary) {
    els.timelineToggleSummary.textContent = summary;
  }
  if (els.timelineDock) {
    els.timelineDock.classList.toggle("is-collapsed", !timelineOpen);
  }
  if (els.timelineShell) {
    els.timelineShell.classList.toggle("is-collapsed", !timelineOpen);
  }
  if (els.timelineBody) {
    els.timelineBody.hidden = !timelineOpen;
    els.timelineBody.setAttribute("aria-hidden", timelineOpen ? "false" : "true");
  }
  return timelineOpen;
}

function singleImageRailMagicSelectSelectionForImage(imageId = "") {
  const normalizedImageId = String(imageId || "").trim();
  if (!normalizedImageId) return null;
  const group = communicationRegionGroupForImage(normalizedImageId);
  if (!group || typeof group !== "object") return null;
  const candidates = Array.isArray(group.candidates) ? group.candidates : [];
  if (!candidates.length) return null;
  const chosenCandidateId = String(group.chosenCandidateId || "").trim();
  const activeCandidateIndex = clamp(Math.max(0, Number(group.activeCandidateIndex) || 0), 0, Math.max(0, candidates.length - 1));
  const candidate =
    (chosenCandidateId
      ? candidates.find((entry) => String(entry?.id || "").trim() === chosenCandidateId)
      : null) ||
    candidates[activeCandidateIndex] ||
    candidates.find((entry) => entry?.active) ||
    null;
  const polygon = communicationRegionCandidateImagePoints(candidate);
  if (polygon.length < 3) return null;
  const bounds = candidate?.bounds
    ? {
        x0: Number(candidate.bounds.x) || 0,
        y0: Number(candidate.bounds.y) || 0,
        x1: (Number(candidate.bounds.x) || 0) + Math.max(1, Number(candidate.bounds.w) || 1),
        y1: (Number(candidate.bounds.y) || 0) + Math.max(1, Number(candidate.bounds.h) || 1),
        w: Math.max(1, Number(candidate.bounds.w) || 1),
        h: Math.max(1, Number(candidate.bounds.h) || 1),
      }
    : communicationPointsBounds(polygon);
  if (!bounds) return null;
  return {
    kind: "magic_select_region",
    imageId: normalizedImageId,
    contourPoints: Array.isArray(candidate?.contourPoints)
      ? candidate.contourPoints.map((point) => ({
          x: Number(point?.x) || 0,
          y: Number(point?.y) || 0,
        }))
      : [],
    maskRef:
      candidate?.maskRef && typeof candidate.maskRef === "object"
        ? JSON.parse(JSON.stringify(candidate.maskRef))
        : candidate?.maskRef
          ? String(candidate.maskRef)
          : null,
    source:
      candidate?.source && typeof candidate.source === "object"
        ? JSON.parse(JSON.stringify(candidate.source))
        : candidate?.source
          ? String(candidate.source)
          : "magic_select",
    confidence: Number(candidate?.confidence) || 0,
    polygon,
    bounds,
    regionCandidateId: String(candidate?.id || "").trim() || null,
    chosenRegionCandidate: {
      id: String(candidate?.id || "").trim() || null,
      imageId: normalizedImageId,
      maskRef:
        candidate?.maskRef && typeof candidate.maskRef === "object"
          ? JSON.parse(JSON.stringify(candidate.maskRef))
          : candidate?.maskRef
            ? String(candidate.maskRef)
            : null,
      source:
        candidate?.source && typeof candidate.source === "object"
          ? JSON.parse(JSON.stringify(candidate.source))
          : candidate?.source
            ? String(candidate.source)
            : "magic_select",
      confidence: Number(candidate?.confidence) || 0,
      contourPoints: Array.isArray(candidate?.contourPoints)
        ? candidate.contourPoints.map((point) => ({
            x: Number(point?.x) || 0,
            y: Number(point?.y) || 0,
          }))
        : [],
      bounds: {
        x: Number(bounds.x0) || 0,
        y: Number(bounds.y0) || 0,
        width: Math.max(1, Number(bounds.w) || 1),
        height: Math.max(1, Number(bounds.h) || 1),
      },
    },
  };
}

function singleImageRailLassoSelectionForImage(imageId = "") {
  const normalizedImageId = String(imageId || "").trim();
  if (!normalizedImageId || normalizedImageId !== String(state.activeId || "").trim()) return null;
  const polygon = Array.isArray(state.selection?.points)
    ? state.selection.points
        .map((point) => ({
          x: Number(point?.x) || 0,
          y: Number(point?.y) || 0,
        }))
        .filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y))
    : [];
  if (polygon.length < 3) return null;
  const bounds = communicationPointsBounds(polygon);
  if (!bounds) return null;
  return {
    kind: "lasso_polygon",
    imageId: normalizedImageId,
    polygon,
    bounds,
    regionCandidateId: null,
    chosenRegionCandidate: null,
  };
}

function resolveSingleImageRailSubjectSelection(imageId = "") {
  const normalizedImageId = String(imageId || state.activeId || "").trim();
  if (!normalizedImageId) return null;
  return (
    singleImageRailMagicSelectSelectionForImage(normalizedImageId) ||
    singleImageRailLassoSelectionForImage(normalizedImageId) ||
    null
  );
}

function singleImageRailRegionSelectionActive(imageId = "") {
  const targetImageId = String(imageId || state.activeId || "").trim();
  return Boolean(resolveSingleImageRailSubjectSelection(targetImageId));
}

function singleImageRailBusy() {
  return Boolean(state.designReviewApply?.status === "running" || currentRunningActionKey());
}

function singleImageRailManipulationActive() {
  return Boolean(state.pointer?.active || state.gestureZoom?.active);
}

function singleImageRailCapabilityAvailability() {
  const availability = {};
  const modeUnavailable = intentModeActive();
  for (const [capability, supported] of Object.entries(SINGLE_IMAGE_RAIL_CAPABILITY_SUPPORT)) {
    if (modeUnavailable) {
      availability[capability] = {
        available: false,
        disabledReason: "unavailable_in_current_mode",
      };
      continue;
    }
    availability[capability] = supported
      ? { available: true }
      : {
          available: false,
          disabledReason: "capability_unavailable",
        };
  }
  return availability;
}

function singleImageRailRecentSuccessfulJobs() {
  const recent = Array.isArray(state.juggernautShell.singleImageRail.recentSuccessfulJobs)
    ? state.juggernautShell.singleImageRail.recentSuccessfulJobs
    : [];
  return recent
    .map((entry) =>
      entry && typeof entry === "object"
        ? {
            jobId: String(entry.jobId || "").trim(),
            capability: String(entry.capability || "").trim(),
            ok: entry.ok !== false,
          }
        : null
    )
    .filter((entry) => entry?.ok && (entry.jobId || entry.capability));
}

function rememberSingleImageRailSuccess(result = {}) {
  const next = [];
  const seen = new Set();
  const candidate = {
    jobId: String(result?.jobId || result?.toolId || "").trim(),
    capability: String(result?.capability || "").trim(),
    ok: true,
  };
  for (const entry of [candidate, ...singleImageRailRecentSuccessfulJobs()]) {
    if (!entry?.ok || (!entry.jobId && !entry.capability)) continue;
    const key = `${entry.jobId}:${entry.capability}`;
    if (seen.has(key)) continue;
    seen.add(key);
    next.push(entry);
    if (next.length >= SINGLE_IMAGE_RAIL_RECENT_SUCCESS_LIMIT) break;
  }
  state.juggernautShell.singleImageRail.recentSuccessfulJobs = next;
}

function buildSingleImageRailIntentInput(context = {}) {
  const activeImage = getActiveImage();
  return {
    imageCount: activeImage ? 1 : 0,
    hasActiveImage: Boolean(activeImage),
    mode: "single",
    busy: Boolean(context?.busy),
    selectionPresent: Boolean(context?.hasRegionSelection),
    selection: {
      present: Boolean(context?.hasRegionSelection),
      count: context?.hasRegionSelection ? 1 : 0,
    },
    activeImage: activeImage
      ? {
          id: activeImage.id,
          path: activeImage.path,
          width: activeImage?.img?.naturalWidth || activeImage?.width || null,
          height: activeImage?.img?.naturalHeight || activeImage?.height || null,
          supported: true,
        }
      : null,
    capabilityAvailability: singleImageRailCapabilityAvailability(),
    recentSuccessfulJobs: singleImageRailRecentSuccessfulJobs(),
  };
}

function buildSingleImageRailRuntimeContext() {
  const activeImage = getActiveImage();
  return {
    activeImageId: state.activeId || "",
    selectedImageIds: getSelectedIds().slice(0, 3),
    subjectSelectionAvailable: singleImageRailRegionSelectionActive(state.activeId || ""),
    busy: singleImageRailBusy(),
    mode: state.canvasMode || "single",
    image: activeImage
      ? {
          id: activeImage.id,
          path: activeImage.path,
          width: activeImage?.img?.naturalWidth || activeImage?.width || null,
          height: activeImage?.img?.naturalHeight || activeImage?.height || null,
          supported: true,
        }
      : null,
    capabilityAvailability: singleImageRailCapabilityAvailability(),
    capabilityExecutorAvailable: true,
  };
}

function normalizeSingleImageRailRankerPayload(rawPayload) {
  const rawJobs = Array.isArray(rawPayload)
    ? rawPayload
    : Array.isArray(rawPayload?.rankedJobs)
      ? rawPayload.rankedJobs
      : [];
  const rankedJobs = normalizeSingleImageRailJobs(rawJobs);
  if (!rankedJobs.length) return null;
  const rawAdapter = rawPayload && typeof rawPayload === "object" && !Array.isArray(rawPayload) ? rawPayload.adapter : null;
  const adapter =
    rawAdapter && typeof rawAdapter === "object"
      ? {
          id: String(rawAdapter.id || SINGLE_IMAGE_RAIL_REGISTERED_ADAPTER.id).trim() || SINGLE_IMAGE_RAIL_REGISTERED_ADAPTER.id,
          kind: String(rawAdapter.kind || SINGLE_IMAGE_RAIL_REGISTERED_ADAPTER.kind).trim() || SINGLE_IMAGE_RAIL_REGISTERED_ADAPTER.kind,
          mock: Boolean(rawAdapter.mock),
        }
      : { ...SINGLE_IMAGE_RAIL_REGISTERED_ADAPTER };
  return {
    adapter,
    rankedJobs,
    mock: Boolean(
      rawPayload && typeof rawPayload === "object" && !Array.isArray(rawPayload)
        ? rawPayload.mock ?? adapter.mock
        : adapter.mock
    ),
  };
}

function normalizeSingleImageRailJobs(rawJobs) {
  if (!Array.isArray(rawJobs)) return [];
  return rawJobs
    .map((job) => {
      const item = getSingleImageRailItem(job?.jobId);
      if (!item?.capability) return null;
      return {
        jobId: String(job?.jobId || item.key || "").trim(),
        label: String(job?.label || item.label || "").trim() || item.label,
        capability: String(job?.capability || item.capability || "").trim() || item.capability,
        requiresSelection:
          job?.requiresSelection == null ? Boolean(item.requiresSelection) : Boolean(job.requiresSelection),
        enabled: job?.enabled !== false,
        disabledReason: String(job?.disabledReason || "").trim(),
        confidence: Number(job?.confidence) || 0,
        reasonCodes: Array.isArray(job?.reasonCodes) ? job.reasonCodes.slice(0, 6) : [],
        stickyKey: String(job?.stickyKey || item.stickyKey || item.key || "").trim() || String(item.key || ""),
      };
    })
    .filter(Boolean);
}

function resolveSingleImageRailRankedJobs(context) {
  const ranker = state.juggernautShell.singleImageRail.ranker;
  if (typeof ranker === "function") {
    try {
      const normalized = normalizeSingleImageRailRankerPayload(ranker(context));
      if (normalized?.rankedJobs?.length) {
        return normalized;
      }
    } catch (error) {
      console.error("Single-image rail ranker failed, falling back to mock adapter:", error);
    }
  }
  return {
    adapter: { ...SINGLE_IMAGE_RAIL_MOCK_ADAPTER },
    rankedJobs: getSingleImageRailMockRankedJobs(context),
    mock: true,
  };
}

function buildJuggernautShellContext() {
  const selectedIds = getSelectedIds();
  const activeImage = getActiveImage();
  const subjectSelection = resolveSingleImageRailSubjectSelection(state.activeId || "");
  return {
    version: JUGGERNAUT_SHELL_BRIDGE_VERSION,
    railContract: JUGGERNAUT_SHELL_RAIL_CONTRACT,
    runDir: state.runDir || null,
    activeTabId: state.activeTabId || null,
    canvasMode: state.canvasMode,
    imageCount: Array.isArray(state.images) ? state.images.length : 0,
    activeImageId: state.activeId || null,
    activeImagePath: activeImage?.path || null,
    regionSelectionActive: Boolean(subjectSelection),
    regionSelectionPointCount: Array.isArray(subjectSelection?.polygon) ? subjectSelection.polygon.length : 0,
    singleImageRail: {
      contract: state.juggernautShell.singleImageRail.contract,
      adapter: { ...state.juggernautShell.singleImageRail.adapter },
      mock: Boolean(state.juggernautShell.singleImageRail.mock),
      recentSuccessfulJobs: singleImageRailRecentSuccessfulJobs(),
      visibleJobs: state.juggernautShell.singleImageRail.visibleJobs.map((job) => ({ ...job })),
    },
    runtimeVisibility: runtimeChromeVisibilitySnapshot(),
    selectedImageIds: selectedIds,
    images: (state.images || []).map((item) => ({
      id: item.id,
      path: item.path,
      label: item.label || basename(item.path) || "Untitled",
      width: item.width || item?.img?.naturalWidth || null,
      height: item.height || item?.img?.naturalHeight || null,
      active: String(item.id || "") === String(state.activeId || ""),
      selected: selectedIds.includes(String(item.id || "")),
    })),
    communicationReview: buildCommunicationReviewPayload({ source: "shell_context" }),
  };
}

function screenshotPolishMetadataPanelIsOpen() {
  return Boolean(screenshotPolishMetadataUi.panel && !screenshotPolishMetadataUi.panel.classList.contains("hidden"));
}

function closeScreenshotPolishMetadataPanel({ focusButton = false } = {}) {
  const panel = screenshotPolishMetadataUi.panel;
  if (!panel) return false;
  panel.classList.add("hidden");
  screenshotPolishMetadataUi.button?.classList.remove("is-open");
  screenshotPolishMetadataUi.button?.setAttribute("aria-expanded", "false");
  if (focusButton) {
    requestAnimationFrame(() => screenshotPolishMetadataUi.button?.focus());
  }
  return true;
}

function ensureScreenshotPolishMetadataUi() {
  const existingButton = screenshotPolishMetadataUi.button;
  const existingPanel = screenshotPolishMetadataUi.panel;
  if (existingButton && existingPanel) return screenshotPolishMetadataUi;
  if (typeof document === "undefined") return screenshotPolishMetadataUi;
  const actions = els.sessionTabStrip?.querySelector?.(".session-tab-strip-actions");
  if (!actions) return screenshotPolishMetadataUi;

  const button = document.createElement("button");
  button.type = "button";
  button.className = "session-tab-strip-action session-tab-strip-pill-action session-tab-runtime-action";
  const buttonLabel = document.createElement("span");
  buttonLabel.textContent = "Metadata";
  button.append(buttonLabel);
  button.setAttribute("aria-label", "Screenshot metadata");
  button.title = "Screenshot metadata";
  button.setAttribute("aria-haspopup", "dialog");
  button.setAttribute("aria-expanded", "false");
  syncActionProvenanceBadge(button, ACTION_PROVENANCE.LOCAL_ONLY);

  const panel = document.createElement("div");
  panel.className = "annotate-panel hidden";
  panel.setAttribute("role", "dialog");
  panel.setAttribute("aria-label", "Screenshot metadata");
  panel.style.left = "50%";
  panel.style.top = "74px";
  panel.style.transform = "translateX(-50%)";
  panel.style.zIndex = "14";

  const header = document.createElement("div");
  header.className = "annotate-header";
  const title = document.createElement("div");
  title.className = "annotate-title";
  title.textContent = "Screenshot Metadata";
  const close = document.createElement("button");
  close.type = "button";
  close.className = "ghost";
  close.textContent = "Close";
  close.setAttribute("aria-label", "Close screenshot metadata");
  header.append(title, close);

  const body = document.createElement("div");
  body.className = "annotate-body";
  const meta = document.createElement("div");
  meta.className = "annotate-meta muted";
  const source = document.createElement("div");
  source.className = "annotate-meta muted";

  const platformField = document.createElement("label");
  platformField.className = "annotate-field";
  const platformLabel = document.createElement("div");
  platformLabel.className = "annotate-label";
  platformLabel.textContent = "Platform";
  const platform = document.createElement("select");
  for (const option of SCREENSHOT_POLISH_PLATFORM_OPTIONS) {
    const node = document.createElement("option");
    node.value = option.value;
    node.textContent = option.label;
    platform.append(node);
  }
  platformField.append(platformLabel, platform);

  const screenField = document.createElement("label");
  screenField.className = "annotate-field";
  const screenLabel = document.createElement("div");
  screenLabel.className = "annotate-label";
  screenLabel.textContent = "Screen";
  const screen = document.createElement("input");
  screen.type = "text";
  screen.className = "annotate-input";
  screen.maxLength = SCREENSHOT_POLISH_SCREEN_NAME_MAX_LENGTH;
  screen.placeholder = "Primary Screen";
  screenField.append(screenLabel, screen);

  const actionsRow = document.createElement("div");
  actionsRow.className = "annotate-actions";
  const done = document.createElement("button");
  done.type = "button";
  done.textContent = "Done";
  actionsRow.append(done);

  body.append(meta, source, platformField, screenField, actionsRow);
  panel.append(header, body);
  actions.insertBefore(button, actions.firstChild || null);
  (document.body || actions).append(panel);

  button.addEventListener("click", () => {
    if (button.disabled) return;
    bumpInteraction();
    if (screenshotPolishMetadataPanelIsOpen()) {
      closeScreenshotPolishMetadataPanel({ focusButton: true });
      return;
    }
    openScreenshotPolishMetadataPanel();
  });
  close.addEventListener("click", () => {
    closeScreenshotPolishMetadataPanel({ focusButton: true });
  });
  done.addEventListener("click", () => {
    closeScreenshotPolishMetadataPanel({ focusButton: true });
  });
  platform.addEventListener("change", () => {
    updateActiveScreenshotPolishMetadata({ platformTarget: platform.value || null });
  });
  screen.addEventListener("input", () => {
    const next = normalizeScreenshotPolishScreenName(screen.value);
    if (screen.value !== next) screen.value = next;
    updateActiveScreenshotPolishMetadata({ screenName: next || null });
  });
  screen.addEventListener("keydown", (event) => {
    if (event.key !== "Enter") return;
    event.preventDefault();
    closeScreenshotPolishMetadataPanel({ focusButton: true });
  });
  if (typeof window !== "undefined" && !panel.dataset.bound) {
    panel.dataset.bound = "1";
    window.addEventListener("keydown", (event) => {
      if (event.key !== "Escape" || !screenshotPolishMetadataPanelIsOpen()) return;
      closeScreenshotPolishMetadataPanel({ focusButton: true });
    });
    window.addEventListener(
      "pointerdown",
      (event) => {
        if (!screenshotPolishMetadataPanelIsOpen()) return;
        const target = event?.target;
        if (target && (panel.contains(target) || button.contains(target))) return;
        closeScreenshotPolishMetadataPanel();
      },
      { capture: true }
    );
  }

  screenshotPolishMetadataUi = {
    button,
    panel,
    meta,
    source,
    platform,
    screen,
    done,
  };
  return screenshotPolishMetadataUi;
}

function renderScreenshotPolishMetadataPanel() {
  const ui = ensureScreenshotPolishMetadataUi();
  if (!ui.button) return false;
  const current = resolveScreenshotPolishMetadata(state, state.screenshotPolishMeta, { allowInference: true });
  const hasPersistedMetadata = Boolean(normalizeScreenshotPolishMetadata(state.screenshotPolishMeta));
  const canEdit = Boolean(current) && (hasPersistedMetadata || (Array.isArray(state.images) && state.images.length === 1));
  const summary = current ? screenshotPolishTabSubtitle(current) : "";
  const resolution = current ? screenshotPolishResolutionLabel(current) : "";
  ui.button.disabled = !canEdit;
  ui.button.classList.toggle("is-ready", canEdit);
  ui.button.title = canEdit
    ? [summary || "Screenshot metadata", resolution].filter(Boolean).join("\n")
    : "Open an image before editing screenshot metadata.";
  ui.button.setAttribute("aria-disabled", canEdit ? "false" : "true");
  if (!canEdit) {
    closeScreenshotPolishMetadataPanel();
    return false;
  }
  if (ui.meta) {
    ui.meta.textContent = resolution || "Resolution loads from the source frame.";
  }
  if (ui.source) {
    const sourceLabel =
      readFirstString(current?.sourceFrame?.label) ||
      (current?.sourceFrame?.path ? basename(current.sourceFrame.path) : "") ||
      "Source frame";
    const sourcePath = current?.sourceFrame?.path ? basename(current.sourceFrame.path) : "";
    ui.source.textContent = [sourceLabel, sourcePath].filter(Boolean).join(" · ");
  }
  if (ui.platform) {
    ui.platform.value = current?.platformTarget || SCREENSHOT_POLISH_PLATFORM_OPTIONS[0].value;
  }
  if (ui.screen) {
    const nextScreen = normalizeScreenshotPolishScreenName(current?.screenName || "");
    if (ui.screen.value !== nextScreen) ui.screen.value = nextScreen;
  }
  return true;
}

function openScreenshotPolishMetadataPanel() {
  const current = initializeActiveScreenshotPolishMetadata();
  if (!current) {
    showToast("Open an image before editing screenshot metadata.", "tip", 2200);
    return false;
  }
  const ui = ensureScreenshotPolishMetadataUi();
  if (!ui.panel) return false;
  renderScreenshotPolishMetadataPanel();
  ui.panel.classList.remove("hidden");
  ui.button?.classList.add("is-open");
  ui.button?.setAttribute("aria-expanded", "true");
  requestAnimationFrame(() => ui.screen?.focus());
  return true;
}

function syncScreenshotPolishMetadataUi() {
  renderScreenshotPolishMetadataPanel();
}

function renderJuggernautShellChrome() {
  const activeImage = getActiveImage();
  const selectedIds = getSelectedIds();
  const emptyCanvas = state.images.length === 0;
  syncJuggernautShellIconography();
  if (els.juggernautSelectionStatus) {
    if (emptyCanvas) {
      els.juggernautSelectionStatus.textContent = "Drop an image to begin";
    } else if (activeImage) {
      const dims =
        activeImage.width && activeImage.height ? ` · ${activeImage.width}x${activeImage.height}` : "";
      const multi = selectedIds.length > 1 ? ` · ${selectedIds.length} selected` : "";
      els.juggernautSelectionStatus.textContent = `${basename(activeImage.path) || "Image"}${dims}${multi}`;
    } else {
      els.juggernautSelectionStatus.textContent = `${state.images.length} image${state.images.length === 1 ? "" : "s"} on canvas`;
    }
  }
  syncRuntimeStatusAffordances();
  syncScreenshotPolishMetadataUi();
  syncTimelineDockVisibility();

  const toolHookReady = typeof state.juggernautShell.toolInvoker === "function";
  const customPsdExportReady = typeof state.juggernautShell.psdExportHandler === "function";
  const nativeExportReady = nativeRasterExportReady();
  const psdExportReady = customPsdExportReady || nativeExportReady;
  const exportMenuReady = psdExportReady;
  const exportToggleReady = !emptyCanvas && exportMenuReady;
  renderAgentRunnerActivityChrome();
  if (els.juggernautExportPsd) {
    if (!exportToggleReady && isJuggernautExportMenuOpen()) {
      closeJuggernautExportMenu();
    }
    const exportTitleBase = emptyCanvas
      ? "Upload an image before exporting"
      : exportMenuReady
        ? "Export"
        : "Export is unavailable in this runtime";
    const exportTitle = appendActionProvenanceDescription(exportTitleBase, ACTION_PROVENANCE.LOCAL_ONLY);
    syncActionProvenanceBadge(els.juggernautExportPsd, ACTION_PROVENANCE.LOCAL_ONLY);
    els.juggernautExportPsd.disabled = !exportToggleReady;
    els.juggernautExportPsd.title = exportTitle;
    els.juggernautExportPsd.setAttribute("aria-label", exportTitle);
    els.juggernautExportPsd.setAttribute("aria-disabled", exportToggleReady ? "false" : "true");
    els.juggernautExportPsd.setAttribute("aria-expanded", exportToggleReady && isJuggernautExportMenuOpen() ? "true" : "false");
    els.juggernautExportPsd.classList.toggle("is-open", isJuggernautExportMenuOpen());
    els.juggernautExportPsd.classList.toggle("is-ready", exportToggleReady);
    els.juggernautExportPsd.classList.toggle("is-pending-hook", !emptyCanvas && !exportMenuReady);
  }
  if (els.juggernautExportFormatPsd) {
    const psdTitle = emptyCanvas
      ? "Upload an image before exporting PSD"
      : psdExportReady
        ? exportFormatTitle("psd")
        : exportFormatUnavailableMessage("psd");
    els.juggernautExportFormatPsd.disabled = emptyCanvas || !psdExportReady;
    els.juggernautExportFormatPsd.title = psdTitle;
    els.juggernautExportFormatPsd.setAttribute("aria-label", psdTitle);
    els.juggernautExportFormatPsd.classList.toggle("is-pending-hook", !emptyCanvas && !psdExportReady);
  }
  if (els.juggernautExportFormatPng) {
    const pngTitle = emptyCanvas
      ? "Upload an image before exporting PNG"
      : nativeExportReady
        ? exportFormatTitle("png")
        : exportFormatUnavailableMessage("png");
    els.juggernautExportFormatPng.disabled = emptyCanvas || !nativeExportReady;
    els.juggernautExportFormatPng.title = pngTitle;
    els.juggernautExportFormatPng.setAttribute("aria-label", pngTitle);
    els.juggernautExportFormatPng.classList.toggle("is-pending-hook", !emptyCanvas && !nativeExportReady);
  }
  if (els.juggernautExportFormatJpg) {
    const jpgTitle = emptyCanvas
      ? "Upload an image before exporting JPG"
      : nativeExportReady
        ? exportFormatTitle("jpg")
        : exportFormatUnavailableMessage("jpg");
    els.juggernautExportFormatJpg.disabled = emptyCanvas || !nativeExportReady;
    els.juggernautExportFormatJpg.title = jpgTitle;
    els.juggernautExportFormatJpg.setAttribute("aria-label", jpgTitle);
    els.juggernautExportFormatJpg.classList.toggle("is-pending-hook", !emptyCanvas && !nativeExportReady);
  }
  if (els.juggernautExportFormatWebp) {
    const webpTitle = emptyCanvas
      ? "Upload an image before exporting WEBP"
      : nativeExportReady
        ? exportFormatTitle("webp")
        : exportFormatUnavailableMessage("webp");
    els.juggernautExportFormatWebp.disabled = emptyCanvas || !nativeExportReady;
    els.juggernautExportFormatWebp.title = webpTitle;
    els.juggernautExportFormatWebp.setAttribute("aria-label", webpTitle);
    els.juggernautExportFormatWebp.classList.toggle("is-pending-hook", !emptyCanvas && !nativeExportReady);
  }
  if (els.juggernautExportFormatTiff) {
    const tiffTitle = emptyCanvas
      ? "Upload an image before exporting TIFF"
      : nativeExportReady
        ? exportFormatTitle("tiff")
        : exportFormatUnavailableMessage("tiff");
    els.juggernautExportFormatTiff.disabled = emptyCanvas || !nativeExportReady;
    els.juggernautExportFormatTiff.title = tiffTitle;
    els.juggernautExportFormatTiff.setAttribute("aria-label", tiffTitle);
    els.juggernautExportFormatTiff.classList.toggle("is-pending-hook", !emptyCanvas && !nativeExportReady);
  }
  if (els.sessionTabDesignReview) {
    const reviewTitle = appendActionProvenanceDescription("Design Review", ACTION_PROVENANCE.EXTERNAL_MODEL);
    syncActionProvenanceBadge(els.sessionTabDesignReview, ACTION_PROVENANCE.EXTERNAL_MODEL);
    els.sessionTabDesignReview.title = reviewTitle;
    els.sessionTabDesignReview.setAttribute("aria-label", reviewTitle);
  }

  for (const btn of juggernautToolButtons()) {
    const key = String(btn.dataset?.toolId || btn.dataset?.toolKey || "").trim();
    const disabledReason = String(btn.dataset?.disabledReason || "").trim();
    const provenance = actionElementProvenance(
      btn,
      resolveActionProvenance({
        capability: btn.dataset?.capability || "",
      })
    );
    const isLocalOnly = provenance === ACTION_PROVENANCE.LOCAL_ONLY;
    const isPending = provenance === ACTION_PROVENANCE.EXTERNAL_MODEL && disabledReason === "capability_unavailable" && !toolHookReady;
    btn.classList.toggle("is-local-utility", isLocalOnly);
    btn.classList.toggle("is-local-first", provenance === ACTION_PROVENANCE.LOCAL_FIRST);
    btn.classList.toggle("is-ai-tool", provenance === ACTION_PROVENANCE.EXTERNAL_MODEL);
    btn.classList.toggle("is-active-request", String(state.juggernautShell.lastToolKey || "") === key);
    btn.classList.toggle("is-pending-hook", isPending);
    btn.classList.toggle(
      "is-selection-empty",
      disabledReason === "selection_required" || (key === "select" && disabledReason === "unavailable_in_current_mode")
    );
  }
}

async function invokeJuggernautShellTool(toolKey, { source = "shell" } = {}) {
  void source;
  return applyJuggernautTool(toolKey);
}

async function requestJuggernautPsdExport({ source = "shell" } = {}) {
  return exportJuggernautPsd({ source });
}

async function requestJuggernautExport({ format = "psd", source = "shell" } = {}) {
  return exportJuggernautFormat({ format, source });
}

function isJuggernautExportMenuOpen() {
  return Boolean(
    els.juggernautExportMenu &&
      !els.juggernautExportMenu.classList.contains("hidden") &&
      els.juggernautExportMenu.classList.contains("is-open")
  );
}

function closeJuggernautExportMenu({ focusToggle = false } = {}) {
  if (!els.juggernautExportMenu) return false;
  els.juggernautExportMenu.classList.remove("is-open");
  els.juggernautExportPsd?.setAttribute("aria-expanded", "false");
  els.juggernautExportPsd?.classList.remove("is-open");
  clearTimeout(juggernautExportMenuHideTimer);
  juggernautExportMenuHideTimer = setTimeout(() => {
    if (els.juggernautExportMenu?.classList.contains("is-open")) return;
    els.juggernautExportMenu?.classList.add("hidden");
  }, 180);
  if (focusToggle) {
    requestAnimationFrame(() => els.juggernautExportPsd?.focus());
  }
  return true;
}

function openJuggernautExportMenu({ focusFirst = false } = {}) {
  if (!els.juggernautExportPsd || !els.juggernautExportMenu) return false;
  const emptyCanvas = state.images.length === 0;
  const exportHookReady = typeof state.juggernautShell.psdExportHandler === "function" || nativeRasterExportReady();
  if (emptyCanvas) {
    showToast("Upload an image before exporting.", "tip", 2600);
    return false;
  }
  if (!exportHookReady) {
    showToast("Export is unavailable in this runtime.", "tip", 2600);
    return false;
  }
  clearTimeout(juggernautExportMenuHideTimer);
  els.juggernautExportMenu.classList.remove("hidden");
  requestAnimationFrame(() => {
    if (els.juggernautExportMenu?.classList.contains("hidden")) return;
    els.juggernautExportMenu.classList.add("is-open");
    els.juggernautExportPsd?.setAttribute("aria-expanded", "true");
    els.juggernautExportPsd?.classList.add("is-open");
    if (focusFirst) {
      const target = els.juggernautExportMenu.querySelector('button[data-export-format]:not(:disabled)');
      target?.focus();
    }
  });
  return true;
}

function toggleJuggernautExportMenu(options = {}) {
  if (isJuggernautExportMenuOpen()) {
    return closeJuggernautExportMenu(options);
  }
  return openJuggernautExportMenu(options);
}

function juggernautExportActionLabel(format = "psd") {
  return `Export ${exportFormatLabel(format)}`;
}

function juggernautExportRetryHint(format = "psd") {
  void format;
  return "Try again after the canvas finishes loading.";
}

function publishTabbedSessionsSnapshot(snapshot = null) {
  if (typeof window === "undefined" || typeof window.dispatchEvent !== "function") return null;
  const payload =
    snapshot && typeof snapshot === "object" && Array.isArray(snapshot.tabs)
      ? {
          tabsOrder: Array.isArray(snapshot.tabsOrder) ? snapshot.tabsOrder.slice() : state.tabsOrder.slice(),
          activeTabId: snapshot.activeTabId || state.activeTabId || null,
          tabs: snapshot.tabs.slice(),
        }
      : getTabsSnapshot();
  window.dispatchEvent(
    new CustomEvent(TABBED_SESSIONS_CHANGED_EVENT, {
      detail: payload,
    })
  );
  return payload;
}

function installTabbedSessionsBridge(shellBridge = null) {
  if (typeof window === "undefined") return null;
  const bridge = {
    listTabs,
    createNewRunTab() {
      return createRun();
    },
    openRunTab() {
      return openExistingRun();
    },
    activateTab,
    closeTab,
    subscribeTabs,
    getActiveTabId() {
      return state.activeTabId || null;
    },
  };
  window[TABBED_SESSIONS_BRIDGE_KEY] = bridge;
  if (shellBridge && typeof shellBridge === "object") {
    shellBridge.tabsBridgeKey = TABBED_SESSIONS_BRIDGE_KEY;
    shellBridge.listTabs = listTabs;
    shellBridge.createNewRunTab = bridge.createNewRunTab;
    shellBridge.openRunTab = bridge.openRunTab;
    shellBridge.activateTab = activateTab;
    shellBridge.closeTab = closeTab;
    shellBridge.subscribeTabs = subscribeTabs;
  }
  publishTabbedSessionsSnapshot();
  return bridge;
}

function installJuggernautShellBridge() {
  if (typeof window === "undefined") return;
  window.__JUGGERNAUT_SHELL__ = {
    version: JUGGERNAUT_SHELL_BRIDGE_VERSION,
    railContract: JUGGERNAUT_SHELL_RAIL_CONTRACT,
    rail: JUGGERNAUT_SHELL_RAIL.map((item) => ({ ...item })),
    singleImageRail: {
      contract: state.juggernautShell.singleImageRail.contract,
      adapter: { ...state.juggernautShell.singleImageRail.adapter },
      mock: Boolean(state.juggernautShell.singleImageRail.mock),
      recentSuccessfulJobs: singleImageRailRecentSuccessfulJobs(),
    },
    runtimeVisibility: runtimeChromeVisibilitySnapshot(),
    applyJuggernautTool,
    exportJuggernautPsd,
    registerToolInvoker(fn) {
      state.juggernautShell.toolInvoker = typeof fn === "function" ? fn : null;
      renderQuickActions();
      return () => {
        if (state.juggernautShell.toolInvoker === fn) {
          state.juggernautShell.toolInvoker = null;
          renderQuickActions();
        }
      };
    },
    registerSingleImageRailRanker(fn) {
      state.juggernautShell.singleImageRail.ranker = typeof fn === "function" ? fn : null;
      renderQuickActions();
      return () => {
        if (state.juggernautShell.singleImageRail.ranker === fn) {
          state.juggernautShell.singleImageRail.ranker = null;
          renderQuickActions();
        }
      };
    },
    registerPsdExportHandler(fn) {
      state.juggernautShell.psdExportHandler = typeof fn === "function" ? fn : null;
      renderJuggernautShellChrome();
      return () => {
        if (state.juggernautShell.psdExportHandler === fn) {
          state.juggernautShell.psdExportHandler = null;
          renderJuggernautShellChrome();
        }
      };
    },
    requestToolInvocation(toolKey, meta = {}) {
      return invokeJuggernautShellTool(toolKey, meta);
    },
    requestExport(meta = {}) {
      return requestJuggernautExport(meta);
    },
    requestPsdExport(meta = {}) {
      return requestJuggernautPsdExport(meta);
    },
    getRuntimeVisibility() {
      return runtimeChromeVisibilitySnapshot();
    },
    setRuntimeVisibility(next = {}) {
      return setRuntimeChromeVisibility(next, { source: "bridge" });
    },
    importImages() {
      return importPhotos();
    },
    listTabs,
    createNewRunTab() {
      return createRun();
    },
    openRunTab() {
      return openExistingRun();
    },
    activateTab,
    closeTab,
    subscribeTabs,
    getCanvasSnapshot() {
      return buildJuggernautShellContext();
    },
    getCommunicationReviewPayload(meta = {}) {
      return buildCommunicationReviewPayload(meta);
    },
    agentRunnerBridgeKey: AGENT_RUNNER_BRIDGE_KEY,
    openAgentRunner() {
      return showAgentRunnerPanel({ focusGoal: !agentRunnerActive(), expand: false });
    },
    closeAgentRunner() {
      return hideAgentRunnerPanel();
    },
    getAgentRunnerState() {
      return buildAgentRunnerBridgeSnapshot();
    },
    requestDesignReview(meta = {}) {
      return requestCommunicationDesignReview(meta);
    },
    showCommunicationProposalTray(next = {}) {
      return setCommunicationProposalTray(next, { source: "bridge" });
    },
    setCommunicationProposalTrayUi(next = {}) {
      return setCommunicationProposalTrayUi(next, { source: "bridge" });
    },
    hydrateCommunicationProposalTrayMedia() {
      return hydrateCommunicationProposalTrayMedia();
    },
    hideCommunicationProposalTray(meta = {}) {
      return hideCommunicationProposalTray({ ...meta, source: "bridge" });
    },
    setCommunicationTool(tool = null) {
      return setCommunicationTool(tool, { source: "bridge" });
    },
    communicationReview: {
      state: buildCommunicationBridgeSnapshot(),
      getState() {
        return buildCommunicationBridgeSnapshot();
      },
      getPayload(meta = {}) {
        return buildCommunicationReviewPayload(meta);
      },
      request(meta = {}) {
        return requestCommunicationDesignReview(meta);
      },
      showTray(next = {}) {
        return setCommunicationProposalTray(next, { source: "bridge_nested" });
      },
      setTrayUi(next = {}) {
        return setCommunicationProposalTrayUi(next, { source: "bridge_nested" });
      },
      hydrateTrayMedia() {
        return hydrateCommunicationProposalTrayMedia();
      },
      hideTray(meta = {}) {
        return hideCommunicationProposalTray({ ...meta, source: "bridge_nested" });
      },
      setTool(tool = null) {
        return setCommunicationTool(tool, { source: "bridge_nested" });
      },
    },
  };
  installTabbedSessionsBridge(window.__JUGGERNAUT_SHELL__);
  window.__JUGGERNAUT_RUNTIME_FLAGS__ = {
    getRuntimeVisibility() {
      return runtimeChromeVisibilitySnapshot();
    },
    setRuntimeVisibility(next = {}) {
      return setRuntimeChromeVisibility(next, { source: "bridge" });
    },
  };
  dispatchJuggernautShellEvent("juggernaut:shell-ready", {
    version: JUGGERNAUT_SHELL_BRIDGE_VERSION,
    railContract: JUGGERNAUT_SHELL_RAIL_CONTRACT,
    rail: JUGGERNAUT_SHELL_RAIL.map((item) => ({ ...item })),
    context: buildJuggernautShellContext(),
  });
}

let wheelForcePanHeld = false;
const REEL_PRESET_MARGIN_PX = 24;
let reelPresetWindowResizeAttached = false;

function getReelScaleForViewport() {
  const appWidth = Math.max(1, window.innerWidth - REEL_PRESET_MARGIN_PX);
  const appHeight = Math.max(1, window.innerHeight - REEL_PRESET_MARGIN_PX);
  const widthScale = appWidth / REEL_PRESET.width;
  const heightScale = appHeight / REEL_PRESET.height;
  const rawScale = Math.min(widthScale, heightScale, 1);
  return clamp(rawScale, 0.08, 1);
}

function isReelSizeLocked() {
  return document.documentElement.dataset.reelSizePreset === "active";
}

function shouldSuppressToastInReelMode(message, kind = "info") {
  if (!isReelSizeLocked()) return false;
  if (String(kind || "").toLowerCase() === "error") return false;
  const text = String(message || "").trim();
  if (!text) return false;
  return /[^/\s]+\.(png|jpe?g|webp|heic|gif|bmp|tiff?|mp4|mov|webm)/i.test(text);
}

function suppressReelDnaToasts() {
  return isReelSizeLocked();
}

function desktopEventVersionId(event) {
  const versionId = String(event?.version_id || "").trim();
  return versionId || null;
}

function bumpInteraction({ semantic = true, proposalLiveRefresh = false } = {}) {
  void semantic;
  void proposalLiveRefresh;
  state.lastInteractionAt = Date.now();
}

const USER_EVENT_MAX = 72;
const USER_TELEMETRY_EVENT_MAX = 240;
function recordUserEvent(type, fields = {}, { includeInScoringRing = true } = {}) {
  const t = String(type || "").trim();
  if (!t) return;
  const entry = {
    seq: (state.userEventSeq += 1),
    at_ms: Date.now(),
    type: t,
    ...fields,
  };
  if (!Array.isArray(state.userTelemetryEvents)) state.userTelemetryEvents = [];
  state.userTelemetryEvents.push(entry);
  if (state.userTelemetryEvents.length > USER_TELEMETRY_EVENT_MAX) {
    state.userTelemetryEvents = state.userTelemetryEvents.slice(state.userTelemetryEvents.length - USER_TELEMETRY_EVENT_MAX);
  }
  if (includeInScoringRing) {
    state.userEvents.push(entry);
    if (state.userEvents.length > USER_EVENT_MAX) {
      state.userEvents = state.userEvents.slice(state.userEvents.length - USER_EVENT_MAX);
    }
  }
}

function escapeHtml(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function basename(path) {
  if (!path) return "";
  const parts = String(path).split(/[\\/]/);
  return parts[parts.length - 1] || "";
}

function extname(path) {
  const name = basename(path);
  const dot = name.lastIndexOf(".");
  if (dot === -1) return "";
  return name.slice(dot).toLowerCase();
}

function mimeFromPath(path) {
  const ext = extname(path);
  if (ext === ".png") return "image/png";
  if (ext === ".jpg" || ext === ".jpeg") return "image/jpeg";
  if (ext === ".webp") return "image/webp";
  if (ext === ".heic") return "image/heic";
  if (ext === ".mp4") return "video/mp4";
  if (ext === ".mov") return "video/quicktime";
  if (ext === ".webm") return "video/webm";
  return "application/octet-stream";
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function getDpr() {
  return Math.max(1, Math.min(window.devicePixelRatio || 1, 3));
}

function getMultiViewTransform() {
  return {
    scale: Math.max(0.0001, Number(state.multiView?.scale) || 1),
    offsetX: Number(state.multiView?.offsetX) || 0,
    offsetY: Number(state.multiView?.offsetY) || 0,
  };
}

function isFreeformTransformDragKind(kind) {
  return (
    kind === POINTER_KINDS.FREEFORM_MOVE ||
    kind === POINTER_KINDS.FREEFORM_RESIZE ||
    kind === POINTER_KINDS.FREEFORM_ROTATE ||
    kind === POINTER_KINDS.FREEFORM_SKEW
  );
}

function isFreeformTransformPointerDragActive() {
  return Boolean(state.pointer?.active && isFreeformTransformDragKind(state.pointer.kind));
}

function multiRectToScreenRect(rect, transform = getMultiViewTransform()) {
  if (!rect) return null;
  const x = Number(rect.x);
  const y = Number(rect.y);
  const w = Number(rect.w);
  const h = Number(rect.h);
  if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(w) || !Number.isFinite(h)) return null;
  const scale = Math.max(0.0001, Number(transform?.scale) || 1);
  const offsetX = Number(transform?.offsetX) || 0;
  const offsetY = Number(transform?.offsetY) || 0;
  return {
    x: x * scale + offsetX,
    y: y * scale + offsetY,
    w: w * scale,
    h: h * scale,
  };
}

let lastHudHeightCssPx = null;
let hudResizeObserver = null;
function syncHudHeightVar() {
  if (!els.canvasWrap || !els.hud) return;
  if (els.hud.classList.contains("hidden")) {
    const next = "0px";
    if (next !== lastHudHeightCssPx) {
      lastHudHeightCssPx = next;
      els.canvasWrap.style.setProperty("--hud-h", next);
    }
    return;
  }
  // "HUD" height should match the central readout shell, not the action grid.
  const hudShell = els.hud.querySelector(".hud-shell") || els.hud;
  const rect = hudShell.getBoundingClientRect();
  const h = Math.max(0, Math.round(rect.height));
  // Avoid setting 0px during early boot/layout churn; it would hide bumpers.
  if (!h) return;
  const next = `${h}px`;
  if (next !== lastHudHeightCssPx) {
    lastHudHeightCssPx = next;
    els.canvasWrap.style.setProperty("--hud-h", next);
  }
}

let lastBrandStripHeightCssPx = null;
let brandStripResizeObserver = null;
function syncBrandStripHeightVar() {
  const el = els.brandStrip;
  if (!el) return;
  const rect = el.getBoundingClientRect();
  const h = Math.max(0, Math.round(rect.height));
  if (!h) return;
  const next = `${h}px`;
  if (next !== lastBrandStripHeightCssPx) {
    lastBrandStripHeightCssPx = next;
    document.documentElement.style.setProperty("--brand-strip-h", next);
  }
}

function ensureCanvasSize() {
  if (!els.canvasWrap || !els.workCanvas || !els.overlayCanvas) return;
  const rect = els.canvasWrap.getBoundingClientRect();
  const dpr = getDpr();
  const width = Math.max(1, Math.floor(rect.width * dpr));
  const height = Math.max(1, Math.floor(rect.height * dpr));
  if (els.workCanvas.width !== width || els.workCanvas.height !== height) {
    els.workCanvas.width = width;
    els.workCanvas.height = height;
    if (els.effectsCanvas) {
      els.effectsCanvas.width = width;
      els.effectsCanvas.height = height;
    }
    els.overlayCanvas.width = width;
    els.overlayCanvas.height = height;
    if (effectsRuntime) {
      effectsRuntime.resize({ width, height, dpr });
    }
    resetViewToFit();
  } else if (effectsRuntime) {
    effectsRuntime.resize({ width, height, dpr });
  }
}

let dprWatchMql = null;
let dprWatchListener = null;
function installDprWatcher() {
  if (!("matchMedia" in window)) return;

  if (dprWatchMql && dprWatchListener) {
    try {
      if (typeof dprWatchMql.removeEventListener === "function") dprWatchMql.removeEventListener("change", dprWatchListener);
      else if (typeof dprWatchMql.removeListener === "function") dprWatchMql.removeListener(dprWatchListener);
    } catch {
      // ignore
    }
  }

  // Watch DPR changes even when layout size doesn't change (multi-monitor scaling / backing scale changes).
  const dpr = window.devicePixelRatio || 1;
  dprWatchMql = window.matchMedia(`(resolution: ${dpr}dppx)`);
  dprWatchListener = () => {
    ensureCanvasSize();
    requestRender();
    // Re-arm the watcher for the new DPR value.
    installDprWatcher();
  };
  try {
    if (typeof dprWatchMql.addEventListener === "function") dprWatchMql.addEventListener("change", dprWatchListener);
    else if (typeof dprWatchMql.addListener === "function") dprWatchMql.addListener(dprWatchListener);
  } catch {
    // ignore
  }
}

function canvasPointFromEvent(event) {
  const dpr = getDpr();
  // Prefer offsetX/Y to avoid triggering layout (getBoundingClientRect) on hot paths.
  const ox = event?.offsetX;
  const oy = event?.offsetY;
  if (typeof ox === "number" && typeof oy === "number" && Number.isFinite(ox) && Number.isFinite(oy)) {
    return { x: ox * dpr, y: oy * dpr };
  }
  const rect = els.overlayCanvas.getBoundingClientRect();
  const x = (event.clientX - rect.left) * dpr;
  const y = (event.clientY - rect.top) * dpr;
  return { x, y };
}

function canvasCssPointFromEvent(event) {
  const ox = event?.offsetX;
  const oy = event?.offsetY;
  if (typeof ox === "number" && typeof oy === "number" && Number.isFinite(ox) && Number.isFinite(oy)) {
    return { x: ox, y: oy };
  }
  const rect = els.overlayCanvas.getBoundingClientRect();
  const x = event.clientX - rect.left;
  const y = event.clientY - rect.top;
  return { x, y };
}

function clampCanvasCssPoint(ptCss) {
  const x0 = Number(ptCss?.x);
  const y0 = Number(ptCss?.y);
  const wrap = els.canvasWrap;
  const w = Number(wrap?.clientWidth) || 0;
  const h = Number(wrap?.clientHeight) || 0;
  if (!(w > 0 && h > 0)) {
    return {
      x: Number.isFinite(x0) ? x0 : 0,
      y: Number.isFinite(y0) ? y0 : 0,
    };
  }
  const x = Number.isFinite(x0) ? clamp(x0, 0, w) : Math.round(w * 0.5);
  const y = Number.isFinite(y0) ? clamp(y0, 0, h) : Math.round(h * 0.5);
  return { x, y };
}

function rememberPromptGenerateHoverCss(ptCss) {
  if (!ptCss) return;
  state.promptGenerateHoverCss = clampCanvasCssPoint(ptCss);
}

function currentPromptGenerateAnchorCss(preferred = null) {
  const base = preferred || state.promptGenerateHoverCss || _defaultImportPointCss();
  return clampCanvasCssPoint(base);
}

function canvasScreenCssToWorldCss(ptCss) {
  const p = ptCss || {};
  const x0 = Number(p.x) || 0;
  const y0 = Number(p.y) || 0;
  if (state.canvasMode !== "multi") return { x: x0, y: y0 };
  const ms = Number(state.multiView?.scale) || 1;
  const dpr = getDpr();
  const mxCss = (Number(state.multiView?.offsetX) || 0) / Math.max(dpr, 0.0001);
  const myCss = (Number(state.multiView?.offsetY) || 0) / Math.max(dpr, 0.0001);
  return {
    x: (x0 - mxCss) / Math.max(ms, 0.0001),
    y: (y0 - myCss) / Math.max(ms, 0.0001),
  };
}

function canvasWorldCssToScreenCss(ptWorldCss) {
  const p = ptWorldCss || {};
  const x0 = Number(p.x) || 0;
  const y0 = Number(p.y) || 0;
  if (state.canvasMode !== "multi") return { x: x0, y: y0 };
  const ms = Number(state.multiView?.scale) || 1;
  const dpr = getDpr();
  const mxCss = (Number(state.multiView?.offsetX) || 0) / Math.max(dpr, 0.0001);
  const myCss = (Number(state.multiView?.offsetY) || 0) / Math.max(dpr, 0.0001);
  return {
    x: mxCss + x0 * ms,
    y: myCss + y0 * ms,
  };
}

function canvasToImage(pt) {
  const img = getActiveImage();
  if (!img) return { x: 0, y: 0 };
  if (state.canvasMode === "multi") {
    const ms = state.multiView?.scale || 1;
    const mx = state.multiView?.offsetX || 0;
    const my = state.multiView?.offsetY || 0;
    const rect = img?.id ? state.multiRects.get(img.id) : null;
    if (rect) {
      const iw = img?.img?.naturalWidth || img?.width || rect.w || 1;
      const ih = img?.img?.naturalHeight || img?.height || rect.h || 1;
      const lx = (pt.x - mx) / Math.max(ms, 0.0001);
      const ly = (pt.y - my) / Math.max(ms, 0.0001);
      return {
        x: ((lx - rect.x) * iw) / Math.max(1, rect.w),
        y: ((ly - rect.y) * ih) / Math.max(1, rect.h),
      };
    }
  }
  return {
    x: (pt.x - state.view.offsetX) / state.view.scale,
    y: (pt.y - state.view.offsetY) / state.view.scale,
  };
}

function imageToCanvas(pt) {
  if (state.canvasMode === "multi") {
    const img = getActiveImage();
    const ms = state.multiView?.scale || 1;
    const mx = state.multiView?.offsetX || 0;
    const my = state.multiView?.offsetY || 0;
    const rect = img?.id ? state.multiRects.get(img.id) : null;
    if (img && rect) {
      const iw = img?.img?.naturalWidth || img?.width || rect.w || 1;
      const ih = img?.img?.naturalHeight || img?.height || rect.h || 1;
      const lx = rect.x + (pt.x * rect.w) / Math.max(1, iw);
      const ly = rect.y + (pt.y * rect.h) / Math.max(1, ih);
      return {
        x: mx + lx * ms,
        y: my + ly * ms,
      };
    }
  }
  return {
    x: state.view.offsetX + pt.x * state.view.scale,
    y: state.view.offsetY + pt.y * state.view.scale,
  };
}

function circleImageToCanvasGeom(circle) {
  if (!circle) return { cx: 0, cy: 0, r: 0 };
  const cxImg = Number(circle.cx) || 0;
  const cyImg = Number(circle.cy) || 0;
  const rImg = Math.max(0, Number(circle.r) || 0);
  const c = imageToCanvas({ x: cxImg, y: cyImg });
  const edge = imageToCanvas({ x: cxImg + rImg, y: cyImg });
  const rPx = Math.max(0, Math.hypot(edge.x - c.x, edge.y - c.y));
  return { cx: c.x, cy: c.y, r: rPx };
}

function hitTestCircleMarks(ptCanvas, circles) {
  if (!ptCanvas || !Array.isArray(circles) || circles.length === 0) return null;
  const tol = Math.max(8, Math.round(10 * getDpr()));
  for (let i = circles.length - 1; i >= 0; i -= 1) {
    const circle = circles[i];
    if (!circle) continue;
    const geom = circleImageToCanvasGeom(circle);
    if (!geom.r) continue;
    const dist = Math.hypot(ptCanvas.x - geom.cx, ptCanvas.y - geom.cy);
    if (Math.abs(dist - geom.r) <= tol) return circle;
    if (geom.r < tol && dist <= geom.r + tol) return circle;
  }
  return null;
}

function transformPointForRect(point = null, { x = 0, y = 0, w = 1, h = 1, rotateDeg = 0, skewXDeg = 0 } = {}) {
  const px = Number(point?.x);
  const py = Number(point?.y);
  const width = Math.max(1, Number(w) || 1);
  const height = Math.max(1, Number(h) || 1);
  const cx = (Number(x) || 0) + width * 0.5;
  const cy = (Number(y) || 0) + height * 0.5;
  if (!Number.isFinite(px) || !Number.isFinite(py)) return { x: cx, y: cy };
  const rotation = normalizeFreeformRotateDeg(rotateDeg);
  const skew = normalizeFreeformSkewDeg(skewXDeg);
  if (Math.abs(rotation) < 0.001 && Math.abs(skew) < 0.001) {
    return { x: px, y: py };
  }
  const rotationRad = (rotation * Math.PI) / 180;
  const cos = Math.cos(rotationRad);
  const sin = Math.sin(rotationRad);
  const dx = px - cx;
  const dy = py - cy;
  const skewTan = Math.tan((skew * Math.PI) / 180);
  const sx = dx + skewTan * dy;
  const sy = dy;
  return {
    x: cx + sx * cos - sy * sin,
    y: cy + sx * sin + sy * cos,
  };
}

function canvasToImageForImageId(pt, imageId) {
  const id = String(imageId || "").trim();
  const item = id ? state.imagesById.get(id) || null : null;
  if (!pt || !item) return null;
  if (state.canvasMode === "multi") {
    const ms = Math.max(0.0001, Number(state.multiView?.scale) || 1);
    const mx = Number(state.multiView?.offsetX) || 0;
    const my = Number(state.multiView?.offsetY) || 0;
    const rect = state.multiRects.get(id) || null;
    if (!rect) return null;
    const rectTransform = readFreeformRectTransform(state.freeformRects.get(id) || null);
    const localPoint = {
      x: ((Number(pt.x) || 0) - mx) / ms,
      y: ((Number(pt.y) || 0) - my) / ms,
    };
    const untransformed = untransformPointForRect(localPoint, {
      x: Number(rect.x) || 0,
      y: Number(rect.y) || 0,
      w: Math.max(1, Number(rect.w) || 1),
      h: Math.max(1, Number(rect.h) || 1),
      rotateDeg: rectTransform.rotateDeg,
      skewXDeg: rectTransform.skewXDeg,
    });
    const iw = item?.img?.naturalWidth || item?.width || rect.w || 1;
    const ih = item?.img?.naturalHeight || item?.height || rect.h || 1;
    return {
      x: ((untransformed.x - rect.x) * iw) / Math.max(1, rect.w),
      y: ((untransformed.y - rect.y) * ih) / Math.max(1, rect.h),
    };
  }
  if (state.activeId !== id) return null;
  const iw = item?.img?.naturalWidth || item?.width || 1;
  const ih = item?.img?.naturalHeight || item?.height || 1;
  const rectTransform = readFreeformRectTransform(state.freeformRects.get(id) || null);
  const localPoint = {
    x: ((Number(pt.x) || 0) - (Number(state.view?.offsetX) || 0)) / Math.max(0.0001, Number(state.view?.scale) || 1),
    y: ((Number(pt.y) || 0) - (Number(state.view?.offsetY) || 0)) / Math.max(0.0001, Number(state.view?.scale) || 1),
  };
  return untransformPointForRect(localPoint, {
    x: 0,
    y: 0,
    w: Math.max(1, iw),
    h: Math.max(1, ih),
    rotateDeg: rectTransform.rotateDeg,
    skewXDeg: rectTransform.skewXDeg,
  });
}

function imageToCanvasForImageId(imageId, pt) {
  const id = String(imageId || "").trim();
  const item = id ? state.imagesById.get(id) || null : null;
  if (!pt || !item) return null;
  if (state.canvasMode === "multi") {
    const rect = state.multiRects.get(id) || null;
    if (!rect) return null;
    const iw = item?.img?.naturalWidth || item?.width || rect.w || 1;
    const ih = item?.img?.naturalHeight || item?.height || rect.h || 1;
    const rectTransform = readFreeformRectTransform(state.freeformRects.get(id) || null);
    const localPoint = transformPointForRect(
      {
        x: rect.x + ((Number(pt.x) || 0) * rect.w) / Math.max(1, iw),
        y: rect.y + ((Number(pt.y) || 0) * rect.h) / Math.max(1, ih),
      },
      {
        x: Number(rect.x) || 0,
        y: Number(rect.y) || 0,
        w: Math.max(1, Number(rect.w) || 1),
        h: Math.max(1, Number(rect.h) || 1),
        rotateDeg: rectTransform.rotateDeg,
        skewXDeg: rectTransform.skewXDeg,
      }
    );
    const ms = Math.max(0.0001, Number(state.multiView?.scale) || 1);
    return {
      x: (Number(state.multiView?.offsetX) || 0) + localPoint.x * ms,
      y: (Number(state.multiView?.offsetY) || 0) + localPoint.y * ms,
    };
  }
  if (state.activeId !== id) return null;
  const iw = item?.img?.naturalWidth || item?.width || 1;
  const ih = item?.img?.naturalHeight || item?.height || 1;
  const rectTransform = readFreeformRectTransform(state.freeformRects.get(id) || null);
  const localPoint = transformPointForRect(
    {
      x: Number(pt.x) || 0,
      y: Number(pt.y) || 0,
    },
    {
      x: 0,
      y: 0,
      w: Math.max(1, iw),
      h: Math.max(1, ih),
      rotateDeg: rectTransform.rotateDeg,
      skewXDeg: rectTransform.skewXDeg,
    }
  );
  const scale = Math.max(0.0001, Number(state.view?.scale) || 1);
  return {
    x: (Number(state.view?.offsetX) || 0) + localPoint.x * scale,
    y: (Number(state.view?.offsetY) || 0) + localPoint.y * scale,
  };
}

function hitTestVisibleCanvasImage(ptCanvas) {
  if (!ptCanvas) return null;
  if (state.canvasMode === "multi") return hitTestMulti(ptCanvas);
  const active = getActiveImage();
  if (!active?.id) return null;
  const local = canvasToImageForImageId(ptCanvas, active.id);
  if (!local) return null;
  const iw = active?.img?.naturalWidth || active?.width || 1;
  const ih = active?.img?.naturalHeight || active?.height || 1;
  if (local.x < 0 || local.y < 0 || local.x > iw || local.y > ih) return null;
  return active.id;
}

function communicationToolId() {
  const raw = String(state.communication?.tool || "").trim();
  return COMMUNICATION_TOOL_IDS.includes(raw) ? raw : null;
}

function communicationBehaviorToolId(tool = null) {
  const key = String(tool || communicationToolId() || "").trim();
  return COMMUNICATION_TOOL_BEHAVIOR[key] || null;
}

function communicationCanvasMarks() {
  return Array.isArray(state.communication?.canvasMarks) ? state.communication.canvasMarks : [];
}

function communicationCanvasStamps() {
  return Array.isArray(state.communication?.canvasStamps) ? state.communication.canvasStamps : [];
}

function communicationStampsForImage(imageId) {
  const id = String(imageId || "").trim();
  const bucket = id ? state.communication?.stampsByImageId?.get(id) : null;
  return Array.isArray(bucket) ? bucket : [];
}

function communicationToolArmed() {
  return Boolean(communicationToolId());
}

function communicationMarksForImage(imageId) {
  const id = String(imageId || "").trim();
  const bucket = id ? state.communication?.marksByImageId?.get(id) : null;
  return Array.isArray(bucket) ? bucket : [];
}

function communicationRegionGroupForImage(imageId) {
  const id = String(imageId || "").trim();
  const bucket = id ? state.communication?.regionProposalsByImageId?.get(id) : null;
  return bucket && typeof bucket === "object" ? bucket : null;
}

function communicationPointsBounds(points = []) {
  if (!Array.isArray(points) || points.length === 0) return null;
  let minX = Number.POSITIVE_INFINITY;
  let minY = Number.POSITIVE_INFINITY;
  let maxX = Number.NEGATIVE_INFINITY;
  let maxY = Number.NEGATIVE_INFINITY;
  for (const point of points) {
    const x = Number(point?.x);
    const y = Number(point?.y);
    if (!Number.isFinite(x) || !Number.isFinite(y)) continue;
    if (x < minX) minX = x;
    if (y < minY) minY = y;
    if (x > maxX) maxX = x;
    if (y > maxY) maxY = y;
  }
  if (!Number.isFinite(minX) || !Number.isFinite(minY) || !Number.isFinite(maxX) || !Number.isFinite(maxY)) return null;
  return {
    x0: minX,
    y0: minY,
    x1: maxX,
    y1: maxY,
    w: Math.max(1, maxX - minX),
    h: Math.max(1, maxY - minY),
  };
}

function communicationRegionCandidateImagePoints(candidate = null) {
  if (!candidate || typeof candidate !== "object") return [];
  const rawPoints = Array.isArray(candidate?.contourPoints)
    ? candidate.contourPoints
    : Array.isArray(candidate?.polygon)
      ? candidate.polygon
      : [];
  const contourPoints = rawPoints
    .map((point) => ({
      x: Number(point?.x),
      y: Number(point?.y),
    }))
    .filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y));
  if (contourPoints.length >= 3) return contourPoints;
  const bounds = candidate?.bounds && typeof candidate.bounds === "object" ? candidate.bounds : null;
  if (!bounds) return [];
  const x = Number(bounds.x) || 0;
  const y = Number(bounds.y) || 0;
  const w = Math.max(1, Number(bounds.w) || Number(bounds.width) || 1);
  const h = Math.max(1, Number(bounds.h) || Number(bounds.height) || 1);
  return [
    { x, y },
    { x: x + w, y },
    { x: x + w, y: y + h },
    { x, y: y + h },
  ];
}

function normalizeCommunicationRegionBounds(bounds = null, points = [], dims = null) {
  const raw = bounds && typeof bounds === "object" ? bounds : null;
  let x = raw ? Number(raw.x ?? raw.left ?? raw.x0) : Number.NaN;
  let y = raw ? Number(raw.y ?? raw.top ?? raw.y0) : Number.NaN;
  let w = raw ? Number(raw.w ?? raw.width) : Number.NaN;
  let h = raw ? Number(raw.h ?? raw.height) : Number.NaN;
  if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(w) || !Number.isFinite(h)) {
    const computed = communicationPointsBounds(points);
    if (computed) {
      x = Number(computed.x0) || 0;
      y = Number(computed.y0) || 0;
      w = Math.max(1, Number(computed.w) || 1);
      h = Math.max(1, Number(computed.h) || 1);
    }
  }
  if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(w) || !Number.isFinite(h)) return null;
  const maxW = Math.max(1, Number(dims?.w) || 1);
  const maxH = Math.max(1, Number(dims?.h) || 1);
  const clampedX = clamp(x, 0, Math.max(0, maxW - 1));
  const clampedY = clamp(y, 0, Math.max(0, maxH - 1));
  const clampedW = clamp(w, 1, Math.max(1, maxW - clampedX));
  const clampedH = clamp(h, 1, Math.max(1, maxH - clampedY));
  return {
    x: clampedX,
    y: clampedY,
    w: clampedW,
    h: clampedH,
  };
}

function normalizeCommunicationRegionContourPoints(points = [], dims = null) {
  const maxW = Math.max(1, Number(dims?.w) || 1);
  const maxH = Math.max(1, Number(dims?.h) || 1);
  const normalized = Array.isArray(points)
    ? points
        .map((point) => ({
          x: clamp(Number(point?.x) || 0, 0, maxW),
          y: clamp(Number(point?.y) || 0, 0, maxH),
        }))
        .filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y))
    : [];
  return normalized.length >= 3 ? normalized : [];
}

function communicationPolygonArea(points = []) {
  if (!Array.isArray(points) || points.length < 3) return 0;
  let signedArea = 0;
  for (let index = 0; index < points.length; index += 1) {
    const current = points[index] || null;
    const next = points[(index + 1) % points.length] || null;
    signedArea += ((Number(current?.x) || 0) * (Number(next?.y) || 0)) - ((Number(next?.x) || 0) * (Number(current?.y) || 0));
  }
  return Math.abs(signedArea) * 0.5;
}

function communicationPolygonCentroid(points = [], fallbackBounds = null) {
  if (!Array.isArray(points) || points.length < 3) {
    return fallbackBounds
      ? {
          x: (Number(fallbackBounds.x) || 0) + Math.max(1, Number(fallbackBounds.w) || 1) * 0.5,
          y: (Number(fallbackBounds.y) || 0) + Math.max(1, Number(fallbackBounds.h) || 1) * 0.5,
        }
      : { x: 0, y: 0 };
  }
  let signedArea = 0;
  let centroidX = 0;
  let centroidY = 0;
  for (let index = 0; index < points.length; index += 1) {
    const current = points[index] || null;
    const next = points[(index + 1) % points.length] || null;
    const currentX = Number(current?.x) || 0;
    const currentY = Number(current?.y) || 0;
    const nextX = Number(next?.x) || 0;
    const nextY = Number(next?.y) || 0;
    const cross = currentX * nextY - nextX * currentY;
    signedArea += cross;
    centroidX += (currentX + nextX) * cross;
    centroidY += (currentY + nextY) * cross;
  }
  if (Math.abs(signedArea) < 0.0001) {
    return fallbackBounds
      ? {
          x: (Number(fallbackBounds.x) || 0) + Math.max(1, Number(fallbackBounds.w) || 1) * 0.5,
          y: (Number(fallbackBounds.y) || 0) + Math.max(1, Number(fallbackBounds.h) || 1) * 0.5,
        }
      : { x: 0, y: 0 };
  }
  return {
    x: centroidX / (3 * signedArea),
    y: centroidY / (3 * signedArea),
  };
}

function communicationMagicSelectCandidateSelectionScore(candidate = null, anchor = null, dims = null, maxArea = 1) {
  const polygon = communicationRegionCandidateImagePoints(candidate);
  const bounds = normalizeCommunicationRegionBounds(candidate?.bounds, polygon, dims);
  if (!bounds) return Number.NEGATIVE_INFINITY;
  const polygonArea = Math.max(1, communicationPolygonArea(polygon));
  const boundsArea = Math.max(1, Math.max(1, Number(bounds.w) || 1) * Math.max(1, Number(bounds.h) || 1));
  const normalizedArea = clamp(polygonArea / Math.max(1, Number(maxArea) || 1), 0, 1);
  const fillRatio = clamp(polygonArea / boundsArea, 0, 1);
  const centroid = communicationPolygonCentroid(polygon, bounds);
  const confidence = clamp(Number(candidate?.confidence) || 0, 0, 1);
  const diagonal = Math.max(1, Math.hypot(Math.max(1, Number(dims?.w) || bounds.w), Math.max(1, Number(dims?.h) || bounds.h)));
  const anchorDistance = anchor ? Math.hypot((Number(anchor.x) || 0) - centroid.x, (Number(anchor.y) || 0) - centroid.y) : 0;
  const anchorScore = anchor ? 1 - clamp(anchorDistance / diagonal, 0, 1) : 0.5;
  return confidence * 0.35 + normalizedArea * 0.45 + fillRatio * 0.1 + anchorScore * 0.1;
}

function rerankCommunicationMagicSelectCandidates(candidates = [], anchor = null, dims = null) {
  if (!Array.isArray(candidates) || candidates.length <= 1) return Array.isArray(candidates) ? candidates.slice() : [];
  const maxArea = candidates.reduce((largest, candidate) => {
    const polygon = communicationRegionCandidateImagePoints(candidate);
    const bounds = normalizeCommunicationRegionBounds(candidate?.bounds, polygon, dims);
    if (!bounds) return largest;
    return Math.max(largest, communicationPolygonArea(polygon), Math.max(1, Number(bounds.w) || 1) * Math.max(1, Number(bounds.h) || 1));
  }, 1);
  return candidates
    .map((candidate, index) => ({
      candidate,
      index,
      score: communicationMagicSelectCandidateSelectionScore(candidate, anchor, dims, maxArea),
    }))
    .sort((left, right) => {
      if (Math.abs(right.score - left.score) > 0.0001) return right.score - left.score;
      return left.index - right.index;
    })
    .map((entry) => entry.candidate);
}

function normalizeCommunicationRegionCandidate(imageId, anchor, dims, candidate = null, index = 0) {
  const raw = candidate && typeof candidate === "object" ? candidate : null;
  if (!raw) return null;
  const contourPoints = normalizeCommunicationRegionContourPoints(
    raw.contourPoints ?? raw.contour_points ?? raw.polygon ?? [],
    dims
  );
  const bounds = normalizeCommunicationRegionBounds(raw.bounds, contourPoints, dims);
  if (!bounds) return null;
  const polygon = contourPoints.length >= 3 ? contourPoints : communicationRegionCandidateImagePoints({ bounds });
  const maskRef =
    raw.maskRef && typeof raw.maskRef === "object"
      ? {
          path: String(raw.maskRef.path || "").trim() || null,
          sha256: String(raw.maskRef.sha256 || "").trim() || null,
          width: Math.max(1, Number(raw.maskRef.width) || 1),
          height: Math.max(1, Number(raw.maskRef.height) || 1),
          format: String(raw.maskRef.format || "png").trim() || "png",
        }
      : raw.maskRef
        ? String(raw.maskRef)
        : raw.mask_ref
          ? String(raw.mask_ref)
          : null;
  const source =
    raw.source && typeof raw.source === "object"
      ? JSON.parse(JSON.stringify(raw.source))
      : String(raw.source || "magic_select");
  return {
    id: String(raw.id || raw.candidateId || raw.candidate_id || `region-${Date.now()}-${index + 1}-${Math.random().toString(16).slice(2, 7)}`),
    label: String(raw.label || `Candidate ${index + 1}`),
    confidence: Number.isFinite(Number(raw.confidence)) ? clamp(Number(raw.confidence), 0, 1) : 0,
    bounds,
    contourPoints,
    maskRef,
    source,
    polygon,
    clickPoint: anchor
      ? {
          x: Number(anchor.x) || 0,
          y: Number(anchor.y) || 0,
        }
      : null,
  };
}

function resolveCommunicationMagicSelectCandidates(imageId, anchor, dims, deterministicResult = null) {
  const rawCandidates = Array.isArray(deterministicResult)
    ? deterministicResult
    : Array.isArray(deterministicResult?.candidates)
      ? deterministicResult.candidates
      : [];
  const normalized = rawCandidates
    .map((candidate, index) => normalizeCommunicationRegionCandidate(imageId, anchor, dims, candidate, index))
    .filter(Boolean);
  if (normalized.length) return rerankCommunicationMagicSelectCandidates(normalized, anchor, dims);
  return Array.from({ length: COMMUNICATION_REGION_CANDIDATE_COUNT }, (_, index) =>
    buildCommunicationFallbackRegionCandidate(imageId, anchor, dims, ["tight", "medium", "loose"][index] || "medium", index)
  );
}

function communicationPolylineLength(points = []) {
  if (!Array.isArray(points) || points.length < 2) return 0;
  let total = 0;
  for (let i = 1; i < points.length; i += 1) {
    const prev = points[i - 1];
    const next = points[i];
    total += Math.hypot((Number(next?.x) || 0) - (Number(prev?.x) || 0), (Number(next?.y) || 0) - (Number(prev?.y) || 0));
  }
  return total;
}

function communicationScreenCssPointToCanvas(ptCss = null) {
  const dpr = Math.max(0.0001, getDpr());
  return {
    x: (Number(ptCss?.x) || 0) * dpr,
    y: (Number(ptCss?.y) || 0) * dpr,
  };
}

function communicationDraftScreenPoints(draft = null) {
  return Array.isArray(draft?.screenPoints)
    ? draft.screenPoints.map((point) => ({
        x: Number(point?.x) || 0,
        y: Number(point?.y) || 0,
      }))
    : [];
}

function communicationDraftPointsToCanvas(draft = null) {
  return communicationDraftScreenPoints(draft).map((point) => communicationScreenCssPointToCanvas(point));
}

function communicationCoalescedScreenPoints(event) {
  if (!event) return [];
  const out = [];
  const pushSample = (sampleEvent) => {
    if (!sampleEvent) return;
    const sample = canvasCssPointFromEvent(sampleEvent);
    const next = {
      x: Number(sample?.x) || 0,
      y: Number(sample?.y) || 0,
    };
    const last = out[out.length - 1] || null;
    if (last && Math.hypot(next.x - last.x, next.y - last.y) < 0.01) return;
    out.push(next);
  };
  if (typeof event.getCoalescedEvents === "function") {
    for (const sampleEvent of event.getCoalescedEvents()) {
      pushSample(sampleEvent);
    }
  }
  pushSample(event);
  return out;
}

function communicationAppendDraftScreenPoints(points = [], samples = []) {
  const next = Array.isArray(points)
    ? points.map((point) => ({
        x: Number(point?.x) || 0,
        y: Number(point?.y) || 0,
      }))
    : [];
  for (const sample of Array.isArray(samples) ? samples : []) {
    const point = {
      x: Number(sample?.x) || 0,
      y: Number(sample?.y) || 0,
    };
    const last = next[next.length - 1] || null;
    if (
      !last ||
      Math.hypot(point.x - last.x, point.y - last.y) >= COMMUNICATION_MARK_MIN_POINT_SPACING_PX
    ) {
      next.push(point);
      if (next.length > COMMUNICATION_MARK_MAX_POINTS) {
        next.splice(0, next.length - COMMUNICATION_MARK_MAX_POINTS);
      }
      continue;
    }
    next[next.length - 1] = point;
  }
  return next;
}

function communicationCommittedPointsFromDraft(draft = null) {
  return communicationDraftScreenPoints(draft)
    .map((point) => ({
      x: Number(point?.x) || 0,
      y: Number(point?.y) || 0,
    }));
}

function communicationMarkPointsToCanvasCss(mark = null) {
  const points = Array.isArray(mark?.points) ? mark.points : [];
  if (!points.length) return [];
  const coordinateSpace = String(mark?.coordinateSpace || "").trim();
  if (coordinateSpace === "canvas_overlay") {
    return points.map((point) => ({
      x: Number(point?.x) || 0,
      y: Number(point?.y) || 0,
    }));
  }
  if (coordinateSpace === "canvas_world" || !String(mark?.imageId || "").trim()) {
    return points
      .map((point) => {
        const css = canvasWorldCssToScreenCss(point);
        return css
          ? {
              x: Number(css.x) || 0,
              y: Number(css.y) || 0,
            }
          : null;
      })
      .filter(Boolean);
  }
  return points
    .map((point) => {
      const canvasPoint = imageToCanvasForImageId(mark.imageId, point);
      const dpr = Math.max(0.0001, getDpr());
      return canvasPoint
        ? {
            x: (Number(canvasPoint.x) || 0) / dpr,
            y: (Number(canvasPoint.y) || 0) / dpr,
          }
        : null;
    })
    .filter(Boolean);
}

function communicationMarkPointsToCanvas(mark = null) {
  return communicationMarkPointsToCanvasCss(mark).map((point) => communicationScreenCssPointToCanvas(point));
}

function communicationCanvasCssScaleForImageId(imageId) {
  const id = String(imageId || "").trim();
  if (!id) return 1;
  const item = state.imagesById.get(id) || null;
  const dpr = Math.max(0.0001, getDpr());
  if (!item) return 1;
  if (state.canvasMode === "multi") {
    const rect = state.multiRects.get(id) || null;
    const ms = Math.max(0.0001, Number(state.multiView?.scale) || 1);
    if (!rect) return ms;
    const iw = Math.max(1, Number(item?.img?.naturalWidth || item?.width || rect.w) || 1);
    const ih = Math.max(1, Number(item?.img?.naturalHeight || item?.height || rect.h) || 1);
    const scaleX = (Math.max(1, Number(rect.w) || 1) * ms) / iw;
    const scaleY = (Math.max(1, Number(rect.h) || 1) * ms) / ih;
    return Math.max(0.05, ((scaleX + scaleY) * 0.5) / dpr);
  }
  return Math.max(0.05, (Math.max(0.0001, Number(state.view?.scale) || 1)) / dpr);
}

function communicationMarkViewportScale(mark = null) {
  const coordinateSpace = String(mark?.coordinateSpace || "").trim();
  const imageId = String(mark?.imageId || "").trim();
  if (coordinateSpace === "canvas_overlay") return 1;
  if (coordinateSpace === "canvas_world" || !imageId) {
    return state.canvasMode === "multi" ? Math.max(0.05, Number(state.multiView?.scale) || 1) : 1;
  }
  return communicationCanvasCssScaleForImageId(imageId);
}

function buildCommunicationStampTargetBounds({
  imageId = null,
  coordinateSpace = "canvas_world",
  targetPoint = null,
} = {}) {
  const point = targetPoint && typeof targetPoint === "object"
    ? {
        x: Number(targetPoint.x) || 0,
        y: Number(targetPoint.y) || 0,
      }
    : null;
  if (!point) return null;
  const id = String(imageId || "").trim();
  if (coordinateSpace === "image" && id) {
    const item = state.imagesById.get(id) || null;
    const imageWidth = Math.max(1, Number(item?.img?.naturalWidth || item?.width) || 1);
    const imageHeight = Math.max(1, Number(item?.img?.naturalHeight || item?.height) || 1);
    const shortEdge = Math.max(24, Math.min(imageWidth, imageHeight));
    const width = clamp(Math.round(shortEdge * 0.18), 36, Math.max(44, Math.round(imageWidth * 0.42)));
    const height = clamp(Math.round(width * 0.66), 28, Math.max(32, Math.round(imageHeight * 0.32)));
    return {
      x: clamp(Math.round(point.x - width * 0.5), 0, Math.max(0, imageWidth - width)),
      y: clamp(Math.round(point.y - height * 0.5), 0, Math.max(0, imageHeight - height)),
      w: width,
      h: height,
    };
  }
  return {
    x: Math.round(point.x - COMMUNICATION_STAMP_TARGET_BOX_CSS_PX.width * 0.5),
    y: Math.round(point.y - COMMUNICATION_STAMP_TARGET_BOX_CSS_PX.height * 0.5),
    w: COMMUNICATION_STAMP_TARGET_BOX_CSS_PX.width,
    h: COMMUNICATION_STAMP_TARGET_BOX_CSS_PX.height,
  };
}

function communicationStampTargetPointToCanvasCss(stamp = null) {
  if (!stamp) return null;
  const coordinateSpace = String(stamp?.coordinateSpace || "").trim();
  const point = stamp?.targetPoint && typeof stamp.targetPoint === "object"
    ? {
        x: Number(stamp.targetPoint.x) || 0,
        y: Number(stamp.targetPoint.y) || 0,
      }
    : null;
  if (!point) return null;
  if (coordinateSpace === "image" && String(stamp?.imageId || "").trim()) {
    const canvasPoint = imageToCanvasForImageId(stamp.imageId, point);
    if (!canvasPoint) return null;
    const dpr = Math.max(0.0001, getDpr());
    return {
      x: (Number(canvasPoint.x) || 0) / dpr,
      y: (Number(canvasPoint.y) || 0) / dpr,
    };
  }
  if (coordinateSpace === "canvas_world") {
    return clampCanvasCssPoint(canvasWorldCssToScreenCss(point));
  }
  return clampCanvasCssPoint(point);
}

function communicationStampChipWidthCss(stamp = null) {
  const label = communicationStampDisplayLabel(stamp);
  return clamp(
    Math.round(label.length * 8.6 + COMMUNICATION_STAMP_CHIP_PADDING_X_CSS_PX * 2 + 18),
    84,
    188
  );
}

function communicationStampLayoutCss(stamp = null) {
  const anchorCss = communicationStampTargetPointToCanvasCss(stamp);
  if (!anchorCss) return null;
  const wrapWidth = Math.max(1, Number(els.canvasWrap?.clientWidth) || 1);
  const wrapHeight = Math.max(1, Number(els.canvasWrap?.clientHeight) || 1);
  const width = communicationStampChipWidthCss(stamp);
  const height = COMMUNICATION_STAMP_CHIP_HEIGHT_CSS_PX;
  let left = Number(anchorCss.x) + COMMUNICATION_STAMP_CHIP_OFFSET_X_CSS_PX;
  if (left + width > wrapWidth - 12) {
    left = Number(anchorCss.x) - width - COMMUNICATION_STAMP_CHIP_OFFSET_X_CSS_PX;
  }
  left = clamp(left, 12, Math.max(12, wrapWidth - width - 12));
  const top = clamp(
    Number(anchorCss.y) - COMMUNICATION_STAMP_CHIP_OFFSET_Y_CSS_PX,
    12,
    Math.max(12, wrapHeight - height - 12)
  );
  const chipRect = {
    left,
    top,
    width,
    height,
    right: left + width,
    bottom: top + height,
  };
  const leaderTo =
    left >= Number(anchorCss.x)
      ? { x: left, y: top + Math.round(height * 0.5) }
      : { x: left + width, y: top + Math.round(height * 0.5) };
  return {
    anchorCss,
    chipRect,
    leaderTo,
  };
}

function findCommunicationStampById(stampId = null) {
  const target = String(stampId || "").trim();
  if (!target) return null;
  for (const stamp of communicationCanvasStamps()) {
    if (String(stamp?.id || "") === target) return stamp;
  }
  for (const [imageId, stamps] of Array.from(state.communication?.stampsByImageId?.entries?.() || [])) {
    const list = Array.isArray(stamps) ? stamps : [];
    const match = list.find((stamp) => String(stamp?.id || "") === target) || null;
    if (match) {
      return {
        ...match,
        imageId: String(match?.imageId || imageId || "") || null,
      };
    }
  }
  return null;
}

function commitCommunicationStampIntent(intentId = "") {
  const normalizedIntentId = normalizeCommunicationStampIntentId(intentId);
  const picker = state.communication?.stampPicker || createFreshCommunicationStampPickerState();
  const point = picker?.targetPoint && typeof picker.targetPoint === "object"
    ? {
        x: Number(picker.targetPoint.x) || 0,
        y: Number(picker.targetPoint.y) || 0,
      }
      : null;
  if (!normalizedIntentId || !point) return null;
  const customText = normalizeCommunicationStampCustomText(picker?.customText);
  const label = normalizedIntentId === "custom" ? customText : communicationStampLabel(normalizedIntentId);
  const instruction = normalizedIntentId === "custom" ? customText : communicationStampInstruction(normalizedIntentId);
  if (!label || !instruction) return null;
  const imageId = String(picker.imageId || "").trim() || null;
  const coordinateSpace = imageId ? "image" : "canvas_world";
  const targetBounds =
    picker?.targetBounds && typeof picker.targetBounds === "object"
      ? {
          x: Number(picker.targetBounds.x) || 0,
          y: Number(picker.targetBounds.y) || 0,
          w: Math.max(1, Number(picker.targetBounds.w) || 1),
          h: Math.max(1, Number(picker.targetBounds.h) || 1),
        }
      : buildCommunicationStampTargetBounds({
          imageId,
          coordinateSpace,
          targetPoint: point,
        });
  const stamp = {
    id: `stamp-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`,
    imageId,
    sourceImageId: imageId || String(picker.sourceImageId || "").trim() || null,
    coordinateSpace,
    intentId: normalizedIntentId,
    label,
    instruction,
    targetPoint: point,
    targetBounds,
    createdAt: Date.now(),
  };
  if (imageId) {
    const existing = communicationStampsForImage(imageId);
    state.communication.stampsByImageId.set(imageId, existing.concat(stamp));
  } else {
    state.communication.canvasStamps = communicationCanvasStamps().concat(stamp);
  }
  state.communication.lastAnchor = communicationAnchorFromStamp(stamp);
  return stamp;
}

function finalizeCommunicationStampCommit(stamp = null, { source = "communication_stamp_commit" } = {}) {
  if (!stamp) return null;
  if (
    state.communication?.proposalTray?.visible &&
    !communicationTrayAnchorPinnedToTitlebar(state.communication?.proposalTray?.anchor)
  ) {
    state.communication.proposalTray.anchor = state.communication.lastAnchor;
  }
  recordTimelineNode({
    imageId: stamp.imageId || null,
    action: "Stamp",
    kind: "annotation",
    visualMode: "icon",
    label: communicationStampDisplayLabel(stamp),
    previewImageId: stamp.imageId || null,
    previewPath: stamp.imageId ? state.imagesById.get(stamp.imageId)?.path || null : null,
  });
  invalidateActiveTabPreview("selection_overlay_change");
  dispatchJuggernautShellEvent(COMMUNICATION_STATE_CHANGED_EVENT, {
    source,
    communication: buildCommunicationBridgeSnapshot(),
    context: buildJuggernautShellContext(),
  });
  renderCommunicationChrome();
  requestRender();
  return stamp;
}

function communicationAnchorFromMark(mark = null) {
  if (!mark) return null;
  const coordinateSpace = String(mark?.coordinateSpace || "").trim();
  const imageId = String(mark?.imageId || "").trim();
  const rawPoints = Array.isArray(mark?.points)
    ? mark.points.map((point) => ({
        x: Number(point?.x) || 0,
        y: Number(point?.y) || 0,
      }))
    : [];
  const canvasPoints = communicationMarkPointsToCanvasCss(mark);
  if (!rawPoints.length && !canvasPoints.length) return null;
  const bounds = communicationPointsBounds(rawPoints);
  const tail = rawPoints[rawPoints.length - 1] || null;
  const canvasTail = canvasPoints[canvasPoints.length - 1] || null;
  if (coordinateSpace === "canvas_overlay") {
    return {
      kind: "mark",
      imageId: null,
      sourceImageId: String(mark?.sourceImageId || mark?.imageId || "") || null,
      markId: String(mark.id || ""),
      canvasOverlayPoint: tail ? { x: Number(tail.x) || 0, y: Number(tail.y) || 0 } : null,
      canvasOverlayBounds: bounds,
    };
  }
  if (coordinateSpace === "canvas_world" || !String(mark?.imageId || "").trim()) {
    return {
      kind: "mark",
      imageId: null,
      markId: String(mark.id || ""),
      canvasWorldPoint: tail ? { x: Number(tail.x) || 0, y: Number(tail.y) || 0 } : null,
      canvasWorldBounds: bounds,
    };
  }
  return {
    kind: "mark",
    imageId,
    markId: String(mark.id || ""),
    imagePoint: tail ? { x: Number(tail.x) || 0, y: Number(tail.y) || 0 } : null,
    imageBounds: bounds,
    canvasPoint: canvasTail ? { x: Number(canvasTail.x) || 0, y: Number(canvasTail.y) || 0 } : null,
  };
}

function communicationAnchorFromStamp(stamp = null) {
  if (!stamp) return null;
  const coordinateSpace = String(stamp?.coordinateSpace || "").trim();
  const imageId = String(stamp?.imageId || "").trim();
  const point = stamp?.targetPoint && typeof stamp.targetPoint === "object"
    ? {
        x: Number(stamp.targetPoint.x) || 0,
        y: Number(stamp.targetPoint.y) || 0,
      }
    : null;
  const bounds = stamp?.targetBounds && typeof stamp.targetBounds === "object"
    ? {
        x0: Number(stamp.targetBounds.x) || 0,
        y0: Number(stamp.targetBounds.y) || 0,
        x1: (Number(stamp.targetBounds.x) || 0) + Math.max(1, Number(stamp.targetBounds.w) || 1),
        y1: (Number(stamp.targetBounds.y) || 0) + Math.max(1, Number(stamp.targetBounds.h) || 1),
        w: Math.max(1, Number(stamp.targetBounds.w) || 1),
        h: Math.max(1, Number(stamp.targetBounds.h) || 1),
      }
    : null;
  const canvasPoint = communicationStampTargetPointToCanvasCss(stamp);
  if (coordinateSpace === "image" && imageId) {
    return {
      kind: "stamp",
      imageId,
      stampId: String(stamp.id || ""),
      imagePoint: point,
      imageBounds: bounds,
      canvasPoint: canvasPoint ? { x: Number(canvasPoint.x) || 0, y: Number(canvasPoint.y) || 0 } : null,
    };
  }
  return {
    kind: "stamp",
    imageId: null,
    stampId: String(stamp.id || ""),
    sourceImageId: String(stamp?.sourceImageId || stamp?.imageId || "") || null,
    canvasWorldPoint: point,
    canvasWorldBounds: bounds,
    canvasPoint: canvasPoint ? { x: Number(canvasPoint.x) || 0, y: Number(canvasPoint.y) || 0 } : null,
  };
}

function communicationAnchorFromRegionGroup(group = null) {
  if (!group || !group.imageId) return null;
  const candidates = Array.isArray(group.candidates) ? group.candidates : [];
  const index = clamp(Math.max(0, Number(group.activeCandidateIndex) || 0), 0, Math.max(0, candidates.length - 1));
  const active = candidates[index] || null;
  if (!active) return null;
  return {
    kind: "region",
    imageId: String(group.imageId || ""),
    regionId: String(active.id || ""),
    imagePoint: group.anchor ? { x: Number(group.anchor.x) || 0, y: Number(group.anchor.y) || 0 } : null,
    imageBounds: active.bounds
      ? {
          x0: Number(active.bounds.x) || 0,
          y0: Number(active.bounds.y) || 0,
          x1: (Number(active.bounds.x) || 0) + Math.max(1, Number(active.bounds.w) || 1),
          y1: (Number(active.bounds.y) || 0) + Math.max(1, Number(active.bounds.h) || 1),
          w: Math.max(1, Number(active.bounds.w) || 1),
          h: Math.max(1, Number(active.bounds.h) || 1),
        }
      : null,
  };
}

function resolveCommunicationReviewAnchor() {
  const last = state.communication?.lastAnchor;
  if (last && (!last.imageId || state.imagesById.has(String(last.imageId || "")))) return last;
  for (const [, group] of Array.from(state.communication?.regionProposalsByImageId?.entries?.() || [])) {
    const anchor = communicationAnchorFromRegionGroup(group);
    if (anchor) return anchor;
  }
  for (const [, stamps] of Array.from(state.communication?.stampsByImageId?.entries?.() || [])) {
    const list = Array.isArray(stamps) ? stamps : [];
    const anchor = communicationAnchorFromStamp(list[list.length - 1] || null);
    if (anchor) return anchor;
  }
  const canvasStamps = communicationCanvasStamps();
  if (canvasStamps.length) {
    return communicationAnchorFromStamp(canvasStamps[canvasStamps.length - 1]);
  }
  for (const [, marks] of Array.from(state.communication?.marksByImageId?.entries?.() || [])) {
    const list = Array.isArray(marks) ? marks : [];
    const anchor = communicationAnchorFromMark(list[list.length - 1] || null);
    if (anchor) return anchor;
  }
  const canvasMarks = communicationCanvasMarks();
  if (canvasMarks.length) {
    return communicationAnchorFromMark(canvasMarks[canvasMarks.length - 1]);
  }
  return null;
}

function designReviewButtonTrayAnchor() {
  const button = els.sessionTabDesignReview;
  const wrap = els.canvasWrap;
  const buttonRect = button?.getBoundingClientRect?.();
  const wrapRect = wrap?.getBoundingClientRect?.();
  if (!buttonRect || !wrapRect) return null;
  return {
    kind: "titlebar_button",
    role: "design_review_button",
    trayPlacement: "below",
    canvasOverlayBounds: {
      x0: (Number(buttonRect.left) || 0) - (Number(wrapRect.left) || 0),
      y0: (Number(buttonRect.top) || 0) - (Number(wrapRect.top) || 0),
      w: Math.max(1, Number(buttonRect.width) || 1),
      h: Math.max(1, Number(buttonRect.height) || 1),
    },
  };
}

function communicationAnchorCanvasCss(anchor = resolveCommunicationReviewAnchor()) {
  if (!anchor) return null;
  if (anchor.kind === "stamp" && anchor.canvasPoint) {
    return clampCanvasCssPoint(anchor.canvasPoint);
  }
  if (anchor.canvasOverlayPoint) {
    return clampCanvasCssPoint(anchor.canvasOverlayPoint);
  }
  if (anchor.canvasOverlayBounds) {
    const bounds = anchor.canvasOverlayBounds;
    return clampCanvasCssPoint({
      x: (Number(bounds.x0) || 0) + Math.max(1, Number(bounds.w) || 1) * 0.5,
      y: (Number(bounds.y0) || 0) + Math.max(1, Number(bounds.h) || 1) * 0.5,
    });
  }
  if (!anchor.imageId) {
    if (anchor.canvasWorldPoint) {
      return clampCanvasCssPoint(canvasWorldCssToScreenCss(anchor.canvasWorldPoint));
    }
    const bounds = anchor.canvasWorldBounds;
    if (bounds) {
      return clampCanvasCssPoint(
        canvasWorldCssToScreenCss({
          x: (Number(bounds.x0) || 0) + Math.max(1, Number(bounds.w) || 1) * 0.5,
          y: (Number(bounds.y0) || 0) + Math.max(1, Number(bounds.h) || 1) * 0.5,
        })
      );
    }
    return null;
  }
  const dpr = Math.max(0.0001, getDpr());
  if (anchor.imagePoint) {
    const point = imageToCanvasForImageId(anchor.imageId, anchor.imagePoint);
    if (point) {
      return {
        x: (Number(point.x) || 0) / dpr,
        y: (Number(point.y) || 0) / dpr,
      };
    }
  }
  const bounds = anchor.imageBounds;
  if (bounds) {
    const center = imageToCanvasForImageId(anchor.imageId, {
      x: (Number(bounds.x0) || 0) + Math.max(1, Number(bounds.w) || 1) * 0.5,
      y: (Number(bounds.y0) || 0) + Math.max(1, Number(bounds.h) || 1) * 0.5,
    });
    if (center) {
      return {
        x: (Number(center.x) || 0) / dpr,
        y: (Number(center.y) || 0) / dpr,
      };
    }
  }
  return null;
}

function communicationTrayAnchorPlacement(anchor = null) {
  return String(anchor?.trayPlacement || "").trim().toLowerCase() === "below" ? "below" : "above";
}

function communicationTrayAnchorPinnedToTitlebar(anchor = null) {
  return String(anchor?.kind || "").trim().toLowerCase() === "titlebar_button";
}

function shouldPinCommunicationReviewTrayToTitlebar(source = "") {
  const normalizedSource = String(source || "").trim().toLowerCase();
  if (!normalizedSource) return true;
  if (normalizedSource.startsWith("titlebar")) return true;
  if (normalizedSource === "agent_runner") return true;
  if (normalizedSource === "bridge") return true;
  if (normalizedSource === "bridge_nested") return true;
  return false;
}

function clearCommunicationProposalTrayAnchorLock(tray = state.communication?.proposalTray || null) {
  if (!tray || typeof tray !== "object") return tray || null;
  tray.anchorLockCss = null;
  tray.anchorLockSignature = "";
  return tray;
}

function communicationProposalTrayAnchorLockSignature(anchor = null, wrap = els.canvasWrap) {
  if (!communicationTrayAnchorPinnedToTitlebar(anchor)) return "";
  const bounds = anchor?.canvasOverlayBounds && typeof anchor.canvasOverlayBounds === "object"
    ? anchor.canvasOverlayBounds
    : null;
  if (!bounds) return "";
  return [
    communicationTrayAnchorPlacement(anchor),
    Math.round(Number(bounds.x0) || 0),
    Math.round(Number(bounds.y0) || 0),
    Math.round(Math.max(1, Number(bounds.w) || 1)),
    Math.round(Math.max(1, Number(bounds.h) || 1)),
    Math.round(Number(wrap?.clientWidth) || 0),
    Math.round(Number(wrap?.clientHeight) || 0),
  ].join(":");
}

function timelineDockCollisionBoundsCss(wrap = els.canvasWrap, dockEl = els.timelineDock) {
  const dockRect = dockEl?.getBoundingClientRect?.();
  const wrapRect = wrap?.getBoundingClientRect?.();
  if (!dockRect || !wrapRect) return null;
  if (!(Number(dockRect.width) > 0) || !(Number(dockRect.height) > 0)) return null;
  return {
    left: (Number(dockRect.left) || 0) - (Number(wrapRect.left) || 0),
    top: (Number(dockRect.top) || 0) - (Number(wrapRect.top) || 0),
    right: (Number(dockRect.right) || 0) - (Number(wrapRect.left) || 0),
    bottom: (Number(dockRect.bottom) || 0) - (Number(wrapRect.top) || 0),
    width: Math.max(1, Number(dockRect.width) || 0),
    height: Math.max(1, Number(dockRect.height) || 0),
  };
}

function positionCommunicationProposalTrayElement(trayEl, anchor = null, anchorCss = null) {
  const wrap = els.canvasWrap;
  let nextAnchor = anchor;
  let nextAnchorCss = anchorCss;
  if (communicationTrayAnchorPinnedToTitlebar(nextAnchor)) {
    nextAnchor = designReviewButtonTrayAnchor() || nextAnchor;
    nextAnchorCss = communicationAnchorCanvasCss(nextAnchor) || nextAnchorCss;
  }
  if (!trayEl || !wrap || !nextAnchorCss) return false;
  const trayState =
    state.communication?.proposalTray && typeof state.communication.proposalTray === "object"
      ? state.communication.proposalTray
      : null;
  const maxX = Math.max(12, (Number(wrap?.clientWidth) || 0) - (trayEl.offsetWidth || 0) - 12);
  const maxY = Math.max(12, (Number(wrap?.clientHeight) || 0) - (trayEl.offsetHeight || 0) - 18);
  const placement = communicationTrayAnchorPlacement(nextAnchor);
  let preferredX = 12;
  let preferredY = 12;
  if (placement === "below") {
    const bounds = nextAnchor?.canvasOverlayBounds && typeof nextAnchor.canvasOverlayBounds === "object"
      ? nextAnchor.canvasOverlayBounds
      : null;
    const anchorRight = bounds
      ? (Number(bounds.x0) || 0) + Math.max(1, Number(bounds.w) || 1)
      : Number(nextAnchorCss.x) || 0;
    const anchorLeft = bounds
      ? Number(bounds.x0) || 0
      : Number(nextAnchorCss.x) || 0;
    const anchorBottom = bounds
      ? (Number(bounds.y0) || 0) + Math.max(1, Number(bounds.h) || 1)
      : Number(nextAnchorCss.y) || 0;
    if (communicationTrayAnchorPinnedToTitlebar(nextAnchor)) {
      const anchorLockSignature = communicationProposalTrayAnchorLockSignature(nextAnchor, wrap);
      const titlebarDockGap =
        typeof DESIGN_REVIEW_TITLEBAR_DOCK_GAP_PX === "number" ? DESIGN_REVIEW_TITLEBAR_DOCK_GAP_PX : 4;
      const titlebarRect = els?.brandStrip?.getBoundingClientRect?.();
      const titlebarBottom = titlebarRect ? Number(titlebarRect.bottom) || 0 : 0;
      const lockedX =
        trayState?.anchorLockCss && trayState.anchorLockSignature === anchorLockSignature
          ? Number(trayState.anchorLockCss.x)
          : NaN;
      preferredX = clamp(Number.isFinite(lockedX) ? lockedX : anchorLeft, 12, maxX);
      preferredY = clamp(
        Math.max(anchorBottom + titlebarDockGap, titlebarBottom > 0 ? titlebarBottom - 1 : anchorBottom + titlebarDockGap),
        12,
        maxY
      );
      if (trayState && anchorLockSignature) {
        trayState.anchorLockSignature = anchorLockSignature;
        trayState.anchorLockCss = {
          x: preferredX,
          y: preferredY,
        };
      }
    } else {
      preferredX = clamp(anchorRight - (trayEl.offsetWidth || 0), 12, maxX);
      preferredY = clamp(anchorBottom + 12, 12, maxY);
      clearCommunicationProposalTrayAnchorLock(trayState);
    }
  } else {
    preferredX = clamp((Number(nextAnchorCss.x) || 0) + 18, 12, maxX);
    preferredY = clamp((Number(nextAnchorCss.y) || 0) - (trayEl.offsetHeight || 0) - 16, 12, maxY);
    clearCommunicationProposalTrayAnchorLock(trayState);
  }
  const timelineBounds =
    typeof timelineDockCollisionBoundsCss === "function"
      ? timelineDockCollisionBoundsCss(wrap)
      : null;
  if (timelineBounds) {
    const trayWidth = Math.max(1, Number(trayEl.offsetWidth) || 1);
    const trayHeight = Math.max(1, Number(trayEl.offsetHeight) || 1);
    const clearance = Math.max(0, Number(DESIGN_REVIEW_TIMELINE_CLEARANCE_PX) || 0);
    const overlapsTimeline =
      preferredX < timelineBounds.right + clearance &&
      preferredX + trayWidth > timelineBounds.left - clearance &&
      preferredY < timelineBounds.bottom + clearance &&
      preferredY + trayHeight > timelineBounds.top - clearance;
    if (overlapsTimeline) {
      preferredY = clamp(timelineBounds.bottom + clearance, 12, maxY);
      if (communicationTrayAnchorPinnedToTitlebar(nextAnchor) && trayState) {
        trayState.anchorLockCss = {
          x: preferredX,
          y: preferredY,
        };
      }
    }
  }
  if (trayEl.dataset) {
    trayEl.dataset.anchorPlacement = placement;
    trayEl.dataset.anchorKind = String(nextAnchor?.kind || "").trim();
  }
  trayEl.style.left = `${preferredX}px`;
  trayEl.style.top = `${preferredY}px`;
  return true;
}

function communicationRectCssPolygon(rectCss = null) {
  const rect = rectCss && typeof rectCss === "object" ? rectCss : null;
  if (!rect) return [];
  const left = Number(rect.left) || 0;
  const top = Number(rect.top) || 0;
  const width = Math.max(1, Number(rect.width) || 1);
  const height = Math.max(1, Number(rect.height) || 1);
  const transform = {
    x: left,
    y: top,
    w: width,
    h: height,
    rotateDeg: Number(rect.rotateDeg) || 0,
    skewXDeg: Number(rect.skewXDeg) || 0,
  };
  return [
    transformPointForRect({ x: left, y: top }, transform),
    transformPointForRect({ x: left + width, y: top }, transform),
    transformPointForRect({ x: left + width, y: top + height }, transform),
    transformPointForRect({ x: left, y: top + height }, transform),
  ];
}

function communicationRegionBoundsCssPolygon(visibleImage = null, bounds = null) {
  const image = visibleImage && typeof visibleImage === "object" ? visibleImage : null;
  const rect = image?.rectCss && typeof image.rectCss === "object" ? image.rectCss : null;
  const region = bounds && typeof bounds === "object" ? bounds : null;
  const width = Math.max(1, Number(image?.width) || 1);
  const height = Math.max(1, Number(image?.height) || 1);
  if (!rect || !region) return [];
  const corners = [
    { x: Number(region.x) || 0, y: Number(region.y) || 0 },
    { x: (Number(region.x) || 0) + Math.max(1, Number(region.w) || 1), y: Number(region.y) || 0 },
    {
      x: (Number(region.x) || 0) + Math.max(1, Number(region.w) || 1),
      y: (Number(region.y) || 0) + Math.max(1, Number(region.h) || 1),
    },
    { x: Number(region.x) || 0, y: (Number(region.y) || 0) + Math.max(1, Number(region.h) || 1) },
  ];
  const transform = {
    x: Number(rect.left) || 0,
    y: Number(rect.top) || 0,
    w: Math.max(1, Number(rect.width) || 1),
    h: Math.max(1, Number(rect.height) || 1),
    rotateDeg: Number(rect.rotateDeg) || 0,
    skewXDeg: Number(rect.skewXDeg) || 0,
  };
  return corners.map((corner) =>
    transformPointForRect(
      {
        x: (Number(rect.left) || 0) + ((Number(corner.x) || 0) * Math.max(1, Number(rect.width) || 1)) / width,
        y: (Number(rect.top) || 0) + ((Number(corner.y) || 0) * Math.max(1, Number(rect.height) || 1)) / height,
      },
      transform
    )
  );
}

function communicationRegionCandidateCssPolygon(visibleImage = null, candidate = null) {
  const image = visibleImage && typeof visibleImage === "object" ? visibleImage : null;
  const rect = image?.rectCss && typeof image.rectCss === "object" ? image.rectCss : null;
  const points = communicationRegionCandidateImagePoints(candidate);
  const width = Math.max(1, Number(image?.width) || 1);
  const height = Math.max(1, Number(image?.height) || 1);
  if (!rect || points.length < 3) return communicationRegionBoundsCssPolygon(visibleImage, candidate?.bounds);
  const transform = {
    x: Number(rect.left) || 0,
    y: Number(rect.top) || 0,
    w: Math.max(1, Number(rect.width) || 1),
    h: Math.max(1, Number(rect.height) || 1),
    rotateDeg: Number(rect.rotateDeg) || 0,
    skewXDeg: Number(rect.skewXDeg) || 0,
  };
  return points.map((point) =>
    transformPointForRect(
      {
        x: (Number(rect.left) || 0) + ((Number(point?.x) || 0) * Math.max(1, Number(rect.width) || 1)) / width,
        y: (Number(rect.top) || 0) + ((Number(point?.y) || 0) * Math.max(1, Number(rect.height) || 1)) / height,
      },
      transform
    )
  );
}

function communicationPointInPolygon(point = null, polygon = []) {
  const px = Number(point?.x);
  const py = Number(point?.y);
  if (!Number.isFinite(px) || !Number.isFinite(py) || !Array.isArray(polygon) || polygon.length < 3) return false;
  let inside = false;
  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i, i += 1) {
    const xi = Number(polygon[i]?.x) || 0;
    const yi = Number(polygon[i]?.y) || 0;
    const xj = Number(polygon[j]?.x) || 0;
    const yj = Number(polygon[j]?.y) || 0;
    const intersects = yi > py !== yj > py && px < ((xj - xi) * (py - yi)) / Math.max(0.000001, yj - yi) + xi;
    if (intersects) inside = !inside;
  }
  return inside;
}

function communicationSegmentCross(a = null, b = null, c = null) {
  return (
    ((Number(b?.x) || 0) - (Number(a?.x) || 0)) * ((Number(c?.y) || 0) - (Number(a?.y) || 0)) -
    ((Number(b?.y) || 0) - (Number(a?.y) || 0)) * ((Number(c?.x) || 0) - (Number(a?.x) || 0))
  );
}

function communicationPointOnSegment(point = null, start = null, end = null) {
  const cross = Math.abs(communicationSegmentCross(start, end, point));
  if (cross > 0.001) return false;
  const px = Number(point?.x) || 0;
  const py = Number(point?.y) || 0;
  const minX = Math.min(Number(start?.x) || 0, Number(end?.x) || 0) - 0.001;
  const maxX = Math.max(Number(start?.x) || 0, Number(end?.x) || 0) + 0.001;
  const minY = Math.min(Number(start?.y) || 0, Number(end?.y) || 0) - 0.001;
  const maxY = Math.max(Number(start?.y) || 0, Number(end?.y) || 0) + 0.001;
  return px >= minX && px <= maxX && py >= minY && py <= maxY;
}

function communicationSegmentsIntersect(a1 = null, a2 = null, b1 = null, b2 = null) {
  const d1 = communicationSegmentCross(a1, a2, b1);
  const d2 = communicationSegmentCross(a1, a2, b2);
  const d3 = communicationSegmentCross(b1, b2, a1);
  const d4 = communicationSegmentCross(b1, b2, a2);
  if ((d1 > 0 && d2 < 0) || (d1 < 0 && d2 > 0)) {
    if ((d3 > 0 && d4 < 0) || (d3 < 0 && d4 > 0)) return true;
  }
  if (Math.abs(d1) <= 0.001 && communicationPointOnSegment(b1, a1, a2)) return true;
  if (Math.abs(d2) <= 0.001 && communicationPointOnSegment(b2, a1, a2)) return true;
  if (Math.abs(d3) <= 0.001 && communicationPointOnSegment(a1, b1, b2)) return true;
  if (Math.abs(d4) <= 0.001 && communicationPointOnSegment(a2, b1, b2)) return true;
  return false;
}

function communicationPolylinePolygonOverlapScore(points = [], polygon = []) {
  if (!Array.isArray(points) || points.length < 2 || !Array.isArray(polygon) || polygon.length < 3) return 0;
  let score = 0;
  for (const point of points) {
    if (communicationPointInPolygon(point, polygon)) score += 2;
  }
  for (let i = 1; i < points.length; i += 1) {
    const start = points[i - 1];
    const end = points[i];
    for (let j = 0; j < polygon.length; j += 1) {
      const edgeStart = polygon[j];
      const edgeEnd = polygon[(j + 1) % polygon.length];
      if (communicationSegmentsIntersect(start, end, edgeStart, edgeEnd)) score += 4;
    }
  }
  return score;
}

function findCommunicationMarkById(markId = null) {
  const target = String(markId || "").trim();
  if (!target) return null;
  for (const mark of communicationCanvasMarks()) {
    if (String(mark?.id || "") === target) return mark;
  }
  for (const [imageId, marks] of Array.from(state.communication?.marksByImageId?.entries?.() || [])) {
    const list = Array.isArray(marks) ? marks : [];
    const match = list.find((mark) => String(mark?.id || "") === target) || null;
    if (match) {
      return {
        ...match,
        imageId: String(match?.imageId || imageId || "") || null,
      };
    }
  }
  return null;
}

function resolveCommunicationMarkOverlapTarget(mark = null) {
  if (!mark) return null;
  const points = communicationMarkPointsToCanvasCss(mark);
  const boundsCss = communicationPointsBounds(points);
  const markId = String(mark?.id || "") || null;
  const sourceImageId = String(mark?.sourceImageId || mark?.imageId || "") || null;
  const visibleImages = buildCommunicationVisibleImagesPayload();
  const regions = buildCommunicationRegionsPayload();
  let bestRegion = null;
  let bestRegionScore = 0;
  for (const region of regions) {
    const imageId = String(region?.imageId || "").trim();
    if (!imageId) continue;
    const visibleImage = visibleImages.find((image) => String(image?.id || "") === imageId) || null;
    if (!visibleImage?.rectCss) continue;
    const candidates = Array.isArray(region?.candidates) ? region.candidates : [];
    for (const candidate of candidates) {
      const polygon = communicationRegionCandidateCssPolygon(visibleImage, candidate);
      const score = communicationPolylinePolygonOverlapScore(points, polygon);
      if (score <= 0) continue;
      if (score > bestRegionScore) {
        bestRegionScore = score;
        bestRegion = {
          kind: "region",
          imageId,
          regionId: String(candidate?.id || "") || null,
          markId,
          sourceImageId,
          boundsCss,
          source: "mark_overlap_region",
        };
      }
    }
  }
  if (bestRegion) return bestRegion;

  let bestImage = null;
  let bestImageScore = 0;
  for (const image of visibleImages) {
    const polygon = communicationRectCssPolygon(image?.rectCss);
    const score = communicationPolylinePolygonOverlapScore(points, polygon);
    if (score <= 0) continue;
    if (
      score > bestImageScore ||
      (score === bestImageScore && !bestImage?.active && Boolean(image?.active)) ||
      (score === bestImageScore && !bestImage?.selected && Boolean(image?.selected))
    ) {
      bestImageScore = score;
      bestImage = {
        kind: "image",
        imageId: String(image?.id || "") || null,
        regionId: null,
        markId,
        sourceImageId,
        boundsCss,
        source: "mark_overlap_image",
      };
    }
  }
  if (bestImage) return bestImage;
  if (sourceImageId && visibleImages.some((image) => String(image?.id || "") === sourceImageId)) {
    return {
      kind: "image",
      imageId: sourceImageId,
      regionId: null,
      markId,
      sourceImageId,
      boundsCss,
      source: "mark_source_image_hint",
    };
  }
  return {
    kind: "canvas",
    imageId: null,
    regionId: null,
    markId,
    sourceImageId,
    boundsCss,
    source: "mark_canvas",
  };
}

function resolveCommunicationStampTarget(stamp = null) {
  if (!stamp) return null;
  const imageId = String(stamp?.imageId || "").trim() || null;
  if (imageId && state.imagesById.has(imageId)) {
    return {
      kind: "image",
      imageId,
      regionId: null,
      markId: null,
      stampId: String(stamp?.id || "") || null,
      sourceImageId: String(stamp?.sourceImageId || imageId || "") || null,
      source: "stamp_image",
    };
  }
  const sourceImageId = String(stamp?.sourceImageId || "").trim() || null;
  if (sourceImageId && state.imagesById.has(sourceImageId)) {
    return {
      kind: "image",
      imageId: sourceImageId,
      regionId: null,
      markId: null,
      stampId: String(stamp?.id || "") || null,
      sourceImageId,
      source: "stamp_source_image",
    };
  }
  return {
    kind: "canvas",
    imageId: null,
    regionId: null,
    markId: null,
    stampId: String(stamp?.id || "") || null,
    sourceImageId,
    source: "stamp_canvas",
  };
}

function resolveCommunicationReviewTarget(anchor = resolveCommunicationReviewAnchor()) {
  if (!anchor) return null;
  if (anchor.kind === "region") {
    return {
      kind: "region",
      imageId: String(anchor.imageId || "") || null,
      regionId: String(anchor.regionId || "") || null,
      markId: null,
      sourceImageId: null,
      source: "region_anchor",
    };
  }
  if (anchor.kind === "mark") {
    const mark = findCommunicationMarkById(anchor.markId);
    if (!mark) {
      return {
        kind: "canvas",
        imageId: null,
        regionId: null,
        markId: String(anchor.markId || "") || null,
        sourceImageId: String(anchor.sourceImageId || "") || null,
        source: "mark_missing",
      };
    }
    return resolveCommunicationMarkOverlapTarget(mark);
  }
  if (anchor.kind === "stamp") {
    const stamp = findCommunicationStampById(anchor.stampId);
    if (!stamp) {
      return {
        kind: "canvas",
        imageId: null,
        regionId: null,
        markId: null,
        stampId: String(anchor.stampId || "") || null,
        sourceImageId: String(anchor.sourceImageId || "") || null,
        source: "stamp_missing",
      };
    }
    return resolveCommunicationStampTarget(stamp);
  }
  return null;
}

function communicationSegmentDistancePx(point = null, start = null, end = null) {
  const px = Number(point?.x) || 0;
  const py = Number(point?.y) || 0;
  const x1 = Number(start?.x) || 0;
  const y1 = Number(start?.y) || 0;
  const x2 = Number(end?.x) || 0;
  const y2 = Number(end?.y) || 0;
  const dx = x2 - x1;
  const dy = y2 - y1;
  if (Math.abs(dx) < 0.0001 && Math.abs(dy) < 0.0001) return Math.hypot(px - x1, py - y1);
  const t = clamp(((px - x1) * dx + (py - y1) * dy) / (dx * dx + dy * dy), 0, 1);
  const cx = x1 + dx * t;
  const cy = y1 + dy * t;
  return Math.hypot(px - cx, py - cy);
}

function hitTestCommunicationMark(ptCanvas) {
  if (!ptCanvas) return null;
  const tolerance = Math.max(10, Math.round(12 * getDpr()));
  for (const [imageId, marks] of Array.from(state.communication?.marksByImageId?.entries?.() || [])) {
    const list = Array.isArray(marks) ? marks : [];
    for (let i = list.length - 1; i >= 0; i -= 1) {
      const mark = list[i];
      const points = communicationMarkPointsToCanvas({ ...mark, imageId });
      if (points.length < 2) continue;
      for (let j = 1; j < points.length; j += 1) {
        const distance = communicationSegmentDistancePx(ptCanvas, points[j - 1], points[j]);
        if (distance <= tolerance) {
          return { imageId: String(imageId || ""), mark };
        }
      }
    }
  }
  const canvasMarks = communicationCanvasMarks();
  for (let i = canvasMarks.length - 1; i >= 0; i -= 1) {
    const mark = canvasMarks[i];
    const points = communicationMarkPointsToCanvas(mark);
    if (points.length < 2) continue;
    for (let j = 1; j < points.length; j += 1) {
      const distance = communicationSegmentDistancePx(ptCanvas, points[j - 1], points[j]);
      if (distance <= tolerance) {
        return { imageId: null, mark };
      }
    }
  }
  return null;
}

function hitTestCommunicationStamp(ptCanvas) {
  if (!ptCanvas) return null;
  const pointCss = {
    x: (Number(ptCanvas.x) || 0) / Math.max(0.0001, getDpr()),
    y: (Number(ptCanvas.y) || 0) / Math.max(0.0001, getDpr()),
  };
  const hitPadding = COMMUNICATION_STAMP_HIT_PADDING_CSS_PX;
  const all = [];
  for (const [imageId, stamps] of Array.from(state.communication?.stampsByImageId?.entries?.() || [])) {
    const list = Array.isArray(stamps) ? stamps : [];
    for (const stamp of list) {
      all.push({ imageId: String(imageId || ""), stamp });
    }
  }
  for (const stamp of communicationCanvasStamps()) {
    all.push({ imageId: null, stamp });
  }
  for (let index = all.length - 1; index >= 0; index -= 1) {
    const entry = all[index];
    const layout = communicationStampLayoutCss(entry.stamp);
    if (!layout) continue;
    const chip = layout.chipRect;
    const anchor = layout.anchorCss;
    const inChip =
      pointCss.x >= chip.left - hitPadding &&
      pointCss.x <= chip.right + hitPadding &&
      pointCss.y >= chip.top - hitPadding &&
      pointCss.y <= chip.bottom + hitPadding;
    const anchorDistance = Math.hypot(pointCss.x - Number(anchor.x || 0), pointCss.y - Number(anchor.y || 0));
    if (inChip || anchorDistance <= hitPadding + 6) {
      return entry;
    }
  }
  return null;
}

function hitTestCommunicationRegionCandidate(ptCanvas) {
  if (!ptCanvas) return null;
  const tolerance = Math.max(12, Math.round(14 * getDpr()));
  for (const [imageId, group] of Array.from(state.communication?.regionProposalsByImageId?.entries?.() || [])) {
    const candidates = Array.isArray(group?.candidates) ? group.candidates : [];
    for (let i = candidates.length - 1; i >= 0; i -= 1) {
      const candidate = candidates[i];
      const polygon = communicationRegionCandidateImagePoints(candidate)
        .map((point) => imageToCanvasForImageId(imageId, point))
        .filter(Boolean);
      if (polygon.length >= 3) {
        if (communicationPointInPolygon(ptCanvas, polygon)) {
          return { imageId: String(imageId || ""), group, candidate };
        }
        for (let j = 0; j < polygon.length; j += 1) {
          const edgeStart = polygon[j];
          const edgeEnd = polygon[(j + 1) % polygon.length];
          if (communicationSegmentDistancePx(ptCanvas, edgeStart, edgeEnd) <= tolerance) {
            return { imageId: String(imageId || ""), group, candidate };
          }
        }
      }
      const bounds = candidate?.bounds;
      if (!bounds) continue;
      const center = imageToCanvasForImageId(imageId, {
        x: (Number(bounds.x) || 0) + Math.max(1, Number(bounds.w) || 1) * 0.5,
        y: (Number(bounds.y) || 0) + Math.max(1, Number(bounds.h) || 1) * 0.5,
      });
      if (!center) continue;
      const dpr = Math.max(0.0001, getDpr());
      const canvasW = (Math.max(1, Number(bounds.w) || 1) / dpr) * Math.max(0.35, Number(getImageRectCss(imageId)?.width || 1) / Math.max(1, Number(state.imagesById.get(imageId)?.width || 1)));
      const canvasH = (Math.max(1, Number(bounds.h) || 1) / dpr) * Math.max(0.35, Number(getImageRectCss(imageId)?.height || 1) / Math.max(1, Number(state.imagesById.get(imageId)?.height || 1)));
      if (Math.abs((Number(ptCanvas.x) || 0) - center.x) <= canvasW + tolerance && Math.abs((Number(ptCanvas.y) || 0) - center.y) <= canvasH + tolerance) {
        return { imageId: String(imageId || ""), group, candidate };
      }
    }
  }
  return null;
}

function trySetOverlayPointerCapture(pointerId) {
  try {
    if (els.overlayCanvas && typeof els.overlayCanvas.setPointerCapture === "function") {
      els.overlayCanvas.setPointerCapture(pointerId);
    }
  } catch {
    // Observable driver calls can use synthetic pointer ids with no browser capture backing them.
  }
}

function beginCommunicationMarkerStroke(event, p, pCss, communicationImageId = null, markKind = "freehand_marker") {
  const imageId = String(communicationImageId || "").trim() || null;
  const kind = String(markKind || "").trim().toLowerCase() === "freehand_protect"
    ? "freehand_protect"
    : "freehand_marker";
  if (typeof event?.preventDefault === "function") event.preventDefault();
  if (typeof event?.stopPropagation === "function") event.stopPropagation();
  bumpInteraction({ semantic: false });
  trySetOverlayPointerCapture(event.pointerId);
  state.pointer.active = true;
  state.pointer.kind = COMMUNICATION_POINTER_KINDS.MARKER;
  state.pointer.imageId = imageId;
  state.pointer.startX = Number(p?.x) || 0;
  state.pointer.startY = Number(p?.y) || 0;
  state.pointer.lastX = Number(p?.x) || 0;
  state.pointer.lastY = Number(p?.y) || 0;
  state.pointer.startCssX = Number(pCss?.x) || 0;
  state.pointer.startCssY = Number(pCss?.y) || 0;
  state.pointer.wheelOnTap = false;
  state.pointer.moved = false;
  state.communication.markDraft = {
    imageId,
    kind,
    coordinateSpace: "canvas_overlay",
    screenPoints: [
      {
        x: Number(pCss?.x) || 0,
        y: Number(pCss?.y) || 0,
      },
    ],
    createdAt: Date.now(),
  };
  requestRender();
}

function beginCommunicationMagicSelectStroke(event, p, pCss, communicationImageId = null) {
  const imageId = String(communicationImageId || "").trim();
  if (!imageId) return false;
  bumpInteraction({ semantic: false });
  trySetOverlayPointerCapture(event.pointerId);
  state.pointer.active = true;
  state.pointer.kind = COMMUNICATION_POINTER_KINDS.MAGIC_SELECT;
  state.pointer.imageId = imageId;
  state.pointer.startX = Number(p?.x) || 0;
  state.pointer.startY = Number(p?.y) || 0;
  state.pointer.lastX = Number(p?.x) || 0;
  state.pointer.lastY = Number(p?.y) || 0;
  state.pointer.startCssX = Number(pCss?.x) || 0;
  state.pointer.startCssY = Number(pCss?.y) || 0;
  state.pointer.wheelOnTap = false;
  state.pointer.moved = false;
  requestRender();
  return true;
}

function beginCommunicationImageEraseStroke(event, p, pCss, communicationImageId = null) {
  const imageId = String(communicationImageId || "").trim();
  if (!imageId) return false;
  bumpInteraction({ semantic: false });
  trySetOverlayPointerCapture(event.pointerId);
  state.pointer.active = true;
  state.pointer.kind = COMMUNICATION_POINTER_KINDS.ERASER;
  state.pointer.imageId = imageId;
  state.pointer.startX = Number(p?.x) || 0;
  state.pointer.startY = Number(p?.y) || 0;
  state.pointer.lastX = Number(p?.x) || 0;
  state.pointer.lastY = Number(p?.y) || 0;
  state.pointer.startCssX = Number(pCss?.x) || 0;
  state.pointer.startCssY = Number(pCss?.y) || 0;
  state.pointer.wheelOnTap = false;
  state.pointer.moved = false;
  state.communication.eraseDraft = {
    imageId,
    brushCssPx: COMMUNICATION_IMAGE_ERASE_BRUSH_CSS_PX,
    screenPoints: [
      {
        x: Number(pCss?.x) || 0,
        y: Number(pCss?.y) || 0,
      },
    ],
    createdAt: Date.now(),
  };
  requestRender();
  return true;
}

function communicationImageEraseBrushRadiusPx(imageId = "", brushCssPx = COMMUNICATION_IMAGE_ERASE_BRUSH_CSS_PX) {
  const id = String(imageId || "").trim();
  if (!id) return Math.max(2, Number(brushCssPx) || COMMUNICATION_IMAGE_ERASE_BRUSH_CSS_PX);
  const item = state.imagesById.get(id) || null;
  const rectCss = getImageRectCss(id);
  const imageWidth = Math.max(1, Number(item?.img?.naturalWidth || item?.width) || 1);
  const imageHeight = Math.max(1, Number(item?.img?.naturalHeight || item?.height) || 1);
  const rectWidth = Math.max(1, Number(rectCss?.width) || imageWidth);
  const rectHeight = Math.max(1, Number(rectCss?.height) || imageHeight);
  const scaleX = imageWidth / rectWidth;
  const scaleY = imageHeight / rectHeight;
  return Math.max(2, Math.round((Number(brushCssPx) || COMMUNICATION_IMAGE_ERASE_BRUSH_CSS_PX) * Math.max(scaleX, scaleY) * 0.5));
}

function communicationImageErasePointsToImage(draft = null) {
  const imageId = String(draft?.imageId || "").trim();
  if (!imageId) return [];
  return communicationDraftPointsToCanvas(draft)
    .map((point) => canvasToImageForImageId(point, imageId))
    .filter((point) => Number.isFinite(Number(point?.x)) && Number.isFinite(Number(point?.y)))
    .map((point) => ({
      x: Number(point.x) || 0,
      y: Number(point.y) || 0,
    }));
}

async function commitCommunicationImageEraseDraft(draft = null) {
  const imageId = String(draft?.imageId || "").trim();
  if (!imageId) return null;
  const item = state.imagesById.get(imageId) || null;
  if (!item?.path) return null;
  await ensureRun();
  const sourceImg = readSessionRuntimeImageHandle(item) || await loadImage(item.path);
  if (!sourceImg) return null;
  const width = Math.max(1, Number(sourceImg.naturalWidth || item.width) || 1);
  const height = Math.max(1, Number(sourceImg.naturalHeight || item.height) || 1);
  const points = communicationImageErasePointsToImage(draft)
    .map((point) => ({
      x: clamp(point.x, 0, width),
      y: clamp(point.y, 0, height),
    }));
  if (!points.length) return null;
  const brushRadiusPx = communicationImageEraseBrushRadiusPx(imageId, draft?.brushCssPx);
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext("2d");
  if (!ctx) return null;
  ctx.drawImage(sourceImg, 0, 0, width, height);
  ctx.save();
  ctx.globalCompositeOperation = "destination-out";
  ctx.lineCap = "round";
  ctx.lineJoin = "round";
  ctx.strokeStyle = "rgba(0, 0, 0, 1)";
  ctx.fillStyle = "rgba(0, 0, 0, 1)";
  ctx.lineWidth = Math.max(2, brushRadiusPx * 2);
  if (points.length === 1) {
    ctx.beginPath();
    ctx.arc(Number(points[0]?.x) || 0, Number(points[0]?.y) || 0, brushRadiusPx, 0, Math.PI * 2);
    ctx.fill();
  } else if (traceCommunicationMarkPath(ctx, points)) {
    ctx.stroke();
  }
  ctx.restore();
  const result = await saveCanvasAsArtifact(canvas, {
    operation: "erase",
    label: "Erase",
    meta: {
      image_id: imageId,
      path_point_count: points.length,
      brush_radius_px: brushRadiusPx,
    },
    replaceActive: true,
    targetId: imageId,
  });
  requestRender();
  return result;
}

function setCommunicationStampPicker(next = {}, { render = true, requestRender: shouldRequestRender = false } = {}) {
  const picker = {
    ...createFreshCommunicationStampPickerState(),
    ...(state.communication?.stampPicker && typeof state.communication.stampPicker === "object" ? state.communication.stampPicker : {}),
    ...(next && typeof next === "object" ? next : {}),
  };
  picker.selectedIntentId = normalizeCommunicationStampIntentId(picker.selectedIntentId || "");
  picker.pickerMode = normalizeCommunicationStampPickerMode(picker.pickerMode);
  picker.customText = normalizeCommunicationStampCustomText(picker.customText);
  state.communication.stampPicker = picker;
  if (render) {
    renderCommunicationChrome();
  }
  if (shouldRequestRender) {
    requestRender();
  }
  return picker;
}

function hideCommunicationStampPicker({
  clearSelection = false,
  render = true,
  requestRender: shouldRequestRender = false,
} = {}) {
  const next = {
    ...(clearSelection ? createFreshCommunicationStampPickerState() : state.communication?.stampPicker || createFreshCommunicationStampPickerState()),
    visible: false,
    imageId: null,
    sourceImageId: null,
    coordinateSpace: null,
    targetPoint: null,
    targetBounds: null,
    anchorCss: null,
    anchorFrame: "shell",
    pickerMode: "intent_list",
    customText: "",
    selectedIntentId:
      clearSelection || selectedCommunicationStampIntentId() === "custom"
        ? ""
        : selectedCommunicationStampIntentId(),
  };
  return setCommunicationStampPicker(next, {
    render,
    requestRender: shouldRequestRender,
  });
}

function selectCommunicationStampIntent(intentId = "", { render = true } = {}) {
  const normalizedIntentId = normalizeCommunicationStampIntentId(intentId);
  if (!normalizedIntentId) return null;
  return setCommunicationStampPicker(
    {
      pickerMode: normalizedIntentId === "custom" ? "custom_input" : "intent_list",
      selectedIntentId: normalizedIntentId,
    },
    { render }
  );
}

function openCommunicationStampPickerAtPoint(ptCanvas, ptCss, imageId = null) {
  const pickerCss = clampCanvasCssPoint(ptCss);
  const normalizedImageId = String(imageId || "").trim() || null;
  const imagePoint = normalizedImageId ? canvasToImageForImageId(ptCanvas, normalizedImageId) : null;
  const coordinateSpace = normalizedImageId && imagePoint ? "image" : "canvas_world";
  const targetPoint =
    coordinateSpace === "image"
      ? {
          x: Number(imagePoint?.x) || 0,
          y: Number(imagePoint?.y) || 0,
        }
      : canvasScreenCssToWorldCss(pickerCss);
  const targetBounds = buildCommunicationStampTargetBounds({
    imageId: normalizedImageId,
    coordinateSpace,
    targetPoint,
  });
  return setCommunicationStampPicker(
    {
      visible: true,
      imageId: normalizedImageId,
      sourceImageId: normalizedImageId,
      coordinateSpace,
      targetPoint,
      targetBounds,
      anchorCss: pickerCss,
      anchorFrame: "canvas",
      pickerMode: "intent_list",
      customText: "",
    },
    { render: true }
  );
}

function focusCommunicationStampCustomInput({ select = false } = {}) {
  if (typeof window === "undefined") return;
  window.requestAnimationFrame(() => {
    const inputEl = els.communicationStampCustomInput;
    if (!inputEl || state.communication?.stampPicker?.visible !== true) return;
    if (typeof inputEl.focus === "function") inputEl.focus();
    if (select && typeof inputEl.select === "function") inputEl.select();
  });
}

function openCommunicationStampCustomInput() {
  const picker = state.communication?.stampPicker || createFreshCommunicationStampPickerState();
  if (!picker?.visible) return null;
  const next = setCommunicationStampPicker(
    {
      pickerMode: "custom_input",
      selectedIntentId: "custom",
    },
    { render: true, requestRender: false }
  );
  focusCommunicationStampCustomInput({ select: true });
  return next;
}

function commitCommunicationCustomStampFromPicker({ source = "communication_stamp_custom_commit" } = {}) {
  const customText = normalizeCommunicationStampCustomText(
    readFirstString(els.communicationStampCustomInput?.value, state.communication?.stampPicker?.customText)
  );
  if (!customText) {
    showToast("Enter stamp text.", "tip", 1400);
    focusCommunicationStampCustomInput({ select: true });
    return null;
  }
  setCommunicationStampPicker(
    {
      selectedIntentId: "custom",
      pickerMode: "custom_input",
      customText,
    },
    { render: false, requestRender: false }
  );
  const stamp = commitCommunicationStampIntent("custom");
  if (!stamp) return null;
  hideCommunicationStampPicker({ render: false, requestRender: false });
  return finalizeCommunicationStampCommit(stamp, { source });
}

function commitPlacedCommunicationStampAtCanvasPoint(
  ptCanvas,
  ptCss,
  imageId = null,
  intentId = "",
  { source = "communication_stamp_commit", customText = "" } = {}
) {
  const normalizedIntentId = normalizeCommunicationStampIntentId(intentId || selectedCommunicationStampIntentId());
  if (!normalizedIntentId) {
    openCommunicationStampPickerAtPoint(ptCanvas, ptCss, imageId);
    return null;
  }
  const normalizedCustomText = normalizeCommunicationStampCustomText(customText);
  if (normalizedIntentId === "custom" && !normalizedCustomText) {
    openCommunicationStampPickerAtPoint(ptCanvas, ptCss, imageId);
    setCommunicationStampPicker(
      {
        pickerMode: "custom_input",
        selectedIntentId: "custom",
      },
      { render: true, requestRender: false }
    );
    return null;
  }
  openCommunicationStampPickerAtPoint(ptCanvas, ptCss, imageId);
  setCommunicationStampPicker(
    {
      selectedIntentId: normalizedIntentId,
      pickerMode: normalizedIntentId === "custom" ? "custom_input" : "intent_list",
      customText: normalizedIntentId === "custom" ? normalizedCustomText : "",
    },
    { render: false, requestRender: false }
  );
  const stamp = commitCommunicationStampIntent(normalizedIntentId);
  if (!stamp) return null;
  hideCommunicationStampPicker({ render: false, requestRender: false });
  return finalizeCommunicationStampCommit(stamp, { source });
}

function handleCommunicationCanvasPointerDown(event, p, pCss) {
  const communicationTool = communicationToolId();
  const behaviorTool = communicationBehaviorToolId(communicationTool);
  if (event.button !== 0 || !communicationTool) return false;
  const resolveCommunicationImageId = () => {
    let imageId = hitTestVisibleCanvasImage(p);
    if (imageId) return imageId;
    if (state.canvasMode === "multi") {
      const canvas = els.workCanvas;
      if (canvas) {
        state.multiRects = computeFreeformRectsPx(canvas.width, canvas.height);
        imageId = hitTestVisibleCanvasImage(p);
      }
      return imageId;
    }
    if (state.canvasMode !== "multi") {
      const activeImageId = readFirstString(state.activeId, getActiveImage()?.id);
      if (activeImageId && state.imagesById?.has?.(activeImageId)) {
        return activeImageId;
      }
      return null;
    }
    return imageId;
  };
  if (behaviorTool === "eraser") {
    const erased = eraseCommunicationAtCanvasPoint(p);
    if (erased) {
      const previewPath =
        erased.imageId && typeof state !== "undefined" && state?.imagesById instanceof Map
          ? state.imagesById.get(erased.imageId)?.path || null
          : null;
      recordTimelineNode({
        imageId: erased.imageId || null,
        action:
          erased.kind === "region"
            ? "Erase Region"
            : erased.kind === "stamp"
              ? "Erase Stamp"
              : "Erase Mark",
        kind: "annotation",
        visualMode: "icon",
        label: erased.kind === "region" ? "Region" : erased.kind === "stamp" ? "Stamp" : "Mark",
        previewImageId: erased.imageId || null,
        previewPath,
      });
      invalidateActiveTabPreview("selection_overlay_change");
      dispatchJuggernautShellEvent(COMMUNICATION_STATE_CHANGED_EVENT, {
        source: "canvas_eraser",
        communication: buildCommunicationBridgeSnapshot(),
        context: buildJuggernautShellContext(),
      });
      requestRender();
      return true;
    }
    const targetImageId = resolveCommunicationImageId();
    if (targetImageId) {
      return beginCommunicationImageEraseStroke(event, p, pCss, targetImageId);
    }
    return false;
  }
  const communicationImageId = resolveCommunicationImageId();
  if (behaviorTool === "marker") {
    beginCommunicationMarkerStroke(
      event,
      p,
      pCss,
      communicationImageId,
      communicationTool === "protect" ? "freehand_protect" : "freehand_marker"
    );
    return true;
  }
  if (behaviorTool === "stamp") {
    if (typeof event?.preventDefault === "function") event.preventDefault();
    if (typeof event?.stopPropagation === "function") event.stopPropagation();
    bumpInteraction({ semantic: false });
    openCommunicationStampPickerAtPoint(p, pCss, communicationImageId);
    return true;
  }
  let imagePoint = communicationImageId && behaviorTool === "magic_select"
    ? resolveCommunicationMagicSelectImagePoint(p, communicationImageId)
    : communicationImageId
      ? canvasToImageForImageId(p, communicationImageId)
      : null;
  if (behaviorTool === "magic_select" && communicationImageId && imagePoint) {
    return beginCommunicationMagicSelectStroke(event, p, pCss, communicationImageId);
  }
  return false;
}

function resolveCommunicationMagicSelectImagePoint(ptCanvas = null, imageId = "") {
  const normalizedImageId = String(imageId || "").trim();
  if (!ptCanvas || !normalizedImageId) return null;
  let imagePoint = canvasToImageForImageId(ptCanvas, normalizedImageId);
  if (!imagePoint && state.canvasMode === "multi") {
    const canvas = els.workCanvas;
    if (canvas) {
      state.multiRects = computeFreeformRectsPx(canvas.width, canvas.height);
      imagePoint = canvasToImageForImageId(ptCanvas, normalizedImageId);
    }
  }
  if (!imagePoint && state.canvasMode !== "multi") {
    const activeImageId = readFirstString(state.activeId, getActiveImage()?.id);
    if (normalizedImageId === activeImageId) {
      imagePoint = canvasToImage(ptCanvas);
    }
  }
  return imagePoint;
}

function applyCommunicationToolSelection(tool = null, { source = "communication_rail", toggle = true } = {}) {
  const normalized = String(tool || "").trim().toLowerCase();
  const next = COMMUNICATION_TOOL_IDS.includes(normalized) ? normalized : null;
  if (toggle && state.communication.tool === next) {
    state.communication.tool = null;
  } else {
    state.communication.tool = next;
  }
  state.communication.markDraft = null;
  state.communication.eraseDraft = null;
  if (next !== "stamp") {
    hideCommunicationStampPicker({ clearSelection: false, render: false, requestRender: false });
  }
  syncLocalMagicSelectUiPrewarmTargets({
    primaryImageId: state.activeId || null,
    hoverImageId: null,
    source: "communication_magic_select",
  });
  syncDropHintInteractivity();
  renderCommunicationChrome();
  renderQuickActions();
  dispatchJuggernautShellEvent(COMMUNICATION_STATE_CHANGED_EVENT, {
    source,
    communication: buildCommunicationBridgeSnapshot(),
    context: buildJuggernautShellContext(),
  });
  requestRender();
  return state.communication.tool;
}

function setCommunicationTool(tool = null, { source = "communication_rail" } = {}) {
  return applyCommunicationToolSelection(tool, { source, toggle: true });
}

function ensureCommunicationToolActive(tool = null, { source = "agent_observable_driver" } = {}) {
  return applyCommunicationToolSelection(tool, { source, toggle: false });
}

function renderCommunicationRail() {
  const activeTool = communicationToolId();
  const buttons = [
    els.communicationToolMarker,
    els.communicationToolProtect,
    els.communicationToolMagicSelect,
    els.communicationToolStamp,
    els.communicationToolMakeSpace,
    els.communicationToolEraser,
  ].filter(Boolean);
  for (const button of buttons) {
    const tool = String(button.dataset?.communicationTool || "").trim();
    button.classList.toggle("is-active", tool && tool === activeTool);
    button.setAttribute("aria-pressed", tool && tool === activeTool ? "true" : "false");
  }
}

function buildCommunicationFallbackRegionCandidate(imageId, anchor, dims, scale, index) {
  const shortEdge = Math.max(24, Math.min(Number(dims.w) || 0, Number(dims.h) || 0));
  const factor = index === 0 ? 0.18 : index === 1 ? 0.26 : 0.34;
  const w = clamp(Math.round(shortEdge * (index === 1 ? factor * 1.22 : factor)), 24, Math.max(36, Math.round((Number(dims.w) || 1) * 0.68)));
  const h = clamp(Math.round(shortEdge * (index === 2 ? factor * 1.2 : factor)), 24, Math.max(36, Math.round((Number(dims.h) || 1) * 0.68)));
  const x = clamp(Math.round((Number(anchor.x) || 0) - w * 0.5), 0, Math.max(0, (Number(dims.w) || 1) - w));
  const y = clamp(Math.round((Number(anchor.y) || 0) - h * 0.5), 0, Math.max(0, (Number(dims.h) || 1) - h));
  const cx = x + w * 0.5;
  const cy = y + h * 0.5;
  const polygon = [
    { x: cx, y },
    { x: x + w, y: cy },
    { x: cx, y: y + h },
    { x, y: cy },
  ];
  return {
    id: `region-${Date.now()}-${index + 1}-${Math.random().toString(16).slice(2, 7)}`,
    label: `Candidate ${index + 1}`,
    confidence: clamp(0.94 - index * 0.12, 0.36, 0.98),
    bounds: { x, y, w, h },
    contourPoints: polygon,
    maskRef: null,
    source: "coarse_fallback",
    polygon,
    scale,
  };
}

function applyCommunicationMagicSelectAtPoint(imageId, imagePoint, deterministicResult = null) {
  const id = String(imageId || "").trim();
  const item = state.imagesById.get(id) || null;
  if (!id || !item || !imagePoint) return null;
  const dims = {
    w: Math.max(1, Number(item?.img?.naturalWidth || item?.width) || 1),
    h: Math.max(1, Number(item?.img?.naturalHeight || item?.height) || 1),
  };
  const existing = communicationRegionGroupForImage(id);
  const nextAnchor = {
    x: clamp(Math.round(Number(imagePoint.x) || 0), 0, dims.w),
    y: clamp(Math.round(Number(imagePoint.y) || 0), 0, dims.h),
  };
  let group = null;
  if (
    existing?.anchor &&
    readFirstString(existing?.imagePath, item?.path) === readFirstString(item?.path) &&
    Math.hypot((Number(existing.anchor.x) || 0) - nextAnchor.x, (Number(existing.anchor.y) || 0) - nextAnchor.y) <=
      Math.max(24, Math.round(Math.min(dims.w, dims.h) * 0.08))
  ) {
    group = {
      ...existing,
      imagePath: readFirstString(item?.path) || null,
      activeCandidateIndex: (Math.max(0, Number(existing.activeCandidateIndex) || 0) + 1) %
        Math.max(1, Array.isArray(existing.candidates) ? existing.candidates.length : 1),
      chosenCandidateId:
        existing.candidates?.[
          (Math.max(0, Number(existing.activeCandidateIndex) || 0) + 1) %
            Math.max(1, Array.isArray(existing.candidates) ? existing.candidates.length : 1)
        ]?.id || existing.chosenCandidateId || null,
      updatedAt: Date.now(),
    };
  } else {
    const candidates = resolveCommunicationMagicSelectCandidates(id, nextAnchor, dims, deterministicResult);
    const preserveRequestedChoice = deterministicResult?.preserveChosenCandidate === true;
    const requestedChosenCandidateId = preserveRequestedChoice ? readFirstString(deterministicResult?.chosenCandidateId) || null : null;
    const requestedActiveCandidateIndex = requestedChosenCandidateId
      ? candidates.findIndex((candidate) => String(candidate?.id || "").trim() === requestedChosenCandidateId)
      : preserveRequestedChoice
        ? Math.max(0, Number(deterministicResult?.activeCandidateIndex) || 0)
        : 0;
    const activeCandidateIndex = clamp(
      requestedActiveCandidateIndex >= 0 ? requestedActiveCandidateIndex : 0,
      0,
      Math.max(0, candidates.length - 1)
    );
    group = {
      imageId: id,
      imagePath: readFirstString(item?.path) || null,
      anchor: nextAnchor,
      candidates,
      activeCandidateIndex,
      chosenCandidateId: candidates[activeCandidateIndex]?.id || candidates[0]?.id || null,
      reproducibility:
        deterministicResult?.reproducibility && typeof deterministicResult.reproducibility === "object"
          ? JSON.parse(JSON.stringify(deterministicResult.reproducibility))
          : null,
      receipt:
        deterministicResult?.receipt && typeof deterministicResult.receipt === "object"
          ? JSON.parse(JSON.stringify(deterministicResult.receipt))
          : null,
      warnings: Array.isArray(deterministicResult?.warnings)
        ? deterministicResult.warnings.map((value) => String(value))
        : [],
      updatedAt: Date.now(),
    };
  }
  state.communication.regionProposalsByImageId.set(id, group);
  state.communication.lastAnchor = communicationAnchorFromRegionGroup(group);
  return group;
}

async function runLocalCommunicationMagicSelectAtPoint(
  imageId,
  imagePoint,
  { source = "communication_magic_select" } = {}
) {
  const id = String(imageId || "").trim();
  const item = state.imagesById.get(id) || null;
  if (!id || !item || !imagePoint) {
    throw new Error("Magic Select requires a visible target image.");
  }
  if (!item?.path) {
    throw new Error("Magic Select target image does not have a local source path.");
  }
  const dims = {
    w: Math.max(1, Number(item?.img?.naturalWidth || item?.width) || 1),
    h: Math.max(1, Number(item?.img?.naturalHeight || item?.height) || 1),
  };
  const anchor = {
    x: clamp(Math.round(Number(imagePoint?.x) || 0), 0, Math.max(0, dims.w - 1)),
    y: clamp(Math.round(Number(imagePoint?.y) || 0), 0, Math.max(0, dims.h - 1)),
  };
  const existing = communicationRegionGroupForImage(id);
  const shouldCycleExisting = Boolean(
    existing?.anchor &&
      readFirstString(existing?.imagePath, item?.path) === readFirstString(item?.path) &&
      Math.hypot((Number(existing.anchor.x) || 0) - anchor.x, (Number(existing.anchor.y) || 0) - anchor.y) <=
        Math.max(24, Math.round(Math.min(dims.w, dims.h) * 0.08))
  );

  let response = null;
  let fallbackWarning = "";
  let group = null;
  if (shouldCycleExisting) {
    group = applyCommunicationMagicSelectAtPoint(id, anchor);
  } else {
    await ensureRun();
    beginLocalMagicSelectUiActivity("click");
    const directClickRequest = {
      imageId: id,
      imagePath: String(item.path),
      runDir: state.runDir || null,
      stableSourceRef: readFirstString(item?.receiptPath, item?.path) || null,
      clickAnchor: anchor,
      source,
    };
    const applyDeterministicResponse = (result = null) => {
      if (result?.preparedImage) {
        rememberLocalMagicSelectPreparedImageForUi(result.preparedImage);
      }
      return applyCommunicationMagicSelectAtPoint(id, anchor, {
        ...(result?.group && typeof result.group === "object" ? result.group : {}),
        receipt: result?.receipt || null,
        reproducibility: result?.group?.reproducibility ?? result?.receipt?.reproducibility ?? null,
        warnings: Array.isArray(result?.warnings) ? result.warnings : [],
      });
    };
    const directClick = async () => {
      const result = await runLocalMagicSelectClick(directClickRequest);
      void prepareLocalMagicSelectImageForUi(id, { source }).catch(() => {});
      return result;
    };
    const preparedImage = localMagicSelectPreparedImageForUi(id, {
      imagePath: String(item.path),
      runDir: state.runDir || null,
    });
    try {
      if (preparedImage) {
        try {
          response = await runWarmLocalMagicSelectClick({
            preparedImageId: preparedImage.id,
            preparedImage,
            imageId: id,
            clickAnchor: anchor,
            source,
          });
        } catch (error) {
          void dropLocalMagicSelectPreparedImageForUi(id, {
            reason: "warm_click_failed",
          }).catch(() => {});
          response = await directClick().catch((directError) => {
            throw directError?.message ? directError : error;
          });
        }
      } else {
        response = await directClick();
      }
      group = applyDeterministicResponse(response);
    } catch (error) {
      fallbackWarning = readFirstString(error?.message, "Magic Select local runtime failed.");
      group = applyCommunicationMagicSelectAtPoint(id, anchor, {
        warnings: [fallbackWarning],
      });
    } finally {
      endLocalMagicSelectUiActivity("click");
    }
  }

  if (!group) {
    throw new Error("Magic Select failed to create a region group.");
  }
  if (
    state.communication?.proposalTray?.visible &&
    !communicationTrayAnchorPinnedToTitlebar(state.communication?.proposalTray?.anchor)
  ) {
    state.communication.proposalTray.anchor = state.communication.lastAnchor;
  }
  invalidateActiveTabPreview("selection_overlay_change");
  dispatchJuggernautShellEvent(COMMUNICATION_STATE_CHANGED_EVENT, {
    source,
    communication: buildCommunicationBridgeSnapshot(),
    context: buildJuggernautShellContext(),
  });
  requestRender();
  const warnings = Array.isArray(group?.warnings) ? group.warnings.map((value) => String(value)) : [];
  const candidateCount = Array.isArray(group?.candidates) ? group.candidates.length : 0;
  const activeCandidateIndex = clamp(Math.max(0, Number(group?.activeCandidateIndex) || 0), 0, Math.max(0, candidateCount - 1));
  const hasModelCandidates =
    Array.isArray(group?.candidates) &&
    group.candidates.some((entry) => String(entry?.source || "").trim() !== "coarse_fallback");
  if (hasModelCandidates && candidateCount > 1) {
    if (shouldCycleExisting) {
      showToast(`Magic Select ${activeCandidateIndex + 1} of ${candidateCount}. Click again near the same spot to cycle.`, "tip", 2200);
    } else {
      showToast(`Magic Select found ${candidateCount} masks. Click again near the same spot to cycle.`, "tip", 2800);
    }
  }
  const candidate =
    (Array.isArray(group?.candidates) && String(group?.chosenCandidateId || "").trim()
      ? group.candidates.find((entry) => String(entry?.id || "").trim() === String(group.chosenCandidateId || "").trim())
      : null) ||
    group?.candidates?.[Math.max(0, Number(group?.activeCandidateIndex) || 0)] ||
    null;
  return {
    ok: true,
    contract: response?.contract || null,
    action: response?.action || "magic_select_click",
    imageId: id,
    candidate,
    group,
    receipt: response?.receipt || group?.receipt || null,
    warnings,
    fallback: Boolean(fallbackWarning),
  };
}

function commitCommunicationMarkDraft() {
  const draft = state.communication?.markDraft;
  const screenPoints = communicationDraftScreenPoints(draft);
  if (screenPoints.length < 2) {
    state.communication.markDraft = null;
    return null;
  }
  const totalLength = communicationPolylineLength(screenPoints);
  if (totalLength < COMMUNICATION_MARK_MIN_DRAG_PX) {
    state.communication.markDraft = null;
    return null;
  }
  const committedPoints = communicationCommittedPointsFromDraft(draft);
  if (committedPoints.length < 2) {
    state.communication.markDraft = null;
    return null;
  }
  const markKind = String(draft?.kind || "").trim().toLowerCase() === "freehand_protect"
    ? "freehand_protect"
    : "freehand_marker";
  const markColor = markKind === "freehand_protect" ? COMMUNICATION_PROTECT_STROKE : COMMUNICATION_MARK_STROKE;
  const imageId = String(draft.imageId || "").trim();
  const sourceImageId = imageId || null;
  const nextId = `mark-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`;
  const finalize = (mark, { imageBucketId = "" } = {}) => {
    if (imageBucketId) {
      const existing = communicationMarksForImage(imageBucketId);
      state.communication.marksByImageId.set(imageBucketId, existing.concat(mark));
    } else {
      state.communication.canvasMarks = communicationCanvasMarks().concat(mark);
    }
    state.communication.markDraft = null;
    state.communication.lastAnchor = communicationAnchorFromMark(mark);
    return mark;
  };
  if (imageId) {
    const imagePoints = committedPoints
      .map((point) =>
        canvasToImageForImageId(communicationScreenCssPointToCanvas(point), imageId)
      )
      .filter(
        (point) =>
          Number.isFinite(Number(point?.x)) && Number.isFinite(Number(point?.y))
      )
      .map((point) => ({
        x: Number(point.x) || 0,
        y: Number(point.y) || 0,
      }));
    if (imagePoints.length >= 2) {
      return finalize(
        {
          id: nextId,
          imageId,
          sourceImageId,
          kind: markKind,
          coordinateSpace: "image",
          color: markColor,
          points: imagePoints.slice(0, COMMUNICATION_MARK_MAX_POINTS),
          createdAt: Date.now(),
        },
        { imageBucketId: imageId }
      );
    }
  }
  const next = {
    id: nextId,
    imageId: null,
    sourceImageId,
    kind: markKind,
    coordinateSpace: "canvas_world",
    color: markColor,
    points: committedPoints
      .slice(0, COMMUNICATION_MARK_MAX_POINTS)
      .map((point) => canvasScreenCssToWorldCss(point))
      .map((point) => ({
        x: Number(point?.x) || 0,
        y: Number(point?.y) || 0,
      })),
    createdAt: Date.now(),
  };
  return finalize(next);
}

function eraseCommunicationAtCanvasPoint(ptCanvas) {
  const stampHit = hitTestCommunicationStamp(ptCanvas);
  if (stampHit?.stamp?.id) {
    const imageId = String(stampHit.imageId || "");
    if (imageId) {
      const next = communicationStampsForImage(imageId).filter((stamp) => String(stamp?.id || "") !== String(stampHit.stamp.id || ""));
      if (next.length) state.communication.stampsByImageId.set(imageId, next);
      else state.communication.stampsByImageId.delete(imageId);
    } else {
      state.communication.canvasStamps = communicationCanvasStamps().filter(
        (stamp) => String(stamp?.id || "") !== String(stampHit.stamp.id || "")
      );
    }
    if (state.communication.lastAnchor?.stampId === String(stampHit.stamp.id || "")) {
      state.communication.lastAnchor = resolveCommunicationReviewAnchor();
    }
    if (state.communication.proposalTray?.anchor?.stampId === String(stampHit.stamp.id || "")) {
      hideCommunicationProposalTray({ preserveAnchor: false, source: "eraser" });
    }
    return { kind: "stamp", imageId };
  }
  const markHit = hitTestCommunicationMark(ptCanvas);
  if (markHit?.mark?.id) {
    const imageId = String(markHit.imageId || "");
    if (imageId) {
      const next = communicationMarksForImage(imageId).filter((mark) => String(mark?.id || "") !== String(markHit.mark.id || ""));
      if (next.length) state.communication.marksByImageId.set(imageId, next);
      else state.communication.marksByImageId.delete(imageId);
    } else {
      state.communication.canvasMarks = communicationCanvasMarks().filter(
        (mark) => String(mark?.id || "") !== String(markHit.mark.id || "")
      );
    }
    if (state.communication.lastAnchor?.markId === String(markHit.mark.id || "")) {
      state.communication.lastAnchor = resolveCommunicationReviewAnchor();
    }
    if (state.communication.proposalTray?.anchor?.markId === String(markHit.mark.id || "")) {
      hideCommunicationProposalTray({ preserveAnchor: false, source: "eraser" });
    }
    return { kind: "mark", imageId };
  }
  const regionHit = hitTestCommunicationRegionCandidate(ptCanvas);
  if (regionHit?.imageId) {
    state.communication.regionProposalsByImageId.delete(String(regionHit.imageId || ""));
    if (state.communication.lastAnchor?.imageId === String(regionHit.imageId || "") && state.communication.lastAnchor?.kind === "region") {
      state.communication.lastAnchor = resolveCommunicationReviewAnchor();
    }
    if (state.communication.proposalTray?.anchor?.imageId === String(regionHit.imageId || "") && state.communication.proposalTray?.anchor?.kind === "region") {
      hideCommunicationProposalTray({ preserveAnchor: false, source: "eraser" });
    }
    return { kind: "region", imageId: String(regionHit.imageId || "") };
  }
  return null;
}

function buildCommunicationVisibleImagesPayload() {
  return getVisibleCanvasImages().map((item) => {
    const rectCss = getImageRectCss(item?.id) || null;
    return {
      id: String(item?.id || ""),
      path: item?.path ? String(item.path) : null,
      label: item?.label ? String(item.label) : basename(item?.path || "") || "Untitled",
      width: Number(item?.img?.naturalWidth || item?.width) || null,
      height: Number(item?.img?.naturalHeight || item?.height) || null,
      active: String(item?.id || "") === String(state.activeId || ""),
      selected: getSelectedIds().includes(String(item?.id || "")),
      rectCss: rectCss
        ? {
            left: Number(rectCss.left) || 0,
            top: Number(rectCss.top) || 0,
            width: Number(rectCss.width) || 0,
            height: Number(rectCss.height) || 0,
            rotateDeg: Number(rectCss.rotateDeg) || 0,
            skewXDeg: Number(rectCss.skewXDeg) || 0,
          }
        : null,
    };
  });
}

function buildCommunicationMarksPayload() {
  const out = [];
  for (const [imageId, marks] of Array.from(state.communication?.marksByImageId?.entries?.() || [])) {
    const list = Array.isArray(marks) ? marks : [];
    for (const mark of list) {
      const bounds = communicationPointsBounds(mark?.points || []);
      out.push({
        id: String(mark?.id || ""),
        type: String(mark?.kind || "freehand_marker"),
        imageId: String(imageId || "") || null,
        coordinateSpace: String(mark?.coordinateSpace || "image"),
        color: String(mark?.color || COMMUNICATION_MARK_STROKE),
        createdAt: Number(mark?.createdAt) || Date.now(),
        points: Array.isArray(mark?.points)
          ? mark.points.map((point) => ({
              x: Number(point?.x) || 0,
              y: Number(point?.y) || 0,
            }))
          : [],
        bounds,
      });
    }
  }
  for (const mark of communicationCanvasMarks()) {
    const bounds = communicationPointsBounds(
      String(mark?.coordinateSpace || "").trim() === "canvas_overlay"
        ? mark?.points || []
        : communicationMarkPointsToCanvasCss(mark)
    );
    out.push({
      id: String(mark?.id || ""),
      type: String(mark?.kind || "freehand_marker"),
      imageId: String(mark?.coordinateSpace || "").trim() === "canvas_overlay" ? null : String(mark?.imageId || "") || null,
      sourceImageId: String(mark?.sourceImageId || mark?.imageId || "") || null,
      coordinateSpace: String(mark?.coordinateSpace || "canvas_overlay"),
      color: String(mark?.color || COMMUNICATION_MARK_STROKE),
      createdAt: Number(mark?.createdAt) || Date.now(),
      points: Array.isArray(mark?.points)
        ? mark.points.map((point) => ({
            x: Number(point?.x) || 0,
            y: Number(point?.y) || 0,
          }))
        : [],
      bounds,
    });
  }
  return out;
}

function buildCommunicationStampsPayload() {
  const out = [];
  for (const [imageId, stamps] of Array.from(state.communication?.stampsByImageId?.entries?.() || [])) {
    const list = Array.isArray(stamps) ? stamps : [];
    for (const stamp of list) {
      out.push({
        id: String(stamp?.id || ""),
        intentId: normalizeCommunicationStampIntentId(stamp?.intentId),
        label: communicationStampRecordLabel(stamp),
        instruction: communicationStampRecordInstruction(stamp),
        imageId: String(imageId || "") || null,
        sourceImageId: String(stamp?.sourceImageId || imageId || "") || null,
        coordinateSpace: String(stamp?.coordinateSpace || "image"),
        targetPoint: stamp?.targetPoint
          ? {
              x: Number(stamp.targetPoint.x) || 0,
              y: Number(stamp.targetPoint.y) || 0,
            }
          : null,
        bounds: stamp?.targetBounds
          ? {
              x: Number(stamp.targetBounds.x) || 0,
              y: Number(stamp.targetBounds.y) || 0,
              w: Math.max(1, Number(stamp.targetBounds.w) || 1),
              h: Math.max(1, Number(stamp.targetBounds.h) || 1),
            }
          : null,
        createdAt: Number(stamp?.createdAt) || Date.now(),
      });
    }
  }
  for (const stamp of communicationCanvasStamps()) {
    out.push({
      id: String(stamp?.id || ""),
      intentId: normalizeCommunicationStampIntentId(stamp?.intentId),
      label: communicationStampRecordLabel(stamp),
      instruction: communicationStampRecordInstruction(stamp),
      imageId: null,
      sourceImageId: String(stamp?.sourceImageId || stamp?.imageId || "") || null,
      coordinateSpace: String(stamp?.coordinateSpace || "canvas_world"),
      targetPoint: stamp?.targetPoint
        ? {
            x: Number(stamp.targetPoint.x) || 0,
            y: Number(stamp.targetPoint.y) || 0,
          }
        : null,
      bounds: stamp?.targetBounds
        ? {
            x: Number(stamp.targetBounds.x) || 0,
            y: Number(stamp.targetBounds.y) || 0,
            w: Math.max(1, Number(stamp.targetBounds.w) || 1),
            h: Math.max(1, Number(stamp.targetBounds.h) || 1),
          }
        : null,
      createdAt: Number(stamp?.createdAt) || Date.now(),
    });
  }
  return out.slice(0, COMMUNICATION_STAMP_MAX_VISIBLE);
}

function buildCommunicationStampFocusInputsPayload() {
  return buildCommunicationStampsPayload().map((stamp, index) => ({
    focusInputId: `stamp-focus:${readFirstString(stamp?.id) || index + 1}`,
    kind: "highlight",
    imageId: readFirstString(stamp?.imageId, stamp?.sourceImageId) || null,
    bounds: stamp?.bounds
      ? {
          x: Number(stamp.bounds.x) || 0,
          y: Number(stamp.bounds.y) || 0,
          width: Math.max(1, Number(stamp.bounds.w) || 1),
          height: Math.max(1, Number(stamp.bounds.h) || 1),
        }
      : null,
    instruction: readFirstString(stamp?.instruction, stamp?.label) || communicationStampInstruction(stamp?.intentId),
    sourceTool: "stamp",
    tool: "stamp",
    stampId: readFirstString(stamp?.id) || null,
    stampIntentId: normalizeCommunicationStampIntentId(stamp?.intentId) || null,
    stampLabel: readFirstString(stamp?.label) || null,
  }));
}

function buildCommunicationRegionsPayload() {
  const out = [];
  for (const [imageId, group] of Array.from(state.communication?.regionProposalsByImageId?.entries?.() || [])) {
    const candidates = Array.isArray(group?.candidates) ? group.candidates : [];
    const activeCandidateIndex = Math.max(0, Number(group?.activeCandidateIndex) || 0);
    out.push({
      imageId: String(imageId || ""),
      anchor: group?.anchor
        ? {
            x: Number(group.anchor.x) || 0,
            y: Number(group.anchor.y) || 0,
          }
        : null,
      activeCandidateIndex,
      chosenCandidateId: group?.chosenCandidateId ? String(group.chosenCandidateId) : null,
      reproducibility:
        group?.reproducibility && typeof group.reproducibility === "object"
          ? JSON.parse(JSON.stringify(group.reproducibility))
          : null,
      receipt:
        group?.receipt && typeof group.receipt === "object"
          ? JSON.parse(JSON.stringify(group.receipt))
          : null,
      warnings: Array.isArray(group?.warnings) ? group.warnings.map((value) => String(value)) : [],
      candidates: candidates.map((candidate, index) => {
        const polygon = communicationRegionCandidateImagePoints(candidate);
        return {
          id: String(candidate?.id || `candidate-${index + 1}`),
          label: String(candidate?.label || `Candidate ${index + 1}`),
          confidence: Number(candidate?.confidence) || 0,
          source:
            candidate?.source && typeof candidate.source === "object"
              ? JSON.parse(JSON.stringify(candidate.source))
              : candidate?.source
                ? String(candidate.source)
                : "magic_select",
          maskRef:
            candidate?.maskRef && typeof candidate.maskRef === "object"
              ? {
                  path: readFirstString(candidate.maskRef.path) || null,
                  sha256: readFirstString(candidate.maskRef.sha256) || null,
                  width: Math.max(1, Number(candidate.maskRef.width) || 1),
                  height: Math.max(1, Number(candidate.maskRef.height) || 1),
                  format: readFirstString(candidate.maskRef.format, "png"),
                }
              : candidate?.maskRef
                ? String(candidate.maskRef)
                : null,
          bounds: candidate?.bounds
            ? {
                x: Number(candidate.bounds.x) || 0,
                y: Number(candidate.bounds.y) || 0,
                w: Math.max(1, Number(candidate.bounds.w) || 1),
                h: Math.max(1, Number(candidate.bounds.h) || 1),
              }
            : null,
          contourPoints: Array.isArray(candidate?.contourPoints)
            ? candidate.contourPoints.map((point) => ({
                x: Number(point?.x) || 0,
                y: Number(point?.y) || 0,
              }))
            : [],
          polygon,
          active: index === activeCandidateIndex,
        };
      }),
    });
  }
  return out;
}

function buildCommunicationProposalTraySnapshot() {
  const tray = state.communication?.proposalTray || createFreshCommunicationState().proposalTray;
  const ui = normalizeCommunicationProposalTrayUiState(tray.ui);
  return {
    visible: Boolean(tray.visible),
    requestId: tray.requestId ? String(tray.requestId) : null,
    source: tray.source ? String(tray.source) : null,
    anchor: tray.anchor ? { ...tray.anchor } : null,
    ui,
    slots: Array.isArray(tray.slots)
      ? tray.slots.map((slot, index) =>
          createCommunicationProposalSlot(index, {
            ...slot,
            selected: ui.selectedProposalId && readFirstString(slot?.proposalId) === ui.selectedProposalId,
          })
        )
      : Array.from({ length: COMMUNICATION_PROPOSAL_SLOT_COUNT }, (_, index) => createCommunicationProposalSlot(index, {})),
  };
}

function buildScreenshotPolishFrameSnapshot(frame = null, overrides = {}) {
  const current = asRecord(frame) || {};
  const normalizedOverrides = asRecord(overrides) || {};
  const snapshot = {
    imageId:
      readFirstString(
        normalizedOverrides.imageId,
        normalizedOverrides.image_id,
        current.imageId,
        current.image_id,
        current.id
      ) || null,
    path: readFirstString(normalizedOverrides.path, current.path, normalizedOverrides.outputPath, normalizedOverrides.output_path) || null,
    receiptPath:
      readFirstString(
        normalizedOverrides.receiptPath,
        normalizedOverrides.receipt_path,
        current.receiptPath,
        current.receipt_path
      ) || null,
    label: readFirstString(normalizedOverrides.label, current.label) || null,
    timelineNodeId:
      readFirstString(
        normalizedOverrides.timelineNodeId,
        normalizedOverrides.timeline_node_id,
        current.timelineNodeId,
        current.timeline_node_id
      ) || null,
    source: readFirstString(normalizedOverrides.source, current.source) || null,
    kind: readFirstString(normalizedOverrides.kind, current.kind) || null,
  };
  if (!snapshot.imageId && !snapshot.path && !snapshot.receiptPath) return null;
  return snapshot;
}

function buildScreenshotPolishFrameContext({
  detail = null,
  targetBefore = null,
  targetAfter = null,
  receiptPath = null,
  outputPath = null,
  timelineNodeId = null,
} = {}) {
  const originalFrame = buildScreenshotPolishFrameSnapshot(targetBefore);
  const approvedFrame = buildScreenshotPolishFrameSnapshot(targetAfter, {
    path: outputPath,
    receiptPath,
    timelineNodeId,
  });
  const targetImageId =
    readFirstString(detail?.targetImageId, detail?.target_image_id, approvedFrame?.imageId, originalFrame?.imageId) || null;
  if (!targetImageId && !originalFrame && !approvedFrame) return null;
  return {
    sessionKind: "screenshot_polish",
    requestId: readFirstString(detail?.requestId, detail?.request_id, detail?.request?.requestId) || null,
    targetImageId,
    originalFrame,
    approvedFrame,
  };
}

function buildScreenshotPolishApprovalState(options = {}) {
  const detail = asRecord(options?.detail) || {};
  const proposal = asRecord(detail.proposal) || {};
  const proposalId = readFirstString(detail.proposalId, detail.proposal_id, proposal.proposalId, proposal.id) || null;
  const selectedProposalId =
    readFirstString(detail.selectedProposalId, detail.selected_proposal_id, proposalId) || null;
  const previewImagePath =
    readFirstString(
      detail.previewImagePath,
      detail.preview_image_path,
      proposal.previewImagePath,
      proposal.preview_image_path
    ) || null;
  const changedRegionBounds =
    asRecord(detail.changedRegionBounds)
      ? cloneToolRuntimeValue(detail.changedRegionBounds)
      : asRecord(detail.changed_region_bounds)
        ? cloneToolRuntimeValue(detail.changed_region_bounds)
        : asRecord(proposal.changedRegionBounds)
          ? cloneToolRuntimeValue(proposal.changedRegionBounds)
          : asRecord(proposal.changed_region_bounds)
            ? cloneToolRuntimeValue(proposal.changed_region_bounds)
            : null;
  const preserveRegionIds = uniqueStringList([
    ...(Array.isArray(detail.preserveRegionIds) ? detail.preserveRegionIds : []),
    ...(Array.isArray(detail.preserve_region_ids) ? detail.preserve_region_ids : []),
    ...(Array.isArray(proposal.preserveRegionIds) ? proposal.preserveRegionIds : []),
    ...(Array.isArray(proposal.preserve_region_ids) ? proposal.preserve_region_ids : []),
  ]);
  const rationaleCodes = uniqueStringList([
    ...(Array.isArray(detail.rationaleCodes) ? detail.rationaleCodes : []),
    ...(Array.isArray(detail.rationale_codes) ? detail.rationale_codes : []),
    ...(Array.isArray(proposal.rationaleCodes) ? proposal.rationaleCodes : []),
    ...(Array.isArray(proposal.rationale_codes) ? proposal.rationale_codes : []),
  ]);
  const frameContext = buildScreenshotPolishFrameContext(options);
  if (
    !proposalId &&
    !selectedProposalId &&
    !previewImagePath &&
    !changedRegionBounds &&
    preserveRegionIds.length === 0 &&
    rationaleCodes.length === 0 &&
    !frameContext
  ) {
    return createFreshScreenshotPolishState();
  }
  return {
    proposalId,
    selectedProposalId,
    previewImagePath,
    changedRegionBounds,
    preserveRegionIds,
    rationaleCodes,
    frameContext: frameContext ? cloneToolRuntimeValue(frameContext) : null,
    updatedAt: Date.now(),
  };
}

function buildCommunicationReviewHistoryEntry({
  reason = "review_apply_success",
  detail = null,
  targetBefore = null,
  targetAfter = null,
  receiptPath = null,
  outputPath = null,
  timelineNodeId = null,
} = {}) {
  const normalizedDetail = detail && typeof detail === "object" ? detail : {};
  const marks = buildCommunicationMarksPayload();
  const stamps = buildCommunicationStampsPayload();
  const regionSelections = buildCommunicationRegionsPayload();
  const proposal = normalizedDetail?.proposal && typeof normalizedDetail.proposal === "object"
    ? cloneToolRuntimeValue(normalizedDetail.proposal)
    : null;
  const request = normalizedDetail?.request && typeof normalizedDetail.request === "object"
    ? cloneToolRuntimeValue(normalizedDetail.request)
    : null;
  const screenshotPolish = buildScreenshotPolishApprovalState({
    detail: normalizedDetail,
    targetBefore,
    targetAfter,
    receiptPath,
    outputPath,
    timelineNodeId,
  });
  const frameContext = screenshotPolish.frameContext;
  const hasScreenshotPolish =
    Boolean(
      screenshotPolish.proposalId ||
        screenshotPolish.selectedProposalId ||
        screenshotPolish.previewImagePath ||
        screenshotPolish.changedRegionBounds ||
        screenshotPolish.frameContext
    ) ||
    screenshotPolish.preserveRegionIds.length > 0 ||
    screenshotPolish.rationaleCodes.length > 0;
  if (!marks.length && !stamps.length && !regionSelections.length && !proposal && !request && !hasScreenshotPolish) {
    return null;
  }
  const selectedProposalId =
    readFirstString(
      normalizedDetail?.selectedProposalId,
      normalizedDetail?.selected_proposal_id,
      normalizedDetail?.proposalId,
      normalizedDetail?.proposal_id,
      proposal?.proposalId,
      proposal?.id,
      screenshotPolish.selectedProposalId,
      screenshotPolish.proposalId
    ) || null;
  return {
    archivedAt: new Date().toISOString(),
    reason: String(reason || "review_apply_success").trim() || "review_apply_success",
    requestId: readFirstString(normalizedDetail?.requestId, request?.requestId, state.communication?.proposalTray?.requestId) || null,
    proposalId: screenshotPolish.proposalId || selectedProposalId,
    selectedProposalId,
    anchor: cloneToolRuntimeValue(resolveCommunicationReviewAnchor()),
    resolvedTarget: cloneToolRuntimeValue(resolveCommunicationReviewTarget()),
    marks,
    stamps,
    regionSelections,
    proposalTray: buildCommunicationProposalTraySnapshot(),
    request,
    proposal,
    apply: {
      status: readFirstString(normalizedDetail?.status) || "succeeded",
      source: readFirstString(normalizedDetail?.source, DESIGN_REVIEW_APPLY_SOURCE) || DESIGN_REVIEW_APPLY_SOURCE,
      targetImageId: readFirstString(normalizedDetail?.targetImageId, targetAfter?.id, targetBefore?.id) || null,
      referenceImageIds: uniqueStringList(normalizedDetail?.referenceImageIds || []),
      provider: readFirstString(normalizedDetail?.provider) || null,
      requestedModel: readFirstString(normalizedDetail?.requestedModel) || null,
      normalizedModel: readFirstString(normalizedDetail?.normalizedModel) || null,
      receiptPath: readFirstString(receiptPath) || null,
      outputPath: readFirstString(outputPath) || null,
      timelineNodeId: readFirstString(timelineNodeId) || null,
      proposalId: screenshotPolish.proposalId || null,
      selectedProposalId: screenshotPolish.selectedProposalId || null,
      previewImagePath: screenshotPolish.previewImagePath || null,
      changedRegionBounds: screenshotPolish.changedRegionBounds ? cloneToolRuntimeValue(screenshotPolish.changedRegionBounds) : null,
      preserveRegionIds: uniqueStringList(screenshotPolish.preserveRegionIds || []),
      rationaleCodes: uniqueStringList(screenshotPolish.rationaleCodes || []),
      frameContext: frameContext ? cloneToolRuntimeValue(frameContext) : null,
    },
    targetBefore: targetBefore ? cloneToolRuntimeValue(targetBefore) : null,
    targetAfter: targetAfter ? cloneToolRuntimeValue(targetAfter) : null,
  };
}

function archiveCommunicationReviewContext(options = {}) {
  const entry = buildCommunicationReviewHistoryEntry(options);
  if (!entry) return null;
  const history = Array.isArray(state.communication?.reviewHistory) ? state.communication.reviewHistory.slice() : [];
  state.communication.reviewHistory = [entry, ...history].slice(0, COMMUNICATION_REVIEW_HISTORY_MAX);
  return entry;
}

function clearVisibleCommunicationReviewState() {
  if (!state.communication || typeof state.communication !== "object") {
    state.communication = createFreshCommunicationState();
    return state.communication;
  }
  state.communication.markDraft = null;
  state.communication.eraseDraft = null;
  state.communication.stampPicker = createFreshCommunicationStampPickerState();
  state.communication.marksByImageId = new Map();
  state.communication.canvasMarks = [];
  state.communication.stampsByImageId = new Map();
  state.communication.canvasStamps = [];
  state.communication.regionProposalsByImageId = new Map();
  state.communication.lastAnchor = null;
  return state.communication;
}

function buildCommunicationReviewPayload({ requestId = null, source = "ui" } = {}) {
  const wrap = els.canvasWrap;
  return {
    schemaVersion: COMMUNICATION_REVIEW_SCHEMA_VERSION,
    requestId: requestId ? String(requestId) : null,
    source,
    tabId: state.activeTabId || null,
    runDir: state.runDir || null,
    canvas: {
      mode: state.canvasMode,
      sizeCss: {
        width: Number(wrap?.clientWidth) || 0,
        height: Number(wrap?.clientHeight) || 0,
      },
      activeImageId: state.activeId || null,
      selectedImageIds: getSelectedIds(),
      view: {
        scale: Number(state.view?.scale) || 1,
        offsetX: Number(state.view?.offsetX) || 0,
        offsetY: Number(state.view?.offsetY) || 0,
      },
      multiView: {
        scale: Number(state.multiView?.scale) || 1,
        offsetX: Number(state.multiView?.offsetX) || 0,
        offsetY: Number(state.multiView?.offsetY) || 0,
      },
      visibleImages: buildCommunicationVisibleImagesPayload(),
    },
    communication: {
      tool: communicationReviewToolId(communicationToolId()),
      marks: buildCommunicationMarksPayload(),
      stamps: buildCommunicationStampsPayload(),
      focusInputs: buildCommunicationStampFocusInputsPayload(),
      regionSelections: buildCommunicationRegionsPayload(),
      latestAnchor: resolveCommunicationReviewAnchor(),
      resolvedTarget: resolveCommunicationReviewTarget(),
      proposalTray: buildCommunicationProposalTraySnapshot(),
    },
  };
}

function buildCommunicationBridgeSnapshot() {
  return {
    tool: communicationToolId(),
    markCount: buildCommunicationMarksPayload().length,
    stampCount: buildCommunicationStampsPayload().length,
    regionGroupCount: buildCommunicationRegionsPayload().length,
    latestAnchor: resolveCommunicationReviewAnchor(),
    proposalTray: buildCommunicationProposalTraySnapshot(),
  };
}

let observableCommunicationPointerSeq = 0;

function nextObservableCommunicationPointerId() {
  observableCommunicationPointerSeq += 1;
  return 900_000_000 + observableCommunicationPointerSeq;
}

function buildObservableCommunicationPointerEvent(pointCss = null, { pointerId = null, button = 0 } = {}) {
  const clamped = clampCanvasCssPoint(pointCss);
  return {
    button,
    pointerId: Number.isFinite(Number(pointerId)) ? Number(pointerId) : nextObservableCommunicationPointerId(),
    offsetX: Number(clamped.x) || 0,
    offsetY: Number(clamped.y) || 0,
    preventDefault() {},
    stopPropagation() {},
  };
}

function assertObservableCommunicationReady(tool = "") {
  if (state.pointer?.active) {
    const label = String(tool || "communication tool").trim() || "communication tool";
    throw new Error(`Observable ${label} action requires the canvas pointer state to be idle.`);
  }
}

function clearObservableCommunicationPointerState() {
  state.pointer.active = false;
  state.pointer.kind = null;
  state.pointer.imageId = null;
  state.pointer.role = null;
  state.pointer.corner = null;
  state.pointer.startRectCss = null;
  state.pointer.transformHandleEdge = null;
  state.pointer.transformPivotX = 0;
  state.pointer.transformPivotY = 0;
  state.pointer.transformAnchorWidthPx = 0;
  state.pointer.transformStartAngleRad = 0;
  state.pointer.transformStartRotateDeg = 0;
  state.pointer.transformStartSkewXDeg = 0;
  state.pointer.startX = 0;
  state.pointer.startY = 0;
  state.pointer.lastX = 0;
  state.pointer.lastY = 0;
  state.pointer.startCssX = 0;
  state.pointer.startCssY = 0;
  state.pointer.startOffsetX = 0;
  state.pointer.startOffsetY = 0;
  state.pointer.importPointCss = null;
  state.pointer.wheelOnTap = false;
  state.pointer.moved = false;
  state.pointer.semanticInteractionEmitted = false;
}

function resolveObservableCommunicationImageId(pointCanvas = null, requestedImageId = null) {
  const explicitImageId = String(requestedImageId || "").trim();
  if (explicitImageId) {
    return state.imagesById.has(explicitImageId) ? explicitImageId : null;
  }
  return pointCanvas ? hitTestVisibleCanvasImage(pointCanvas) : null;
}

function appendObservableCommunicationStrokeSamples(kind, samplesCss = []) {
  const draft = kind === COMMUNICATION_POINTER_KINDS.MARKER
    ? state.communication?.markDraft
    : kind === COMMUNICATION_POINTER_KINDS.ERASER
      ? state.communication?.eraseDraft
      : null;
  if (!draft) return [];
  const samples = Array.isArray(samplesCss)
    ? samplesCss.map((point) => clampCanvasCssPoint(point))
    : [];
  if (!samples.length) return communicationDraftScreenPoints(draft);
  const latest = samples[samples.length - 1] || null;
  if (latest) {
    const distancePx = Math.hypot(
      (Number(latest.x) || 0) - (Number(state.pointer.startCssX) || 0),
      (Number(latest.y) || 0) - (Number(state.pointer.startCssY) || 0)
    );
    if (distancePx > COMMUNICATION_MARK_MIN_DRAG_PX) {
      state.pointer.moved = true;
    }
    const latestCanvas = communicationScreenCssPointToCanvas(latest);
    state.pointer.lastX = Number(latestCanvas.x) || 0;
    state.pointer.lastY = Number(latestCanvas.y) || 0;
  }
  draft.screenPoints = communicationAppendDraftScreenPoints(draft.screenPoints, samples);
  requestRender();
  return communicationDraftScreenPoints(draft);
}

async function waitObservableCommunicationStep(stepDelayMs = 0) {
  const delay = Math.max(0, Math.min(5000, Math.round(Number(stepDelayMs) || 0)));
  await new Promise((resolve) => {
    if (typeof window !== "undefined" && typeof window.requestAnimationFrame === "function") {
      window.requestAnimationFrame(() => {
        if (delay > 0 && typeof window.setTimeout === "function") {
          window.setTimeout(resolve, delay);
        } else {
          resolve();
        }
      });
      return;
    }
    if (delay > 0) {
      setTimeout(resolve, delay);
      return;
    }
    resolve();
  });
}

async function appendObservableCommunicationStrokeSamplesWithPacing(
  kind,
  samplesCss = [],
  { stepDelayMs = 0 } = {}
) {
  const points = Array.isArray(samplesCss)
    ? samplesCss.map((point) => clampCanvasCssPoint(point))
    : [];
  if (!points.length) return [];
  if (!(Number(stepDelayMs) > 0)) {
    return appendObservableCommunicationStrokeSamples(kind, points);
  }
  for (const point of points) {
    appendObservableCommunicationStrokeSamples(kind, [point]);
    await waitObservableCommunicationStep(stepDelayMs);
  }
  const draft = kind === COMMUNICATION_POINTER_KINDS.MARKER
    ? state.communication?.markDraft
    : kind === COMMUNICATION_POINTER_KINDS.ERASER
      ? state.communication?.eraseDraft
      : null;
  return communicationDraftScreenPoints(draft);
}

function buildObservableCommunicationTraceSnapshot(request = null) {
  return buildCommunicationReviewPayload({
    requestId: readFirstString(request?.request_id, request?.requestId) || null,
    source: readFirstString(request?.source, "agent_observable_driver") || "agent_observable_driver",
  });
}

function finishObservableCommunicationMarkerStroke(
  pointerEvent = null,
  { source = "agent_observable_marker", tool = "marker" } = {}
) {
  const mark = commitCommunicationMarkDraft();
  clearObservableCommunicationPointerState();
  if (mark) {
    if (
      state.communication?.proposalTray?.visible &&
      !communicationTrayAnchorPinnedToTitlebar(state.communication?.proposalTray?.anchor)
    ) {
      state.communication.proposalTray.anchor = state.communication.lastAnchor;
    }
    invalidateActiveTabPreview("selection_overlay_change");
    dispatchJuggernautShellEvent(COMMUNICATION_STATE_CHANGED_EVENT, {
      source,
      communication: buildCommunicationBridgeSnapshot(),
      context: buildJuggernautShellContext(),
    });
  }
  requestRender();
  try {
    els.overlayCanvas.releasePointerCapture(pointerEvent?.pointerId);
  } catch {
    // ignore
  }
  return {
    ok: Boolean(mark),
    tool: tool === "protect" ? "highlight" : tool,
    mark_id: mark?.id ? String(mark.id) : null,
    image_id: mark?.imageId ? String(mark.imageId) : null,
    source_image_id: mark?.sourceImageId ? String(mark.sourceImageId) : null,
    coordinate_space: mark?.coordinateSpace ? String(mark.coordinateSpace) : null,
    point_count: Array.isArray(mark?.points) ? mark.points.length : 0,
    communication: buildCommunicationBridgeSnapshot(),
  };
}

async function finishObservableCommunicationMagicSelectClick(
  pointerEvent = null,
  { source = "agent_observable_magic_select" } = {}
) {
  const targetImageId = String(state.pointer.imageId || "").trim();
  const moved = Boolean(state.pointer.moved);
  const imagePoint = !moved && targetImageId
    ? resolveCommunicationMagicSelectImagePoint(canvasPointFromEvent(pointerEvent), targetImageId)
    : null;
  clearObservableCommunicationPointerState();
  requestRender();
  try {
    els.overlayCanvas.releasePointerCapture(pointerEvent?.pointerId);
  } catch {
    // ignore
  }
  const response = targetImageId && imagePoint
    ? await runLocalCommunicationMagicSelectAtPoint(targetImageId, imagePoint, { source })
    : null;
  const group = response?.group || null;
  return {
    ok: Boolean(group),
    tool: "magic_select",
    image_id: targetImageId || null,
    active_candidate_id: group?.chosenCandidateId ? String(group.chosenCandidateId) : null,
    candidate_count: Array.isArray(group?.candidates) ? group.candidates.length : 0,
    receipt: response?.receipt || null,
    warnings: Array.isArray(response?.warnings) ? response.warnings.map((value) => String(value)) : [],
    communication: buildCommunicationBridgeSnapshot(),
  };
}

async function finishObservableCommunicationEraserStroke(
  pointerEvent = null,
  { source = "agent_observable_eraser" } = {}
) {
  const eraseDraft = state.communication?.eraseDraft
    ? {
        ...state.communication.eraseDraft,
        screenPoints: communicationDraftScreenPoints(state.communication.eraseDraft),
      }
    : null;
  state.communication.eraseDraft = null;
  clearObservableCommunicationPointerState();
  requestRender();
  try {
    els.overlayCanvas.releasePointerCapture(pointerEvent?.pointerId);
  } catch {
    // ignore
  }
  let artifact = null;
  if (eraseDraft?.imageId) {
    artifact = await commitCommunicationImageEraseDraft(eraseDraft);
  }
  return {
    ok: Boolean(artifact),
    tool: "eraser",
    operation: artifact ? "image_erase" : "image_erase_noop",
    image_id: eraseDraft?.imageId ? String(eraseDraft.imageId) : null,
    point_count: Array.isArray(eraseDraft?.screenPoints) ? eraseDraft.screenPoints.length : 0,
    output_path: artifact?.outputPath || artifact?.path || null,
    receipt_path: artifact?.receiptPath || null,
    source,
    communication: buildCommunicationBridgeSnapshot(),
  };
}

function performObservableCommunicationAnnotationErase(
  pointCss = null,
  { source = "agent_observable_eraser" } = {}
) {
  const pointCanvas = communicationScreenCssPointToCanvas(pointCss);
  const erased = eraseCommunicationAtCanvasPoint(pointCanvas);
  if (!erased) {
    return {
      ok: false,
      tool: "eraser",
      operation: "annotation_erase_noop",
      image_id: null,
      communication: buildCommunicationBridgeSnapshot(),
    };
  }
  invalidateActiveTabPreview("selection_overlay_change");
  dispatchJuggernautShellEvent(COMMUNICATION_STATE_CHANGED_EVENT, {
    source,
    communication: buildCommunicationBridgeSnapshot(),
    context: buildJuggernautShellContext(),
  });
  requestRender();
  return {
    ok: true,
    tool: "eraser",
    operation: "annotation_erase",
    erased_kind: erased.kind ? String(erased.kind) : null,
    image_id: erased.imageId ? String(erased.imageId) : null,
    communication: buildCommunicationBridgeSnapshot(),
  };
}

async function performObservableCommunicationMarkerStroke(
  request = {},
  { toolId = "marker", toolLabel = "marker" } = {}
) {
  assertObservableCommunicationReady(toolLabel);
  ensureCommunicationToolActive(toolId, { source: readFirstString(request?.source, "agent_observable_driver") });
  const pointsCss = Array.isArray(request?.points) ? request.points.map((point) => clampCanvasCssPoint(point)) : [];
  const startCss = pointsCss[0] || { x: 0, y: 0 };
  const startCanvas = communicationScreenCssPointToCanvas(startCss);
  const targetImageId = resolveObservableCommunicationImageId(startCanvas, request?.image_id);
  const pointerEvent = buildObservableCommunicationPointerEvent(startCss);
  beginCommunicationMarkerStroke(
    pointerEvent,
    startCanvas,
    startCss,
    targetImageId,
    toolId === "protect" ? "freehand_protect" : "freehand_marker"
  );
  await appendObservableCommunicationStrokeSamplesWithPacing(
    COMMUNICATION_POINTER_KINDS.MARKER,
    pointsCss.slice(1),
    { stepDelayMs: request?.step_delay_ms }
  );
  return finishObservableCommunicationMarkerStroke(pointerEvent, { tool: toolId });
}

async function performObservableCommunicationMagicSelectClick(
  request = {},
  { toolId = "magic_select", toolLabel = "magic select" } = {}
) {
  assertObservableCommunicationReady(toolLabel);
  ensureCommunicationToolActive(toolId, { source: readFirstString(request?.source, "agent_observable_driver") });
  const pointCss = clampCanvasCssPoint(request?.point || request?.points?.[0]);
  const pointCanvas = communicationScreenCssPointToCanvas(pointCss);
  const targetImageId = resolveObservableCommunicationImageId(pointCanvas, request?.image_id);
  if (!targetImageId) {
    throw new Error(`${toolLabel[0].toUpperCase()}${toolLabel.slice(1)} requires a visible target image.`);
  }
  const pointerEvent = buildObservableCommunicationPointerEvent(pointCss);
  const began = beginCommunicationMagicSelectStroke(pointerEvent, pointCanvas, pointCss, targetImageId);
  if (!began) {
    throw new Error(`${toolLabel[0].toUpperCase()}${toolLabel.slice(1)} could not begin on the requested target image.`);
  }
  await waitObservableCommunicationStep(request?.step_delay_ms);
  return finishObservableCommunicationMagicSelectClick(pointerEvent);
}

async function performObservableCommunicationStampClick(request = {}) {
  assertObservableCommunicationReady("stamp");
  ensureCommunicationToolActive("stamp", { source: readFirstString(request?.source, "agent_observable_driver") });
  const pointCss = clampCanvasCssPoint(request?.point || request?.points?.[0]);
  const pointCanvas = communicationScreenCssPointToCanvas(pointCss);
  const targetImageId = resolveObservableCommunicationImageId(pointCanvas, request?.image_id);
  const intentId = normalizeCommunicationStampIntentId(
    readFirstString(request?.intent_id, request?.intentId, request?.stamp_intent, request?.stampIntent)
  );
  const customText = normalizeCommunicationStampCustomText(
    readFirstString(request?.custom_text, request?.customText, request?.label, request?.text)
  );
  if (!intentId) {
    throw new Error("Stamp requires an intent_id from the starter stamp set.");
  }
  if (intentId === "custom" && !customText) {
    throw new Error("Custom stamp requires custom_text.");
  }
  openCommunicationStampPickerAtPoint(pointCanvas, pointCss, targetImageId);
  await waitObservableCommunicationStep(request?.step_delay_ms);
  const stamp = commitPlacedCommunicationStampAtCanvasPoint(pointCanvas, pointCss, targetImageId, intentId, {
    source: "agent_observable_stamp",
    customText,
  });
  if (!stamp) {
    throw new Error(`Stamp intent "${intentId}" is unavailable.`);
  }
  return {
    ok: true,
    tool: "stamp",
    stamp_id: readFirstString(stamp?.id) || null,
    image_id: readFirstString(stamp?.imageId) || null,
    intent_id: normalizeCommunicationStampIntentId(stamp?.intentId) || null,
    label: communicationStampRecordLabel(stamp),
    instruction: communicationStampRecordInstruction(stamp),
    communication: buildCommunicationBridgeSnapshot(),
  };
}

async function performObservableCommunicationEraserStroke(request = {}) {
  assertObservableCommunicationReady("eraser");
  ensureCommunicationToolActive("eraser", { source: readFirstString(request?.source, "agent_observable_driver") });
  const pointsCss = Array.isArray(request?.points) ? request.points.map((point) => clampCanvasCssPoint(point)) : [];
  const startCss = pointsCss[0] || { x: 0, y: 0 };
  if (!String(request?.image_id || "").trim() && pointsCss.length === 1) {
    const annotationErase = performObservableCommunicationAnnotationErase(startCss);
    if (annotationErase.ok) {
      return annotationErase;
    }
  }
  const startCanvas = communicationScreenCssPointToCanvas(startCss);
  const targetImageId = resolveObservableCommunicationImageId(startCanvas, request?.image_id);
  if (!targetImageId) {
    throw new Error("Eraser stroke requires a visible target image.");
  }
  const pointerEvent = buildObservableCommunicationPointerEvent(startCss);
  const began = beginCommunicationImageEraseStroke(pointerEvent, startCanvas, startCss, targetImageId);
  if (!began) {
    throw new Error("Eraser stroke could not begin on the requested target image.");
  }
  await appendObservableCommunicationStrokeSamplesWithPacing(
    COMMUNICATION_POINTER_KINDS.ERASER,
    pointsCss.slice(1),
    { stepDelayMs: request?.step_delay_ms }
  );
  return await finishObservableCommunicationEraserStroke(pointerEvent);
}

function installAgentObservableDriverRuntime() {
  if (typeof window === "undefined") return null;
  const traceLog = createAgentTraceLog({
    appendJsonl: appendJsonlWithFallback,
    resolveRunDir: () => state.runDir,
  });
  const driver = createAgentObservableDriver({
    performMarkerStroke: performObservableCommunicationMarkerStroke,
    performProtectStroke: (request = {}) =>
      performObservableCommunicationMarkerStroke(request, { toolId: "protect", toolLabel: "highlight" }),
    performMagicSelectClick: performObservableCommunicationMagicSelectClick,
    performStampClick: performObservableCommunicationStampClick,
    performMakeSpaceClick: (request = {}) =>
      performObservableCommunicationMagicSelectClick(request, { toolId: "make_space", toolLabel: "make space" }),
    performEraserStroke: performObservableCommunicationEraserStroke,
    getContextSnapshot: ({ request }) => buildObservableCommunicationTraceSnapshot(request),
    traceLog,
  });
  const runtime = installAgentObservableDriverBridge({
    windowObj: window,
    CustomEventCtor: typeof CustomEvent === "function" ? CustomEvent : null,
    driver,
  });
  agentObservableDriverRuntime = {
    driver,
    traceLog,
    bridge: runtime?.bridge || null,
    handler: runtime?.handler || null,
  };
  return agentObservableDriverRuntime;
}

function buildCommunicationReviewPendingSlots({ overallStatus = "preparing" } = {}) {
  const normalized = normalizeCommunicationProposalSlotStatus(overallStatus);
  let slotStatuses = ["preparing", "planning", "planning"];
  if (normalized === "planning") {
    slotStatuses = ["planning", "planning", "planning"];
  } else if (normalized === "preview_running" || normalized === "ready") {
    slotStatuses = ["planning", "planning", "ready"];
  } else if (normalized === "failed") {
    slotStatuses = ["failed", "failed", "failed"];
  }
  return Array.from({ length: COMMUNICATION_PROPOSAL_SLOT_COUNT }, (_, index) =>
    createCommunicationProposalSlot(index, {
      status: slotStatuses[index] || slotStatuses[slotStatuses.length - 1] || "skeleton",
    })
  );
}

function communicationProposalCopyFromReviewState(slot = {}, status = "skeleton") {
  const rawStatus = String(slot?.status || "").trim().toLowerCase();
  const proposal = slot?.proposal && typeof slot.proposal === "object" ? slot.proposal : null;
  if (rawStatus === "apply_running") {
    return "Applying to the target image.";
  }
  if (rawStatus === "apply_succeeded") {
    return "Applied to the target image.";
  }
  if (slot?.error || rawStatus === "failed" || rawStatus === "apply_failed") {
    return clampText(
      String(slot?.error || "The final edit could not be rendered.").trim(),
      120
    );
  }
  return clampText(
    readFirstString(proposal?.previewBrief, proposal?.applyBrief, proposal?.why) ||
      communicationProposalDefaultCopy(status),
    104
  );
}

function buildCommunicationProposalSlotsFromReviewState(reviewState = {}) {
  const normalizedState = reviewState && typeof reviewState === "object" ? reviewState : {};
  const overallStatus = normalizeCommunicationProposalSlotStatus(normalizedState.status || "preparing");
  const rawSlots = Array.isArray(normalizedState.slots) ? normalizedState.slots : [];
  if (!rawSlots.length) return buildCommunicationReviewPendingSlots({ overallStatus });
  const trayUi = normalizeCommunicationProposalTrayUiState(
    state.communication?.proposalTray?.ui,
    normalizedState?.communication?.proposalTray?.ui
  );
  return Array.from({ length: COMMUNICATION_PROPOSAL_SLOT_COUNT }, (_, index) => {
    const slot = rawSlots[index] || {};
    const proposal = slot?.proposal && typeof slot.proposal === "object" ? slot.proposal : null;
    const status = normalizeCommunicationProposalSlotStatus(slot?.status || overallStatus);
    const proposalId = readFirstString(slot?.proposalId, proposal?.proposalId) || null;
    return createCommunicationProposalSlot(index, {
      status,
      proposalId,
      label: slot?.rank ? `Proposal ${slot.rank}` : null,
      title: proposal?.label || slot?.label || communicationProposalDefaultTitle(status),
      copy: communicationProposalCopyFromReviewState(slot, status),
      previewImagePath: readFirstString(slot?.previewImagePath, proposal?.previewImagePath) || null,
      changedRegionBounds:
        proposal?.changedRegionBounds &&
        typeof proposal.changedRegionBounds === "object" &&
        !Array.isArray(proposal.changedRegionBounds)
          ? { ...proposal.changedRegionBounds }
          : null,
      preserveRegionIds: Array.isArray(proposal?.preserveRegionIds) ? proposal.preserveRegionIds : [],
      rationaleCodes: Array.isArray(proposal?.rationaleCodes) ? proposal.rationaleCodes : [],
      selected: Boolean(proposalId && trayUi.selectedProposalId === proposalId),
      previewStatus: slot?.status || normalizedState.status || null,
    });
  });
}

function suppressBootstrapDesignReviewTray() {
  if (typeof document === "undefined") return false;
  const tray = document.getElementById(DESIGN_REVIEW_BOOTSTRAP_TRAY_ID);
  if (!tray) return false;
  tray.classList.add("hidden");
  tray.hidden = true;
  tray.style.display = "none";
  tray.setAttribute("aria-hidden", "true");
  return true;
}

function setCommunicationProposalTray(
  next = {},
  {
    source = "review_runtime",
    render = true,
    dispatch = true,
    requestRender: shouldRequestRender = true,
  } = {}
) {
  clearCommunicationProposalTrayDismissTimer();
  els.communicationProposalTray?.classList.remove("is-dismissing");
  const tray = state.communication.proposalTray || createFreshCommunicationState().proposalTray;
  const previousRequestId = readFirstString(tray.requestId);
  const anchor = next?.anchor && typeof next.anchor === "object" ? { ...next.anchor } : resolveCommunicationReviewAnchor();
  tray.visible = next?.visible !== false;
  tray.requestId = next?.requestId ? String(next.requestId) : tray.requestId || null;
  tray.source = String(next?.source || source || "review_runtime").trim() || "review_runtime";
  tray.anchor = anchor || null;
  if (!communicationTrayAnchorPinnedToTitlebar(anchor)) {
    clearCommunicationProposalTrayAnchorLock(tray);
  }
  tray.slots = Array.from({ length: COMMUNICATION_PROPOSAL_SLOT_COUNT }, (_, index) =>
    createCommunicationProposalSlot(index, Array.isArray(next?.slots) ? next.slots[index] || {} : tray.slots?.[index] || {})
  );
  const requestChanged = previousRequestId !== readFirstString(tray.requestId);
  const baseUi = normalizeCommunicationProposalTrayUiState(
    requestChanged ? null : tray.ui
  );
  const selectableProposalId =
    tray.slots.find((slot) => readFirstString(slot?.proposalId))?.proposalId || null;
  const nextUi = normalizeCommunicationProposalTrayUiState(
    next?.ui && typeof next.ui === "object"
      ? {
          ...baseUi,
          ...next.ui,
        }
      : baseUi
  );
  if (nextUi.selectedProposalId) {
    const stillPresent = tray.slots.some((slot) => readFirstString(slot?.proposalId) === nextUi.selectedProposalId);
    if (!stillPresent) nextUi.selectedProposalId = selectableProposalId;
  } else {
    nextUi.selectedProposalId = selectableProposalId;
  }
  tray.ui = nextUi;
  state.communication.proposalTray = tray;
  if (render) {
    renderCommunicationChrome();
  }
  syncActiveTabReviewFlowState({ publish: true });
  if (dispatch) {
    dispatchJuggernautShellEvent(COMMUNICATION_PROPOSAL_TRAY_EVENT, {
      source,
      tray: buildCommunicationProposalTraySnapshot(),
      context: buildJuggernautShellContext(),
    });
  }
  if (shouldRequestRender) {
    requestRender();
  }
  return tray;
}

function setCommunicationProposalTrayUi(
  nextUi = {},
  {
    source = "review_runtime_ui",
    render = true,
    dispatch = true,
    requestRender: shouldRequestRender = false,
  } = {}
) {
  const tray = state.communication?.proposalTray || createFreshCommunicationState().proposalTray;
  const candidateSlots = Array.isArray(tray.slots) ? tray.slots : [];
  const selectableProposalId =
    candidateSlots.find((slot) => readFirstString(slot?.proposalId))?.proposalId || null;
  const mergedUi = normalizeCommunicationProposalTrayUiState({
    ...normalizeCommunicationProposalTrayUiState(tray.ui),
    ...(nextUi && typeof nextUi === "object" ? nextUi : {}),
  });
  if (mergedUi.selectedProposalId) {
    const stillPresent = candidateSlots.some((slot) => readFirstString(slot?.proposalId) === mergedUi.selectedProposalId);
    if (!stillPresent) mergedUi.selectedProposalId = selectableProposalId;
  } else {
    mergedUi.selectedProposalId = selectableProposalId;
  }
  tray.ui = mergedUi;
  state.communication.proposalTray = tray;
  if (render) {
    renderCommunicationProposalTray();
  }
  if (dispatch) {
    dispatchJuggernautShellEvent(COMMUNICATION_PROPOSAL_TRAY_EVENT, {
      source,
      tray: buildCommunicationProposalTraySnapshot(),
      context: buildJuggernautShellContext(),
    });
  }
  if (shouldRequestRender) {
    requestRender();
  }
  return tray;
}

function hideCommunicationProposalTray({ preserveAnchor = true, source = "ui" } = {}) {
  clearCommunicationProposalTrayDismissTimer();
  els.communicationProposalTray?.classList.remove("is-dismissing");
  const tray = state.communication.proposalTray || createFreshCommunicationState().proposalTray;
  tray.visible = false;
  clearCommunicationProposalTrayAnchorLock(tray);
  if (!preserveAnchor) {
    tray.anchor = null;
    tray.requestId = null;
  } else if (source === "communication_tray_close") {
    tray.requestId = null;
  }
  state.communication.proposalTray = tray;
  renderCommunicationChrome();
  syncActiveTabReviewFlowState({ publish: true });
  dispatchJuggernautShellEvent(COMMUNICATION_PROPOSAL_TRAY_EVENT, {
    source,
    tray: buildCommunicationProposalTraySnapshot(),
    context: buildJuggernautShellContext(),
  });
  requestRender();
}

function dismissCommunicationProposalTrayAfterReviewApply({
  requestId = null,
  preserveAnchor = false,
  delayMs = DESIGN_REVIEW_TRAY_DISMISS_MS,
} = {}) {
  const tray = els.communicationProposalTray;
  const activeRequestId = readFirstString(
    requestId,
    state.communication?.proposalTray?.requestId
  );
  if (!tray || !activeRequestId) return false;
  if (state.communication?.proposalTray?.visible === false) return false;
  if (readFirstString(state.communication?.proposalTray?.requestId) !== activeRequestId) return false;
  clearCommunicationProposalTrayDismissTimer();
  tray.classList.add("is-dismissing");
  communicationProposalTrayDismissTimer = window.setTimeout(() => {
    communicationProposalTrayDismissTimer = null;
    if (readFirstString(state.communication?.proposalTray?.requestId) !== activeRequestId) {
      tray.classList.remove("is-dismissing");
      return;
    }
    hideCommunicationProposalTray({
      preserveAnchor,
      source: "review_apply_success",
    });
  }, Math.max(0, Number(delayMs) || 0));
  return true;
}

function hydrateCommunicationProposalTrayMedia(root = els.communicationProposalTray) {
  const trayEl = root || els.communicationProposalTray;
  if (!trayEl?.querySelectorAll) return false;
  const media = Array.from(trayEl.querySelectorAll("img[data-review-image-path]"));
  for (const imgEl of media) {
    const path = readFirstString(imgEl?.dataset?.reviewImagePath);
    if (!path) continue;
    ensureImageUrl(path)
      .then((url) => {
        if (!url || !imgEl || readFirstString(imgEl?.dataset?.reviewImagePath) !== path) return;
        imgEl.src = url;
      })
      .catch(() => {});
  }
  return media.length > 0;
}

function renderCommunicationProposalTray() {
  const trayEl = els.communicationProposalTray;
  const listEl = els.communicationProposalSlotList;
  if (!trayEl || !listEl) return;
  const tray = buildCommunicationProposalTraySnapshot();
  const anchor = tray.anchor || resolveCommunicationReviewAnchor();
  const anchorCss = communicationAnchorCanvasCss(anchor);
  const visible = Boolean(tray.visible && anchorCss);
  trayEl.classList.toggle("hidden", !visible);
  if (!visible) {
    if (trayEl.dataset) {
      trayEl.dataset.anchorPlacement = "";
      trayEl.dataset.anchorKind = "";
    }
    return;
  }
  const traySource = String(tray.source || "").trim();
  const runtimeOwnsSlotList =
    trayEl.classList.contains("is-design-review-runtime") &&
    (
      traySource.startsWith("review_runtime") ||
      traySource === "design_review_bootstrap_state"
    );
  if (!runtimeOwnsSlotList) {
    const fragment = document.createDocumentFragment();
    for (const slot of tray.slots) {
      if (slot.status === "hidden") continue;
      const pending = communicationProposalSlotIsPending(slot.status);
      const card = document.createElement("div");
      card.className = `communication-proposal-slot ${pending ? "is-skeleton" : ""} ${slot.status === "failed" ? "is-failed" : ""}`.trim();
      card.dataset.slotIndex = String(slot.index);
      card.dataset.slotState = String(slot.status || "skeleton");
      card.setAttribute("role", "listitem");
      const eyebrow = document.createElement("div");
      eyebrow.className = "communication-proposal-slot-eyebrow";
      eyebrow.textContent = slot.label;
      const title = document.createElement("div");
      title.className = "communication-proposal-slot-title";
      title.textContent = slot.title;
      const copy = document.createElement("div");
      copy.className = "communication-proposal-slot-copy";
      copy.textContent = slot.copy;
      card.append(eyebrow, title, copy);
      fragment.append(card);
    }
    listEl.replaceChildren(fragment);
  }
  hydrateCommunicationProposalTrayMedia(trayEl);
  const positioned = positionCommunicationProposalTrayElement(trayEl, anchor, anchorCss);
  if (!positioned) {
    trayEl.style.left = `${Math.round(Number(anchorCss.x) || 0)}px`;
    trayEl.style.top = `${Math.round(Number(anchorCss.y) || 0)}px`;
  }
  if (trayEl.dataset) {
    trayEl.dataset.anchorKind = String(anchor?.kind || "").trim();
  }
  requestAnimationFrame(() => {
    if (trayEl.classList.contains("hidden")) return;
    hydrateCommunicationProposalTrayMedia(trayEl);
    positionCommunicationProposalTrayElement(trayEl, anchor, anchorCss);
  });
}

function renderCommunicationStampPicker() {
  const pickerEl = els.communicationStampPicker;
  const titleEl = els.communicationStampPickerTitle;
  const subtitleEl = els.communicationStampPickerSubtitle;
  const listEl = els.communicationStampIntentList;
  const customPanelEl = els.communicationStampCustomPanel;
  const customInputEl = els.communicationStampCustomInput;
  const pickerState = state.communication?.stampPicker || createFreshCommunicationStampPickerState();
  if (!pickerEl) return;
  const visible = Boolean(pickerState.visible && communicationToolId() === "stamp");
  pickerEl.classList.toggle("hidden", !visible);
  pickerEl.hidden = !visible;
  pickerEl.setAttribute("aria-hidden", visible ? "false" : "true");
  const selectedIntentId = selectedCommunicationStampIntentId(pickerState);
  const pickerMode = normalizeCommunicationStampPickerMode(pickerState?.pickerMode);
  const customMode = pickerMode === "custom_input";
  if (titleEl) {
    titleEl.textContent = customMode ? "Custom" : "Stamp";
  }
  if (subtitleEl) {
    subtitleEl.textContent = customMode ? "Type note" : "Choose";
  }
  if (pickerEl.dataset) {
    pickerEl.dataset.pickerMode = customMode ? "custom" : "intents";
  }
  if (listEl) {
    listEl.hidden = customMode;
    if (listEl.classList?.toggle) listEl.classList.toggle("hidden", customMode);
  }
  if (customPanelEl) {
    customPanelEl.hidden = !customMode;
    if (customPanelEl.classList?.toggle) customPanelEl.classList.toggle("hidden", !customMode);
  }
  const activeElement = typeof document !== "undefined" ? document.activeElement : null;
  if (customInputEl && customInputEl !== activeElement) {
    customInputEl.value = normalizeCommunicationStampCustomText(pickerState?.customText);
  }
  if (listEl && typeof listEl.querySelectorAll === "function") {
    for (const button of Array.from(listEl.querySelectorAll("[data-stamp-intent]"))) {
      const intentId = normalizeCommunicationStampIntentId(button.dataset?.stampIntent || "");
      const selected = Boolean(intentId && intentId === selectedIntentId);
      button.classList.toggle("is-selected", selected);
      button.setAttribute("aria-pressed", selected ? "true" : "false");
    }
  }
  if (!visible) {
    pickerEl.style.left = "-9999px";
    pickerEl.style.top = "-9999px";
    pickerEl.style.right = "auto";
    pickerEl.style.bottom = "auto";
    if (pickerEl.dataset) {
      pickerEl.dataset.anchorPlacement = "";
      pickerEl.dataset.pickerMode = customMode ? "custom" : "intents";
    }
    return;
  }
  const shellRect = els.communicationShell?.getBoundingClientRect?.() || pickerEl.parentElement?.getBoundingClientRect?.() || {
    left: 0,
    top: 0,
    width: Math.max(1, Number(els.communicationShell?.clientWidth) || 1),
    height: Math.max(1, Number(els.communicationShell?.clientHeight) || 1),
  };
  const viewportWidth =
    (typeof window !== "undefined" && Number(window.innerWidth)) ||
    Math.max(1, (typeof document !== "undefined" && Number(document.documentElement?.clientWidth)) || 1);
  const viewportHeight =
    (typeof window !== "undefined" && Number(window.innerHeight)) ||
    Math.max(1, (typeof document !== "undefined" && Number(document.documentElement?.clientHeight)) || 1);
  const width = Math.max(144, Number(pickerEl.offsetWidth) || 168);
  const height = Math.max(144, Number(pickerEl.offsetHeight) || 168);
  let anchorViewportX = Number(shellRect.left || 0) + Math.max(0, Math.round((Number(shellRect.width || 0) || width) * 0.5));
  let anchorViewportY = Number(shellRect.top || 0) + 20;
  if (pickerState.anchorFrame === "canvas" && pickerState.anchorCss && els.canvasWrap?.getBoundingClientRect) {
    const wrapRect = els.canvasWrap.getBoundingClientRect();
    const anchorCss = clampCanvasCssPoint(pickerState.anchorCss);
    anchorViewportX = Number(wrapRect.left || 0) + Number(anchorCss.x || 0);
    anchorViewportY = Number(wrapRect.top || 0) + Number(anchorCss.y || 0);
  } else if (pickerState.anchorCss) {
    anchorViewportX = Number(shellRect.left || 0) + Number(pickerState.anchorCss.x || 0);
    anchorViewportY = Number(shellRect.top || 0) + Number(pickerState.anchorCss.y || 0);
  } else if (els.communicationToolStamp?.getBoundingClientRect) {
    const buttonRect = els.communicationToolStamp.getBoundingClientRect();
    anchorViewportX = Number(buttonRect.left || 0) + Number(buttonRect.width || 0) * 0.5;
    anchorViewportY = Number(buttonRect.top || 0);
  }
  const horizontalGap = 12;
  let anchorPlacement = "right";
  let viewportLeft = anchorViewportX + horizontalGap;
  if (viewportLeft + width > viewportWidth - 12) {
    anchorPlacement = "left";
    viewportLeft = anchorViewportX - width - horizontalGap;
  }
  viewportLeft = clamp(viewportLeft, 12, Math.max(12, viewportWidth - width - 12));
  const viewportTop = clamp(anchorViewportY - height * 0.5, 12, Math.max(12, viewportHeight - height - 12));
  pickerEl.style.left = `${viewportLeft - Number(shellRect.left || 0)}px`;
  pickerEl.style.top = `${viewportTop - Number(shellRect.top || 0)}px`;
  pickerEl.style.right = "auto";
  pickerEl.style.bottom = "auto";
  if (pickerEl.dataset) {
    pickerEl.dataset.anchorPlacement = anchorPlacement;
  }
}

function renderCommunicationChrome() {
  renderCommunicationRail();
  renderCommunicationStampPicker();
  renderCommunicationProposalTray();
  syncCommunicationCanvasCursor();
  if (typeof window !== "undefined") {
    syncJuggernautShellState();
  }
}

function syncCommunicationProposalTrayFromReviewState(reviewState = {}, { source = "review_runtime_state" } = {}) {
  suppressBootstrapDesignReviewTray();
  const tray = state.communication?.proposalTray || createFreshCommunicationState().proposalTray;
  if (!tray.visible && !tray.requestId) return null;
  const normalizedState = reviewState && typeof reviewState === "object" ? reviewState : {};
  const rawSlots = Array.isArray(normalizedState.slots) ? normalizedState.slots : [];
  const rawStatus = String(normalizedState.status || "").trim().toLowerCase();
  if (!rawSlots.length && !rawStatus) return null;
  if (!rawSlots.length && rawStatus === "idle") return null;
  return setCommunicationProposalTray(
    {
      visible: true,
      requestId: tray.requestId || null,
      source,
      anchor: tray.anchor || resolveCommunicationReviewAnchor(),
      slots: buildCommunicationProposalSlotsFromReviewState(normalizedState),
    },
    { source }
  );
}

function requestCommunicationDesignReview({ source = "titlebar" } = {}) {
  const reviewAnchor = resolveCommunicationReviewAnchor();
  if (!reviewAnchor) {
    showToast("Add a mark, stamp, or Magic Select region first.", "tip", 1800);
    return { ok: false, reason: "missing_anchor" };
  }
  const pinToTitlebar = shouldPinCommunicationReviewTrayToTitlebar(source);
  const trayAnchor = pinToTitlebar ? designReviewButtonTrayAnchor() || reviewAnchor : reviewAnchor;
  suppressBootstrapDesignReviewTray();
  const now = Date.now();
  const tray = state.communication.proposalTray || createFreshCommunicationState().proposalTray;
  const lastRequestedAt = Number(state.communication.lastReviewRequestedAt) || 0;
  const activeRequestId = tray.requestId ? String(tray.requestId) : null;
  if (tray.visible && activeRequestId && now - lastRequestedAt < 450) {
    const payload = buildCommunicationReviewPayload({ requestId: activeRequestId, source });
    return { ok: true, requestId: activeRequestId, payload, deduped: true };
  }
  state.communication.lastReviewRequestedAt = now;
  const requestId = `design-review-${Date.now()}-${Math.max(1, ++state.communication.reviewRequestSeq)}`;
  const silentPrime = pinToTitlebar;
  setCommunicationProposalTray(
    {
      visible: true,
      requestId,
      source,
      anchor: trayAnchor,
      slots: buildCommunicationReviewPendingSlots({ overallStatus: "preparing" }),
    },
    {
      source,
      render: !silentPrime,
      dispatch: !silentPrime,
      requestRender: !silentPrime,
    }
  );
  const payload = buildCommunicationReviewPayload({ requestId, source });
  dispatchJuggernautShellEvent(COMMUNICATION_REVIEW_REQUESTED_EVENT, {
    requestId,
    source,
    communication: payload.communication,
    context: payload,
  });
  return { ok: true, requestId, payload, deduped: false };
}

function suppressNextDesignReviewTitlebarClick() {
  const button = els.sessionTabDesignReview;
  if (!button) return;
  button.disabled = true;
  setTimeout(() => {
    if (!els.sessionTabDesignReview) return;
    els.sessionTabDesignReview.disabled = false;
  }, 0);
}

function startBootstrapDesignReview(request = null, { source = "titlebar" } = {}) {
  const bridge = typeof window !== "undefined" ? window.__JUGGERNAUT_REVIEW__ : null;
  if (!bridge || typeof bridge.startReviewFromShell !== "function") return false;
  Promise.resolve()
    .then(() => bridge.startReviewFromShell())
    .catch((error) => {
      console.error(`${EDIT_PROPOSALS_LABEL} bootstrap failed:`, error);
      const detail = normalizeErrorMessage(error, `${EDIT_PROPOSALS_LABEL} failed to start.`);
      setCommunicationProposalTray(
        {
          visible: true,
          requestId: request?.requestId ? String(request.requestId) : state.communication?.proposalTray?.requestId || null,
          source: `${source}_bridge_failed`,
          anchor: state.communication?.proposalTray?.anchor || resolveCommunicationReviewAnchor(),
          slots: Array.from({ length: COMMUNICATION_PROPOSAL_SLOT_COUNT }, (_, index) =>
            createCommunicationProposalSlot(index, index === 0
              ? {
                  status: "failed",
                  title: "Review failed",
                  copy: detail,
                }
              : { status: "hidden" })
          ),
        },
        { source: `${source}_bridge_failed` }
      );
    });
  return true;
}

function triggerCommunicationDesignReviewFromTitlebar({ source = "titlebar" } = {}) {
  const request = requestCommunicationDesignReview({ source });
  if (!request?.ok || request?.deduped) return request;
  startBootstrapDesignReview(request, { source });
  return request;
}

function bindCommunicationReviewBootstrapBridge() {
  if (communicationReviewBootstrapBridgeBound || typeof window === "undefined") return;
  communicationReviewBootstrapBridgeBound = true;
  window.addEventListener(DESIGN_REVIEW_BOOTSTRAP_STATE_EVENT, (event) => {
    syncCommunicationProposalTrayFromReviewState(event?.detail || null, {
      source: "design_review_bootstrap_state",
    });
  });
}

function currentDesignReviewApplySessionKey() {
  const tabId = readFirstString(state.activeTabId);
  if (tabId) return `tab:${tabId}`;
  const runDir = readFirstString(state.runDir);
  if (runDir) return `run:${runDir}`;
  return "";
}

function designReviewApplyActionLabel(detail = {}) {
  return readFirstString(detail?.proposal?.label, detail?.proposal?.actionType) || "Apply Proposal";
}

function normalizeDesignReviewApplyEventDetail(detail = {}, { fallbackState = null, status = "" } = {}) {
  const record = asRecord(detail) || {};
  const fallback = cloneDesignReviewApplyState(fallbackState);
  const parseApplyEventTimestamp = (...values) => {
    for (const value of values) {
      if (value == null || value === "") continue;
      const numeric = Number(value);
      if (Number.isFinite(numeric) && numeric > 0) return numeric;
      const parsed = Date.parse(String(value));
      if (Number.isFinite(parsed) && parsed > 0) return parsed;
    }
    return 0;
  };
  const proposal =
    asRecord(record.proposal)
      ? cloneToolRuntimeValue(record.proposal)
      : fallback.proposal
        ? cloneToolRuntimeValue(fallback.proposal)
        : null;
  const request =
    asRecord(record.request)
      ? cloneToolRuntimeValue(record.request)
      : asRecord(record.requestSnapshot)
        ? cloneToolRuntimeValue(record.requestSnapshot)
        : fallback.request
          ? cloneToolRuntimeValue(fallback.request)
          : null;
  const sessionKey =
    readFirstString(
      record.sessionKey,
      record.session_id,
      request?.sessionId,
      fallback.sessionKey,
      currentDesignReviewApplySessionKey()
    ) || null;
  const tabId =
    readFirstString(
      record.tabId,
      record.tab_id,
      record.activeTabId,
      record.active_tab_id,
      sessionKey && sessionKey.startsWith("tab:") ? sessionKey.slice(4) : "",
      fallback.tabId
    ) || null;
  const targetImageId =
    readFirstString(
      record.targetImageId,
      record.target_image_id,
      proposal?.imageId,
      request?.primaryImageId,
      fallback.targetImageId
    ) || null;
  const explicitReferenceImageIds = uniqueStringList(
    [
      ...(Array.isArray(record.referenceImageIds) ? record.referenceImageIds : []),
      ...(Array.isArray(record.reference_image_ids) ? record.reference_image_ids : []),
      ...((Array.isArray(record.referenceImages) ? record.referenceImages : []).map((image) =>
        readFirstString(image?.imageId, image?.image_id, image?.id)
      )),
    ],
    { exclude: [targetImageId] }
  );
  const fallbackReferenceImageIds = uniqueStringList(
    Array.isArray(fallback.referenceImageIds) ? fallback.referenceImageIds : [],
    { exclude: [targetImageId] }
  );
  const requestReferenceImageIds = uniqueStringList(
    [
      ...(Array.isArray(request?.selectedImageIds) ? request.selectedImageIds : []),
      ...(Array.isArray(request?.imageIdsInView) ? request.imageIdsInView : []),
      ...((Array.isArray(request?.visibleCanvasContext?.images) ? request.visibleCanvasContext.images : []).map((image) =>
        readFirstString(image?.imageId, image?.image_id, image?.id)
      )),
      ...((Array.isArray(request?.images) ? request.images : []).map((image) =>
        readFirstString(image?.imageId, image?.image_id, image?.id)
      )),
    ],
    { exclude: [targetImageId] }
  );
  const referenceImageIds =
    explicitReferenceImageIds.length > 0
      ? explicitReferenceImageIds
      : fallbackReferenceImageIds.length > 0
        ? fallbackReferenceImageIds
        : requestReferenceImageIds;
  const debugInfo =
    asRecord(record.debugInfo)
      ? cloneToolRuntimeValue(record.debugInfo)
      : asRecord(record.debug_info)
        ? cloneToolRuntimeValue(record.debug_info)
        : fallback.debugInfo
          ? cloneToolRuntimeValue(fallback.debugInfo)
          : null;
  const selectedProposalId =
    readFirstString(
      record.selectedProposalId,
      record.selected_proposal_id,
      record.proposalId,
      record.proposal_id,
      proposal?.proposalId,
      proposal?.id,
      fallback.selectedProposalId
    ) || null;
  return {
    ...fallback,
    status: readFirstString(status, record.status, fallback.status) || "idle",
    sessionKey,
    tabId,
    requestId:
      readFirstString(
        record.requestId,
        record.request_id,
        request?.requestId,
        fallback.requestId,
        state.communication?.proposalTray?.requestId
      ) || null,
    proposalId:
      readFirstString(record.proposalId, record.proposal_id, proposal?.proposalId, proposal?.id, fallback.proposalId) || null,
    selectedProposalId,
    targetImageId,
    referenceImageIds,
    previewImagePath:
      readFirstString(
        record.previewImagePath,
        record.preview_image_path,
        proposal?.previewImagePath,
        proposal?.preview_image_path,
        fallback.previewImagePath
      ) || null,
    changedRegionBounds:
      asRecord(record.changedRegionBounds)
        ? cloneToolRuntimeValue(record.changedRegionBounds)
        : asRecord(record.changed_region_bounds)
          ? cloneToolRuntimeValue(record.changed_region_bounds)
          : asRecord(proposal?.changedRegionBounds)
            ? cloneToolRuntimeValue(proposal.changedRegionBounds)
            : asRecord(proposal?.changed_region_bounds)
              ? cloneToolRuntimeValue(proposal.changed_region_bounds)
              : fallback.changedRegionBounds
                ? cloneToolRuntimeValue(fallback.changedRegionBounds)
                : null,
    preserveRegionIds: uniqueStringList([
      ...(Array.isArray(record.preserveRegionIds) ? record.preserveRegionIds : []),
      ...(Array.isArray(record.preserve_region_ids) ? record.preserve_region_ids : []),
      ...(Array.isArray(proposal?.preserveRegionIds) ? proposal.preserveRegionIds : []),
      ...(Array.isArray(proposal?.preserve_region_ids) ? proposal.preserve_region_ids : []),
      ...(Array.isArray(fallback.preserveRegionIds) ? fallback.preserveRegionIds : []),
    ]),
    rationaleCodes: uniqueStringList([
      ...(Array.isArray(record.rationaleCodes) ? record.rationaleCodes : []),
      ...(Array.isArray(record.rationale_codes) ? record.rationale_codes : []),
      ...(Array.isArray(proposal?.rationaleCodes) ? proposal.rationaleCodes : []),
      ...(Array.isArray(proposal?.rationale_codes) ? proposal.rationale_codes : []),
      ...(Array.isArray(fallback.rationaleCodes) ? fallback.rationaleCodes : []),
    ]),
    outputPath: readFirstString(record.outputPath, record.output_path, fallback.outputPath) || null,
    error: readFirstString(record.error, record.failureReason, record.failure_reason, fallback.error) || null,
    startedAt: parseApplyEventTimestamp(record.startedAt, fallback.startedAt, Date.now()),
    completedAt: parseApplyEventTimestamp(record.completedAt, fallback.completedAt, Date.now()),
    proposal,
    request,
    debugInfo,
    provider:
      readFirstString(record.provider, debugInfo?.provider, debugInfo?.route?.provider, fallback.provider) || null,
    requestedModel:
      readFirstString(
        record.requestedModel,
        record.requested_model,
        record.model,
        debugInfo?.requestedModel,
        debugInfo?.providerRequest?.model,
        fallback.requestedModel
      ) || null,
    normalizedModel:
      readFirstString(
        record.normalizedModel,
        record.normalized_model,
        debugInfo?.normalizedModel,
        debugInfo?.route?.normalizedModel,
        fallback.normalizedModel
      ) || null,
    costTotalUsd: readFirstNumber(record.costTotalUsd, record.cost_total_usd, fallback.costTotalUsd),
    latencyPerImageS: readFirstNumber(record.latencyPerImageS, record.latency_per_image_s, fallback.latencyPerImageS),
  };
}

function sessionTabHasRunningReviewApply(record = null) {
  const session = record?.session && typeof record.session === "object" ? record.session : null;
  if (readFirstString(record?.designReviewApply?.status, session?.designReviewApply?.status).toLowerCase() === "running") {
    return true;
  }
  return (
    normalizeSessionTabReviewFlowState(record?.reviewFlowState) === "applying" ||
    normalizeSessionTabReviewFlowState(session?.reviewFlowState) === "applying"
  );
}

function ensureSessionTabRecordSession(record = null) {
  if (!record || typeof record !== "object") return null;
  if (!record.session || typeof record.session !== "object") {
    record.session = createFreshTabSession({
      runDir: record.runDir || null,
      eventsPath: record.eventsPath || null,
    });
  }
  return record.session;
}

function buildSessionTabUiMeta(session = null, existing = null, { bumpVersions = false } = {}) {
  const current = session && typeof session === "object" ? session : createFreshTabSession();
  const previous = normalizeTabUiMeta(existing);
  const images = Array.isArray(current.images) ? current.images : [];
  const toolCount = Array.isArray(current.sessionTools) ? current.sessionTools.length : 0;
  const timelineCount = Array.isArray(current.timelineNodes) ? current.timelineNodes.length : 0;
  const activeImage = current.activeId ? current.imagesById?.get?.(current.activeId) || null : null;
  const bump = bumpVersions ? 1 : 0;
  return {
    metadataVersion: previous.metadataVersion + bump,
    filmstripVersion: previous.filmstripVersion + bump,
    timelineVersion: previous.timelineVersion + bump,
    spawnVersion: previous.spawnVersion + bump,
    quickActionsVersion: previous.quickActionsVersion + bump,
    customToolDockVersion: previous.customToolDockVersion,
    imageCount: images.length,
    toolCount,
    timelineCount,
    isDirty: images.length > 0 || toolCount > 0 || timelineCount > 0,
    thumbnailPath: activeImage?.path || images[0]?.path || null,
  };
}

function syncSessionTabRecordFromSession(
  record = null,
  {
    publish = true,
    bumpVersions = false,
    busy = null,
    reviewFlowState = null,
  } = {}
) {
  if (!record || typeof record !== "object") return null;
  const session = ensureSessionTabRecordSession(record);
  if (!session) return null;
  const nextReviewFlowState = normalizeSessionTabReviewFlowState(
    reviewFlowState == null
      ? currentSessionTabReviewFlowState({
          communication: session.communication,
          designReviewApply: session.designReviewApply,
        })
      : reviewFlowState
  );
  const nextMeta = buildSessionTabUiMeta(session, record.tabUiMeta || session.tabUiMeta, {
    bumpVersions,
  });
  session.tabUiMeta = { ...nextMeta };
  record.tabUiMeta = nextMeta;
  record.runDir = session.runDir || record.runDir || null;
  if (!record.labelManual) {
    record.label = automaticSessionTabLabel({
      images: session.images,
      activeId: session.activeId,
      runDir: record.runDir,
      fallback: DEFAULT_UNTITLED_TAB_TITLE,
    });
  } else {
    record.label = normalizeSessionTabTitleInput(record.label, SESSION_TAB_TITLE_MAX_LENGTH) || DEFAULT_UNTITLED_TAB_TITLE;
  }
  session.label = record.label;
  session.labelManual = Boolean(record.labelManual);
  session.reviewFlowState = nextReviewFlowState;
  record.reviewFlowState = nextReviewFlowState;
  if (typeof busy === "boolean") {
    record.busy = busy;
  }
  record.thumbnailPath = nextMeta.thumbnailPath;
  record.updatedAt = Date.now();
  if (publish) {
    tabbedSessions.upsertTab({ ...record }, { activate: false });
  }
  return record;
}

function designReviewApplyEventMatchesTabRecord(record = null, detail = {}, fallbackState = null) {
  const normalized = cloneDesignReviewApplyState(detail);
  const fallback = cloneDesignReviewApplyState(fallbackState);
  const session = record?.session && typeof record.session === "object" ? record.session : null;
  const recordTabId = readFirstString(record?.tabId);
  const recordSessionKey = readFirstString(
    session?.designReviewApply?.sessionKey,
    recordTabId ? `tab:${recordTabId}` : "",
    record?.runDir ? `run:${record.runDir}` : ""
  );
  if (normalized.sessionKey && recordSessionKey && normalized.sessionKey !== recordSessionKey) return false;
  if (normalized.tabId && recordTabId && normalized.tabId !== recordTabId) return false;
  if (fallback.sessionKey && normalized.sessionKey && fallback.sessionKey !== normalized.sessionKey) return false;
  if (fallback.requestId && normalized.requestId && fallback.requestId !== normalized.requestId) return false;
  if (
    fallback.selectedProposalId &&
    normalized.selectedProposalId &&
    fallback.selectedProposalId !== normalized.selectedProposalId
  ) {
    return false;
  }
  if (!fallback.selectedProposalId && fallback.proposalId && normalized.proposalId && fallback.proposalId !== normalized.proposalId) {
    return false;
  }
  if (fallback.tabId && normalized.tabId && fallback.tabId !== normalized.tabId) return false;
  return true;
}

function resolveDesignReviewApplyTargetRecord(detail = {}, fallbackState = null) {
  let normalized = normalizeDesignReviewApplyEventDetail(detail, { fallbackState });
  let record = null;
  for (const candidateTabId of uniqueStringList([
    normalized.tabId,
    normalized.sessionKey?.startsWith?.("tab:") ? normalized.sessionKey.slice(4) : "",
  ])) {
    record = tabbedSessions.getTab(candidateTabId) || null;
    if (record) break;
  }
  if (!record) {
    const requestId = readFirstString(normalized.requestId);
    const sessionKey = readFirstString(normalized.sessionKey);
    const runDirFromSessionKey = sessionKey.startsWith("run:") ? sessionKey.slice(4) : "";
    for (const tabId of tabbedSessions.tabsOrder) {
      const candidate = tabbedSessions.getTab(tabId) || null;
      const session = candidate?.session && typeof candidate.session === "object" ? candidate.session : null;
      const sessionApply = cloneDesignReviewApplyState(session?.designReviewApply);
      const candidateRequestId = readFirstString(sessionApply.requestId, session?.communication?.proposalTray?.requestId);
      const candidateSessionKey = readFirstString(
        sessionApply.sessionKey,
        candidate?.tabId ? `tab:${candidate.tabId}` : "",
        candidate?.runDir ? `run:${candidate.runDir}` : ""
      );
      const candidateRunDir = readFirstString(session?.runDir, candidate?.runDir);
      if (requestId && candidateRequestId && requestId === candidateRequestId) {
        record = candidate;
        break;
      }
      if (sessionKey && candidateSessionKey && sessionKey === candidateSessionKey) {
        record = candidate;
        break;
      }
      if (runDirFromSessionKey && candidateRunDir && runDirFromSessionKey === candidateRunDir) {
        record = candidate;
        break;
      }
    }
  }
  const session = record ? ensureSessionTabRecordSession(record) : null;
  if (record && session && String(record.tabId || "").trim() !== String(state.activeTabId || "").trim()) {
    const sessionFallback = cloneDesignReviewApplyState(session.designReviewApply);
    if (sessionFallback.requestId || sessionFallback.sessionKey || sessionFallback.tabId) {
      normalized = normalizeDesignReviewApplyEventDetail(detail, {
        fallbackState: sessionFallback,
        status: normalized.status,
      });
    }
  }
  return {
    normalized,
    record,
    session,
    isActive: Boolean(record && String(record.tabId || "").trim() === String(state.activeTabId || "").trim()),
  };
}

function designReviewApplyEventMatchesActiveTab(detail = {}, fallbackState = null) {
  const normalized = cloneDesignReviewApplyState(detail);
  const fallback = cloneDesignReviewApplyState(fallbackState);
  const activeSessionKey = currentDesignReviewApplySessionKey();
  const activeTabId = readFirstString(state.activeTabId) || null;
  if (normalized.sessionKey && activeSessionKey && normalized.sessionKey !== activeSessionKey) return false;
  if (normalized.tabId && activeTabId && normalized.tabId !== activeTabId) return false;
  if (fallback.sessionKey && normalized.sessionKey && fallback.sessionKey !== normalized.sessionKey) return false;
  if (fallback.requestId && normalized.requestId && fallback.requestId !== normalized.requestId) return false;
  if (
    fallback.selectedProposalId &&
    normalized.selectedProposalId &&
    fallback.selectedProposalId !== normalized.selectedProposalId
  ) {
    return false;
  }
  if (!fallback.selectedProposalId && fallback.proposalId && normalized.proposalId && fallback.proposalId !== normalized.proposalId) {
    return false;
  }
  return true;
}

function setDesignReviewApplyState(nextState = null, { capture = true, publish = true } = {}) {
  state.designReviewApply = cloneDesignReviewApplyState(nextState);
  syncActiveTabRecord({ capture, publish });
  syncJuggernautShellState();
  renderQuickActions();
  renderHudReadout();
  return state.designReviewApply;
}

function clearDesignReviewApplyState({ capture = true, publish = true } = {}) {
  return setDesignReviewApplyState(createFreshDesignReviewApplyState(), { capture, publish });
}

function markDesignReviewApplyRunning(detail = {}) {
  const resolved = resolveDesignReviewApplyTargetRecord(detail, state.designReviewApply);
  if (!resolved.record) return false;
  if (!resolved.isActive) {
    return markDesignReviewApplyRunningInSessionRecord(resolved.record, detail);
  }
  const previous = cloneDesignReviewApplyState(state.designReviewApply);
  const normalized = normalizeDesignReviewApplyEventDetail(detail, {
    fallbackState: previous,
    status: "running",
  });
  if (!designReviewApplyEventMatchesActiveTab(normalized, previous)) return false;
  normalized.completedAt = 0;
  setDesignReviewApplyState(normalized, { capture: true, publish: true });
  syncActiveTabReviewFlowState({ publish: true });
  setStatus("Engine: applying accepted review…");
  requestRender();
  return true;
}

function updateDesignReviewApplyCostLatency(detail = {}) {
  const provider = readFirstString(detail.provider) || null;
  const model = readFirstString(detail.normalizedModel, detail.requestedModel) || null;
  const costTotalUsd = readFirstNumber(detail.costTotalUsd);
  const latencyPerImageS = readFirstNumber(detail.latencyPerImageS);
  if (!provider && !model && costTotalUsd == null && latencyPerImageS == null) return false;
  state.lastCostLatency = {
    provider,
    model,
    cost_total_usd: costTotalUsd,
    cost_per_1k_images_usd: null,
    latency_per_image_s: latencyPerImageS,
    at: Date.now(),
  };
  return true;
}

function updateDesignReviewApplyCostLatencyForSession(session = null, detail = {}) {
  const current = session && typeof session === "object" ? session : null;
  if (!current) return false;
  const provider = readFirstString(detail.provider) || null;
  const model = readFirstString(detail.normalizedModel, detail.requestedModel) || null;
  const costTotalUsd = readFirstNumber(detail.costTotalUsd);
  const latencyPerImageS = readFirstNumber(detail.latencyPerImageS);
  if (!provider && !model && costTotalUsd == null && latencyPerImageS == null) return false;
  current.lastCostLatency = {
    provider,
    model,
    cost_total_usd: costTotalUsd,
    cost_per_1k_images_usd: null,
    latency_per_image_s: latencyPerImageS,
    at: Date.now(),
  };
  return true;
}

function recordTimelineNodeInSession(
  session = null,
  {
    imageId,
    path,
    receiptPath = null,
    label = null,
    action = null,
    kind = null,
    detail = null,
    visualMode = null,
    parents = null,
    previewImageId = null,
    previewPath = null,
    receiptPaths = null,
  } = {}
) {
  const current = session && typeof session === "object" ? session : null;
  if (!current) return null;
  const node = buildTimelineNodeForSession(current, {
    imageId,
    path,
    receiptPath,
    label,
    action,
    kind,
    detail,
    visualMode,
    parents,
    previewImageId,
    previewPath,
    receiptPaths,
  });
  return applyTimelineNodeToSession(current, node, imageId);
}

function replaceImageInSessionRecord(
  session = null,
  targetId,
  { path, receiptPath = null, kind = null, label = null, clearVision = true } = {}
) {
  const current = session && typeof session === "object" ? session : null;
  const item = current?.imagesById?.get?.(targetId) || null;
  if (!item || !path) return false;
  const oldPath = item.path;
  if (oldPath && oldPath !== path) {
    invalidateImageCache(oldPath);
    dropVisionDescribePath(oldPath, { cancelInFlight: true });
  }
  invalidateImageCache(path);
  item.path = path;
  item.receiptPath = receiptPath;
  item.receiptMeta = null;
  item.receiptMetaChecked = false;
  item.receiptMetaLoading = false;
  if (kind) item.kind = kind;
  const explicitLabel = typeof label === "string" ? label.trim() : "";
  if (explicitLabel) {
    item.label = explicitLabel;
  } else if (path && oldPath && oldPath !== path) {
    const oldPathLabel = basename(oldPath || "");
    const nextPathLabel = basename(path || "");
    const currentLabel = String(item.label || "").trim();
    if (!currentLabel || (oldPathLabel && currentLabel === oldPathLabel)) {
      if (nextPathLabel) item.label = nextPathLabel;
    }
  }
  item.img = null;
  item.width = null;
  item.height = null;
  if (current.communication?.regionProposalsByImageId instanceof Map) {
    current.communication.regionProposalsByImageId.delete(String(targetId || "").trim());
    if (String(current.communication?.lastAnchor?.imageId || "").trim() === String(targetId || "").trim()) {
      current.communication.lastAnchor = null;
    }
  }
  if (clearVision) {
    item.visionDesc = null;
    item.visionPending = false;
    if (state.describePendingPath === oldPath) state.describePendingPath = null;
  }
  return true;
}

function removeImageFromSessionRecord(session = null, imageId = "") {
  const current = session && typeof session === "object" ? session : null;
  const normalizedImageId = String(imageId || "").trim();
  if (!current || !normalizedImageId) return false;
  if (!current.imagesById?.has?.(normalizedImageId)) return false;
  current.imagesById.delete(normalizedImageId);
  current.images = (Array.isArray(current.images) ? current.images : []).filter(
    (item) => String(item?.id || "").trim() !== normalizedImageId
  );
  if (current.circlesByImageId instanceof Map) {
    current.circlesByImageId.delete(normalizedImageId);
  }
  if (current.freeformRects instanceof Map) {
    current.freeformRects.delete(normalizedImageId);
  }
  if (current.multiRects instanceof Map) {
    current.multiRects.delete(normalizedImageId);
  }
  current.freeformZOrder = (Array.isArray(current.freeformZOrder) ? current.freeformZOrder : []).filter(
    (value) => String(value || "").trim() !== normalizedImageId
  );
  current.selectedIds = (Array.isArray(current.selectedIds) ? current.selectedIds : []).filter(
    (value) => String(value || "").trim() !== normalizedImageId
  );
  if (String(current.activeId || "").trim() === normalizedImageId) {
    current.activeId = current.selectedIds[current.selectedIds.length - 1] || current.images[current.images.length - 1]?.id || null;
  }
  return true;
}

function clearVisibleCommunicationReviewStateForSession(session = null, { hideTray = true } = {}) {
  const current = session && typeof session === "object" ? session : null;
  if (!current) return null;
  const communication =
    current.communication && typeof current.communication === "object"
      ? current.communication
      : createFreshCommunicationState();
  communication.markDraft = null;
  communication.eraseDraft = null;
  communication.stampPicker = createFreshCommunicationStampPickerState();
  communication.marksByImageId = new Map();
  communication.canvasMarks = [];
  communication.stampsByImageId = new Map();
  communication.canvasStamps = [];
  communication.regionProposalsByImageId = new Map();
  communication.lastAnchor = null;
  if (hideTray) {
    const tray =
      communication.proposalTray && typeof communication.proposalTray === "object"
        ? communication.proposalTray
        : createFreshCommunicationState().proposalTray;
    tray.visible = false;
    tray.requestId = null;
    tray.anchor = null;
    communication.proposalTray = tray;
  }
  current.communication = communication;
  return communication;
}

function reviewApplyShouldPreserveCommunicationTool(toolId = "") {
  return readFirstString(toolId) === "magic_select";
}

function designReviewApplyRequestUsesMagicSelect(request = null) {
  const record = asRecord(request) || {};
  if (readFirstString(record.reviewTool).toLowerCase() === "magic_select") return true;
  const communicationReview = asRecord(record.communicationReview) || {};
  if (readFirstString(communicationReview.tool).toLowerCase() === "magic_select") return true;
  const candidates = [];
  if (asRecord(record.chosenRegionCandidate)) candidates.push(record.chosenRegionCandidate);
  if (Array.isArray(record.regionCandidates)) candidates.push(...record.regionCandidates);
  const regionSelections = Array.isArray(communicationReview.regionSelections) ? communicationReview.regionSelections : [];
  for (const selection of regionSelections) {
    if (asRecord(selection?.chosenRegionCandidate)) candidates.push(selection.chosenRegionCandidate);
    if (Array.isArray(selection?.candidates)) candidates.push(...selection.candidates);
    candidates.push(selection);
  }
  if (candidates.some((candidate) => readFirstString(candidate?.source).toLowerCase() === "magic_select")) {
    return true;
  }
  const activeRegionCandidateId = readFirstString(record.activeRegionCandidateId);
  if (activeRegionCandidateId) return true;
  if (readFirstString(record.selectionState).toLowerCase() === "region" && asRecord(record.chosenRegionCandidate)) {
    return true;
  }
  return false;
}

function designReviewApplyProposalUsesMagicSelect(proposal = null) {
  const record = asRecord(proposal) || {};
  const targetRegion = asRecord(record.targetRegion) || asRecord(record.target_region) || {};
  if (readFirstString(targetRegion.regionCandidateId, targetRegion.region_candidate_id)) return true;
  if (asRecord(record.chosenRegionCandidate) && readFirstString(record.chosenRegionCandidate?.source).toLowerCase() === "magic_select") {
    return true;
  }
  return false;
}

function resolveReviewApplyCommunicationTool(currentTool = "", detail = {}) {
  if (reviewApplyShouldPreserveCommunicationTool(currentTool)) return "magic_select";
  if (designReviewApplyRequestUsesMagicSelect(detail?.request)) return "magic_select";
  if (designReviewApplyProposalUsesMagicSelect(detail?.proposal)) return "magic_select";
  return null;
}

function markSessionCommunicationProposalTrayApplyFailed(session = null, detail = {}, message = "Review apply failed.") {
  const current = session && typeof session === "object" ? session : null;
  if (!current) return null;
  const communication =
    current.communication && typeof current.communication === "object"
      ? current.communication
      : createFreshCommunicationState();
  const tray =
    communication.proposalTray && typeof communication.proposalTray === "object"
      ? communication.proposalTray
      : createFreshCommunicationState().proposalTray;
  const slots = Array.isArray(tray.slots)
    ? tray.slots.map((slot) => ({ ...slot }))
    : Array.from({ length: COMMUNICATION_PROPOSAL_SLOT_COUNT }, (_, index) => createCommunicationProposalSlot(index, {}));
  const normalizedProposalId = readFirstString(
    detail?.selectedProposalId,
    detail?.selected_proposal_id,
    detail?.proposalId,
    detail?.proposal?.proposalId,
    detail?.proposal?.id
  );
  let applied = false;
  for (let index = 0; index < slots.length; index += 1) {
    const slot = slots[index] || {};
    const slotProposalId = readFirstString(slot?.proposalId, slot?.proposal?.proposalId, slot?.proposal?.id);
    const slotStatus = normalizeCommunicationProposalSlotStatus(slot?.status || "");
    if (normalizedProposalId && slotProposalId && normalizedProposalId !== slotProposalId) continue;
    if (slotStatus === "apply_running" || (!normalizedProposalId && !applied)) {
      slots[index] = createCommunicationProposalSlot(index, {
        ...slot,
        status: "apply_failed",
        copy: clampText(message, 120),
      });
      applied = true;
      break;
    }
  }
  if (!applied && slots.length) {
    slots[0] = createCommunicationProposalSlot(0, {
      ...slots[0],
      status: "apply_failed",
      copy: clampText(message, 120),
    });
  }
  tray.visible = true;
  tray.requestId = readFirstString(detail?.requestId, tray.requestId) || null;
  tray.slots = slots;
  communication.proposalTray = tray;
  current.communication = communication;
  return tray;
}

function markDesignReviewApplyRunningInSessionRecord(record = null, detail = {}) {
  const session = ensureSessionTabRecordSession(record);
  if (!session) return false;
  const previous = cloneDesignReviewApplyState(session.designReviewApply);
  const normalized = normalizeDesignReviewApplyEventDetail(detail, {
    fallbackState: previous,
    status: "running",
  });
  if (!designReviewApplyEventMatchesTabRecord(record, normalized, previous)) return false;
  normalized.completedAt = 0;
  session.designReviewApply = normalized;
  session.lastStatusText = "Engine: applying accepted review…";
  session.lastStatusError = false;
  syncSessionTabRecordFromSession(record, {
    publish: true,
    bumpVersions: false,
    busy: true,
    reviewFlowState: "applying",
  });
  return true;
}

async function applyAcceptedDesignReviewOutputToSessionRecord(record = null, detail = {}) {
  const session = ensureSessionTabRecordSession(record);
  if (!session) return false;
  const pending = cloneDesignReviewApplyState(session.designReviewApply);
  const normalized = normalizeDesignReviewApplyEventDetail(detail, {
    fallbackState: pending,
    status: "succeeded",
  });
  if ((!pending.sessionKey && !normalized.sessionKey && !pending.requestId) || !designReviewApplyEventMatchesTabRecord(record, normalized, pending)) {
    return false;
  }
  const targetId = readFirstString(normalized.targetImageId);
  const outputPath = readFirstString(normalized.outputPath);
  if (!targetId || !outputPath) return false;
  const target = session.imagesById.get(targetId) || null;
  const actionLabel = designReviewApplyActionLabel(normalized);
  if (!target?.path) {
    session.designReviewApply = createFreshDesignReviewApplyState();
    session.lastStatusText = `Engine: ${actionLabel.toLowerCase()} failed (target image missing).`;
    session.lastStatusError = true;
    syncSessionTabRecordFromSession(record, {
      publish: true,
      bumpVersions: false,
      busy: false,
      reviewFlowState: "failed",
    });
    return false;
  }
  const targetSnapshot = {
    id: targetId,
    path: String(target.path || ""),
    receiptPath: target.receiptPath ? String(target.receiptPath) : null,
    kind: target.kind ? String(target.kind) : null,
    source: target.source ? String(target.source) : null,
    label: target.label ? String(target.label) : basename(outputPath),
    timelineNodeId: target.timelineNodeId ? String(target.timelineNodeId) : null,
  };
  const receiptPath = await writeDesignReviewApplyReceipt({
    runDir: session.runDir || record?.runDir || null,
    outputPath,
    targetBefore: targetSnapshot,
    targetImageId: targetId,
    referenceImageIds: normalized.referenceImageIds,
    selectedProposalId: normalized.selectedProposalId,
    proposal: normalized.proposal,
    request: normalized.request,
    debugInfo: normalized.debugInfo,
    provider: normalized.provider,
    requestedModel: normalized.requestedModel,
    normalizedModel: normalized.normalizedModel,
    costTotalUsd: normalized.costTotalUsd,
    latencyPerImageS: normalized.latencyPerImageS,
  }).catch((error) => {
    console.error("Failed to write background design-review apply receipt:", error);
    return null;
  });
  const ok = replaceImageInSessionRecord(session, targetId, {
    path: outputPath,
    receiptPath,
    kind: "engine",
    label: targetSnapshot.label || basename(outputPath),
  });
  if (!ok) {
    if (receiptPath) removeFile(receiptPath).catch(() => {});
    session.designReviewApply = createFreshDesignReviewApplyState();
    session.lastStatusText = `Engine: ${actionLabel.toLowerCase()} failed (replace failed).`;
    session.lastStatusError = true;
    syncSessionTabRecordFromSession(record, {
      publish: true,
      bumpVersions: false,
      busy: false,
      reviewFlowState: "failed",
    });
    return false;
  }
  const nodeId = recordTimelineNodeInSession(session, {
    imageId: targetId,
    path: outputPath,
    receiptPath,
    label: targetSnapshot.label || basename(outputPath),
    action: actionLabel,
    kind: "image_result",
    visualMode: "thumbnail",
    parents: targetSnapshot.timelineNodeId ? [targetSnapshot.timelineNodeId] : [],
    previewImageId: targetId,
    previewPath: outputPath,
    receiptPaths: receiptPath ? [receiptPath] : [],
  });
  const item = session.imagesById.get(targetId) || null;
  if (item) {
    item.source = DESIGN_REVIEW_APPLY_SOURCE;
    if (nodeId) item.timelineNodeId = nodeId;
  }
  const targetAfter = item
    ? {
        id: String(item.id || targetId),
        path: String(item.path || outputPath),
        receiptPath: item.receiptPath ? String(item.receiptPath) : receiptPath,
        kind: item.kind ? String(item.kind) : "engine",
        source: item.source ? String(item.source) : DESIGN_REVIEW_APPLY_SOURCE,
        label: item.label ? String(item.label) : targetSnapshot.label,
        timelineNodeId: item.timelineNodeId ? String(item.timelineNodeId) : nodeId || null,
      }
    : {
        id: targetId,
        path: outputPath,
        receiptPath,
        kind: "engine",
        source: DESIGN_REVIEW_APPLY_SOURCE,
        label: targetSnapshot.label || basename(outputPath),
        timelineNodeId: nodeId || null,
      };
  const communication =
    session.communication && typeof session.communication === "object"
      ? session.communication
      : createFreshCommunicationState();
  communication.screenshotPolish = buildScreenshotPolishApprovalState({
    detail: normalized,
    targetBefore: targetSnapshot,
    targetAfter,
    receiptPath,
    outputPath,
    timelineNodeId: nodeId,
  });
  session.communication = communication;
  const referenceImageIds = uniqueStringList(
    Array.isArray(normalized.referenceImageIds) ? normalized.referenceImageIds : [],
    { exclude: ["", targetId] }
  );
  for (const referenceImageId of referenceImageIds) {
    removeImageFromSessionRecord(session, referenceImageId);
  }
  if (session.communication && typeof session.communication === "object") {
    session.communication.tool = resolveReviewApplyCommunicationTool(session.communication.tool, normalized);
  }
  clearVisibleCommunicationReviewStateForSession(session);
  session.activeId = targetId;
  session.selectedIds = [targetId];
  updateDesignReviewApplyCostLatencyForSession(session, normalized);
  session.designReviewApply = createFreshDesignReviewApplyState();
  session.lastStatusText = "Engine: ready";
  session.lastStatusError = false;
  syncSessionTabRecordFromSession(record, {
    publish: true,
    bumpVersions: true,
    busy: false,
    reviewFlowState: "",
  });
  persistSessionTimelineForSession(session).catch(() => {});
  return true;
}

async function applyAcceptedDesignReviewOutput(detail = {}) {
  const resolved = resolveDesignReviewApplyTargetRecord(detail, state.designReviewApply);
  if (!resolved.record) return false;
  if (!resolved.isActive) {
    return applyAcceptedDesignReviewOutputToSessionRecord(resolved.record, detail);
  }
  const pending = cloneDesignReviewApplyState(state.designReviewApply);
  const normalized = normalizeDesignReviewApplyEventDetail(detail, {
    fallbackState: pending,
    status: "succeeded",
  });
  if ((!pending.sessionKey && !normalized.sessionKey && !pending.requestId) || !designReviewApplyEventMatchesActiveTab(normalized, pending)) {
    return false;
  }
  const targetId = readFirstString(normalized.targetImageId);
  const outputPath = readFirstString(normalized.outputPath);
  if (!targetId || !outputPath) return false;
  const target = state.imagesById.get(targetId) || null;
  const actionLabel = designReviewApplyActionLabel(normalized);
  if (!target?.path) {
    clearDesignReviewApplyState({ capture: true, publish: true });
    setStatus(`Engine: ${actionLabel.toLowerCase()} failed (target image missing).`, true);
    showToast("Review apply failed: target image missing.", "error", 3200);
    return false;
  }
  const targetSnapshot = {
    id: targetId,
    path: String(target.path || ""),
    receiptPath: target.receiptPath ? String(target.receiptPath) : null,
    kind: target.kind ? String(target.kind) : null,
    source: target.source ? String(target.source) : null,
    label: target.label ? String(target.label) : basename(outputPath),
    timelineNodeId: target.timelineNodeId ? String(target.timelineNodeId) : null,
  };
  const receiptPath = await writeDesignReviewApplyReceipt({
    outputPath,
    targetBefore: targetSnapshot,
    targetImageId: targetId,
    referenceImageIds: normalized.referenceImageIds,
    selectedProposalId: normalized.selectedProposalId,
    proposal: normalized.proposal,
    request: normalized.request,
    debugInfo: normalized.debugInfo,
    provider: normalized.provider,
    requestedModel: normalized.requestedModel,
    normalizedModel: normalized.normalizedModel,
    costTotalUsd: normalized.costTotalUsd,
    latencyPerImageS: normalized.latencyPerImageS,
  }).catch((error) => {
    console.error("Failed to write design-review apply receipt:", error);
    return null;
  });
  const ok = await replaceImageInPlace(targetId, {
    path: outputPath,
    receiptPath,
    kind: "engine",
    label: targetSnapshot.label || basename(outputPath),
  }).catch((error) => {
    console.error(error);
    return false;
  });
  if (!ok) {
    if (receiptPath) removeFile(receiptPath).catch(() => {});
    clearDesignReviewApplyState({ capture: true, publish: true });
    setStatus(`Engine: ${actionLabel.toLowerCase()} failed (replace failed).`, true);
    showToast("Review apply failed to replace the target image.", "error", 3200);
    return false;
  }
  const nodeId = recordTimelineNode({
    imageId: targetId,
    path: outputPath,
    receiptPath,
    label: targetSnapshot.label || basename(outputPath),
    action: actionLabel,
    kind: "image_result",
    visualMode: "thumbnail",
    parents: targetSnapshot.timelineNodeId ? [targetSnapshot.timelineNodeId] : [],
    previewImageId: targetId,
    previewPath: outputPath,
    receiptPaths: receiptPath ? [receiptPath] : [],
  });
  const item = state.imagesById.get(targetId) || null;
  if (item) {
    item.source = DESIGN_REVIEW_APPLY_SOURCE;
    if (nodeId) item.timelineNodeId = nodeId;
  }
  const targetAfter = item
    ? {
        id: String(item.id || targetId),
        path: String(item.path || outputPath),
        receiptPath: item.receiptPath ? String(item.receiptPath) : receiptPath,
        kind: item.kind ? String(item.kind) : "engine",
        source: item.source ? String(item.source) : DESIGN_REVIEW_APPLY_SOURCE,
        label: item.label ? String(item.label) : targetSnapshot.label,
        timelineNodeId: item.timelineNodeId ? String(item.timelineNodeId) : nodeId || null,
      }
    : {
        id: targetId,
        path: outputPath,
        receiptPath,
        kind: "engine",
        source: DESIGN_REVIEW_APPLY_SOURCE,
        label: targetSnapshot.label || basename(outputPath),
        timelineNodeId: nodeId || null,
      };
  if (state.communication && typeof state.communication === "object") {
    state.communication.screenshotPolish = buildScreenshotPolishApprovalState({
      detail: normalized,
      targetBefore: targetSnapshot,
      targetAfter,
      receiptPath,
      outputPath,
      timelineNodeId: nodeId,
    });
  }
  const referenceImageIds = uniqueStringList(
    Array.isArray(normalized.referenceImageIds) ? normalized.referenceImageIds : [],
    { exclude: ["", targetId] }
  );
  archiveCommunicationReviewContext({
    reason: "review_apply_success",
    detail: normalized,
    targetBefore: targetSnapshot,
    targetAfter,
    receiptPath,
    outputPath,
    timelineNodeId: nodeId,
  });
  for (const referenceImageId of referenceImageIds) {
    await removeImageFromCanvas(referenceImageId).catch(() => {});
  }
  const nextCommunicationTool = resolveReviewApplyCommunicationTool(state.communication?.tool, normalized);
  if (nextCommunicationTool) {
    if (String(state.communication?.tool || "").trim() !== nextCommunicationTool) {
      ensureCommunicationToolActive(nextCommunicationTool, { source: "review_apply_success" });
    }
  } else if (state.communication?.tool) {
    setCommunicationTool(null, { source: "review_apply_success" });
  }
  clearVisibleCommunicationReviewState();
  dispatchJuggernautShellEvent(COMMUNICATION_STATE_CHANGED_EVENT, {
    source: "review_apply_success_cleanup",
    communication: buildCommunicationBridgeSnapshot(),
    context: buildJuggernautShellContext(),
  });
  if (state.canvasMode === "multi" && state.tool !== "pan") {
    setTool("pan");
  }
  updateDesignReviewApplyCostLatency(normalized);
  if (receiptPath) {
    ingestTopMetricsFromReceiptPath(receiptPath, {
      allowCostFallback: true,
      allowLatencyFallback: true,
    }).catch(() => {});
  }
  clearDesignReviewApplyState({ capture: true, publish: true });
  syncActiveTabReviewFlowState({ publish: true });
  dismissCommunicationProposalTrayAfterReviewApply({
    requestId: normalized.requestId,
  });
  setStatus("Engine: ready");
  showToast(`${actionLabel} applied.`, "tip", 2200);
  requestRender();
  processActionQueue().catch(() => {});
  return true;
}

function handleDesignReviewApplyFailureInSessionRecord(record = null, detail = {}) {
  const session = ensureSessionTabRecordSession(record);
  if (!session) return false;
  const pending = cloneDesignReviewApplyState(session.designReviewApply);
  const normalized = normalizeDesignReviewApplyEventDetail(detail, {
    fallbackState: pending,
    status: "failed",
  });
  if ((!pending.sessionKey && !normalized.sessionKey && !pending.requestId) || !designReviewApplyEventMatchesTabRecord(record, normalized, pending)) {
    return false;
  }
  const actionLabel = designReviewApplyActionLabel(normalized);
  const message = readFirstString(normalized.error, normalized.debugInfo?.error) || "Review apply failed.";
  session.designReviewApply = createFreshDesignReviewApplyState();
  session.lastStatusText = `Engine: ${actionLabel.toLowerCase()} failed (${message})`;
  session.lastStatusError = true;
  markSessionCommunicationProposalTrayApplyFailed(session, normalized, message);
  syncSessionTabRecordFromSession(record, {
    publish: true,
    bumpVersions: true,
    busy: false,
    reviewFlowState: "failed",
  });
  return true;
}

function handleDesignReviewApplyFailure(detail = {}) {
  const resolved = resolveDesignReviewApplyTargetRecord(detail, state.designReviewApply);
  if (!resolved.record) return false;
  if (!resolved.isActive) {
    return handleDesignReviewApplyFailureInSessionRecord(resolved.record, detail);
  }
  const pending = cloneDesignReviewApplyState(state.designReviewApply);
  const normalized = normalizeDesignReviewApplyEventDetail(detail, {
    fallbackState: pending,
    status: "failed",
  });
  if ((!pending.sessionKey && !normalized.sessionKey && !pending.requestId) || !designReviewApplyEventMatchesActiveTab(normalized, pending)) {
    return false;
  }
  const actionLabel = designReviewApplyActionLabel(normalized);
  const message = readFirstString(normalized.error, normalized.debugInfo?.error) || "Review apply failed.";
  clearDesignReviewApplyState({ capture: true, publish: true });
  syncActiveTabReviewFlowState({ publish: true });
  setStatus(`Engine: ${actionLabel.toLowerCase()} failed (${message})`, true);
  showToast(message, "error", 3200);
  requestRender();
  processActionQueue().catch(() => {});
  return true;
}

function bindDesignReviewApplyRuntimeBridge() {
  if (designReviewApplyBridgeBound || typeof window === "undefined") return;
  designReviewApplyBridgeBound = true;
  window.addEventListener(DESIGN_REVIEW_APPLY_EVENT, (event) => {
    const detail = event?.detail || {};
    const phase = readFirstString(detail?.phase, detail?.status).toLowerCase();
    if (phase === "started" || phase === "starting" || phase === "running") {
      markDesignReviewApplyRunning(detail);
      return;
    }
    if (phase === "succeeded" || phase === "success" || phase === "complete" || phase === "completed") {
      void applyAcceptedDesignReviewOutput(detail);
      return;
    }
    if (phase === "failed" || phase === "error") {
      handleDesignReviewApplyFailure(detail);
    }
  });
}

function dropCommunicationStateForImageId(imageId) {
  const id = String(imageId || "").trim();
  if (!id) return;
  void dropLocalMagicSelectPreparedImageForUi(id, {
    reason: "image_remove",
    evict: true,
  }).catch(() => {});
  state.communication?.marksByImageId?.delete(id);
  state.communication?.stampsByImageId?.delete(id);
  state.communication?.regionProposalsByImageId?.delete(id);
  if (state.communication?.markDraft?.imageId === id) {
    state.communication.markDraft = null;
  }
  if (state.communication?.eraseDraft?.imageId === id) {
    state.communication.eraseDraft = null;
  }
  if (state.communication?.stampPicker?.imageId === id) {
    state.communication.stampPicker = createFreshCommunicationStampPickerState();
  }
  if (state.communication?.lastAnchor?.imageId === id) {
    state.communication.lastAnchor = resolveCommunicationReviewAnchor();
  }
  if (state.communication?.proposalTray?.anchor?.imageId === id) {
    hideCommunicationProposalTray({ preserveAnchor: false, source: "image_remove" });
  }
}

function traceCommunicationMarkPath(octx, points = []) {
  if (!octx || !Array.isArray(points) || points.length < 2) return false;
  octx.beginPath();
  octx.moveTo(Number(points[0]?.x) || 0, Number(points[0]?.y) || 0);
  if (points.length === 2) {
    octx.lineTo(Number(points[1]?.x) || 0, Number(points[1]?.y) || 0);
    return true;
  }
  for (let i = 1; i < points.length - 1; i += 1) {
    const current = points[i];
    const next = points[i + 1];
    const midX = ((Number(current?.x) || 0) + (Number(next?.x) || 0)) * 0.5;
    const midY = ((Number(current?.y) || 0) + (Number(next?.y) || 0)) * 0.5;
    octx.quadraticCurveTo(Number(current?.x) || 0, Number(current?.y) || 0, midX, midY);
  }
  const penultimate = points[points.length - 2];
  const tail = points[points.length - 1];
  octx.quadraticCurveTo(
    Number(penultimate?.x) || 0,
    Number(penultimate?.y) || 0,
    Number(tail?.x) || 0,
    Number(tail?.y) || 0
  );
  return true;
}

function renderCommunicationOverlay(octx) {
  if (!octx) return;
  const dpr = getDpr();
  const markerStrokeVariant = (color, alpha) => {
    const rawColor = String(color || COMMUNICATION_MARK_STROKE).trim();
    const match = rawColor.match(/^rgba?\(([^)]+)\)$/i);
    if (!match) return rawColor;
    const parts = match[1].split(",").map((part) => Number.parseFloat(part.trim()));
    const r = Number.isFinite(parts[0]) ? parts[0] : 235;
    const g = Number.isFinite(parts[1]) ? parts[1] : 76;
    const b = Number.isFinite(parts[2]) ? parts[2] : 52;
    const a = Math.max(0, Math.min(1, Number(alpha)));
    return `rgba(${Math.round(r)}, ${Math.round(g)}, ${Math.round(b)}, ${a})`;
  };
  for (const [imageId, group] of Array.from(state.communication?.regionProposalsByImageId?.entries?.() || [])) {
    const candidates = Array.isArray(group?.candidates) ? group.candidates : [];
    const activeIndex = Math.max(0, Number(group?.activeCandidateIndex) || 0);
    const viewportScale = communicationCanvasCssScaleForImageId(imageId);
    candidates.forEach((candidate, index) => {
      const imagePolygon = Array.isArray(candidate?.contourPoints) && candidate.contourPoints.length >= 3
        ? candidate.contourPoints
        : Array.isArray(candidate?.polygon) && candidate.polygon.length >= 3
          ? candidate.polygon
          : candidate?.bounds
            ? [
                { x: Number(candidate.bounds.x) || 0, y: Number(candidate.bounds.y) || 0 },
                {
                  x: (Number(candidate.bounds.x) || 0) + Math.max(1, Number(candidate.bounds.w) || 1),
                  y: Number(candidate.bounds.y) || 0,
                },
                {
                  x: (Number(candidate.bounds.x) || 0) + Math.max(1, Number(candidate.bounds.w) || 1),
                  y: (Number(candidate.bounds.y) || 0) + Math.max(1, Number(candidate.bounds.h) || 1),
                },
                {
                  x: Number(candidate.bounds.x) || 0,
                  y: (Number(candidate.bounds.y) || 0) + Math.max(1, Number(candidate.bounds.h) || 1),
                },
              ]
            : [];
      const polygon = imagePolygon.map((point) => imageToCanvasForImageId(imageId, point)).filter(Boolean);
      if (polygon.length < 3) return;
      octx.save();
      octx.lineWidth = Math.max(1, Math.round((index === activeIndex ? 2.5 : 1.5) * dpr * viewportScale));
      octx.strokeStyle = index === activeIndex ? COMMUNICATION_REGION_ACTIVE : COMMUNICATION_REGION_IDLE;
      octx.fillStyle = index === activeIndex ? "rgba(100, 210, 255, 0.18)" : "rgba(100, 210, 255, 0.06)";
      if (index !== activeIndex) {
        octx.setLineDash([
          Math.max(2, Math.round(8 * dpr * viewportScale)),
          Math.max(2, Math.round(7 * dpr * viewportScale)),
        ]);
      }
      if (drawPolygonPath(octx, polygon)) {
        octx.fill();
        octx.stroke();
      }
      octx.restore();
    });
  }

  const drawMark = (mark, { draft = false } = {}) => {
    const points = draft ? communicationDraftPointsToCanvas(mark) : communicationMarkPointsToCanvas(mark);
    if (points.length < 2) return;
    const markKind = String(mark?.kind || "").trim().toLowerCase() === "freehand_protect"
      ? "freehand_protect"
      : "freehand_marker";
    const markerColor = String(
      mark?.color || (markKind === "freehand_protect" ? COMMUNICATION_PROTECT_STROKE : COMMUNICATION_MARK_STROKE)
    );
    const markerShoulderColor = markerStrokeVariant(markerColor, draft ? 0.26 : 0.16);
    const markerCoreColor = markerStrokeVariant(markerColor, draft ? 0.68 : 0.94);
    octx.save();
    octx.lineCap = "round";
    octx.lineJoin = "round";
    octx.globalAlpha = 1;
    octx.shadowColor = "transparent";
    octx.shadowBlur = 0;
    if (markKind === "freehand_protect") {
      const highlightBodyWidthCss = draft
        ? COMMUNICATION_PROTECT_DRAFT_WIDTH_CSS_PX
        : COMMUNICATION_PROTECT_COMMITTED_WIDTH_CSS_PX;
      const highlightCoreWidthCss = highlightBodyWidthCss * 0.58;
      octx.globalCompositeOperation = "multiply";
      octx.lineWidth = Math.max(1, Math.round(highlightBodyWidthCss * dpr));
      octx.strokeStyle = draft
        ? markerStrokeVariant(markerColor, 0.5)
        : markerStrokeVariant(markerColor, 0.38);
      if (traceCommunicationMarkPath(octx, points)) octx.stroke();
      octx.lineWidth = Math.max(1, Math.round(highlightCoreWidthCss * dpr));
      octx.strokeStyle = draft
        ? markerStrokeVariant(markerColor, 0.74)
        : markerStrokeVariant(markerColor, 0.58);
      if (traceCommunicationMarkPath(octx, points)) octx.stroke();
      octx.restore();
      return;
    }
    octx.lineWidth = Math.max(
      1,
      Math.round((draft ? COMMUNICATION_MARK_DRAFT_SHOULDER_CSS_PX : COMMUNICATION_MARK_COMMITTED_SHOULDER_CSS_PX) * dpr)
    );
    octx.strokeStyle = markerShoulderColor;
    if (traceCommunicationMarkPath(octx, points)) octx.stroke();
    octx.lineWidth = Math.max(
      1,
      Math.round((draft ? COMMUNICATION_MARK_DRAFT_CORE_CSS_PX : COMMUNICATION_MARK_COMMITTED_CORE_CSS_PX) * dpr)
    );
    octx.strokeStyle = markerCoreColor;
    if (traceCommunicationMarkPath(octx, points)) octx.stroke();
    octx.restore();
  };

  for (const [, marks] of Array.from(state.communication?.marksByImageId?.entries?.() || [])) {
    const list = Array.isArray(marks) ? marks : [];
    for (const mark of list) {
      drawMark(mark);
    }
  }
  for (const mark of communicationCanvasMarks()) {
    drawMark(mark);
  }
  let stampBackdropCtx = null;
  if (els.workCanvas && typeof els.workCanvas.getContext === "function") {
    try {
      stampBackdropCtx = els.workCanvas.getContext("2d", { willReadFrequently: true }) || els.workCanvas.getContext("2d");
    } catch {
      stampBackdropCtx = els.workCanvas.getContext("2d");
    }
  }
  const traceStampChipPath = (ctx, left, top, width, height, radius) => {
    const bevel = clamp(
      Math.round(Number(radius) || 0),
      0,
      Math.max(0, Math.floor(Math.min(Math.abs(width), Math.abs(height)) * 0.48))
    );
    ctx.beginPath();
    if (!(bevel > 0)) {
      ctx.rect(left, top, width, height);
      return;
    }
    ctx.moveTo(left + bevel, top);
    ctx.lineTo(left + width - bevel, top);
    ctx.lineTo(left + width, top + bevel);
    ctx.lineTo(left + width, top + height - bevel);
    ctx.lineTo(left + width - bevel, top + height);
    ctx.lineTo(left + bevel, top + height);
    ctx.lineTo(left, top + height - bevel);
    ctx.lineTo(left, top + bevel);
    ctx.closePath();
  };
  const sampleStampBackdropLuminance = (centerX, centerY) => {
    if (!stampBackdropCtx || !els.workCanvas?.width || !els.workCanvas?.height) return null;
    const sampleRadius = Math.max(3, Math.round(7 * dpr));
    const sampleSize = sampleRadius * 2;
    const sampleX = clamp(
      Math.round(centerX - sampleRadius),
      0,
      Math.max(0, Number(els.workCanvas.width || 0) - sampleSize)
    );
    const sampleY = clamp(
      Math.round(centerY - sampleRadius),
      0,
      Math.max(0, Number(els.workCanvas.height || 0) - sampleSize)
    );
    try {
      const imageData = stampBackdropCtx.getImageData(sampleX, sampleY, sampleSize, sampleSize);
      const data = imageData?.data || null;
      if (!data?.length) return null;
      let total = 0;
      let count = 0;
      for (let index = 0; index < data.length; index += 4) {
        const alpha = Number(data[index + 3]) / 255;
        if (!(alpha > 0.01)) continue;
        const r = Number(data[index]) || 0;
        const g = Number(data[index + 1]) || 0;
        const b = Number(data[index + 2]) || 0;
        total += 0.2126 * r + 0.7152 * g + 0.0722 * b;
        count += 1;
      }
      return count ? total / count : null;
    } catch {
      return null;
    }
  };
  const stampRotationDeg = (stamp) => {
    const source = `${readFirstString(stamp?.id)}:${readFirstString(stamp?.intentId)}`;
    let hash = 0;
    for (let index = 0; index < source.length; index += 1) {
      hash = (hash * 33 + source.charCodeAt(index)) | 0;
    }
    return ((((hash % 1000) + 1000) % 1000) / 999 - 0.5) * 3.2;
  };
  const resolveStampPalette = (chipCenterX, chipCenterY) => {
    const luminance = sampleStampBackdropLuminance(chipCenterX, chipCenterY);
    if (Number.isFinite(luminance) && luminance < 88) {
      return {
        ink: "rgba(248, 239, 230, 0.96)",
        inkSoft: "rgba(248, 239, 230, 0.34)",
        wash: "rgba(248, 239, 230, 0.10)",
        halo: "rgba(10, 12, 16, 0.34)",
        ghost: "rgba(10, 12, 16, 0.18)",
        leaderBase: "rgba(8, 10, 14, 0.58)",
        leaderTop: "rgba(248, 239, 230, 0.78)",
        anchorOuter: "rgba(248, 239, 230, 0.96)",
        anchorInner: "rgba(12, 16, 20, 0.94)",
        anchorHalo: "rgba(8, 10, 14, 0.30)",
        registration: "rgba(248, 239, 230, 0.28)",
      };
    }
    return {
      ink: "rgba(174, 56, 44, 0.94)",
      inkSoft: "rgba(174, 56, 44, 0.34)",
      wash: "rgba(174, 56, 44, 0.08)",
      halo: "rgba(255, 255, 255, 0.44)",
      ghost: "rgba(18, 22, 28, 0.14)",
      leaderBase: "rgba(120, 26, 19, 0.52)",
      leaderTop: "rgba(255, 247, 243, 0.72)",
      anchorOuter: "rgba(174, 56, 44, 0.94)",
      anchorInner: "rgba(255, 247, 243, 0.98)",
      anchorHalo: "rgba(255, 255, 255, 0.40)",
      registration: "rgba(174, 56, 44, 0.22)",
    };
  };
  const drawStamp = (stamp) => {
    const layout = communicationStampLayoutCss(stamp);
    if (!layout) return;
    const chipLeft = Math.round(layout.chipRect.left * dpr);
    const chipTop = Math.round(layout.chipRect.top * dpr);
    const chipWidth = Math.max(1, Math.round(layout.chipRect.width * dpr));
    const chipHeight = Math.max(1, Math.round(layout.chipRect.height * dpr));
    const anchorX = Math.round(Number(layout.anchorCss.x || 0) * dpr);
    const anchorY = Math.round(Number(layout.anchorCss.y || 0) * dpr);
    const leaderX = Math.round(Number(layout.leaderTo.x || 0) * dpr);
    const leaderY = Math.round(Number(layout.leaderTo.y || 0) * dpr);
    const label = communicationStampDisplayLabel(stamp).toUpperCase();
    const chipCenterX = chipLeft + Math.round(chipWidth * 0.5);
    const chipCenterY = chipTop + Math.round(chipHeight * 0.5);
    const palette = resolveStampPalette(chipCenterX, chipCenterY);
    const bevel = Math.max(3, Math.round(4.75 * dpr));
    const rotationRad = (stampRotationDeg(stamp) * Math.PI) / 180;
    const anchorRadius = Math.max(3, Math.round(3.7 * dpr));
    const anchorInnerRadius = Math.max(1, Math.round(1.65 * dpr));
    const haloStroke = Math.max(2, Math.round(2.8 * dpr));
    const outerStroke = Math.max(1, Math.round(1.35 * dpr));
    const innerStroke = Math.max(1, Math.round(0.85 * dpr));
    const imprintNudge = Math.max(1, Math.round(0.75 * dpr));
    const registrationWidth = Math.max(10, Math.round(14 * dpr));
    const registrationHeight = Math.max(1, Math.round(1.1 * dpr));
    octx.save();
    octx.lineCap = "round";
    octx.lineJoin = "round";
    octx.strokeStyle = palette.leaderBase;
    octx.lineWidth = Math.max(1, Math.round(2.8 * dpr));
    octx.beginPath();
    octx.moveTo(anchorX, anchorY);
    octx.lineTo(leaderX, leaderY);
    octx.stroke();
    octx.strokeStyle = palette.leaderTop;
    octx.lineWidth = Math.max(1, Math.round(1.4 * dpr));
    octx.beginPath();
    octx.moveTo(anchorX, anchorY);
    octx.lineTo(leaderX, leaderY);
    octx.stroke();
    octx.fillStyle = palette.anchorHalo;
    octx.beginPath();
    octx.arc(anchorX, anchorY, anchorRadius + Math.max(1, Math.round(1.2 * dpr)), 0, Math.PI * 2);
    octx.fill();
    octx.fillStyle = palette.anchorOuter;
    octx.beginPath();
    octx.arc(anchorX, anchorY, anchorRadius, 0, Math.PI * 2);
    octx.fill();
    octx.fillStyle = palette.anchorInner;
    octx.beginPath();
    octx.arc(anchorX, anchorY, anchorInnerRadius, 0, Math.PI * 2);
    octx.fill();
    octx.translate(chipCenterX, chipCenterY);
    octx.rotate(rotationRad);
    octx.translate(-chipCenterX, -chipCenterY);
    octx.save();
    traceStampChipPath(
      octx,
      chipLeft - Math.max(1, Math.round(1.6 * dpr)),
      chipTop - Math.max(1, Math.round(1.6 * dpr)),
      chipWidth + Math.max(2, Math.round(3.2 * dpr)),
      chipHeight + Math.max(2, Math.round(3.2 * dpr)),
      bevel + Math.max(1, Math.round(1.4 * dpr))
    );
    octx.lineWidth = haloStroke;
    octx.strokeStyle = palette.halo;
    octx.stroke();
    octx.restore();
    traceStampChipPath(octx, chipLeft, chipTop, chipWidth, chipHeight, bevel);
    octx.fillStyle = palette.wash;
    octx.fill();
    octx.save();
    octx.translate(imprintNudge, imprintNudge);
    traceStampChipPath(octx, chipLeft, chipTop, chipWidth, chipHeight, bevel);
    octx.lineWidth = outerStroke;
    octx.strokeStyle = palette.ghost;
    octx.stroke();
    octx.restore();
    traceStampChipPath(octx, chipLeft, chipTop, chipWidth, chipHeight, bevel);
    octx.lineWidth = outerStroke;
    octx.strokeStyle = palette.ink;
    octx.stroke();
    traceStampChipPath(
      octx,
      chipLeft + Math.max(2, Math.round(2.1 * dpr)),
      chipTop + Math.max(2, Math.round(2.1 * dpr)),
      Math.max(1, chipWidth - Math.max(4, Math.round(4.2 * dpr))),
      Math.max(1, chipHeight - Math.max(4, Math.round(4.2 * dpr))),
      Math.max(2, bevel - Math.round(1 * dpr))
    );
    octx.lineWidth = innerStroke;
    octx.strokeStyle = palette.inkSoft;
    octx.stroke();
    const registrationCenterX = chipLeft + Math.round(chipWidth * 0.5);
    octx.fillStyle = palette.registration;
    octx.fillRect(
      Math.round(registrationCenterX - registrationWidth * 0.5),
      chipTop + Math.max(4, Math.round(4 * dpr)),
      registrationWidth,
      registrationHeight
    );
    octx.fillRect(
      Math.round(registrationCenterX - registrationWidth * 0.5),
      chipTop + chipHeight - Math.max(5, Math.round(5 * dpr)),
      registrationWidth,
      registrationHeight
    );
    octx.fillRect(
      chipLeft + Math.max(8, Math.round(9 * dpr)),
      chipTop + Math.max(6, Math.round(6 * dpr)),
      Math.max(9, Math.round(10 * dpr)),
      registrationHeight
    );
    octx.fillStyle = palette.ink;
    octx.font = `600 ${Math.max(10, Math.round(11.5 * dpr))}px "IBM Plex Sans Condensed", "Arial Narrow", "IBM Plex Sans", "Segoe UI", sans-serif`;
    octx.textBaseline = "middle";
    octx.fillText(
      label,
      chipLeft + Math.max(12, Math.round(14 * dpr)),
      chipTop + Math.round(chipHeight * 0.545)
    );
    octx.restore();
  };
  for (const [, stamps] of Array.from(state.communication?.stampsByImageId?.entries?.() || [])) {
    const list = Array.isArray(stamps) ? stamps : [];
    for (const stamp of list) {
      drawStamp(stamp);
    }
  }
  for (const stamp of communicationCanvasStamps()) {
    drawStamp(stamp);
  }
  if (state.communication?.markDraft) {
    drawMark(state.communication.markDraft, { draft: true });
  }
  if (state.communication?.eraseDraft) {
    const points = communicationDraftPointsToCanvas(state.communication.eraseDraft);
    if (points.length) {
      octx.save();
      octx.lineCap = "round";
      octx.lineJoin = "round";
      octx.lineWidth = Math.max(8, Math.round(COMMUNICATION_IMAGE_ERASE_BRUSH_CSS_PX * dpr));
      octx.strokeStyle = "rgba(120, 228, 255, 0.72)";
      octx.fillStyle = "rgba(214, 247, 255, 0.70)";
      octx.shadowColor = "rgba(120, 228, 255, 0.22)";
      octx.shadowBlur = Math.round(14 * dpr);
      if (points.length === 1) {
        const radius = Math.max(5, Math.round((COMMUNICATION_IMAGE_ERASE_BRUSH_CSS_PX * dpr) * 0.5));
        octx.beginPath();
        octx.arc(Number(points[0]?.x) || 0, Number(points[0]?.y) || 0, radius, 0, Math.PI * 2);
        octx.fill();
      } else if (traceCommunicationMarkPath(octx, points)) {
        octx.stroke();
      }
      octx.restore();
    }
  }
}

function requestRender({ allowTabSwitchPreview = false, reason = "render" } = {}) {
  if (allowTabSwitchPreview) {
    const normalizedTabId = String(state.activeTabId || "").trim();
    if (normalizedTabId) {
      clearPendingTabSwitchFullRender({ stale: true });
      state.pendingTabSwitchPreview = {
        tabId: normalizedTabId,
        reason: String(reason || "render"),
        requestedAt: Date.now(),
      };
    }
  }
  if (state.needsRender) return;
  state.needsRender = true;
  requestAnimationFrame(() => {
    state.needsRender = false;
    render();
  });
}

async function loadImage(path) {
  if (!path) return null;
  const rec = getOrCreateImageCacheRecord(path);
  const cached = readSessionRuntimeImageHandle({ img: rec.img || null });
  if (cached) return cached;
  if (rec.imgPromise) return await rec.imgPromise;
  rec.imgPromise = (async () => {
    // Always use a blob URL to keep the canvas untainted for local edits (toBlob, etc).
    const url = await ensureImageUrl(path);
    return await new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => {
        rec.img = img;
        resolve(img);
      };
      img.onerror = (err) => {
        rec.img = null;
        reject(err);
      };
      img.src = url;
    });
  })();
  return await rec.imgPromise;
}

function readSessionRuntimeImageHandle(entry = null) {
  const img = entry?.img;
  if (!img || typeof img !== "object") return null;
  const naturalWidth = Number(img.naturalWidth);
  const naturalHeight = Number(img.naturalHeight);
  if (!Number.isFinite(naturalWidth) || naturalWidth <= 0) return null;
  if (!Number.isFinite(naturalHeight) || naturalHeight <= 0) return null;
  if (typeof img.complete === "boolean" && !img.complete) return null;
  return img;
}

function readCachedImageHandle(path = "") {
  const normalizedPath = String(path || "").trim();
  if (!normalizedPath) return null;
  const record = state.imageCache.get(normalizedPath);
  return readSessionRuntimeImageHandle({ img: record?.img || null });
}

function clearImageCache() {
  for (const value of state.imageCache.values()) {
    const url = value?.url;
    if (url) {
      try {
        URL.revokeObjectURL(url);
      } catch {
        // ignore
      }
    }
  }
  state.imageCache.clear();
}

function getActiveImage() {
  if (!state.activeId) return null;
  return state.imagesById.get(state.activeId) || null;
}

function runtimeChromeState() {
  if (!state.runtimeChrome || typeof state.runtimeChrome !== "object") {
    state.runtimeChrome = { pinAssistant: false, showDiagnostics: false };
  }
  return state.runtimeChrome;
}

function runtimeChromeAssistantForcedVisible() {
  return false;
}

function runtimeChromeVisibilitySnapshot() {
  const prefs = runtimeChromeState();
  const pinAssistant = Boolean(prefs.pinAssistant);
  const showDiagnostics = Boolean(prefs.showDiagnostics);
  return {
    pinAssistant,
    assistantVisible: pinAssistant || runtimeChromeAssistantForcedVisible(),
    showDiagnostics,
    diagnosticsVisible: showDiagnostics,
  };
}

function syncPortraitDockVisibility() {
  const { diagnosticsVisible } = runtimeChromeVisibilitySnapshot();
  if (els.agentsDock) els.agentsDock.classList.toggle("hidden", !diagnosticsVisible);
  if (!els.portraitDock) return;
  els.portraitDock.classList.toggle("hidden", !diagnosticsVisible);
}

function runtimeChromeShouldShowEngineStatus() {
  return runtimeChromeVisibilitySnapshot().diagnosticsVisible || Boolean(state.lastStatusError);
}

function runtimeChromeShouldShowSelectionStatus() {
  return runtimeChromeVisibilitySnapshot().diagnosticsVisible || (Number(state.images?.length) || 0) > 0;
}

function syncRuntimeStatusAffordances() {
  const showEngineStatus = runtimeChromeShouldShowEngineStatus();
  if (els.engineStatus) {
    els.engineStatus.classList.toggle("hidden", !showEngineStatus);
    els.engineStatus.setAttribute("aria-hidden", showEngineStatus ? "false" : "true");
  }

  const showSelectionStatus = runtimeChromeShouldShowSelectionStatus();
  if (els.juggernautSelectionStatus) {
    els.juggernautSelectionStatus.classList.toggle("hidden", !showSelectionStatus);
    els.juggernautSelectionStatus.setAttribute("aria-hidden", showSelectionStatus ? "false" : "true");
  }
}

let lastRuntimeChromeSignature = "";

function syncRuntimeChromeMenuToggles() {
  const visibility = runtimeChromeVisibilitySnapshot();
  if (els.runtimePinAssistantToggle) {
    els.runtimePinAssistantToggle.checked = visibility.pinAssistant;
    els.runtimePinAssistantToggle.setAttribute("aria-checked", visibility.pinAssistant ? "true" : "false");
  }
  if (els.runtimeDiagnosticsToggle) {
    els.runtimeDiagnosticsToggle.checked = visibility.showDiagnostics;
    els.runtimeDiagnosticsToggle.setAttribute("aria-checked", visibility.showDiagnostics ? "true" : "false");
  }
}

function applyRuntimeChromeVisibility({ source = "runtime" } = {}) {
  const visibility = runtimeChromeVisibilitySnapshot();
  const signature = [
    visibility.pinAssistant ? "1" : "0",
    visibility.assistantVisible ? "1" : "0",
    visibility.showDiagnostics ? "1" : "0",
    visibility.diagnosticsVisible ? "1" : "0",
  ].join(":");
  const changed = signature !== lastRuntimeChromeSignature;

  if (els.topMetricsRoot) els.topMetricsRoot.classList.toggle("hidden", !visibility.diagnosticsVisible);
  if (els.hud) els.hud.classList.toggle("hidden", !visibility.diagnosticsVisible);
  if (els.fileBrowserDock) els.fileBrowserDock.classList.toggle("hidden", !visibility.diagnosticsVisible);
  syncPortraitDockVisibility();
  syncRuntimeStatusAffordances();
  syncRuntimeChromeMenuToggles();

  if (changed) {
    lastRuntimeChromeSignature = signature;
    syncJuggernautShellState();
    syncBrandStripHeightVar();
    syncHudHeightVar();
    refreshAgentPortraitVideos().catch(() => {});
    dispatchJuggernautShellEvent("juggernaut:runtime-visibility-changed", {
      source,
      runtimeVisibility: visibility,
    });
  }
  return visibility;
}

function setRuntimeChromeVisibility(next = {}, { source = "runtime" } = {}) {
  const prefs = runtimeChromeState();
  let changed = false;

  if (Object.prototype.hasOwnProperty.call(next, "pinAssistant")) {
    const value = Boolean(next.pinAssistant);
    if (prefs.pinAssistant !== value) {
      prefs.pinAssistant = value;
      writeJuggernautRuntimeChromePreference(JUGGERNAUT_RUNTIME_PIN_ASSISTANT_LS_KEY, value);
      changed = true;
    }
  }

  if (Object.prototype.hasOwnProperty.call(next, "showDiagnostics")) {
    const value = Boolean(next.showDiagnostics);
    if (prefs.showDiagnostics !== value) {
      prefs.showDiagnostics = value;
      writeJuggernautRuntimeChromePreference(JUGGERNAUT_RUNTIME_SHOW_DIAGNOSTICS_LS_KEY, value);
      changed = true;
    }
  }

  if (!changed) {
    syncRuntimeChromeMenuToggles();
    return runtimeChromeVisibilitySnapshot();
  }
  return applyRuntimeChromeVisibility({ source });
}

function syncJuggernautShellState() {
  const active = getActiveImage();
  state.juggernautShell.selectedImageId = active?.id || null;
  state.juggernautShell.selectedImageIds = getSelectedIds().slice(0, 3);
  state.juggernautShell.selectedImage = active
    ? {
        id: active.id,
        path: active.path,
        name: basename(active.path),
        width: active?.img?.naturalWidth || active?.width || null,
        height: active?.img?.naturalHeight || active?.height || null,
      }
    : null;
  state.juggernautShell.runtimeVisibility = runtimeChromeVisibilitySnapshot();
  if (typeof window !== "undefined") {
    window.__juggernautShellState = state.juggernautShell;
    if (window.__JUGGERNAUT_SHELL__) {
      window.__JUGGERNAUT_SHELL__.railContract = state.juggernautShell.singleImageRail.contract;
      window.__JUGGERNAUT_SHELL__.singleImageRail = {
        contract: state.juggernautShell.singleImageRail.contract,
        adapter: { ...state.juggernautShell.singleImageRail.adapter },
        mock: Boolean(state.juggernautShell.singleImageRail.mock),
        recentSuccessfulJobs: singleImageRailRecentSuccessfulJobs(),
        visibleJobs: state.juggernautShell.singleImageRail.visibleJobs.map((job) => ({ ...job })),
      };
      window.__JUGGERNAUT_SHELL__.runtimeVisibility = state.juggernautShell.runtimeVisibility;
      window.__JUGGERNAUT_SHELL__.communicationReview = {
        ...(window.__JUGGERNAUT_SHELL__.communicationReview || {}),
        state: buildCommunicationBridgeSnapshot(),
      };
    }
  }
  queueNativeSystemMenuSync();
}

function getSelectedIds() {
  const raw = Array.isArray(state.selectedIds) ? state.selectedIds : [];
  const out = [];
  for (const id of raw) {
    const key = String(id || "").trim();
    if (!key) continue;
    if (!out.includes(key)) out.push(key);
  }
  const active = String(state.activeId || "").trim();
  if (active && !out.includes(active)) out.push(active);
  return out;
}

function isVisibleCanvasImageId(imageId) {
  const id = String(imageId || "").trim();
  if (!id) return false;
  if (!state.imagesById.has(id)) return false;
  return !isImageEffectTokenized(id);
}

function getVisibleCanvasImages() {
  return (state.images || []).filter((item) => isVisibleCanvasImageId(item?.id));
}

function getVisibleSelectedIds() {
  return getSelectedIds().filter((id) => isVisibleCanvasImageId(id));
}

function getVisibleActiveId() {
  const activeId = String(state.activeId || "").trim();
  if (!activeId) return null;
  return isVisibleCanvasImageId(activeId) ? activeId : null;
}

function setSelectedIds(nextIds) {
  const out = [];
  for (const id of Array.isArray(nextIds) ? nextIds : []) {
    const key = String(id || "").trim();
    if (!key) continue;
    if (!out.includes(key)) out.push(key);
  }
  state.selectedIds = out;
  syncJuggernautShellState();
}

function selectedCount() {
  return getSelectedImages().length;
}

function getSelectedImages({ requireCount = null } = {}) {
  const ids = getSelectedIds();
  const items = ids.map((id) => state.imagesById.get(id)).filter(Boolean);
  if (typeof requireCount === "number") {
    if (items.length !== requireCount) return [];
  }
  return items;
}

function getSelectedImagesActiveFirst({ requireCount = null } = {}) {
  const selected = getSelectedImages();
  const active = getActiveImage();
  if (active?.id) {
    const ordered = [active, ...selected.filter((item) => item?.id && item.id !== active.id)];
    if (typeof requireCount === "number") {
      if (ordered.length !== requireCount) return [];
    }
    return ordered;
  }
  if (typeof requireCount === "number") {
    if (selected.length !== requireCount) return [];
  }
  return selected;
}

function effectTokenForImageId(imageId) {
  const id = String(imageId || "").trim();
  if (!id) return null;
  const tokenId = state.imageEffectTokenByImageId.get(id);
  if (!tokenId) return null;
  const token = state.effectTokensById.get(tokenId) || null;
  if (!token) {
    state.imageEffectTokenByImageId.delete(id);
    return null;
  }
  return token;
}

function isImageEffectTokenized(imageId) {
  const token = effectTokenForImageId(imageId);
  if (!token) return false;
  return String(token.lifecycle || "") !== EFFECT_TOKEN_LIFECYCLE.CONSUMED;
}

function clearEffectTokenForImageId(imageId) {
  const id = String(imageId || "").trim();
  if (!id) return;
  const tokenId = state.imageEffectTokenByImageId.get(id);
  state.imageEffectTokenByImageId.delete(id);
  if (!tokenId) return;
  const token = state.effectTokensById.get(tokenId) || null;
  if (!token) return;
  // Keep other bindings if this token was intentionally shared.
  const stillUsed = Array.from(state.imageEffectTokenByImageId.values()).some((boundId) => String(boundId) === String(tokenId));
  if (!stillUsed) {
    state.effectTokensById.delete(tokenId);
    state.effectTokenApplyLocks.delete(String(tokenId));
  }
}

function clearAllEffectTokens() {
  state.imageEffectTokenByImageId.clear();
  state.effectTokensById.clear();
  state.effectTokenApplyLocks.clear();
  state.effectTokenDrag = null;
}

function syncSelectionForTokenizedImages() {
  const selected = getSelectedIds();
  const visibleSelected = selected.filter((id) => isVisibleCanvasImageId(id));
  if (visibleSelected.length !== selected.length) {
    setSelectedIds(visibleSelected.slice(-3));
  }

  const activeId = String(state.activeId || "").trim();
  if (activeId && isVisibleCanvasImageId(activeId)) return;
  const fallbackSelected = visibleSelected[visibleSelected.length - 1] || null;
  const fallbackAny = getVisibleCanvasImages().slice(-1)[0]?.id || null;
  state.activeId = String(fallbackSelected || fallbackAny || "").trim() || null;
}

function createOrUpdateEffectToken({
  type,
  imageId,
  imagePath,
  palette = [],
  colors = [],
  materials = [],
  emotion = "",
  summary = "",
  source = null,
  model = null,
} = {}) {
  const imageKey = String(imageId || "").trim();
  const tokenType = String(type || "").trim();
  if (!imageKey || !tokenType) return null;
  const existing = effectTokenForImageId(imageKey);
  const tokenId = existing?.id || `fx-${tokenType}-${Date.now()}-${Math.random().toString(16).slice(2, 8)}`;
  const next = createEffectTokenState({
    id: tokenId,
    type: tokenType,
    sourceImageId: imageKey,
    sourceImagePath: String(imagePath || ""),
    palette,
    colors,
    materials,
    emotion,
    summary,
    source,
    model,
    createdAt: existing?.createdAt || Date.now(),
  });
  if (!next) return null;
  state.effectTokensById.set(tokenId, next);
  state.imageEffectTokenByImageId.set(imageKey, tokenId);
  state.effectTokenApplyLocks.delete(tokenId);
  syncSelectionForTokenizedImages();
  renderQuickActions();
  renderHudReadout();
  renderSelectionMeta();
  return next;
}

function effectTokenLabel(token) {
  const type = String(token?.type || "").trim();
  if (type === "extract_dna") return "Extract DNA";
  if (type === "soul_leech") return "Soul Leech";
  return "Effect";
}

function buildEffectTokenEditPrompt(token) {
  const type = String(token?.type || "").trim();
  if (type === "extract_dna") {
    const palette = Array.isArray(token?.palette) ? token.palette.filter(Boolean).slice(0, 6) : [];
    const colors = Array.isArray(token?.colors) ? token.colors.filter(Boolean).slice(0, 6) : [];
    const materials = Array.isArray(token?.materials) ? token.materials.filter(Boolean).slice(0, 6) : [];
    const summary = String(token?.summary || "").trim();
    const parts = [];
    if (summary) parts.push(summary);
    if (palette.length) parts.push(`palette anchors: ${palette.join(", ")}`);
    if (colors.length) parts.push(`dominant colors: ${colors.join(", ")}`);
    if (materials.length) parts.push(`dominant materials/textures: ${materials.join(", ")}`);
    const transfer = parts.length ? parts.join(". ") : "transfer the extracted color and material DNA";
    return (
      "edit the image in place. keep the target subject class, silhouette, geometry, and object boundaries unchanged. " +
      `apply the extracted dna as style/material transfer only: ${transfer}. ` +
      "dna is metaphorical here, not literal content. " +
      "Do not replace the target with the source subject. Do not turn the subject into a DNA strand, helix, genome icon, or abstract ribbon. " +
      "No collage, no split-screen, no double exposure, no extra humans/faces unless already present, no text overlays."
    );
  }
  if (type === "soul_leech") {
    const emotion = String(token?.emotion || "").trim();
    const summary = String(token?.summary || "").trim();
    const essence = summary || (emotion ? `make the scene emotionally ${emotion}` : "shift the image to the extracted emotional tone");
    return (
      `edit the image: ${essence}. Keep scene geometry coherent and photorealistic. ` +
      "Preserve core subject identity and materials unless the emotional change requires subtle lighting/color shifts. " +
      "No collage, no split-screen, no double exposure, no text overlays."
    );
  }
  return "edit the image: refine the image with the selected effect token. Output one coherent image.";
}

async function applyEffectTokenToImage(tokenId, targetId, { fromQueue = false, dispatchId = null } = {}) {
  const dispatchIdOverride = Number(dispatchId) || null;
  const tokenKey = String(tokenId || "").trim();
  const targetKey = String(targetId || "").trim();
  const token = state.effectTokensById.get(tokenKey) || null;
  if (!requireIntentUnlocked()) {
    state.effectTokenApplyLocks.delete(tokenKey);
    if (token && String(token.lifecycle || "") === EFFECT_TOKEN_LIFECYCLE.APPLYING) {
      recoverEffectTokenApply(token);
      requestRender();
    }
    return false;
  }
  const target = state.imagesById.get(targetKey) || null;
  if (!token || !target?.path) {
    state.effectTokenApplyLocks.delete(tokenKey);
    if (token && String(token.lifecycle || "") === EFFECT_TOKEN_LIFECYCLE.APPLYING) {
      recoverEffectTokenApply(token);
      requestRender();
    }
    showToast("Effect apply failed: missing token or target image.", "error", 2600);
    return false;
  }
  if (!isValidEffectDrop(token.sourceImageId, target.id)) {
    state.effectTokenApplyLocks.delete(tokenKey);
    if (String(token.lifecycle || "") === EFFECT_TOKEN_LIFECYCLE.APPLYING) {
      recoverEffectTokenApply(token);
      requestRender();
    }
    showToast("Drop this token onto a different image.", "tip", 1800);
    return false;
  }

  let lock = state.effectTokenApplyLocks.get(tokenKey) || null;
  if (dispatchIdOverride && lock && Number(lock.dispatchId) !== dispatchIdOverride) {
    return false;
  }
  if (dispatchIdOverride && !lock) {
    return false;
  }
  if (!lock) {
    const dispatchId = beginEffectTokenApply(token, targetKey, Date.now());
    if (!dispatchId) return false;
    lock = {
      dispatchId,
      targetImageId: targetKey,
      queued: false,
      startedAt: Date.now(),
    };
    state.effectTokenApplyLocks.set(tokenKey, lock);
    requestRender();
  }
  if (!effectTokenCanDispatchApply(token, lock.dispatchId, targetKey)) {
    return false;
  }

  const actionLabel = effectTokenLabel(token);
  const queueKey = `effect_apply:${token.id}:${target.id}`;
  if (!fromQueue && (isEngineBusy() || state.actionQueueActive || state.actionQueue.length)) {
    lock.queued = true;
    enqueueAction({
      label: `${actionLabel} Apply`,
      key: queueKey,
      priority: ACTION_QUEUE_PRIORITY.user,
      run: () => applyEffectTokenToImage(token.id, target.id, { fromQueue: true, dispatchId: lock.dispatchId }),
    });
    return true;
  }

  lock.queued = false;
  bumpInteraction({ semantic: false });
  await ensureRun();
  const provider = providerFromModel(
    token.type === "soul_leech" ? ACTION_IMAGE_MODEL.soul_leech_apply : ACTION_IMAGE_MODEL.extract_dna_apply
  );
  setImageFxActive(true, `${actionLabel} Apply`);
  portraitWorking(`${actionLabel} Apply`, { providerOverride: provider || "gemini" });
  beginPendingReplace(target.id, `${actionLabel} Apply`, {
    mode: "effect_token_apply",
    effect_token_id: token.id,
    effect_type: token.type,
    source_image_id: token.sourceImageId || null,
    effect_token_dispatch_id: lock.dispatchId,
  });

  try {
    const ok = await ensureEngineSpawned({ reason: `${actionLabel} apply` });
    if (!ok) throw new Error("Engine unavailable");
    await setEngineActiveImage(target.path);
    const desiredModel = token.type === "soul_leech" ? ACTION_IMAGE_MODEL.soul_leech_apply : ACTION_IMAGE_MODEL.extract_dna_apply;
    await maybeOverrideEngineImageModel(desiredModel || pickGeminiFastImageModel());
    state.expectingArtifacts = true;
    state.lastAction = `${actionLabel} Apply`;
    setStatus(`Engine: ${actionLabel.toLowerCase()} apply…`);
    showToast(`${actionLabel}: applying to ${target.label || basename(target.path)}…`, "info", 2200);

    const prompt = buildEffectTokenEditPrompt(token);
    await invoke("write_pty", { data: `${prompt}\n` });
    return true;
  } catch (err) {
    state.expectingArtifacts = false;
    state.engineImageModelRestore = null;
    clearPendingReplace();
    state.effectTokenApplyLocks.delete(tokenKey);
    recoverEffectTokenApply(token);
    setImageFxActive(false);
    updatePortraitIdle();
    requestRender();
    throw err;
  }
}

function effectTokenGlyphSizeForRect(rect) {
  const w = Number(rect?.w) || 0;
  const h = Number(rect?.h) || 0;
  return clamp(Math.min(w, h) * 0.35, 40, 116);
}

function effectTokenDisplaySizeForRect(rect, effectType) {
  const normalized = effectTypeFromTokenType(effectType || "extract_dna");
  const base = effectTokenGlyphSizeForRect(rect);
  if (normalized === "extract_dna") return clamp(base * 1.75, 70, 203);
  return base;
}

function effectTokenDefaultDragSize(effectType) {
  const normalized = effectTypeFromTokenType(effectType || "extract_dna");
  return normalized === "extract_dna" ? 130 : 74;
}

async function animateThenApplyEffectToken({
  tokenId,
  targetImageId,
  dispatchId,
  fromX,
  fromY,
} = {}) {
  const token = state.effectTokensById.get(String(tokenId || "").trim()) || null;
  const targetId = String(targetImageId || "").trim();
  if (!token || !targetId) return;
  const targetRect = state.multiRects.get(targetId) || null;
  if (effectsRuntime && targetRect) {
    const transform = getMultiViewTransform();
    const targetScreenRect = multiRectToScreenRect(targetRect, transform);
    const effectType = effectTypeFromTokenType(token.type);
    await effectsRuntime.playDropIntoTarget({
      tokenId: token.id,
      effectType,
      fromX: Number(fromX) || 0,
      fromY: Number(fromY) || 0,
      targetRect: targetScreenRect,
      size: effectTokenDisplaySizeForRect(targetScreenRect, effectType),
      data: token,
    });
  }

  const current = state.effectTokensById.get(String(tokenId || "").trim()) || null;
  if (!current) return;
  if (!effectTokenCanDispatchApply(current, dispatchId, targetId)) return;
  try {
    await applyEffectTokenToImage(current.id, targetId, { dispatchId: Number(dispatchId) || 0 });
  } catch (err) {
    console.error(err);
    state.effectTokenApplyLocks.delete(String(current.id));
    recoverEffectTokenApply(current);
    showToast(err?.message || "Effect apply failed.", "error", 2600);
    requestRender();
    return;
  }
}

async function runExtractDnaFromSelection({ fromQueue = false } = {}) {
  if (!requireIntentUnlocked()) return;
  const selected = getSelectedImages();
  if (!selected.length) {
    showToast("Extract DNA needs at least one selected image.", "tip", 2400);
    return;
  }
  const sources = selected.filter((item) => item?.path);
  if (!sources.length) {
    showToast("Extract DNA failed: missing image paths.", "error", 2600);
    return;
  }
  if (!fromQueue && (isEngineBusy() || isMultiActionRunning() || state.actionQueueActive || state.actionQueue.length)) {
    const sig = sources.map((item) => String(item.id || "")).join(",");
    enqueueAction({
      label: "Extract DNA",
      key: `extract_dna:${sig}`,
      priority: ACTION_QUEUE_PRIORITY.user,
      run: () => runExtractDnaFromSelection({ fromQueue: true }),
    });
    return;
  }

  bumpInteraction();
  if (!state.runDir) await ensureRun();
  const okEngine = await ensureEngineSpawned({ reason: "extract dna" });
  if (!okEngine) return;
  for (const src of sources) {
    if (src?.id) clearEffectTokenForImageId(src.id);
  }
  state.pendingExtractDna = createPendingEffectExtractionState(sources);
  state.lastAction = "Extract DNA";
  setStatus("Director: extracting DNA…");
  portraitWorking("Extract DNA", { providerOverride: "openai", clearDirector: false });
  if (!suppressReelDnaToasts()) {
    showToast("Extracting DNA from selected image(s)…", "info", 2200);
  }
  renderQuickActions();
  requestRender();

  const args = sources.map((item) => quoteForPtyArg(item.path)).join(" ");
  try {
    await invoke("write_pty", { data: `${PTY_COMMANDS.EXTRACT_DNA} ${args}\n` });
    bumpSessionApiCalls();
  } catch (err) {
    console.error(err);
    state.pendingExtractDna = null;
    setStatus(`Director: extract dna failed (${err?.message || err})`, true);
    showToast("Extract DNA failed to start.", "error", 3200);
    updatePortraitIdle();
    renderQuickActions();
  }
}

