const CREATE_LAYERS_CHROMA_KEY = Object.freeze({
  r: 0,
  g: 255,
  b: 0,
  tolerance: 38,
  feather: 14,
});

function createSemanticLayerSpecs(imgItem = null) {
  const sourceLabel = String(imgItem?.label || basename(imgItem?.path || "") || "the source image").trim();
  return [
    {
      key: "background",
      label: "Layer 1/3 - Background",
      summary: "background only",
      applyChromaKey: false,
      prompt:
        `edit the image: remove all foreground subjects and handheld props, and reconstruct only the clean background from ${sourceLabel}. ` +
        "keep exact framing and dimensions. output one image. no text, no logos, no collage.",
    },
    {
      key: "subject",
      label: "Layer 2/3 - Main Subject",
      summary: "main subject",
      applyChromaKey: true,
      prompt:
        "edit the image: isolate only the main subject (usually the primary person or hero object). " +
        "exclude detachable props such as balls, tools, bags, instruments, and accessories. " +
        "replace everything else with a flat solid #00FF00 background (pure chroma green), no gradient, no texture, no shadow. " +
        "keep exact framing and dimensions. output one image with clean edges. no text or logos.",
    },
    {
      key: "props",
      label: "Layer 3/3 - Key Props",
      summary: "detachable props",
      applyChromaKey: true,
      prompt:
        "edit the image: isolate only detachable foreground props (for example balls, tools, bags, instruments, accessories). " +
        "remove the main subject. replace everything else with a flat solid #00FF00 background (pure chroma green), no gradient, no texture, no shadow. " +
        "if no detachable props exist, return a full #00FF00 image. keep exact framing and dimensions. output one image with clean edges. no text or logos.",
    },
  ];
}

function applyChromaKeyToCreateLayerCanvas(canvas, chroma = CREATE_LAYERS_CHROMA_KEY) {
  const ctx = canvas?.getContext?.("2d", { willReadFrequently: true });
  const w = Math.max(1, Number(canvas?.width) || 0);
  const h = Math.max(1, Number(canvas?.height) || 0);
  if (!ctx || !w || !h) {
    return { transparent_px: 0, softened_px: 0, total_px: 0 };
  }
  const imageData = ctx.getImageData(0, 0, w, h);
  const data = imageData.data;
  const targetR = clamp(Math.round(Number(chroma?.r) || 0), 0, 255);
  const targetG = clamp(Math.round(Number(chroma?.g) || 0), 0, 255);
  const targetB = clamp(Math.round(Number(chroma?.b) || 0), 0, 255);
  const tol = clamp(Number(chroma?.tolerance) || 38, 0, 255);
  const feather = clamp(Number(chroma?.feather) || 14, 0, 255);
  let transparentPx = 0;
  let softenedPx = 0;

  for (let i = 0; i < data.length; i += 4) {
    const alpha = data[i + 3];
    if (!alpha) continue;
    const dr = data[i] - targetR;
    const dg = data[i + 1] - targetG;
    const db = data[i + 2] - targetB;
    const dist = Math.sqrt(dr * dr + dg * dg + db * db);
    if (dist <= tol) {
      data[i + 3] = 0;
      transparentPx += 1;
      continue;
    }
    if (feather > 0 && dist <= tol + feather) {
      const keep = (dist - tol) / feather;
      const nextAlpha = Math.max(0, Math.min(255, Math.round(alpha * keep)));
      if (nextAlpha < alpha) {
        data[i + 3] = nextAlpha;
        softenedPx += 1;
        if (nextAlpha === 0) transparentPx += 1;
      }
    }
  }
  ctx.putImageData(imageData, 0, 0);
  return {
    transparent_px: transparentPx,
    softened_px: softenedPx,
    total_px: w * h,
  };
}

async function dispatchCreateLayersPass() {
  const pending = state.pendingCreateLayers;
  if (!pending) return false;
  const idx = Math.max(0, Number(pending.nextIndex) || 0);
  const specs = Array.isArray(pending.layerSpecs) ? pending.layerSpecs : [];
  const spec = specs[idx];
  if (!spec) return false;

  const okEngine = await ensureEngineSpawned({ reason: "create layers" });
  if (!okEngine) throw new Error("Engine unavailable");
  await setEngineActiveImage(pending.sourcePath);
  await maybeOverrideEngineImageModel(ACTION_IMAGE_MODEL.create_layers || pickGeminiImageModel());

  state.expectingArtifacts = true;
  state.lastAction = "Create Layers";
  setStatus(`Director: creating layers (${idx + 1}/${specs.length})…`);
  showToast(`Create Layers: generating ${spec.summary}…`, "info", 1800);
  await invoke("write_pty", { data: `${spec.prompt}\n` });
  return true;
}

function finishCreateLayersFailure(message) {
  state.pendingCreateLayers = null;
  state.expectingArtifacts = false;
  restoreEngineImageModelIfNeeded();
  setImageFxActive(false);
  updatePortraitIdle();
  clearRunningAction("create_layers");
  setStatus(`Director: ${message}`, true);
  showToast(message, "error", 3600);
  renderQuickActions();
  renderHudReadout();
  processActionQueue().catch(() => {});
}

async function handleCreateLayersArtifact(event) {
  const pending = state.pendingCreateLayers;
  if (!pending) return false;
  const artifactId = String(event?.artifact_id || "").trim();
  const imagePath = String(event?.image_path || "").trim();
  if (!artifactId || !imagePath) return false;
  const receiptPath = event?.receipt_path ? String(event.receipt_path) : null;
  const idx = Math.max(0, Number(pending.nextIndex) || 0);
  const specs = Array.isArray(pending.layerSpecs) ? pending.layerSpecs : [];
  const spec = specs[idx] || null;
  if (!spec) return false;

  try {
    const generated = await loadImage(imagePath);
    const w = Math.max(1, Number(generated?.naturalWidth) || 0);
    const h = Math.max(1, Number(generated?.naturalHeight) || 0);
    if (!w || !h) throw new Error("layer artifact dimensions unavailable");

    const out = document.createElement("canvas");
    out.width = w;
    out.height = h;
    const outCtx = out.getContext("2d");
    outCtx.drawImage(generated, 0, 0, w, h);
    const chromaStats = spec.applyChromaKey ? applyChromaKeyToCreateLayerCanvas(out) : null;

    await saveCanvasAsArtifact(out, {
      operation: `create_layers_${String(spec.key || "layer")}`,
      label: String(spec.label || `Layer ${idx + 1}/${specs.length}`),
      meta: {
        source_image_id: String(pending.sourceId || ""),
        source_image_path: String(pending.sourcePath || ""),
        layer_index: idx + 1,
        layer_count: specs.length,
        layer_key: String(spec.key || ""),
        semantic_description: String(spec.summary || ""),
        chroma_key_hex: spec.applyChromaKey ? "#00FF00" : null,
        chroma_key_stats: chromaStats,
        engine_artifact_id: artifactId,
        engine_receipt_path: receiptPath,
        recomposition_note: "Stack in order: Background -> Main Subject -> Key Props.",
      },
      replaceActive: false,
      parentImageId: pending.sourceId,
      select: false,
    });
    const created = state.images[state.images.length - 1];
    if (created?.id) pending.createdIds.push(String(created.id));
    removeFile(imagePath).catch(() => {});
    if (receiptPath) removeFile(receiptPath).catch(() => {});

    pending.nextIndex = idx + 1;
    if (pending.nextIndex < specs.length) {
      await dispatchCreateLayersPass();
      return true;
    }

    const createdIds = Array.isArray(pending.createdIds) ? pending.createdIds.slice(0, 3) : [];
    state.pendingCreateLayers = null;
    state.expectingArtifacts = false;
    restoreEngineImageModelIfNeeded();
    setImageFxActive(false);
    updatePortraitIdle();
    clearRunningAction("create_layers");
    if (createdIds.length) {
      setSelectedIds(createdIds.slice(-3));
      await setActiveImage(createdIds[0], { preserveSelection: true }).catch(() => {});
    }
    setStatus("Director: layers ready");
    showToast(`Create Layers complete: ${createdIds.length} semantic layers generated.`, "tip", 2800);
    renderQuickActions();
    renderHudReadout();
    requestRender();
    processActionQueue().catch(() => {});
    return true;
  } catch (err) {
    console.error(err);
    finishCreateLayersFailure(`Create Layers failed (${err?.message || err}).`);
    return true;
  }
}

async function runCreateLayersFromSelection({ fromQueue = false } = {}) {
  if (!requireIntentUnlocked()) return;
  const selected = getSelectedImagesActiveFirst({ requireCount: 1 });
  const imgItem = selected.length === 1 ? selected[0] : null;
  if (!imgItem?.path) {
    showToast("Create Layers needs exactly one selected image.", "tip", 2400);
    return;
  }
  if (state.pendingCreateLayers) {
    showToast("Create Layers is already running.", "tip", 2200);
    return;
  }

  if (!fromQueue && (isEngineBusy() || state.actionQueueActive || state.actionQueue.length)) {
    enqueueAction({
      label: "Create Layers",
      key: `create_layers:${String(imgItem.id || "")}`,
      priority: ACTION_QUEUE_PRIORITY.user,
      run: () => runCreateLayersFromSelection({ fromQueue: true }),
    });
    return;
  }

  bumpInteraction();
  await ensureRun();
  beginRunningAction("create_layers");
  setImageFxActive(true, "Create Layers");
  state.lastAction = "Create Layers";
  setStatus("Director: creating layers…");
  portraitWorking("Create Layers", {
    providerOverride: providerFromModel(ACTION_IMAGE_MODEL.create_layers) || "gemini",
    clearDirector: false,
  });
  showToast("Splitting image into semantic layers…", "info", 2200);
  renderQuickActions();
  requestRender();

  try {
    if (!imgItem.img) {
      imgItem.img = await loadImage(imgItem.path);
      imgItem.width = imgItem.img?.naturalWidth || imgItem.width || null;
      imgItem.height = imgItem.img?.naturalHeight || imgItem.height || null;
    }
    const specs = createSemanticLayerSpecs(imgItem);
    if (!specs.length) throw new Error("no layer specs configured");
    state.pendingCreateLayers = {
      sourceId: String(imgItem.id || ""),
      sourcePath: String(imgItem.path || ""),
      layerSpecs: specs,
      nextIndex: 0,
      createdIds: [],
      startedAt: Date.now(),
    };
    await dispatchCreateLayersPass();
  } catch (err) {
    console.error(err);
    finishCreateLayersFailure(`Create Layers failed (${err?.message || err}).`);
  }
}

function consumePendingEffectExtraction(kind, imagePath) {
  const path = String(imagePath || "").trim();
  const isSoul = String(kind || "") === "soul";
  const pending = isSoul ? state.pendingSoulLeech : state.pendingExtractDna;
  if (!pending) return null;
  if (!path) return null;
  const { matchedImageId, unresolvedCount } = consumePendingEffectSourceSlot(pending, path, Date.now());
  if (unresolvedCount === 0) {
    if (isSoul) state.pendingSoulLeech = null;
    else state.pendingExtractDna = null;
    setStatus(isSoul ? "Director: soul extraction ready" : "Director: dna extraction ready");
    updatePortraitIdle();
    renderQuickActions();
    processActionQueue().catch(() => {});
  }

  return matchedImageId;
}

function resolveExtractionEventImageIdByPath(imagePath) {
  const path = String(imagePath || "").trim();
  if (!path) return null;

  const activeId = String(state.activeId || "").trim();
  if (activeId) {
    const active = state.imagesById.get(activeId) || null;
    if (active?.path && String(active.path) === path) return activeId;
  }

  const selected = getSelectedIds().map((id) => String(id || "").trim()).filter(Boolean);
  for (const id of selected) {
    const item = state.imagesById.get(id) || null;
    if (item?.path && String(item.path) === path) return id;
  }

  const z = Array.isArray(state.freeformZOrder) ? state.freeformZOrder.slice().reverse() : [];
  for (const rawId of z) {
    const id = String(rawId || "").trim();
    if (!id) continue;
    const item = state.imagesById.get(id) || null;
    if (item?.path && String(item.path) === path) return id;
  }

  const images = Array.isArray(state.images) ? state.images.slice().reverse() : [];
  for (const item of images) {
    const id = String(item?.id || "").trim();
    if (!id) continue;
    if (item?.path && String(item.path) === path) return id;
  }
  return null;
}

function pendingEffectUnresolvedSlots(pending) {
  if (!pending || typeof pending !== "object") return [];
  const slots = Array.isArray(pending.sourceSlots) ? pending.sourceSlots : [];
  return slots.filter((slot) => slot && !slot.resolved);
}

function pendingExtractionKindForImageId(imageId) {
  const id = String(imageId || "").trim();
  if (!id) return null;
  const dnaPending = pendingEffectUnresolvedSlots(state.pendingExtractDna).some(
    (slot) => String(slot.imageId || "").trim() === id
  );
  if (dnaPending) return "extract_dna";
  const soulPending = pendingEffectUnresolvedSlots(state.pendingSoulLeech).some(
    (slot) => String(slot.imageId || "").trim() === id
  );
  if (soulPending) return "soul_leech";
  return null;
}

function shouldAnimateEffectVisuals() {
  if (state.canvasMode !== "multi") return false;
  if (pendingEffectUnresolvedSlots(state.pendingExtractDna).length) return true;
  if (pendingEffectUnresolvedSlots(state.pendingSoulLeech).length) return true;
  for (const token of state.effectTokensById.values()) {
    if (!token) continue;
    const life = String(token.lifecycle || "");
    if (life === EFFECT_TOKEN_LIFECYCLE.CONSUMED) continue;
    return true;
  }
  return false;
}

function shouldAnimateDesignReviewApplyShimmer() {
  return String(state.designReviewApply?.status || "").trim().toLowerCase() === "running";
}

function renderDesignReviewApplyShimmerPath(octx, points = [], { emphasis = "target", elapsedMs = 0 } = {}) {
  if (!octx || !Array.isArray(points) || points.length < 3) return false;
  const xs = points.map((point) => Number(point?.x) || 0);
  const ys = points.map((point) => Number(point?.y) || 0);
  const minX = Math.min(...xs);
  const maxX = Math.max(...xs);
  const minY = Math.min(...ys);
  const maxY = Math.max(...ys);
  const width = Math.max(1, maxX - minX);
  const height = Math.max(1, maxY - minY);
  const dpr = getDpr();
  const shimmerProgress =
    (Math.max(0, Number(elapsedMs) || 0) % DESIGN_REVIEW_APPLY_SHIMMER_LOOP_MS) /
    DESIGN_REVIEW_APPLY_SHIMMER_LOOP_MS;
  const pulse = 0.5 + 0.5 * Math.sin((Math.max(0, Number(elapsedMs) || 0) / 1000) * Math.PI * 2 * 0.72);
  const sweepCenter = minX + (width + height * 1.4) * shimmerProgress - height * 0.7;
  const isTarget = emphasis === "target";

  octx.save();
  octx.globalCompositeOperation = "source-over";
  if (drawPolygonPath(octx, points)) {
    octx.fillStyle = isTarget
      ? `rgba(70, 208, 255, ${(0.08 + pulse * 0.05).toFixed(3)})`
      : `rgba(214, 244, 255, ${(0.08 + pulse * 0.05).toFixed(3)})`;
    octx.fill();
  }
  octx.restore();

  octx.save();
  if (drawPolygonPath(octx, points)) {
    octx.clip();
    const shimmer = octx.createLinearGradient(
      sweepCenter - height * 0.85,
      minY,
      sweepCenter + height * 0.85,
      maxY
    );
    if (isTarget) {
      shimmer.addColorStop(0, "rgba(92, 222, 255, 0)");
      shimmer.addColorStop(0.45, "rgba(164, 244, 255, 0.12)");
      shimmer.addColorStop(0.5, "rgba(236, 252, 255, 0.44)");
      shimmer.addColorStop(0.55, "rgba(164, 244, 255, 0.12)");
      shimmer.addColorStop(1, "rgba(92, 222, 255, 0)");
    } else {
      shimmer.addColorStop(0, "rgba(214, 244, 255, 0)");
      shimmer.addColorStop(0.45, "rgba(232, 250, 255, 0.12)");
      shimmer.addColorStop(0.5, "rgba(248, 253, 255, 0.34)");
      shimmer.addColorStop(0.55, "rgba(232, 250, 255, 0.12)");
      shimmer.addColorStop(1, "rgba(214, 244, 255, 0)");
    }
    octx.fillStyle = shimmer;
    octx.fillRect(
      Math.round(minX - height),
      Math.round(minY),
      Math.round(width + height * 2),
      Math.round(height)
    );
  }
  octx.restore();

  octx.save();
  octx.lineJoin = "round";
  octx.strokeStyle = isTarget
    ? `rgba(94, 232, 255, ${(0.72 + pulse * 0.16).toFixed(3)})`
    : `rgba(212, 244, 255, ${(0.62 + pulse * 0.16).toFixed(3)})`;
  octx.lineWidth = Math.max(1, Math.round((isTarget ? 2.2 : 1.9) * dpr));
  octx.shadowColor = isTarget
    ? `rgba(94, 232, 255, ${(0.26 + pulse * 0.12).toFixed(3)})`
    : `rgba(212, 244, 255, ${(0.20 + pulse * 0.10).toFixed(3)})`;
  octx.shadowBlur = Math.round((isTarget ? 18 : 14) * dpr);
  if (!isTarget) {
    octx.setLineDash([Math.max(2, Math.round(8 * dpr)), Math.max(2, Math.round(6 * dpr))]);
    octx.lineDashOffset = -Math.round(shimmerProgress * Math.max(10, 36 * dpr));
  }
  if (drawPolygonPath(octx, points)) octx.stroke();
  octx.setLineDash([]);
  octx.restore();
  return true;
}

function renderDesignReviewApplyShimmer(octx) {
  if (!octx || !shouldAnimateDesignReviewApplyShimmer()) return;
  const apply = state.designReviewApply || null;
  const imageIds = uniqueStringList(
    [
      readFirstString(apply?.targetImageId),
      ...(Array.isArray(apply?.referenceImageIds) ? apply.referenceImageIds : []),
    ],
    { exclude: [""] }
  );
  if (!imageIds.length) return;
  const startedAt = Number(apply?.startedAt) || Date.now();
  const elapsedMs = Math.max(0, Date.now() - startedAt);

  if (state.canvasMode === "multi") {
    const ms = Number(state.multiView?.scale) || 1;
    const mox = Number(state.multiView?.offsetX) || 0;
    const moy = Number(state.multiView?.offsetY) || 0;
    for (const imageId of imageIds) {
      const rect = state.multiRects.get(imageId) || null;
      if (!rect) continue;
      const transform = readFreeformRectTransform(state.freeformRects.get(imageId) || null);
      const points = transformedRectPolygonPoints({
        x: rect.x * ms + mox,
        y: rect.y * ms + moy,
        w: rect.w * ms,
        h: rect.h * ms,
        rotateDeg: transform.rotateDeg,
        skewXDeg: transform.skewXDeg,
      });
      renderDesignReviewApplyShimmerPath(octx, points, {
        emphasis: imageId === readFirstString(apply?.targetImageId) ? "target" : "reference",
        elapsedMs,
      });
    }
    return;
  }

  const active = getActiveImage();
  const activeId = String(active?.id || "").trim();
  if (!activeId || !imageIds.includes(activeId) || !active?.img) return;
  const transform = readFreeformRectTransform(state.freeformRects.get(activeId) || null);
  const points = transformedRectPolygonPoints({
    x: state.view.offsetX,
    y: state.view.offsetY,
    w: (active.img.naturalWidth || active.width || 1) * state.view.scale,
    h: (active.img.naturalHeight || active.height || 1) * state.view.scale,
    rotateDeg: transform.rotateDeg,
    skewXDeg: transform.skewXDeg,
  });
  renderDesignReviewApplyShimmerPath(octx, points, {
    emphasis: activeId === readFirstString(apply?.targetImageId) ? "target" : "reference",
    elapsedMs,
  });
}

function buildEffectsRuntimeScene() {
  if (state.canvasMode !== "multi") return { extracting: [], tokens: [], drag: null, draftingGuide: null };
  const transform = getMultiViewTransform();
  const extracting = [];
  const tokens = [];

  for (const [imageId, rect] of state.multiRects.entries()) {
    const screenRect = multiRectToScreenRect(rect, transform);
    if (!screenRect) continue;
    const extractionKind = pendingExtractionKindForImageId(imageId);
    if (extractionKind) {
      extracting.push({
        imageId: String(imageId || ""),
        effectType: extractionKind,
        rect: screenRect,
      });
    }
    const token = effectTokenForImageId(imageId);
    if (!token) continue;
    if (String(token.lifecycle || "") === EFFECT_TOKEN_LIFECYCLE.CONSUMED) continue;
    tokens.push({
      tokenId: String(token.id || ""),
      imageId: String(imageId || ""),
      effectType: effectTypeFromTokenType(token.type),
      lifecycle: String(token.lifecycle || EFFECT_TOKEN_LIFECYCLE.READY),
      rect: screenRect,
      palette: Array.isArray(token.palette) ? token.palette.slice(0, 8) : [],
      colors: Array.isArray(token.colors) ? token.colors.slice(0, 8) : [],
      materials: Array.isArray(token.materials) ? token.materials.slice(0, 8) : [],
      emotion: token.emotion ? String(token.emotion) : "",
      summary: token.summary ? String(token.summary) : "",
      sourceImageId: String(token.sourceImageId || ""),
    });
  }

  let drag = null;
  const dragState = state.effectTokenDrag || null;
  if (dragState) {
    const token = state.effectTokensById.get(String(dragState.tokenId || "").trim()) || null;
    const effectType = effectTypeFromTokenType(token?.type || "extract_dna");
    const targetId = String(dragState.targetImageId || "").trim();
    const targetRect = targetId ? state.multiRects.get(targetId) || null : null;
    const targetScreenRect = targetRect ? multiRectToScreenRect(targetRect, transform) : null;
    drag = {
      tokenId: String(dragState.tokenId || ""),
      effectType,
      x: Number(dragState.x) || 0,
      y: Number(dragState.y) || 0,
      size: targetScreenRect
        ? effectTokenDisplaySizeForRect(targetScreenRect, effectType)
        : effectTokenDefaultDragSize(effectType),
      targetRect: targetScreenRect,
      data: token,
    };
  }

  return { extracting, tokens, drag, draftingGuide: null };
}

function syncEffectsRuntimeScene() {
  if (!effectsRuntime) return;
  const suspended = document.hidden || state.canvasMode !== "multi";
  effectsRuntime.setSuspended(suspended);
  if (suspended) {
    effectsRuntime.syncScene({ extracting: [], tokens: [], drag: null, draftingGuide: null });
    return;
  }
  effectsRuntime.syncScene(buildEffectsRuntimeScene());
}

async function selectCanvasImage(imageId, { toggle = false } = {}) {
  const id = String(imageId || "").trim();
  if (!id) return;
  const item = state.imagesById.get(id) || null;
  if (!item) return;

  const current = getSelectedIds();
  const has = current.includes(id);
  let next = current.slice();

  if (!toggle) {
    next = [id];
  } else if (has) {
    // Keep at least one selected image to avoid entering a confusing "no selection" state.
    if (next.length > 1) next = next.filter((v) => v !== id);
  } else {
    next.push(id);
    // Cap multi-select to 3 images (2/3-image abilities).
    if (next.length > 3) next = next.slice(next.length - 3);
  }

  setSelectedIds(next);
  const nextActive = next.includes(id) ? id : next[next.length - 1] || null;
  invalidateActiveTabPreview("selection_change");
  recordUserEvent("selection_change", {
    canvas_mode: state.canvasMode,
    active_id: nextActive || state.activeId || null,
    selected_ids: next.slice(0, 3),
    toggle: Boolean(toggle),
  });
  if (!nextActive) {
    renderQuickActions();
    renderHudReadout();
    requestRender();
    return;
  }

  if (nextActive === state.activeId) {
    renderQuickActions();
    renderHudReadout();
    requestRender();
    return;
  }

  await setActiveImage(nextActive, { preserveSelection: true }).catch(() => {});
}

function setCanvasMode(_mode) {
  const next = "multi";
  if (state.canvasMode === next) return;
  const prevMode = state.canvasMode;
  state.canvasMode = next;
  markActiveTabUiDirty({ spawn: true, quickActions: true });
  recordUserEvent("canvas_mode_set", { prev: prevMode, next });
  const active = String(state.activeId || "").trim();
  if (active && selectedCount() === 0) setSelectedIds([active]);
  state.multiRects.clear();
  state.multiView.scale = 1;
  state.multiView.offsetX = 0;
  state.multiView.offsetY = 0;
  state.pointer.active = false;
  state.selection = null;
  state.lassoDraft = [];
  state.annotateDraft = null;
  state.annotateBox = null;
  invalidateActiveTabPreview("canvas_mode_change");
  hideAnnotatePanel();
  state.circleDraft = null;
  hideMarkPanel();
  setTool("pan");
  chooseSpawnNodes();
  renderFilmstrip();
  renderSelectionMeta();
  scheduleVisualPromptWrite();
  if (effectsRuntime) effectsRuntime.setSuspended(document.hidden || state.canvasMode !== "multi");
  requestRender();
}

function ensureCanvasImageLoaded(item) {
  if (!item || !item.path) return;
  if (readSessionRuntimeImageHandle(item)) return;
  if (item.img) item.img = null;
  if (item.imgLoading) return;
  item.imgLoading = true;
  loadImage(item.path)
    .then((img) => {
      item.img = img;
      item.width = img?.naturalWidth || null;
      item.height = img?.naturalHeight || null;
      // One-shot: once we know the real aspect ratio, convert square placeholders into
      // aspect-correct freeform rects (keeps the click-to-place flow feeling intentional).
      if (item?.id) {
        const rect = state.freeformRects.get(item.id) || null;
        const iw = item.width;
        const ih = item.height;
        if (rect && rect.autoAspect && iw && ih) {
          const wrap = els.canvasWrap;
          const cw = wrap?.clientWidth || 0;
          const ch = wrap?.clientHeight || 0;
          const settled = settleAutoAspectRectCss(
            rect,
            { width: iw, height: ih },
            {
              canvasCssW: cw,
              canvasCssH: ch,
              clampOptions:
                cw && ch ? freeformWorkspaceClampOptions(cw, ch, { minSize: 44 }) : null,
            }
          );
          rect.x = settled.x;
          rect.y = settled.y;
          rect.w = settled.w;
          rect.h = settled.h;
          rect.autoAspect = settled.autoAspect;
          invalidateActiveTabPreview("image_layout_settle");
          scheduleVisualPromptWrite();
          if (intentModeActive()) {
            scheduleIntentStateWrite();
          }
        }
      }
    })
    .catch((err) => {
      console.warn("Failed to load image for canvas:", err);
    })
    .finally(() => {
      item.imgLoading = false;
      invalidateActiveTabPreview("image_decode_ready");
      requestRender();
    });
}

function freeformDefaultTileCss(canvasCssW, canvasCssH, { count = null } = {}) {
  const isMobile =
    window.matchMedia && typeof window.matchMedia === "function"
      ? window.matchMedia("(max-width: 980px)").matches
      : false;
  const minDim = Math.max(1, Math.min(Number(canvasCssW) || 0, Number(canvasCssH) || 0));
  const n = Math.max(1, Number.isFinite(Number(count)) ? Math.round(Number(count) || 0) : 1);

  // Default import size: bias larger because most sessions start with 1-3 images.
  // Still clamp to avoid overlap in the auto-layout grid.
  let frac = isMobile ? 0.38 : 0.26;
  if (isMobile) {
    if (n <= 1) frac = 0.62;
    else if (n === 2) frac = 0.48;
    else if (n === 3) frac = 0.44;
    else if (n === 4) frac = 0.40;
  } else {
    if (n <= 1) frac = 0.54;
    else if (n === 2) frac = 0.42;
    else if (n === 3) frac = 0.38;
    else if (n === 4) frac = 0.32;
  }

  const base = Math.round(minDim * frac);
  const minPx = isMobile ? 160 : 220;
  const maxPx = isMobile ? (n <= 1 ? 520 : 420) : n <= 1 ? 680 : 560;

  // Ensure the implied grid (based on n) can fit within the canvas.
  const margin = 14;
  const gapFrac = 0.11;
  let cols = 1;
  if (n <= 1) cols = 1;
  else if (n === 2) cols = 2;
  else if (n <= 4) cols = 2;
  else cols = 3;
  const rows = Math.ceil(n / cols);
  const availW = Math.max(1, (Number(canvasCssW) || 0) - margin * 2);
  const availH = Math.max(1, (Number(canvasCssH) || 0) - margin * 2);
  const denomW = cols + Math.max(0, cols - 1) * gapFrac;
  const denomH = rows + Math.max(0, rows - 1) * gapFrac;
  const fitMax = Math.floor(Math.min(availW / Math.max(denomW, 0.0001), availH / Math.max(denomH, 0.0001)));

  return clamp(base, minPx, Math.max(minPx, Math.min(maxPx, fitMax)));
}

function ensureFreeformLayoutRectsCss(items, canvasCssW, canvasCssH) {
  const list = Array.isArray(items) ? items : [];
  if (!list.length) return;
  const tile = freeformDefaultTileCss(canvasCssW, canvasCssH, { count: list.length });
  const gap = Math.round(tile * 0.11);
  const margin = 14;

  // Keep z-order stable: start with import order, allow runtime reordering via state.freeformZOrder.
  for (const item of list) {
    if (!item?.id) continue;
    if (!state.freeformZOrder.includes(item.id)) state.freeformZOrder.push(item.id);
  }

  const missing = list.some((item) => item?.id && !state.freeformRects.has(item.id));
  if (!missing) return;

  const n = list.length;
  let cols = 1;
  if (n <= 1) cols = 1;
  else if (n === 2) cols = 2;
  else if (n <= 4) cols = 2;
  else cols = 3;
  const rows = Math.ceil(n / cols);

  const gridW = cols * tile + (cols - 1) * gap;
  const gridH = rows * tile + (rows - 1) * gap;
  const startX = Math.round((canvasCssW - gridW) * 0.5);
  const startY = Math.round((canvasCssH - gridH) * 0.5);

  for (let i = 0; i < list.length; i += 1) {
    const item = list[i];
    if (!item?.id) continue;
    if (state.freeformRects.has(item.id)) continue;
    const col = i % cols;
    const row = Math.floor(i / cols);
    let x = startX + col * (tile + gap);
    let y = startY + row * (tile + gap);
    x = clamp(Math.round(x), margin, Math.max(margin, Math.round(canvasCssW - tile - margin)));
    y = clamp(Math.round(y), margin, Math.max(margin, Math.round(canvasCssH - tile - margin)));
    state.freeformRects.set(item.id, { x, y, w: tile, h: tile, autoAspect: true });
  }
}

function computeFreeformRectsPx(canvasW, canvasH) {
  const dpr = getDpr();
  const canvasCssW = (Number(canvasW) || 0) / dpr;
  const canvasCssH = (Number(canvasH) || 0) / dpr;
  ensureFreeformLayoutRectsCss(state.images || [], canvasCssW, canvasCssH);

  const rects = new Map();
  for (const imageId of state.freeformZOrder || []) {
    const rectCss = state.freeformRects.get(imageId) || null;
    if (!rectCss) continue;
    rects.set(imageId, {
      x: Math.round((Number(rectCss.x) || 0) * dpr),
      y: Math.round((Number(rectCss.y) || 0) * dpr),
      w: Math.max(1, Math.round((Number(rectCss.w) || 1) * dpr)),
      h: Math.max(1, Math.round((Number(rectCss.h) || 1) * dpr)),
    });
  }
  return rects;
}

function normalizeFreeformRotateDeg(raw) {
  const value = Number(raw);
  if (!Number.isFinite(value)) return 0;
  let out = value % 360;
  if (out > 180) out -= 360;
  if (out <= -180) out += 360;
  return Number(out.toFixed(2));
}

function normalizeFreeformSkewDeg(raw) {
  const value = Number(raw);
  if (!Number.isFinite(value)) return 0;
  return Number(clamp(value, -28, 28).toFixed(2));
}

function readFreeformRectTransform(rectCss = null) {
  return {
    rotateDeg: normalizeFreeformRotateDeg(rectCss?.rotateDeg),
    skewXDeg: normalizeFreeformSkewDeg(rectCss?.skewXDeg),
  };
}

function drawImageRectWithTransform(ctx, img, { x = 0, y = 0, w = 1, h = 1, rotateDeg = 0, skewXDeg = 0 } = {}) {
  if (!ctx || !img) return;
  const rotation = normalizeFreeformRotateDeg(rotateDeg);
  const skew = normalizeFreeformSkewDeg(skewXDeg);
  const rotationRad = (rotation * Math.PI) / 180;
  const skewTan = Math.tan((skew * Math.PI) / 180);
  if (Math.abs(rotation) < 0.001 && Math.abs(skew) < 0.001) {
    ctx.drawImage(img, x, y, w, h);
    return;
  }
  ctx.save();
  ctx.translate(x + w * 0.5, y + h * 0.5);
  if (Math.abs(rotationRad) > 0.00001) ctx.rotate(rotationRad);
  if (Math.abs(skewTan) > 0.00001) ctx.transform(1, 0, skewTan, 1, 0, 0);
  ctx.beginPath();
  ctx.rect(-w * 0.5, -h * 0.5, w, h);
  ctx.clip();
  ctx.drawImage(img, -w * 0.5, -h * 0.5, w, h);
  ctx.restore();
}

function transformedRectPolygonPoints({ x = 0, y = 0, w = 1, h = 1, rotateDeg = 0, skewXDeg = 0 } = {}) {
  const width = Math.max(1, Number(w) || 1);
  const height = Math.max(1, Number(h) || 1);
  const rotation = normalizeFreeformRotateDeg(rotateDeg);
  const skew = normalizeFreeformSkewDeg(skewXDeg);
  const rotationRad = (rotation * Math.PI) / 180;
  const cos = Math.cos(rotationRad);
  const sin = Math.sin(rotationRad);
  const skewTan = Math.tan((skew * Math.PI) / 180);
  const cx = (Number(x) || 0) + width * 0.5;
  const cy = (Number(y) || 0) + height * 0.5;
  const local = [
    { x: -width * 0.5, y: -height * 0.5 },
    { x: width * 0.5, y: -height * 0.5 },
    { x: width * 0.5, y: height * 0.5 },
    { x: -width * 0.5, y: height * 0.5 },
  ];
  return local.map((pt) => {
    const sx = pt.x + skewTan * pt.y;
    const sy = pt.y;
    return {
      x: cx + sx * cos - sy * sin,
      y: cy + sx * sin + sy * cos,
    };
  });
}

function untransformPointForRect(point = null, { x = 0, y = 0, w = 1, h = 1, rotateDeg = 0, skewXDeg = 0 } = {}) {
  const px = Number(point?.x);
  const py = Number(point?.y);
  const width = Math.max(1, Number(w) || 1);
  const height = Math.max(1, Number(h) || 1);
  const cx = (Number(x) || 0) + width * 0.5;
  const cy = (Number(y) || 0) + height * 0.5;
  if (!Number.isFinite(px) || !Number.isFinite(py)) return { x: cx, y: cy };
  const rotation = normalizeFreeformRotateDeg(rotateDeg);
  const skew = normalizeFreeformSkewDeg(skewXDeg);
  if (Math.abs(rotation) < 0.001 && Math.abs(skew) < 0.001) {
    return { x: px, y: py };
  }
  const rotationRad = (rotation * Math.PI) / 180;
  const cos = Math.cos(rotationRad);
  const sin = Math.sin(rotationRad);
  const dx = px - cx;
  const dy = py - cy;
  const rx = dx * cos + dy * sin;
  const ry = -dx * sin + dy * cos;
  const skewTan = Math.tan((skew * Math.PI) / 180);
  const lx = rx - skewTan * ry;
  const ly = ry;
  return {
    x: cx + lx,
    y: cy + ly,
  };
}

function drawPolygonPath(ctx, points = []) {
  if (!ctx || !Array.isArray(points) || points.length < 2) return false;
  ctx.beginPath();
  ctx.moveTo(Number(points[0].x) || 0, Number(points[0].y) || 0);
  for (let i = 1; i < points.length; i += 1) {
    ctx.lineTo(Number(points[i].x) || 0, Number(points[i].y) || 0);
  }
  ctx.closePath();
  return true;
}

function polygonCanvasBounds(points = []) {
  if (!Array.isArray(points) || points.length === 0) return null;
  let left = Number.POSITIVE_INFINITY;
  let top = Number.POSITIVE_INFINITY;
  let right = Number.NEGATIVE_INFINITY;
  let bottom = Number.NEGATIVE_INFINITY;
  for (const point of points) {
    const x = Number(point?.x);
    const y = Number(point?.y);
    if (!Number.isFinite(x) || !Number.isFinite(y)) continue;
    if (x < left) left = x;
    if (y < top) top = y;
    if (x > right) right = x;
    if (y > bottom) bottom = y;
  }
  if (!Number.isFinite(left) || !Number.isFinite(top) || !Number.isFinite(right) || !Number.isFinite(bottom)) return null;
  return {
    left,
    top,
    right,
    bottom,
    width: Math.max(1, right - left),
    height: Math.max(1, bottom - top),
  };
}

function renderCanvasImagePlaceholder(ctx, polygon = []) {
  if (!ctx) return false;
  const bounds = polygonCanvasBounds(polygon);
  if (!bounds) return false;
  const dpr = getDpr();
  const pad = Math.max(10, Math.round(12 * dpr));
  const bandHeight = Math.max(6, Math.round(8 * dpr));
  ctx.save();
  if (drawPolygonPath(ctx, polygon)) ctx.clip();
  const backdrop = ctx.createLinearGradient(bounds.left, bounds.top, bounds.right, bounds.bottom);
  backdrop.addColorStop(0, "rgba(22, 34, 48, 0.96)");
  backdrop.addColorStop(1, "rgba(8, 12, 18, 0.98)");
  ctx.fillStyle = backdrop;
  ctx.fillRect(bounds.left, bounds.top, bounds.width, bounds.height);
  const wash = ctx.createLinearGradient(bounds.left, bounds.top, bounds.right, bounds.top);
  wash.addColorStop(0, "rgba(120, 200, 255, 0.06)");
  wash.addColorStop(0.52, "rgba(255, 255, 255, 0.14)");
  wash.addColorStop(1, "rgba(120, 200, 255, 0.04)");
  ctx.fillStyle = wash;
  ctx.fillRect(bounds.left, bounds.top, bounds.width, bounds.height);
  ctx.fillStyle = "rgba(232, 242, 252, 0.14)";
  ctx.fillRect(
    Math.round(bounds.left + pad),
    Math.round(bounds.top + pad),
    Math.max(1, Math.round(bounds.width * 0.56)),
    bandHeight
  );
  ctx.fillRect(
    Math.round(bounds.left + pad),
    Math.round(bounds.top + pad + bandHeight + Math.max(6, Math.round(7 * dpr))),
    Math.max(1, Math.round(bounds.width * 0.34)),
    bandHeight
  );
  ctx.restore();
  return true;
}

function singleCanvasLoadingPlaceholderPolygon(item = null, workCanvas = null, singleTransform = null) {
  const canvasW = Number(workCanvas?.width) || 0;
  const canvasH = Number(workCanvas?.height) || 0;
  if (!(canvasW > 0 && canvasH > 0)) return [];
  const rotateDeg = Number(singleTransform?.rotateDeg) || 0;
  const skewXDeg = Number(singleTransform?.skewXDeg) || 0;
  const imageW = Math.max(0, Number(item?.width) || 0);
  const imageH = Math.max(0, Number(item?.height) || 0);
  const viewScale = Math.max(0.05, Number(state.view?.scale) || 1);
  const viewRect = imageW > 0 && imageH > 0
    ? {
        x: Number(state.view?.offsetX) || 0,
        y: Number(state.view?.offsetY) || 0,
        w: imageW * viewScale,
        h: imageH * viewScale,
      }
    : null;
  const viewRectLooksUsable =
    viewRect &&
    viewRect.w > 0 &&
    viewRect.h > 0 &&
    viewRect.x < canvasW &&
    viewRect.y < canvasH &&
    viewRect.x + viewRect.w > 0 &&
    viewRect.y + viewRect.h > 0 &&
    viewRect.w <= canvasW * 4 &&
    viewRect.h <= canvasH * 4;
  if (viewRectLooksUsable) {
    return transformedRectPolygonPoints({
      ...viewRect,
      rotateDeg,
      skewXDeg,
    });
  }
  if (imageW > 0 && imageH > 0) {
    const isMobile =
      window.matchMedia && typeof window.matchMedia === "function"
        ? window.matchMedia("(max-width: 980px)").matches
        : false;
    const maxWidthFrac = isMobile ? 0.92 : 0.6;
    const maxHeightFrac = isMobile ? 0.9 : 0.86;
    const fitScale = clamp(Math.min((canvasW * maxWidthFrac) / imageW, (canvasH * maxHeightFrac) / imageH), 0.05, 20);
    const fitW = imageW * fitScale;
    const fitH = imageH * fitScale;
    const slackX = canvasW - fitW;
    const slackY = canvasH - fitH;
    const desiredTop = Math.round(canvasH * (isMobile ? 0.04 : 0.06));
    return transformedRectPolygonPoints({
      x: slackX / 2,
      y: slackY <= desiredTop ? slackY / 2 : desiredTop,
      w: fitW,
      h: fitH,
      rotateDeg,
      skewXDeg,
    });
  }
  const dpr = getDpr();
  const fallbackCssSize = freeformDefaultTileCss(
    canvasW / Math.max(dpr, 0.0001),
    canvasH / Math.max(dpr, 0.0001),
    { count: 1 }
  );
  const fallbackW = Math.max(1, Math.round(fallbackCssSize * dpr));
  const fallbackH = Math.max(1, Math.round(fallbackCssSize * dpr));
  return transformedRectPolygonPoints({
    x: Math.round((canvasW - fallbackW) * 0.5),
    y: Math.round((canvasH - fallbackH) * 0.5),
    w: fallbackW,
    h: fallbackH,
    rotateDeg,
    skewXDeg,
  });
}

function renderCanvasImageStatusPill(ctx, polygon = [], affordance = null) {
  if (!ctx || !affordance?.statusLabel) return false;
  const bounds = polygonCanvasBounds(polygon);
  if (!bounds) return false;
  const dpr = getDpr();
  const fontSize = Math.max(10, Math.round(11 * dpr));
  const padX = Math.max(7, Math.round(8 * dpr));
  const padY = Math.max(4, Math.round(5 * dpr));
  const inset = Math.max(8, Math.round(10 * dpr));
  const maxPillWidth = Math.max(0, Math.round(bounds.width - inset * 2));
  if (maxPillWidth < Math.round(92 * dpr)) return false;
  const palette =
    affordance.phase === "warming_magic_select"
      ? {
          fill: "rgba(34, 16, 36, 0.88)",
          stroke: "rgba(255, 120, 202, 0.38)",
          text: "rgba(255, 236, 247, 0.98)",
          shadow: "rgba(255, 120, 202, 0.18)",
        }
      : {
          fill: "rgba(14, 22, 32, 0.86)",
          stroke: "rgba(164, 214, 255, 0.32)",
          text: "rgba(236, 246, 255, 0.98)",
          shadow: "rgba(100, 210, 255, 0.16)",
        };
  ctx.save();
  ctx.font = `600 ${fontSize}px "IBM Plex Sans", "Segoe UI", sans-serif`;
  ctx.textBaseline = "middle";
  const label = String(affordance.statusLabel || "").trim();
  const measured = ctx.measureText(label);
  const pillH = Math.max(20, Math.round(fontSize + padY * 2));
  const pillW = Math.min(
    maxPillWidth,
    Math.max(Math.round(measured.width + padX * 2), Math.round(108 * dpr))
  );
  const x = clamp(
    Math.round(bounds.left + inset),
    Math.round(bounds.left),
    Math.round(bounds.right - pillW)
  );
  const y = clamp(
    Math.round(bounds.top + inset),
    Math.round(bounds.top),
    Math.round(bounds.bottom - pillH)
  );
  ctx.shadowColor = palette.shadow;
  ctx.shadowBlur = Math.round(14 * dpr);
  _drawRoundedRect(ctx, x, y, pillW, pillH, Math.max(6, Math.round(8 * dpr)));
  ctx.fillStyle = palette.fill;
  ctx.fill();
  ctx.shadowBlur = 0;
  ctx.lineWidth = Math.max(1, Math.round(1.1 * dpr));
  ctx.strokeStyle = palette.stroke;
  ctx.stroke();
  ctx.fillStyle = palette.text;
  ctx.fillText(label, x + padX, y + pillH * 0.5);
  ctx.restore();
  return true;
}

function clampFreeformRectCss(rectCss, canvasCssW, canvasCssH, { margin = 14, minSize = 44 } = {}) {
  const w = Math.max(minSize, Math.round(Number(rectCss?.w) || 0));
  const h = Math.max(minSize, Math.round(Number(rectCss?.h) || 0));
  const maxX = Math.max(margin, Math.round((Number(canvasCssW) || 0) - w - margin));
  const maxY = Math.max(margin, Math.round((Number(canvasCssH) || 0) - h - margin));
  return {
    x: clamp(Math.round(Number(rectCss?.x) || 0), margin, maxX),
    y: clamp(Math.round(Number(rectCss?.y) || 0), margin, maxY),
    w,
    h,
    autoAspect: Boolean(rectCss?.autoAspect),
    rotateDeg: normalizeFreeformRotateDeg(rectCss?.rotateDeg),
    skewXDeg: normalizeFreeformSkewDeg(rectCss?.skewXDeg),
  };
}

function settleAutoAspectRectCss(
  rectCss,
  { width = 0, height = 0 } = {},
  { canvasCssW = 0, canvasCssH = 0, clampOptions = null } = {}
) {
  const baseRect = rectCss && typeof rectCss === "object" ? rectCss : {};
  const prevW = Math.max(1, Math.round(Number(baseRect.w) || 1));
  const prevH = Math.max(1, Math.round(Number(baseRect.h) || 1));
  const iw = Math.max(1, Math.round(Number(width) || 0));
  const ih = Math.max(1, Math.round(Number(height) || 0));
  const aspect = iw / Math.max(1, ih);
  let nextW = prevW;
  let nextH = prevH;

  if (aspect >= 1) {
    nextH = Math.max(1, Math.round(prevW / Math.max(0.0001, aspect)));
    if (nextH > prevH) {
      nextH = prevH;
      nextW = Math.max(1, Math.round(prevH * aspect));
    }
  } else {
    nextW = Math.max(1, Math.round(prevH * aspect));
    if (nextW > prevW) {
      nextW = prevW;
      nextH = Math.max(1, Math.round(prevW / Math.max(0.0001, aspect)));
    }
  }

  const centered = {
    ...baseRect,
    x: (Number(baseRect.x) || 0) + Math.round((prevW - nextW) / 2),
    y: (Number(baseRect.y) || 0) + Math.round((prevH - nextH) / 2),
    w: nextW,
    h: nextH,
    autoAspect: false,
  };

  if (
    canvasCssW > 0 &&
    canvasCssH > 0 &&
    clampOptions &&
    typeof clampOptions === "object"
  ) {
    return clampFreeformRectCss(centered, canvasCssW, canvasCssH, clampOptions);
  }
  return centered;
}

function freeformWorkspaceClampOptions(canvasCssW, canvasCssH, { minSize = 44 } = {}) {
  const span = Math.max(1, Math.round(Math.max(Number(canvasCssW) || 0, Number(canvasCssH) || 0)));
  // Allow drag/resize across a wide off-screen workspace; avoid a hard wall at the visible canvas edge.
  const workspaceMargin = -Math.max(2000, span * 4);
  return { margin: workspaceMargin, minSize };
}

function hitTestFreeformCornerHandleWithPad(ptCanvas, rectPx, padPx = 0, rectTransform = null) {
  if (!ptCanvas || !rectPx) return null;
  const dpr = getDpr();
  const hs = Math.max(10, Math.round(10 * dpr));
  const r = Math.round(hs / 2) + Math.max(0, Math.round(Number(padPx) || 0));
  const transform = readFreeformRectTransform(rectTransform);
  const transformedCorners = transformedRectPolygonPoints({
    x: rectPx.x,
    y: rectPx.y,
    w: rectPx.w,
    h: rectPx.h,
    rotateDeg: transform.rotateDeg,
    skewXDeg: transform.skewXDeg,
  });
  const corners = Array.isArray(transformedCorners) && transformedCorners.length === 4
    ? [
        { id: "nw", x: transformedCorners[0].x, y: transformedCorners[0].y },
        { id: "ne", x: transformedCorners[1].x, y: transformedCorners[1].y },
        { id: "se", x: transformedCorners[2].x, y: transformedCorners[2].y },
        { id: "sw", x: transformedCorners[3].x, y: transformedCorners[3].y },
      ]
    : [
        { id: "nw", x: rectPx.x, y: rectPx.y },
        { id: "ne", x: rectPx.x + rectPx.w, y: rectPx.y },
        { id: "sw", x: rectPx.x, y: rectPx.y + rectPx.h },
        { id: "se", x: rectPx.x + rectPx.w, y: rectPx.y + rectPx.h },
      ];
  for (const c of corners) {
    if (Math.abs(ptCanvas.x - c.x) <= r && Math.abs(ptCanvas.y - c.y) <= r) return c.id;
  }
  return null;
}

function hitTestAnyFreeformCornerHandle(ptCanvas, { padPx = 0 } = {}) {
  if (!ptCanvas) return null;
  const ms = state.multiView?.scale || 1;
  const mx = state.multiView?.offsetX || 0;
  const my = state.multiView?.offsetY || 0;
  const x = (ptCanvas.x - mx) / Math.max(ms, 0.0001);
  const y = (ptCanvas.y - my) / Math.max(ms, 0.0001);
  const entries = Array.from(state.multiRects.entries());
  for (let i = entries.length - 1; i >= 0; i -= 1) {
    const [id, rect] = entries[i];
    if (isImageEffectTokenized(id)) continue;
    if (!rect) continue;
    const rectTransform = state.freeformRects.get(id) || null;
    const corner = hitTestFreeformCornerHandleWithPad({ x, y }, rect, padPx, rectTransform);
    if (!corner) continue;
    return { id, corner };
  }
  return null;
}

function resizeFreeformRectFromCorner(startRectCss, corner, pointerCss, canvasCssW, canvasCssH, clampOpts = {}) {
  const start = startRectCss || {};
  const x0 = Number(start.x) || 0;
  const y0 = Number(start.y) || 0;
  const w0 = Math.max(1, Number(start.w) || 1);
  const h0 = Math.max(1, Number(start.h) || 1);
  const x1 = x0 + w0;
  const y1 = y0 + h0;

  const px = Number(pointerCss?.x) || 0;
  const py = Number(pointerCss?.y) || 0;

  let fx = x0;
  let fy = y0;
  let sx = 1;
  let sy = 1;
  if (corner === "nw") {
    fx = x1;
    fy = y1;
    sx = -1;
    sy = -1;
  } else if (corner === "ne") {
    fx = x0;
    fy = y1;
    sx = 1;
    sy = -1;
  } else if (corner === "sw") {
    fx = x1;
    fy = y0;
    sx = -1;
    sy = 1;
  } else if (corner === "se") {
    fx = x0;
    fy = y0;
    sx = 1;
    sy = 1;
  }

  const dx = px - fx;
  const dy = py - fy;
  const aspect = w0 / Math.max(1, h0);
  const absW = Math.max(1, Math.abs(dx));
  const absH = Math.max(1, Math.abs(dy));

  const nextW = Math.max(absW, absH * aspect);
  const nextH = nextW / Math.max(0.001, aspect);

  const cx = fx + sx * nextW;
  const cy = fy + sy * nextH;
  const nx0 = Math.min(fx, cx);
  const ny0 = Math.min(fy, cy);
  const nx1 = Math.max(fx, cx);
  const ny1 = Math.max(fy, cy);

  return clampFreeformRectCss(
    {
      x: nx0,
      y: ny0,
      w: nx1 - nx0,
      h: ny1 - ny0,
      autoAspect: false,
      rotateDeg: start.rotateDeg,
      skewXDeg: start.skewXDeg,
    },
    canvasCssW,
    canvasCssH,
    clampOpts
  );
}

function hitTestMulti(pt, { includeTokenized = false } = {}) {
  if (!pt) return null;
  const ms = state.multiView?.scale || 1;
  const mx = state.multiView?.offsetX || 0;
  const my = state.multiView?.offsetY || 0;
  const x = (pt.x - mx) / Math.max(ms, 0.0001);
  const y = (pt.y - my) / Math.max(ms, 0.0001);
  const entries = Array.from(state.multiRects.entries());
  for (let i = entries.length - 1; i >= 0; i -= 1) {
    const [id, rect] = entries[i];
    if (!includeTokenized && isImageEffectTokenized(id)) continue;
    if (!rect) continue;
    const rectTransform = state.freeformRects.get(id) || null;
    const localPoint = untransformPointForRect(
      { x, y },
      {
        x: rect.x,
        y: rect.y,
        w: rect.w,
        h: rect.h,
        rotateDeg: rectTransform?.rotateDeg,
        skewXDeg: rectTransform?.skewXDeg,
      }
    );
    if (localPoint.x < rect.x || localPoint.x > rect.x + rect.w) continue;
    if (localPoint.y < rect.y || localPoint.y > rect.y + rect.h) continue;
    return id;
  }
  return null;
}

function hitTestMultiWithPad(pt, padPx = 0, { includeTokenized = false } = {}) {
  const padRaw = Math.max(0, Number(padPx) || 0);
  if (!padRaw) return hitTestMulti(pt, { includeTokenized });
  if (!pt) return null;
  const ms = state.multiView?.scale || 1;
  const mx = state.multiView?.offsetX || 0;
  const my = state.multiView?.offsetY || 0;
  const x = (pt.x - mx) / Math.max(ms, 0.0001);
  const y = (pt.y - my) / Math.max(ms, 0.0001);
  // Pad is specified in screen/canvas pixels; convert to local multi-rect space.
  const pad = padRaw / Math.max(ms, 0.0001);
  const entries = Array.from(state.multiRects.entries());
  for (let i = entries.length - 1; i >= 0; i -= 1) {
    const [id, rect] = entries[i];
    if (!includeTokenized && isImageEffectTokenized(id)) continue;
    if (!rect) continue;
    const rectTransform = state.freeformRects.get(id) || null;
    const localPoint = untransformPointForRect(
      { x, y },
      {
        x: rect.x,
        y: rect.y,
        w: rect.w,
        h: rect.h,
        rotateDeg: rectTransform?.rotateDeg,
        skewXDeg: rectTransform?.skewXDeg,
      }
    );
    if (localPoint.x < rect.x - pad || localPoint.x > rect.x + rect.w + pad) continue;
    if (localPoint.y < rect.y - pad || localPoint.y > rect.y + rect.h + pad) continue;
    return id;
  }
  return null;
}

function resetViewToFit() {
  if (state.canvasMode !== "single") return;
  const img = getActiveImage();
  if (!img || !img.img) return;
  const canvas = els.workCanvas;
  if (!canvas) return;
  const cw = canvas.width;
  const ch = canvas.height;
  if (!cw || !ch) return;
  const iw = img.img.naturalWidth || img.width || 1;
  const ih = img.img.naturalHeight || img.height || 1;
  const isMobile =
    window.matchMedia && typeof window.matchMedia === "function"
      ? window.matchMedia("(max-width: 980px)").matches
      : false;
  // Keep the image smaller than full-bleed so the HUD/spawnbar have breathing room.
  const maxWidthFrac = isMobile ? 0.92 : 0.6;
  const maxHeightFrac = isMobile ? 0.9 : 0.86;
  const prevScale = Number(state.view.scale) || 1;
  const prevOffsetX = Number(state.view.offsetX) || 0;
  const prevOffsetY = Number(state.view.offsetY) || 0;
  const scale = Math.min((cw * maxWidthFrac) / iw, (ch * maxHeightFrac) / ih);
  state.view.scale = clamp(scale, 0.05, 20);
  const slackX = cw - iw * state.view.scale;
  const slackY = ch - ih * state.view.scale;
  state.view.offsetX = slackX / 2;

  // Bias images toward the top so the bottom HUD/spawnbar feels like "control surface" space.
  const desiredTop = Math.round(ch * (isMobile ? 0.04 : 0.06));
  state.view.offsetY = slackY <= desiredTop ? slackY / 2 : desiredTop;
  const nextScale = Number(state.view.scale) || 1;
  const nextOffsetX = Number(state.view.offsetX) || 0;
  const nextOffsetY = Number(state.view.offsetY) || 0;
  const fitChanged =
    Math.abs(nextScale - prevScale) > 0.0001 ||
    Math.abs(nextOffsetX - prevOffsetX) > 0.5 ||
    Math.abs(nextOffsetY - prevOffsetY) > 0.5;
  if (fitChanged) {
    invalidateActiveTabPreview("viewport_fit_change");
    recordUserEvent("canvas_fit", {
      actor: "system",
      source: "reset_view_to_fit",
      canvas_mode: state.canvasMode,
      active_id: state.activeId || null,
      scale: nextScale,
      offset_x: nextOffsetX,
      offset_y: nextOffsetY,
    }, { includeInScoringRing: false });
  }
  renderHudReadout();
  scheduleVisualPromptWrite();
  requestRender();
}

function getActiveImageRectCss() {
  const dpr = getDpr();
  if (state.canvasMode === "multi") {
    const ms = state.multiView?.scale || 1;
    const mx = state.multiView?.offsetX || 0;
    const my = state.multiView?.offsetY || 0;
    const rect = state.activeId ? state.multiRects.get(state.activeId) : null;
    if (!rect) return null;
    const rectTransform = readFreeformRectTransform(
      state.activeId ? state.freeformRects.get(state.activeId) || null : null
    );
    return {
      left: (mx + rect.x * ms) / dpr,
      top: (my + rect.y * ms) / dpr,
      width: (rect.w * ms) / dpr,
      height: (rect.h * ms) / dpr,
      rotateDeg: rectTransform.rotateDeg,
      skewXDeg: rectTransform.skewXDeg,
    };
  }
  if (state.canvasMode !== "single") return null;
  const item = getActiveImage();
  const img = item?.img;
  if (!item || !img) return null;
  const iw = img.naturalWidth || item.width || 1;
  const ih = img.naturalHeight || item.height || 1;
  return {
    left: state.view.offsetX / dpr,
    top: state.view.offsetY / dpr,
    width: (iw * state.view.scale) / dpr,
    height: (ih * state.view.scale) / dpr,
    rotateDeg: 0,
    skewXDeg: 0,
  };
}

function getImageRectCss(imageId) {
  if (!imageId) return null;
  if (state.canvasMode === "multi") {
    const dpr = getDpr();
    const ms = state.multiView?.scale || 1;
    const mx = state.multiView?.offsetX || 0;
    const my = state.multiView?.offsetY || 0;
    const rect = state.multiRects.get(imageId) || null;
    if (!rect) return null;
    const rectTransform = readFreeformRectTransform(state.freeformRects.get(imageId) || null);
    return {
      left: (mx + rect.x * ms) / dpr,
      top: (my + rect.y * ms) / dpr,
      width: (rect.w * ms) / dpr,
      height: (rect.h * ms) / dpr,
      rotateDeg: rectTransform.rotateDeg,
      skewXDeg: rectTransform.skewXDeg,
    };
  }
  if (state.canvasMode !== "single") return null;
  if (state.activeId !== imageId) return null;
  return getActiveImageRectCss();
}

function getImageFxTargets() {
  const swap = state.pendingSwapDna;
  if (swap?.structureId && swap?.surfaceId) return [swap.structureId, swap.surfaceId];

  const blend = state.pendingBlend?.sourceIds;
  if (Array.isArray(blend) && blend.length >= 2) return [blend[0], blend[1]];

  const bridge = state.pendingBridge?.sourceIds;
  if (Array.isArray(bridge) && bridge.length >= 2) return [bridge[0], bridge[1]];

  const createLayersId = state.pendingCreateLayers?.sourceId;
  if (createLayersId) return [createLayersId];

  const replaceId = state.pendingReplace?.targetId;
  if (replaceId) return [replaceId];

  const recastId = state.pendingRecast?.sourceId;
  if (recastId) return [recastId];

  const activeId = state.activeId;
  if (activeId) return [activeId];
  return [];
}

let imageFxDynamicEls = [];

function ensureImageFxOverlays(count = 0) {
  const baseEls = [];
  if (els.imageFx) baseEls.push(els.imageFx);
  if (els.imageFx2) baseEls.push(els.imageFx2);
  const minimumCount = Math.max(baseEls.length, Number(count) || 0);
  const neededDynamic = Math.max(0, minimumCount - baseEls.length);
  const wrap = els.canvasWrap;

  while (imageFxDynamicEls.length < neededDynamic) {
    if (!wrap) break;
    const fx = document.createElement("div");
    fx.className = "image-fx hidden";
    fx.setAttribute("aria-hidden", "true");
    wrap.appendChild(fx);
    imageFxDynamicEls.push(fx);
  }
  while (imageFxDynamicEls.length > neededDynamic) {
    const fx = imageFxDynamicEls.pop();
    if (fx?.parentNode) {
      fx.parentNode.removeChild(fx);
    }
  }
  return [...baseEls, ...imageFxDynamicEls];
}

function hideImageFxOverlays() {
  const overlays = ensureImageFxOverlays(0);
  for (const fx of overlays) {
    if (!fx) continue;
    fx.classList.add("hidden");
    fx.style.width = "0px";
    fx.style.height = "0px";
    fx.style.transform = "none";
  }
}

function updateImageFxRect() {
  const targets = getImageFxTargets();
  const overlays = ensureImageFxOverlays(Math.max(1, targets.length));
  if (!overlays.length) return;
  if (!state.imageFx?.active) {
    hideImageFxOverlays();
    return;
  }

  const setRect = (el, rect) => {
    if (!el) return;
    if (!rect) {
      el.style.width = "0px";
      el.style.height = "0px";
      el.style.transform = "none";
      return;
    }
    const rotateDeg = Number(rect.rotateDeg) || 0;
    const skewXDeg = Number(rect.skewXDeg) || 0;
    el.style.left = `${rect.left.toFixed(2)}px`;
    el.style.top = `${rect.top.toFixed(2)}px`;
    el.style.width = `${Math.max(0, rect.width).toFixed(2)}px`;
    el.style.height = `${Math.max(0, rect.height).toFixed(2)}px`;
    el.style.transformOrigin = "50% 50%";
    el.style.transform =
      Math.abs(rotateDeg) > 0.001 || Math.abs(skewXDeg) > 0.001
        ? `rotate(${rotateDeg.toFixed(2)}deg) skewX(${skewXDeg.toFixed(2)}deg)`
        : "none";
  };

  const fallbackRect = getActiveImageRectCss();
  overlays.forEach((fx, idx) => {
    const targetId = targets[idx] || null;
    const rect = targetId ? getImageRectCss(targetId) : idx === 0 ? fallbackRect : null;
    fx.classList.toggle("hidden", !rect);
    setRect(fx, rect);
  });
}

function setImageFxActive(active, label = null) {
  state.imageFx.active = Boolean(active);
  state.imageFx.label = label || null;
  if (state.imageFx.active) {
    updateImageFxRect();
  } else {
    hideImageFxOverlays();
  }
  requestRender();
}

function beginPendingReplace(targetId, label, extra = null) {
  if (!targetId) return;
  const payload = { targetId, startedAt: Date.now(), label: label || null };
  if (extra && typeof extra === "object") {
    for (const [key, value] of Object.entries(extra)) {
      // Prevent accidental override of the core routing keys.
      if (key === "targetId" || key === "startedAt") continue;
      payload[key] = value;
    }
  }
  state.pendingReplace = payload;
}

function clearPendingReplace() {
  state.pendingReplace = null;
}

function beginRunningAction(key) {
  const k = String(key || "").trim();
  if (!k) return;
  state.runningActionKey = k;
  renderQuickActions();
}

function clearRunningAction(key = null) {
  if (key && state.runningActionKey !== key) return;
  state.runningActionKey = null;
  renderQuickActions();
}

function clearSelection() {
  state.selection = null;
  state.lassoDraft = [];
  state.annotateDraft = null;
  state.annotateBox = null;
  state.circleDraft = null;
  invalidateActiveTabPreview("selection_clear");
  hideMarkPanel();
  hideAnnotatePanel();
  hidePromptGeneratePanel();
  setTip(DEFAULT_TIP);
  scheduleVisualPromptWrite();
  requestRender();
  renderSelectionMeta();
  renderHudReadout();
}

function setTool(tool) {
  const allowed = new Set(["annotate", "pan", "lasso"]);
  if (!allowed.has(tool)) return;
  const prevTool = state.tool;
  if (tool !== "annotate") {
    state.annotateDraft = null;
    state.annotateBox = null;
    hideAnnotatePanel();
    hidePromptGeneratePanel();
    state.circleDraft = null;
    hideMarkPanel();
  }
  state.tool = tool;
  if (prevTool !== tool) {
    recordUserEvent("tool_set", { tool });
  }
  renderQuickActions();
  renderSelectionMeta();
  renderHudReadout();
  if (tool === "lasso") {
    setTip("Lasso your product, then click Studio White. Or skip lasso and let the model infer the subject.");
  } else if (tool === "annotate") {
    setTip("Annotate: drag a box to edit. Hold Shift to draw a red circle label.");
  } else {
    setTip(DEFAULT_TIP);
  }
  scheduleVisualPromptWrite();
}

function showDropHint(show) {
  if (!els.dropHint) return;
  els.dropHint.classList.toggle("hidden", !show);
  syncDropHintInteractivity();
}

function renderSelectionMeta() {
  const img = getActiveImage();
  if (!img) {
    if (els.selectionMeta) els.selectionMeta.textContent = "No image selected.";
    renderHudReadout();
    return;
  }
  const name = basename(img.path);
  const sel = state.selection ? `${state.selection.points.length} pts` : "none";
  if (els.selectionMeta) els.selectionMeta.textContent = `${name}\nSelection: ${sel}`;
  renderHudReadout();
}

function hideImageMenu() {
  if (!els.imageMenu) return;
  els.imageMenu.classList.add("hidden");
  state.imageMenuTargetId = null;
}

function showImageMenuAt(ptCss, imageId) {
  const menu = els.imageMenu;
  const wrap = els.canvasWrap;
  if (!menu || !wrap || !ptCss || !imageId) return;
  state.imageMenuTargetId = String(imageId);
  menu.classList.remove("hidden");

  const dx = 12;
  const dy = 12;
  const x0 = (Number(ptCss.x) || 0) + dx;
  const y0 = (Number(ptCss.y) || 0) + dy;

  menu.style.left = `${x0}px`;
  menu.style.top = `${y0}px`;

  requestAnimationFrame(() => {
    const mw = menu.offsetWidth || 0;
    const mh = menu.offsetHeight || 0;
    const maxX = Math.max(8, wrap.clientWidth - mw - 8);
    const maxY = Math.max(8, wrap.clientHeight - mh - 8);
    const x = clamp(x0, 8, maxX);
    const y = clamp(y0, 8, maxY);
    menu.style.left = `${x}px`;
    menu.style.top = `${y}px`;
  });
}

function hideAnnotatePanel() {
  if (!els.annotatePanel) return;
  els.annotatePanel.classList.add("hidden");
}

function promptGenerateAvailableModels() {
  if (!els.imageModel) return [];
  return Array.from(els.imageModel.options || [])
    .map((opt) => String(opt?.value || "").trim())
    .filter(Boolean);
}

function resolvePromptGenerateModel(rawModel = "") {
  const requested = String(rawModel || "").trim();
  const available = promptGenerateAvailableModels();
  if (!available.length) {
    return requested || settings.imageModel || DEFAULT_IMAGE_MODEL;
  }
  if (requested && available.includes(requested)) return requested;
  if (settings.imageModel && available.includes(settings.imageModel)) return settings.imageModel;
  return available[0];
}

function capturePromptGenerateDraftFromUi() {
  const prompt = String(els.promptGenerateText?.value || "").trim();
  const model = resolvePromptGenerateModel(els.promptGenerateModel?.value || "");
  state.promptGenerateDraft = { prompt, model };
}

function hidePromptGeneratePanel({ clearDraft = false } = {}) {
  if (!els.promptGeneratePanel) return;
  capturePromptGenerateDraftFromUi();
  if (clearDraft) {
    state.promptGenerateDraft = { prompt: "", model: "" };
    state.promptGenerateDraftAnchor = null;
    if (els.promptGenerateText) els.promptGenerateText.value = "";
  }
  els.promptGeneratePanel.classList.add("hidden");
}

function showPromptGeneratePanel() {
  const panel = els.promptGeneratePanel;
  if (!panel) return;
  const anchorCss = currentPromptGenerateAnchorCss();
  state.promptGenerateDraftAnchor = {
    anchorCss,
    anchorWorldCss: canvasScreenCssToWorldCss(anchorCss),
  };

  const targetModel = resolvePromptGenerateModel(
    state.promptGenerateDraft?.model || settings.imageModel || DEFAULT_IMAGE_MODEL
  );
  if (els.promptGenerateModel) {
    els.promptGenerateModel.innerHTML = "";
    for (const opt of Array.from(els.imageModel?.options || [])) {
      if (!opt?.value) continue;
      const optionEl = document.createElement("option");
      optionEl.value = opt.value;
      optionEl.textContent = opt.textContent || opt.value;
      els.promptGenerateModel.appendChild(optionEl);
    }
    els.promptGenerateModel.value = targetModel;
    if (els.promptGenerateModel.value !== targetModel) {
      const fallbackModel = resolvePromptGenerateModel(targetModel);
      els.promptGenerateModel.value = fallbackModel;
    }
  }

  if (els.promptGenerateText) {
    const draftPrompt = String(state.promptGenerateDraft?.prompt || "");
    els.promptGenerateText.value = draftPrompt;
  }
  if (els.promptGenerateMeta) {
    els.promptGenerateMeta.textContent = "Create a new image (no source image required).";
  }

  panel.style.left = "50%";
  panel.style.top = "50%";
  panel.style.transform = "translate(-50%, -50%)";
  panel.classList.remove("hidden");
  setTimeout(() => {
    try {
      if (els.promptGenerateText) els.promptGenerateText.focus();
    } catch {
      // ignore
    }
  }, 0);
}

function normalizePromptGeneratePrompt(promptText = "") {
  const trimmed = String(promptText || "").trim();
  if (!trimmed) return "";
  if (/^(edit|replace)\b/i.test(trimmed)) {
    return `generate a brand-new image from text only: ${trimmed}`;
  }
  return trimmed;
}

async function runPromptGenerate({ prompt = "", model = "", fromQueue = false, anchorCss = null, anchorWorldCss = null } = {}) {
  if (!requireIntentUnlocked()) return;
  bumpInteraction();

  const rawPrompt = String(prompt || "").trim();
  if (!rawPrompt) {
    showToast("Prompt Generate: enter a prompt.", "tip", 2200);
    return;
  }
  const normalizedPrompt = normalizePromptGeneratePrompt(rawPrompt);
  const selectedModel = resolvePromptGenerateModel(model || settings.imageModel || DEFAULT_IMAGE_MODEL);
  const resolvedAnchorCss = currentPromptGenerateAnchorCss(anchorCss);
  const resolvedAnchorWorldCss =
    anchorWorldCss && Number.isFinite(Number(anchorWorldCss.x)) && Number.isFinite(Number(anchorWorldCss.y))
      ? {
          x: Number(anchorWorldCss.x) || 0,
          y: Number(anchorWorldCss.y) || 0,
        }
      : canvasScreenCssToWorldCss(resolvedAnchorCss);

  if (!fromQueue && (isEngineBusy() || state.actionQueueActive || state.actionQueue.length)) {
    enqueueAction({
      label: "Prompt Generate",
      key: "prompt_generate",
      priority: ACTION_QUEUE_PRIORITY.user,
      run: () =>
        runPromptGenerate({
          prompt: rawPrompt,
          model: selectedModel,
          fromQueue: true,
          anchorCss: resolvedAnchorCss,
          anchorWorldCss: resolvedAnchorWorldCss,
        }),
    });
    return;
  }

  await ensureRun();
  setImageFxActive(true, "Prompt Generate");
  portraitWorking("Prompt Generate", {
    providerOverride: providerFromModel(selectedModel) || providerFromModel(settings.imageModel),
  });

  try {
    const ok = await ensureEngineSpawned({ reason: "prompt generate" });
    if (!ok) throw new Error("Engine unavailable");

    await maybeOverrideEngineImageModel(selectedModel);

    state.expectingArtifacts = true;
    state.pendingPromptGenerate = {
      prompt: normalizedPrompt,
      model: selectedModel,
      startedAt: Date.now(),
      anchorCss: resolvedAnchorCss,
      anchorWorldCss: resolvedAnchorWorldCss,
    };
    state.lastAction = "Prompt Generate";
    setStatus("Engine: prompt generate…");
    showToast(`Generating with ${selectedModel}…`, "info", 2200);
    renderQuickActions();
    requestRender();
    await invoke("write_pty", { data: `${normalizedPrompt}\n` });
  } catch (err) {
    state.pendingPromptGenerate = null;
    state.expectingArtifacts = false;
    restoreEngineImageModelIfNeeded();
    setImageFxActive(false);
    updatePortraitIdle();
    renderQuickActions();
    throw err;
  }
}

async function runPromptGenerateFromPanel() {
  const rawPrompt = String(els.promptGenerateText?.value || "").trim();
  const selectedModel = resolvePromptGenerateModel(
    els.promptGenerateModel?.value || state.promptGenerateDraft?.model || settings.imageModel || DEFAULT_IMAGE_MODEL
  );
  const draftAnchor = state.promptGenerateDraftAnchor
    ? {
        anchorCss: state.promptGenerateDraftAnchor.anchorCss
          ? {
              x: Number(state.promptGenerateDraftAnchor.anchorCss.x) || 0,
              y: Number(state.promptGenerateDraftAnchor.anchorCss.y) || 0,
            }
          : null,
        anchorWorldCss: state.promptGenerateDraftAnchor.anchorWorldCss
          ? {
              x: Number(state.promptGenerateDraftAnchor.anchorWorldCss.x) || 0,
              y: Number(state.promptGenerateDraftAnchor.anchorWorldCss.y) || 0,
            }
          : null,
      }
    : null;
  state.promptGenerateDraft = {
    prompt: rawPrompt,
    model: selectedModel,
  };
  if (!rawPrompt) {
    showToast("Prompt Generate: enter a prompt.", "tip", 2200);
    if (els.promptGenerateText) {
      try {
        els.promptGenerateText.focus();
      } catch {
        // ignore
      }
    }
    return;
  }
  hidePromptGeneratePanel();
  await runPromptGenerate({
    prompt: rawPrompt,
    model: selectedModel,
    anchorCss: draftAnchor?.anchorCss || null,
    anchorWorldCss: draftAnchor?.anchorWorldCss || null,
  });
}

function cloneToolRuntimeValue(value) {
  return value == null ? value : JSON.parse(JSON.stringify(value));
}

function cloneSessionValue(value, seen = new Map()) {
  if (value == null || typeof value !== "object") return value;
  if (typeof structuredClone === "function") {
    try {
      return structuredClone(value);
    } catch {
      // Fall through to the manual clone for browser objects structuredClone cannot handle.
    }
  }
  if (seen.has(value)) return seen.get(value);
  if (value instanceof Map) {
    const next = new Map();
    seen.set(value, next);
    for (const [key, entry] of value.entries()) {
      next.set(cloneSessionValue(key, seen), cloneSessionValue(entry, seen));
    }
    return next;
  }
  if (value instanceof Set) {
    const next = new Set();
    seen.set(value, next);
    for (const entry of value.values()) {
      next.add(cloneSessionValue(entry, seen));
    }
    return next;
  }
  if (Array.isArray(value)) {
    const next = [];
    seen.set(value, next);
    for (const entry of value) {
      next.push(cloneSessionValue(entry, seen));
    }
    return next;
  }
  const next = {};
  seen.set(value, next);
  for (const [key, entry] of Object.entries(value)) {
    next[key] = cloneSessionValue(entry, seen);
  }
  return next;
}

function rehydrateForkedTabSessionImageRuntime(session = null, sourceSession = null) {
  const current = session && typeof session === "object" ? session : null;
  if (!current) return current;

  const collectSourceHandles = (entries = []) => {
    const byId = new Map();
    const byPath = new Map();
    for (const entry of entries) {
      if (!entry || typeof entry !== "object") continue;
      const handle = readSessionRuntimeImageHandle(entry);
      if (!handle) continue;
      const id = String(entry.id || "").trim();
      const path = String(entry.path || "").trim();
      if (id && !byId.has(id)) byId.set(id, handle);
      if (path && !byPath.has(path)) byPath.set(path, handle);
    }
    return { byId, byPath };
  };

  const applyHandles = (entries = [], handles = null) => {
    const seen = new Set();
    for (const entry of entries) {
      if (!entry || typeof entry !== "object" || seen.has(entry)) continue;
      seen.add(entry);
      const id = String(entry.id || "").trim();
      const path = String(entry.path || "").trim();
      entry.img =
        (id && handles?.byId instanceof Map ? handles.byId.get(id) : null) ||
        (path && handles?.byPath instanceof Map ? handles.byPath.get(path) : null) ||
        null;
      entry.imgLoading = false;
    }
  };

  const sourceImages = [
    ...(Array.isArray(sourceSession?.images) ? sourceSession.images : []),
    ...(sourceSession?.imagesById instanceof Map ? Array.from(sourceSession.imagesById.values()) : []),
  ];
  const targetImages = [
    ...(Array.isArray(current.images) ? current.images : []),
    ...(current.imagesById instanceof Map ? Array.from(current.imagesById.values()) : []),
  ];
  applyHandles(targetImages, collectSourceHandles(sourceImages));

  return current;
}

function syncSessionToolsFromRegistry() {
  const previousSignature = Array.isArray(state.sessionTools)
    ? state.sessionTools.map((tool) => `${tool?.toolId || ""}:${tool?.label || ""}`).join("|")
    : "";
  state.sessionTools = sessionToolRegistry.list();
  const nextSignature = Array.isArray(state.sessionTools)
    ? state.sessionTools.map((tool) => `${tool?.toolId || ""}:${tool?.label || ""}`).join("|")
    : "";
  if (previousSignature !== nextSignature) {
    markActiveTabUiDirty({ quickActions: true, customToolDock: true, publishTabs: true });
  }
}

function captureCreateToolDraftFromUi() {
  const name = String(els.createToolName?.value || "").trim();
  const description = String(els.createToolText?.value || "").trim();
  state.customToolDraft = { name, description };
  return state.customToolDraft;
}

function createToolPreviewText(manifest) {
  if (!manifest || typeof manifest !== "object") {
    return "Describe a tool to preview the manifest.";
  }
  const preview = {
    schema: manifest.schema,
    toolId: manifest.toolId,
    label: manifest.label,
    provenance: manifest.provenance || ACTION_PROVENANCE.LOCAL_ONLY,
    execution: `${manifest.execution?.kind || "local_edit"}:${manifest.execution?.operation || "unknown"}`,
    params: manifest.execution?.params || {},
    selection: {
      minImages: Number(manifest.inputContract?.minImages) || 1,
      maxImages: Number(manifest.inputContract?.maxImages) || 1,
      requiresActiveImage: Boolean(manifest.inputContract?.requiresActiveImage),
    },
    receipt: manifest.receipt?.include || [],
  };
  return JSON.stringify(preview, null, 2);
}

function renderCreateToolPreview() {
  if (!els.createToolPreview) return;
  const draft = captureCreateToolDraftFromUi();
  const description = String(draft?.description || "").trim();
  if (!description) {
    els.createToolPreview.textContent = "Describe a tool to preview the manifest.";
    if (els.createToolMeta) {
      els.createToolMeta.textContent =
        "Describe the tool you want. Cue will map it to a deterministic local edit manifest for today's slice.";
    }
    if (els.createToolSave) els.createToolSave.disabled = true;
    return;
  }
  try {
    const existingIds = state.sessionTools.map((tool) => String(tool?.toolId || "").trim()).filter(Boolean);
    const manifest = generateToolManifest({
      name: draft.name,
      description,
      existingIds,
    });
    els.createToolPreview.textContent = createToolPreviewText(manifest);
    if (els.createToolMeta) {
      els.createToolMeta.textContent = appendActionProvenanceDescription(
        `Mapped to ${manifest.execution.kind}:${manifest.execution.operation}.`,
        manifest.provenance || ACTION_PROVENANCE.LOCAL_ONLY
      );
    }
    if (els.createToolSave) els.createToolSave.disabled = false;
  } catch (err) {
    els.createToolPreview.textContent = err?.message || "Could not preview manifest.";
    if (els.createToolMeta) els.createToolMeta.textContent = "Describe the tool you want.";
    if (els.createToolSave) els.createToolSave.disabled = true;
  }
}

function hideCreateToolPanel({ clearDraft = false } = {}) {
  if (!els.createToolPanel) return;
  captureCreateToolDraftFromUi();
  if (clearDraft) {
    state.customToolDraft = { name: "", description: "" };
    if (els.createToolName) els.createToolName.value = "";
    if (els.createToolText) els.createToolText.value = "";
  }
  els.createToolPanel.classList.add("hidden");
  bumpTabUiVersion("customToolDock");
  renderCreateToolPreview();
  renderCustomToolDock();
}

function showCreateToolPanel() {
  const panel = els.createToolPanel;
  if (!panel) return;
  if (els.createToolName) {
    els.createToolName.value = String(state.customToolDraft?.name || "");
  }
  if (els.createToolText) {
    els.createToolText.value = String(state.customToolDraft?.description || "");
  }
  panel.style.left = "50%";
  panel.style.top = "50%";
  panel.style.transform = "translate(-50%, -50%)";
  panel.classList.remove("hidden");
  bumpTabUiVersion("customToolDock");
  renderCreateToolPreview();
  renderCustomToolDock();
  setTimeout(() => {
    try {
      if (els.createToolText) els.createToolText.focus();
    } catch {
      // ignore
    }
  }, 0);
}

function invokeRegisteredTool(
  toolId,
  {
    activeImageId = null,
    selectedImageIds = null,
    source = "custom_tool_dock",
    trigger = "click",
  } = {}
) {
  const tool = sessionToolRegistry.get(toolId);
  if (!tool) {
    throw new Error(`Unknown custom tool: ${toolId}`);
  }
  const activeId = String(activeImageId || state.activeId || "").trim();
  const selection = Array.isArray(selectedImageIds) ? selectedImageIds : getSelectedIds();
  const normalizedSelection = selection.map((id) => String(id || "").trim()).filter(Boolean);
  const minImages = Math.max(1, Number(tool.inputContract?.minImages) || 1);
  const maxImages = Math.max(minImages, Number(tool.inputContract?.maxImages) || minImages);

  if (tool.inputContract?.requiresActiveImage && !activeId) {
    showToast("Select an image before running a custom tool.", "tip", 2200);
    return null;
  }
  if (normalizedSelection.length < minImages) {
    showToast(`${tool.label}: select at least ${minImages} image${minImages === 1 ? "" : "s"}.`, "tip", 2200);
    return null;
  }
  if (normalizedSelection.length > maxImages) {
    showToast(`${tool.label}: select no more than ${maxImages} image${maxImages === 1 ? "" : "s"}.`, "tip", 2200);
    return null;
  }

  const invocation = buildToolInvocation(tool, {
    activeImageId: activeId || null,
    selectedImageIds: normalizedSelection,
    source,
    trigger,
    requestId: `tool-runtime-${state.toolInvocationSeq++}`,
  });
  state.lastToolInvocation = invocation;
  state.activeCustomToolId = tool.toolId;
  markActiveTabUiDirty({ quickActions: true, customToolDock: true });
  recordUserEvent("custom_tool_invoked", {
    tool_id: tool.toolId,
    operation: tool.execution?.operation || null,
    selection_count: normalizedSelection.length,
    source,
  });
  setStatus(`Tool runtime: dispatched ${tool.label}`);
  showToast(`${tool.label}: dispatched to the edit runtime.`, "tip", 2200);
  renderCustomToolDock();
  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent(TOOL_INVOCATION_EVENT, { detail: cloneToolRuntimeValue(invocation) }));
  }
  return invocation;
}

function publishToolRuntimeBridge() {
  if (typeof window === "undefined") return;
  window[TOOL_RUNTIME_BRIDGE_KEY] = Object.freeze({
    createToolContract: CREATE_TOOL_INVOCATION_CONTRACT,
    manifestSchema: TOOL_MANIFEST_SCHEMA,
    invocationSchema: TOOL_INVOCATION_SCHEMA,
    invocationEvent: TOOL_INVOCATION_EVENT,
    listTools: () => sessionToolRegistry.list(),
    getTool: (toolId) => sessionToolRegistry.get(toolId),
    previewCreateTool: ({ name = "", description = "" } = {}) =>
      buildCreateToolInvocation({
        name,
        description,
        existingIds: state.sessionTools.map((tool) => String(tool?.toolId || "").trim()).filter(Boolean),
        source: "bridge",
        trigger: "preview",
      }),
    createTool: ({ name = "", description = "" } = {}) => {
      const manifest = sessionToolRegistry.createFromDescription({ name, description });
      syncSessionToolsFromRegistry();
      state.activeCustomToolId = manifest.toolId;
      renderQuickActions();
      renderCreateToolPreview();
      return manifest;
    },
    invokeTool: ({ toolId, activeImageId = null, selectedImageIds = null, source = "bridge", trigger = "api" } = {}) =>
      invokeRegisteredTool(toolId, {
        activeImageId,
        selectedImageIds,
        source,
        trigger,
      }),
    getLastInvocation: () => cloneToolRuntimeValue(state.lastToolInvocation),
  });
}

async function runCreateToolFromPanel() {
  bumpInteraction();
  const draft = captureCreateToolDraftFromUi();
  if (!draft.description) {
    showToast("Create Tool: describe the tool first.", "tip", 2200);
    if (els.createToolText) {
      try {
        els.createToolText.focus();
      } catch {
        // ignore
      }
    }
    return null;
  }
  const manifest = sessionToolRegistry.createFromDescription(draft);
  syncSessionToolsFromRegistry();
  state.activeCustomToolId = manifest.toolId;
  recordUserEvent("custom_tool_created", {
    tool_id: manifest.toolId,
    operation: manifest.execution?.operation || null,
  });
  hideCreateToolPanel({ clearDraft: true });
  renderQuickActions();
  showToast(`Tool added: ${manifest.label}.`, "tip", 2200);
  setStatus(`Tool runtime: ${manifest.label} ready`);
  return manifest;
}

function agentRunnerPanelVisible() {
  return Boolean(els.agentRunnerPanel && !els.agentRunnerPanel.classList.contains("hidden"));
}

function agentRunnerActive(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const evaluationStatus = readFirstString(record?.finalEvaluation?.status).toLowerCase();
  return Boolean(record.running || record.autoRunning || record.stopRequested || evaluationStatus === "pending");
}

function latestAgentRunnerLogEntry(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const log = Array.isArray(record.log) ? record.log : [];
  return log.length ? log[log.length - 1] : null;
}

function resolveAgentRunnerActivitySummary(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const evaluation = asRecord(record?.finalEvaluation);
  const evaluationStatus = readFirstString(evaluation?.status).toLowerCase();
  const stopCheck = asRecord(record?.lastStopCheck);
  if (stopCheck?.status === "ready" && stopCheck.allowStop === false) {
    return clampText(readFirstString(stopCheck.summary) || "Visible hard requirements are still missing.", 160);
  }
  if (evaluationStatus === "pending") return "Scoring the visible result against the goal.";
  if (record.stopRequested) return "Stopping after the current step finishes.";
  if (evaluationStatus === "ready" && Number.isFinite(Number(evaluation?.score))) {
    return `Final score ${Math.round(Number(evaluation.score))} / 100.`;
  }
  if (evaluationStatus === "failed") {
    return readFirstString(evaluation?.error) || "Final scoring was unavailable.";
  }
  const planSummary = readFirstString(record?.lastPlan?.summary);
  if (planSummary) return clampText(planSummary, 160);
  const lastMessage = readFirstString(latestAgentRunnerLogEntry(record)?.message);
  if (lastMessage) return clampText(lastMessage, 160);
  if (record.autoRunning || record.running) return "Agent Run is controlling the canvas.";
  if (String(record.goal || "").trim()) return "Goal ready. Step it or let it run.";
  return "Give the agent a goal, then step it or let it run.";
}

function resolveAgentRunnerBannerMode(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const evaluationStatus = readFirstString(record?.finalEvaluation?.status).toLowerCase();
  if (evaluationStatus === "pending") return "Agent Run · scoring";
  if (record.stopRequested) return "Agent Run · stopping";
  if (record.autoRunning) return "Agent Run · auto";
  if (record.running) return "Agent Run · step";
  return "Agent Run";
}

function resolveAgentRunnerBannerStepLabel(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const stepCount = Math.max(0, Number(record.stepCount) || 0);
  const evaluationStatus = readFirstString(record?.finalEvaluation?.status).toLowerCase();
  if (evaluationStatus === "pending") return "Scoring";
  if (record.stopRequested) return stepCount > 0 ? `Finishing step ${stepCount}` : "Finishing";
  if (record.autoRunning) return stepCount > 0 ? `Step ${stepCount}` : "Preparing";
  if (record.running) return stepCount > 0 ? `Step ${stepCount}` : "Preparing";
  return "Idle";
}

function resolveAgentRunnerBannerDetail(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const limit = resolveAgentRunnerActionBudgetLimit(record);
  const used = roundAgentRunnerBudgetValue(record.budgetUsed);
  if (!(used > 0) && !(record.autoRunning || record.running)) return "";
  return `Budget ${formatAgentRunnerBudgetValue(used)} / ${formatAgentRunnerBudgetValue(limit)}`;
}

function renderAgentRunnerBanner() {
  if (!els.agentRunnerBanner) return;
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const visible = agentRunnerActive(runner) && !agentRunnerPanelVisible();
  els.agentRunnerBanner.classList.toggle("hidden", !visible);
  if (!visible) return;
  const evaluationStatus = readFirstString(runner?.finalEvaluation?.status).toLowerCase();
  const stateKey = evaluationStatus === "pending"
    ? "scoring"
    : runner.stopRequested
      ? "stopping"
      : runner.autoRunning
        ? "auto"
        : runner.running
          ? "step"
          : "idle";
  els.agentRunnerBanner.dataset.state = stateKey;
  if (els.agentRunnerBannerMode) {
    els.agentRunnerBannerMode.textContent = resolveAgentRunnerBannerMode(runner);
  }
  if (els.agentRunnerBannerStep) {
    els.agentRunnerBannerStep.textContent = resolveAgentRunnerBannerStepLabel(runner);
  }
  if (els.agentRunnerBannerSummary) {
    els.agentRunnerBannerSummary.textContent = resolveAgentRunnerActivitySummary(runner);
  }
  if (els.agentRunnerBannerDetail) {
    const detailText = resolveAgentRunnerBannerDetail(runner);
    els.agentRunnerBannerDetail.textContent = detailText;
    els.agentRunnerBannerDetail.classList.toggle("hidden", !detailText);
  }
  if (els.agentRunnerBannerStop) {
    els.agentRunnerBannerStop.disabled = !(runner.running || runner.autoRunning);
  }
}

function renderAgentRunnerActivityChrome() {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const active = agentRunnerActive(runner);
  const panelVisible = agentRunnerPanelVisible();
  const openTitleBase = active
    ? panelVisible
      ? "Hide Agent Run and watch the canvas"
      : "Show Agent Run"
    : panelVisible
      ? "Hide Agent Run"
      : "Open Agent Run";
  const openTitle = appendActionProvenanceDescription(openTitleBase, ACTION_PROVENANCE.EXTERNAL_MODEL);
  if (els.juggernautAgentRunnerOpen) {
    syncActionProvenanceBadge(els.juggernautAgentRunnerOpen, ACTION_PROVENANCE.EXTERNAL_MODEL);
    els.juggernautAgentRunnerOpen.title = openTitle;
    els.juggernautAgentRunnerOpen.setAttribute("aria-label", openTitle);
    els.juggernautAgentRunnerOpen.classList.toggle("is-ready", state.images.length > 0);
    els.juggernautAgentRunnerOpen.classList.toggle("is-active-request", active || panelVisible);
    els.juggernautAgentRunnerOpen.classList.toggle("is-agent-runner-live", active);
  }
  if (els.canvasWrap) {
    els.canvasWrap.classList.toggle("agent-runner-active", active);
    els.canvasWrap.classList.toggle("agent-runner-auto", Boolean(runner.autoRunning));
    els.canvasWrap.classList.toggle("agent-runner-stopping", Boolean(runner.stopRequested));
    const evaluationStatus = readFirstString(runner?.finalEvaluation?.status).toLowerCase();
    els.canvasWrap.dataset.agentRunnerState = active
      ? evaluationStatus === "pending"
        ? "scoring"
        : runner.stopRequested
          ? "stopping"
          : runner.autoRunning
            ? "auto"
            : "step"
      : "idle";
  }
  renderAgentRunnerBanner();
}

function collapseAgentRunnerPanelToBanner() {
  if (!els.agentRunnerPanel) return false;
  els.agentRunnerPanel.classList.add("hidden");
  renderQuickActions();
  renderAgentRunnerActivityChrome();
  return true;
}

function buildAgentRunnerBridgeSnapshot() {
  const runner = asRecord(state.agentRunner) || createFreshAgentRunnerState();
  return {
    goal: String(runner.goal || ""),
    goalContract: cloneToolRuntimeValue(runner.goalContract),
    goalContractStatus: readFirstString(runner.goalContractStatus) || "idle",
    goalContractSourceGoal: String(runner.goalContractSourceGoal || ""),
    lastStopCheck: cloneToolRuntimeValue(runner.lastStopCheck),
    panelExpanded: Boolean(runner.panelExpanded),
    plannerMode: String(runner.plannerMode || "auto"),
    maxSteps: Math.max(1, Math.min(AGENT_RUNNER_MAX_STEPS_LIMIT, Number(runner.maxSteps) || AGENT_RUNNER_DEFAULT_MAX_STEPS)),
    stepCount: Math.max(0, Number(runner.stepCount) || 0),
    budgetUsed: roundAgentRunnerBudgetValue(runner.budgetUsed),
    budgetLimit: resolveAgentRunnerActionBudgetLimit(runner),
    budgetRemaining: agentRunnerBudgetRemaining(runner),
    reviewRequestId: readFirstString(runner.reviewRequestId) || null,
    running: Boolean(runner.running),
    autoRunning: Boolean(runner.autoRunning),
    stopRequested: Boolean(runner.stopRequested),
    lastPlan: cloneToolRuntimeValue(runner.lastPlan),
    lastPlanRawText: String(runner.lastPlanRawText || ""),
    lastContextSummary: cloneToolRuntimeValue(runner.lastContextSummary),
    finalEvaluation: cloneToolRuntimeValue(runner.finalEvaluation),
    log: cloneToolRuntimeValue(runner.log || []),
    panelVisible: agentRunnerPanelVisible(),
    activitySummary: resolveAgentRunnerActivitySummary(runner),
  };
}

function publishAgentRunnerStateEvent() {
  if (typeof window === "undefined") return null;
  const detail = buildAgentRunnerBridgeSnapshot();
  window.dispatchEvent(new CustomEvent(AGENT_RUNNER_STATE_EVENT, { detail }));
  return detail;
}

function publishAgentRunnerLogEvent(entry = null) {
  if (typeof window === "undefined" || !entry) return null;
  const detail = cloneToolRuntimeValue(entry);
  window.dispatchEvent(new CustomEvent(AGENT_RUNNER_LOG_EVENT, { detail }));
  return detail;
}

function renderAgentRunnerPlannerOptions() {
  if (!els.agentRunnerPlanner) return;
  if (els.agentRunnerPlanner.dataset.bound === "1") return;
  const frag = document.createDocumentFragment();
  for (const option of agentRunnerPlanner.plannerOptions || []) {
    const el = document.createElement("option");
    el.value = String(option?.id || "");
    el.textContent = String(option?.label || option?.id || "");
    frag.appendChild(el);
  }
  els.agentRunnerPlanner.innerHTML = "";
  els.agentRunnerPlanner.appendChild(frag);
  els.agentRunnerPlanner.dataset.bound = "1";
}

function normalizeAgentRunnerMaxSteps(value) {
  return Math.max(1, Math.min(AGENT_RUNNER_MAX_STEPS_LIMIT, Number(value) || AGENT_RUNNER_DEFAULT_MAX_STEPS));
}

const AGENT_RUNNER_ACTION_BUDGET_COSTS = Object.freeze({
  set_active_image: 0.25,
  set_selected_images: 0.25,
  marker_stroke: 0.5,
  magic_select_click: 0.5,
  eraser_stroke: 0.5,
});

const AGENT_RUNNER_MIN_ACTION_BUDGET_COST = Math.min(
  ...Object.values(AGENT_RUNNER_ACTION_BUDGET_COSTS).filter((value) => Number(value) > 0)
);

const AGENT_RUNNER_REVIEW_PROPOSAL_STOP_WORDS = new Set([
  "a",
  "an",
  "and",
  "are",
  "as",
  "at",
  "be",
  "both",
  "clearly",
  "context",
  "depicted",
  "do",
  "for",
  "from",
  "he",
  "her",
  "him",
  "his",
  "in",
  "into",
  "is",
  "it",
  "its",
  "james",
  "lebron",
  "must",
  "of",
  "on",
  "or",
  "over",
  "past",
  "performing",
  "player",
  "shown",
  "that",
  "the",
  "their",
  "them",
  "they",
  "this",
  "to",
  "visible",
  "visibly",
  "with",
]);

const AGENT_RUNNER_REVIEW_WEAK_SHORTCUT_PATTERN =
  /\b(face|faces|likeness|look like|looks like|restyle|restyled|recolor|recolored|palette|uniform|jersey|colorway)\b/i;

function roundAgentRunnerBudgetValue(value = 0) {
  return Math.round((Number(value) || 0) * 100) / 100;
}

function formatAgentRunnerBudgetValue(value = 0) {
  const rounded = roundAgentRunnerBudgetValue(value);
  return Number.isInteger(rounded)
    ? String(rounded)
    : rounded.toFixed(2).replace(/\.?0+$/, "");
}

function isAgentRunnerExportAction(action = null) {
  const actionType = readFirstString(action?.type).toLowerCase();
  return actionType === "export" || actionType === "export_psd";
}

function agentRunnerExportFormat(action = null) {
  const actionType = readFirstString(action?.type).toLowerCase();
  if (actionType === "export_psd") return "psd";
  return normalizeExportFormat(action?.format || "psd");
}

function isAgentRunnerTerminalAction(action = null) {
  const actionType = readFirstString(action?.type).toLowerCase();
  return actionType === "stop" || isAgentRunnerExportAction(action);
}

function resolveAgentRunnerActionBudgetCost(action = null) {
  const actionType = readFirstString(action?.type).toLowerCase();
  if (!actionType || actionType === "stop" || isAgentRunnerExportAction(action)) return 0;
  return Number(AGENT_RUNNER_ACTION_BUDGET_COSTS[actionType]) || 1;
}

function resolveAgentRunnerActionBudgetLimit(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  return normalizeAgentRunnerMaxSteps(record.maxSteps);
}

function agentRunnerBudgetRemaining(runner = null) {
  const limit = resolveAgentRunnerActionBudgetLimit(runner);
  const used = roundAgentRunnerBudgetValue(asRecord(runner)?.budgetUsed ?? state.agentRunner?.budgetUsed ?? 0);
  return Math.max(0, roundAgentRunnerBudgetValue(limit - used));
}

function buildAgentRunnerRunStateSummary(runner = null) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const limit = resolveAgentRunnerActionBudgetLimit(record);
  const used = roundAgentRunnerBudgetValue(record.budgetUsed);
  return {
    stepCount: Math.max(0, Number(record.stepCount) || 0),
    maxSteps: limit,
    actionBudget: {
      limit,
      used,
      remaining: Math.max(0, roundAgentRunnerBudgetValue(limit - used)),
      discountedActionTypes: Object.keys(AGENT_RUNNER_ACTION_BUDGET_COSTS),
    },
  };
}

function clearAgentRunnerReviewReuseState(runner = null) {
  const record = asRecord(runner) || state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  record.reviewRequestId = null;
  record.reviewContextSignature = "";
  record.reviewSourceGoal = "";
  return record;
}

function rememberAgentRunnerReviewReuseState(runner = null, { requestId = null, contextSignature = "", goal = "" } = {}) {
  const record = asRecord(runner) || state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  record.reviewRequestId = readFirstString(requestId) || null;
  record.reviewContextSignature = readFirstString(contextSignature) || "";
  record.reviewSourceGoal = String(goal || "").trim();
  return record;
}

function agentRunnerActionInvalidatesReviewReuse(action = null) {
  const actionType = readFirstString(action?.type).toLowerCase();
  return [
    "accept_review_proposal",
    "invoke_seeded_tool",
    "invoke_direct_affordance",
    "invoke_custom_tool",
  ].includes(actionType);
}

function resolveAgentRunnerReviewReuseState({
  runner = null,
  goal = "",
  goalContract = null,
  reviewState = null,
  reviewPayload = null,
} = {}) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const nextGoal = String(goal || "").trim();
  const currentRequestId =
    readFirstString(reviewState?.request?.requestId, reviewState?.requestId, record.reviewRequestId) || null;
  const contextSignature = buildAgentRunnerReviewContextSignatureFromPayload(reviewPayload);
  const currentSignature = buildAgentRunnerReviewContextSignatureFromState(reviewState);
  const goalMatchesCurrentGoal = Boolean(nextGoal) && readFirstString(record.reviewSourceGoal) === nextGoal;
  const runnerContextMatches = Boolean(contextSignature) && readFirstString(record.reviewContextSignature) === contextSignature;
  const reviewStateContextMatches = Boolean(contextSignature) && currentSignature === contextSignature;
  const contextMatchesVisiblePrep = runnerContextMatches && reviewStateContextMatches;
  const reviewStatus = readFirstString(reviewState?.status).toLowerCase();
  const proposals = Array.isArray(reviewState?.proposals) ? reviewState.proposals : [];
  const hasReadyProposals = reviewStatus === "ready" && proposals.length > 0;
  const plausibleReadyProposal = hasReadyProposals
    ? agentRunnerReviewHasPlausibleReadyProposal(reviewState, goalContract)
    : false;
  const canReuseReadyReview = Boolean(goalMatchesCurrentGoal && contextMatchesVisiblePrep && reviewStatus === "ready" && currentRequestId);
  let reason = "review_unavailable";
  if (!goalMatchesCurrentGoal) {
    reason = nextGoal ? "goal_changed" : "missing_goal";
  } else if (!contextSignature) {
    reason = "review_context_unavailable";
  } else if (!runnerContextMatches) {
    reason = "runner_context_changed";
  } else if (!reviewStateContextMatches) {
    reason = "review_state_mismatch";
  } else if (canReuseReadyReview) {
    reason = "same_goal_same_canvas_ready_review";
  } else if (reviewStatus) {
    reason = `review_${reviewStatus}`;
  }
  return {
    requestId: currentRequestId,
    contextSignature,
    reviewStatus,
    goalMatchesCurrentGoal,
    contextMatchesVisiblePrep,
    hasReadyProposals,
    plausibleReadyProposal,
    canReuseReadyReview,
    reason,
  };
}

function buildAgentRunnerReviewContextSnapshotFromPayload(reviewPayload = null) {
  const payload = asRecord(reviewPayload) || {};
  const canvas = asRecord(payload.canvas) || {};
  const communication = asRecord(payload.communication) || {};
  const visibleImages = Array.isArray(canvas.visibleImages) ? canvas.visibleImages : [];
  const marks = Array.isArray(communication.marks) ? communication.marks : [];
  const regionSelections = Array.isArray(communication.regionSelections) ? communication.regionSelections : [];
  return {
    activeImageId: readFirstString(canvas.activeImageId) || null,
    selectedImageIds: (Array.isArray(canvas.selectedImageIds) ? canvas.selectedImageIds : [])
      .map((value) => readFirstString(value))
      .filter(Boolean),
    visibleImageIds: visibleImages
      .map((image) => readFirstString(image?.id))
      .filter(Boolean),
    markIds: marks.map((mark) => readFirstString(mark?.id)).filter(Boolean),
    regionCandidateIds: regionSelections
      .map((group) => readFirstString(group?.chosenCandidateId))
      .filter(Boolean),
    reviewTool: readFirstString(communication.tool) || null,
  };
}

function buildAgentRunnerReviewContextSnapshotFromState(reviewState = null) {
  const request = asRecord(reviewState?.request) || asRecord(reviewState) || {};
  return {
    activeImageId: readFirstString(request?.primaryImageId, request?.activeImageId) || null,
    selectedImageIds: (Array.isArray(request?.selectedImageIds) ? request.selectedImageIds : [])
      .map((value) => readFirstString(value))
      .filter(Boolean),
    visibleImageIds: (Array.isArray(request?.imageIdsInView) ? request.imageIdsInView : [])
      .map((value) => readFirstString(value))
      .filter(Boolean),
    markIds: (Array.isArray(request?.markIds) ? request.markIds : [])
      .map((value) => readFirstString(value))
      .filter(Boolean),
    regionCandidateIds: [readFirstString(request?.activeRegionCandidateId)].filter(Boolean),
    reviewTool: readFirstString(request?.reviewTool) || null,
  };
}

function sortAgentRunnerSignatureValue(value = null) {
  if (Array.isArray(value)) {
    return value.map((entry) => sortAgentRunnerSignatureValue(entry));
  }
  if (!value || typeof value !== "object") return value;
  return Object.keys(value)
    .sort()
    .reduce((acc, key) => {
      acc[key] = sortAgentRunnerSignatureValue(value[key]);
      return acc;
    }, {});
}

function buildAgentRunnerReviewContextSignatureFromPayload(reviewPayload = null) {
  const snapshot = buildAgentRunnerReviewContextSnapshotFromPayload(reviewPayload);
  return JSON.stringify(sortAgentRunnerSignatureValue(snapshot));
}

function buildAgentRunnerReviewContextSignatureFromState(reviewState = null) {
  const snapshot = buildAgentRunnerReviewContextSnapshotFromState(reviewState);
  return JSON.stringify(sortAgentRunnerSignatureValue(snapshot));
}

function tokenizeAgentRunnerReviewProposalText(text = "") {
  return String(text || "")
    .toLowerCase()
    .match(/[a-z0-9]+/g) || [];
}

function collectAgentRunnerProposalGoalTokens(goalContract = null) {
  const contract = asRecord(goalContract) || {};
  const hardRequirements = asRecord(contract.hardRequirements) || {};
  const entityTokens = new Set();
  for (const entity of Array.isArray(hardRequirements.entities) ? hardRequirements.entities : []) {
    for (const token of tokenizeAgentRunnerReviewProposalText(readFirstString(entity?.name))) {
      if (token.length >= 3) entityTokens.add(token);
    }
  }
  const sources = [];
  for (const interaction of Array.isArray(hardRequirements.interactions) ? hardRequirements.interactions : []) {
    sources.push(readFirstString(interaction?.type));
    sources.push(readFirstString(interaction?.description));
    sources.push(readFirstString(interaction?.sport));
  }
  for (const objectEntry of Array.isArray(hardRequirements.objects) ? hardRequirements.objects : []) {
    sources.push(readFirstString(objectEntry?.name));
  }
  for (const cue of Array.isArray(hardRequirements.sceneCues) ? hardRequirements.sceneCues : []) {
    sources.push(readFirstString(cue));
  }
  const tokens = new Set();
  for (const source of sources) {
    for (const token of tokenizeAgentRunnerReviewProposalText(source)) {
      if (token.length < 4) continue;
      if (entityTokens.has(token) || AGENT_RUNNER_REVIEW_PROPOSAL_STOP_WORDS.has(token)) continue;
      tokens.add(token);
    }
  }
  return Array.from(tokens);
}

function countAgentRunnerProposalGoalTokenHits(text = "", tokens = []) {
  const normalizedText = ` ${String(text || "").toLowerCase()} `;
  let hits = 0;
  for (const token of Array.isArray(tokens) ? tokens : []) {
    if (!token) continue;
    if (normalizedText.includes(` ${String(token).toLowerCase()} `)) hits += 1;
  }
  return hits;
}

function agentRunnerReviewHasPlausibleReadyProposal(reviewState = null, goalContract = null) {
  const proposals = Array.isArray(reviewState?.proposals) ? reviewState.proposals : [];
  if (!proposals.length) return false;
  const contract = asRecord(goalContract);
  if (!contract) return true;
  const goalType = readFirstString(contract?.goalType).toLowerCase();
  const hardRequirements = asRecord(contract?.hardRequirements) || {};
  const interactionGoal =
    goalType === "directed_action" ||
    goalType === "competition" ||
    (Array.isArray(hardRequirements.interactions) && hardRequirements.interactions.length > 0);
  const goalTokens = collectAgentRunnerProposalGoalTokens(contract);
  return proposals.some((proposal) => {
    const text = [
      readFirstString(proposal?.label),
      readFirstString(proposal?.title),
      readFirstString(proposal?.actionType, proposal?.actionIntent),
      readFirstString(proposal?.why),
      readFirstString(proposal?.previewBrief),
      readFirstString(proposal?.applyBrief),
      ...(Array.isArray(proposal?.negativeConstraints) ? proposal.negativeConstraints : []).map((entry) =>
        readFirstString(entry)
      ),
    ]
      .filter(Boolean)
      .join(" ");
    const tokenHits = countAgentRunnerProposalGoalTokenHits(text, goalTokens);
    const weakShortcut = AGENT_RUNNER_REVIEW_WEAK_SHORTCUT_PATTERN.test(text);
    if (interactionGoal) {
      return tokenHits >= 2 && !weakShortcut;
    }
    if (goalTokens.length) {
      return tokenHits >= 1 || !weakShortcut;
    }
    return !weakShortcut;
  });
}

function captureAgentRunnerDraftFromUi() {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const nextGoal = String(els.agentRunnerGoal?.value || runner.goal || "").trim();
  const goalChanged = nextGoal !== String(runner.goal || "");
  runner.goal = nextGoal;
  if (goalChanged) {
    runner.budgetUsed = 0;
    runner.goalContract = null;
    runner.goalContractRawText = "";
    runner.goalContractSourceGoal = "";
    runner.goalContractStatus = "idle";
    runner.goalContractPromise = null;
    runner.lastStopCheck = null;
    clearAgentRunnerReviewReuseState(runner);
  }
  runner.plannerMode = readFirstString(els.agentRunnerPlanner?.value, runner.plannerMode, "auto") || "auto";
  runner.maxSteps = normalizeAgentRunnerMaxSteps(els.agentRunnerMaxSteps?.value ?? runner.maxSteps);
  return runner;
}

function formatAgentRunnerLogDetail(detail = null) {
  if (detail == null) return "";
  if (typeof detail === "string") return detail;
  try {
    return JSON.stringify(detail, null, 2);
  } catch {
    return String(detail);
  }
}

function appendAgentRunnerLog(kind = "info", message = "", detail = null, extras = {}) {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const entry = {
    id: `agent-runner-log-${Date.now()}-${Math.floor(Math.random() * 1e6)}`,
    at: new Date().toISOString(),
    kind: String(kind || "info"),
    message: String(message || "").trim() || "Agent runner update.",
    detail: formatAgentRunnerLogDetail(detail),
    actionType: readFirstString(extras?.actionType) || null,
    ok: extras?.ok == null ? null : Boolean(extras.ok),
  };
  runner.log = [...(Array.isArray(runner.log) ? runner.log : []), entry].slice(-AGENT_RUNNER_LOG_LIMIT);
  renderAgentRunnerPanel();
  publishAgentRunnerLogEvent(entry);
  return entry;
}

function clearAgentRunnerLog() {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  runner.log = [];
  runner.lastPlan = null;
  runner.lastPlanRawText = "";
  runner.lastContextSummary = null;
  runner.lastStopCheck = null;
  runner.finalEvaluation = null;
  runner.stepCount = 0;
  runner.budgetUsed = 0;
  clearAgentRunnerReviewReuseState(runner);
  renderAgentRunnerPanel();
  publishAgentRunnerStateEvent();
  return buildAgentRunnerBridgeSnapshot();
}

function buildAgentRunnerClipboardText() {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const sections = [];
  const goal = String(runner.goal || "").trim();
  const goalContract = asRecord(runner.goalContract);
  const lastPlan = runner.lastPlan ? JSON.stringify(runner.lastPlan, null, 2) : "No step yet.";
  const finalEvaluation = asRecord(runner.finalEvaluation);
  const log = Array.isArray(runner.log) ? runner.log : [];

  sections.push("Goal");
  sections.push(goal || "(empty)");
  sections.push("");
  sections.push("Goal Contract");
  if (!goalContract) {
    const goalContractStatus = readFirstString(runner.goalContractStatus).toLowerCase();
    if (goalContractStatus === "failed") {
      sections.push("Goal contract unavailable.");
    } else if (goalContractStatus === "pending") {
      sections.push("Goal contract is still compiling in the background.");
    } else {
      sections.push("No goal contract yet.");
    }
  } else {
    sections.push(JSON.stringify(goalContract, null, 2));
  }
  sections.push("");
  sections.push("Last Plan");
  sections.push(lastPlan);
  sections.push("");
  sections.push("Final Score");
  if (!finalEvaluation) {
    sections.push("No final score yet.");
  } else if (readFirstString(finalEvaluation.status).toLowerCase() === "pending") {
    sections.push("Scoring the visible result against the goal...");
  } else if (readFirstString(finalEvaluation.status).toLowerCase() === "ready") {
    sections.push(`${Math.max(0, Math.min(100, Math.round(Number(finalEvaluation.score) || 0)))} / 100`);
    if (readFirstString(finalEvaluation.verdict)) sections.push(readFirstString(finalEvaluation.verdict));
    const strengths = Array.isArray(finalEvaluation.strengths) ? finalEvaluation.strengths.filter(Boolean) : [];
    if (strengths.length) sections.push(`Strengths: ${strengths.join(" | ")}`);
    const misses = Array.isArray(finalEvaluation.misses) ? finalEvaluation.misses.filter(Boolean) : [];
    if (misses.length) sections.push(`Misses: ${misses.join(" | ")}`);
    const uxSuggestions = Array.isArray(finalEvaluation.uxSuggestions) ? finalEvaluation.uxSuggestions.filter(Boolean) : [];
    if (uxSuggestions.length) sections.push(`UX Suggestions: ${uxSuggestions.join(" | ")}`);
    const agentSuggestions = Array.isArray(finalEvaluation.agentSuggestions) ? finalEvaluation.agentSuggestions.filter(Boolean) : [];
    if (agentSuggestions.length) sections.push(`Agent Suggestions: ${agentSuggestions.join(" | ")}`);
    const suggestions =
      Array.isArray(finalEvaluation.suggestions) && !uxSuggestions.length && !agentSuggestions.length
        ? finalEvaluation.suggestions.filter(Boolean)
        : [];
    if (suggestions.length) sections.push(`Suggestions: ${suggestions.join(" | ")}`);
  } else {
    sections.push(readFirstString(finalEvaluation.error) || "Final score unavailable.");
  }
  sections.push("");
  sections.push("Activity");

  if (!log.length) {
    sections.push("No agent steps yet.");
  } else {
    for (const entry of log) {
      const stamp = new Date(entry?.at || Date.now());
      const time = Number.isNaN(stamp.getTime())
        ? "Now"
        : stamp.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });
      sections.push(`${String(entry?.kind || "info").toUpperCase()} ${time}`);
      sections.push(String(entry?.message || "").trim() || "Agent runner update.");
      const detail = String(entry?.detail || "").trim();
      if (detail) sections.push(detail);
      sections.push("");
    }
  }

  return sections.join("\n").trim();
}

function renderAgentRunnerFinalEvaluation() {
  if (!els.agentRunnerScore) return;
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const evaluation = asRecord(runner.finalEvaluation);
  const status = readFirstString(evaluation?.status).toLowerCase();
  els.agentRunnerScore.dataset.state = status || "idle";
  if (!evaluation) {
    els.agentRunnerScore.textContent = "No final score yet.";
    return;
  }
  if (status === "pending") {
    els.agentRunnerScore.textContent = "Scoring the visible result against the goal...";
    return;
  }
  if (status === "failed") {
    els.agentRunnerScore.textContent = readFirstString(evaluation?.error) || "Final score unavailable.";
    return;
  }
  const lines = [];
  lines.push(`${Math.max(0, Math.min(100, Math.round(Number(evaluation?.score) || 0)))} / 100`);
  if (readFirstString(evaluation?.verdict)) lines.push(readFirstString(evaluation.verdict));
  const strengths = Array.isArray(evaluation?.strengths) ? evaluation.strengths.filter(Boolean) : [];
  if (strengths.length) lines.push(`Strengths: ${strengths.join(" | ")}`);
  const misses = Array.isArray(evaluation?.misses) ? evaluation.misses.filter(Boolean) : [];
  if (misses.length) lines.push(`Misses: ${misses.join(" | ")}`);
  const uxSuggestions = Array.isArray(evaluation?.uxSuggestions) ? evaluation.uxSuggestions.filter(Boolean) : [];
  if (uxSuggestions.length) lines.push(`UX Suggestions: ${uxSuggestions.join(" | ")}`);
  const agentSuggestions = Array.isArray(evaluation?.agentSuggestions) ? evaluation.agentSuggestions.filter(Boolean) : [];
  if (agentSuggestions.length) lines.push(`Agent Suggestions: ${agentSuggestions.join(" | ")}`);
  const suggestions =
    Array.isArray(evaluation?.suggestions) && !uxSuggestions.length && !agentSuggestions.length
      ? evaluation.suggestions.filter(Boolean)
      : [];
  if (suggestions.length) lines.push(`Suggestions: ${suggestions.join(" | ")}`);
  els.agentRunnerScore.textContent = lines.join("\n");
}

async function copyAgentRunnerLogToClipboard() {
  const text = buildAgentRunnerClipboardText();
  if (!text) {
    showToast("Agent Run: nothing to copy yet.", "tip", 1800);
    return false;
  }
  try {
    await navigator.clipboard.writeText(text);
    showToast("Agent Run logs copied.", "tip", 1800);
    return true;
  } catch {
    showToast("Could not copy Agent Run logs.", "error", 2200);
    return false;
  }
}

function renderAgentRunnerLog() {
  if (!els.agentRunnerLog) return;
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  els.agentRunnerLog.innerHTML = "";
  const log = Array.isArray(runner.log) ? runner.log : [];
  if (!log.length) {
    const empty = document.createElement("div");
    empty.className = "agent-runner-log-entry";
    empty.dataset.kind = "info";
    empty.innerHTML = [
      '<div class="agent-runner-log-head">',
      '<span class="agent-runner-log-kind">Ready</span>',
      '<span class="agent-runner-log-time">Now</span>',
      "</div>",
      '<div class="agent-runner-log-message">No agent steps yet.</div>',
      '<div class="agent-runner-log-detail">Enter a goal, then click Step or Auto.</div>',
    ].join("");
    els.agentRunnerLog.appendChild(empty);
    return;
  }
  for (const entry of log.slice().reverse()) {
    const root = document.createElement("div");
    root.className = "agent-runner-log-entry";
    root.dataset.kind = String(entry?.kind || "info");

    const head = document.createElement("div");
    head.className = "agent-runner-log-head";

    const kind = document.createElement("span");
    kind.className = "agent-runner-log-kind";
    kind.textContent = String(entry?.kind || "info");
    head.appendChild(kind);

    const time = document.createElement("span");
    time.className = "agent-runner-log-time";
    const stamp = new Date(entry?.at || Date.now());
    time.textContent = Number.isNaN(stamp.getTime())
      ? "Now"
      : stamp.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", second: "2-digit" });
    head.appendChild(time);

    const message = document.createElement("div");
    message.className = "agent-runner-log-message";
    message.textContent = String(entry?.message || "");

    root.appendChild(head);
    root.appendChild(message);

    const detailText = String(entry?.detail || "").trim();
    if (detailText) {
      const detail = document.createElement("div");
      detail.className = "agent-runner-log-detail";
      detail.textContent = detailText;
      root.appendChild(detail);
    }
    els.agentRunnerLog.appendChild(root);
  }
}

function renderAgentRunnerPanel() {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const expanded = Boolean(runner.panelExpanded);
  const setAgentRunnerButtonLabel = (button, label) => {
    if (!button) return;
    const labelNode = button.querySelector(".agent-runner-button-label");
    if (labelNode) {
      labelNode.textContent = label;
      return;
    }
    button.textContent = label;
  };
  renderAgentRunnerPlannerOptions();
  if (els.agentRunnerPanel) {
    els.agentRunnerPanel.classList.toggle("is-expanded", expanded);
    els.agentRunnerPanel.classList.toggle("is-collapsed", !expanded);
  }
  if (els.agentRunnerGoal && document.activeElement !== els.agentRunnerGoal) {
    els.agentRunnerGoal.value = String(runner.goal || "");
  }
  if (els.agentRunnerPlanner && document.activeElement !== els.agentRunnerPlanner) {
    els.agentRunnerPlanner.value = readFirstString(runner.plannerMode, "auto") || "auto";
  }
  if (els.agentRunnerMaxSteps && document.activeElement !== els.agentRunnerMaxSteps) {
    els.agentRunnerMaxSteps.value = String(normalizeAgentRunnerMaxSteps(runner.maxSteps));
  }
  if (els.agentRunnerMeta) {
    const imageCount = Array.isArray(state.images) ? state.images.length : 0;
    const selectedCount = getSelectedIds().length;
    const evaluationStatus = readFirstString(runner?.finalEvaluation?.status).toLowerCase();
    const stopCheck = asRecord(runner?.lastStopCheck);
    const budgetLimit = resolveAgentRunnerActionBudgetLimit(runner);
    const budgetUsed = roundAgentRunnerBudgetValue(runner.budgetUsed);
    const budgetSuffix = budgetUsed > 0 ? ` Budget ${formatAgentRunnerBudgetValue(budgetUsed)} / ${formatAgentRunnerBudgetValue(budgetLimit)}.` : "";
    let text = "Give the agent a goal, then step it or let it run.";
    if (!String(runner.goal || "").trim()) {
      text = "Describe the goal first. The runner will use the visible canvas, markings, design review, and current tool runtime.";
    } else if (evaluationStatus === "pending") {
      text = `Scoring the final visible result against the goal on ${imageCount} image${imageCount === 1 ? "" : "s"}.`;
    } else if (stopCheck?.status === "ready" && stopCheck.allowStop === false) {
      text = stopCheck.summary || "Visible hard requirements are still missing.";
    } else if (runner.stopRequested) {
      text = "Stopping after the current step finishes.";
    } else if (runner.autoRunning) {
      text = `Auto running step ${Math.max(0, Number(runner.stepCount) || 0)} on ${imageCount} image${imageCount === 1 ? "" : "s"}.${budgetSuffix}`;
    } else if (runner.running) {
      text = `Executing step ${Math.max(0, Number(runner.stepCount) || 0)} with ${selectedCount} selected image${selectedCount === 1 ? "" : "s"}.${budgetSuffix}`;
    } else if (!imageCount) {
      text = "Goal ready. Import an image or let the agent use Create Tool / export paths on an empty canvas.";
    } else {
      text = `${imageCount} image${imageCount === 1 ? "" : "s"} on canvas · ${selectedCount || 1} active focus target${selectedCount === 1 ? "" : "s"}.${budgetSuffix}`;
    }
    els.agentRunnerMeta.textContent = text;
  }
  if (els.agentRunnerPlan) {
    els.agentRunnerPlan.textContent = runner.lastPlan
      ? JSON.stringify(runner.lastPlan, null, 2)
      : "No step yet.";
  }
  renderAgentRunnerFinalEvaluation();
  if (els.agentRunnerClose) {
    const closeLabel = agentRunnerActive(runner) ? "Hide" : "Close";
    setAgentRunnerButtonLabel(els.agentRunnerClose, closeLabel);
    els.agentRunnerClose.setAttribute("aria-label", `${closeLabel} agent run panel`);
    els.agentRunnerClose.setAttribute("title", `${closeLabel} agent run panel`);
  }
  if (els.agentRunnerExpand) {
    const expandLabel = expanded ? "Compact" : "Expand";
    setAgentRunnerButtonLabel(els.agentRunnerExpand, expandLabel);
    els.agentRunnerExpand.setAttribute("aria-label", `${expandLabel} agent run panel`);
    els.agentRunnerExpand.setAttribute("title", `${expandLabel} agent run panel`);
  }
  if (els.agentRunnerSubmit) {
    const canSubmit = Boolean(String(runner.goal || "").trim()) && !(runner.running || runner.autoRunning);
    els.agentRunnerSubmit.disabled = !canSubmit;
    setAgentRunnerButtonLabel(els.agentRunnerSubmit, runner.autoRunning ? "Running" : "Submit");
    const submitLabel = runner.autoRunning ? "Agent Run is running" : "Submit agent run";
    els.agentRunnerSubmit.setAttribute("aria-label", submitLabel);
    els.agentRunnerSubmit.setAttribute("title", submitLabel);
  }
  if (els.agentRunnerCopy) {
    const hasCopyableContent = Boolean(String(runner.goal || "").trim() || runner.lastPlan || (Array.isArray(runner.log) && runner.log.length));
    els.agentRunnerCopy.disabled = !hasCopyableContent;
  }
  if (els.agentRunnerClear) els.agentRunnerClear.disabled = Boolean(runner.running || runner.autoRunning);
  if (els.agentRunnerStep) els.agentRunnerStep.disabled = Boolean(runner.running || runner.autoRunning);
  if (els.agentRunnerAuto) els.agentRunnerAuto.disabled = Boolean(runner.running || runner.autoRunning);
  if (els.agentRunnerStop) els.agentRunnerStop.disabled = !(runner.running || runner.autoRunning);
  renderAgentRunnerLog();
  renderAgentRunnerActivityChrome();
  publishAgentRunnerStateEvent();
}

function hideAgentRunnerPanel({ force = false } = {}) {
  if (!els.agentRunnerPanel) return false;
  captureAgentRunnerDraftFromUi();
  els.agentRunnerPanel.classList.add("hidden");
  renderQuickActions();
  renderAgentRunnerPanel();
  return true;
}

function showAgentRunnerPanel({ focusGoal = true, expand = false } = {}) {
  if (!els.agentRunnerPanel) return false;
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  renderAgentRunnerPlannerOptions();
  runner.panelExpanded = Boolean(expand);
  els.agentRunnerPanel.style.left = "";
  els.agentRunnerPanel.style.top = "";
  els.agentRunnerPanel.style.bottom = "";
  els.agentRunnerPanel.style.transform = "";
  els.agentRunnerPanel.classList.remove("hidden");
  renderQuickActions();
  renderAgentRunnerPanel();
  setTimeout(() => {
    try {
      if (focusGoal && els.agentRunnerGoal) els.agentRunnerGoal.focus();
    } catch {
      // ignore
    }
  }, 0);
  return true;
}

function agentRunnerVisibleImages(shellSnapshot = null) {
  const visible =
    shellSnapshot?.communicationReview?.canvas?.visibleImages ||
    shellSnapshot?.communicationReview?.canvas?.visible_images ||
    [];
  return Array.isArray(visible) ? visible.filter((item) => item && typeof item === "object") : [];
}

async function buildAgentRunnerPlannerImages(shellSnapshot = null) {
  const visibleImages = agentRunnerVisibleImages(shellSnapshot);
  const runDir = readFirstString(state.runDir, shellSnapshot?.runDir, shellSnapshot?.communicationReview?.runDir);
  if (!runDir) return visibleImages;
  try {
    const visibleCanvasRef = await captureAgentRunnerVisibleCanvasRef(runDir);
    if (!visibleCanvasRef) return visibleImages;
    return [visibleCanvasRef, ...visibleImages];
  } catch (error) {
    console.warn("Agent Run planner vision capture failed; falling back to visible images.", error);
    return visibleImages;
  }
}

function resolveAgentRunnerVisibleImage(shellSnapshot = null, imageId = "") {
  const normalizedImageId = readFirstString(imageId);
  const visibleImages = agentRunnerVisibleImages(shellSnapshot);
  if (normalizedImageId) {
    const match = visibleImages.find((item) => readFirstString(item?.id) === normalizedImageId);
    if (match) return match;
  }
  return (
    visibleImages.find((item) => item?.active) ||
    visibleImages.find((item) => item?.selected) ||
    visibleImages[0] ||
    null
  );
}

function resolveAgentRunnerCanvasPoint(shellSnapshot = null, action = {}, point = null, pointPct = null, label = "point") {
  if (point && typeof point === "object") {
    return {
      imageId: readFirstString(action?.imageId) || readFirstString(resolveAgentRunnerVisibleImage(shellSnapshot, action?.imageId)?.id) || null,
      point: {
        x: Number(point.x) || 0,
        y: Number(point.y) || 0,
      },
    };
  }
  const visibleImage = resolveAgentRunnerVisibleImage(shellSnapshot, action?.imageId);
  const rect = asRecord(visibleImage?.rectCss);
  if (!visibleImage?.id || !rect) {
    throw new Error(`${label} requires an image with visible bounds`);
  }
  return {
    imageId: readFirstString(visibleImage.id) || null,
    point: {
      x: (Number(rect.left) || 0) + (Number(rect.width) || 0) * (Number(pointPct?.x) || 0),
      y: (Number(rect.top) || 0) + (Number(rect.height) || 0) * (Number(pointPct?.y) || 0),
    },
  };
}

function resolveAgentRunnerStrokePoints(shellSnapshot = null, action = {}, { minPoints = 1, label = "points" } = {}) {
  const points = Array.isArray(action?.points) ? action.points : null;
  if (points?.length) {
    if (points.length < minPoints) {
      throw new Error(`${label} requires at least ${minPoints} point${minPoints === 1 ? "" : "s"}`);
    }
    return {
      imageId: readFirstString(action?.imageId) || readFirstString(resolveAgentRunnerVisibleImage(shellSnapshot, action?.imageId)?.id) || null,
      points: points.map((point) => ({
        x: Number(point?.x) || 0,
        y: Number(point?.y) || 0,
      })),
    };
  }
  const pctPoints = Array.isArray(action?.pointsPct) ? action.pointsPct : null;
  if (!pctPoints?.length || pctPoints.length < minPoints) {
    throw new Error(`${label} requires at least ${minPoints} point${minPoints === 1 ? "" : "s"}`);
  }
  const mapped = pctPoints.map((pointPct, index) =>
    resolveAgentRunnerCanvasPoint(shellSnapshot, action, null, pointPct, `${label}[${index}]`)
  );
  return {
    imageId: readFirstString(mapped[0]?.imageId) || null,
    points: mapped.map((entry) => entry.point),
  };
}

async function waitForAgentRunnerReviewState({
  requestId = "",
  terminalStatuses = [],
  timeoutMs = AGENT_RUNNER_REVIEW_TIMEOUT_MS,
} = {}) {
  const bridge = typeof window !== "undefined" ? window.__JUGGERNAUT_REVIEW__ : null;
  const statuses = new Set((Array.isArray(terminalStatuses) ? terminalStatuses : []).map((value) => String(value || "").trim().toLowerCase()));
  const startedAt = Date.now();
  while (Date.now() - startedAt < timeoutMs) {
    const reviewState = bridge?.getState?.() || null;
    const currentRequestId = readFirstString(reviewState?.request?.requestId, reviewState?.requestId);
    const status = readFirstString(reviewState?.status).toLowerCase();
    if ((!requestId || !currentRequestId || currentRequestId === requestId) && statuses.has(status)) {
      return reviewState;
    }
    await new Promise((resolve) => setTimeout(resolve, 120));
  }
  throw new Error("Agent Run: design review timed out.");
}

function normalizeAgentRunnerImageIdList(imageIds = [], { min = 0, max = 3, label = "imageIds" } = {}) {
  const out = [];
  for (const value of Array.isArray(imageIds) ? imageIds : []) {
    const imageId = readFirstString(value);
    if (!imageId || out.includes(imageId)) continue;
    if (!isVisibleCanvasImageId(imageId)) {
      throw new Error(`${label} references an unavailable image: ${imageId}`);
    }
    out.push(imageId);
  }
  if (out.length < min) {
    throw new Error(`${label} requires at least ${min} image id${min === 1 ? "" : "s"}`);
  }
  if (out.length > max) {
    throw new Error(`${label} supports at most ${max} image id${max === 1 ? "" : "s"}`);
  }
  return out;
}

async function applyAgentRunnerImageSelection({ imageIds = [], activeImageId = null } = {}) {
  const selectedImageIds = normalizeAgentRunnerImageIdList(imageIds, {
    min: 1,
    max: 3,
    label: "imageIds",
  });
  const requestedActiveId = readFirstString(activeImageId);
  const nextActiveId = requestedActiveId || selectedImageIds[selectedImageIds.length - 1] || null;
  if (nextActiveId && !selectedImageIds.includes(nextActiveId)) {
    throw new Error(`activeImageId must be included in imageIds (${nextActiveId})`);
  }

  setSelectedIds(selectedImageIds);
  invalidateActiveTabPreview("selection_change");
  recordUserEvent("selection_change", {
    actor: "system",
    source: "agent_runner",
    reason: "agent_runner_select_images",
    canvas_mode: state.canvasMode,
    active_id: nextActiveId || state.activeId || null,
    selected_ids: selectedImageIds.slice(0, 3),
    toggle: false,
  });

  if (nextActiveId && nextActiveId !== state.activeId) {
    await setActiveImage(nextActiveId, {
      preserveSelection: true,
      source: "agent_runner",
      reason: "agent_runner_select_images",
      actor: "system",
    }).catch(() => {});
  } else {
    renderSelectionMeta();
    renderQuickActions();
    renderHudReadout();
    requestRender();
  }

  return {
    activeImageId: readFirstString(state.activeId) || null,
    selectedImageIds: getSelectedIds().slice(0, 3),
  };
}

async function ensureAgentRunnerSingleImageTarget(imageId = null) {
  const requestedImageId = readFirstString(imageId);
  const targetImageId = requestedImageId || readFirstString(state.activeId);
  if (!targetImageId || !isVisibleCanvasImageId(targetImageId)) {
    throw new Error(`Agent Run could not resolve a single-image target (${targetImageId || "none"}).`);
  }
  return applyAgentRunnerImageSelection({
    imageIds: [targetImageId],
    activeImageId: targetImageId,
  });
}

function formatAgentRunnerToolFailure(toolId = "", result = null) {
  const toolName = readFirstString(result?.label, toolId) || "This tool";
  const baseMessage = readFirstString(result?.error) || `${toolName} failed.`;
  const disabledReason = readFirstString(result?.disabledReason);
  if (!disabledReason || baseMessage.toLowerCase().includes(disabledReason.toLowerCase())) {
    return baseMessage;
  }
  return `${baseMessage} (${disabledReason})`;
}

function agentRunnerSummarySuggestsSubjectExtraction(goal = "", plannerSummary = "") {
  const text = `${String(plannerSummary || "").trim()} ${String(goal || "").trim()}`.toLowerCase();
  if (!text) return false;
  return (
    /\b(isolate|isolated|isolating|extract|extraction|cut ?out|cutout|source subject|reusable subject|reusable cutout)\b/.test(text) ||
    /\b(place|put|insert|composite|merge|bring|add)\b[\s\S]{0,32}\b(into|onto|with|next)\b/.test(text)
  );
}

async function executeAgentRunnerAction(action = null, { goal = "", goalContract = null, plannerSummary = "", shellSnapshot = null } = {}) {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const requestId = `agent-runner-${Date.now()}-${Math.max(1, Number(runner.stepCount) || 0)}`;
  const actionLabel = summarizeAgentRunnerAction(action);
  const observable = typeof window !== "undefined" ? window.__JUGGERNAUT_AGENT_OBSERVABLE__ : null;
  const reviewBridge = typeof window !== "undefined" ? window.__JUGGERNAUT_REVIEW__ : null;
  const toolRuntime = typeof window !== "undefined" ? window[TOOL_RUNTIME_BRIDGE_KEY] : null;
  const currentImageContext = () => {
    const activeImage = getActiveImage();
    return {
      activeImage,
      activeImageId: readFirstString(activeImage?.id, state.activeId),
      selectedImageIds: getSelectedIds(),
    };
  };

  if (!action || typeof action !== "object") {
    throw new Error("Agent Run action is missing.");
  }

  if (action.type === "set_active_image") {
    const imageId = readFirstString(action?.imageId);
    if (!imageId || !isVisibleCanvasImageId(imageId)) {
      throw new Error(`Agent Run could not activate image ${imageId || "(empty)"}.`);
    }
    if (state.activeId !== imageId) {
      await setActiveImage(imageId, {
        preserveSelection: true,
        source: "agent_runner",
        reason: "agent_runner_set_active_image",
        actor: "system",
      }).catch(() => {});
    }
    return {
      ok: true,
      message: `${actionLabel} complete.`,
      detail: {
        activeImageId: readFirstString(state.activeId) || null,
        selectedImageIds: getSelectedIds().slice(0, 3),
      },
    };
  }

  if (action.type === "set_selected_images") {
    const selection = await applyAgentRunnerImageSelection({
      imageIds: action?.imageIds,
      activeImageId: action?.activeImageId,
    });
    return {
      ok: true,
      message: `${actionLabel} complete.`,
      detail: selection,
    };
  }

  if (action.type === "marker_stroke") {
    if (!observable?.markerStroke) throw new Error("Observable marker driver is unavailable.");
    const resolved = resolveAgentRunnerStrokePoints(shellSnapshot, action, {
      minPoints: 2,
      label: "marker points",
    });
    const result = await observable.markerStroke({
      request_id: requestId,
      source: "agent_runner",
      image_id: resolved.imageId,
      points: resolved.points,
      step_delay_ms: Number(action?.stepDelayMs) || 0,
      meta: {
        goal,
        planner_summary: plannerSummary || null,
      },
    });
    if (!result?.ok) throw new Error(readFirstString(result?.error) || "Marker stroke failed.");
    return {
      ok: true,
      message: `${actionLabel} complete.`,
      detail: result,
    };
  }

  if (action.type === "magic_select_click") {
    if (!observable?.magicSelectClick) throw new Error("Observable Magic Select driver is unavailable.");
    const resolved = resolveAgentRunnerCanvasPoint(shellSnapshot, action, action?.point, action?.pointPct, "magic_select_click.point");
    const result = await observable.magicSelectClick({
      request_id: requestId,
      source: "agent_runner",
      image_id: resolved.imageId,
      point: resolved.point,
      meta: {
        goal,
        planner_summary: plannerSummary || null,
      },
    });
    if (!result?.ok) throw new Error(readFirstString(result?.error) || "Magic Select failed.");
    return {
      ok: true,
      message: `${actionLabel} complete.`,
      detail: result,
    };
  }

  if (action.type === "eraser_stroke") {
    if (!observable?.eraserStroke) throw new Error("Observable eraser driver is unavailable.");
    const resolved = resolveAgentRunnerStrokePoints(shellSnapshot, action, {
      minPoints: 1,
      label: "eraser points",
    });
    const result = await observable.eraserStroke({
      request_id: requestId,
      source: "agent_runner",
      image_id: resolved.imageId,
      points: resolved.points,
      step_delay_ms: Number(action?.stepDelayMs) || 0,
      meta: {
        goal,
        planner_summary: plannerSummary || null,
      },
    });
    if (!result?.ok) throw new Error(readFirstString(result?.error) || "Eraser stroke failed.");
    return {
      ok: true,
      message: `${actionLabel} complete.`,
      detail: result,
    };
  }

  if (action.type === "request_design_review") {
    if (!reviewBridge?.startReviewFromShell) throw new Error("Design review bridge is unavailable.");
    const reviewPayload = buildCommunicationReviewPayload({ source: "agent_runner" });
    const existingReviewState = reviewBridge.getState?.() || null;
    const reuseState = resolveAgentRunnerReviewReuseState({
      runner,
      goal,
      goalContract,
      reviewState: existingReviewState,
      reviewPayload,
    });
    if (reuseState.goalMatchesCurrentGoal && reuseState.contextMatchesVisiblePrep && reuseState.requestId) {
      const currentStatus = reuseState.reviewStatus;
      if (currentStatus === "ready") {
        rememberAgentRunnerReviewReuseState(runner, {
          requestId: reuseState.requestId,
          contextSignature: reuseState.contextSignature,
          goal,
        });
        return {
          ok: true,
          message: `Reused ready design review with ${Array.isArray(existingReviewState?.proposals) ? existingReviewState.proposals.length : 0} proposal${Array.isArray(existingReviewState?.proposals) && existingReviewState.proposals.length === 1 ? "" : "s"}.`,
          detail: {
            ...cloneToolRuntimeValue(existingReviewState),
            reused: true,
            plausibleReadyProposal: reuseState.plausibleReadyProposal,
            reason: reuseState.reason,
          },
          budgetCostOverride: 0,
        };
      }
      if (["planning", "previewing", "preparing"].includes(currentStatus)) {
        const pendingReviewState = await waitForAgentRunnerReviewState({
          requestId: reuseState.requestId,
          terminalStatuses: ["ready", "failed"],
          timeoutMs: AGENT_RUNNER_REVIEW_TIMEOUT_MS,
        });
        if (readFirstString(pendingReviewState?.status).toLowerCase() === "failed") {
          throw new Error(readFirstString(pendingReviewState?.errors?.[0], pendingReviewState?.slots?.[0]?.error, "Design review failed."));
        }
        rememberAgentRunnerReviewReuseState(runner, {
          requestId: reuseState.requestId,
          contextSignature: reuseState.contextSignature,
          goal,
        });
        return {
          ok: true,
          message: `Design review ready with ${Array.isArray(pendingReviewState?.proposals) ? pendingReviewState.proposals.length : 0} proposal${Array.isArray(pendingReviewState?.proposals) && pendingReviewState.proposals.length === 1 ? "" : "s"}.`,
          detail: {
            ...cloneToolRuntimeValue(pendingReviewState),
            reused: true,
            waitedForExistingRequest: true,
            reason: reuseState.reason,
          },
          budgetCostOverride: 0,
        };
      }
    }
    const start = await reviewBridge.startReviewFromShell({ source: "agent_runner" });
    if (start?.ok === false) {
      if (start?.reason === "missing_anchor") {
        throw new Error("Design review needs a visible mark or Magic Select region first.");
      }
      throw new Error("Design review did not start.");
    }
    const reviewState = await waitForAgentRunnerReviewState({
      requestId: readFirstString(start?.requestId),
      terminalStatuses: ["ready", "failed"],
      timeoutMs: AGENT_RUNNER_REVIEW_TIMEOUT_MS,
    });
    if (readFirstString(reviewState?.status).toLowerCase() === "failed") {
      throw new Error(readFirstString(reviewState?.errors?.[0], reviewState?.slots?.[0]?.error, "Design review failed."));
    }
    rememberAgentRunnerReviewReuseState(runner, {
      requestId: readFirstString(reviewState?.request?.requestId, reviewState?.requestId, start?.requestId),
      contextSignature: reuseState.contextSignature,
      goal,
    });
    return {
      ok: true,
      message: `Design review ready with ${Array.isArray(reviewState?.proposals) ? reviewState.proposals.length : 0} proposal${Array.isArray(reviewState?.proposals) && reviewState.proposals.length === 1 ? "" : "s"}.`,
      detail: {
        ...cloneToolRuntimeValue(reviewState),
        deduped: Boolean(start?.deduped),
      },
      budgetCostOverride: start?.deduped ? 0 : null,
    };
  }

  if (action.type === "accept_review_proposal") {
    if (!reviewBridge?.acceptProposal) throw new Error("Design review accept bridge is unavailable.");
    const accepted = await reviewBridge.acceptProposal({
      proposalId: action?.proposalId,
      proposalRank: action?.proposalRank,
    });
    if (!accepted?.ok) {
      throw new Error("Review proposal could not be resolved.");
    }
    const reviewState = await waitForAgentRunnerReviewState({
      requestId: readFirstString(accepted?.requestId),
      terminalStatuses: ["apply_succeeded", "apply_failed"],
      timeoutMs: AGENT_RUNNER_APPLY_TIMEOUT_MS,
    });
    if (readFirstString(reviewState?.status).toLowerCase() !== "apply_succeeded") {
      throw new Error(readFirstString(reviewState?.lastApplyEvent?.error, reviewState?.errors?.[0], "Review apply failed."));
    }
    return {
      ok: true,
      message: `${actionLabel} complete.`,
      detail: reviewState?.lastApplyEvent || reviewState,
    };
  }

  if (action.type === "invoke_seeded_tool") {
    if (typeof window === "undefined" || typeof window.juggernautApplyTool !== "function") {
      throw new Error("Tool apply bridge is unavailable.");
    }
    if (readFirstString(action?.toolId) === "remove" && agentRunnerSummarySuggestsSubjectExtraction(goal, plannerSummary)) {
      throw new Error("Remove deletes the selected content from the active image. Use cut_out to extract a subject for compositing.");
    }
    await ensureAgentRunnerSingleImageTarget(action?.imageId);
    const { activeImage, activeImageId, selectedImageIds } = currentImageContext();
    const invocation = buildSingleImageRailInvocation(action.toolId, {
      activeImageId: activeImageId || null,
      selectedImageIds: [activeImageId].filter(Boolean).length ? [activeImageId] : selectedImageIds,
      subjectSelectionAvailable: singleImageRailRegionSelectionActive(activeImageId || ""),
      source: "agent_runner",
      trigger: "agent_run",
      requestId,
      mode: state.canvasMode,
      image: activeImage,
      capabilityAvailability: singleImageRailCapabilityAvailability(),
      capabilityExecutorAvailable: true,
    });
    const result = await window.juggernautApplyTool(invocation);
    if (!result?.ok) throw new Error(formatAgentRunnerToolFailure(action.toolId, result));
    return {
      ok: true,
      message: `${action.toolId} applied.`,
      detail: result,
    };
  }

  if (action.type === "invoke_direct_affordance") {
    if (typeof window === "undefined" || typeof window.juggernautApplyTool !== "function") {
      throw new Error("Tool apply bridge is unavailable.");
    }
    await ensureAgentRunnerSingleImageTarget(action?.imageId);
    const { activeImage, activeImageId, selectedImageIds } = currentImageContext();
    const invocation = buildSingleImageDirectAffordanceInvocation(action.toolId, {
      activeImageId: activeImageId || null,
      selectedImageIds: [activeImageId].filter(Boolean).length ? [activeImageId] : selectedImageIds,
      source: "agent_runner",
      trigger: "agent_run",
      requestId,
      params: asRecord(action.params) || {},
      mode: state.canvasMode,
      image: activeImage,
      capabilityExecutorAvailable: true,
      localExecutorAvailable: true,
    });
    const result = await window.juggernautApplyTool(invocation);
    if (!result?.ok) throw new Error(formatAgentRunnerToolFailure(action.toolId, result));
    return {
      ok: true,
      message: `${action.toolId} applied.`,
      detail: result,
    };
  }

  if (action.type === "preview_create_tool") {
    if (!toolRuntime?.previewCreateTool) throw new Error("Create Tool runtime bridge is unavailable.");
    const name = readFirstString(action?.name);
    const description = readFirstString(action?.description);
    if (!description) throw new Error("Create Tool preview requires a description.");
    state.customToolDraft = { name, description };
    if (els.createToolName) els.createToolName.value = name;
    if (els.createToolText) els.createToolText.value = description;
    renderCreateToolPreview();
    const preview = toolRuntime.previewCreateTool({ name, description });
    return {
      ok: true,
      message: `Create Tool preview ready for ${preview?.generatedManifest?.label || name || "new tool"}.`,
      detail: preview?.generatedManifest || preview,
    };
  }

  if (action.type === "create_tool") {
    if (!toolRuntime?.createTool) throw new Error("Create Tool runtime bridge is unavailable.");
    const name = readFirstString(action?.name);
    const description = readFirstString(action?.description);
    if (!description) throw new Error("Create Tool requires a description.");
    state.customToolDraft = { name, description };
    if (els.createToolName) els.createToolName.value = name;
    if (els.createToolText) els.createToolText.value = description;
    const manifest = toolRuntime.createTool({ name, description });
    syncSessionToolsFromRegistry();
    renderCreateToolPreview();
    renderQuickActions();
    return {
      ok: true,
      message: `Created tool ${manifest?.label || manifest?.toolId || name || "custom tool"}.`,
      detail: manifest,
    };
  }

  if (action.type === "invoke_custom_tool") {
    if (!toolRuntime?.invokeTool) throw new Error("Tool runtime bridge is unavailable.");
    if (typeof window === "undefined" || typeof window.juggernautApplyTool !== "function") {
      throw new Error("Tool apply bridge is unavailable.");
    }
    await ensureAgentRunnerSingleImageTarget(action?.imageId);
    const { activeImageId, selectedImageIds } = currentImageContext();
    const invocation = toolRuntime.invokeTool({
      toolId: action.toolId,
      activeImageId: activeImageId || null,
      selectedImageIds: [activeImageId].filter(Boolean).length ? [activeImageId] : selectedImageIds,
      source: "agent_runner",
      trigger: "agent_run",
    });
    if (!invocation) throw new Error(`Custom tool ${action.toolId} could not be prepared.`);
    const result = await window.juggernautApplyTool(invocation);
    if (!result?.ok) throw new Error(formatAgentRunnerToolFailure(action.toolId, result));
    return {
      ok: true,
      message: `Custom tool ${action.toolId} applied.`,
      detail: result,
    };
  }

  if (isAgentRunnerExportAction(action)) {
    const format = agentRunnerExportFormat(action);
    const ok = await requestJuggernautExport({ format, source: "agent_runner" });
    if (!ok) throw new Error(`${exportFormatLabel(format)} export failed.`);
    return {
      ok: true,
      message: `${exportFormatLabel(format)} export requested.`,
      detail: {
        format,
      },
    };
  }

  if (action.type === "stop") {
    return {
      ok: true,
      terminal: true,
      message: readFirstString(action?.message) || "Agent Run stopped.",
      detail: {
        type: "stop",
      },
    };
  }

  throw new Error(`Unsupported Agent Run action: ${readFirstString(action?.type) || "(empty)"}`);
}

async function readAgentRunnerEvaluationKeyStatus() {
  if (state.keyStatus && typeof state.keyStatus === "object") return state.keyStatus;
  await refreshKeyStatus({ reason: "agent_runner_evaluation" }).catch(() => {});
  return state.keyStatus || {};
}

function createAgentRunnerEvaluationProviderRouter() {
  return createDesignReviewProviderRouter({
    requestProvider: invokeDesignReviewProviderRequest,
    keyStatus: state.keyStatus || {},
    getKeyStatus: () => readAgentRunnerEvaluationKeyStatus(),
  });
}

async function ensureAgentRunnerGoalContract({ runner = null, shellSnapshot = null } = {}) {
  const record = asRecord(runner) || state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const goal = String(record.goal || "").trim();
  if (!goal) {
    record.goalContract = null;
    record.goalContractRawText = "";
    record.goalContractSourceGoal = "";
    record.goalContractStatus = "idle";
    record.goalContractPromise = null;
    return null;
  }
  if (record.goalContract && readFirstString(record.goalContractSourceGoal) === goal && readFirstString(record.goalContractStatus) === "ready") {
    return record.goalContract;
  }
  if (readFirstString(record.goalContractSourceGoal) === goal && readFirstString(record.goalContractStatus) === "failed") {
    return null;
  }
  if (record.goalContractPromise && readFirstString(record.goalContractSourceGoal) === goal && readFirstString(record.goalContractStatus) === "pending") {
    return null;
  }
  record.goalContract = null;
  record.goalContractRawText = "";
  record.goalContractSourceGoal = goal;
  record.goalContractStatus = "pending";
  record.lastStopCheck = null;
  appendAgentRunnerLog("info", "Compiling goal contract from the goal text.");
  renderAgentRunnerPanel();
  const pendingGoal = goal;
  const compilePromise = agentRunnerGoalContractCompiler
    .compile({
      goal,
      shellSnapshot,
      requestId: `agent-runner-goal-contract-${Date.now()}`,
    })
    .then((result) => {
      if (record.goalContractPromise !== compilePromise || String(record.goal || "").trim() !== pendingGoal) {
        return null;
      }
      record.goalContract = cloneToolRuntimeValue(result.goalContract);
      record.goalContractRawText = String(result.rawText || "");
      record.goalContractSourceGoal = pendingGoal;
      record.goalContractStatus = "ready";
      appendAgentRunnerLog("success", `Goal contract ready: ${summarizeAgentRunnerGoalContract(record.goalContract)}`, {
        goalContract: record.goalContract,
      });
      renderAgentRunnerPanel();
      return record.goalContract;
    })
    .catch((error) => {
      if (record.goalContractPromise !== compilePromise || String(record.goal || "").trim() !== pendingGoal) {
        return null;
      }
      const message = normalizeErrorMessage(error, "Goal contract compilation failed.");
      record.goalContract = null;
      record.goalContractRawText = "";
      record.goalContractSourceGoal = pendingGoal;
      record.goalContractStatus = "failed";
      appendAgentRunnerLog("error", `Goal contract unavailable: ${message}`, error?.debugInfo || error?.stack || null);
      renderAgentRunnerPanel();
      return null;
    })
    .finally(() => {
      if (record.goalContractPromise === compilePromise) {
        record.goalContractPromise = null;
      }
    });
  record.goalContractPromise = compilePromise;
  return null;
}

async function maybeRunAgentRunnerStopCheck({
  runner = null,
  shellSnapshot = null,
  plannedAction = null,
  plannerResult = null,
} = {}) {
  const record = asRecord(runner) || state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  const actionType = readFirstString(plannedAction?.type).toLowerCase();
  if (!(actionType === "stop" || isAgentRunnerExportAction(plannedAction))) {
    return { allowStop: true, skipped: true, reason: "non_terminal_action" };
  }
  const goal = String(record.goal || "").trim();
  if (!goal) {
    return { allowStop: true, skipped: true, reason: "missing_goal" };
  }
  const goalContract = await ensureAgentRunnerGoalContract({
    runner: record,
    shellSnapshot,
  });
  if (!goalContract) {
    const goalContractStatus = readFirstString(record.goalContractStatus).toLowerCase();
    return {
      allowStop: true,
      skipped: true,
      reason: goalContractStatus === "pending" ? "goal_contract_pending" : "goal_contract_unavailable",
    };
  }
  const runDir = readFirstString(state.runDir, shellSnapshot?.runDir, shellSnapshot?.communicationReview?.runDir);
  if (!runDir) {
    return { allowStop: true, skipped: true, reason: "missing_run_dir" };
  }
  const visibleCanvasRef = await captureAgentRunnerVisibleCanvasRef(runDir);
  if (!visibleCanvasRef) {
    return { allowStop: true, skipped: true, reason: "missing_visible_canvas" };
  }
  try {
    const result = await agentRunnerGoalContractCompiler.checkStop({
      goal,
      goalContract,
      lastPlan: plannerResult?.plan || null,
      visibleImages: agentRunnerVisibleImages(shellSnapshot),
      recentLog: record.log,
      image: visibleCanvasRef,
      requestId: `agent-runner-goal-check-${Date.now()}`,
    });
    record.lastStopCheck = {
      status: "ready",
      actionType,
      visibleCanvasRef,
      ...cloneToolRuntimeValue(result.verdict),
      completedAt: new Date().toISOString(),
    };
    if (!result.verdict.allowStop) {
      const label = isAgentRunnerExportAction(plannedAction) ? "Export" : "Stop";
      appendAgentRunnerLog("info", `${label} blocked: ${result.verdict.summary}`, result.verdict, {
        actionType,
        ok: false,
      });
      renderAgentRunnerPanel();
    }
    return result.verdict;
  } catch (error) {
    const message = normalizeErrorMessage(error, "Goal contract stop check failed.");
    record.lastStopCheck = {
      status: "failed",
      actionType,
      error: message,
      completedAt: new Date().toISOString(),
    };
    appendAgentRunnerLog("error", `Goal check unavailable: ${message}`, error?.debugInfo || error?.stack || null, {
      actionType,
      ok: false,
    });
    renderAgentRunnerPanel();
    return {
      allowStop: true,
      skipped: true,
      reason: "goal_check_failed",
      error: message,
    };
  }
}

async function captureAgentRunnerVisibleCanvasRef(runDir = "") {
  const normalizedRunDir = String(runDir || "").trim();
  if (!normalizedRunDir) return null;
  const canvases = [
    document.getElementById("work-canvas"),
    document.getElementById("effects-canvas"),
    document.getElementById("overlay-canvas"),
  ].filter(Boolean);
  const source = canvases.find((canvas) => Number(canvas?.width) > 0 && Number(canvas?.height) > 0);
  if (!source) return null;
  const composite = document.createElement("canvas");
  composite.width = source.width;
  composite.height = source.height;
  const ctx = composite.getContext("2d");
  if (!ctx) return null;
  for (const canvas of canvases) {
    if (!canvas || !canvas.width || !canvas.height) continue;
    ctx.drawImage(canvas, 0, 0, composite.width, composite.height);
  }
  const blob = await new Promise((resolve) => composite.toBlob(resolve, "image/png"));
  if (!blob) return null;
  const buffer = await blob.arrayBuffer();
  const outputPath = await join(normalizedRunDir, `agent-runner-visible-${Date.now()}.png`);
  await writeBinaryFile(outputPath, new Uint8Array(buffer));
  return outputPath;
}

function shouldRunAgentRunnerFinalEvaluation({ runner = null, shellSnapshot = null } = {}) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  if (!String(record.goal || "").trim()) return false;
  if (!(Math.max(0, Number(record.stepCount) || 0) > 0)) return false;
  if (readFirstString(record?.finalEvaluation?.status).toLowerCase() === "pending") return false;
  return agentRunnerVisibleImages(shellSnapshot || buildJuggernautShellContext()).length > 0;
}

function resolveAgentRunnerFinalEvaluationFinishReason({ outcome = null, stopped = false, maxStepsReached = false } = {}) {
  if (stopped) return "stopped_by_user";
  if (maxStepsReached) return "max_steps_reached";
  if (!outcome?.ok) return "failed";
  if (outcome?.terminal) return "terminal";
  const status = readFirstString(outcome?.status).toLowerCase();
  if (status === "complete") return "complete";
  if (status === "blocked") return "blocked";
  return "finished";
}

async function maybeRunAgentRunnerFinalEvaluation({
  runner = null,
  outcome = null,
  stopped = false,
  maxStepsReached = false,
} = {}) {
  const record = asRecord(runner) || state.agentRunner || createFreshAgentRunnerState();
  const shellSnapshot = buildJuggernautShellContext();
  if (!shouldRunAgentRunnerFinalEvaluation({ runner: record, shellSnapshot })) return null;
  const goal = String(record.goal || "").trim();
  const runDir = readFirstString(state.runDir, shellSnapshot?.runDir, shellSnapshot?.communicationReview?.runDir);
  if (!runDir) return null;
  const finishReason = resolveAgentRunnerFinalEvaluationFinishReason({ outcome, stopped, maxStepsReached });
  record.finalEvaluation = {
    status: "pending",
    goal,
    finishReason,
    startedAt: new Date().toISOString(),
  };
  appendAgentRunnerLog("info", "Scoring the final result against the goal.");
  renderAgentRunnerPanel();
  try {
    const visibleCanvasRef = await captureAgentRunnerVisibleCanvasRef(runDir);
    if (!visibleCanvasRef) {
      throw new Error("Could not capture the visible canvas for scoring.");
    }
    const providerRouter = createAgentRunnerEvaluationProviderRouter();
    const prompt = buildAgentRunnerEvaluationPrompt({
      goal,
      goalContract: record.goalContract,
      finishReason,
      stepCount: record.stepCount,
      lastPlan: record.lastPlan,
      visibleImages: agentRunnerVisibleImages(shellSnapshot),
      recentLog: record.log,
    });
    const requestId = `agent-runner-eval-${Date.now()}`;
    const result = await providerRouter.runPlanner({
      request: { requestId },
      prompt,
      images: [visibleCanvasRef],
    });
    const parsed = parseAgentRunnerEvaluationResponse(
      result?.text || result?.outputText || result?.rawText || "",
      { goal }
    );
    record.finalEvaluation = {
      ...parsed,
      status: "ready",
      finishReason,
      visibleCanvasRef,
      provider: readFirstString(result?.provider, result?.debugInfo?.provider) || null,
      requestedModel:
        readFirstString(result?.requestedModel, result?.debugInfo?.requestedModel, result?.debugInfo?.providerRequest?.model) ||
        null,
      normalizedModel:
        readFirstString(result?.normalizedModel, result?.debugInfo?.normalizedModel, result?.debugInfo?.route?.normalizedModel) ||
        null,
      debugInfo: cloneToolRuntimeValue(result?.debugInfo || null),
      completedAt: new Date().toISOString(),
    };
    appendAgentRunnerLog("success", `Final score: ${parsed.score} / 100.`, {
      score: parsed.score,
      goalAchieved: Boolean(parsed.goalAchieved),
      verdict: parsed.verdict,
      strengths: parsed.strengths,
      misses: parsed.misses,
      uxSuggestions: parsed.uxSuggestions,
      agentSuggestions: parsed.agentSuggestions,
      suggestions: parsed.suggestions,
    });
    renderAgentRunnerPanel();
    return cloneToolRuntimeValue(record.finalEvaluation);
  } catch (error) {
    const message = normalizeErrorMessage(error, "Final scoring failed.");
    record.finalEvaluation = {
      status: "failed",
      goal,
      finishReason,
      error: message,
      debugInfo: cloneToolRuntimeValue(error?.debugInfo || null),
      completedAt: new Date().toISOString(),
    };
    appendAgentRunnerLog("error", `Final score unavailable: ${message}`, error?.debugInfo || error?.stack || null);
    renderAgentRunnerPanel();
    return cloneToolRuntimeValue(record.finalEvaluation);
  }
}

async function runAgentRunnerStepInternal({ source = "agent_runner_panel" } = {}) {
  const runner = captureAgentRunnerDraftFromUi();
  const goal = String(runner.goal || "").trim();
  if (!goal) {
    showToast("Agent Run: enter a goal first.", "tip", 2200);
    if (els.agentRunnerGoal) {
      try {
        els.agentRunnerGoal.focus();
      } catch {
        // ignore
      }
    }
    return {
      ok: false,
      blocked: true,
      message: "Missing goal",
    };
  }

  const shellSnapshot = buildJuggernautShellContext();
  const reviewState =
    (typeof window !== "undefined" ? window.__JUGGERNAUT_REVIEW__?.getState?.() : null) ||
    null;
  const goalContract = await ensureAgentRunnerGoalContract({
    runner,
    shellSnapshot,
  });
  const reviewPayload = buildCommunicationReviewPayload({ source: "agent_runner" });
  const reviewReuse = resolveAgentRunnerReviewReuseState({
    runner,
    goal,
    goalContract,
    reviewState,
    reviewPayload,
  });
  const runState = buildAgentRunnerRunStateSummary(runner);
  const contextSummary = buildAgentRunnerContextSummary({
    goal,
    goalContract,
    shellSnapshot,
    reviewState,
    runState,
    reviewReuse,
    sessionTools: state.sessionTools,
    recentLog: runner.log,
  });
  runner.lastContextSummary = cloneToolRuntimeValue(contextSummary);
  const plannerImages = await buildAgentRunnerPlannerImages(shellSnapshot);

  const plannerResult = await agentRunnerPlanner.plan({
    goal,
    goalContract,
    shellSnapshot,
    reviewState,
    runState,
    reviewReuse,
    sessionTools: state.sessionTools,
    recentLog: runner.log,
    plannerMode: runner.plannerMode,
    images: plannerImages,
    requestId: `agent-runner-plan-${Date.now()}`,
  });
  runner.stepCount = Math.max(0, Number(runner.stepCount) || 0) + 1;
  runner.lastPlan = cloneToolRuntimeValue(plannerResult?.plan || null);
  runner.lastPlanRawText = readFirstString(plannerResult?.rawText);
  renderAgentRunnerPanel();

  const plannedAction = plannerResult?.plan?.action || null;
  appendAgentRunnerLog(
    plannedAction?.type === "stop" ? "info" : "action",
    plannerResult?.plan?.summary || summarizeAgentRunnerAction(plannedAction),
    plannerResult?.plan,
    {
      actionType: plannedAction?.type || null,
    }
  );

  if (isAgentRunnerTerminalAction(plannedAction)) {
    const stopCheck = await maybeRunAgentRunnerStopCheck({
      runner,
      shellSnapshot,
      plannedAction,
      plannerResult,
    });
    if (stopCheck && stopCheck.allowStop === false) {
      const blockedMessage = readFirstString(stopCheck.summary) || "Visible hard requirements are still missing.";
      setStatus(`Agent Run: ${blockedMessage}`);
      return {
        ok: true,
        terminal: false,
        status: "continue",
        action: plannedAction,
        message: blockedMessage,
        stopCheck,
      };
    }
  }

  if (!plannedAction || plannedAction.type === "stop") {
    const stopMessage =
      readFirstString(plannedAction?.message, plannerResult?.plan?.summary) || "Agent Run stopped.";
    setStatus(`Agent Run: ${stopMessage}`);
    return {
      ok: true,
      terminal: true,
      status: plannerResult?.plan?.status || "complete",
      action: plannedAction,
      message: stopMessage,
    };
  }

  const actionBudgetCost = resolveAgentRunnerActionBudgetCost(plannedAction);
  const budgetLimit = resolveAgentRunnerActionBudgetLimit(runner);
  const budgetUsed = roundAgentRunnerBudgetValue(runner.budgetUsed);
  if (actionBudgetCost > 0 && budgetUsed + actionBudgetCost > budgetLimit + 1e-9) {
    const blockedMessage = `Weighted action budget exhausted at ${formatAgentRunnerBudgetValue(budgetUsed)} / ${formatAgentRunnerBudgetValue(budgetLimit)}. Stop, export, or change the canvas before continuing.`;
    appendAgentRunnerLog("info", blockedMessage, {
      actionType: plannedAction?.type || null,
      budgetUsed,
      budgetLimit,
      attemptedCost: actionBudgetCost,
    }, {
      actionType: plannedAction?.type || null,
      ok: false,
    });
    setStatus(`Agent Run: ${blockedMessage}`);
    return {
      ok: true,
      terminal: false,
      status: "budget_exhausted",
      action: plannedAction,
      message: blockedMessage,
      budgetUsed,
      budgetLimit,
      attemptedCost: actionBudgetCost,
    };
  }

  const actionResult = await executeAgentRunnerAction(plannedAction, {
    goal,
    goalContract,
    plannerSummary: plannerResult?.plan?.summary || "",
    shellSnapshot,
  });
  const appliedBudgetCost =
    actionResult?.budgetCostOverride == null
      ? actionBudgetCost
      : Math.max(0, Number(actionResult.budgetCostOverride) || 0);
  if (actionResult?.ok !== false && appliedBudgetCost > 0) {
    runner.budgetUsed = roundAgentRunnerBudgetValue((Number(runner.budgetUsed) || 0) + appliedBudgetCost);
  }
  if (actionResult?.ok !== false && agentRunnerActionInvalidatesReviewReuse(plannedAction)) {
    clearAgentRunnerReviewReuseState(runner);
  }
  appendAgentRunnerLog(actionResult?.ok ? "success" : "error", actionResult?.message || summarizeAgentRunnerAction(plannedAction), actionResult?.detail, {
    actionType: plannedAction?.type || null,
    ok: actionResult?.ok !== false,
  });
  setStatus(`Agent Run: ${actionResult?.message || summarizeAgentRunnerAction(plannedAction)}`);
  return {
    ok: actionResult?.ok !== false,
    terminal: Boolean(actionResult?.terminal),
    status: plannerResult?.plan?.status || "continue",
    action: plannedAction,
    result: actionResult,
  };
}

async function runAgentRunnerStep({ source = "agent_runner_panel" } = {}) {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  if (runner.running || runner.autoRunning) {
    showToast("Agent Run is already executing.", "tip", 1800);
    return null;
  }
  const draft = captureAgentRunnerDraftFromUi();
  if (!String(draft.goal || "").trim()) {
    showToast("Agent Run: enter a goal first.", "tip", 2200);
    if (els.agentRunnerGoal) {
      try {
        els.agentRunnerGoal.focus();
      } catch {
        // ignore
      }
    }
    renderAgentRunnerPanel();
    return {
      ok: false,
      blocked: true,
      message: "Missing goal",
    };
  }
  runner.running = true;
  runner.stopRequested = false;
  runner.finalEvaluation = null;
  collapseAgentRunnerPanelToBanner();
  renderAgentRunnerPanel();
  let outcome = null;
  try {
    outcome = await runAgentRunnerStepInternal({ source });
  } catch (error) {
    const message = normalizeErrorMessage(error, "Agent Run step failed.");
    appendAgentRunnerLog("error", message, error?.debugInfo || error?.stack || null);
    setStatus(`Agent Run: ${message}`, true);
    showToast(message, "error", 3200);
    outcome = {
      ok: false,
      status: "blocked",
      message,
    };
  } finally {
    runner.running = false;
    renderAgentRunnerPanel();
  }
  if (
    outcome?.terminal ||
    outcome?.status === "complete" ||
    outcome?.status === "blocked" ||
    outcome?.status === "budget_exhausted" ||
    outcome?.ok === false
  ) {
    await maybeRunAgentRunnerFinalEvaluation({ runner, outcome });
  }
  return outcome;
}

function requestAgentRunnerStop() {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  runner.stopRequested = true;
  renderAgentRunnerPanel();
  showToast("Agent Run: stopping after the current step.", "tip", 1800);
  return buildAgentRunnerBridgeSnapshot();
}

async function runAgentRunnerAuto({ source = "agent_runner_panel" } = {}) {
  const runner = state.agentRunner || (state.agentRunner = createFreshAgentRunnerState());
  if (runner.running || runner.autoRunning) {
    showToast("Agent Run is already executing.", "tip", 1800);
    return null;
  }
  const draft = captureAgentRunnerDraftFromUi();
  if (!String(draft.goal || "").trim()) {
    showToast("Agent Run: enter a goal first.", "tip", 2200);
    if (els.agentRunnerGoal) {
      try {
        els.agentRunnerGoal.focus();
      } catch {
        // ignore
      }
    }
    renderAgentRunnerPanel();
    return {
      ok: false,
      blocked: true,
      message: "Missing goal",
    };
  }
  runner.autoRunning = true;
  runner.stopRequested = false;
  runner.finalEvaluation = null;
  collapseAgentRunnerPanelToBanner();
  renderAgentRunnerPanel();
  appendAgentRunnerLog("info", `Auto run started for up to ${normalizeAgentRunnerMaxSteps(runner.maxSteps)} step(s).`);
  let finalOutcome = null;
  let stoppedByUser = false;
  let maxStepsReached = false;
  const budgetLimit = resolveAgentRunnerActionBudgetLimit(runner);
  const maxAutoIterations = Math.max(1, Math.ceil(budgetLimit / AGENT_RUNNER_MIN_ACTION_BUDGET_COST) + 1);
  try {
    for (let index = 0; index < maxAutoIterations; index += 1) {
      if (runner.stopRequested) {
        appendAgentRunnerLog("info", "Auto run stopped by user.");
        stoppedByUser = true;
        break;
      }
      runner.running = true;
      renderAgentRunnerPanel();
      let outcome = null;
      try {
        outcome = await runAgentRunnerStepInternal({
          source: `${source}_auto`,
        });
        finalOutcome = outcome;
      } catch (error) {
        const message = normalizeErrorMessage(error, "Agent Run auto step failed.");
        appendAgentRunnerLog("error", message, error?.debugInfo || error?.stack || null);
        setStatus(`Agent Run: ${message}`, true);
        showToast(message, "error", 3200);
        finalOutcome = {
          ok: false,
          status: "blocked",
          message,
        };
        break;
      } finally {
        runner.running = false;
        renderAgentRunnerPanel();
      }
      if (
        !outcome?.ok ||
        outcome?.terminal ||
        outcome?.status === "blocked" ||
        outcome?.status === "complete" ||
        outcome?.status === "budget_exhausted"
      ) {
        break;
      }
      await new Promise((resolve) => setTimeout(resolve, 180));
    }
    if (!stoppedByUser && !finalOutcome && runner.stopRequested) stoppedByUser = true;
    if (
      !stoppedByUser &&
      !maxStepsReached &&
      (
        finalOutcome?.status === "budget_exhausted" ||
        agentRunnerBudgetRemaining(runner) <= 1e-9
      ) &&
      !(finalOutcome?.terminal || finalOutcome?.status === "complete" || finalOutcome?.status === "blocked" || finalOutcome?.ok === false)
    ) {
      maxStepsReached = true;
      appendAgentRunnerLog(
        "info",
        `Auto run hit the weighted action budget (${formatAgentRunnerBudgetValue(roundAgentRunnerBudgetValue(runner.budgetUsed))} / ${formatAgentRunnerBudgetValue(budgetLimit)}).`
      );
    }
    if (!runner.stopRequested) {
      appendAgentRunnerLog("info", "Auto run finished.");
    }
  } finally {
    runner.autoRunning = false;
    runner.running = false;
    runner.stopRequested = false;
    renderAgentRunnerPanel();
  }
  await maybeRunAgentRunnerFinalEvaluation({
    runner,
    outcome: finalOutcome,
    stopped: stoppedByUser,
    maxStepsReached,
  });
  return buildAgentRunnerBridgeSnapshot();
}

function publishAgentRunnerBridge() {
  if (typeof window === "undefined") return null;
  window[AGENT_RUNNER_BRIDGE_KEY] = Object.freeze({
    plannerOptions: agentRunnerPlanner.plannerOptions.map((option) => ({ ...option })),
    stateEvent: AGENT_RUNNER_STATE_EVENT,
    logEvent: AGENT_RUNNER_LOG_EVENT,
    getState: () => buildAgentRunnerBridgeSnapshot(),
    open() {
      showAgentRunnerPanel({ focusGoal: !agentRunnerActive(), expand: false });
      return buildAgentRunnerBridgeSnapshot();
    },
    close() {
      hideAgentRunnerPanel();
      return buildAgentRunnerBridgeSnapshot();
    },
    setGoal(goal = "") {
      state.agentRunner.goal = String(goal || "").trim();
      renderAgentRunnerPanel();
      return buildAgentRunnerBridgeSnapshot();
    },
    setPlannerMode(plannerMode = "auto") {
      state.agentRunner.plannerMode = readFirstString(plannerMode, "auto") || "auto";
      renderAgentRunnerPanel();
      return buildAgentRunnerBridgeSnapshot();
    },
    setMaxSteps(maxSteps = AGENT_RUNNER_DEFAULT_MAX_STEPS) {
      state.agentRunner.maxSteps = normalizeAgentRunnerMaxSteps(maxSteps);
      renderAgentRunnerPanel();
      return buildAgentRunnerBridgeSnapshot();
    },
    clearLog() {
      return clearAgentRunnerLog();
    },
    step(meta = {}) {
      return runAgentRunnerStep(meta);
    },
    auto(meta = {}) {
      return runAgentRunnerAuto(meta);
    },
    stop() {
      return requestAgentRunnerStop();
    },
  });
  window.juggernautAgentRunner = window[AGENT_RUNNER_BRIDGE_KEY];
  publishAgentRunnerStateEvent();
  return window[AGENT_RUNNER_BRIDGE_KEY];
}

function _annotateBoxToCssRect(box) {
  if (!box) return null;
  const dpr = getDpr();
  const a = imageToCanvas({ x: Number(box.x0) || 0, y: Number(box.y0) || 0 });
  const b = imageToCanvas({ x: Number(box.x1) || 0, y: Number(box.y1) || 0 });
  const left = Math.min(a.x, b.x) / dpr;
  const top = Math.min(a.y, b.y) / dpr;
  const right = Math.max(a.x, b.x) / dpr;
  const bottom = Math.max(a.y, b.y) / dpr;
  return { left, top, right, bottom, width: right - left, height: bottom - top };
}

function _normalizeAnnotateBox(box, img) {
  if (!box) return null;
  const x0 = Number(box.x0) || 0;
  const y0 = Number(box.y0) || 0;
  const x1 = Number(box.x1) || 0;
  const y1 = Number(box.y1) || 0;
  let left = Math.min(x0, x1);
  let top = Math.min(y0, y1);
  let right = Math.max(x0, x1);
  let bottom = Math.max(y0, y1);
  const iw = img?.img?.naturalWidth || img?.width || null;
  const ih = img?.img?.naturalHeight || img?.height || null;
  if (iw && ih) {
    left = clamp(left, 0, iw);
    right = clamp(right, 0, iw);
    top = clamp(top, 0, ih);
    bottom = clamp(bottom, 0, ih);
  }
  return { imageId: box.imageId, x0: left, y0: top, x1: right, y1: bottom, at: box.at || Date.now() };
}

function showAnnotatePanelForBox() {
  const panel = els.annotatePanel;
  const wrap = els.canvasWrap;
  const img = getActiveImage();
  const box = state.annotateBox;
  if (!panel || !wrap || !img || !box || box.imageId !== img.id) return;

  // Populate model selector from the main image model dropdown.
  if (els.annotateModel && els.imageModel) {
    els.annotateModel.innerHTML = "";
    for (const opt of Array.from(els.imageModel.options || [])) {
      if (!opt?.value) continue;
      const o = document.createElement("option");
      o.value = opt.value;
      o.textContent = opt.textContent || opt.value;
      els.annotateModel.appendChild(o);
    }
    els.annotateModel.value = settings.imageModel;
  }

  const normalized = _normalizeAnnotateBox(box, img);
  if (!normalized) return;
  const iw = img?.img?.naturalWidth || img?.width || null;
  const ih = img?.img?.naturalHeight || img?.height || null;
  if (els.annotateMeta) {
    if (iw && ih) {
      const xPct = (normalized.x0 / iw) * 100;
      const yPct = (normalized.y0 / ih) * 100;
      const wPct = ((normalized.x1 - normalized.x0) / iw) * 100;
      const hPct = ((normalized.y1 - normalized.y0) / ih) * 100;
      els.annotateMeta.textContent = `Box: x ${xPct.toFixed(1)}% y ${yPct.toFixed(1)}% w ${wPct.toFixed(1)}% h ${hPct.toFixed(1)}%`;
    } else {
      const wPx = Math.max(0, normalized.x1 - normalized.x0);
      const hPx = Math.max(0, normalized.y1 - normalized.y0);
      els.annotateMeta.textContent = `Box: x ${Math.round(normalized.x0)} y ${Math.round(normalized.y0)} w ${Math.round(wPx)} h ${Math.round(hPx)}`;
    }
  }

  // Position near the box, clamped within canvas.
  panel.classList.remove("hidden");
  const rect = _annotateBoxToCssRect(normalized);
  const baseX = rect ? rect.right + 12 : 12;
  const baseY = rect ? rect.top : 12;
  panel.style.left = `${baseX}px`;
  panel.style.top = `${baseY}px`;

  requestAnimationFrame(() => {
    const pw = panel.offsetWidth || 0;
    const ph = panel.offsetHeight || 0;
    const maxX = Math.max(8, wrap.clientWidth - pw - 8);
    const maxY = Math.max(8, wrap.clientHeight - ph - 8);
    let x = clamp(baseX, 8, maxX);
    let y = clamp(baseY, 8, maxY);
    // If it doesn't fit to the right, prefer left of the box.
    if (rect && x >= maxX && rect.left - pw - 12 >= 8) {
      x = clamp(rect.left - pw - 12, 8, maxX);
    }
    panel.style.left = `${x}px`;
    panel.style.top = `${y}px`;
  });

  // Focus input for speed.
  setTimeout(() => {
    try {
      if (els.annotateText) els.annotateText.focus();
    } catch {
      // ignore
    }
  }, 0);
}

function _getCircles(imageId) {
  const key = String(imageId || "");
  if (!key) return [];
  const existing = state.circlesByImageId.get(key);
  return Array.isArray(existing) ? existing : [];
}

function hideMarkPanel() {
  if (!els.markPanel) return;
  els.markPanel.classList.add("hidden");
  state.activeCircle = null;
}

function showMarkPanelForCircle(circle) {
  const panel = els.markPanel;
  const wrap = els.canvasWrap;
  const img = getActiveImage();
  if (!panel || !wrap || !img || !circle || circle.imageId !== img.id) return;

  panel.classList.remove("hidden");
  state.activeCircle = { imageId: circle.imageId, id: circle.id };

  if (els.markTitle) {
    els.markTitle.textContent = "Circle";
  }

  const iw = img?.img?.naturalWidth || img?.width || null;
  const ih = img?.img?.naturalHeight || img?.height || null;
  if (els.markMeta) {
    if (iw && ih) {
      const xPct = (Number(circle.cx) / iw) * 100;
      const yPct = (Number(circle.cy) / ih) * 100;
      const rPct = (Number(circle.r) / Math.max(1, Math.min(iw, ih))) * 100;
      els.markMeta.textContent = `Circle: x ${xPct.toFixed(1)}% y ${yPct.toFixed(1)}% r ${rPct.toFixed(1)}%`;
    } else {
      els.markMeta.textContent = `Circle: x ${Math.round(Number(circle.cx) || 0)} y ${Math.round(Number(circle.cy) || 0)} r ${Math.round(
        Number(circle.r) || 0
      )} (px)`;
    }
  }

  if (els.markText) {
    els.markText.value = String(circle.label || "");
  }

  // Position near the circle (prefer right side), clamped within canvas.
  const dpr = getDpr();
  const c = imageToCanvas({ x: Number(circle.cx) || 0, y: Number(circle.cy) || 0 });
  const edge = imageToCanvas({ x: (Number(circle.cx) || 0) + (Number(circle.r) || 0), y: Number(circle.cy) || 0 });
  const rPx = Math.max(0, Math.hypot(edge.x - c.x, edge.y - c.y));
  const baseX = (c.x + rPx) / dpr + 12;
  const baseY = c.y / dpr - 10;
  panel.style.left = `${baseX}px`;
  panel.style.top = `${baseY}px`;

  requestAnimationFrame(() => {
    const pw = panel.offsetWidth || 0;
    const ph = panel.offsetHeight || 0;
    const maxX = Math.max(8, wrap.clientWidth - pw - 8);
    const maxY = Math.max(8, wrap.clientHeight - ph - 8);
    const x = clamp(baseX, 8, maxX);
    const y = clamp(baseY, 8, maxY);
    panel.style.left = `${x}px`;
    panel.style.top = `${y}px`;
  });

  // Focus input for speed.
  setTimeout(() => {
    try {
      if (els.markText) els.markText.focus();
    } catch {
      // ignore
    }
  }, 0);
}

function updateActiveCircleLabel(label) {
  const sel = state.activeCircle;
  if (!sel?.imageId || !sel?.id) return false;
  const nextLabel = String(label || "").trim();
  const list = _getCircles(sel.imageId).slice();
  const idx = list.findIndex((c) => c && c.id === sel.id);
  if (idx < 0) return false;
  list[idx] = { ...list[idx], label: nextLabel };
  state.circlesByImageId.set(sel.imageId, list);
  scheduleVisualPromptWrite();
  requestRender();
  return true;
}

function deleteActiveCircle() {
  const sel = state.activeCircle;
  if (!sel?.imageId || !sel?.id) return false;
  const list = _getCircles(sel.imageId).slice();
  const next = list.filter((c) => c && c.id !== sel.id);
  state.circlesByImageId.set(sel.imageId, next);
  hideMarkPanel();
  scheduleVisualPromptWrite();
  recordTimelineNode({
    imageId: sel.imageId,
    action: "Erase Mark",
    kind: "annotation",
    visualMode: "icon",
    label: "Circle Mark",
    previewImageId: sel.imageId,
    previewPath: state.imagesById.get(sel.imageId)?.path || null,
  });
  requestRender();
  return true;
}

const SVG_NS = "http://www.w3.org/2000/svg";
const XLINK_NS = "http://www.w3.org/1999/xlink";

function svgEl(name) {
  return document.createElementNS(SVG_NS, name);
}

function rand01(seed) {
  // Deterministic 0..1 value for a given number seed.
  const x = Math.sin(seed * 999.123) * 43758.5453123;
  return x - Math.floor(x);
}

function hash32(value) {
  // FNV-1a-ish 32-bit hash for stable per-node motion patterns.
  const s = String(value || "");
  let h = 2166136261;
  for (let i = 0; i < s.length; i += 1) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
}

let larvaRaf = null;
let larvaStartedAt = null;
function stopLarvaAnimator() {
  if (!larvaRaf) return;
  try {
    cancelAnimationFrame(larvaRaf);
  } catch {
    // ignore
  }
  larvaRaf = null;
}

function ensureLarvaAnimator() {
  if (larvaRaf) return;
  if (!state.larvaTargets || state.larvaTargets.length === 0) return;
  if (document.hidden) return;
  if (window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;
  if (larvaStartedAt == null) larvaStartedAt = performance.now();
  const TAU = Math.PI * 2;
  const LOOP_MS = 4000; // Perfect loop: all larva motion repeats exactly every 4s.
  const tick = (now) => {
    if (document.hidden) {
      larvaRaf = null;
      return;
    }
    const targets = state.larvaTargets || [];
    if (targets.length === 0) {
      larvaRaf = null;
      return;
    }
    const phase = ((now - larvaStartedAt) % LOOP_MS) / LOOP_MS; // 0..1
    const w = TAU * phase;
    for (const target of targets) {
      const seed = Number(target?.seed || 0);
      const svg = target?.svgEl;
      const btnEl = target?.btnEl;
      const headEl = target?.headEl;
      const tailEl = target?.tailEl;
      if (target?.exploding) continue;

      if (svg) {
        const tilt = target?.tiltDeg || 0;
        const rotAmp = target?.rotAmp || 0.8;
        const nRot = target?.nRot || 2;
        const nSquish = target?.nSquish || 2;
        const pRot = target?.phaseRot || 0;
        const pSquish = target?.phaseSquish || 0;
        const squishAmp = target?.squishAmp || 0.0065;
        const rot = tilt + rotAmp * Math.sin(w * nRot + pRot + seed * 0.01);
        const squish = 1 + squishAmp * Math.sin(w * nSquish + pSquish + seed * 0.01);
        // Keep the larva "on the surface"; motion reads mostly as head/tail movement.
        svg.style.transform = `rotate(${rot.toFixed(2)}deg) scale(${squish.toFixed(4)})`;
      }

      if (headEl) {
        const nHead = target?.nHead || 2;
        const nHeadRot = target?.nHeadRot || nHead;
        const ampHX = target?.headAmpX || 1.3;
        const ampHY = target?.headAmpY || 0.9;
        const ampHRot = target?.headRotAmp || 8;
        const pHX = target?.phaseHeadX || 0;
        const pHY = target?.phaseHeadY || 0;
        const pHRot = target?.phaseHeadRot || 0;
        const hx = ampHX * Math.sin(w * nHead + pHX + seed * 0.01);
        const hy = ampHY * Math.cos(w * nHead + pHY + seed * 0.01);
        const ha = ampHRot * Math.sin(w * nHeadRot + pHRot + seed * 0.01);
        headEl.setAttribute(
          "transform",
          `translate(${hx.toFixed(2)} ${hy.toFixed(2)}) rotate(${ha.toFixed(2)} 54 44)`
        );
      }

      if (tailEl) {
        const nTail = target?.nTail || 2;
        const nTailRot = target?.nTailRot || nTail;
        const ampTX = target?.tailAmpX || 1.0;
        const ampTY = target?.tailAmpY || 0.7;
        const ampTRot = target?.tailRotAmp || 6;
        const pTX = target?.phaseTailX || 0;
        const pTY = target?.phaseTailY || 0;
        const pTRot = target?.phaseTailRot || 0;
        const tx = ampTX * Math.sin(w * nTail + pTX + seed * 0.01);
        const ty = ampTY * Math.cos(w * nTail + pTY + seed * 0.01);
        const ta = ampTRot * Math.sin(w * nTailRot + pTRot + seed * 0.01);
        tailEl.setAttribute(
          "transform",
          `translate(${tx.toFixed(2)} ${ty.toFixed(2)}) rotate(${ta.toFixed(2)} 302 44)`
        );
      }

      if (btnEl) {
        const nShadow = target?.nShadow || 2;
        const pShadow = target?.phaseShadow || 0;
        const sh = 0.92 + 0.08 * Math.sin(w * nShadow + pShadow + seed * 0.01);
        const sh2 = 0.70 + 0.06 * Math.sin(w * nShadow + pShadow + seed * 0.01 + 1.2);
        const shA = 0.72 + 0.10 * Math.sin(w * nShadow + pShadow + seed * 0.01 + 2.4);
        btnEl.style.setProperty("--larva-shadow-sx", sh.toFixed(3));
        btnEl.style.setProperty("--larva-shadow-sy", sh2.toFixed(3));
        btnEl.style.setProperty("--larva-shadow-a", shA.toFixed(3));
      }
    }
    larvaRaf = requestAnimationFrame(tick);
  };
  larvaRaf = requestAnimationFrame(tick);
}

function buildLarvaSvg(label, { uid, seed } = {}) {
  const title = String(label || "").toUpperCase();
  const safeUid = uid || `larva-${state.larvaUid++}`;
  const bodyId = `larva-body-${safeUid}`;
  const glowId = `larva-glow-${safeUid}`;
  const curveId = `larva-curve-${safeUid}`;
  const filterId = `larva-wiggle-${safeUid}`;

  const svg = svgEl("svg");
  svg.setAttribute("class", "larva-svg");
  svg.setAttribute("viewBox", "0 0 320 84");
  svg.setAttribute("fill", "none");
  svg.setAttribute("aria-hidden", "true");
  svg.setAttribute("preserveAspectRatio", "none");

  const defs = svgEl("defs");

  const bodyGrad = svgEl("radialGradient");
  bodyGrad.setAttribute("id", bodyId);
  bodyGrad.setAttribute("cx", "34%");
  bodyGrad.setAttribute("cy", "26%");
  bodyGrad.setAttribute("r", "90%");
  {
    const stop1 = svgEl("stop");
    stop1.setAttribute("offset", "0%");
    stop1.setAttribute("stop-color", "#ff8fd4");
    bodyGrad.appendChild(stop1);
    const stop2 = svgEl("stop");
    stop2.setAttribute("offset", "42%");
    stop2.setAttribute("stop-color", "#ff2f9c");
    bodyGrad.appendChild(stop2);
    const stop3 = svgEl("stop");
    stop3.setAttribute("offset", "100%");
    stop3.setAttribute("stop-color", "#1f020e");
    bodyGrad.appendChild(stop3);
  }
  defs.appendChild(bodyGrad);

  const glowGrad = svgEl("radialGradient");
  glowGrad.setAttribute("id", glowId);
  glowGrad.setAttribute("cx", "40%");
  glowGrad.setAttribute("cy", "40%");
  glowGrad.setAttribute("r", "80%");
  {
    const stop1 = svgEl("stop");
    stop1.setAttribute("offset", "0%");
    stop1.setAttribute("stop-color", "#ff5ebe");
    stop1.setAttribute("stop-opacity", "0.40");
    glowGrad.appendChild(stop1);
    const stop2 = svgEl("stop");
    stop2.setAttribute("offset", "60%");
    stop2.setAttribute("stop-color", "#c56bff");
    stop2.setAttribute("stop-opacity", "0.12");
    glowGrad.appendChild(stop2);
    const stop3 = svgEl("stop");
    stop3.setAttribute("offset", "100%");
    stop3.setAttribute("stop-color", "#000000");
    stop3.setAttribute("stop-opacity", "0");
    glowGrad.appendChild(stop3);
  }
  defs.appendChild(glowGrad);

  const filter = svgEl("filter");
  filter.setAttribute("id", filterId);
  filter.setAttribute("x", "-30");
  filter.setAttribute("y", "-30");
  filter.setAttribute("width", "380");
  filter.setAttribute("height", "160");
  filter.setAttribute("filterUnits", "userSpaceOnUse");

  const turb = svgEl("feTurbulence");
  turb.setAttribute("type", "turbulence");
  turb.setAttribute("baseFrequency", "0.012 0.020");
  turb.setAttribute("numOctaves", "2");
  turb.setAttribute("seed", String(seed ?? 2));
  turb.setAttribute("result", "noise");
  filter.appendChild(turb);

  const disp = svgEl("feDisplacementMap");
  disp.setAttribute("in", "SourceGraphic");
  disp.setAttribute("in2", "noise");
  disp.setAttribute("scale", "10");
  disp.setAttribute("xChannelSelector", "R");
  disp.setAttribute("yChannelSelector", "G");
  filter.appendChild(disp);

  defs.appendChild(filter);
  svg.appendChild(defs);

  const g = svgEl("g");
  g.setAttribute("filter", `url(#${filterId})`);

  const aura = svgEl("path");
  aura.setAttribute(
    "d",
    "M24 44 C32 22 78 14 124 18 C176 22 236 14 280 20 C300 22 312 30 316 42 C320 54 312 64 294 66 C244 74 176 78 122 74 C76 70 34 62 24 44 Z"
  );
  aura.setAttribute("fill", `url(#${glowId})`);
  aura.setAttribute("opacity", "0.62");
  g.appendChild(aura);

  const body = svgEl("path");
  body.setAttribute(
    "d",
    "M28 44 C36 24 82 16 128 20 C186 24 248 16 286 22 C302 24 312 32 316 42 C320 52 312 60 296 64 C248 72 180 74 128 70 C82 66 40 58 28 44 Z"
  );
  body.setAttribute("fill", `url(#${bodyId})`);
  body.setAttribute("stroke", "rgba(170, 40, 110, 0.62)");
  body.setAttribute("stroke-width", "2");
  g.appendChild(body);

  const headGroup = svgEl("g");
  headGroup.dataset.part = "head";
  // Head cap (subtle) so head/tail motion reads as "alive" without looking like a UI widget.
  const headCap = svgEl("ellipse");
  headCap.setAttribute("cx", "54");
  headCap.setAttribute("cy", "44");
  headCap.setAttribute("rx", "22");
  headCap.setAttribute("ry", "18");
  headCap.setAttribute("fill", "rgba(0, 0, 0, 0.14)");
  headGroup.appendChild(headCap);

  const headSheen = svgEl("ellipse");
  headSheen.setAttribute("cx", "48");
  headSheen.setAttribute("cy", "38");
  headSheen.setAttribute("rx", "14");
  headSheen.setAttribute("ry", "10");
  headSheen.setAttribute("fill", "rgba(255, 255, 255, 0.12)");
  headSheen.setAttribute("opacity", "0.7");
  headGroup.appendChild(headSheen);

  const headDot1 = svgEl("circle");
  headDot1.setAttribute("cx", "44");
  headDot1.setAttribute("cy", "48");
  headDot1.setAttribute("r", "2.0");
  headDot1.setAttribute("fill", "rgba(255, 255, 255, 0.10)");
  headGroup.appendChild(headDot1);

  const headDot2 = svgEl("circle");
  headDot2.setAttribute("cx", "52");
  headDot2.setAttribute("cy", "50");
  headDot2.setAttribute("r", "1.4");
  headDot2.setAttribute("fill", "rgba(255, 255, 255, 0.08)");
  headGroup.appendChild(headDot2);

  g.appendChild(headGroup);

  const tailGroup = svgEl("g");
  tailGroup.dataset.part = "tail";
  const tailTip = svgEl("path");
  tailTip.setAttribute("d", "M302 40 L318 44 L302 48 Z");
  tailTip.setAttribute("fill", "rgba(70, 10, 120, 0.55)");
  tailGroup.appendChild(tailTip);

  const tailShine = svgEl("path");
  tailShine.setAttribute("d", "M300 38 C308 38 314 40 318 44 C314 48 308 50 300 50");
  tailShine.setAttribute("stroke", "rgba(255, 255, 255, 0.10)");
  tailShine.setAttribute("stroke-width", "2");
  tailShine.setAttribute("stroke-linecap", "round");
  tailGroup.appendChild(tailShine);
  g.appendChild(tailGroup);

  // Segment ridges (worm rings).
  for (let i = 0; i < 10; i += 1) {
    const x = 68 + i * 22;
    const ridge = svgEl("path");
    ridge.setAttribute("d", `M${x} 18 Q${x - 10} 42 ${x} 66`);
    ridge.setAttribute("stroke", "rgba(255, 255, 255, 0.17)");
    ridge.setAttribute("stroke-width", "3");
    ridge.setAttribute("stroke-linecap", "round");
    ridge.setAttribute("opacity", "0.55");
    g.appendChild(ridge);

    const shadow = svgEl("path");
    shadow.setAttribute("d", `M${x + 2} 22 Q${x - 6} 44 ${x + 2} 62`);
    shadow.setAttribute("stroke", "rgba(0, 0, 0, 0.18)");
    shadow.setAttribute("stroke-width", "3");
    shadow.setAttribute("stroke-linecap", "round");
    shadow.setAttribute("opacity", "0.55");
    g.appendChild(shadow);
  }

  // Gloss highlight.
  const gloss = svgEl("path");
  gloss.setAttribute("d", "M54 34 C124 16 204 16 286 30");
  gloss.setAttribute("stroke", "rgba(255, 255, 255, 0.18)");
  gloss.setAttribute("stroke-width", "9");
  gloss.setAttribute("stroke-linecap", "round");
  gloss.setAttribute("opacity", "0.46");
  g.appendChild(gloss);

  // Speckles.
  for (let i = 0; i < 14; i += 1) {
    const c = svgEl("circle");
    const cx = 56 + ((i * 19 + (seed ?? 0) * 17) % 220);
    const cy = 26 + ((i * 13 + (seed ?? 0) * 11) % 32);
    const r = 1.1 + ((i + (seed ?? 0)) % 3) * 0.5;
    c.setAttribute("cx", String(cx));
    c.setAttribute("cy", String(cy));
    c.setAttribute("r", String(r));
    c.setAttribute("fill", "rgba(255, 255, 255, 0.11)");
    g.appendChild(c);
  }

  // Slight curve so the text feels "painted onto" the larva.
  const curve = svgEl("path");
  curve.setAttribute("id", curveId);
  // Keep the label centered on the thickest part of the body.
  curve.setAttribute("d", "M62 52 C136 50 210 50 282 52");
  curve.setAttribute("fill", "none");
  g.appendChild(curve);

  const tight = title.replace(/\s+/g, "").length;
  let fontSize = 26;
  if (tight >= 12) fontSize = 24;
  if (tight >= 14) fontSize = 22;
  if (tight >= 16) fontSize = 20;

  const text = svgEl("text");
  text.setAttribute("fill", "rgba(255, 246, 252, 0.96)");
  text.setAttribute("stroke", "rgba(0, 0, 0, 0.40)");
  text.setAttribute("stroke-width", "6");
  text.setAttribute("font-family", "Space Grotesk, sans-serif");
  text.setAttribute("font-weight", "800");
  text.setAttribute("font-size", String(fontSize));
  text.setAttribute("letter-spacing", "3");
  text.setAttribute("text-anchor", "middle");
  text.setAttribute("paint-order", "stroke fill");

  const textPath = svgEl("textPath");
  textPath.setAttribute("startOffset", "50%");
  textPath.setAttribute("href", `#${curveId}`);
  textPath.setAttributeNS(XLINK_NS, "xlink:href", `#${curveId}`);
  textPath.textContent = title;
  text.appendChild(textPath);
  g.appendChild(text);

  svg.appendChild(g);
  return { svg, turbEl: turb, dispEl: disp, headEl: headGroup, tailEl: tailGroup };
}

function spawnCooldownKey(nodeId, imageId) {
  return `${String(imageId || "")}::${String(nodeId || "")}`;
}

function isSpawnNodeOnCooldown(nodeId, imageId) {
  const key = spawnCooldownKey(nodeId, imageId);
  const until = state.spawnCooldowns.get(key);
  if (!until) return false;
  if (Date.now() >= until) {
    state.spawnCooldowns.delete(key);
    return false;
  }
  return true;
}

function setSpawnNodeCooldown(nodeId, imageId, ms = 60_000) {
  const key = spawnCooldownKey(nodeId, imageId);
  state.spawnCooldowns.set(key, Date.now() + Math.max(1_000, Number(ms) || 60_000));
}

function explodeSpawnNode(btnEl, nodeId, imageId) {
  if (!btnEl || !nodeId) return;
  if (btnEl.classList.contains("exploding")) return;
  setSpawnNodeCooldown(nodeId, imageId, 60_000);

  // Stop per-frame warping so the explosion animation can take over cleanly.
  for (const target of state.larvaTargets) {
    if (target?.btnEl === btnEl) {
      target.exploding = true;
      try {
        if (target.svgEl) target.svgEl.style.transform = "";
      } catch {
        // ignore
      }
      break;
    }
  }

  btnEl.classList.add("exploding");
  btnEl.setAttribute("disabled", "disabled");

  // Let the pop animation play, then rebuild the spawnbar without this node.
  setTimeout(() => {
    if (btnEl?.isConnected) {
      try {
        btnEl.remove();
      } catch {
        // ignore
      }
    }
    chooseSpawnNodes();
  }, 680);

  // After cooldown, refresh if the same image is still selected.
  setTimeout(() => {
    const active = getActiveImage();
    if (active?.id && active.id === imageId) chooseSpawnNodes();
  }, 60_200);
}

function renderSpawnbar() {
  if (!els.spawnbar) return;
  if (!ENABLE_SPAWN_ACTIONS) {
    els.spawnbar.innerHTML = "";
    els.spawnbar.classList.add("hidden");
    stopLarvaAnimator();
    state.larvaTargets = [];
    return;
  }
  els.spawnbar.classList.remove("hidden");
  els.spawnbar.innerHTML = "";
  stopLarvaAnimator();
  state.larvaTargets = [];
  if (!state.activeId) return;
  const activeItem = getActiveImage();
  const activeId = activeItem?.id || state.activeId || "";
  const activePath = activeItem?.path || "";
  const frag = document.createDocumentFragment();
  for (const node of state.spawnNodes) {
    if (isSpawnNodeOnCooldown(node.id, activeId)) continue;
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = ENABLE_LARVA_SPAWN ? "spawn-node" : "spawn-action";
    btn.setAttribute("aria-label", node.title || "Action");
    const text = String(node.title || "");
    if (!ENABLE_LARVA_SPAWN) {
      btn.textContent = text;
    } else {
      const rawWidth = (120 + text.length * 10) * 0.8;
      const width = clamp(Math.round(rawWidth), 150, 240);
      btn.style.setProperty("--larva-w", `${width}px`);
      btn.style.setProperty("--larva-h", "46px");
      const stable = hash32(`${node.id}::${activeId}`);
      const uid = `larva-${node.id}-${stable.toString(16)}-${state.larvaUid++}`;
      const seed = stable % 1000;
      const built = buildLarvaSvg(text, { uid, seed });
      const r1 = rand01(stable + 1.1);
      const r2 = rand01(stable + 2.2);
      const r3 = rand01(stable + 3.3);
      const r4 = rand01(stable + 4.4);
      const tilt = (r1 - 0.5) * 7.0; // ~[-3.5..3.5]deg
      btn.style.setProperty("--larva-tilt", `${tilt.toFixed(2)}deg`);
      built.svg.style.transform = `rotate(${tilt.toFixed(2)}deg)`;
      btn.appendChild(built.svg);

      // Static organic warp; we animate head/tail (not full-body squiggle).
      const baseF1 = 0.0095 + r2 * 0.0040;
      const baseF2 = 0.0140 + r3 * 0.0050;
      const warpScale = 5.2 + r3 * 1.6;
      try {
        if (built.turbEl) built.turbEl.setAttribute("baseFrequency", `${baseF1.toFixed(4)} ${baseF2.toFixed(4)}`);
        if (built.dispEl) built.dispEl.setAttribute("scale", `${warpScale.toFixed(1)}`);
      } catch {
        // ignore
      }

      state.larvaTargets.push({
        nodeId: node.id,
        imagePath: activePath,
        btnEl: btn,
        svgEl: built.svg,
        turbEl: built.turbEl,
        dispEl: built.dispEl,
        headEl: built.headEl,
        tailEl: built.tailEl,
        seed,
        tiltDeg: tilt,
        rotAmp: 0.16 + r4 * 0.55,
        nRot: 1 + Math.floor(r3 * 3),
        nSquish: 1 + Math.floor(r4 * 3),
        phaseRot: r4 * Math.PI * 2,
        phaseSquish: r1 * Math.PI * 2,
        squishAmp: 0.0045 + r2 * 0.0035,
        nHead: 1 + Math.floor(r2 * 3),
        nHeadRot: 1 + Math.floor(r3 * 3),
        headAmpX: 1.0 + r1 * 1.6,
        headAmpY: 0.6 + r2 * 1.2,
        headRotAmp: 5 + r4 * 10,
        phaseHeadX: r2 * Math.PI * 2,
        phaseHeadY: r3 * Math.PI * 2,
        phaseHeadRot: r4 * Math.PI * 2,
        nTail: 1 + Math.floor(r3 * 3),
        nTailRot: 1 + Math.floor(r4 * 3),
        tailAmpX: 0.8 + r2 * 1.4,
        tailAmpY: 0.5 + r1 * 1.0,
        tailRotAmp: 4 + r3 * 8,
        phaseTailX: r3 * Math.PI * 2,
        phaseTailY: r4 * Math.PI * 2,
        phaseTailRot: r1 * Math.PI * 2,
        nShadow: 1 + Math.floor(r2 * 3),
        phaseShadow: r4 * Math.PI * 2,
      });
    }
    btn.addEventListener("click", () => {
      bumpInteraction();
      const imageId = getActiveImage()?.id || activeId;
      explodeSpawnNode(btn, node.id, imageId);
      handleSpawnNode(node).catch((err) => {
        console.error(err);
        showToast(err?.message || String(err), "error");
      });
    });
    frag.appendChild(btn);
  }
  els.spawnbar.appendChild(frag);
  if (ENABLE_LARVA_SPAWN) ensureLarvaAnimator();
}

function isMultiActionRunning() {
  return Boolean(
    state.pendingBlend ||
      state.pendingSwapDna ||
      state.pendingBridge ||
      state.pendingExtractDna ||
      state.pendingSoulLeech ||
      state.pendingExtractRule ||
      state.pendingOddOneOut ||
      state.pendingTriforce
  );
}

const ACTION_QUEUE_MAX = 32;
const ACTION_QUEUE_PRIORITY = {
  user: 100,
  background: 10,
};

function isEngineBusy({ includeReviewApply = true } = {}) {
  return Boolean(
    state.ptySpawning ||
      (includeReviewApply && state.designReviewApply?.status === "running") ||
      state.pendingBlend ||
      state.pendingSwapDna ||
      state.pendingBridge ||
      state.pendingExtractDna ||
      state.pendingSoulLeech ||
      state.pendingExtractRule ||
      state.pendingOddOneOut ||
      state.pendingTriforce ||
      state.pendingRecast ||
      state.pendingCreateLayers ||
      state.pendingPromptGenerate ||
      state.pendingReplace ||
      state.pendingRecreate ||
      state.expectingArtifacts
  );
}

function resetActionQueue() {
  state.actionQueue = [];
  state.actionQueueActive = null;
  state.actionQueueRunning = false;
  state.actionQueueStats = {
    replacedByKey: 0,
    droppedOverflow: 0,
    lastDropLabel: null,
  };
  syncActiveTabRecord({ capture: false, publish: true });
  renderSessionApiCallsReadout();
}

function _actionQueueMakeId() {
  return `aq-${Date.now()}-${Math.floor(Math.random() * 1e9)}`;
}

function enqueueAction({ label, key = null, priority = ACTION_QUEUE_PRIORITY.user, source = "user", run } = {}) {
  const fn = typeof run === "function" ? run : null;
  if (!label || !fn) return false;

  if (key && state.actionQueueActive?.key && state.actionQueueActive.key === key) {
    showToast(`${label} already running.`, "tip", 1800);
    return false;
  }

  const now = Date.now();
  let replacedCount = 0;
  if (key) {
    // De-dupe repeated clicks; keep latest request.
    const before = state.actionQueue.length;
    state.actionQueue = state.actionQueue.filter((item) => item?.key !== key);
    replacedCount = Math.max(0, before - state.actionQueue.length);
    if (replacedCount) {
      state.actionQueueStats.replacedByKey = Math.max(0, Number(state.actionQueueStats.replacedByKey) || 0) + replacedCount;
    }
  }

  const queuedItem = {
    id: _actionQueueMakeId(),
    label: String(label),
    key: key ? String(key) : null,
    priority: typeof priority === "number" ? priority : ACTION_QUEUE_PRIORITY.user,
    enqueuedAt: now,
    source: source ? String(source) : "user",
    run: fn,
  };
  state.actionQueue.push(queuedItem);

  // Keep queue bounded by dropping the lowest-priority oldest items.
  const droppedItems = [];
  while (state.actionQueue.length > ACTION_QUEUE_MAX) {
    let dropIdx = 0;
    for (let i = 1; i < state.actionQueue.length; i += 1) {
      const a = state.actionQueue[i];
      const b = state.actionQueue[dropIdx];
      const ap = typeof a?.priority === "number" ? a.priority : 0;
      const bp = typeof b?.priority === "number" ? b.priority : 0;
      if (ap < bp) {
        dropIdx = i;
        continue;
      }
      if (ap === bp && (a?.enqueuedAt || 0) < (b?.enqueuedAt || 0)) {
        dropIdx = i;
      }
    }
    const dropped = state.actionQueue.splice(dropIdx, 1)[0];
    if (dropped) droppedItems.push(dropped);
  }

  if (droppedItems.length) {
    state.actionQueueStats.droppedOverflow =
      Math.max(0, Number(state.actionQueueStats.droppedOverflow) || 0) + droppedItems.length;
    state.actionQueueStats.lastDropLabel = String(droppedItems[droppedItems.length - 1]?.label || "Action");
    const dropLead = String(droppedItems[0]?.label || "action");
    const more = droppedItems.length > 1 ? ` (+${droppedItems.length - 1} more)` : "";
    showToast(`Queue full: dropped ${dropLead}${more}.`, "tip", 2600);
  }

  const queuedKept = state.actionQueue.some((item) => item?.id === queuedItem.id);
  if (queuedKept) {
    const mergedNote = replacedCount ? ` (updated ${replacedCount})` : "";
    showToast(`Queued: ${label}${mergedNote}`, "tip", 1500);
  } else {
    showToast(`Queue full: ${label} was not queued.`, "error", 2800);
  }
  syncActiveTabRecord({ capture: false, publish: true });
  renderQuickActions();
  renderSessionApiCallsReadout();
  processActionQueue().catch((err) => {
    reportUserError("Queue processing", err, { retryHint: "Wait for current work to finish, then retry." });
  });
  return queuedKept;
}

function _pickNextQueuedActionIndex() {
  if (!state.actionQueue.length) return -1;
  let bestIdx = 0;
  for (let i = 1; i < state.actionQueue.length; i += 1) {
    const a = state.actionQueue[i];
    const b = state.actionQueue[bestIdx];
    const ap = typeof a?.priority === "number" ? a.priority : 0;
    const bp = typeof b?.priority === "number" ? b.priority : 0;
    if (ap > bp) {
      bestIdx = i;
      continue;
    }
    if (ap === bp && (a?.enqueuedAt || 0) < (b?.enqueuedAt || 0)) {
      bestIdx = i;
    }
  }
  return bestIdx;
}

async function processActionQueue() {
  if (state.actionQueueRunning) return;
  state.actionQueueRunning = true;
  try {
    if (state.actionQueueActive && !isEngineBusy()) {
      state.actionQueueActive = null;
      syncActiveTabRecord({ capture: false, publish: true });
      renderQuickActions();
      renderSessionApiCallsReadout();
    }

    while (!state.actionQueueActive && !isEngineBusy() && state.actionQueue.length) {
      const idx = _pickNextQueuedActionIndex();
      if (idx < 0) return;
      const item = state.actionQueue.splice(idx, 1)[0];
      if (!item) return;

      state.actionQueueActive = {
        id: item.id,
        label: item.label,
        key: item.key || null,
        priority: item.priority,
        enqueuedAt: item.enqueuedAt,
        source: item.source || "user",
      };
      syncActiveTabRecord({ capture: false, publish: true });
      renderQuickActions();
      renderSessionApiCallsReadout();

      const queuedStatus = `Engine: queued action running (${item.label})`;
      const prevStatusText = String(state.lastStatusText || "");
      const prevStatusError = Boolean(state.lastStatusError);
      try {
        setStatus(queuedStatus);
        await Promise.resolve(item.run());
      } catch (err) {
        console.error("Queued action failed:", item?.label, err);
        reportUserError(item?.label || "Queued action", err, { retryHint: "Retry from Skills." });
      }

      if (isEngineBusy()) {
        // Engine-driven action is in flight; completion events will resume the queue.
        return;
      }

      // If the queued callback returned without launching engine work, clear the
      // temporary queue-running status so the ribbon does not appear stuck.
      if (String(state.lastStatusText || "") === queuedStatus) {
        setStatus(prevStatusText || (state.ptySpawned ? "Engine: ready" : "Engine: idle"), prevStatusError);
      }

      // Completed immediately (local action or no-op); continue draining.
      state.actionQueueActive = null;
      syncActiveTabRecord({ capture: false, publish: true });
      renderQuickActions();
      renderSessionApiCallsReadout();
    }
  } finally {
    state.actionQueueRunning = false;
    syncActiveTabRecord({ capture: false, publish: true });
    renderSessionApiCallsReadout();
  }
}

function chooseSpawnNodes() {
  const currentNodesSignature = Array.isArray(state.spawnNodes)
    ? state.spawnNodes.map((node) => `${node?.id || ""}:${node?.title || ""}:${node?.action || ""}`).join("|")
    : "";
  if (!ENABLE_SPAWN_ACTIONS) {
    const nextKey = `disabled||${state.spawnNodesVersion}`;
    if (state.lastRenderedSpawnNodesKey === nextKey) return false;
    state.spawnNodes = [];
    state.lastRenderedSpawnNodesKey = nextKey;
    renderSpawnbar();
    renderQuickActions();
    return true;
  }
  if (!state.activeId) {
    const nextKey = `empty||${state.spawnNodesVersion}`;
    if (state.lastRenderedSpawnNodesKey === nextKey) return false;
    state.spawnNodes = [];
    state.lastRenderedSpawnNodesKey = nextKey;
    renderSpawnbar();
    renderQuickActions();
    return true;
  }
  const img = getActiveImage();
  const items = [];
  if (state.canvasMode === "multi") {
    const canBlend = selectedCount() === 2 && !isMultiActionRunning();
    if (canBlend) items.push({ id: "blend_pair", title: "Combine", action: "blend_pair" });
  }
  items.push({ id: "bg_white", title: "Studio White", action: "bg_white" });
  items.push({ id: "variations", title: "Variations", action: "variations" });
  if (img?.img) {
    const w = img.img.naturalWidth;
    const h = img.img.naturalHeight;
    if (w && h && Math.abs(w - h) > 8) {
      items.push({ id: "crop_square", title: "Square Crop", action: "crop_square" });
    } else {
      items.push({ id: "bg_sweep", title: "Soft Sweep", action: "bg_sweep" });
    }
  } else {
    items.push({ id: "bg_sweep", title: "Soft Sweep", action: "bg_sweep" });
  }
  // Keep it to 3 kernels.
  const imageId = img?.id || state.activeId || "";
  const available = items.filter((item) => !isSpawnNodeOnCooldown(item.id, imageId));
  const nextNodes = available.slice(0, 3);
  const nextNodesSignature = nextNodes.map((node) => `${node?.id || ""}:${node?.title || ""}:${node?.action || ""}`).join("|");
  const nextKey = [
    state.spawnNodesVersion,
    state.canvasMode || "multi",
    imageId,
    nextNodesSignature,
  ].join("||");
  if (state.lastRenderedSpawnNodesKey === nextKey) return false;
  if (currentNodesSignature !== nextNodesSignature) {
    state.spawnNodes = nextNodes;
  }
  state.lastRenderedSpawnNodesKey = nextKey;
  renderSpawnbar();
  renderQuickActions();
  return true;
}

function computeQuickActions() {
  // Scaffolding: keep this as a pure function of current canvas state so we can
  // grow rules over time without entangling UI code.
  const actions = [];
  const active = getActiveImage();
  const nSelected = selectedCount();

  if (!active) {
    actions.push({
      id: "no_image",
      label: "Import photos to unlock skills",
      disabled: true,
    });
    return actions;
  }

  // Multi canvas is the only supported mode.

  // Multi-image skills are driven by *selected* images, not run size.
  if (nSelected === 2) {
    actions.push({
      id: "combine",
      label: state.pendingBlend ? "Combine (running…)" : "Combine",
      title: "Blend the 2 selected photos into one",
      disabled: false,
      onClick: () => runBlendPair().catch((err) => console.error(err)),
    });
    actions.push({
      id: "bridge",
      label: state.pendingBridge ? "Bridge (running…)" : "Bridge",
      title: "Find the aesthetic midpoint between the 2 selected images (not a collage)",
      disabled: false,
      onClick: () => runBridgePair().catch((err) => console.error(err)),
    });
    actions.push({
      id: "swap_dna",
      label: state.pendingSwapDna ? "Swap DNA (running…)" : "Swap DNA",
      title: "Use structure from the active image and surface qualities from the other (Shift-click to invert)",
      disabled: false,
      onClick: (ev) =>
        runSwapDnaPair({ invert: Boolean(ev?.shiftKey) }).catch((err) => console.error(err)),
    });
    return actions;
  }
  if (nSelected === 3) {
    const runningMulti = isMultiActionRunning();
    actions.push({
      id: "extract_rule",
      label: state.pendingExtractRule ? "Extract the Rule (running…)" : "Extract the Rule",
      title: "Extract the invisible rule you're applying across the 3 selected images.",
      disabled: Boolean(runningMulti && !state.pendingExtractRule),
      onClick: () => runExtractRuleTriplet().catch((err) => console.error(err)),
    });
    actions.push({
      id: "odd_one_out",
      label: state.pendingOddOneOut ? "Odd One Out (running…)" : "Odd One Out",
      title: "Identify which of the 3 selected breaks the shared pattern, and explain why.",
      disabled: Boolean(runningMulti && !state.pendingOddOneOut),
      onClick: () => runOddOneOutTriplet().catch((err) => console.error(err)),
    });
    actions.push({
      id: "triforce",
      label: state.pendingTriforce ? "Triforce (running…)" : "Triforce",
      title: "Generate the centroid: one image equidistant from all 3 selected references.",
      disabled: Boolean(runningMulti && !state.pendingTriforce),
      onClick: () => runTriforceTriplet().catch((err) => console.error(err)),
    });
    return actions;
  }
  if (nSelected > 3) {
    actions.push({
      id: "multi_hint",
      label: `Multi-select: pick exactly 2 or 3 images (you have ${nSelected}).`,
      disabled: true,
    });
    return actions;
  }

  const iw = active?.img?.naturalWidth || active?.width || null;
  const ih = active?.img?.naturalHeight || active?.height || null;
  const canCropSquare = Boolean(iw && ih && Math.abs(iw - ih) > 8);

  actions.push({
    id: "create_layers",
    label: state.runningActionKey === "create_layers" ? "Create Layers (running…)" : "Create Layers",
    title: "Generate semantic layers: background, main subject, and detachable props.",
    disabled: nSelected !== 1,
    onClick: () => runCreateLayersFromSelection().catch((err) => console.error(err)),
  });
  actions.push({
    id: "recast",
    label: state.pendingRecast ? "Recast (running…)" : "Recast",
    title: "Reimagine the image in a totally different medium/context (lateral leap)",
    disabled: false,
    onClick: () => runRecast().catch((err) => console.error(err)),
  });

  actions.push({
    id: "bg_white",
    label: "Background: White",
    title: "Replace background with a clean studio white",
    disabled: false,
    onClick: () => applyBackground("white").catch((err) => console.error(err)),
  });
  actions.push({
    id: "bg_sweep",
    label: "Background: Sweep",
    title: "Replace background with a soft sweep gradient",
    disabled: false,
    onClick: () => applyBackground("sweep").catch((err) => console.error(err)),
  });
  actions.push({
    id: "crop_square",
    label: "Crop: Square",
    title: canCropSquare ? "Crop the active image to a centered square" : "Already square (or image size unknown)",
    disabled: !canCropSquare,
    onClick: canCropSquare ? () => cropSquare().catch((err) => console.error(err)) : null,
  });
  actions.push({
    id: "variations",
    label: "Variations",
    title: "Zero-prompt variations of the active image",
    disabled: false,
    onClick: () => runVariations().catch((err) => console.error(err)),
  });

  return actions;
}

function _runningKeyFromPendingReplace(pending) {
  const label = pending?.label ? String(pending.label) : "";
  const stable = label.toLowerCase();
  if (stable.includes("remove people")) return "remove_people";
  if (stable.includes("extract dna")) return "extract_dna";
  if (stable.includes("soul leech")) return "soul_leech";
  if (stable.includes("surprise")) return "surprise";
  if (stable.includes("studio white") || stable.includes("soft sweep") || stable.includes("background")) return "bg";
  if (stable.includes("annotate")) return "annotate";
  return "bg";
}

function currentRunningActionKey() {
  if (state.runningActionKey) return state.runningActionKey;
  if (state.pendingBlend) return "combine";
  if (state.pendingBridge) return "bridge";
  if (state.pendingSwapDna) return "swap_dna";
  if (state.pendingExtractDna) return "extract_dna";
  if (state.pendingSoulLeech) return "soul_leech";
  if (state.pendingExtractRule) return "extract_rule";
  if (state.pendingOddOneOut) return "odd_one_out";
  if (state.pendingTriforce) return "triforce";
  if (state.pendingPromptGenerate) return "prompt_generate";
  if (state.pendingRecast) return "recast";
  if (state.pendingCreateLayers) return "create_layers";
  if (state.pendingRecreate) return "variations";
  if (state.pendingReplace) return _runningKeyFromPendingReplace(state.pendingReplace);
  return null;
}

function juggernautActiveToolId() {
  if (communicationToolArmed()) return "";
  if (state.tool === "pan") return "move";
  if (state.tool === "lasso") return "select";
  return "";
}

function juggernautRunningToolId() {
  const runningKey = currentRunningActionKey();
  if (runningKey === "bg") return "new_background";
  if (runningKey === "remove_people") return "remove";
  if (runningKey === "variations") return "variants";
  if (runningKey === "crop_square" || runningKey === "recast") return "reframe";
  return "";
}

function singleImageRailJobMeta(toolKey) {
  const key = String(toolKey || "").trim();
  if (!key) return null;
  const visible = state.juggernautShell.singleImageRail.visibleJobs.find((job) => job.jobId === key) || null;
  const seed = getSingleImageRailItem(key);
  if (!visible && !seed) return null;
  return {
    ...(seed || {}),
    ...(visible || {}),
  };
}

function dispatchJuggernautShellEvent(type, detail = {}) {
  if (typeof window === "undefined" || typeof window.dispatchEvent !== "function") return null;
  const payload = detail && typeof detail === "object" ? detail : {};
  const event = new CustomEvent(type, {
    cancelable: true,
    detail: payload,
  });
  window.dispatchEvent(event);
  return event;
}

export async function applyJuggernautTool(toolId) {
  const normalizedRaw = String(toolId || "")
    .trim()
    .toLowerCase();
  const normalized = normalizedRaw === "select_subject" ? "select" : normalizedRaw;
  if (!normalized) return false;
  state.juggernautShell.lastToolKey = normalized;
  renderJuggernautShellChrome();
  const railJob = singleImageRailJobMeta(normalized);

  const eventDetail = {
    toolId: normalized,
    label: juggernautShellToolLabel(normalized),
    railContract: JUGGERNAUT_SHELL_RAIL_CONTRACT,
    jobId: railJob?.jobId || null,
    capability: railJob?.capability || null,
    requiresSelection: railJob?.requiresSelection ?? null,
    confidence: railJob?.confidence ?? null,
    reasonCodes: Array.isArray(railJob?.reasonCodes) ? railJob.reasonCodes.slice(0, 6) : [],
    stickyKey: railJob?.stickyKey || null,
    source: "shell",
    context: buildJuggernautShellContext(),
    requestedAt: Date.now(),
    selectedImageId: state.juggernautShell.selectedImageId,
    selectedImageIds: state.juggernautShell.selectedImageIds.slice(0, 3),
    selectedImage: state.juggernautShell.selectedImage,
  };
  dispatchJuggernautShellEvent("juggernaut:tool-requested", eventDetail);
  const delegated = dispatchJuggernautShellEvent("juggernaut:apply-tool", eventDetail);
  if (delegated?.defaultPrevented) return true;

  if (normalized === "move") {
    setCommunicationTool(null, { source: "shell_move" });
    setTool("pan");
    return true;
  }
  if (normalized === "upload") {
    return runWithUserError("Import photos", () => importPhotos(), {
      retryHint: "Choose supported image files and retry.",
    });
  }
  if (normalized === "select") {
    setCommunicationTool(null, { source: "shell_select" });
    setTool(state.tool === "lasso" ? "pan" : "lasso");
    return true;
  }
  if (typeof state.juggernautShell.toolInvoker === "function") {
    return (
      (await state.juggernautShell.toolInvoker({
        toolKey: normalized,
        ...eventDetail,
      })) ?? true
    );
  }
  if (railJob?.capability) {
    return false;
  }
  if (normalized === "export_psd") {
    return exportJuggernautPsd();
  }
  return false;
}

function dispatchJuggernautExportEvents(format, eventDetail) {
  dispatchJuggernautShellEvent("juggernaut:export-requested", eventDetail);
  if (format === "psd") {
    dispatchJuggernautShellEvent("juggernaut:export-psd-requested", eventDetail);
  }
  const delegated = dispatchJuggernautShellEvent("juggernaut:export", eventDetail);
  const legacyDelegated =
    format === "psd" ? dispatchJuggernautShellEvent("juggernaut:export-psd", eventDetail) : null;
  return Boolean(delegated?.defaultPrevented || legacyDelegated?.defaultPrevented);
}

function buildJuggernautExportEventDetail({ format = "psd", source = "shell" } = {}) {
  return {
    source,
    format: normalizeExportFormat(format),
    context: buildJuggernautShellContext(),
    requestedAt: Date.now(),
    selectedImageId: state.juggernautShell.selectedImageId,
    selectedImageIds: state.juggernautShell.selectedImageIds.slice(0, 3),
    selectedImage: state.juggernautShell.selectedImage,
  };
}

async function exportJuggernautFormat({ format = "psd", source = "shell" } = {}) {
  const normalizedFormat = normalizeExportFormat(format);
  state.juggernautShell.lastToolKey = exportFormatActionKey(normalizedFormat);
  renderJuggernautShellChrome();
  const eventDetail = buildJuggernautExportEventDetail({
    source,
    format: normalizedFormat,
  });
  if (dispatchJuggernautExportEvents(normalizedFormat, eventDetail)) return true;
  if (normalizedFormat === "psd" && typeof state.juggernautShell.psdExportHandler === "function") {
    return (
      (await state.juggernautShell.psdExportHandler({
        ...eventDetail,
      })) ?? true
    );
  }
  if (nativeRasterExportReady()) {
    return await exportRunInFormat(normalizedFormat);
  }
  showToast(exportFormatUnavailableMessage(normalizedFormat), "tip", 2800);
  return false;
}

export async function exportJuggernautPsd({ source = "shell" } = {}) {
  return exportJuggernautFormat({ format: "psd", source });
}

export async function exportJuggernautPng({ source = "shell" } = {}) {
  return exportJuggernautFormat({ format: "png", source });
}

async function exportJuggernautJpg({ source = "shell" } = {}) {
  return exportJuggernautFormat({ format: "jpg", source });
}

async function exportJuggernautWebp({ source = "shell" } = {}) {
  return exportJuggernautFormat({ format: "webp", source });
}

async function exportJuggernautTiff({ source = "shell" } = {}) {
  return exportJuggernautFormat({ format: "tiff", source });
}

function isSingleImageRailCapabilityPlan(plan = {}) {
  return Boolean(
    plan?.capability ||
      plan?.executionKind === "model_capability" ||
      plan?.execution?.kind === "model_capability"
  );
}

async function ensureSingleImageRailTargetLoaded(target = null) {
  if (!target?.path || target?.img) return target?.img || null;
  target.img = await loadImage(target.path);
  target.width = target.img?.naturalWidth || target.width || null;
  target.height = target.img?.naturalHeight || target.height || null;
  return target.img || null;
}

function captureSingleImageRailArtifactSnapshot(imageId = "") {
  const targetId = String(imageId || state.activeId || "").trim();
  const target = targetId ? state.imagesById.get(targetId) || null : null;
  const active = getActiveImage();
  return {
    targetImageId: targetId,
    targetImagePath: target?.path || "",
    activeImageId: active?.id || "",
    activeImagePath: active?.path || "",
    imageCount: Array.isArray(state.images) ? state.images.length : 0,
  };
}

function resolveSingleImageRailArtifact(route, snapshot) {
  if (String(route?.jobId || "").trim() === "variants") {
    const active = getActiveImage();
    const activeId = String(active?.id || "").trim();
    const activePath = String(active?.path || "").trim();
    if (!activeId || !activePath) return null;
    if (
      activeId !== String(snapshot?.activeImageId || "").trim() ||
      activePath !== String(snapshot?.activeImagePath || "").trim() ||
      (Array.isArray(state.images) ? state.images.length : 0) > Number(snapshot?.imageCount || 0)
    ) {
      return {
        imageId: activeId,
        outputPath: activePath,
        receiptPath: active?.receiptPath || null,
      };
    }
    return null;
  }

  const targetId = String(snapshot?.targetImageId || "").trim();
  const target = targetId ? state.imagesById.get(targetId) || null : null;
  const nextPath = String(target?.path || "").trim();
  if (!targetId || !nextPath) return null;
  if (nextPath === String(snapshot?.targetImagePath || "").trim()) return null;
  return {
    imageId: targetId,
    outputPath: nextPath,
    receiptPath: target?.receiptPath || null,
  };
}

function singleImageRailExecutionPending() {
  return Boolean(currentRunningActionKey() || state.expectingArtifacts);
}

async function waitForSingleImageRailArtifact(route, snapshot, { timeoutMs = SINGLE_IMAGE_RAIL_CAPABILITY_EXECUTION_TIMEOUT_MS } = {}) {
  const startedAt = Date.now();
  let sawPending = singleImageRailExecutionPending();
  while (Date.now() - startedAt < timeoutMs) {
    const artifact = resolveSingleImageRailArtifact(route, snapshot);
    if (artifact) return artifact;
    const pending = singleImageRailExecutionPending();
    if (pending) sawPending = true;
    if (!pending && sawPending && Date.now() - startedAt > 180) break;
    if (!pending && !sawPending && Date.now() - startedAt > 400) break;
    await new Promise((resolve) => setTimeout(resolve, 60));
  }
  const artifact = resolveSingleImageRailArtifact(route, snapshot);
  if (artifact) return artifact;
  throw new Error(`${route?.label || "This action"} did not produce an output artifact.`);
}

async function readSingleImageRailApplyKeyStatus() {
  if (state.keyStatus && typeof state.keyStatus === "object") return state.keyStatus;
  await refreshKeyStatus({ reason: "single_image_rail_apply" }).catch(() => {});
  return state.keyStatus || {};
}

function createSingleImageRailApplyProviderRouter() {
  return createDesignReviewProviderRouter({
    requestProvider: invokeDesignReviewProviderRequest,
    keyStatus: state.keyStatus || {},
    getKeyStatus: () => readSingleImageRailApplyKeyStatus(),
  });
}

function singleImageRailSubjectIsolationTargetRegion(selection = null) {
  if (!selection || typeof selection !== "object") return null;
  const bounds = selection.bounds && typeof selection.bounds === "object"
    ? {
        x: Number(selection.bounds.x0) || 0,
        y: Number(selection.bounds.y0) || 0,
        width: Math.max(1, Number(selection.bounds.w) || 1),
        height: Math.max(1, Number(selection.bounds.h) || 1),
      }
    : null;
  return {
    markIds: [],
    regionCandidateId: String(selection.regionCandidateId || "").trim() || null,
    bounds,
  };
}

async function writeSingleImageRailSubjectIsolationHintImage({ imageId = "", target = null, selection = null, requestId = "" } = {}) {
  if (!state.runDir) return null;
  const normalizedImageId = String(imageId || "").trim();
  const polygon = Array.isArray(selection?.polygon) ? selection.polygon : [];
  const bounds = selection?.bounds && typeof selection.bounds === "object" ? selection.bounds : null;
  if (!normalizedImageId || !target?.path || polygon.length < 3 || !bounds) return null;
  const img = await ensureSingleImageRailTargetLoaded(target);
  if (!img) return null;

  const x0 = Math.max(0, Math.floor(Number(bounds.x0) || 0));
  const y0 = Math.max(0, Math.floor(Number(bounds.y0) || 0));
  const width = Math.max(1, Math.ceil(Number(bounds.w) || 1));
  const height = Math.max(1, Math.ceil(Number(bounds.h) || 1));
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext("2d");
  if (!ctx) return null;
  ctx.clearRect(0, 0, width, height);
  ctx.save();
  ctx.translate(-x0, -y0);
  if (!drawPolygonPath(ctx, polygon)) {
    ctx.restore();
    return null;
  }
  ctx.clip();
  ctx.drawImage(img, 0, 0);
  ctx.restore();

  const stem = exportBaseStem(target?.label || target?.path || normalizedImageId);
  const requestKey = String(requestId || Date.now()).replace(/[^a-z0-9._:-]+/gi, "_");
  const outputPath = `${state.runDir}/cut-out-hint-${stem}-${requestKey}.png`;
  await writeCanvasPngToPath(canvas, outputPath);
  return {
    imageId: `${normalizedImageId}:cut_out_hint`,
    path: outputPath,
    label: "Cut Out Hint",
    width,
    height,
  };
}

function buildSingleImageRailSubjectIsolationApplyPayload({ route, imageId, target, selection, hintImage = null } = {}) {
  const requestId = `single-image-cut-out-${Date.now()}`;
  const proposalId = `${requestId}-proposal`;
  const outputStem = exportBaseStem(target?.label || target?.path || imageId || "cut-out");
  const outputPath = `${state.runDir}/review-apply-${outputStem}-${proposalId}.png`;
  const targetImage = {
    id: String(imageId || "").trim() || null,
    imageId: String(imageId || "").trim() || null,
    path: String(target?.path || "").trim() || null,
    label: String(target?.label || basename(target?.path || "") || "Image").trim() || "Image",
    width: Number(target?.img?.naturalWidth || target?.width) || null,
    height: Number(target?.img?.naturalHeight || target?.height) || null,
  };
  const targetRegion = singleImageRailSubjectIsolationTargetRegion(selection);
  const visibleImages = [targetImage];
  if (hintImage?.path) {
    visibleImages.push({
      id: String(hintImage.imageId || "").trim() || null,
      imageId: String(hintImage.imageId || "").trim() || null,
      path: String(hintImage.path || "").trim() || null,
      label: String(hintImage.label || "Cut Out Hint").trim() || "Cut Out Hint",
      width: Number(hintImage.width) || null,
      height: Number(hintImage.height) || null,
    });
  }
  const request = {
    requestId,
    sessionId: currentDesignReviewApplySessionKey() || `single_image:${String(imageId || "").trim()}`,
    primaryImageId: String(imageId || "").trim() || null,
    imageIdsInView: [String(imageId || "").trim()].filter(Boolean),
    selectedImageIds: [String(imageId || "").trim()].filter(Boolean),
    markIds: [],
    activeRegionCandidateId: String(selection?.regionCandidateId || "").trim() || null,
    selectionState: "region",
    visibleCanvasContext: {
      runDir: state.runDir || null,
      canvasMode: "single",
      imageCount: 1,
      activeImageId: String(imageId || "").trim() || null,
      images: visibleImages,
    },
    chosenRegionCandidate: selection?.chosenRegionCandidate || null,
  };
  const proposal = {
    proposalId,
    imageId: String(imageId || "").trim() || null,
    label: String(route?.label || "Cut Out").trim() || "Cut Out",
    actionType: "cut_out_subject",
    applyBrief:
      "Cut out only the selected subject. Remove everything outside the selected subject and return a transparent background PNG. " +
      "Preserve the subject's exact identity, pose, silhouette, clothing, logos, and readable text. " +
      "Do not add a new background, halo, shadow, padding, extra objects, or extra people.",
    targetRegion,
    referenceImageIds: hintImage?.imageId ? [String(hintImage.imageId)] : [],
    negativeConstraints: [
      "no background fill",
      "no drop shadow",
      "no glow or halo",
      "no extra objects",
      "no extra people",
      "preserve subject details exactly",
    ],
  };
  return {
    request,
    proposal,
    outputPath,
    targetImage,
    referenceImages: hintImage?.path ? [hintImage] : [],
    referenceImageIds: hintImage?.imageId ? [String(hintImage.imageId)] : [],
  };
}

async function executeSingleImageRailSubjectIsolation({ route, imageId, target }) {
  const targetId = String(imageId || "").trim();
  const selection = resolveSingleImageRailSubjectSelection(targetId);
  if (!selection) {
    const error = new Error("Cut Out needs a lasso or Magic Select region first.");
    error.disabledReason = "selection_required";
    throw error;
  }

  await ensureSingleImageRailTargetLoaded(target);
  await readSingleImageRailApplyKeyStatus();

  const label = String(route?.label || "Cut Out").trim() || "Cut Out";
  beginRunningAction("cut_out");
  setImageFxActive(true, label);
  portraitWorking(label, { providerOverride: "gemini" });
  setStatus(`Engine: ${label.toLowerCase()}…`);

  const targetSnapshot = {
    id: targetId,
    path: String(target?.path || ""),
    receiptPath: target?.receiptPath ? String(target.receiptPath) : null,
    kind: target?.kind ? String(target.kind) : null,
    source: target?.source ? String(target.source) : null,
    label: target?.label ? String(target.label) : basename(target?.path || ""),
    timelineNodeId: target?.timelineNodeId ? String(target.timelineNodeId) : null,
  };

  try {
    const hintImage = await writeSingleImageRailSubjectIsolationHintImage({
      imageId: targetId,
      target,
      selection,
      requestId: Date.now().toString(36),
    }).catch(() => null);
    const applyPayload = buildSingleImageRailSubjectIsolationApplyPayload({
      route,
      imageId: targetId,
      target,
      selection,
      hintImage,
    });
    const providerRouter = createSingleImageRailApplyProviderRouter();
    const result = await providerRouter.runApply({
      request: applyPayload.request,
      proposal: applyPayload.proposal,
      targetImage: applyPayload.targetImage,
      referenceImages: applyPayload.referenceImages,
      outputPath: applyPayload.outputPath,
      model: SINGLE_IMAGE_RAIL_SUBJECT_ISOLATION_MODEL,
    });

    const outputPath = readFirstString(result?.outputPath, applyPayload.outputPath);
    if (!outputPath) {
      throw new Error("Cut Out did not produce an output image.");
    }

    const receiptPath = await writeDesignReviewApplyReceipt({
      outputPath,
      targetBefore: targetSnapshot,
      targetImageId: targetId,
      referenceImageIds: applyPayload.referenceImageIds,
      proposal: applyPayload.proposal,
      request: applyPayload.request,
      debugInfo: result?.debugInfo || null,
      provider: result?.provider || null,
      requestedModel: result?.requestedModel || SINGLE_IMAGE_RAIL_SUBJECT_ISOLATION_MODEL,
      normalizedModel: result?.normalizedModel || null,
      costTotalUsd: readFirstNumber(result?.costTotalUsd, result?.cost_total_usd),
      latencyPerImageS: readFirstNumber(result?.latencyPerImageS, result?.latency_per_image_s),
    }).catch((error) => {
      console.error("Failed to write cut-out receipt:", error);
      return null;
    });

    const ok = await replaceImageInPlace(targetId, {
      path: outputPath,
      receiptPath,
      kind: "engine",
      label: targetSnapshot.label || basename(outputPath),
    }).catch((error) => {
      console.error(error);
      return false;
    });
    if (!ok) {
      if (receiptPath) removeFile(receiptPath).catch(() => {});
      throw new Error("Cut Out failed to replace the active image.");
    }

    const nodeId = recordTimelineNode({
      imageId: targetId,
      path: outputPath,
      receiptPath,
      label: targetSnapshot.label || basename(outputPath),
      action: label,
      kind: "image_result",
      visualMode: "thumbnail",
      parents: targetSnapshot.timelineNodeId ? [targetSnapshot.timelineNodeId] : [],
      previewImageId: targetId,
      previewPath: outputPath,
      receiptPaths: receiptPath ? [receiptPath] : [],
    });
    const item = state.imagesById.get(targetId) || null;
    if (item) {
      item.source = DESIGN_REVIEW_APPLY_SOURCE;
      if (nodeId) item.timelineNodeId = nodeId;
    }

    dropCommunicationStateForImageId(targetId);
    if (String(state.activeId || "").trim() === targetId) {
      clearSelection();
    }
    updateDesignReviewApplyCostLatency({
      provider: result?.provider || null,
      requestedModel: result?.requestedModel || SINGLE_IMAGE_RAIL_SUBJECT_ISOLATION_MODEL,
      normalizedModel: result?.normalizedModel || null,
      costTotalUsd: readFirstNumber(result?.costTotalUsd, result?.cost_total_usd),
      latencyPerImageS: readFirstNumber(result?.latencyPerImageS, result?.latency_per_image_s),
    });
    if (receiptPath) {
      ingestTopMetricsFromReceiptPath(receiptPath, {
        allowCostFallback: true,
        allowLatencyFallback: true,
      }).catch(() => {});
    }
    setStatus("Engine: ready");
    return {
      imageId: targetId,
      outputPath: String(item?.path || outputPath),
      receiptPath,
      provider: result?.provider || null,
      requestedModel: result?.requestedModel || SINGLE_IMAGE_RAIL_SUBJECT_ISOLATION_MODEL,
      normalizedModel: result?.normalizedModel || null,
      costTotalUsd: readFirstNumber(result?.costTotalUsd, result?.cost_total_usd),
      latencyPerImageS: readFirstNumber(result?.latencyPerImageS, result?.latency_per_image_s),
    };
  } finally {
    setImageFxActive(false);
    updatePortraitIdle();
    clearRunningAction("cut_out");
  }
}

async function executeSingleImageRailCapability({ route, imageId, target }) {
  const snapshot = captureSingleImageRailArtifactSnapshot(imageId);
  if (route?.capability === "crop_or_outpaint" || route?.capability === "subject_isolation") {
    await ensureSingleImageRailTargetLoaded(target);
  }

  let runner = null;
  if (route?.capability === "subject_isolation") {
    runner = () => executeSingleImageRailSubjectIsolation({ route, imageId, target });
  } else if (route?.capability === "targeted_remove") {
    runner = () => aiRemovePeople();
  } else if (route?.capability === "background_replace") {
    runner = () => applyBackground("white");
  } else if (route?.capability === "crop_or_outpaint") {
    runner = () => cropSquare();
  } else if (route?.capability === "identity_preserving_variation") {
    runner = () => runVariations();
  }

  if (typeof runner !== "function") {
    throw new Error("Capability executor is unavailable.");
  }

  const artifact = await runner();
  if (artifact?.outputPath || artifact?.imagePath) {
    return artifact;
  }
  return waitForSingleImageRailArtifact(route, snapshot);
}

function installBuiltInSingleImageRailIntegration() {
  if (typeof window === "undefined") return;
  const bridge = window.__JUGGERNAUT_SHELL__;
  if (!bridge || typeof bridge !== "object") return;

  if (typeof bridge.registerSingleImageRailRanker === "function") {
    bridge.registerSingleImageRailRanker((shellContext = {}) =>
      rankSingleImageIntentJobs(buildSingleImageRailIntentInput(shellContext)).rankedJobs
    );
  }

  if (typeof bridge.registerToolInvoker === "function") {
    bridge.registerToolInvoker(async (request = {}) => {
      const toolKey = String(request?.toolKey || request?.jobId || request?.toolId || "").trim();
      const railJob = singleImageRailJobMeta(toolKey);
      if (!railJob?.capability) return null;

      const runtimeContext = buildSingleImageRailRuntimeContext();
      const invocation = buildSingleImageRailInvocation(railJob, {
        activeImageId: request?.selectedImageId || runtimeContext.activeImageId,
        selectedImageIds: Array.isArray(request?.selectedImageIds)
          ? request.selectedImageIds.slice(0, 3)
          : runtimeContext.selectedImageIds,
        subjectSelectionAvailable:
          request?.subjectSelectionAvailable == null
            ? runtimeContext.subjectSelectionAvailable
            : Boolean(request.subjectSelectionAvailable),
        source: String(request?.source || "shell").trim() || "shell",
        trigger: "click",
        requestId: `single-image-rail-${state.toolInvocationSeq++}`,
        confidence: railJob?.confidence || 0,
        reasonCodes: Array.isArray(railJob?.reasonCodes) ? railJob.reasonCodes : [],
        busy: runtimeContext.busy,
        mode: runtimeContext.mode,
        image: runtimeContext.image,
        capabilityAvailability: runtimeContext.capabilityAvailability,
        capabilityExecutorAvailable: true,
      });
      const result = await applyToolRuntimeEdit(invocation);
      if (!result?.ok && result?.error) {
        showToast(result.error, "error", 3200);
      }
      return Boolean(result?.ok);
    });
  }
}

function exposeJuggernautShellHooks() {
  if (typeof window === "undefined") return;
  window.applyJuggernautTool = applyJuggernautTool;
  window.exportJuggernautPsd = exportJuggernautPsd;
  window.__juggernautShell = {
    state: state.juggernautShell,
    applyJuggernautTool,
    exportJuggernautPsd,
  };
  if (window.__JUGGERNAUT_SHELL__ && typeof window.__JUGGERNAUT_SHELL__ === "object") {
    window.__JUGGERNAUT_SHELL__.applyJuggernautTool = applyJuggernautTool;
    window.__JUGGERNAUT_SHELL__.exportJuggernautPsd = exportJuggernautPsd;
  }
}

