function actionGridReelIconOverrideFor(key) {
  const k = String(key || "").trim();
  if (!k) return "";
  if (k === "pan") {
    // iOS-style gesture icon for reel mode: finger + touch ring.
    return `<svg class="tool-icon tool-icon-ios-pan" viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="17.5" cy="6.5" r="2.2" fill="none" stroke="currentColor" stroke-width="1.8" />
      <path d="M12 19v-8.4a1.6 1.6 0 0 1 3.2 0V14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
      <path d="M12 14l-1.6-1.5a1.5 1.5 0 0 0-2.2 2l2.5 2.8A4.7 4.7 0 0 0 14.3 19H16a4 4 0 0 0 4-4v-2.2a1.5 1.5 0 0 0-3 0V14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" />
    </svg>`;
  }
  return "";
}

function customToolDockTitleFor(tool) {
  if (!tool || typeof tool !== "object") return "Custom tool";
  const label = String(tool.label || tool.shortLabel || tool.toolId || "Custom tool").trim();
  const execution = `${tool.execution?.kind || "local_edit"}:${tool.execution?.operation || "unknown"}`;
  const provenance = resolveActionProvenance({
    provenance: tool.provenance,
    executionKind: tool.execution?.kind,
  });
  return appendActionProvenanceDescription(`${label} (${execution})`, provenance);
}

function customToolProvenance(tool) {
  return resolveActionProvenance({
    provenance: tool?.provenance,
    executionKind: tool?.execution?.kind,
  });
}

function customToolDockIconFor(tool) {
  const glyph = String(tool?.display?.glyph || "").trim();
  if (glyph === "mono") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="12" cy="12" r="7" fill="none" stroke="currentColor" stroke-width="2" />
      <path d="M12 5a7 7 0 0 1 0 14" fill="none" stroke="currentColor" stroke-width="2" />
    </svg>`;
  }
  if (glyph === "sepia") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <path d="M7 6h10v12H7z" fill="none" stroke="currentColor" stroke-width="2" />
      <path d="M9 9h6M9 12h6M9 15h4" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
    </svg>`;
  }
  if (glyph === "invert") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 4l7 12H5z" fill="none" stroke="currentColor" stroke-width="2" stroke-linejoin="round" />
      <path d="M12 4v12" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
    </svg>`;
  }
  if (glyph === "blur") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="9" cy="12" r="3" fill="none" stroke="currentColor" stroke-width="2" />
      <path d="M15 9.5h3M15 12h4M15 14.5h3" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
    </svg>`;
  }
  if (glyph === "brightness") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="12" cy="12" r="4" fill="none" stroke="currentColor" stroke-width="2" />
      <path d="M12 3v3M12 18v3M3 12h3M18 12h3M5.6 5.6l2.1 2.1M16.3 16.3l2.1 2.1M5.6 18.4l2.1-2.1M16.3 7.7l2.1-2.1" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
    </svg>`;
  }
  if (glyph === "shadow") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 4a7 7 0 1 0 0 14 6 6 0 0 1 0-14z" fill="none" stroke="currentColor" stroke-width="2" />
    </svg>`;
  }
  if (glyph === "contrast") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <circle cx="12" cy="12" r="7" fill="none" stroke="currentColor" stroke-width="2" />
      <path d="M12 5a7 7 0 0 0 0 14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
    </svg>`;
  }
  if (glyph === "saturation") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 4l5 6-5 10-5-10z" fill="none" stroke="currentColor" stroke-width="2" stroke-linejoin="round" />
      <path d="M9 10h6" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
    </svg>`;
  }
  if (glyph === "muted") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 4l5 6-5 10-5-10z" fill="none" stroke="currentColor" stroke-width="2" stroke-linejoin="round" />
      <path d="M7 7l10 10" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
    </svg>`;
  }
  if (glyph === "mirror") {
    return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 5v14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
      <path d="M10 8L6 12l4 4M14 8l4 4-4 4" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" />
    </svg>`;
  }
  return `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
    <path d="M12 4l2.2 4.8L19 10l-3.5 3 1.1 4.8-4.6-2.7-4.6 2.7L8.5 13 5 10l4.8-1.2z" fill="none" stroke="currentColor" stroke-width="2" stroke-linejoin="round" />
  </svg>`;
}

function customToolCreateIcon() {
  return (
    getJuggernautRailIconMarkup("create_tool", settings.railIconPack) ||
    `<svg class="tool-icon" viewBox="0 0 24 24" aria-hidden="true">
      <path d="M12 5v14M5 12h14" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" />
      <path d="M17.5 5.5l1 2.3 2.3 1-2.3 1-1 2.3-1-2.3-2.3-1 2.3-1z" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linejoin="round" />
    </svg>`
  );
}

function customToolDockRenderSignature(tools = []) {
  const panelOpen = Boolean(els.createToolPanel && !els.createToolPanel.classList.contains("hidden"));
  return [
    state.customToolDockVersion,
    panelOpen ? 1 : 0,
    state.activeCustomToolId || "",
    tools.map((tool) => `${tool?.toolId || ""}:${tool?.label || ""}:${tool?.shortLabel || ""}:${customToolProvenance(tool)}`).join("|"),
  ].join("||");
}

function renderCustomToolDock() {
  const root = els.customToolDock;
  const tools = sessionToolRegistry.visible({ limit: 3 });
  if (!root) return false;
  const nextKey = customToolDockRenderSignature(tools);
  if (state.lastRenderedCustomToolDockKey === nextKey) return false;
  state.lastRenderedCustomToolDockKey = nextKey;
  root.innerHTML = "";

  const createBtn = document.createElement("button");
  createBtn.type = "button";
  createBtn.className = "tool tool-create";
  createBtn.dataset.provenance = ACTION_PROVENANCE.LOCAL_ONLY;
  createBtn.classList.toggle("has-action-provenance", actionProvenanceHasModelCost(ACTION_PROVENANCE.LOCAL_ONLY));
  createBtn.title = appendActionProvenanceDescription("Create Tool", ACTION_PROVENANCE.LOCAL_ONLY);
  createBtn.setAttribute("aria-label", appendActionProvenanceDescription("Create Tool", ACTION_PROVENANCE.LOCAL_ONLY));
  createBtn.innerHTML = `${customToolCreateIcon()}${renderActionProvenanceBadge(ACTION_PROVENANCE.LOCAL_ONLY)}`;
  if (els.createToolPanel && !els.createToolPanel.classList.contains("hidden")) {
    createBtn.classList.add("selected");
    createBtn.classList.add("depressed");
  }
  createBtn.addEventListener("click", () => {
    bumpInteraction();
    showCreateToolPanel();
  });
  root.appendChild(createBtn);

  for (const tool of tools) {
    const provenance = customToolProvenance(tool);
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "tool";
    btn.dataset.toolId = String(tool.toolId || "");
    btn.dataset.provenance = provenance;
    btn.classList.toggle("has-action-provenance", actionProvenanceHasModelCost(provenance));
    btn.title = customToolDockTitleFor(tool);
    btn.setAttribute(
      "aria-label",
      appendActionProvenanceDescription(String(tool.label || tool.shortLabel || tool.toolId || "Custom tool"), provenance)
    );
    btn.innerHTML = `${customToolDockIconFor(tool)}${renderActionProvenanceBadge(provenance)}`;
    if (state.activeCustomToolId === tool.toolId) {
      btn.classList.add("selected");
    }
    btn.addEventListener("click", () => {
      bumpInteraction();
      runWithUserError(String(tool.label || "Custom tool"), () => invokeRegisteredTool(tool.toolId), {
        retryHint: "Select one image and retry.",
      });
    });
    root.appendChild(btn);
  }
  return true;
}

function renderActionGrid() {
  const root = els.actionGrid;
  if (!root) return;
  const hasImage = Boolean(getActiveImage());
  const rerank = !singleImageRailManipulationActive();
  const railContext = {
    hasImage,
    hasRegionSelection: singleImageRailRegionSelectionActive(),
    busy: singleImageRailBusy(),
    toolHookReady: typeof state.juggernautShell.toolInvoker === "function",
    context: buildJuggernautShellContext(),
  };
  const rankResult = rerank
    ? resolveSingleImageRailRankedJobs(railContext)
    : {
        adapter: state.juggernautShell.singleImageRail.adapter || { ...SINGLE_IMAGE_RAIL_MOCK_ADAPTER },
        rankedJobs: state.juggernautShell.singleImageRail.rankedJobs,
        mock: Boolean(state.juggernautShell.singleImageRail.mock),
      };
  const runtimeRankedJobs = rankResult.mock
    ? rankResult.rankedJobs
    : buildSingleImageRailJobEntries(rankResult.rankedJobs, buildSingleImageRailRuntimeContext());
  const railState = buildSingleImageRailButtons({
    hasImage,
    hasRegionSelection: railContext.hasRegionSelection,
    activeToolId: juggernautActiveToolId(),
    runningToolId: juggernautRunningToolId(),
    toolHookReady: railContext.toolHookReady,
    busy: railContext.busy,
    rankedJobs: runtimeRankedJobs,
    previousVisibleJobs: state.juggernautShell.singleImageRail.visibleJobs,
    rerank,
    adapter: rankResult.adapter,
  });
  state.juggernautShell.singleImageRail.contract = railState.contractName;
  state.juggernautShell.singleImageRail.adapter = { ...railState.adapter };
  state.juggernautShell.singleImageRail.rankedJobs = railState.rankedJobs.map((job) => ({ ...job }));
  state.juggernautShell.singleImageRail.visibleJobs = railState.visibleDynamicJobs.map((job) => ({ ...job }));
  state.juggernautShell.singleImageRail.mock = Boolean(rankResult.mock);
  state.juggernautShell.visibleToolIds = railState.buttons.map((button) => button.toolId);
  cacheNativeShortcutSlots(railState.buttons);
  renderJuggernautRail(root, {
    buttons: railState.buttons,
    onPress: (button) => {
      bumpInteraction();
      recordUserEvent("action_grid_press", {
        key: button.actionKey || button.toolId || null,
        tool_id: button.toolId || null,
        kind: "juggernaut_shell",
        active_id: state.activeId || null,
        selected_ids: getSelectedIds().slice(0, 3),
      });
      applyJuggernautTool(button.toolId).catch((err) => {
        console.error("Cue tool failed:", err);
      });
    },
  });
  syncJuggernautShellState();
}

function quickActionsRenderSignature() {
  return [
    state.quickActionsVersion,
    state.spawnNodesVersion,
    state.canvasMode || "multi",
    juggernautActiveToolId(),
    state.activeId || "",
    getSelectedIds().join(","),
    Array.isArray(state.images) ? state.images.length : 0,
    Array.isArray(state.sessionTools) ? state.sessionTools.length : 0,
    Array.isArray(state.spawnNodes) ? state.spawnNodes.map((node) => `${node?.id || ""}:${node?.title || ""}`).join("|") : "",
    state.runningActionKey || "",
    state.actionQueue.length,
    state.actionQueueActive?.key || "",
    state.activeCustomToolId || "",
    Boolean(state.expectingArtifacts) ? 1 : 0,
    Boolean(state.juggernautShell?.toolInvoker) ? 1 : 0,
    Boolean(state.juggernautShell?.psdExportHandler) ? 1 : 0,
    Boolean(state.juggernautShell?.singleImageRail?.ranker) ? 1 : 0,
    String(state.juggernautShell?.lastToolKey || ""),
  ].join("||");
}

function renderQuickActions() {
  const nextKey = quickActionsRenderSignature();
  if (state.lastRenderedQuickActionsKey === nextKey) return false;
  state.lastRenderedQuickActionsKey = nextKey;
  renderActionGrid();
  renderJuggernautShellChrome();
  renderCustomToolDock();
  renderAgentRunnerPanel();
  return true;
}

async function handleSpawnNode(node) {
  if (!node) return;
  if (node.action === "blend_pair") {
    await runBlendPair();
    return;
  }
  if (node.action === "bg_white") {
    await applyBackground("white");
    return;
  }
  if (node.action === "bg_sweep") {
    await applyBackground("sweep");
    return;
  }
  if (node.action === "crop_square") {
    await cropSquare();
    return;
  }
  if (node.action === "variations") {
    await runVariations();
    return;
  }
}

function filmstripDataSignature() {
  if (!state.filmstripVisible || state.canvasMode === "multi") return "hidden";
  return [
    state.filmstripVersion,
    Array.isArray(state.images) ? state.images.length : 0,
    (state.images || [])
      .map((item) => `${item?.id || ""}:${item?.label || basename(item?.path || "")}:${item?.path || ""}`)
      .join("|"),
  ].join("||");
}

function filmstripSelectionSignature() {
  return [state.activeId || "", getSelectedIds().join(",")].join("||");
}

function syncFilmstripRenderSignature() {
  state.lastRenderedFilmstripKey = filmstripDataSignature();
  state.lastRenderedFilmstripSelectionKey = filmstripSelectionSignature();
  state.lastRenderedFilmstripActiveId = state.activeId || null;
}

function renderFilmstrip() {
  if (!els.filmstrip) return false;
  const nextDataKey = filmstripDataSignature();
  const nextSelectionKey = filmstripSelectionSignature();
  if (!state.filmstripVisible || state.canvasMode === "multi") {
    if (
      state.lastRenderedFilmstripKey === nextDataKey &&
      state.lastRenderedFilmstripSelectionKey === nextSelectionKey
    ) {
      return false;
    }
    els.filmstrip.classList.add("hidden");
    // Avoid accumulating observed nodes when we teardown/rebuild the filmstrip.
    if (thumbObserver) {
      try {
        thumbObserver.disconnect();
      } catch {
        // ignore
      }
    }
    state.thumbsById.clear();
    els.filmstrip.innerHTML = "";
    syncFilmstripRenderSignature();
    return true;
  }
  if (state.lastRenderedFilmstripKey === nextDataKey) {
    if (state.lastRenderedFilmstripSelectionKey !== nextSelectionKey) {
      setFilmstripSelected(state.lastRenderedFilmstripActiveId, state.activeId);
      state.lastRenderedFilmstripSelectionKey = nextSelectionKey;
      state.lastRenderedFilmstripActiveId = state.activeId || null;
      return true;
    }
    return false;
  }
  const perfSample = startPerfSample("tab:filmstrip-refresh", {
    runDir: state.runDir || null,
    imageCount: Array.isArray(state.images) ? state.images.length : 0,
  });
  els.filmstrip.classList.remove("hidden");
  ensureThumbObserver();
  // Avoid accumulating observed nodes when we teardown/rebuild the filmstrip.
  if (thumbObserver) {
    try {
      thumbObserver.disconnect();
    } catch {
      // ignore
    }
  }
  state.thumbsById.clear();
  els.filmstrip.innerHTML = "";
  const frag = document.createDocumentFragment();
  for (const item of state.images) {
    const div = document.createElement("div");
    div.className = "thumb" + (item.id === state.activeId ? " selected" : "");
    div.dataset.id = item.id;
    const img = document.createElement("img");
    img.alt = item.label || basename(item.path) || "Artifact";
    img.loading = "lazy";
    img.decoding = "async";
    img.dataset.path = item.path;
    // Give it something valid to avoid broken-image glyphs before we swap in a blob URL.
    img.src = THUMB_PLACEHOLDER_SRC;
    if (thumbObserver) {
      thumbObserver.observe(img);
    } else {
      ensureImageUrl(item.path)
        .then((url) => {
          if (url) img.src = url;
        })
        .catch(() => {});
    }
    div.appendChild(img);
    const label = document.createElement("div");
    label.className = "thumb-label";
    label.textContent = item.label || basename(item.path);
    div.appendChild(label);
    state.thumbsById.set(item.id, { rootEl: div, imgEl: img, labelEl: label });
    frag.appendChild(div);
  }
  els.filmstrip.appendChild(frag);
  syncFilmstripRenderSignature();
  finishPerfSample(perfSample, "filmstripRefreshMs", {
    rebuilt: true,
    imageCount: Array.isArray(state.images) ? state.images.length : 0,
  });
  return true;
}

function appendFilmstripThumb(item) {
  if (!els.filmstrip || !item?.id || !item?.path) return;
  if (!state.filmstripVisible) return;
  if (state.canvasMode === "multi") return;
  if (state.thumbsById.has(item.id)) return;
  ensureThumbObserver();
  const div = document.createElement("div");
  div.className = "thumb" + (item.id === state.activeId ? " selected" : "");
  div.dataset.id = item.id;
  const img = document.createElement("img");
  img.alt = item.label || basename(item.path) || "Artifact";
  img.loading = "lazy";
  img.decoding = "async";
  img.dataset.path = item.path;
  img.src = THUMB_PLACEHOLDER_SRC;
  if (thumbObserver) {
    thumbObserver.observe(img);
  } else {
    ensureImageUrl(item.path)
      .then((url) => {
        if (url) img.src = url;
      })
      .catch(() => {});
  }
  div.appendChild(img);
  const label = document.createElement("div");
  label.className = "thumb-label";
  label.textContent = item.label || basename(item.path);
  div.appendChild(label);
  state.thumbsById.set(item.id, { rootEl: div, imgEl: img, labelEl: label });
  els.filmstrip.appendChild(div);
  syncFilmstripRenderSignature();
}

function setFilmstripSelected(prevId, nextId) {
  if (prevId && prevId !== nextId) {
    const prev = state.thumbsById.get(prevId);
    if (prev?.rootEl) prev.rootEl.classList.remove("selected");
  }
  const next = state.thumbsById.get(nextId);
  if (next?.rootEl) next.rootEl.classList.add("selected");
}

function updateFilmstripThumb(item) {
  if (!item?.id) return;
  const rec = state.thumbsById.get(item.id);
  if (!rec) return;
  if (rec.labelEl) rec.labelEl.textContent = item.label || basename(item.path);
  if (rec.imgEl && item.path) {
    rec.imgEl.alt = item.label || basename(item.path) || "Artifact";
    rec.imgEl.dataset.path = item.path;
    rec.imgEl.src = THUMB_PLACEHOLDER_SRC;
    if (thumbObserver) {
      thumbObserver.observe(rec.imgEl);
    } else {
      ensureImageUrl(item.path)
        .then((url) => {
          if (url) rec.imgEl.src = url;
        })
        .catch(() => {});
    }
  }
  syncFilmstripRenderSignature();
}

function timelineSortedNodes(nodes = state.timelineNodes) {
  return Array.from(Array.isArray(nodes) ? nodes : []).sort((a, b) => {
    const aSeq = Math.max(0, Number(a?.seq) || 0);
    const bSeq = Math.max(0, Number(b?.seq) || 0);
    if (aSeq !== bSeq) return aSeq - bSeq;
    return Math.max(0, Number(a?.createdAt) || 0) - Math.max(0, Number(b?.createdAt) || 0);
  });
}

function currentTimelineHeadNode() {
  const headNodeId = String(state.timelineHeadNodeId || "").trim();
  if (headNodeId && state.timelineNodesById instanceof Map && state.timelineNodesById.has(headNodeId)) {
    return state.timelineNodesById.get(headNodeId) || null;
  }
  const nodes = timelineSortedNodes();
  return nodes[nodes.length - 1] || null;
}

function _timelineMakeNodeId(seq = 1) {
  return `tl-${String(Math.max(1, Number(seq) || 1)).padStart(6, "0")}`;
}

function timelineActionKey(action = null, kind = null) {
  const normalized = String(action || "").trim().toLowerCase();
  if (normalized.includes("highlight") || normalized.includes("protect")) return "highlight";
  if (normalized.includes("magic")) return "magic";
  if (normalized.includes("erase region")) return "erase";
  if (normalized.includes("erase mark")) return "erase";
  if (normalized.includes("delete")) return "delete";
  if (normalized.includes("annotate")) return "annotate";
  if (normalized.includes("circle")) return "circle";
  if (normalized.includes("resize")) return "resize";
  if (normalized.includes("rotate")) return "rotate";
  if (normalized.includes("skew")) return "skew";
  if (normalized.includes("move")) return "move";
  if (normalized.includes("mark")) return "mark";
  if (normalized.includes("import") || normalized.includes("upload") || normalized.includes("add image")) return "import";
  if (
    normalized.includes("generate") ||
    normalized.includes("recast") ||
    normalized.includes("variation") ||
    normalized.includes("review") ||
    normalized.includes("bridge") ||
    normalized.includes("combine") ||
    normalized.includes("swap dna") ||
    normalized.includes("subject isolation") ||
    normalized.includes("cut out")
  ) {
    return "result";
  }
  if (kind === "image_result") return "result";
  if (kind === "transform") return "move";
  if (kind === "annotation") return "mark";
  if (kind === "delete") return "delete";
  return "state";
}

function timelineKindForAction(actionKey = "state", explicitKind = null) {
  if (explicitKind) return String(explicitKind);
  if (actionKey === "import" || actionKey === "result") return "image_result";
  if (actionKey === "move" || actionKey === "resize" || actionKey === "rotate" || actionKey === "skew") {
    return "transform";
  }
  if (actionKey === "delete") return "delete";
  if (actionKey === "mark" || actionKey === "highlight" || actionKey === "magic" || actionKey === "erase" || actionKey === "annotate" || actionKey === "circle") {
    return "annotation";
  }
  return "state";
}

function timelineVisualModeForAction(actionKey = "state", explicitVisualMode = null) {
  if (explicitVisualMode) return String(explicitVisualMode);
  return actionKey === "import" || actionKey === "result" ? "thumbnail" : "icon";
}

function timelineImagesByIdForSession(session = null) {
  return session?.imagesById instanceof Map ? session.imagesById : new Map();
}

function timelinePreviewPathForSession(session = null, { path = null, previewPath = null, previewImageId = null, imageId = null } = {}) {
  const directPreviewPath = String(previewPath || "").trim();
  if (directPreviewPath) return directPreviewPath;
  const directPath = String(path || "").trim();
  if (directPath) return directPath;
  const imagesById = timelineImagesByIdForSession(session);
  const previewId = String(previewImageId || imageId || session?.activeId || "").trim();
  if (previewId && imagesById.has(previewId)) {
    const item = imagesById.get(previewId) || null;
    const itemPath = String(item?.path || "").trim();
    if (itemPath) return itemPath;
  }
  const images = Array.isArray(session?.images) ? session.images : [];
  for (const item of images) {
    const itemPath = String(item?.path || "").trim();
    if (itemPath) return itemPath;
  }
  return null;
}

function timelineImageIdsForSession(session = null) {
  return uniqueStringList(
    (Array.isArray(session?.images) ? session.images : []).map((item) => String(item?.id || "").trim())
  );
}

function buildTimelineNodeForSession(
  session = null,
  {
    imageId = null,
    path = null,
    receiptPath = null,
    label = null,
    action = null,
    kind = null,
    detail = null,
    visualMode = null,
    parents = null,
    previewImageId = null,
    previewPath = null,
    receiptPaths = null,
  } = {}
) {
  const nextSeq = Math.max(1, Number(session?.timelineNextSeq) || 1);
  const actionKey = timelineActionKey(action, kind);
  const resolvedKind = timelineKindForAction(actionKey, kind);
  const resolvedPreviewImageId = String(previewImageId || imageId || session?.activeId || "").trim() || null;
  const resolvedPreviewPath = timelinePreviewPathForSession(session, {
    path,
    previewPath,
    previewImageId: resolvedPreviewImageId,
    imageId,
  });
  const resolvedParents = uniqueStringList(
    Array.isArray(parents) ? parents : session?.timelineHeadNodeId ? [session.timelineHeadNodeId] : []
  );
  const resolvedLabel =
    String(label || "").trim() ||
    (resolvedPreviewPath ? basename(resolvedPreviewPath) : "") ||
    (action ? String(action) : "") ||
    "State";
  return {
    nodeId: _timelineMakeNodeId(nextSeq),
    seq: nextSeq,
    createdAt: Date.now(),
    kind: resolvedKind,
    action: action ? String(action) : null,
    visualMode: timelineVisualModeForAction(actionKey, visualMode),
    label: resolvedLabel,
    detail: detail ? String(detail) : null,
    parents: resolvedParents,
    imageIds: timelineImageIdsForSession(session),
    previewImageId: resolvedPreviewImageId,
    previewPath: resolvedPreviewPath,
    receiptPaths: uniqueStringList([receiptPath, ...(Array.isArray(receiptPaths) ? receiptPaths : [])]),
    snapshot: captureSessionTimelineSnapshot(session),
  };
}

function applyTimelineNodeToSession(session = null, node = null, imageId = null) {
  const current = session && typeof session === "object" ? session : null;
  if (!current || !node?.nodeId) return null;
  if (!Array.isArray(current.timelineNodes)) current.timelineNodes = [];
  if (!(current.timelineNodesById instanceof Map)) current.timelineNodesById = new Map();
  current.timelineNodes.push(node);
  current.timelineNodesById.set(node.nodeId, node);
  current.timelineHeadNodeId = node.nodeId;
  current.timelineLatestNodeId = node.nodeId;
  current.timelineNextSeq = Math.max(1, Number(node.seq) || 1) + 1;
  current.timelineOpen = true;
  const normalizedImageId = String(imageId || "").trim();
  if (normalizedImageId && current.imagesById?.has?.(normalizedImageId)) {
    const item = current.imagesById.get(normalizedImageId) || null;
    if (item) item.timelineNodeId = node.nodeId;
  }
  return node.nodeId;
}

function recordTimelineNode({
  imageId = null,
  path = null,
  receiptPath = null,
  label = null,
  action = null,
  kind = null,
  detail = null,
  visualMode = null,
  parents = null,
  previewImageId = null,
  previewPath = null,
  receiptPaths = null,
} = {}) {
  const node = buildTimelineNodeForSession(state, {
    imageId,
    path,
    receiptPath,
    label,
    action,
    kind,
    detail,
    visualMode,
    parents,
    previewImageId,
    previewPath,
    receiptPaths,
  });
  const nodeId = applyTimelineNodeToSession(state, node, imageId);
  if (!nodeId) return null;
  markActiveTabUiDirty({ timeline: true, quickActions: true, publishTabs: true });
  syncActiveTabRecord({ capture: true, publish: true });
  persistActiveSessionTimeline();
  renderTimeline();
  return nodeId;
}

function ensureTimelineNodeForImageItem(item) {
  if (!item || !item.id || !item.path) return null;
  if (item.timelineNodeId && state.timelineNodesById.has(item.timelineNodeId)) return item.timelineNodeId;
  const action = item.timelineAction || item.kind || "Import";
  const parents = Array.isArray(item.timelineParents) ? item.timelineParents : null;
  const nodeId = recordTimelineNode({
    imageId: item.id,
    path: item.path,
    receiptPath: item.receiptPath || null,
    label: item.label || null,
    action,
    kind: "image_result",
    visualMode: "thumbnail",
    parents,
    previewImageId: item.id,
    previewPath: item.path,
    receiptPaths: item.receiptPath ? [item.receiptPath] : [],
  });
  item.timelineNodeId = nodeId;
  if ("timelineAction" in item) delete item.timelineAction;
  if ("timelineParents" in item) delete item.timelineParents;
  return nodeId;
}

function openTimeline(options = {}) {
  return setTimelineOpen(true, options);
}

function closeTimeline(options = {}) {
  return setTimelineOpen(false, options);
}

function toggleTimeline(options = {}) {
  return setTimelineOpen(state.timelineOpen === false, options);
}

function syncTimelineDockVisibility() {
  if (els.timelineDock) {
    els.timelineDock.classList.remove("hidden");
  }
  const nodes = timelineSortedNodes();
  const headNode = currentTimelineHeadNode();
  return syncTimelineShelfToggle(nodes, headNode);
}

function setTimelineOpen(open = true, { persist = false } = {}) {
  const nextOpen = open !== false;
  const changed = state.timelineOpen !== nextOpen;
  state.timelineOpen = nextOpen;
  syncTimelineDockVisibility();
  if (nextOpen) renderTimeline();
  if (changed && persist) {
    syncActiveTabRecord({ capture: true, publish: true });
  }
  return changed;
}

function timelineRailIconIdForActionKey(actionKey = "state") {
  const normalized = String(actionKey || "").trim().toLowerCase();
  if (!normalized) return null;
  if (normalized === "import") return "upload";
  if (normalized === "move") return "move";
  return null;
}

