function timelineNodeLabel(node = null) {
  if (!node) return "Timeline";
  return (
    String(node.label || "").trim() ||
    String(node.action || "").trim() ||
    (node.previewPath ? basename(node.previewPath) : "") ||
    "State"
  );
}

function timelineNodeSummary(node = null) {
  if (!node) return "Committed session history";
  const action = String(node.action || "").trim();
  const label = timelineNodeLabel(node);
  const imageCount = Array.isArray(node.imageIds) ? node.imageIds.length : 0;
  const countText = imageCount ? `${imageCount} image${imageCount === 1 ? "" : "s"}` : "";
  const canvasCountText = imageCount ? `${imageCount}-image` : "";
  const targetLabel =
    label && label !== action && label !== "State" && label !== "Timeline"
      ? String(label).trim()
      : "";
  const normalizedAction = action.toLowerCase();
  const singleCanvasContext = countText ? ` (${countText})` : "";
  const multiCanvasContext = imageCount > 1 ? ` in a ${canvasCountText} canvas` : "";
  const parentheticalCanvasContext = countText ? ` (${countText} on canvas)` : "";
  const targetWithContext = targetLabel ? `${targetLabel}${multiCanvasContext}` : "";
  if (normalizedAction === "import" || normalizedAction === "upload" || normalizedAction === "add image") {
    if (targetLabel) return `Imported ${targetLabel}${singleCanvasContext}`;
    if (countText) return `Imported an image${singleCanvasContext}`;
    return "Imported an image";
  }
  if (normalizedAction === "mark") {
    return targetWithContext ? `Marked ${targetWithContext}` : "Added a marker annotation";
  }
  if (normalizedAction === "highlight" || normalizedAction === "protect") {
    return targetWithContext ? `Highlighted ${targetWithContext}` : "Added a highlight annotation";
  }
  if (normalizedAction === "magic select" || normalizedAction === "select" || normalizedAction === "select region") {
    return targetWithContext ? `Selected a region on ${targetWithContext}` : "Selected a region";
  }
  if (normalizedAction === "erase") {
    return targetWithContext ? `Erased part of ${targetWithContext}` : "Erased part of the image";
  }
  if (normalizedAction === "annotate") {
    return targetWithContext ? `Annotated ${targetWithContext}` : "Added an annotation";
  }
  if (normalizedAction === "circle") {
    return targetWithContext ? `Circled ${targetWithContext}` : "Circled a region";
  }
  if (normalizedAction === "delete" || normalizedAction === "remove") {
    if (targetLabel && countText) return `Removed ${targetLabel}${parentheticalCanvasContext}`;
    if (targetLabel) return `Removed ${targetLabel}`;
    if (countText) return `Removed an image${singleCanvasContext}`;
    return "Removed an image";
  }
  if (normalizedAction === "move") {
    return targetWithContext ? `Moved ${targetWithContext}` : "Moved the selection";
  }
  if (normalizedAction === "resize") {
    return targetWithContext ? `Resized ${targetWithContext}` : "Resized the selection";
  }
  if (normalizedAction === "rotate") {
    return targetWithContext ? `Rotated ${targetWithContext}` : "Rotated the selection";
  }
  if (normalizedAction === "skew") {
    return targetWithContext ? `Skewed ${targetWithContext}` : "Skewed the selection";
  }
  if (normalizedAction === "combine") {
    return countText ? `Combined images${parentheticalCanvasContext}` : "Combined multiple images";
  }
  if (normalizedAction === "bridge") {
    return countText ? `Bridged images${parentheticalCanvasContext}` : "Bridged multiple images";
  }
  if (normalizedAction === "triforce") {
    return countText ? `Merged images${parentheticalCanvasContext}` : "Merged multiple images";
  }
  if (normalizedAction === "swap dna") {
    return targetWithContext ? `Swapped the DNA of ${targetWithContext}` : "Swapped image DNA";
  }
  if (normalizedAction === "recast") {
    return targetWithContext ? `Recast ${targetWithContext}` : "Recast the active image";
  }
  if (normalizedAction === "prompt generate") {
    if (targetLabel) return `Generated ${targetLabel}${singleCanvasContext}`;
    if (countText) return `Generated a new image${singleCanvasContext}`;
    return "Generated a new image";
  }
  if (normalizedAction === "create layers") {
    if (targetWithContext) return `Created layers for ${targetWithContext}`;
    if (countText) return `Created layers${singleCanvasContext}`;
    return "Created layers";
  }
  if (normalizedAction === "export") {
    if (targetLabel) return `Exported ${targetLabel}${singleCanvasContext}`;
    if (countText) return `Exported the canvas${singleCanvasContext}`;
    return "Exported the canvas";
  }
  if (action) {
    if (targetWithContext) return `Applied ${action} to ${targetWithContext}`;
    if (countText) return `Applied ${action}${singleCanvasContext}`;
    return `Applied ${action}`;
  }
  return targetLabel || countText || "Committed session history";
}

function timelineNodeAriaLabel(node = null, { current = false, future = false, historical = false } = {}) {
  const pieces = [];
  pieces.push(timelineNodeSummary(node));
  if (current) pieces.push("Current state");
  else if (historical) pieces.push("Historical state");
  else if (future) pieces.push("Future state");
  return pieces.join(". ");
}

function timelineDetailText(headNode = currentTimelineHeadNode()) {
  const headNodeId = String(headNode?.nodeId || "").trim() || null;
  const previewNodeId = String(state.timelinePreviewNodeId || "").trim();
  const previewNode =
    previewNodeId && state.timelineNodesById instanceof Map
      ? state.timelineNodesById.get(previewNodeId) || null
      : null;
  if (!previewNode) return headNode ? timelineNodeSummary(headNode) : "";
  const previewSummary = timelineNodeSummary(previewNode);
  if (previewNodeId === headNodeId) return `Current state: ${previewSummary}`;
  return `Preview change: ${previewSummary}`;
}

function syncTimelineDetailText(headNode = currentTimelineHeadNode()) {
  const detail = els.timelineDetail;
  if (!detail) return false;
  if (state.timelinePreviewNodeId) {
    const previewNodeId = String(state.timelinePreviewNodeId || "").trim();
    if (!(state.timelineNodesById instanceof Map) || !state.timelineNodesById.has(previewNodeId)) {
      state.timelinePreviewNodeId = null;
    }
  }
  const nextDetail = timelineDetailText(headNode);
  if (detail.textContent === nextDetail) return false;
  detail.textContent = nextDetail;
  return true;
}

const TIMELINE_CAROUSEL_PAGE_RATIO = 0.82;
const TIMELINE_CAROUSEL_GESTURE_LOCK_PX = 12;
const TIMELINE_CAROUSEL_GESTURE_THRESHOLD_PX = 38;
const TIMELINE_CAROUSEL_WHEEL_THRESHOLD_PX = 34;
const TIMELINE_CAROUSEL_CLICK_SUPPRESS_MS = 240;
const TIMELINE_CAROUSEL_EDGE_EPSILON_PX = 4;

function timelineNowMs() {
  if (typeof performance !== "undefined" && typeof performance.now === "function") {
    return performance.now();
  }
  return Date.now();
}

function timelineNodeStructureKey(node = null) {
  return [
    node?.nodeId || "",
    node?.seq || 0,
    node?.kind || "",
    node?.action || "",
    node?.visualMode || "",
    node?.label || "",
    node?.detail || "",
    node?.previewPath || "",
    node?.previewImageId || "",
    Array.isArray(node?.parents) ? node.parents.join(",") : "",
    Array.isArray(node?.imageIds) ? node.imageIds.join(",") : "",
    Array.isArray(node?.receiptPaths) ? node.receiptPaths.join(",") : "",
    node?.createdAt || 0,
  ].join(":");
}

function timelineStructureSignature(nodes = timelineSortedNodes()) {
  return Array.from(Array.isArray(nodes) ? nodes : [])
    .map((node) => timelineNodeStructureKey(node))
    .join("|");
}

function timelineViewSignature(headNode = currentTimelineHeadNode()) {
  return [
    String(headNode?.nodeId || "").trim(),
    Math.max(0, Number(headNode?.seq) || 0),
  ].join(":");
}

function timelineCardStateForNode(node = null, headNode = currentTimelineHeadNode()) {
  const headNodeId = String(headNode?.nodeId || "").trim() || null;
  const headSeq = Math.max(0, Number(headNode?.seq) || 0);
  const current = headNodeId === String(node?.nodeId || "").trim();
  const future = !current && Math.max(0, Number(node?.seq) || 0) > headSeq;
  const historical = !current && !future;
  const inactive = !current;
  return { current, future, historical, inactive };
}

function timelineCarouselAnchors(strip = els.timelineStrip) {
  if (!strip?.querySelectorAll) return [];
  const maxScroll = Math.max(0, Number(strip.scrollWidth || 0) - Number(strip.clientWidth || 0));
  const anchors = new Set([0, maxScroll]);
  const cards = Array.from(strip.querySelectorAll(".timeline-card[data-node-id]"));
  for (const card of cards) {
    const left = Math.max(0, Math.round(Number(card?.offsetLeft) || 0));
    anchors.add(Math.min(maxScroll, left));
  }
  return Array.from(anchors)
    .filter((left) => Number.isFinite(left))
    .sort((a, b) => a - b);
}

function timelineCarouselTargetLeft(strip = els.timelineStrip, direction = 0) {
  const normalizedDirection = Number(direction) > 0 ? 1 : Number(direction) < 0 ? -1 : 0;
  if (!strip || !normalizedDirection) return 0;
  const maxScroll = Math.max(0, Number(strip.scrollWidth || 0) - Number(strip.clientWidth || 0));
  if (maxScroll <= 0) return 0;
  const currentLeft = Math.min(maxScroll, Math.max(0, Number(strip.scrollLeft) || 0));
  const anchors = timelineCarouselAnchors(strip);
  if (!anchors.length) return currentLeft;
  const pageWidth = Math.max(1, Math.round(Number(strip.clientWidth || 0) * TIMELINE_CAROUSEL_PAGE_RATIO));
  const currentIndex = anchors.reduce((best, anchor, index) => (anchor <= currentLeft + 4 ? index : best), 0);
  if (normalizedDirection > 0) {
    const desired = Math.min(maxScroll, currentLeft + pageWidth);
    let target = anchors.find((anchor) => anchor >= desired - 4);
    if (target == null || target <= currentLeft + 4) {
      target = anchors[Math.min(anchors.length - 1, currentIndex + 1)] ?? maxScroll;
    }
    return Math.min(maxScroll, Math.max(0, Number(target) || 0));
  }
  const desired = Math.max(0, currentLeft - pageWidth);
  let target = Array.from(anchors)
    .reverse()
    .find((anchor) => anchor <= desired + 4);
  if (target == null || target >= currentLeft - 4) {
    target = anchors[Math.max(0, currentIndex - 1)] ?? 0;
  }
  return Math.min(maxScroll, Math.max(0, Number(target) || 0));
}

function timelineCarouselDirectionState(strip = els.timelineStrip) {
  const maxScroll = Math.max(0, Number(strip?.scrollWidth || 0) - Number(strip?.clientWidth || 0));
  const currentLeft = Math.min(maxScroll, Math.max(0, Number(strip?.scrollLeft) || 0));
  const hasOverflow = Boolean(strip && maxScroll > TIMELINE_CAROUSEL_EDGE_EPSILON_PX);
  return {
    hasOverflow,
    currentLeft,
    maxScroll,
    canPageLeft: hasOverflow && currentLeft > TIMELINE_CAROUSEL_EDGE_EPSILON_PX,
    canPageRight: hasOverflow && currentLeft < maxScroll - TIMELINE_CAROUSEL_EDGE_EPSILON_PX,
  };
}

function syncTimelineCarouselOverflow(strip = els.timelineStrip) {
  const { hasOverflow, canPageLeft, canPageRight } = timelineCarouselDirectionState(strip);
  strip?.classList?.toggle("is-scrollable", hasOverflow);
  els.timelineShell?.classList?.toggle("is-scrollable", hasOverflow);
  if (els.timelinePrev) {
    els.timelinePrev.classList.toggle("is-hidden", !canPageLeft);
    els.timelinePrev.disabled = !canPageLeft;
    els.timelinePrev.tabIndex = canPageLeft ? 0 : -1;
  }
  if (els.timelineNext) {
    els.timelineNext.classList.toggle("is-hidden", !canPageRight);
    els.timelineNext.disabled = !canPageRight;
    els.timelineNext.tabIndex = canPageRight ? 0 : -1;
  }
  return hasOverflow;
}

function scheduleTimelineCarouselChromeSync() {
  if (Number(state.timelineCarouselChromeFrame) > 0) return;
  const run = () => {
    state.timelineCarouselChromeFrame = 0;
    syncTimelineCarouselOverflow();
  };
  if (typeof requestAnimationFrame === "function") {
    state.timelineCarouselChromeFrame = requestAnimationFrame(run);
    return;
  }
  run();
}

function centerTimelineCardInStrip(card = null, strip = els.timelineStrip, { behavior = "smooth", force = false } = {}) {
  if (!card || !strip) return false;
  const maxScroll = Math.max(0, Number(strip.scrollWidth || 0) - Number(strip.clientWidth || 0));
  if (maxScroll <= 0) return false;
  const currentLeft = Math.min(maxScroll, Math.max(0, Number(strip.scrollLeft) || 0));
  const cardLeft = Math.max(0, Number(card.offsetLeft) || 0);
  const cardWidth = Math.max(1, Number(card.offsetWidth) || 0);
  const visibleLeft = currentLeft + 6;
  const visibleRight = currentLeft + Math.max(0, Number(strip.clientWidth || 0)) - 6;
  if (!force && cardLeft >= visibleLeft && cardLeft + cardWidth <= visibleRight) return false;
  const targetLeft = Math.min(
    maxScroll,
    Math.max(0, Math.round(cardLeft - Math.max(0, (Number(strip.clientWidth || 0) - cardWidth) / 2)))
  );
  if (Math.abs(targetLeft - currentLeft) <= 2) return false;
  if (typeof strip.scrollTo === "function") {
    strip.scrollTo({ left: targetLeft, behavior });
  } else {
    strip.scrollLeft = targetLeft;
  }
  return true;
}

function scrollTimelineCarousel(direction = 0, { behavior = "smooth" } = {}) {
  const strip = els.timelineStrip;
  const targetLeft = timelineCarouselTargetLeft(strip, direction);
  if (!strip) return false;
  const currentLeft = Math.max(0, Number(strip.scrollLeft) || 0);
  if (Math.abs(targetLeft - currentLeft) <= 2) return false;
  if (typeof strip.scrollTo === "function") {
    strip.scrollTo({ left: targetLeft, behavior });
  } else {
    strip.scrollLeft = targetLeft;
  }
  return true;
}

function suppressTimelineCardClick() {
  state.timelineSuppressClickUntil = timelineNowMs() + TIMELINE_CAROUSEL_CLICK_SUPPRESS_MS;
}

function shouldSuppressTimelineCardClick() {
  return timelineNowMs() < Math.max(0, Number(state.timelineSuppressClickUntil) || 0);
}

function resetTimelineCarouselGesture() {
  const pointerId = state.timelineCarouselGesture?.pointerId;
  if (pointerId != null && typeof els.timelineShell?.releasePointerCapture === "function") {
    try {
      els.timelineShell.releasePointerCapture(pointerId);
    } catch (_) {}
  }
  els.timelineShell?.classList?.remove("is-swiping");
  state.timelineCarouselGesture = null;
}

function beginTimelineCarouselGesture(event) {
  if (!els.timelineStrip || !syncTimelineCarouselOverflow()) return;
  if (event?.pointerType === "mouse" && Number(event?.button) !== 0) return;
  if (event?.target?.closest && event.target.closest(".timeline-arrow")) return;
  state.timelineCarouselGesture = {
    pointerId: event?.pointerId ?? null,
    startX: Number(event?.clientX) || 0,
    startY: Number(event?.clientY) || 0,
    dragging: false,
  };
  if (event?.pointerId != null && typeof els.timelineShell?.setPointerCapture === "function") {
    try {
      els.timelineShell.setPointerCapture(event.pointerId);
    } catch (_) {}
  }
}

function updateTimelineCarouselGesture(event) {
  const gesture = state.timelineCarouselGesture;
  if (!gesture) return false;
  if (gesture.pointerId != null && event?.pointerId != null && gesture.pointerId !== event.pointerId) return false;
  const dx = (Number(event?.clientX) || 0) - gesture.startX;
  const dy = (Number(event?.clientY) || 0) - gesture.startY;
  if (!gesture.dragging) {
    if (Math.abs(dx) < TIMELINE_CAROUSEL_GESTURE_LOCK_PX && Math.abs(dy) < TIMELINE_CAROUSEL_GESTURE_LOCK_PX) {
      return false;
    }
    if (Math.abs(dx) <= Math.abs(dy)) {
      resetTimelineCarouselGesture();
      return false;
    }
    gesture.dragging = true;
    els.timelineShell?.classList?.add("is-swiping");
  }
  event?.preventDefault?.();
  return true;
}

function finishTimelineCarouselGesture(event) {
  const gesture = state.timelineCarouselGesture;
  if (!gesture) return false;
  if (gesture.pointerId != null && event?.pointerId != null && gesture.pointerId !== event.pointerId) return false;
  const dx = (Number(event?.clientX) || 0) - gesture.startX;
  const dy = (Number(event?.clientY) || 0) - gesture.startY;
  const shouldSlide =
    gesture.dragging &&
    Math.abs(dx) >= TIMELINE_CAROUSEL_GESTURE_THRESHOLD_PX &&
    Math.abs(dx) > Math.abs(dy);
  resetTimelineCarouselGesture();
  if (!shouldSlide) return false;
  const moved = scrollTimelineCarousel(dx < 0 ? 1 : -1);
  if (moved) {
    suppressTimelineCardClick();
    event?.preventDefault?.();
  }
  return moved;
}

function handleTimelineCarouselWheel(event) {
  if (!els.timelineStrip || !syncTimelineCarouselOverflow()) return false;
  const deltaX = Number(event?.deltaX) || 0;
  const deltaY = Number(event?.deltaY) || 0;
  const usesHorizontalGesture = Math.abs(deltaX) > Math.abs(deltaY) ? deltaX : 0;
  const delta = usesHorizontalGesture || (event?.shiftKey ? deltaY : 0);
  if (!delta) {
    state.timelineCarouselWheel.delta = 0;
    return false;
  }
  const now = timelineNowMs();
  if (now - (Number(state.timelineCarouselWheel?.lastAt) || 0) > 220) {
    state.timelineCarouselWheel.delta = 0;
  }
  state.timelineCarouselWheel.lastAt = now;
  state.timelineCarouselWheel.delta += delta;
  if (Math.abs(state.timelineCarouselWheel.delta) < TIMELINE_CAROUSEL_WHEEL_THRESHOLD_PX) {
    return false;
  }
  const direction = state.timelineCarouselWheel.delta > 0 ? 1 : -1;
  state.timelineCarouselWheel.delta = 0;
  const moved = scrollTimelineCarousel(direction);
  if (moved) {
    suppressTimelineCardClick();
    event?.preventDefault?.();
  }
  return moved;
}

function buildTimelineCard(node = null, headNode = currentTimelineHeadNode()) {
  if (!node?.nodeId) return null;
  const { current, future, historical, inactive } = timelineCardStateForNode(node, headNode);
  const actionKey = timelineActionKey(node.action, node.kind);
  const usesThumbnail =
    String(node.visualMode || "").trim() === "thumbnail" &&
    String(node.previewPath || "").trim();
  const card = document.createElement("button");
  card.type = "button";
  card.className = `timeline-card ${usesThumbnail ? "timeline-card--thumb" : "timeline-card--icon"}${current ? " selected" : ""}${inactive ? " is-inactive" : ""}${historical ? " is-historical" : ""}${future ? " is-future" : ""}`;
  card.dataset.nodeId = node.nodeId;
  card.dataset.seq = String(Math.max(1, Number(node.seq) || 1));
  card.dataset.structureKey = timelineNodeStructureKey(node);
  card.setAttribute("aria-label", timelineNodeAriaLabel(node, { current, future, historical }));
  card.title = timelineNodeSummary(node);
  const seq = document.createElement("span");
  seq.className = "timeline-card-seq";
  seq.textContent = card.dataset.seq;
  card.appendChild(seq);
  const visual = document.createElement("span");
  visual.className = "timeline-card-visual";
  if (usesThumbnail) {
    const img = document.createElement("img");
    img.alt = timelineNodeLabel(node);
    img.loading = "lazy";
    img.decoding = "async";
    img.src = THUMB_PLACEHOLDER_SRC;
    ensureImageUrl(node.previewPath)
      .then((url) => {
        if (url) img.src = url;
      })
      .catch(() => {});
    visual.appendChild(img);
  } else {
    const glyph = document.createElement("span");
    glyph.className = `timeline-card-glyph timeline-card-glyph--${actionKey}`;
    glyph.innerHTML = timelineCardGlyphMarkup(actionKey);
    visual.appendChild(glyph);
  }
  card.appendChild(visual);
  return card;
}

function rebuildTimelineStrip(nodes = timelineSortedNodes(), headNode = currentTimelineHeadNode()) {
  const strip = els.timelineStrip;
  if (!strip) return false;
  els.timelineShell?.classList?.toggle("is-empty", !nodes.length);
  strip.classList?.toggle("is-empty", !nodes.length);
  if (!nodes.length) {
    const currentEmpty = strip.querySelector(".timeline-empty");
    if (!currentEmpty || String(currentEmpty.textContent || "").trim() !== "Your timeline appears here after you upload your first image.") {
      strip.replaceChildren();
      const empty = document.createElement("div");
      empty.className = "timeline-empty muted";
      empty.textContent = "Your timeline appears here after you upload your first image.";
      strip.appendChild(empty);
    }
    state.lastTimelineCenteredNodeId = null;
    scheduleTimelineCarouselChromeSync();
    return true;
  }

  for (const empty of Array.from(strip.querySelectorAll(".timeline-empty"))) {
    empty.remove();
  }

  const desiredNodeIds = new Set();
  const existingCards = Array.from(strip.querySelectorAll(".timeline-card[data-node-id]"));
  const existingById = new Map();
  for (const card of existingCards) {
    const nodeId = String(card.dataset?.nodeId || "").trim();
    if (!nodeId) continue;
    existingById.set(nodeId, card);
  }

  for (const node of nodes) {
    const nodeId = String(node?.nodeId || "").trim();
    if (!nodeId) continue;
    desiredNodeIds.add(nodeId);
  }

  for (const card of existingCards) {
    const nodeId = String(card.dataset?.nodeId || "").trim();
    if (!nodeId || desiredNodeIds.has(nodeId)) continue;
    card.remove();
    existingById.delete(nodeId);
  }

  let referenceNode = strip.firstChild;
  for (const node of nodes) {
    const nodeId = String(node?.nodeId || "").trim();
    if (!nodeId) continue;
    const structureKey = timelineNodeStructureKey(node);
    let card = existingById.get(nodeId) || null;
    if (!card) {
      card = buildTimelineCard(node, headNode);
      if (!card) continue;
      existingById.set(nodeId, card);
    } else if (String(card.dataset?.structureKey || "") !== structureKey) {
      const replacement = buildTimelineCard(node, headNode);
      if (!replacement) continue;
      if (card.parentNode === strip) {
        strip.replaceChild(replacement, card);
        if (referenceNode === card) referenceNode = replacement;
      }
      existingById.set(nodeId, replacement);
      card = replacement;
    }
    if (card.parentNode !== strip) {
      strip.insertBefore(card, referenceNode);
    } else if (card !== referenceNode) {
      strip.insertBefore(card, referenceNode);
    } else {
      referenceNode = card.nextSibling;
      continue;
    }
    referenceNode = card.nextSibling;
  }

  syncTimelineCarouselOverflow(strip);
  return true;
}

function syncTimelineViewState(nodes = timelineSortedNodes(), headNode = currentTimelineHeadNode()) {
  const strip = els.timelineStrip;
  if (!strip) return false;
  const headNodeId = String(headNode?.nodeId || "").trim() || null;
  let changed = false;
  const cards = Array.from(strip.querySelectorAll(".timeline-card[data-node-id]"));
  for (const card of cards) {
    const nodeId = String(card.dataset?.nodeId || "").trim();
    if (!nodeId) continue;
    const node = state.timelineNodesById instanceof Map ? state.timelineNodesById.get(nodeId) || null : null;
    if (!node) continue;
    const { current, future, historical, inactive } = timelineCardStateForNode(node, headNode);
    if (card.classList.contains("selected") !== current) {
      card.classList.toggle("selected", current);
      changed = true;
    }
    if (card.classList.contains("is-inactive") !== inactive) {
      card.classList.toggle("is-inactive", inactive);
      changed = true;
    }
    if (card.classList.contains("is-historical") !== historical) {
      card.classList.toggle("is-historical", historical);
      changed = true;
    }
    if (card.classList.contains("is-future") !== future) {
      card.classList.toggle("is-future", future);
      changed = true;
    }
    const nextAria = timelineNodeAriaLabel(node, { current, future, historical });
    if (card.getAttribute("aria-label") !== nextAria) {
      card.setAttribute("aria-label", nextAria);
      changed = true;
    }
  }
  changed = syncTimelineDetailText(headNode) || changed;
  const selectedCard = headNodeId
    ? cards.find((card) => String(card.dataset?.nodeId || "").trim() === headNodeId) || null
    : null;
  if (selectedCard && headNodeId) {
    centerTimelineCardInStrip(selectedCard, strip, {
      behavior: state.lastTimelineCenteredNodeId === headNodeId ? "auto" : "smooth",
      force: headNodeId !== state.lastTimelineCenteredNodeId,
    });
    state.lastTimelineCenteredNodeId = headNodeId;
  } else if (!headNodeId) {
    state.lastTimelineCenteredNodeId = null;
  }
  scheduleTimelineCarouselChromeSync();
  return changed;
}

function renderTimeline() {
  const strip = els.timelineStrip;
  if (!strip) return false;
  const nodes = timelineSortedNodes();
  const headNode = currentTimelineHeadNode();
  syncTimelineShelfToggle(nodes, headNode);
  const structureKey = [
    state.timelineVersion,
    state.timelineLatestNodeId || "",
    state.timelineNextSeq || 1,
    timelineStructureSignature(nodes),
  ].join("||");
  const viewKey = timelineViewSignature(headNode);
  let changed = false;
  if (state.lastRenderedTimelineStructureKey !== structureKey) {
    state.lastRenderedTimelineStructureKey = structureKey;
    state.lastRenderedTimelineViewKey = "";
    rebuildTimelineStrip(nodes, headNode);
    changed = true;
  }
  if (state.lastRenderedTimelineViewKey !== viewKey) {
    state.lastRenderedTimelineViewKey = viewKey;
    syncTimelineViewState(nodes, headNode);
    changed = true;
  } else if (!changed) {
    scheduleTimelineCarouselChromeSync();
  }
  return changed;
}

function currentTimelineRestoreBlockReason() {
  if (state.pointer?.active || state.gestureZoom?.active) return "manipulating_canvas";
  if (state.designReviewApply?.status === "running") return "review_apply";
  if (state.pendingReplace) return "visible_mutation";
  return null;
}

function currentTimelineRestoreBlockMessage(reason = currentTimelineRestoreBlockReason()) {
  const normalized = String(reason || "").trim();
  if (normalized === "manipulating_canvas") return "Finish the current canvas gesture before rewinding the timeline.";
  if (normalized === "review_apply") return "Wait for the accepted review edit to finish before rewinding the timeline.";
  if (normalized === "assistant_mutation" || normalized === "visible_mutation") {
    return "Wait for the active canvas mutation to finish before rewinding the timeline.";
  }
  return "Timeline restore is blocked while the canvas is mutating.";
}

async function jumpToLegacyTimelineNode(node = null) {
  if (!node?.imageId || !node?.previewPath) return false;
  const imgItem = state.imagesById.get(String(node.imageId || "")) || null;
  if (!imgItem) return false;
  if (state.activeId !== imgItem.id) {
    await setActiveImage(imgItem.id, {
      source: "timeline",
      reason: "timeline_jump_legacy",
    }).catch(() => {});
  }
  if (imgItem.path !== node.previewPath) {
    const ok = await replaceImageInPlace(imgItem.id, {
      path: node.previewPath,
      receiptPath: Array.isArray(node.receiptPaths) ? node.receiptPaths[0] || null : null,
      kind: imgItem.kind,
      clearVision: true,
      source: "timeline",
      reason: "timeline_jump_legacy",
    });
    if (!ok) return false;
  }
  imgItem.timelineNodeId = node.nodeId;
  state.timelineHeadNodeId = node.nodeId;
  syncActiveTabRecord({ capture: true, publish: true });
  persistActiveSessionTimeline();
  renderTimeline();
  return true;
}

async function jumpToTimelineNode(nodeId) {
  const normalizedNodeId = String(nodeId || "").trim();
  if (!normalizedNodeId || normalizedNodeId === String(state.timelineHeadNodeId || "").trim()) return;
  const node = state.timelineNodesById instanceof Map ? state.timelineNodesById.get(normalizedNodeId) || null : null;
  if (!node) return;
  const blockReason = currentTimelineRestoreBlockReason();
  if (blockReason) {
    showToast(currentTimelineRestoreBlockMessage(blockReason), "tip", 2200);
    return;
  }
  if (!node.snapshot) {
    const restoredLegacy = await jumpToLegacyTimelineNode(node);
    if (!restoredLegacy) {
      showToast("That timeline state cannot be restored.", "error", 2400);
    }
    return;
  }

  const restoredSession = restoreSessionTimelineSnapshot(node.snapshot, {
    runDir: state.runDir || null,
    eventsPath: state.eventsPath || null,
  });
  restoredSession.screenshotPolishMeta = normalizeScreenshotPolishMetadata(
    state.screenshotPolishMeta || restoredSession.screenshotPolishMeta
  );
  restoredSession.timelineNodes = Array.from(state.timelineNodes || []);
  restoredSession.timelineNodesById = state.timelineNodesById instanceof Map ? state.timelineNodesById : new Map();
  restoredSession.timelineHeadNodeId = node.nodeId;
  restoredSession.timelineLatestNodeId = state.timelineLatestNodeId || node.nodeId;
  restoredSession.timelineNextSeq = Math.max(1, Number(state.timelineNextSeq) || Math.max(1, Number(node.seq) || 1) + 1);
  restoredSession.timelineOpen = true;
  bindTabSessionToState(restoredSession);
  syncSessionToolsFromRegistry();
  renderCreateToolPreview();
  renderCustomToolDock();
  renderSelectionMeta();
  renderFilmstrip();
  chooseSpawnNodes();
  renderSessionApiCallsReadout();
  updateEmptyCanvasHint();
  syncIntentModeClass();
  syncJuggernautShellState();
  syncTimelineDockVisibility();
  renderTimeline();
  for (const item of state.images || []) {
    ensureCanvasImageLoaded(item);
  }
  const activeItem = state.activeId ? state.imagesById.get(state.activeId) || null : null;
  if (activeItem?.path) {
    await setEngineActiveImage(activeItem.path).catch(() => {});
  }
  syncActiveTabRecord({ capture: true, publish: true });
  persistActiveSessionTimeline();
  requestRender();
}

const USER_ACTIVE_IMAGE_EVENT_SOURCES = new Set(["user_select", "filmstrip_click", "timeline"]);
function activeImageEventActorForSource(source = "system", explicitActor = null) {
  if (explicitActor === "user" || explicitActor === "system") return explicitActor;
  const normalizedSource = String(source || "system").trim();
  return USER_ACTIVE_IMAGE_EVENT_SOURCES.has(normalizedSource) ? "user" : "system";
}

async function setActiveImage(id, { preserveSelection = false, source = "system", reason = null, actor = null } = {}) {
  const item = state.imagesById.get(id);
  if (!item) return;
  const prevActive = state.activeId;
  state.activeId = id;
  markActiveTabUiDirty({ spawn: true, quickActions: true });
  if (preserveSelection) {
    // Ensure the newly-active image is included and keep multi-select ordering stable.
    const next = getSelectedIds();
    setSelectedIds(next.length > 3 ? next.slice(next.length - 3) : next);
  } else {
    setSelectedIds([id]);
  }
  invalidateActiveTabPreview("active_image_change");
  syncLocalMagicSelectUiPrewarmTargets({
    primaryImageId: id,
    hoverImageId: null,
    source: "communication_magic_select",
  });
  if (prevActive !== id) {
    const eventActor = activeImageEventActorForSource(source, actor);
    recordUserEvent("active_image_change", {
      actor: eventActor,
      source: String(source || "system"),
      reason: reason ? String(reason) : null,
      canvas_mode: state.canvasMode,
      from_active_id: prevActive || null,
      active_id: id,
      selected_ids: getSelectedIds().slice(0, 3),
    });
  }
  setFilmstripSelected(prevActive, id);
  state.lastRenderedFilmstripSelectionKey = filmstripSelectionSignature();
  state.lastRenderedFilmstripActiveId = state.activeId || null;
  clearSelection();
  showDropHint(false);
  renderSelectionMeta();
  renderQuickActions();
  chooseSpawnNodes();
  requestRender();
  await setEngineActiveImage(item.path);
  try {
    item.img = await loadImage(item.path);
    item.width = item.img?.naturalWidth || null;
    item.height = item.img?.naturalHeight || null;
  } catch (err) {
    console.error(err);
  }
  syncActiveScreenshotPolishMetadataFromImage(item);
  renderHudReadout();
  resetViewToFit();
  requestRender();
  if (state.timelineOpen) renderTimeline();
  syncActiveTabRecord({ capture: false, publish: true });
}

function addImage(item, { select = false } = {}) {
  if (!item || !item.id || !item.path) return;
  if (state.imagesById.has(item.id)) return;
  const hadActiveImage = Boolean(state.activeId);
  const assignedPaletteIndex = Number(item.uiPaletteIndex);
  if (!Number.isFinite(assignedPaletteIndex) || assignedPaletteIndex < 0) {
    const nextPaletteIndex = Math.max(0, Math.floor(Number(state.imagePaletteSeed) || 0));
    item.uiPaletteIndex = nextPaletteIndex;
    state.imagePaletteSeed = nextPaletteIndex + 1;
  } else {
    state.imagePaletteSeed = Math.max(
      Math.floor(Number(state.imagePaletteSeed) || 0),
      Math.floor(assignedPaletteIndex) + 1
    );
  }
  state.imagesById.set(item.id, item);
  state.images.push(item);
  invalidateActiveTabPreview("image_add");
  markActiveTabUiDirty({ filmstrip: true, timeline: true, spawn: true, quickActions: true, publishTabs: true });
  if (!state.freeformZOrder.includes(item.id)) {
    state.freeformZOrder.push(item.id);
  }
  ensureTimelineNodeForImageItem(item);
  appendFilmstripThumb(item);
  if (item.receiptPath && !item.receiptMetaChecked) {
    ensureReceiptMeta(item).catch(() => {});
  }
  showDropHint(false);
  scheduleVisualPromptWrite();
  recordUserEvent("image_add", {
    image_id: String(item.id),
    kind: item.kind ? String(item.kind) : null,
    file: item.path ? basename(item.path) : null,
    n_images: state.images.length,
  });
  updateEmptyCanvasHint();
  if (intentModeActive()) {
    scheduleIntentStateWrite();
  }
  if (communicationBehaviorToolId() === "magic_select" || select || !hadActiveImage) {
    void prepareLocalMagicSelectImageForUi(item.id, {
      source: "communication_magic_select",
    }).catch(() => {});
  }
  if (select || !state.activeId) {
    setActiveImage(item.id).catch(() => {});
  }
  requestRender();
}

async function removeImageFromCanvas(imageId, { recordTimeline = false, action = "Delete Image" } = {}) {
  const id = String(imageId || "");
  if (!id) return false;
  const item = state.imagesById.get(id) || null;
  if (!item) return false;
  const removedNodeParentId = item.timelineNodeId ? String(item.timelineNodeId) : null;
  const removedPath = item.path ? String(item.path) : null;
  const removedLabel = item.label ? String(item.label) : removedPath ? basename(removedPath) : "Deleted image";
  const removedReceiptPath = item.receiptPath ? String(item.receiptPath) : null;
  recordUserEvent("image_remove", {
    image_id: id,
    file: item?.path ? basename(item.path) : null,
    n_images_before: state.images.length,
  });

  hideImageMenu();

  if (item?.path) {
    invalidateImageCache(item.path);
    dropVisionDescribePath(item.path, { cancelInFlight: true });
  }

  // Drop per-image marks.
  state.circlesByImageId.delete(id);
  dropCommunicationStateForImageId(id);
  clearEffectTokenForImageId(id);
  if (state.effectTokenDrag) {
    const dragTokenId = String(state.effectTokenDrag.tokenId || "");
    const dragSourceId = String(state.effectTokenDrag.sourceImageId || "");
    if (dragSourceId === id || !state.effectTokensById.has(dragTokenId)) {
      state.effectTokenDrag = null;
    }
  }

  // Remove from collections.
  state.imagesById.delete(id);
  state.images = (state.images || []).filter((item) => item?.id !== id);
  invalidateActiveTabPreview("image_remove");
  markActiveTabUiDirty({ filmstrip: true, timeline: true, spawn: true, quickActions: true });
  state.freeformRects.delete(id);
  state.freeformZOrder = (state.freeformZOrder || []).filter((v) => v !== id);
  state.multiRects.delete(id);
  // Maintain multi-select.
  setSelectedIds(getSelectedIds().filter((v) => v !== id));

  // Remove filmstrip thumb if present (filmstrip might be hidden in multi mode).
  const thumb = state.thumbsById.get(id);
  if (thumb?.rootEl && thumb.rootEl.parentNode) {
    try {
      thumb.rootEl.parentNode.removeChild(thumb.rootEl);
    } catch {
      // ignore
    }
  }
  state.thumbsById.delete(id);
  syncFilmstripRenderSignature();

  // If we removed the active image, select a sensible next.
  if (state.activeId === id) {
    state.activeId = null;
    const selected = Array.isArray(state.selectedIds) ? state.selectedIds : [];
    const nextSelectedId = selected.length ? selected[selected.length - 1] : null;
    const nextSelected = nextSelectedId ? state.imagesById.get(nextSelectedId) : null;
    const next = nextSelected || (state.images.length ? state.images[state.images.length - 1] : null);
    if (next?.id) await setActiveImage(next.id, { preserveSelection: true });
  }

  if (state.images.length === 0) {
    clearImageCache();
    state.imagePaletteSeed = 0;
    state.activeId = null;
    state.selectedIds = [];
    state.canvasMode = "multi";
    state.freeformRects.clear();
    state.freeformZOrder = [];
    state.multiRects.clear();
    state.pendingBlend = null;
    state.pendingSwapDna = null;
    state.pendingBridge = null;
    state.pendingExtractDna = null;
    state.pendingSoulLeech = null;
    state.pendingRecast = null;
    state.pendingPromptGenerate = null;
    clearAllEffectTokens();
    clearSelection();
    if (state.intent && !state.intent.locked) {
      state.intent.lockedAt = 0;
      state.intent.lockedBranchId = null;
      state.intent.startedAt = 0;
      state.intent.deadlineAt = 0;
      state.intent.round = 1;
      state.intent.selections = [];
      state.intent.focusBranchId = null;
      state.intent.iconState = null;
      state.intent.iconStateAt = 0;
      state.intent.pending = false;
      state.intent.pendingPath = null;
      state.intent.pendingAt = 0;
      state.intent.pendingFrameId = null;
      state.intent.rtState = "off";
      state.intent.disabledReason = null;
      state.intent.lastError = null;
      state.intent.lastErrorAt = 0;
      state.intent.lastSignature = null;
      state.intent.lastRunAt = 0;
      state.intent.forceChoice = false;
      state.intent.uiHits = [];
      clearTimeout(intentInferenceTimer);
      intentInferenceTimer = null;
      clearTimeout(intentInferenceTimeout);
      intentInferenceTimeout = null;
      stopIntentTicker();
      if (state.ptySpawned) {
        invoke("write_pty", { data: `${PTY_COMMANDS.INTENT_RT_STOP}\n` }).catch(() => {});
      }
      syncIntentModeClass();
      scheduleIntentStateWrite({ immediate: true });
    }
    resetAmbientIntentState();
    if (state.ptySpawned) {
      invoke("write_pty", { data: `${PTY_COMMANDS.INTENT_RT_STOP}\n` }).catch(() => {});
    }
    updateEmptyCanvasHint();
    setTip(DEFAULT_TIP);
    setDirectorText(null, null);
    renderFilmstrip();
    renderQuickActions();
    renderHudReadout();
    requestRender();
    if (recordTimeline) {
      recordTimelineNode({
        action,
        kind: "delete",
        visualMode: "icon",
        label: removedLabel,
        detail: removedPath ? basename(removedPath) : removedLabel,
        parents: removedNodeParentId ? [removedNodeParentId] : null,
        previewImageId: id,
        previewPath: removedPath,
        receiptPaths: removedReceiptPath ? [removedReceiptPath] : [],
      });
    }
    syncActiveTabRecord({ capture: false, publish: true });
    return true;
  }

  renderFilmstrip();

  updateEmptyCanvasHint();
  scheduleVisualPromptWrite();
  scheduleIntentStateWrite();
  renderQuickActions();
  renderHudReadout();
  requestRender();
  if (recordTimeline) {
    recordTimelineNode({
      action,
      kind: "delete",
      visualMode: "icon",
      label: removedLabel,
      detail: removedPath ? basename(removedPath) : removedLabel,
      parents: removedNodeParentId ? [removedNodeParentId] : null,
      previewImageId: id,
      previewPath: removedPath,
      receiptPaths: removedReceiptPath ? [removedReceiptPath] : [],
    });
  }
  syncActiveTabRecord({ capture: false, publish: true });
  return true;
}

function invalidateImageCache(path) {
  if (!path) return;
  const rec = state.imageCache.get(path);
  if (!rec) return;
  if (rec.url) {
    try {
      URL.revokeObjectURL(rec.url);
    } catch {
      // ignore
    }
  }
  state.imageCache.delete(path);
}

async function replaceImageInPlace(
  targetId,
  { path, receiptPath = null, kind = null, label = null, clearVision = true } = {}
) {
  const item = state.imagesById.get(targetId);
  if (!item || !path) return false;
  clearEffectTokenForImageId(targetId);
  invalidateActiveTabPreview("image_replace");
  const oldPath = item.path;
  if (oldPath && oldPath !== path) {
    invalidateImageCache(oldPath);
    dropVisionDescribePath(oldPath, { cancelInFlight: true });
    void dropLocalMagicSelectPreparedImageForUi(targetId, {
      reason: "image_replaced",
    }).catch(() => {});
  }
  // New paths are always new files; no need to invalidate unless we overwrite, but be safe.
  invalidateImageCache(path);
  markActiveTabUiDirty({ filmstrip: true, timeline: true, spawn: true, quickActions: true });

  item.path = path;
  item.receiptPath = receiptPath;
  item.receiptMeta = null;
  item.receiptMetaChecked = false;
  item.receiptMetaLoading = false;
  if (kind) item.kind = kind;
  const explicitLabel = typeof label === "string" ? label.trim() : "";
  if (explicitLabel) {
    item.label = explicitLabel;
  } else if (path && oldPath && oldPath !== path) {
    const oldPathLabel = basename(oldPath || "");
    const nextPathLabel = basename(path || "");
    const currentLabel = String(item.label || "").trim();
    // If the label still mirrors the old path (or is empty), keep it in sync with the new file path.
    if (!currentLabel || (oldPathLabel && currentLabel === oldPathLabel)) {
      if (nextPathLabel) item.label = nextPathLabel;
    }
  }
  item.img = null;
  item.width = null;
  item.height = null;
  if (state.communication?.regionProposalsByImageId instanceof Map) {
    state.communication.regionProposalsByImageId.delete(String(targetId || "").trim());
    if (String(state.communication?.lastAnchor?.imageId || "").trim() === String(targetId || "").trim()) {
      state.communication.lastAnchor = null;
    }
  }
  if (clearVision) {
    item.visionDesc = null;
    item.visionPending = false;
    if (state.describePendingPath === oldPath) state.describePendingPath = null;
  }

  updateFilmstripThumb(item);
  if (oldPath && oldPath !== path) {
    syncLocalMagicSelectUiPrewarmTargets({
      primaryImageId: state.activeId || null,
      hoverImageId: null,
      source: "communication_magic_select",
    });
  }
  syncActiveTabRecord({ capture: false, publish: true });
  if (item.receiptPath) ensureReceiptMeta(item).catch(() => {});
  if (state.activeId === targetId) {
    try {
      item.img = await loadImage(item.path);
      item.width = item.img?.naturalWidth || null;
      item.height = item.img?.naturalHeight || null;
    } catch (err) {
      console.error(err);
    }
    syncActiveScreenshotPolishMetadataFromImage(item);
    await setEngineActiveImage(item.path);
    renderSelectionMeta();
    chooseSpawnNodes();
    renderHudReadout();
    resetViewToFit();
    requestRender();
  }
  scheduleVisualPromptWrite();
  return true;
}

async function setEngineActiveImage(path) {
  if (!path) return;
  if (!state.ptySpawned) {
    // Active image tracking is best-effort; don't block UI if engine isn't ready yet.
    return;
  }
  await invoke("write_pty", { data: `${PTY_COMMANDS.USE} ${quoteForPtyArg(path)}\n` }).catch(() => {
    state.ptySpawned = false;
  });
}

function restoreEngineImageModelIfNeeded() {
  const restore = state.engineImageModelRestore;
  if (!restore) return;
  state.engineImageModelRestore = null;
  if (!state.ptySpawned) return;
  invoke("write_pty", { data: `${PTY_COMMANDS.IMAGE_MODEL} ${restore}\n` }).catch(() => {});
}

async function maybeOverrideEngineImageModel(desiredModel) {
  const desired = String(desiredModel || "").trim();
  if (!desired) return false;
  if (!state.ptySpawned) return false;
  if (desired === settings.imageModel) return false;
  state.engineImageModelRestore = settings.imageModel;
  await invoke("write_pty", { data: `${PTY_COMMANDS.IMAGE_MODEL} ${desired}\n` }).catch(() => {});
  return true;
}

async function writeLocalReceipt({ artifactId, imagePath, operation, meta = {}, outputDir = null }) {
  const baseDir = String(outputDir || state.runDir || "").trim();
  if (!baseDir) return null;
  const receiptFileName = `receipt-${artifactId}.json`;
  const receiptPath =
    typeof join === "function"
      ? (await join(baseDir, receiptFileName).catch(() => "")) || `${baseDir}/${receiptFileName}`
      : `${baseDir}/${receiptFileName}`;
  const payload = {
    schema_version: 1,
    request: {
      prompt: "",
      mode: "local",
      size: null,
      n: 1,
      seed: null,
      output_format: extname(imagePath).replace(".", "") || "png",
      inputs: { init_image: null, mask: null, reference_images: [] },
      provider: "local",
      model: null,
      provider_options: {},
      out_dir: baseDir,
      metadata: { operation },
    },
    resolved: {
      provider: "local",
      model: null,
      size: null,
      width: null,
      height: null,
      output_format: extname(imagePath).replace(".", "") || "png",
      background: null,
      seed: null,
      n: 1,
      user: null,
      prompt: "",
      inputs: { init_image: null, mask: null, reference_images: [] },
      stream: false,
      partial_images: null,
      provider_params: {},
      warnings: [],
    },
    provider_request: {},
    provider_response: {},
    warnings: [],
    artifacts: { image_path: imagePath, receipt_path: receiptPath },
    result_metadata: { operation, ...meta, created_at: new Date().toISOString() },
  };
  await writeTextFile(receiptPath, JSON.stringify(payload, null, 2));
  return receiptPath;
}

function resolveDesignReviewApplyRequestImagePath(request = null, imageId = "") {
  const normalizedImageId = readFirstString(imageId);
  if (!normalizedImageId) return "";
  const images = Array.isArray(request?.visibleCanvasContext?.images)
    ? request.visibleCanvasContext.images
    : Array.isArray(request?.imagesInView)
      ? request.imagesInView
      : [];
  for (const image of images) {
    const candidateId = readFirstString(image?.id, image?.imageId, image?.image_id);
    if (!candidateId || candidateId !== normalizedImageId) continue;
    return readFirstString(image?.path, image?.imagePath, image?.image_path);
  }
  return "";
}

async function writeDesignReviewApplyReceipt({
  runDir = state.runDir,
  outputPath,
  targetBefore = null,
  targetImageId = null,
  referenceImageIds = [],
  selectedProposalId = null,
  proposal = null,
  request = null,
  debugInfo = null,
  provider = null,
  requestedModel = null,
  normalizedModel = null,
  costTotalUsd = null,
  latencyPerImageS = null,
} = {}) {
  const resolvedRunDir = readFirstString(runDir, state.runDir);
  if (!resolvedRunDir || !outputPath) return null;
  const receiptPath = `${resolvedRunDir}/receipt-review-apply-${Date.now()}.json`;
  const actionLabel = readFirstString(proposal?.label, proposal?.actionType) || "Apply Proposal";
  const resolvedSelectedProposalId = readFirstString(selectedProposalId, proposal?.proposalId, proposal?.id) || null;
  const referencePaths = uniqueStringList(
    referenceImageIds.map((imageId) => resolveDesignReviewApplyRequestImagePath(request, imageId))
  );
  const screenshotPolishMetadata = {
    selectedProposalId: resolvedSelectedProposalId,
    approvedProposalId: resolvedSelectedProposalId,
    previewImagePath: readFirstString(proposal?.previewImagePath, proposal?.preview_image_path) || null,
    changedRegionBounds:
      asRecord(proposal?.changedRegionBounds)
        ? cloneToolRuntimeValue(proposal.changedRegionBounds)
        : asRecord(proposal?.changed_region_bounds)
          ? cloneToolRuntimeValue(proposal.changed_region_bounds)
          : null,
    preserveRegionIds: uniqueStringList(proposal?.preserveRegionIds || proposal?.preserve_region_ids || []),
    rationaleCodes: uniqueStringList(proposal?.rationaleCodes || proposal?.rationale_codes || []),
  };
  const payload = {
    schema_version: 1,
    request: {
      prompt: readFirstString(proposal?.applyBrief) || "",
      mode: "design_review_apply",
      size: null,
      n: 1,
      seed: null,
      output_format: extname(outputPath).replace(".", "") || "png",
      inputs: {
        init_image: targetBefore?.path ? String(targetBefore.path) : null,
        mask: null,
        reference_images: referencePaths,
      },
      provider: readFirstString(provider, debugInfo?.provider, debugInfo?.route?.provider) || null,
      model: readFirstString(requestedModel, debugInfo?.requestedModel, debugInfo?.providerRequest?.model) || null,
      provider_options: {},
      out_dir: resolvedRunDir,
      metadata: {
        operation: "design_review_apply",
        action: actionLabel,
        request_id: readFirstString(request?.requestId) || null,
        proposal_id: readFirstString(proposal?.proposalId, proposal?.id) || null,
        screenshotPolish: cloneToolRuntimeValue(screenshotPolishMetadata),
        proposal_label: readFirstString(proposal?.label) || null,
        action_type: readFirstString(proposal?.actionType) || null,
        target_image_id: readFirstString(targetImageId) || null,
        reference_image_ids: uniqueStringList(referenceImageIds),
        target_region: asRecord(proposal?.targetRegion) ? cloneToolRuntimeValue(proposal.targetRegion) : null,
        negative_constraints: Array.isArray(proposal?.negativeConstraints) ? proposal.negativeConstraints.slice() : [],
      },
    },
    resolved: {
      provider: readFirstString(provider, debugInfo?.provider, debugInfo?.route?.provider) || null,
      model: readFirstString(
        normalizedModel,
        requestedModel,
        debugInfo?.normalizedModel,
        debugInfo?.route?.normalizedModel,
        debugInfo?.providerRequest?.model
      ) || null,
      size: null,
      width: null,
      height: null,
      output_format: extname(outputPath).replace(".", "") || "png",
      background: null,
      seed: null,
      n: 1,
      user: null,
      prompt: readFirstString(proposal?.applyBrief) || "",
      inputs: {
        init_image: targetBefore?.path ? String(targetBefore.path) : null,
        mask: null,
        reference_images: referencePaths,
      },
      stream: false,
      partial_images: null,
      provider_params: {},
      warnings: [],
    },
    provider_request: asRecord(debugInfo?.providerRequest) ? cloneToolRuntimeValue(debugInfo.providerRequest) : {},
    provider_response: {
      output_path: outputPath ? String(outputPath) : null,
      debug_info: asRecord(debugInfo) ? cloneToolRuntimeValue(debugInfo) : null,
    },
    warnings: [],
    artifacts: { image_path: outputPath, receipt_path: receiptPath },
    result_metadata: {
      operation: "design_review_apply",
      action: actionLabel,
      request_id: readFirstString(request?.requestId) || null,
      proposal_id: readFirstString(proposal?.proposalId, proposal?.id) || null,
      screenshotPolish: cloneToolRuntimeValue(screenshotPolishMetadata),
      proposal_label: readFirstString(proposal?.label) || null,
      action_type: readFirstString(proposal?.actionType) || null,
      target_image_id: readFirstString(targetImageId) || null,
      reference_image_ids: uniqueStringList(referenceImageIds),
      cost_total_usd: readFirstNumber(costTotalUsd),
      latency_per_image_s: readFirstNumber(latencyPerImageS),
      created_at: new Date().toISOString(),
    },
  };
  await writeTextFile(receiptPath, JSON.stringify(payload, null, 2));
  return receiptPath;
}

function isoFromMs(ms) {
  const t = typeof ms === "number" && Number.isFinite(ms) ? ms : Date.now();
  try {
    return new Date(t).toISOString();
  } catch {
    return new Date().toISOString();
  }
}

function buildVisualPrompt() {
  const nowIso = new Date().toISOString();
  const canvas = els.workCanvas;
  const dpr = getDpr();
  const active = getActiveImage();

  let multiRects = null;
  if (state.canvasMode === "multi" && canvas) {
    const rectMap =
      state.multiRects && state.multiRects.size ? state.multiRects : computeFreeformRectsPx(canvas.width, canvas.height);
    multiRects = Array.from(rectMap.entries()).map(([imageId, rect]) => ({
      image_id: String(imageId),
      x: Number(rect?.x) || 0,
      y: Number(rect?.y) || 0,
      w: Number(rect?.w) || 0,
      h: Number(rect?.h) || 0,
      cell_x: Number(rect?.cellX) || 0,
      cell_y: Number(rect?.cellY) || 0,
      cell_w: Number(rect?.cellW) || 0,
      cell_h: Number(rect?.cellH) || 0,
    }));
  }

  const images = state.images.map((item) => ({
    id: String(item?.id || ""),
    kind: item?.kind ? String(item.kind) : null,
    source: item?.source ? String(item.source) : "user",
    path: item?.path ? String(item.path) : null,
    label: item?.label ? String(item.label) : null,
    width: Number(item?.img?.naturalWidth || item?.width) || null,
    height: Number(item?.img?.naturalHeight || item?.height) || null,
    // Optional vision-side description of the image contents (e.g., "couch").
    // This is written for run trace/debugging only; intent inference remains images-only.
    vision_desc: item?.visionDesc ? String(item.visionDesc) : null,
    vision_desc_meta: item?.visionDescMeta
      ? {
          source: item.visionDescMeta?.source ? String(item.visionDescMeta.source) : null,
          model: item.visionDescMeta?.model ? String(item.visionDescMeta.model) : null,
          at_ms: Number(item.visionDescMeta?.at) || null,
        }
      : null,
  }));

  const marks = [];

  // Lasso polygon (active image only).
  if (active?.id && state.selection?.points?.length >= 3) {
    const atMs = Number(state.selection?.at) || Date.now();
    marks.push({
      id: `lasso-${atMs}`,
      type: "lasso_polygon",
      color: "rgba(255, 179, 0, 0.95)",
      label: null,
      target_image_id: String(active.id),
      image_space: {
        points: state.selection.points.map((pt) => ({
          x: Number(pt?.x) || 0,
          y: Number(pt?.y) || 0,
        })),
      },
      created_at: isoFromMs(atMs),
    });
  }

  // Annotate box (draft/final, active image only).
  if (active?.id && state.annotateBox && state.annotateBox.imageId === active.id) {
    const atMs = Number(state.annotateBox?.at) || Date.now();
    const label = String(els.annotateText?.value || "").trim() || null;
    marks.push({
      id: `box-${atMs}`,
      type: "box",
      color: "rgba(82, 255, 148, 0.92)",
      label,
      target_image_id: String(active.id),
      image_space: {
        x0: Number(state.annotateBox?.x0) || 0,
        y0: Number(state.annotateBox?.y0) || 0,
        x1: Number(state.annotateBox?.x1) || 0,
        y1: Number(state.annotateBox?.y1) || 0,
      },
      created_at: isoFromMs(atMs),
    });
  }

  // Circles.
  for (const [imageId, list] of Array.from(state.circlesByImageId.entries())) {
    const imageKey = String(imageId || "");
    if (!imageKey || !Array.isArray(list)) continue;
    for (const circle of list) {
      const atMs = Number(circle?.at) || Date.now();
      marks.push({
        id: String(circle?.id || `c-${atMs}`),
        type: "circle",
        color: circle?.color ? String(circle.color) : "rgba(255, 95, 95, 0.92)",
        label: circle?.label ? String(circle.label) : null,
        target_image_id: imageKey,
        image_space: {
          cx: Number(circle?.cx) || 0,
          cy: Number(circle?.cy) || 0,
          r: Number(circle?.r) || 0,
        },
        created_at: isoFromMs(atMs),
      });
    }
  }

  return {
    schema: "cue.visual_prompt",
    schema_version: VISUAL_PROMPT_SCHEMA_VERSION,
    visual_grammar_version: VISUAL_GRAMMAR_VERSION,
    updated_at: nowIso,
    run_dir: state.runDir ? String(state.runDir) : null,
    canvas: {
      mode: state.canvasMode,
      dpr,
      size_px: canvas ? { w: canvas.width || 0, h: canvas.height || 0 } : null,
      tool: state.tool,
      active_image_id: state.activeId ? String(state.activeId) : null,
      view: {
        scale: Number(state.view?.scale) || 1,
        offset_x: Number(state.view?.offsetX) || 0,
        offset_y: Number(state.view?.offsetY) || 0,
      },
      multi_view: {
        scale: Number(state.multiView?.scale) || 1,
        offset_x: Number(state.multiView?.offsetX) || 0,
        offset_y: Number(state.multiView?.offsetY) || 0,
      },
      multi_rects_px: multiRects,
    },
    images,
    marks,
  };
}

async function writeVisualPrompt() {
  if (!state.runDir) return false;
  const outPath = `${state.runDir}/${VISUAL_PROMPT_FILENAME}`;
  const payload = buildVisualPrompt();
  await writeTextFile(outPath, JSON.stringify(payload, null, 2));
  return true;
}

function _defaultImportPointCss() {
  const wrap = els.canvasWrap;
  const w = wrap?.clientWidth || 0;
  const h = wrap?.clientHeight || 0;
  return { x: Math.round(w * 0.5), y: Math.round(h * 0.5) };
}

function visibleImportWorldBoundsCss(canvasCssW, canvasCssH) {
  const width = Math.max(0, Number(canvasCssW) || 0);
  const height = Math.max(0, Number(canvasCssH) || 0);
  if (state.canvasMode !== "multi") {
    return {
      minX: 0,
      minY: 0,
      maxX: width,
      maxY: height,
    };
  }
  const topLeft = canvasScreenCssToWorldCss({ x: 0, y: 0 });
  const bottomRight = canvasScreenCssToWorldCss({ x: width, y: height });
  const x0 = Number(topLeft?.x) || 0;
  const y0 = Number(topLeft?.y) || 0;
  const x1 = Number(bottomRight?.x) || 0;
  const y1 = Number(bottomRight?.y) || 0;
  return {
    minX: Math.min(x0, x1),
    minY: Math.min(y0, y1),
    maxX: Math.max(x0, x1),
    maxY: Math.max(y0, y1),
  };
}

function _computeImportPlacementsCss(n, center, tile, gap, canvasCssW, canvasCssH, worldBounds = null) {
  const count = Math.max(0, Number(n) || 0);
  if (!count) return [];
  const margin = 14;
  const bounds = worldBounds && typeof worldBounds === "object"
    ? worldBounds
    : {
        minX: 0,
        minY: 0,
        maxX: Number(canvasCssW) || 0,
        maxY: Number(canvasCssH) || 0,
      };
  const minX = Math.round(Number(bounds.minX) || 0);
  const minY = Math.round(Number(bounds.minY) || 0);
  const maxWorldX = Math.round(Number(bounds.maxX) || 0);
  const maxWorldY = Math.round(Number(bounds.maxY) || 0);
  let cols = 1;
  if (count <= 1) cols = 1;
  else if (count === 2) cols = 2;
  else if (count <= 4) cols = 2;
  else cols = 3;
  const rows = Math.ceil(count / cols);
  const clusterW = cols * tile + (cols - 1) * gap;
  const clusterH = rows * tile + (rows - 1) * gap;
  const startMinX = minX + margin;
  const startMinY = minY + margin;
  const startMaxX = Math.max(startMinX, maxWorldX - clusterW - margin);
  const startMaxY = Math.max(startMinY, maxWorldY - clusterH - margin);
  const startX = clamp(Math.round((Number(center?.x) || 0) - clusterW / 2), startMinX, startMaxX);
  const startY = clamp(Math.round((Number(center?.y) || 0) - clusterH / 2), startMinY, startMaxY);
  const out = [];
  for (let i = 0; i < count; i += 1) {
    const col = i % cols;
    const row = Math.floor(i / cols);
    out.push({
      x: Math.round(startX + col * (tile + gap)),
      y: Math.round(startY + row * (tile + gap)),
      w: tile,
      h: tile,
    });
  }
  return out;
}

function seedPromptGeneratePlacementRectCss(artifactId, pendingPromptGenerate = null) {
  const id = String(artifactId || "").trim();
  if (!id || state.freeformRects.has(id)) return;

  const wrap = els.canvasWrap;
  const canvasCssW = Number(wrap?.clientWidth) || 0;
  const canvasCssH = Number(wrap?.clientHeight) || 0;
  if (!(canvasCssW > 0 && canvasCssH > 0)) return;

  const totalAfter = (state.images?.length || 0) + 1;
  const tile = freeformDefaultTileCss(canvasCssW, canvasCssH, { count: Math.max(1, totalAfter) });
  const anchorWorldCss = pendingPromptGenerate?.anchorWorldCss
    ? {
        x: Number(pendingPromptGenerate.anchorWorldCss.x) || 0,
        y: Number(pendingPromptGenerate.anchorWorldCss.y) || 0,
      }
    : canvasScreenCssToWorldCss(currentPromptGenerateAnchorCss(pendingPromptGenerate?.anchorCss || null));
  const rect = clampFreeformRectCss(
    {
      x: Math.round((Number(anchorWorldCss.x) || 0) - tile / 2),
      y: Math.round((Number(anchorWorldCss.y) || 0) - tile / 2),
      w: tile,
      h: tile,
      autoAspect: true,
    },
    canvasCssW,
    canvasCssH,
    freeformWorkspaceClampOptions(canvasCssW, canvasCssH, { minSize: 44 })
  );
  state.freeformRects.set(id, rect);
}

async function importLocalPathsAtCanvasPoint(
  paths,
  pointWorldCss,
  { source = "picker", idPrefix = "input", enforceIntentLimit = true, focusImported = false } = {}
) {
  let list = (Array.isArray(paths) ? paths : [paths])
    .map((v) => normalizeLocalFsPath(typeof v === "string" ? v : ""))
    .filter(Boolean);
  if (String(source || "").startsWith("browser")) {
    try {
      list = await fileBrowserResolveImportPaths(list);
    } catch {
      // keep original list on resolver errors
    }
  }
  if (!list.length) {
    setStatus("Engine: ready");
    return { ok: 0, failed: 0, importedIds: [] };
  }

  const INTENT_MAX_PHOTOS = 5;
  const intentActive = intentModeActive();
  let importable = list.filter((path) => isBrowserImagePath(path));
  if (enforceIntentLimit && intentActive) {
    const remaining = Math.max(0, INTENT_MAX_PHOTOS - (state.images?.length || 0));
    if (remaining <= 0) {
      showToast(`Intent Mode: only ${INTENT_MAX_PHOTOS} photos allowed.`, "tip", 2600);
      setStatus("Engine: ready");
      return { ok: 0, failed: 0, importedIds: [] };
    }
    if (importable.length > remaining) {
      importable = importable.slice(0, remaining);
      showToast(`Intent Mode: only ${INTENT_MAX_PHOTOS} photos allowed.`, "tip", 2600);
    }
  }
  if (!importable.length) {
    setStatus("Engine: ready");
    return { ok: 0, failed: 0, importedIds: [] };
  }

  await ensureRun();
  const inputsDir = `${state.runDir}/inputs`;
  await createDir(inputsDir, { recursive: true }).catch(() => {});
  const stamp = Date.now();

  const wrap = els.canvasWrap;
  const canvasCssW = wrap?.clientWidth || 0;
  const canvasCssH = wrap?.clientHeight || 0;
  const totalAfter = (state.images?.length || 0) + importable.length;
  const tile = freeformDefaultTileCss(canvasCssW, canvasCssH, { count: totalAfter });
  const gap = Math.round(tile * 0.11);
  const visibleBounds = visibleImportWorldBoundsCss(canvasCssW, canvasCssH);
  const placements = _computeImportPlacementsCss(
    importable.length,
    pointWorldCss,
    tile,
    gap,
    canvasCssW,
    canvasCssH,
    visibleBounds
  );

  let ok = 0;
  let failed = 0;
  let lastErr = null;
  const importedIds = [];
  for (let idx = 0; idx < importable.length; idx += 1) {
    const src = importable[idx];
    try {
      const ext = extname(src);
      const safeExt = ext && ext.length <= 8 ? ext : ".png";
      const artifactId = `${idPrefix}-${stamp}-${String(idx).padStart(2, "0")}`;
      const dest = `${inputsDir}/${artifactId}${safeExt}`;
      const place = placements[idx] || null;
      if (place && artifactId) {
        state.freeformRects.set(artifactId, { ...place, autoAspect: true });
      }
      await copyFile(src, dest);
      const receiptPath = await writeLocalReceipt({
        artifactId,
        imagePath: dest,
        operation: "import",
        meta: { source_path: src, source },
      });
      addImage(
        {
          id: artifactId,
          kind: "import",
          path: dest,
          receiptPath,
          label: basename(src),
        },
        { select: focusImported ? ok === 0 : ok === 0 && !state.activeId }
      );
      importedIds.push(artifactId);
      ok += 1;
    } catch (err) {
      failed += 1;
      lastErr = err;
      console.error("Import failed:", src, err);
    }
  }

  if (ok <= 0) {
    const msg = lastErr?.message || String(lastErr || "unknown error");
    setStatus(`Engine: import failed (${msg})`, true);
    return { ok, failed, importedIds };
  }

  maybeEmitFirstImportOk({
    source: String(source || "unknown"),
    imported_count: ok,
    failed_count: failed,
  });

  const suffix = failed ? ` (${failed} failed)` : "";
  setStatus(`Engine: imported ${ok} photo${ok === 1 ? "" : "s"}${suffix}`, failed > 0);

  if (state.images.length > 1 && state.canvasMode !== "multi") {
    setCanvasMode("multi");
    if (!intentActive) {
      setTip("Multiple photos loaded. Click a photo to focus it. Press M to toggle multi view.");
    }
  }
  if (intentActive && !state.intent.startedAt) {
    state.intent.startedAt = Date.now();
    state.intent.deadlineAt = state.intent.startedAt + INTENT_DEADLINE_MS;
    state.intent.rtState = "connecting";
    ensureIntentTicker();
  }
  if (intentActive) {
    updateEmptyCanvasHint();
    scheduleIntentInference({ immediate: true, reason: "import" });
    scheduleIntentStateWrite({ immediate: true });
  }
  requestRender();
  return { ok, failed, importedIds };
}

async function importPhotosAtCanvasPoint(pointWorldCss) {
  bumpInteraction();
  setStatus("Engine: pick photos…");
  const picked = await open({
    multiple: true,
    filters: [{ name: "Images", extensions: ["png", "jpg", "jpeg", "webp", "heic"] }],
  });
  const pickedPaths = Array.isArray(picked) ? picked : picked ? [picked] : [];
  if (!pickedPaths.length) {
    setStatus("Engine: ready");
    return;
  }
  await importLocalPathsAtCanvasPoint(pickedPaths, pointWorldCss, {
    source: "picker",
    idPrefix: "input",
    enforceIntentLimit: true,
  });
}

async function importPhotos() {
  await importPhotosAtCanvasPoint(canvasScreenCssToWorldCss(_defaultImportPointCss()));
}

async function cropSquare({ fromQueue = false } = {}) {
  if (!requireIntentUnlocked()) return;
  bumpInteraction();
  if (!fromQueue && (isEngineBusy() || state.actionQueueActive || state.actionQueue.length)) {
    enqueueAction({
      label: "Crop: Square",
      key: "crop_square",
      priority: ACTION_QUEUE_PRIORITY.user,
      run: () => cropSquare({ fromQueue: true }),
    });
    return;
  }
  state.lastAction = "Square Crop";
  const imgItem = getActiveImage();
  if (!imgItem || !imgItem.img) return;
  await ensureRun();
  beginRunningAction("crop_square");
  setImageFxActive(true, "Square Crop");
  portraitWorking("Square Crop");
  try {
    const img = imgItem.img;
    const w = img.naturalWidth;
    const h = img.naturalHeight;
    const size = Math.min(w, h);
    const sx = Math.floor((w - size) / 2);
    const sy = Math.floor((h - size) / 2);
    const canvas = document.createElement("canvas");
    canvas.width = size;
    canvas.height = size;
    const ctx = canvas.getContext("2d");
    ctx.drawImage(img, sx, sy, size, size, 0, 0, size, size);
    await saveCanvasAsArtifact(canvas, {
      operation: "crop_square",
      label: "Square crop",
      replaceActive: true,
      targetId: imgItem.id,
    });
  } finally {
    setImageFxActive(false);
    updatePortraitIdle();
    clearRunningAction("crop_square");
  }
}

async function aiReplaceBackground(style) {
  const imgItem = getActiveImage();
  if (!imgItem) {
    showToast("No image selected.", "error");
    return;
  }
  await ensureRun();
  const label = style === "sweep" ? "Soft Sweep" : "Studio White";
  setImageFxActive(true, label);
  portraitWorking(label, { providerOverride: providerFromModel(ACTION_IMAGE_MODEL.bg_replace) });
  beginPendingReplace(imgItem.id, label);
  try {
    const ok = await ensureEngineSpawned({ reason: label });
    if (!ok) throw new Error("Engine unavailable");
    await setEngineActiveImage(imgItem.path);
    await maybeOverrideEngineImageModel(ACTION_IMAGE_MODEL.bg_replace);
    state.expectingArtifacts = true;
    state.lastAction = label;
    setStatus(`Engine: ${label}…`);
    showToast(`Morphing: ${label}`, "info", 2200);

    // Must start with "replace" for Cue's edit detection.
    const prompt =
      style === "sweep"
        ? "replace the background with a soft studio sweep background. keep the subject exactly the same. preserve logos and text. do not crop."
        : "replace the background with a seamless studio white background. keep the subject exactly the same. preserve logos and text. do not crop.";
    await invoke("write_pty", { data: `${prompt}\n` });
  } catch (err) {
    clearPendingReplace();
    setImageFxActive(false);
    updatePortraitIdle();
    throw err;
  }
}

