async function aiAnnotateEdit({
  fromQueue = false,
  targetId = null,
  boxOverride = null,
  instructionOverride = null,
  requestedModelOverride = null,
} = {}) {
  if (!requireIntentUnlocked()) return;
  bumpInteraction();
  const activeItem = getActiveImage();
  const imgItem = targetId ? state.imagesById.get(targetId) || null : activeItem;
  if (!imgItem) {
    showToast("No image selected.", "error");
    return;
  }

  const box = boxOverride || state.annotateBox;
  if (!box || box.imageId !== imgItem.id) {
    showToast("Annotate: draw a box first.", "tip", 2200);
    return;
  }

  const instruction =
    typeof instructionOverride === "string"
      ? instructionOverride.trim()
      : String(els.annotateText?.value || "").trim();
  if (!instruction) {
    showToast("Annotate: enter an instruction.", "tip", 2200);
    return;
  }

  const requestedModel =
    typeof requestedModelOverride === "string"
      ? requestedModelOverride.trim()
      : String(els.annotateModel?.value || settings.imageModel || "").trim();

  if (!fromQueue && (isEngineBusy() || state.actionQueueActive || state.actionQueue.length)) {
    const captured = {
      targetId: imgItem.id,
      box: { ...box },
      instruction,
      requestedModel,
    };

    // Mirror the "send" UX: clear the box + prompt input immediately, even if queued.
    if (els.annotateText) els.annotateText.value = "";
    state.annotateBox = null;
    state.annotateDraft = null;
    hideAnnotatePanel();
    scheduleVisualPromptWrite();
    requestRender();

    enqueueAction({
      label: "Annotate",
      key: `annotate:${captured.targetId}`,
      priority: ACTION_QUEUE_PRIORITY.user,
      run: () =>
        aiAnnotateEdit({
          fromQueue: true,
          targetId: captured.targetId,
          boxOverride: captured.box,
          instructionOverride: captured.instruction,
          requestedModelOverride: captured.requestedModel,
        }),
    });
    return;
  }

  // Keep the target image visible when replaying queued edits.
  if (state.activeId !== imgItem.id) {
    await setActiveImage(imgItem.id).catch(() => {});
  }

  let effectiveModel = requestedModel || settings.imageModel;
  if (providerFromModel(effectiveModel) !== "gemini") {
    effectiveModel = pickGeminiImageModel();
    if (!fromQueue) {
      showToast(`Annotate box edits currently require Gemini. Using ${effectiveModel}.`, "tip", 3200);
    }
  }
  const provider = providerFromModel(effectiveModel);
  const label = "Annotate";
  await ensureRun();
  setImageFxActive(true, label);
  portraitWorking(label, { providerOverride: provider });
  try {
    const ok = await ensureEngineSpawned({ reason: label });
    if (!ok) throw new Error("Engine unavailable");

    if (!imgItem.img) {
      setStatus("Engine: loading image…");
      try {
        imgItem.img = await loadImage(imgItem.path);
        imgItem.width = imgItem.img?.naturalWidth || imgItem.width || null;
        imgItem.height = imgItem.img?.naturalHeight || imgItem.height || null;
      } catch (err) {
        showToast("Failed to load image.", "error", 3200);
        setStatus("Engine: ready");
        return;
      }
      setStatus("Engine: ready");
    }

    const normalized = _normalizeAnnotateBox(box, imgItem);
    if (!normalized) {
      showToast("Annotate: invalid box.", "error", 2600);
      return;
    }
    const x0 = Math.floor(Number(normalized.x0) || 0);
    const y0 = Math.floor(Number(normalized.y0) || 0);
    const x1 = Math.ceil(Number(normalized.x1) || 0);
    const y1 = Math.ceil(Number(normalized.y1) || 0);
    const wBox = Math.max(1, x1 - x0);
    const hBox = Math.max(1, y1 - y0);
    if (wBox < 8 || hBox < 8) {
      showToast("Annotate: box too small.", "tip", 2200);
      return;
    }

    // Crop the selection region so the model can only edit what's inside the box.
    const cropCanvas = document.createElement("canvas");
    cropCanvas.width = wBox;
    cropCanvas.height = hBox;
    const cropCtx = cropCanvas.getContext("2d");
    cropCtx.drawImage(imgItem.img, x0, y0, wBox, hBox, 0, 0, wBox, hBox);
    const cropPath = `${state.runDir}/tmp-annotate-crop-${Date.now()}-${Math.random().toString(16).slice(2)}.png`;
    await writeCanvasPngToPath(cropCanvas, cropPath);

    beginPendingReplace(imgItem.id, label, {
      mode: "annotate_box",
      basePath: imgItem.path,
      box: { x0, y0, x1, y1, w: wBox, h: hBox },
      cropPath,
      instruction,
    });

    // Point the engine at the cropped image so "edit the image" edits the crop.
    await invoke("write_pty", { data: `${PTY_COMMANDS.USE} ${quoteForPtyArg(cropPath)}\n` }).catch(() => {});

    state.expectingArtifacts = true;
    state.lastAction = label;
    setStatus(`Engine: ${label}…`);
    showToast("Annotate: editing…", "info", 2200);

    if (state.ptySpawned && effectiveModel && effectiveModel !== settings.imageModel) {
      state.engineImageModelRestore = settings.imageModel;
      await invoke("write_pty", { data: `${PTY_COMMANDS.IMAGE_MODEL} ${effectiveModel}\n` }).catch(() => {});
    }

    // Must start with "edit" or "replace" for Cue's edit detection.
    const prompt =
      `edit the image: ${instruction}\n` +
      "Output ONE image. No split-screen or collage. Do not add any text or logos. Do not crop.";
    await invoke("write_pty", { data: `${prompt}\n` });

    // Clear UI selection now that the instruction is sent.
    if (els.annotateText) els.annotateText.value = "";
    state.annotateBox = null;
    state.annotateDraft = null;
    hideAnnotatePanel();
    scheduleVisualPromptWrite();
    requestRender();
  } catch (err) {
    state.expectingArtifacts = false;
    state.engineImageModelRestore = null;
    clearPendingReplace();
    setImageFxActive(false);
    updatePortraitIdle();
    throw err;
  }
}

async function compositeAnnotateBoxEdit(targetId, editedCropPath, { box, instruction = null } = {}) {
  if (!targetId || !editedCropPath || !box) return false;
  const item = state.imagesById.get(targetId) || null;
  if (!item?.path) return false;

  // Ensure base + crop images are loaded.
  if (!item.img) {
    try {
      item.img = await loadImage(item.path);
      item.width = item.img?.naturalWidth || item.width || null;
      item.height = item.img?.naturalHeight || item.height || null;
    } catch (err) {
      console.error("Annotate composite failed to load base image:", err);
      return false;
    }
  }

  let cropImg = null;
  try {
    cropImg = await loadImage(editedCropPath);
  } catch (err) {
    console.error("Annotate composite failed to load crop image:", err);
    return false;
  }

  const baseImg = item.img;
  const bw = baseImg?.naturalWidth || item.width || 1;
  const bh = baseImg?.naturalHeight || item.height || 1;
  const out = document.createElement("canvas");
  out.width = bw;
  out.height = bh;
  const ctx = out.getContext("2d");
  ctx.drawImage(baseImg, 0, 0);
  ctx.drawImage(cropImg, Number(box.x0) || 0, Number(box.y0) || 0, Number(box.w) || 1, Number(box.h) || 1);

  await saveCanvasAsArtifact(out, {
    operation: "annotate_box",
    label: "Annotate",
    meta: {
      instruction: instruction ? String(instruction) : null,
      box,
      edited_crop_path: String(editedCropPath),
    },
    replaceActive: true,
    targetId,
  });
  return true;
}

async function applyBackground(style, { fromQueue = false } = {}) {
  if (!requireIntentUnlocked()) return;
  bumpInteraction();
  if (!fromQueue && (isEngineBusy() || state.actionQueueActive || state.actionQueue.length)) {
    const label = style === "sweep" ? "Background: Sweep" : "Background: White";
    enqueueAction({
      label,
      key: `bg:${String(style || "")}`,
      priority: ACTION_QUEUE_PRIORITY.user,
      run: () => applyBackground(style, { fromQueue: true }),
    });
    return;
  }
  const imgItem = getActiveImage();
  if (!imgItem) {
    showToast("No image selected.", "error");
    return;
  }
  if (!imgItem.img) {
    setStatus("Engine: loading image…");
    try {
      imgItem.img = await loadImage(imgItem.path);
    } catch (err) {
      showToast("Failed to load image.", "error");
      setStatus("Engine: ready");
      return;
    }
    setStatus("Engine: ready");
  }
  // If the user hasn't lassoed, fall back to model-powered background replacement.
  if (!state.selection || !state.selection.points || state.selection.points.length < 3) {
    await aiReplaceBackground(style);
    return;
  }
  const label = style === "sweep" ? "Soft Sweep" : "Studio White";
  state.lastAction = `${label} (local)`;
  await ensureRun();
  beginRunningAction("bg");
  setImageFxActive(true, label);
  portraitWorking(label);
  try {
    const img = imgItem.img;
    const w = img.naturalWidth;
    const h = img.naturalHeight;

    const fgCanvas = document.createElement("canvas");
    fgCanvas.width = w;
    fgCanvas.height = h;
    const fgCtx = fgCanvas.getContext("2d");
    fgCtx.drawImage(img, 0, 0);

    // Build polygon mask in image pixel space.
    const maskCanvas = document.createElement("canvas");
    maskCanvas.width = w;
    maskCanvas.height = h;
    const maskCtx = maskCanvas.getContext("2d");
    maskCtx.clearRect(0, 0, w, h);
    maskCtx.fillStyle = "#fff";
    maskCtx.beginPath();
    const pts = state.selection.points;
    maskCtx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i += 1) {
      maskCtx.lineTo(pts[i].x, pts[i].y);
    }
    maskCtx.closePath();
    maskCtx.fill();

    fgCtx.globalCompositeOperation = "destination-in";
    fgCtx.drawImage(maskCanvas, 0, 0);
    fgCtx.globalCompositeOperation = "source-over";

    const out = document.createElement("canvas");
    out.width = w;
    out.height = h;
    const outCtx = out.getContext("2d");
    if (style === "sweep") {
      const g = outCtx.createLinearGradient(0, 0, 0, h);
      g.addColorStop(0, "#ffffff");
      g.addColorStop(1, "#e9eef5");
      outCtx.fillStyle = g;
    } else {
      outCtx.fillStyle = "#ffffff";
    }
    outCtx.fillRect(0, 0, w, h);
    outCtx.drawImage(fgCanvas, 0, 0);

    await saveCanvasAsArtifact(out, {
      operation: "bg_replace",
      label: style === "sweep" ? "BG sweep" : "BG white",
      meta: { style, selection_points: pts.length },
      replaceActive: true,
      targetId: imgItem.id,
    });
    clearSelection();
    chooseSpawnNodes();
  } finally {
    setImageFxActive(false);
    updatePortraitIdle();
    clearRunningAction("bg");
  }
}

async function writeCanvasPngToPath(canvas, outPath) {
  const blob = await new Promise((resolve) => canvas.toBlob(resolve, "image/png"));
  if (!blob) throw new Error("Failed to encode PNG");
  const buf = new Uint8Array(await blob.arrayBuffer());
  await writeBinaryFile(outPath, buf);
  return outPath;
}

const EXPORT_DIR_LS_KEY = "juggernaut.exportDir";

function readStoredExportDirectory() {
  try {
    const value = localStorage.getItem(EXPORT_DIR_LS_KEY);
    return value ? String(value).trim() || null : null;
  } catch {
    return null;
  }
}

function storeExportDirectory(dir) {
  const normalized = String(dir || "").trim();
  if (!normalized) return;
  try {
    localStorage.setItem(EXPORT_DIR_LS_KEY, normalized);
  } catch {
    // ignore storage access failures
  }
}

async function resolveDefaultExportDirectory() {
  const candidates = [];
  const storedDir = readStoredExportDirectory();
  if (storedDir) candidates.push(storedDir);
  const runDir = String(state.runDir || "").trim();
  if (runDir) candidates.push(runDir);
  const home = await homeDir().catch(() => "");
  if (home) candidates.push(String(home).trim());
  for (const candidate of candidates) {
    if (!candidate) continue;
    if (await exists(candidate).catch(() => false)) return candidate;
  }
  return candidates.find(Boolean) || null;
}

function normalizeExportPathExtension(path, extension) {
  const normalizedPath = String(path || "").trim();
  const normalizedExtension = String(extension || "").trim().toLowerCase();
  if (!normalizedPath || !normalizedExtension) return normalizedPath;
  const currentExt = extname(normalizedPath);
  if (currentExt === normalizedExtension) return normalizedPath;
  if (currentExt) return `${normalizedPath.slice(0, -currentExt.length)}${normalizedExtension}`;
  return `${normalizedPath}${normalizedExtension}`;
}

function normalizeExportFormat(format = "psd") {
  const normalized = String(format || "psd").trim().toLowerCase();
  if (normalized === "png") return "png";
  if (normalized === "jpg" || normalized === "jpeg") return "jpg";
  if (normalized === "webp") return "webp";
  if (normalized === "tif" || normalized === "tiff") return "tiff";
  return "psd";
}

function exportFormatExtension(format = "psd") {
  const normalized = normalizeExportFormat(format);
  if (normalized === "png") return ".png";
  if (normalized === "jpg") return ".jpg";
  if (normalized === "webp") return ".webp";
  if (normalized === "tiff") return ".tiff";
  return ".psd";
}

function exportFormatFilterExtensions(format = "psd") {
  const normalized = normalizeExportFormat(format);
  if (normalized === "jpg") return ["jpg", "jpeg"];
  if (normalized === "tiff") return ["tiff", "tif"];
  return [exportFormatExtension(normalized).replace(".", "")];
}

function exportFormatLabel(format = "psd") {
  const normalized = normalizeExportFormat(format);
  if (normalized === "png") return "PNG";
  if (normalized === "jpg") return "JPG";
  if (normalized === "webp") return "WEBP";
  if (normalized === "tiff") return "TIFF";
  return "PSD";
}

function exportFormatTitle(format = "psd") {
  const normalized = normalizeExportFormat(format);
  if (normalized === "psd") return "Export Photoshop (.psd)";
  return `Export ${exportFormatLabel(normalized)} (${exportFormatExtension(normalized)})`;
}

function exportFormatUnavailableMessage(format = "psd") {
  return `${exportFormatLabel(format)} export is unavailable in this runtime.`;
}

function exportFormatActionKey(format = "psd") {
  return `export_${normalizeExportFormat(format)}`;
}

function nativeRasterExportReady() {
  return typeof invoke === "function" && typeof writeBinaryFile === "function";
}

async function chooseExportDestinationPath({ format = "psd", suggestedStem = "canvas", stamp = "" } = {}) {
  const normalizedFormat = normalizeExportFormat(format);
  const extension = exportFormatExtension(normalizedFormat);
  const label = exportFormatLabel(normalizedFormat);
  setStatus(`Engine: choose ${label} export file…`);
  const defaultDir = await resolveDefaultExportDirectory();
  const suggestedName = `export-${exportBaseStem(suggestedStem)}-${String(stamp || exportTimestampTag())}${extension}`;
  const defaultPath = defaultDir
    ? (await join(defaultDir, suggestedName).catch(() => "")) || `${defaultDir}/${suggestedName}`
    : suggestedName;
  const picked = await save({
    defaultPath,
    filters: [{ name: label, extensions: exportFormatFilterExtensions(normalizedFormat) }],
  });
  const selectedPath = Array.isArray(picked) ? picked[0] : picked;
  const normalizedPath = normalizeExportPathExtension(selectedPath, extension);
  if (!normalizedPath) {
    setStatus("Engine: ready");
    return null;
  }
  const exportDir = typeof dirname === "function" ? await dirname(normalizedPath).catch(() => "") : "";
  if (exportDir) storeExportDirectory(exportDir);
  return normalizedPath;
}

function exportTimestampTag(date = new Date()) {
  const year = String(date.getFullYear() || 0).padStart(4, "0");
  const month = String((date.getMonth() || 0) + 1).padStart(2, "0");
  const day = String(date.getDate() || 0).padStart(2, "0");
  const hours = String(date.getHours() || 0).padStart(2, "0");
  const minutes = String(date.getMinutes() || 0).padStart(2, "0");
  const seconds = String(date.getSeconds() || 0).padStart(2, "0");
  return `${year}${month}${day}T${hours}${minutes}${seconds}`;
}

function exportBaseStem(value = "canvas") {
  const base = basename(value).replace(/\.[^.]+$/, "");
  const slug = String(base || "canvas")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 48);
  return slug || "canvas";
}

function exportPsdLimitations() {
  return [
    "Same-day PSD export is flattened to a single bitmap layer stack with alpha, not fully editable per-source PSD layers.",
    "Canvas transform fidelity is preserved in the flattened composite, but PSD re-editability for masks, effect tokens, and tool semantics is not included in this slice.",
    "Export pixel dimensions currently follow Cue canvas world geometry in CSS pixels rather than preserving source DPI metadata.",
  ];
}

function exportPngLimitations() {
  return [
    "PNG export is flattened to a single bitmap composition with alpha and does not preserve editable layers, masks, or tool semantics.",
    "Canvas transform fidelity is preserved in the flattened composite, but source DPI metadata is not currently retained.",
  ];
}

function exportRasterFormatLimitations(format = "png") {
  const normalized = normalizeExportFormat(format);
  if (normalized === "jpg") {
    return [
      "JPG export is flattened to a single bitmap composition and composites transparent pixels onto white rather than preserving alpha.",
      "Canvas transform fidelity is preserved in the flattened composite, but editable layers, masks, tool semantics, and source DPI metadata are not currently retained.",
    ];
  }
  if (normalized === "webp") {
    return [
      "WEBP export is flattened to a single bitmap composition with alpha and does not preserve editable layers, masks, or tool semantics.",
      "Canvas transform fidelity is preserved in the flattened composite, but source DPI metadata is not currently retained.",
    ];
  }
  if (normalized === "tiff") {
    return [
      "TIFF export is flattened to a single bitmap composition with alpha and does not preserve editable layers, masks, or tool semantics.",
      "Canvas transform fidelity is preserved in the flattened composite, but source DPI metadata is not currently retained.",
    ];
  }
  return exportPngLimitations();
}

function polygonBounds(points = []) {
  let minX = Number.POSITIVE_INFINITY;
  let minY = Number.POSITIVE_INFINITY;
  let maxX = Number.NEGATIVE_INFINITY;
  let maxY = Number.NEGATIVE_INFINITY;
  for (const point of Array.isArray(points) ? points : []) {
    const x = Number(point?.x);
    const y = Number(point?.y);
    if (!Number.isFinite(x) || !Number.isFinite(y)) continue;
    if (x < minX) minX = x;
    if (y < minY) minY = y;
    if (x > maxX) maxX = x;
    if (y > maxY) maxY = y;
  }
  if (!Number.isFinite(minX) || !Number.isFinite(minY) || !Number.isFinite(maxX) || !Number.isFinite(maxY)) {
    return null;
  }
  return { minX, minY, maxX, maxY };
}

function collectExportTimelineNodes() {
  const headNodeId = String(state.timelineHeadNodeId || "").trim();
  return timelineSortedNodes(state.timelineNodes)
    .map((node) => ({
      nodeId: node?.nodeId ? String(node.nodeId) : null,
      seq: Math.max(1, Number(node?.seq) || 1),
      kind: node?.kind ? String(node.kind) : null,
      imageId:
        Array.isArray(node?.imageIds) && node.imageIds.length
          ? String(node.imageIds[node.imageIds.length - 1] || "")
          : node?.previewImageId
            ? String(node.previewImageId)
            : node?.imageId
              ? String(node.imageId)
            : null,
      path: node?.previewPath ? String(node.previewPath) : node?.path ? String(node.path) : null,
      receiptPath:
        Array.isArray(node?.receiptPaths) && node.receiptPaths.length
          ? String(node.receiptPaths[node.receiptPaths.length - 1] || "")
          : node?.receiptPath
            ? String(node.receiptPath)
          : null,
      label: node?.label ? String(node.label) : null,
      action: node?.action ? String(node.action) : null,
      parents: Array.isArray(node?.parents) ? node.parents.map((parent) => String(parent || "")).filter(Boolean) : [],
      imageIds: Array.isArray(node?.imageIds) ? node.imageIds.map((imageId) => String(imageId || "")).filter(Boolean) : [],
      previewImageId: node?.previewImageId ? String(node.previewImageId) : node?.imageId ? String(node.imageId) : null,
      previewPath: node?.previewPath ? String(node.previewPath) : node?.path ? String(node.path) : null,
      receiptPaths: Array.isArray(node?.receiptPaths)
        ? node.receiptPaths.map((path) => String(path || "")).filter(Boolean)
        : node?.receiptPath
          ? [String(node.receiptPath)]
          : [],
      visualMode: node?.visualMode ? String(node.visualMode) : null,
      detail: node?.detail ? String(node.detail) : null,
      isHead: headNodeId ? headNodeId === String(node?.nodeId || "") : false,
      createdAt: typeof node?.createdAt === "number" ? node.createdAt : null,
      createdAtIso: isoFromMs(node?.createdAt),
    }));
}

async function buildPsdExportComposite() {
  const visibleImages = getVisibleCanvasImages();
  if (!visibleImages.length) {
    throw new Error("No visible images on the canvas.");
  }

  const layers = [];
  if (state.canvasMode === "multi") {
    const drawOrder = Array.isArray(state.freeformZOrder) && state.freeformZOrder.length
      ? state.freeformZOrder
      : visibleImages.map((item) => item?.id).filter(Boolean);
    for (let index = 0; index < drawOrder.length; index += 1) {
      const imageId = String(drawOrder[index] || "").trim();
      if (!imageId || !isVisibleCanvasImageId(imageId)) continue;
      const item = state.imagesById.get(imageId) || null;
      if (!item?.path) continue;
      const img = readSessionRuntimeImageHandle(item) || await loadImage(item.path);
      const rect = state.freeformRects.get(imageId) || null;
      if (!img || !rect) continue;
      const transform = readFreeformRectTransform(rect);
      const x = Number(rect.x) || 0;
      const y = Number(rect.y) || 0;
      const w = Math.max(1, Number(rect.w) || img.naturalWidth || item.width || 1);
      const h = Math.max(1, Number(rect.h) || img.naturalHeight || item.height || 1);
      const polygon = transformedRectPolygonPoints({
        x,
        y,
        w,
        h,
        rotateDeg: transform.rotateDeg,
        skewXDeg: transform.skewXDeg,
      });
      layers.push({
        id: imageId,
        item,
        img,
        zIndex: index,
        x,
        y,
        w,
        h,
        rotateDeg: transform.rotateDeg,
        skewXDeg: transform.skewXDeg,
        polygon,
      });
    }
  } else {
    const item = getActiveImage() || visibleImages[0] || null;
    const img = readSessionRuntimeImageHandle(item) || (item?.path ? await loadImage(item.path) : null);
    if (item?.path && img) {
      const w = Math.max(1, img.naturalWidth || item.width || 1);
      const h = Math.max(1, img.naturalHeight || item.height || 1);
      layers.push({
        id: String(item.id || "active"),
        item,
        img,
        zIndex: 0,
        x: 0,
        y: 0,
        w,
        h,
        rotateDeg: 0,
        skewXDeg: 0,
        polygon: transformedRectPolygonPoints({ x: 0, y: 0, w, h }),
      });
    }
  }

  if (!layers.length) {
    throw new Error("No exportable images found.");
  }

  const paddingPx = 1;
  let minX = Number.POSITIVE_INFINITY;
  let minY = Number.POSITIVE_INFINITY;
  let maxX = Number.NEGATIVE_INFINITY;
  let maxY = Number.NEGATIVE_INFINITY;
  for (const layer of layers) {
    const bounds = polygonBounds(layer.polygon);
    if (!bounds) continue;
    minX = Math.min(minX, bounds.minX);
    minY = Math.min(minY, bounds.minY);
    maxX = Math.max(maxX, bounds.maxX);
    maxY = Math.max(maxY, bounds.maxY);
  }
  if (!Number.isFinite(minX) || !Number.isFinite(minY) || !Number.isFinite(maxX) || !Number.isFinite(maxY)) {
    throw new Error("Could not compute export bounds.");
  }

  const floorMinX = Math.floor(minX) - paddingPx;
  const floorMinY = Math.floor(minY) - paddingPx;
  const ceilMaxX = Math.ceil(maxX) + paddingPx;
  const ceilMaxY = Math.ceil(maxY) + paddingPx;
  const width = Math.max(1, ceilMaxX - floorMinX);
  const height = Math.max(1, ceilMaxY - floorMinY);
  const canvas = document.createElement("canvas");
  canvas.width = width;
  canvas.height = height;
  const ctx = canvas.getContext("2d", { alpha: true });
  if (!ctx) throw new Error("Failed to initialize export canvas.");
  ctx.clearRect(0, 0, width, height);
  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";

  for (const layer of layers) {
    drawImageRectWithTransform(ctx, layer.img, {
      x: layer.x - floorMinX,
      y: layer.y - floorMinY,
      w: layer.w,
      h: layer.h,
      rotateDeg: layer.rotateDeg,
      skewXDeg: layer.skewXDeg,
    });
  }

  return {
    canvas,
    width,
    height,
    boundsCss: {
      x: floorMinX,
      y: floorMinY,
      w: width,
      h: height,
    },
    sourceImages: layers.map((layer) => ({
      id: String(layer.id || ""),
      path: String(layer.item?.path || ""),
      receiptPath: layer.item?.receiptPath ? String(layer.item.receiptPath) : null,
      label: layer.item?.label ? String(layer.item.label) : basename(layer.item?.path),
      kind: layer.item?.kind ? String(layer.item.kind) : null,
      timelineNodeId: layer.item?.timelineNodeId ? String(layer.item.timelineNodeId) : null,
      width: Math.max(1, Number(layer.img?.naturalWidth) || Number(layer.item?.width) || 1),
      height: Math.max(1, Number(layer.img?.naturalHeight) || Number(layer.item?.height) || 1),
      zIndex: Number(layer.zIndex) || 0,
      rectCss: {
        x: Number(layer.x) || 0,
        y: Number(layer.y) || 0,
        w: Math.max(1, Number(layer.w) || 1),
        h: Math.max(1, Number(layer.h) || 1),
      },
      transform: {
        rotateDeg: Number(layer.rotateDeg) || 0,
        skewXDeg: Number(layer.skewXDeg) || 0,
      },
      sourceReceiptMeta:
        layer.item?.receiptMeta && typeof layer.item.receiptMeta === "object"
          ? { ...layer.item.receiptMeta }
          : null,
    })),
  };
}

function buildPsdExportRequest({ outPath, flattenedSourcePath, composite, format = "psd" }) {
  const normalizedFormat = normalizeExportFormat(format);
  const timelineNodes = collectExportTimelineNodes();
  const activeImageId = getVisibleActiveId() ? String(getVisibleActiveId()) : null;
  const screenshotPolish =
    state.communication?.screenshotPolish && typeof state.communication.screenshotPolish === "object"
      ? state.communication.screenshotPolish
      : null;
  const rawFrameContext =
    screenshotPolish?.frameContext && typeof screenshotPolish.frameContext === "object"
      ? JSON.parse(JSON.stringify(screenshotPolish.frameContext))
      : null;
  const frameContextTargetImageId =
    rawFrameContext && typeof rawFrameContext === "object"
      ? String(rawFrameContext.targetImageId || rawFrameContext.approvedFrame?.imageId || "").trim()
      : "";
  const frameContext =
    rawFrameContext && (!activeImageId || !frameContextTargetImageId || frameContextTargetImageId === activeImageId)
      ? rawFrameContext
      : null;
  const screenshotPolishTrace = frameContext
    ? {
        proposalId: String(screenshotPolish?.proposalId || "").trim() || null,
        selectedProposalId:
          String(screenshotPolish?.selectedProposalId || screenshotPolish?.proposalId || "").trim() || null,
        previewImagePath: String(screenshotPolish?.previewImagePath || "").trim() || null,
        changedRegionBounds:
          screenshotPolish?.changedRegionBounds && typeof screenshotPolish.changedRegionBounds === "object"
            ? JSON.parse(JSON.stringify(screenshotPolish.changedRegionBounds))
            : null,
        preserveRegionIds: Array.isArray(screenshotPolish?.preserveRegionIds)
          ? screenshotPolish.preserveRegionIds.map((value) => String(value || "").trim()).filter(Boolean)
          : [],
        rationaleCodes: Array.isArray(screenshotPolish?.rationaleCodes)
          ? screenshotPolish.rationaleCodes.map((value) => String(value || "").trim()).filter(Boolean)
          : [],
        frameContext,
      }
    : null;
  return {
    schemaVersion: 1,
    format: normalizedFormat,
    runDir: String(state.runDir || "").trim(),
    outPath,
    flattenedSourcePath,
    canvasMode: state.canvasMode,
    activeImageId,
    exportBoundsCss: composite?.boundsCss || null,
    flattenedSizePx: composite ? { width: composite.width, height: composite.height } : null,
    sourceImages: Array.isArray(composite?.sourceImages) ? composite.sourceImages : [],
    timelineNodes,
    timelineSchemaVersion: SESSION_TIMELINE_SCHEMA_VERSION,
    timelineHeadNodeId: state.timelineHeadNodeId ? String(state.timelineHeadNodeId) : null,
    actionSequence: timelineNodes.map((node) => node?.action).filter(Boolean),
    limitations: normalizedFormat === "psd" ? exportPsdLimitations() : exportRasterFormatLimitations(normalizedFormat),
    screenshotPolish: screenshotPolishTrace,
  };
}

async function saveCanvasAsArtifact(
  canvas,
  { operation, label, meta = {}, replaceActive = false, targetId = null, parentImageId = null, select = true }
) {
  if (!state.runDir) return;
  const stamp = Date.now();
  const artifactId = `local-${operation}-${stamp}`;
  const imagePath = `${state.runDir}/artifact-${stamp}-${operation}.png`;
  setStatus("Engine: writing artifact…");
  const blob = await new Promise((resolve) => canvas.toBlob(resolve, "image/png"));
  if (!blob) throw new Error("Failed to encode PNG");
  const buf = new Uint8Array(await blob.arrayBuffer());
  await writeBinaryFile(imagePath, buf);
  const receiptPath = await writeLocalReceipt({
    artifactId,
    imagePath,
    operation,
    meta,
  });
  let outputImageId = artifactId;
  if (replaceActive) {
    const id = targetId || state.activeId;
    const parentNodeId = id ? state.imagesById.get(id)?.timelineNodeId || null : null;
    const ok = id ? await replaceImageInPlace(id, { path: imagePath, receiptPath, kind: "local" }) : false;
    if (ok && id) {
      outputImageId = id;
      const nodeId = recordTimelineNode({
        imageId: id,
        path: imagePath,
        receiptPath,
        label: label || basename(imagePath),
        action: label || operation,
        kind: "image_result",
        visualMode: "thumbnail",
        parents: parentNodeId ? [parentNodeId] : [],
        previewImageId: id,
        previewPath: imagePath,
        receiptPaths: receiptPath ? [receiptPath] : [],
      });
      const item = state.imagesById.get(id) || null;
      if (item && nodeId) item.timelineNodeId = nodeId;
    } else {
      addImage(
        {
          id: artifactId,
          kind: "local",
          path: imagePath,
          receiptPath,
          label: label || operation,
          timelineAction: label || operation,
        },
        { select: true }
      );
    }
  } else {
    const parentSourceId = parentImageId ? String(parentImageId) : state.activeId;
    const parentNodeId = parentSourceId ? state.imagesById.get(parentSourceId)?.timelineNodeId || null : null;
    addImage(
      {
        id: artifactId,
        kind: "local",
        path: imagePath,
        receiptPath,
        label: label || operation,
        timelineAction: label || operation,
        timelineParents: parentNodeId ? [parentNodeId] : [],
      },
      { select: Boolean(select) }
    );
  }
  maybeEmitFirstAbilitySuccess({
    source: "local_artifact",
    route: replaceActive ? "replace" : "add_image",
    action: String(label || operation || "local"),
  });
  setStatus("Engine: ready");
  return {
    artifactId,
    imageId: outputImageId,
    outputPath: imagePath,
    receiptPath,
  };
}

// Minimal shell bridge: runtime ownership stays in tool_apply_runtime.js and local_tool_edits.js.
async function applyToolRuntimeEdit(request = {}) {
  return applyToolRuntimeRequest(request, {
    hasImageId: (imageId) => state.imagesById.has(String(imageId || "").trim()),
    getActiveImageId: () => state.activeId || "",
    setActiveImage: async (imageId) => {
      if (state.activeId === imageId) return true;
      await setActiveImage(imageId, {
        preserveSelection: true,
        source: "tool_runtime",
        reason: "tool_apply",
        actor: "system",
      }).catch(() => {});
      return true;
    },
    getImageById: (imageId) => state.imagesById.get(String(imageId || "").trim()) || null,
    ensureRun: async () => {
      if (!state.runDir) await ensureRun();
    },
    beginApply: (plan) => {
      if (isSingleImageRailCapabilityPlan(plan)) return;
      beginRunningAction("tool_apply_local");
      setImageFxActive(true, plan.label);
      setStatus(`Engine: applying ${String(plan.label || "tool").toLowerCase()}…`);
    },
    endApply: () => {
      if (isSingleImageRailCapabilityPlan(request)) return;
      setImageFxActive(false);
      clearRunningAction("tool_apply_local");
    },
    isBusy: () => singleImageRailBusy(),
    getExecutionMode: () => state.canvasMode || "single",
    getCapabilityAvailability: (capability) => {
      const availability = singleImageRailCapabilityAvailability();
      const key = String(capability || "").trim();
      return key ? availability[key] || { available: false, disabledReason: "capability_unavailable" } : availability;
    },
    executeCapability: (payload = {}) => executeSingleImageRailCapability(payload),
    loadTargetImage: async (target) => {
      if (!target?.img && target?.path) {
        target.img = await loadImage(target.path);
        target.width = target.img?.naturalWidth || target.width || null;
        target.height = target.img?.naturalHeight || target.height || null;
      }
      return target?.img || null;
    },
    createCanvas: () => document.createElement("canvas"),
    saveCanvasArtifact: (canvas, options) => saveCanvasAsArtifact(canvas, options),
    afterApply: ({ result, plan }) => {
      if (isSingleImageRailCapabilityPlan(plan)) {
        rememberSingleImageRailSuccess(result);
        showToast(`${plan.label} complete.`, "tip", 1800);
        renderQuickActions();
        return;
      }
      showToast(`Applied ${plan.label}.`, "tip", 1800);
    },
    reportError: (error, { plan } = {}) => {
      reportUserError(isSingleImageRailCapabilityPlan(plan) ? "Left rail action" : "Tool apply", error, {
        retryHint: isSingleImageRailCapabilityPlan(plan)
          ? "Select one image and retry."
          : "Select one image and use a supported local tool.",
      });
    },
    normalizeErrorMessage,
  });
}

